insert into public.bible_verses (book_id, chapter, verse, text) values
  (19, 71, 24, 'Ma langue chaque jour publiera ta justice, Car ceux qui cherchent ma perte sont honteux et confus.'),
  (19, 72, 1, 'De Salomon. O Dieu, donne tes jugements au roi, Et ta justice au fils du roi!'),
  (19, 72, 2, 'Il jugera ton peuple avec justice, Et tes malheureux avec équité.'),
  (19, 72, 3, 'Les montagnes porteront la paix pour le peuple, Et les collines aussi, par l''effet de ta justice.'),
  (19, 72, 4, 'Il fera droit aux malheureux du peuple, Il sauvera les enfants du pauvre, Et il écrasera l''oppresseur.'),
  (19, 72, 5, 'On te craindra, tant que subsistera le soleil, Tant que paraîtra la lune, de génération en génération.'),
  (19, 72, 6, 'Il sera comme une pluie qui tombe sur un terrain fauché, Comme des ondées qui arrosent la campagne.'),
  (19, 72, 7, 'En ses jours le juste fleurira, Et la paix sera grande jusqu''à ce qu''il n''y ait plus de lune.'),
  (19, 72, 8, 'Il dominera d''une mer à l''autre, Et du fleuve aux extrémités de la terre.'),
  (19, 72, 9, 'Devant lui, les habitants du désert fléchiront le genou, Et ses ennemis lécheront la poussière.'),
  (19, 72, 10, 'Les rois de Tarsis et des îles paieront des tributs, Les rois de Séba et de Saba offriront des présents.'),
  (19, 72, 11, 'Tous les rois se prosterneront devant lui, Toutes les nations le serviront.'),
  (19, 72, 12, 'Car il délivrera le pauvre qui crie, Et le malheureux qui n''a point d''aide.'),
  (19, 72, 13, 'Il aura pitié du misérable et de l''indigent, Et il sauvera la vie des pauvres;'),
  (19, 72, 14, 'Il les affranchira de l''oppression et de la violence, Et leur sang aura du prix à ses yeux.'),
  (19, 72, 15, 'Ils vivront, et lui donneront de l''or de Séba; Ils prieront pour lui sans cesse, ils le béniront chaque jour.'),
  (19, 72, 16, 'Les blés abonderont dans le pays, au sommet des montagnes, Et leurs épis s''agiteront comme les arbres du Liban; Les hommes fleuriront dans les villes comme l''herbe de la terre.'),
  (19, 72, 17, 'Son nom subsistera toujours, Aussi longtemps que le soleil son nom se perpétuera; Par lui on se bénira mutuellement, Et toutes les nations le diront heureux.'),
  (19, 72, 18, 'Béni soit l''Éternel Dieu, le Dieu d''Israël, qui seul fait des prodiges!'),
  (19, 72, 19, 'Béni soit à jamais son nom glorieux! Que toute la terre soit remplie de sa gloire! Amen! Amen!'),
  (19, 72, 20, 'Fin des prières de David, fils d''Isaï.'),
  (19, 73, 1, 'Psaume d''Asaph. Oui, Dieu est bon pour Israël, Pour ceux qui ont le cœur pur.'),
  (19, 73, 2, 'Toutefois, mon pied allait fléchir, Mes pas étaient sur le point de glisser;'),
  (19, 73, 3, 'Car je portais envie aux insensés, En voyant le bonheur des méchants.'),
  (19, 73, 4, 'Rien ne les tourmente jusqu''à leur mort, Et leur corps est chargé d''embonpoint;'),
  (19, 73, 5, 'Ils n''ont aucune part aux souffrances humaines, Ils ne sont point frappés comme le reste des hommes.'),
  (19, 73, 6, 'Aussi l''orgueil leur sert de collier, La violence est le vêtement qui les enveloppe;'),
  (19, 73, 7, 'L''iniquité sort de leurs entrailles, Les pensées de leur cœur se font jour.'),
  (19, 73, 8, 'Ils raillent, et parlent méchamment d''opprimer; Ils profèrent des discours hautains,'),
  (19, 73, 9, 'Ils élèvent leur bouche jusqu''aux cieux, Et leur langue se promène sur la terre.'),
  (19, 73, 10, 'Voilà pourquoi son peuple se tourne de leur côté, Il avale l''eau abondamment,'),
  (19, 73, 11, 'Et il dit: Comment Dieu saurait-il, Comment le Très-Haut connaîtrait-il?'),
  (19, 73, 12, 'Ainsi sont les méchants: Toujours heureux, ils accroissent leurs richesses.'),
  (19, 73, 13, 'C''est donc en vain que j''ai purifié mon cœur, Et que j''ai lavé mes mains dans l''innocence:'),
  (19, 73, 14, 'Chaque jour je suis frappé, Tous les matins mon châtiment est là.'),
  (19, 73, 15, 'Si je disais: Je veux parler comme eux, Voici, je trahirais la race de tes enfants.'),
  (19, 73, 16, 'Quand j''ai réfléchi là-dessus pour m''éclairer, La difficulté fut grande à mes yeux,'),
  (19, 73, 17, 'Jusqu''à ce que j''eusse pénétré dans les sanctuaires de Dieu, Et que j''eusse pris garde au sort final des méchants.'),
  (19, 73, 18, 'Oui, tu les places sur des voies glissantes, Tu les fais tomber et les mets en ruines.'),
  (19, 73, 19, 'Eh quoi! en un instant les voilà détruits! Ils sont enlevés, anéantis par une fin soudaine!'),
  (19, 73, 20, 'Comme un songe au réveil, Seigneur, à ton réveil, tu repousses leur image.'),
  (19, 73, 21, 'Lorsque mon cœur s''aigrissait, Et que je me sentais percé dans les entrailles,'),
  (19, 73, 22, 'J''étais stupide et sans intelligence, J''étais à ton égard comme les bêtes.'),
  (19, 73, 23, 'Cependant je suis toujours avec toi, Tu m''as saisi la main droite;'),
  (19, 73, 24, 'Tu me conduiras par ton conseil, Puis tu me recevras dans la gloire.'),
  (19, 73, 25, 'Quel autre ai-je au ciel que toi! Et sur la terre je ne prends plaisir qu''en toi.'),
  (19, 73, 26, 'Ma chair et mon cœur peuvent se consumer: Dieu sera toujours le rocher de mon cœur et mon partage.'),
  (19, 73, 27, 'Car voici, ceux qui s''éloignent de toi périssent; Tu anéantis tous ceux qui te sont infidèles.'),
  (19, 73, 28, 'Pour moi, m''approcher de Dieu, c''est mon bien: Je place mon refuge dans le Seigneur, l''Éternel, Afin de raconter toutes tes œuvres.'),
  (19, 74, 1, 'Cantique d''Asaph. Pourquoi, ô Dieu! rejettes-tu pour toujours? Pourquoi t''irrites-tu contre le troupeau de ton pâturage?'),
  (19, 74, 2, 'Souviens-toi de ton peuple que tu as acquis autrefois, Que tu as racheté comme la tribu de ton héritage! Souviens-toi de la montagne de Sion, où tu faisais ta résidence;'),
  (19, 74, 3, 'Porte tes pas vers ces lieux constamment dévastés! L''ennemi a tout ravagé dans le sanctuaire.'),
  (19, 74, 4, 'Tes adversaires ont rugi au milieu de ton temple; Ils ont établi pour signes leurs signes.'),
  (19, 74, 5, 'On les a vus, pareils à celui qui lève La cognée dans une épaisse forêt;'),
  (19, 74, 6, 'Et bientôt ils ont brisé toutes les sculptures, A coups de haches et de marteaux.'),
  (19, 74, 7, 'Ils ont mis le feu à ton sanctuaire; Ils ont abattu, profané la demeure de ton nom.'),
  (19, 74, 8, 'Ils disaient en leur cœur: Traitons-les tous avec violence! Ils ont brûlé dans le pays tous les lieux saints.'),
  (19, 74, 9, 'Nous ne voyons plus nos signes; Il n''y a plus de prophète, Et personne parmi nous qui sache jusqu''à quand…'),
  (19, 74, 10, 'Jusqu''à quand, ô Dieu! l''oppresseur outragera-t-il, L''ennemi méprisera-t-il sans cesse ton nom?'),
  (19, 74, 11, 'Pourquoi retires-tu ta main et ta droite? Sors-la de ton sein! détruis!'),
  (19, 74, 12, 'Dieu est mon roi dès les temps anciens, Lui qui opère des délivrances au milieu de la terre.'),
  (19, 74, 13, 'Tu as fendu la mer par ta puissance, Tu as brisé les têtes des monstres sur les eaux;'),
  (19, 74, 14, 'Tu as écrasé la tête du crocodile, Tu l''as donné pour nourriture au peuple du désert.'),
  (19, 74, 15, 'Tu as fait jaillir des sources et des torrents. Tu as mis à sec des fleuves qui ne tarissent point.'),
  (19, 74, 16, 'A toi est le jour, à toi est la nuit; Tu as créé la lumière et le soleil.'),
  (19, 74, 17, 'Tu as fixé toutes les limites de la terre, Tu as établi l''été et l''hiver.'),
  (19, 74, 18, 'Souviens-toi que l''ennemi outrage l''Éternel, Et qu''un peuple insensé méprise ton nom!'),
  (19, 74, 19, 'Ne livre pas aux bêtes l''âme de ta tourterelle, N''oublie pas à toujours la vie de tes malheureux!'),
  (19, 74, 20, 'Aie égard à l''alliance! Car les lieux sombres du pays sont pleins de repaires de brigands.'),
  (19, 74, 21, 'Que l''opprimé ne retourne pas confus! Que le malheureux et le pauvre célèbrent ton nom!'),
  (19, 74, 22, 'Lève-toi, ô Dieu! défends ta cause! Souviens-toi des outrages que te fait chaque jour l''insensé!'),
  (19, 74, 23, 'N''oublie pas les clameurs de tes adversaires, Le tumulte sans cesse croissant de ceux qui s''élèvent contre toi!'),
  (19, 75, 1, 'Au chef des chantres. «Ne détruis pas». Psaume d''Asaph. Cantique. Nous te louons, ô Dieu! nous te louons; Ton nom est dans nos bouches; Nous publions tes merveilles.'),
  (19, 75, 2, 'Au temps que j''aurai fixé, Je jugerai avec droiture.'),
  (19, 75, 3, 'La terre tremble avec tous ceux qui l''habitent: Moi, j''affermis ses colonnes. -Pause.'),
  (19, 75, 4, 'Je dis à ceux qui se glorifient: Ne vous glorifiez pas! Et aux méchants: N''élevez pas la tête!'),
  (19, 75, 5, 'N''élevez pas si haut votre tête, Ne parlez pas avec tant d''arrogance!'),
  (19, 75, 6, 'Car ce n''est ni de l''orient, ni de l''occident, Ni du désert, que vient l''élévation.'),
  (19, 75, 7, 'Mais Dieu est celui qui juge: Il abaisse l''un, et il élève l''autre.'),
  (19, 75, 8, 'Il y a dans la main de l''Éternel une coupe, Où fermente un vin plein de mélange, Et il en verse: Tous les méchants de la terre sucent, boivent jusqu''à la lie.'),
  (19, 75, 9, 'Je publierai ces choses à jamais; Je chanterai en l''honneur du Dieu de Jacob. -'),
  (19, 75, 10, 'Et j''abattrai toutes les forces des méchants; Les forces du juste seront élevées.'),
  (19, 76, 1, 'Au chef des chantres. Avec instruments à cordes. Psaume d''Asaph. Cantique. Dieu est connu en Juda, Son nom est grand en Israël.'),
  (19, 76, 2, 'Sa tente est à Salem, Et sa demeure à Sion.'),
  (19, 76, 3, 'C''est là qu''il a brisé les flèches, Le bouclier, l''épée et les armes de guerre. -Pause.'),
  (19, 76, 4, 'Tu es plus majestueux, plus puissant Que les montagnes des ravisseurs.'),
  (19, 76, 5, 'Ils ont été dépouillés, ces héros pleins de courage, Ils se sont endormis de leur dernier sommeil; Ils n''ont pas su se défendre, tous ces vaillants hommes.'),
  (19, 76, 6, 'A ta menace, Dieu de Jacob! Ils se sont endormis, cavaliers et chevaux.'),
  (19, 76, 7, 'Tu es redoutable, ô toi! Qui peut te résister, quand ta colère éclate?'),
  (19, 76, 8, 'Du haut des cieux tu as proclamé la sentence; La terre effrayée s''est tenue tranquille,'),
  (19, 76, 9, 'Lorsque Dieu s''est levé pour faire justice, Pour sauver tous les malheureux de la terre. -Pause.'),
  (19, 76, 10, 'L''homme te célèbre même dans sa fureur, Quand tu te revêts de tout ton courroux.'),
  (19, 76, 11, 'Faites des vœux à l''Éternel, votre Dieu, et accomplissez-les! Que tous ceux qui l''environnent apportent des dons au Dieu terrible!'),
  (19, 76, 12, 'Il abat l''orgueil des princes, Il est redoutable aux rois de la terre.'),
  (19, 77, 1, 'Au chef des chantres. D''après Jeduthun. Psaume d''Asaph. Ma voix s''élève à Dieu, et je crie; Ma voix s''élève à Dieu, et il m''écoutera.'),
  (19, 77, 2, 'Au jour de ma détresse, je cherche le Seigneur; La nuit, mes mains sont étendues sans se lasser; Mon âme refuse toute consolation.'),
  (19, 77, 3, 'Je me souviens de Dieu, et je gémis; Je médite, et mon esprit est abattu. -Pause.'),
  (19, 77, 4, 'Tu tiens mes paupières en éveil; Et, dans mon trouble, je ne puis parler.'),
  (19, 77, 5, 'Je pense aux jours anciens, Aux années d''autrefois.'),
  (19, 77, 6, 'Je pense à mes cantiques pendant la nuit, Je fais des réflexions au dedans de mon cœur, Et mon esprit médite.'),
  (19, 77, 7, 'Le Seigneur rejettera-t-il pour toujours? Ne sera-t-il plus favorable?'),
  (19, 77, 8, 'Sa bonté est-elle à jamais épuisée? Sa parole est-elle anéantie pour l''éternité?'),
  (19, 77, 9, 'Dieu a-t-il oublié d''avoir compassion? A-t-il, dans sa colère, retiré sa miséricorde? -Pause.'),
  (19, 77, 10, 'Je dis: Ce qui fait ma souffrance, C''est que la droite du Très-Haut n''est plus la même…'),
  (19, 77, 11, 'Je rappellerai les œuvres de l''Éternel, Car je me souviens de tes merveilles d''autrefois;'),
  (19, 77, 12, 'Je parlerai de toutes tes œuvres, Je raconterai tes hauts faits.'),
  (19, 77, 13, 'O Dieu! tes voies sont saintes; Quel dieu est grand comme Dieu?'),
  (19, 77, 14, 'Tu es le Dieu qui fait des prodiges; Tu as manifesté parmi les peuples ta puissance.'),
  (19, 77, 15, 'Par ton bras tu as délivré ton peuple, Les fils de Jacob et de Joseph. -Pause.'),
  (19, 77, 16, 'Les eaux t''ont vu, ô Dieu! Les eaux t''ont vu, elles ont tremblé; Les abîmes se sont émus.'),
  (19, 77, 17, 'Les nuages versèrent de l''eau par torrents, Le tonnerre retentit dans les nues, Et tes flèches volèrent de toutes parts.'),
  (19, 77, 18, 'Ton tonnerre éclata dans le tourbillon, Les éclairs illuminèrent le monde; La terre s''émut et trembla.'),
  (19, 77, 19, 'Tu te frayas un chemin par la mer, Un sentier par les grandes eaux, Et tes traces ne furent plus reconnues.'),
  (19, 77, 20, 'Tu as conduit ton peuple comme un troupeau, Par la main de Moïse et d''Aaron.'),
  (19, 78, 1, 'Cantique d''Asaph. Mon peuple, écoute mes instructions! Prêtez l''oreille aux paroles de ma bouche!'),
  (19, 78, 2, 'J''ouvre la bouche par des sentences, Je publie la sagesse des temps anciens.'),
  (19, 78, 3, 'Ce que nous avons entendu, ce que nous savons, Ce que nos pères nous ont raconté,'),
  (19, 78, 4, 'Nous ne le cacherons point à leurs enfants; Nous dirons à la génération future les louanges de l''Éternel, Et sa puissance, et les prodiges qu''il a opérés.'),
  (19, 78, 5, 'Il a établi un témoignage en Jacob, Il a mis une loi en Israël, Et il a ordonné à nos pères de l''enseigner à leurs enfants,'),
  (19, 78, 6, 'Pour qu''elle fût connue de la génération future, Des enfants qui naîtraient, Et que, devenus grands, ils en parlassent à leurs enfants,'),
  (19, 78, 7, 'Afin qu''ils missent en Dieu leur confiance, Qu''ils n''oubliassent pas les œuvres de Dieu, Et qu''ils observassent ses commandements,'),
  (19, 78, 8, 'Afin qu''ils ne fussent pas, comme leurs pères, Une race indocile et rebelle, Une race dont le cœur n''était pas ferme, Et dont l''esprit n''était pas fidèle à Dieu.'),
  (19, 78, 9, 'Les fils d''Éphraïm, armés et tirant de l''arc, Tournèrent le dos le jour du combat.'),
  (19, 78, 10, 'Ils ne gardèrent point l''alliance de Dieu, Et ils refusèrent de marcher selon sa loi.'),
  (19, 78, 11, 'Ils mirent en oubli ses œuvres, Ses merveilles qu''il leur avait fait voir.'),
  (19, 78, 12, 'Devant leurs pères il avait fait des prodiges, Au pays d''Égypte, dans les campagnes de Tsoan.'),
  (19, 78, 13, 'Il fendit la mer et leur ouvrit un passage, Il fit dresser les eaux comme une muraille.'),
  (19, 78, 14, 'Il les conduisit le jour par la nuée, Et toute la nuit par un feu éclatant.'),
  (19, 78, 15, 'Il fendit des rochers dans le désert, Et il donna à boire comme des flots abondants;'),
  (19, 78, 16, 'Du rocher il fit jaillir des sources, Et couler des eaux comme des fleuves.'),
  (19, 78, 17, 'Mais ils continuèrent à pécher contre lui, A se révolter contre le Très-Haut dans le désert.'),
  (19, 78, 18, 'Ils tentèrent Dieu dans leur cœur, En demandant de la nourriture selon leur désir.'),
  (19, 78, 19, 'Ils parlèrent contre Dieu, Ils dirent: Dieu pourrait-il Dresser une table dans le désert?'),
  (19, 78, 20, 'Voici, il a frappé le rocher, et des eaux ont coulé, Et des torrents se sont répandus; Pourra-t-il aussi donner du pain, Ou fournir de la viande à son peuple?'),
  (19, 78, 21, 'L''Éternel entendit, et il fut irrité; Un feu s''alluma contre Jacob, Et la colère s''éleva contre Israël,'),
  (19, 78, 22, 'Parce qu''ils ne crurent pas en Dieu, Parce qu''ils n''eurent pas confiance dans son secours.'),
  (19, 78, 23, 'Il commanda aux nuages d''en haut, Et il ouvrit les portes des cieux;'),
  (19, 78, 24, 'Il fit pleuvoir sur eux la manne pour nourriture, Il leur donna le blé du ciel.'),
  (19, 78, 25, 'Ils mangèrent tous le pain des grands, Il leur envoya de la nourriture à satiété.'),
  (19, 78, 26, 'Il fit souffler dans les cieux le vent d''orient, Et il amena par sa puissance le vent du midi;'),
  (19, 78, 27, 'Il fit pleuvoir sur eux la viande comme de la poussière, Et comme le sable des mers les oiseaux ailés;'),
  (19, 78, 28, 'Il les fit tomber au milieu de leur camp, Tout autour de leurs demeures.'),
  (19, 78, 29, 'Ils mangèrent et se rassasièrent abondamment: Dieu leur donna ce qu''ils avaient désiré.'),
  (19, 78, 30, 'Ils n''avaient pas satisfait leur désir, Ils avaient encore leur nourriture dans la bouche,'),
  (19, 78, 31, 'Lorsque la colère de Dieu s''éleva contre eux; Il frappa de mort les plus vigoureux, Il abattit les jeunes hommes d''Israël.'),
  (19, 78, 32, 'Malgré tout cela, ils continuèrent à pécher, Et ne crurent point à ses prodiges.'),
  (19, 78, 33, 'Il consuma leurs jours par la vanité, Et leurs années par une fin soudaine.'),
  (19, 78, 34, 'Quand il les frappait de mort, ils le cherchaient, Ils revenaient et se tournaient vers Dieu;'),
  (19, 78, 35, 'Ils se souvenaient que Dieu était leur rocher, Que le Dieu Très-Haut était leur libérateur.'),
  (19, 78, 36, 'Mais ils le trompaient de la bouche, Et ils lui mentaient de la langue;'),
  (19, 78, 37, 'Leur cœur n''était pas ferme envers lui, Et ils n''étaient pas fidèles à son alliance.'),
  (19, 78, 38, 'Toutefois, dans sa miséricorde, il pardonne l''iniquité et ne détruit pas; Il retient souvent sa colère et ne se livre pas à toute sa fureur.'),
  (19, 78, 39, 'Il se souvint qu''ils n''étaient que chair, Un souffle qui s''en va et ne revient pas.'),
  (19, 78, 40, 'Que de fois ils se révoltèrent contre lui dans le désert! Que de fois ils l''irritèrent dans la solitude!'),
  (19, 78, 41, 'Ils ne cessèrent de tenter Dieu, Et de provoquer le Saint d''Israël.'),
  (19, 78, 42, 'Ils ne se souvinrent pas de sa puissance, Du jour où il les délivra de l''ennemi,'),
  (19, 78, 43, 'Des miracles qu''il accomplit en Égypte, Et de ses prodiges dans les campagnes de Tsoan.'),
  (19, 78, 44, 'Il changea leurs fleuves en sang, Et ils ne purent en boire les eaux.'),
  (19, 78, 45, 'Il envoya contre eux des mouches venimeuses qui les dévorèrent, Et des grenouilles qui les détruisirent.'),
  (19, 78, 46, 'Il livra leurs récoltes aux sauterelles, Le produit de leur travail aux sauterelles.'),
  (19, 78, 47, 'Il fit périr leurs vignes par la grêle, Et leurs sycomores par la gelée.'),
  (19, 78, 48, 'Il abandonna leur bétail à la grêle, Et leurs troupeaux au feu du ciel.'),
  (19, 78, 49, 'Il lança contre eux son ardente colère, La fureur, la rage et la détresse, Une troupe de messagers de malheur.'),
  (19, 78, 50, 'Il donna libre cours à sa colère, Il ne sauva pas leur âme de la mort, Il livra leur vie à la mortalité;'),
  (19, 78, 51, 'Il frappa tous les premiers-nés en Égypte, Les prémices de la force sous les tentes de Cham.'),
  (19, 78, 52, 'Il fit partir son peuple comme des brebis, Il les conduisit comme un troupeau dans le désert.'),
  (19, 78, 53, 'Il les dirigea sûrement, pour qu''ils fussent sans crainte, Et la mer couvrit leurs ennemis.'),
  (19, 78, 54, 'Il les amena vers sa frontière sainte, Vers cette montagne que sa droite a acquise.'),
  (19, 78, 55, 'Il chassa devant eux les nations, Leur distribua le pays en héritage, Et fit habiter dans leurs tentes les tribus d''Israël.'),
  (19, 78, 56, 'Mais ils tentèrent le Dieu Très-Haut et se révoltèrent contre lui, Et ils n''observèrent point ses ordonnances.'),
  (19, 78, 57, 'Ils s''éloignèrent et furent infidèles, comme leurs pères, Ils tournèrent, comme un arc trompeur.'),
  (19, 78, 58, 'Ils l''irritèrent par leurs hauts lieux, Et ils excitèrent sa jalousie par leurs idoles.'),
  (19, 78, 59, 'Dieu entendit, et il fut irrité; Il repoussa fortement Israël.'),
  (19, 78, 60, 'Il abandonna la demeure de Silo, La tente où il habitait parmi les hommes;'),
  (19, 78, 61, 'Il livra sa gloire à la captivité, Et sa majesté entre les mains de l''ennemi.'),
  (19, 78, 62, 'Il mit son peuple à la merci du glaive, Et il s''indigna contre son héritage.'),
  (19, 78, 63, 'Le feu dévora ses jeunes hommes, Et ses vierges ne furent pas célébrées;'),
  (19, 78, 64, 'Ses sacrificateurs tombèrent par l''épée, Et ses veuves ne pleurèrent pas.'),
  (19, 78, 65, 'Le Seigneur s''éveilla comme celui qui a dormi, Comme un héros qu''a subjugué le vin.'),
  (19, 78, 66, 'Il frappa ses adversaires en fuite, Il les couvrit d''un opprobre éternel.'),
  (19, 78, 67, 'Cependant il rejeta la tente de Joseph, Et il ne choisit point la tribu d''Éphraïm;'),
  (19, 78, 68, 'Il préféra la tribu de Juda, La montagne de Sion qu''il aimait.'),
  (19, 78, 69, 'Et il bâtit son sanctuaire comme les lieux élevés, Comme la terre qu''il a fondée pour toujours.'),
  (19, 78, 70, 'Il choisit David, son serviteur, Et il le tira des bergeries;'),
  (19, 78, 71, 'Il le prit derrière les brebis qui allaitent, Pour lui faire paître Jacob, son peuple, Et Israël, son héritage.'),
  (19, 78, 72, 'Et David les dirigea avec un cœur intègre, Et les conduisit avec des mains intelligentes.'),
  (19, 79, 1, 'Psaume d''Asaph. O Dieu! les nations ont envahi ton héritage, Elles ont profané ton saint temple, Elles ont fait de Jérusalem un monceau de pierres.'),
  (19, 79, 2, 'Elles ont livré les cadavres de tes serviteurs En pâture aux oiseaux du ciel, La chair de tes fidèles aux bêtes de la terre;'),
  (19, 79, 3, 'Elles ont versé leur sang comme de l''eau Tout autour de Jérusalem, Et il n''y a eu personne pour les enterrer.'),
  (19, 79, 4, 'Nous sommes devenus un objet d''opprobre pour nos voisins, De moquerie et de risée pour ceux qui nous entourent.'),
  (19, 79, 5, 'Jusques à quand, Éternel! t''irriteras-tu sans cesse, Et ta colère s''embrasera-t-elle comme le feu?'),
  (19, 79, 6, 'Répands ta fureur sur les nations qui ne te connaissent pas, Et sur les royaumes qui n''invoquent pas ton nom!'),
  (19, 79, 7, 'Car on a dévoré Jacob, Et ravagé sa demeure.'),
  (19, 79, 8, 'Ne te souviens plus de nos iniquités passées! Que tes compassions viennent en hâte au-devant de nous! Car nous sommes bien malheureux.'),
  (19, 79, 9, 'Secours-nous, Dieu de notre salut, pour la gloire de ton nom! Délivre-nous, et pardonne nos péchés, à cause de ton nom!'),
  (19, 79, 10, 'Pourquoi les nations diraient-elles: Où est leur Dieu? Qu''on sache, en notre présence, parmi les nations, Que tu venges le sang de tes serviteurs, le sang répandu!'),
  (19, 79, 11, 'Que les gémissements des captifs parviennent jusqu''à toi! Par ton bras puissant sauve ceux qui vont périr!'),
  (19, 79, 12, 'Rends à nos voisins sept fois dans leur sein Les outrages qu''ils t''ont faits, Seigneur!'),
  (19, 79, 13, 'Et nous, ton peuple, le troupeau de ton pâturage, Nous te célébrerons éternellement; De génération en génération nous publierons tes louanges.'),
  (19, 80, 1, 'Au chef des chantres. Sur les lis lyriques. D''Asaph. Psaume. Prête l''oreille, berger d''Israël, Toi qui conduis Joseph comme un troupeau! Parais dans ta splendeur, Toi qui es assis sur les chérubins!'),
  (19, 80, 2, 'Devant Éphraïm, Benjamin et Manassé, réveille ta force, Et viens à notre secours!'),
  (19, 80, 3, 'O Dieu, relève-nous! Fais briller ta face, et nous serons sauvés!'),
  (19, 80, 4, 'Éternel, Dieu des armées! Jusques à quand t''irriteras-tu contre la prière de ton peuple?'),
  (19, 80, 5, 'Tu les nourris d''un pain de larmes. Tu les abreuves de larmes à pleine mesure.'),
  (19, 80, 6, 'Tu fais de nous un objet de discorde pour nos voisins, Et nos ennemis se raillent de nous.'),
  (19, 80, 7, 'Dieu des armées, relève-nous! Fais briller ta face, et nous serons sauvés!'),
  (19, 80, 8, 'Tu avais arraché de l''Égypte une vigne; Tu as chassé des nations, et tu l''as plantée.'),
  (19, 80, 9, 'Tu as fait place devant elle: Elle a jeté des racines et rempli la terre;'),
  (19, 80, 10, 'Les montagnes étaient couvertes de son ombre, Et ses rameaux étaient comme des cèdres de Dieu;'),
  (19, 80, 11, 'Elle étendait ses branches jusqu''à la mer, Et ses rejetons jusqu''au fleuve.'),
  (19, 80, 12, 'Pourquoi as-tu rompu ses clôtures, En sorte que tous les passants la dépouillent?'),
  (19, 80, 13, 'Le sanglier de la forêt la ronge, Et les bêtes des champs en font leur pâture.'),
  (19, 80, 14, 'Dieu des armées, reviens donc! Regarde du haut des cieux, et vois! considère cette vigne!'),
  (19, 80, 15, 'Protège ce que ta droite a planté, Et le fils que tu t''es choisi!…'),
  (19, 80, 16, 'Elle est brûlée par le feu, elle est coupée! Ils périssent devant ta face menaçante.'),
  (19, 80, 17, 'Que ta main soit sur l''homme de ta droite, Sur le fils de l''homme que tu t''es choisi!'),
  (19, 80, 18, 'Et nous ne nous éloignerons plus de toi. Fais-nous revivre, et nous invoquerons ton nom.'),
  (19, 80, 19, 'Éternel, Dieu des armées, relève-nous! Fais briller ta face, et nous serons sauvés!'),
  (19, 81, 1, 'Au chef des chantres. Sur la guitthith. D''Asaph. Chantez avec allégresse à Dieu, notre force! Poussez des cris de joie vers le Dieu de Jacob!'),
  (19, 81, 2, 'Entonnez des cantiques, faites résonner le tambourin, La harpe mélodieuse et le luth!'),
  (19, 81, 3, 'Sonnez de la trompette à la nouvelle lune, A la pleine lune, au jour de notre fête!'),
  (19, 81, 4, 'Car c''est une loi pour Israël, Une ordonnance du Dieu de Jacob.'),
  (19, 81, 5, 'Il en fit un statut pour Joseph, Quand il marcha contre le pays d''Égypte… J''entends une voix qui m''est inconnue:'),
  (19, 81, 6, 'J''ai déchargé son épaule du fardeau, Et ses mains ont lâché la corbeille.'),
  (19, 81, 7, 'Tu as crié dans la détresse, et je t''ai délivré; Je t''ai répondu dans la retraite du tonnerre; Je t''ai éprouvé près des eaux de Meriba. Pause.'),
  (19, 81, 8, 'Écoute, mon peuple! et je t''avertirai; Israël, puisses-tu m''écouter!'),
  (19, 81, 9, 'Qu''il n''y ait au milieu de toi point de dieu étranger! Ne te prosterne pas devant des dieux étrangers!'),
  (19, 81, 10, 'Je suis l''Éternel, ton Dieu, qui t''ai fait monter du pays d''Égypte; Ouvre ta bouche, et je la remplirai.'),
  (19, 81, 11, 'Mais mon peuple n''a point écouté ma voix, Israël ne m''a point obéi.'),
  (19, 81, 12, 'Alors je les ai livrés aux penchants de leur cœur, Et ils ont suivi leurs propres conseils.'),
  (19, 81, 13, 'Oh! si mon peuple m''écoutait, Si Israël marchait dans mes voies!'),
  (19, 81, 14, 'En un instant je confondrais leurs ennemis, Je tournerais ma main contre leurs adversaires;'),
  (19, 81, 15, 'Ceux qui haïssent l''Éternel le flatteraient, Et le bonheur d''Israël durerait toujours;'),
  (19, 81, 16, 'Je le nourrirais du meilleur froment, Et je le rassasierais du miel du rocher.'),
  (19, 82, 1, 'Psaume d''Asaph. Dieu se tient dans l''assemblée de Dieu; Il juge au milieu des dieux.'),
  (19, 82, 2, 'Jusques à quand jugerez-vous avec iniquité, Et aurez-vous égard à la personne des méchants? Pause.'),
  (19, 82, 3, 'Rendez justice au faible et à l''orphelin, Faites droit au malheureux et au pauvre,'),
  (19, 82, 4, 'Sauvez le misérable et l''indigent, Délivrez-les de la main des méchants.'),
  (19, 82, 5, 'Ils n''ont ni savoir ni intelligence, Ils marchent dans les ténèbres; Tous les fondements de la terre sont ébranlés.'),
  (19, 82, 6, 'J''avais dit: Vous êtes des dieux, Vous êtes tous des fils du Très-Haut.'),
  (19, 82, 7, 'Cependant vous mourrez comme des hommes, Vous tomberez comme un prince quelconque.'),
  (19, 82, 8, 'Lève-toi, ô Dieu, juge la terre! Car toutes les nations t''appartiennent.'),
  (19, 83, 1, 'Cantique. Psaume d''Asaph. O Dieu, ne reste pas dans le silence! Ne te tais pas, et ne te repose pas, ô Dieu!'),
  (19, 83, 2, 'Car voici, tes ennemis s''agitent, Ceux qui te haïssent lèvent la tête.'),
  (19, 83, 3, 'Ils forment contre ton peuple des projets pleins de ruse, Et ils délibèrent contre ceux que tu protèges.'),
  (19, 83, 4, 'Venez, disent-ils, exterminons-les du milieu des nations, Et qu''on ne se souvienne plus du nom d''Israël!'),
  (19, 83, 5, 'Ils se concertent tous d''un même cœur, Ils font une alliance contre toi;'),
  (19, 83, 6, 'Les tentes d''Édom et les Ismaélites, Moab et les Hagaréniens,'),
  (19, 83, 7, 'Guebal, Ammon, Amalek, Les Philistins avec les habitants de Tyr;'),
  (19, 83, 8, 'L''Assyrie aussi se joint à eux, Elle prête son bras aux enfants de Lot. Pause.'),
  (19, 83, 9, 'Traite-les comme Madian, Comme Sisera, comme Jabin au torrent de Kison!'),
  (19, 83, 10, 'Ils ont été détruits à En-Dor, Ils sont devenus du fumier pour la terre.'),
  (19, 83, 11, 'Traite leurs chefs comme Oreb et Zeeb, Et tous leurs princes comme Zébach et Tsalmunna!'),
  (19, 83, 12, 'Car ils disent: Emparons-nous Des demeures de Dieu!'),
  (19, 83, 13, 'Mon Dieu! rends-les semblables au tourbillon, Au chaume qu''emporte le vent,'),
  (19, 83, 14, 'Au feu qui brûle la forêt, A la flamme qui embrase les montagnes!'),
  (19, 83, 15, 'Poursuis-les ainsi de ta tempête, Et fais-les trembler par ton ouragan!'),
  (19, 83, 16, 'Couvre leur face d''ignominie, Afin qu''ils cherchent ton nom, ô Éternel!'),
  (19, 83, 17, 'Qu''ils soient confus et épouvantés pour toujours, Qu''ils soient honteux et qu''ils périssent!'),
  (19, 83, 18, 'Qu''ils sachent que toi seul, dont le nom est l''Éternel, Tu es le Très-Haut sur toute la terre!'),
  (19, 84, 1, 'Au chef des chantres. Sur la guitthith. Des fils de Koré. Psaume. Que tes demeures sont aimables, Éternel des armées!'),
  (19, 84, 2, 'Mon âme soupire et languit après les parvis de l''Éternel, Mon cœur et ma chair poussent des cris vers le Dieu vivant.'),
  (19, 84, 3, 'Le passereau même trouve une maison, Et l''hirondelle un nid où elle dépose ses petits… Tes autels, Éternel des armées! Mon roi et mon Dieu!'),
  (19, 84, 4, 'Heureux ceux qui habitent ta maison! Ils peuvent te célébrer encore. Pause.'),
  (19, 84, 5, 'Heureux ceux qui placent en toi leur appui! Ils trouvent dans leur cœur des chemins tout tracés.'),
  (19, 84, 6, 'Lorsqu''ils traversent la vallée de Baca, Ils la transforment en un lieu plein de sources, Et la pluie la couvre aussi de bénédictions.'),
  (19, 84, 7, 'Leur force augmente pendant la marche, Et ils se présentent devant Dieu à Sion.'),
  (19, 84, 8, 'Éternel, Dieu des armées, écoute ma prière! Prête l''oreille, Dieu de Jacob! Pause.'),
  (19, 84, 9, 'Toi qui es notre bouclier, vois, ô Dieu! Et regarde la face de ton oint!'),
  (19, 84, 10, 'Mieux vaut un jour dans tes parvis que mille ailleurs; Je préfère me tenir sur le seuil de la maison de mon Dieu, Plutôt que d''habiter sous les tentes de la méchanceté.'),
  (19, 84, 11, 'Car l''Éternel Dieu est un soleil et un bouclier, L''Éternel donne la grâce et la gloire, Il ne refuse aucun bien à ceux qui marchent dans l''intégrité.'),
  (19, 84, 12, 'Éternel des armées! Heureux l''homme qui se confie en toi!'),
  (19, 85, 1, 'Au chef des chantres. Des fils de Koré. Psaume. Tu as été favorable à ton pays, ô Éternel! Tu as ramené les captifs de Jacob;'),
  (19, 85, 2, 'Tu as pardonné l''iniquité de ton peuple, Tu as couvert tous ses péchés; Pause.'),
  (19, 85, 3, 'Tu as retiré toute ta fureur, Tu es revenu de l''ardeur de ta colère.'),
  (19, 85, 4, 'Rétablis-nous, Dieu de notre salut! Cesse ton indignation contre nous!'),
  (19, 85, 5, 'T''irriteras-tu contre nous à jamais? Prolongeras-tu ta colère éternellement?'),
  (19, 85, 6, 'Ne nous rendras-tu pas à la vie, Afin que ton peuple se réjouisse en toi?'),
  (19, 85, 7, 'Éternel! fais-nous voir ta bonté, Et accorde-nous ton salut!'),
  (19, 85, 8, 'J''écouterai ce que dit Dieu, l''Éternel; Car il parle de paix à son peuple et à ses fidèles, Pourvu qu''ils ne retombent pas dans la folie.'),
  (19, 85, 9, 'Oui, son salut est près de ceux qui le craignent, Afin que la gloire habite dans notre pays.'),
  (19, 85, 10, 'La bonté et la fidélité se rencontrent, La justice et la paix s''embrassent;'),
  (19, 85, 11, 'La fidélité germe de la terre, Et la justice regarde du haut des cieux.'),
  (19, 85, 12, 'L''Éternel aussi accordera le bonheur, Et notre terre donnera ses fruits.'),
  (19, 85, 13, 'La justice marchera devant lui, Et imprimera ses pas sur le chemin.'),
  (19, 86, 1, 'Prière de David. Éternel, prête l''oreille, exauce-moi! Car je suis malheureux et indigent.'),
  (19, 86, 2, 'Garde mon âme, car je suis pieux! Mon Dieu, sauve ton serviteur qui se confie en toi!'),
  (19, 86, 3, 'Aie pitié de moi, Seigneur! Car je crie à toi tout le jour.'),
  (19, 86, 4, 'Réjouis l''âme de ton serviteur, Car à toi, Seigneur, j''élève mon âme.'),
  (19, 86, 5, 'Car tu es bon, Seigneur, tu pardonnes, Tu es plein d''amour pour tous ceux qui t''invoquent.'),
  (19, 86, 6, 'Éternel, prête l''oreille à ma prière, Sois attentif à la voix de mes supplications!'),
  (19, 86, 7, 'Je t''invoque au jour de ma détresse, Car tu m''exauces.'),
  (19, 86, 8, 'Nul n''est comme toi parmi les dieux, Seigneur, Et rien ne ressemble à tes œuvres.'),
  (19, 86, 9, 'Toutes les nations que tu as faites viendront Se prosterner devant ta face, Seigneur, Et rendre gloire à ton nom.'),
  (19, 86, 10, 'Car tu es grand, et tu opères des prodiges; Toi seul, tu es Dieu.'),
  (19, 86, 11, 'Enseigne-moi tes voies, ô Éternel! Je marcherai dans ta fidélité. Dispose mon cœur à la crainte de ton nom.'),
  (19, 86, 12, 'Je te louerai de tout mon cœur, Seigneur, mon Dieu! Et je glorifierai ton nom à perpétuité.'),
  (19, 86, 13, 'Car ta bonté est grande envers moi, Et tu délivres mon âme du séjour profond des morts.'),
  (19, 86, 14, 'O Dieu! des orgueilleux se sont levés contre moi, Une troupe d''hommes violents en veulent à ma vie; Ils ne portent pas leurs pensées sur toi.'),
  (19, 86, 15, 'Mais toi, Seigneur, tu es un Dieu miséricordieux et compatissant, Lent à la colère, riche en bonté et en fidélité;'),
  (19, 86, 16, 'Tourne vers moi les regards et aie pitié de moi, Donne la force à ton serviteur, Et sauve le fils de ta servante!'),
  (19, 86, 17, 'Opère un signe en ma faveur! Que mes ennemis le voient et soient confus! Car tu me secours et tu me consoles, ô Éternel!'),
  (19, 87, 1, 'Des fils de Koré. Psaume. Cantique. Elle est fondée sur les montagnes saintes.'),
  (19, 87, 2, 'L''Éternel aime les portes de Sion Plus que toutes les demeures de Jacob.'),
  (19, 87, 3, 'Des choses glorieuses ont été dites sur toi, Ville de Dieu! Pause.'),
  (19, 87, 4, 'Je proclame l''Égypte et Babylone parmi ceux qui me connaissent; Voici, le pays des Philistins, Tyr, avec l''Éthiopie: C''est dans Sion qu''ils sont nés.'),
  (19, 87, 5, 'Et de Sion il est dit: Tous y sont nés, Et c''est le Très-Haut qui l''affermit.'),
  (19, 87, 6, 'L''Éternel compte en inscrivant les peuples: C''est là qu''ils sont nés. Pause.'),
  (19, 87, 7, 'Et ceux qui chantent et ceux qui dansent s''écrient: Toutes mes sources sont en toi.'),
  (19, 88, 1, 'Cantique. Psaume des fils de Koré. Au chef des chantres. Pour chanter sur la flûte. Cantique d''Héman, l''Ézrachite. Éternel, Dieu de mon salut! Je crie jour et nuit devant toi.'),
  (19, 88, 2, 'Que ma prière parvienne en ta présence! Prête l''oreille à mes supplications!'),
  (19, 88, 3, 'Car mon âme est rassasiée de maux, Et ma vie s''approche du séjour des morts.'),
  (19, 88, 4, 'Je suis mis au rang de ceux qui descendent dans la fosse, Je suis comme un homme qui n''a plus de force.'),
  (19, 88, 5, 'Je suis étendu parmi les morts, Semblable à ceux qui sont tués et couchés dans le sépulcre, A ceux dont tu n''as plus le souvenir, Et qui sont séparés de ta main.'),
  (19, 88, 6, 'Tu m''as jeté dans une fosse profonde, Dans les ténèbres, dans les abîmes.'),
  (19, 88, 7, 'Ta fureur s''appesantit sur moi, Et tu m''accables de tous tes flots. Pause.'),
  (19, 88, 8, 'Tu as éloigné de moi mes amis, Tu m''as rendu pour eux un objet d''horreur; Je suis enfermé et je ne puis sortir.'),
  (19, 88, 9, 'Mes yeux se consument dans la souffrance; Je t''invoque tous les jours, ô Éternel! J''étends vers toi les mains.'),
  (19, 88, 10, 'Est-ce pour les morts que tu fais des miracles? Les morts se lèvent-ils pour te louer? Pause.'),
  (19, 88, 11, 'Parle-t-on de ta bonté dans le sépulcre, De ta fidélité dans l''abîme?'),
  (19, 88, 12, 'Tes prodiges sont-ils connus dans les ténèbres, Et ta justice dans la terre de l''oubli?'),
  (19, 88, 13, 'O Éternel! j''implore ton secours, Et le matin ma prière s''élève à toi.'),
  (19, 88, 14, 'Pourquoi, Éternel, repousses-tu mon âme? Pourquoi me caches-tu ta face?'),
  (19, 88, 15, 'Je suis malheureux et moribond dès ma jeunesse, Je suis chargé de tes terreurs, je suis troublé.'),
  (19, 88, 16, 'Tes fureurs passent sur moi, Tes terreurs m''anéantissent;'),
  (19, 88, 17, 'Elles m''environnent tout le jour comme des eaux, Elles m''enveloppent toutes à la fois.'),
  (19, 88, 18, 'Tu as éloigné de moi amis et compagnons; Mes intimes ont disparu.'),
  (19, 89, 1, 'Cantique d''Éthan, l''Ézrachite. Je chanterai toujours les bontés de l''Éternel; Ma bouche fera connaître à jamais ta fidélité.'),
  (19, 89, 2, 'Car je dis: La bonté a des fondements éternels; Tu établis ta fidélité dans les cieux.'),
  (19, 89, 3, 'J''ai fait alliance avec mon élu; Voici ce que j''ai juré à David, mon serviteur:'),
  (19, 89, 4, 'J''affermirai ta postérité pour toujours, Et j''établirai ton trône à perpétuité. Pause.'),
  (19, 89, 5, 'Les cieux célèbrent tes merveilles, ô Éternel! Et ta fidélité dans l''assemblée des saints.'),
  (19, 89, 6, 'Car qui, dans le ciel, peut se comparer à l''Éternel? Qui est semblable à toi parmi les fils de Dieu?'),
  (19, 89, 7, 'Dieu est terrible dans la grande assemblée des saints, Il est redoutable pour tous ceux qui l''entourent.'),
  (19, 89, 8, 'Éternel, Dieu des armées! qui est comme toi puissant, ô Éternel? Ta fidélité t''environne.'),
  (19, 89, 9, 'Tu domptes l''orgueil de la mer; Quand ses flots se soulèvent, tu les apaises.'),
  (19, 89, 10, 'Tu écrasas l''Égypte comme un cadavre, Tu dispersas tes ennemis par la puissance de ton bras.'),
  (19, 89, 11, 'C''est à toi qu''appartiennent les cieux et la terre, C''est toi qui as fondé le monde et ce qu''il renferme.'),
  (19, 89, 12, 'Tu as créé le nord et le midi; Le Thabor et l''Hermon se réjouissent à ton nom.'),
  (19, 89, 13, 'Ton bras est puissant, Ta main forte, ta droite élevée.'),
  (19, 89, 14, 'La justice et l''équité sont la base de ton trône. La bonté et la fidélité sont devant ta face.'),
  (19, 89, 15, 'Heureux le peuple qui connaît le son de la trompette; Il marche à la clarté de ta face, ô Éternel!'),
  (19, 89, 16, 'Il se réjouit sans cesse de ton nom, Et il se glorifie de ta justice.'),
  (19, 89, 17, 'Car tu es la gloire de sa puissance; C''est ta faveur qui relève notre force.'),
  (19, 89, 18, 'Car l''Éternel est notre bouclier, Le Saint d''Israël est notre roi.'),
  (19, 89, 19, 'Alors tu parlas dans une vision à ton bien-aimé, Et tu dis: J''ai prêté mon secours à un héros, J''ai élevé du milieu du peuple un jeune homme;'),
  (19, 89, 20, 'J''ai trouvé David, mon serviteur, Je l''ai oint de mon huile sainte.'),
  (19, 89, 21, 'Ma main le soutiendra, Et mon bras le fortifiera.'),
  (19, 89, 22, 'L''ennemi ne le surprendra pas, Et le méchant ne l''opprimera point;'),
  (19, 89, 23, 'J''écraserai devant lui ses adversaires, Et je frapperai ceux qui le haïssent.'),
  (19, 89, 24, 'Ma fidélité et ma bonté seront avec lui, Et sa force s''élèvera par mon nom.'),
  (19, 89, 25, 'Je mettrai sa main sur la mer, Et sa droite sur les fleuves.'),
  (19, 89, 26, 'Lui, il m''invoquera: Tu es mon père, Mon Dieu et le rocher de mon salut!'),
  (19, 89, 27, 'Et moi, je ferai de lui le premier-né, Le plus élevé des rois de la terre.'),
  (19, 89, 28, 'Je lui conserverai toujours ma bonté, Et mon alliance lui sera fidèle;'),
  (19, 89, 29, 'Je rendrai sa postérité éternelle, Et son trône comme les jours des cieux.'),
  (19, 89, 30, 'Si ses fils abandonnent ma loi Et ne marchent pas selon ses ordonnances,'),
  (19, 89, 31, 'S''ils violent mes préceptes Et n''observent pas mes commandements,'),
  (19, 89, 32, 'Je punirai de la verge leurs transgressions, Et par des coups leurs iniquités;'),
  (19, 89, 33, 'Mais je ne lui retirerai point ma bonté Et je ne trahirai pas ma fidélité,'),
  (19, 89, 34, 'Je ne violerai point mon alliance Et je ne changerai pas ce qui est sorti de mes lèvres.'),
  (19, 89, 35, 'J''ai juré une fois par ma sainteté: Mentirai-je à David?'),
  (19, 89, 36, 'Sa postérité subsistera toujours; Son trône sera devant moi comme le soleil,'),
  (19, 89, 37, 'Comme la lune il aura une éternelle durée. Le témoin qui est dans le ciel est fidèle. Pause.'),
  (19, 89, 38, 'Et pourtant, tu as rejeté, tu as repoussé! Tu t''es irrité contre ton oint!'),
  (19, 89, 39, 'Tu as dédaigné l''alliance avec ton serviteur; Tu as abattu, profané sa couronne.'),
  (19, 89, 40, 'Tu as détruit toutes ses murailles, Tu as mis en ruines ses forteresses.'),
  (19, 89, 41, 'Tous les passants le dépouillent; Il est un objet d''opprobre pour ses voisins.'),
  (19, 89, 42, 'Tu as élevé la droite de ses adversaires, Tu as réjoui tous ses ennemis;'),
  (19, 89, 43, 'Tu as fait reculer le tranchant de son glaive, Et tu ne l''as pas soutenu dans le combat.'),
  (19, 89, 44, 'Tu as mis un terme à sa splendeur, Et tu as jeté son trône à terre;'),
  (19, 89, 45, 'Tu as abrégé les jours de sa jeunesse, Tu l''as couvert de honte. Pause.'),
  (19, 89, 46, 'Jusques à quand, Éternel! te cacheras-tu sans cesse, Et ta fureur s''embrasera-t-elle comme le feu?'),
  (19, 89, 47, 'Rappelle-toi ce qu''est la durée de ma vie, Et pour quel néant tu as créé tous les fils de l''homme.'),
  (19, 89, 48, 'Y a-t-il un homme qui puisse vivre et ne pas voir la mort, Qui puisse sauver son âme du séjour des morts? Pause.'),
  (19, 89, 49, 'Où sont, Seigneur! tes bontés premières, Que tu juras à David dans ta fidélité?'),
  (19, 89, 50, 'Souviens-toi, Seigneur! de l''opprobre de tes serviteurs, Souviens-toi que je porte en mon sein tous les peuples nombreux;'),
  (19, 89, 51, 'Souviens-toi des outrages de tes ennemis, ô Éternel! De leurs outrages contre les pas de ton oint.'),
  (19, 89, 52, 'Béni soit à jamais l''Éternel! Amen! Amen!'),
  (19, 90, 1, 'Prière de Moïse, homme de Dieu. Seigneur! tu as été pour nous un refuge, De génération en génération.'),
  (19, 90, 2, 'Avant que les montagnes fussent nées, Et que tu eusses créé la terre et le monde, D''éternité en éternité tu es Dieu.'),
  (19, 90, 3, 'Tu fais rentrer les hommes dans la poussière, Et tu dis: Fils de l''homme, retournez!'),
  (19, 90, 4, 'Car mille ans sont, à tes yeux, Comme le jour d''hier, quand il n''est plus, Et comme une veille de la nuit.'),
  (19, 90, 5, 'Tu les emportes, semblables à un songe, Qui, le matin, passe comme l''herbe:'),
  (19, 90, 6, 'Elle fleurit le matin, et elle passe, On la coupe le soir, et elle sèche.'),
  (19, 90, 7, 'Nous sommes consumés par ta colère, Et ta fureur nous épouvante.'),
  (19, 90, 8, 'Tu mets devant toi nos iniquités, Et à la lumière de ta face nos fautes cachées.'),
  (19, 90, 9, 'Tous nos jours disparaissent par ton courroux; Nous voyons nos années s''évanouir comme un son.'),
  (19, 90, 10, 'Les jours de nos années s''élèvent à soixante-dix ans, Et, pour les plus robustes, à quatre-vingts ans; Et l''orgueil qu''ils en tirent n''est que peine et misère, Car il passe vite, et nous nous envolons.'),
  (19, 90, 11, 'Qui prend garde à la force de ta colère, Et à ton courroux, selon la crainte qui t''est due?'),
  (19, 90, 12, 'Enseigne-nous à bien compter nos jours, Afin que nous appliquions notre cœur à la sagesse.'),
  (19, 90, 13, 'Reviens, Éternel! Jusques à quand?… Aie pitié de tes serviteurs!'),
  (19, 90, 14, 'Rassasie-nous chaque matin de ta bonté, Et nous serons toute notre vie dans la joie et l''allégresse.'),
  (19, 90, 15, 'Réjouis-nous autant de jours que tu nous as humiliés, Autant d''années que nous avons vu le malheur.'),
  (19, 90, 16, 'Que ton œuvre se manifeste à tes serviteurs, Et ta gloire sur leurs enfants!'),
  (19, 90, 17, 'Que la grâce de l''Éternel, notre Dieu, soit sur nous! Affermis l''ouvrage de nos mains, Oui, affermis l''ouvrage de nos mains!'),
  (19, 91, 1, 'Celui qui demeure sous l''abri du Très-Haut Repose à l''ombre du Tout-Puissant.'),
  (19, 91, 2, 'Je dis à l''Éternel: Mon refuge et ma forteresse, Mon Dieu en qui je me confie!'),
  (19, 91, 3, 'Car c''est lui qui te délivre du filet de l''oiseleur, De la peste et de ses ravages.'),
  (19, 91, 4, 'Il te couvrira de ses plumes, Et tu trouveras un refuge sous ses ailes; Sa fidélité est un bouclier et une cuirasse.'),
  (19, 91, 5, 'Tu ne craindras ni les terreurs de la nuit, Ni la flèche qui vole de jour,'),
  (19, 91, 6, 'Ni la peste qui marche dans les ténèbres, Ni la contagion qui frappe en plein midi.'),
  (19, 91, 7, 'Que mille tombent à ton côté, Et dix mille à ta droite, Tu ne seras pas atteint;'),
  (19, 91, 8, 'De tes yeux seulement tu regarderas, Et tu verras la rétribution des méchants.'),
  (19, 91, 9, 'Car tu es mon refuge, ô Éternel! Tu fais du Très-Haut ta retraite.'),
  (19, 91, 10, 'Aucun malheur ne t''arrivera, Aucun fléau n''approchera de ta tente.'),
  (19, 91, 11, 'Car il ordonnera à ses anges De te garder dans toutes tes voies;'),
  (19, 91, 12, 'Ils te porteront sur les mains, De peur que ton pied ne heurte contre une pierre.'),
  (19, 91, 13, 'Tu marcheras sur le lion et sur l''aspic, Tu fouleras le lionceau et le dragon.'),
  (19, 91, 14, 'Puisqu''il m''aime, je le délivrerai; Je le protégerai, puisqu''il connaît mon nom.'),
  (19, 91, 15, 'Il m''invoquera, et je lui répondrai; Je serai avec lui dans la détresse, Je le délivrerai et je le glorifierai.'),
  (19, 91, 16, 'Je le rassasierai de longs jours, Et je lui ferai voir mon salut.'),
  (19, 92, 1, 'Psaume. Cantique pour le jour du sabbat. Il est beau de louer l''Éternel, Et de célébrer ton nom, ô Très-Haut!'),
  (19, 92, 2, 'D''annoncer le matin ta bonté, Et ta fidélité pendant les nuits,'),
  (19, 92, 3, 'Sur l''instrument à dix cordes et sur le luth, Aux sons de la harpe.'),
  (19, 92, 4, 'Tu me réjouis par tes œuvres, ô Éternel! Et je chante avec allégresse l''ouvrage de tes mains.'),
  (19, 92, 5, 'Que tes œuvres sont grandes, ô Éternel! Que tes pensées sont profondes!'),
  (19, 92, 6, 'L''homme stupide n''y connaît rien, Et l''insensé n''y prend point garde.'),
  (19, 92, 7, 'Si les méchants croissent comme l''herbe, Si tous ceux qui font le mal fleurissent, C''est pour être anéantis à jamais.'),
  (19, 92, 8, 'Mais toi, tu es le Très-Haut, A perpétuité, ô Éternel!'),
  (19, 92, 9, 'Car voici, tes ennemis, ô Éternel! Car voici, tes ennemis périssent; Tous ceux qui font le mal sont dispersés.'),
  (19, 92, 10, 'Et tu me donnes la force du buffle; Je suis arrosé avec une huile fraîche.'),
  (19, 92, 11, 'Mon œil se plaît à contempler mes ennemis, Et mon oreille à entendre mes méchants adversaires.'),
  (19, 92, 12, 'Les justes croissent comme le palmier, Ils s''élèvent comme le cèdre du Liban.'),
  (19, 92, 13, 'Plantés dans la maison de l''Éternel, Ils prospèrent dans les parvis de notre Dieu;'),
  (19, 92, 14, 'Ils portent encore des fruits dans la vieillesse, Ils sont pleins de sève et verdoyants,'),
  (19, 92, 15, 'Pour faire connaître que l''Éternel est juste. Il est mon rocher, et il n''y a point en lui d''iniquité.'),
  (19, 93, 1, 'L''Éternel règne, il est revêtu de majesté, L''Éternel est revêtu, il est ceint de force. Aussi le monde est ferme, il ne chancelle pas.'),
  (19, 93, 2, 'Ton trône est établi dès les temps anciens; Tu existes de toute éternité.'),
  (19, 93, 3, 'Les fleuves élèvent, ô Éternel! Les fleuves élèvent leur voix, Les fleuves élèvent leurs ondes retentissantes.'),
  (19, 93, 4, 'Plus que la voix des grandes, des puissantes eaux, Des flots impétueux de la mer, L''Éternel est puissant dans les lieux célestes.'),
  (19, 93, 5, 'Tes témoignages sont entièrement véritables; La sainteté convient à ta maison, O Éternel! pour toute la durée des temps.'),
  (19, 94, 1, 'Dieu des vengeances, Éternel! Dieu des vengeances, parais!'),
  (19, 94, 2, 'Lève-toi, juge de la terre! Rends aux superbes selon leurs œuvres!'),
  (19, 94, 3, 'Jusques à quand les méchants, ô Éternel! Jusques à quand les méchants triompheront-ils?'),
  (19, 94, 4, 'Ils discourent, ils parlent avec arrogance; Tous ceux qui font le mal se glorifient.'),
  (19, 94, 5, 'Éternel! ils écrasent ton peuple, Ils oppriment ton héritage;'),
  (19, 94, 6, 'Ils égorgent la veuve et l''étranger, Ils assassinent les orphelins.'),
  (19, 94, 7, 'Et ils disent: L''Éternel ne regarde pas, Le Dieu de Jacob ne fait pas attention!'),
  (19, 94, 8, 'Prenez-y garde, hommes stupides! Insensés, quand serez-vous sages?'),
  (19, 94, 9, 'Celui qui a planté l''oreille n''entendrait-il pas? Celui qui a formé l''œil ne verrait-il pas?'),
  (19, 94, 10, 'Celui qui châtie les nations ne punirait-il point, Lui qui donne à l''homme l''intelligence?'),
  (19, 94, 11, 'L''Éternel connaît les pensées de l''homme, Il sait qu''elles sont vaines.'),
  (19, 94, 12, 'Heureux l''homme que tu châties, ô Éternel! Et que tu instruis par ta loi,'),
  (19, 94, 13, 'Pour le calmer aux jours du malheur, Jusqu''à ce que la fosse soit creusée pour le méchant!'),
  (19, 94, 14, 'Car l''Éternel ne délaisse pas son peuple, Il n''abandonne pas son héritage;'),
  (19, 94, 15, 'Car le jugement sera conforme à la justice, Et tous ceux dont le cœur est droit l''approuveront.'),
  (19, 94, 16, 'Qui se lèvera pour moi contre les méchants? Qui me soutiendra contre ceux qui font le mal?'),
  (19, 94, 17, 'Si l''Éternel n''était pas mon secours, Mon âme serait bien vite dans la demeure du silence.'),
  (19, 94, 18, 'Quand je dis: Mon pied chancelle! Ta bonté, ô Éternel! me sert d''appui.'),
  (19, 94, 19, 'Quand les pensées s''agitent en foule au dedans de moi, Tes consolations réjouissent mon âme.'),
  (19, 94, 20, 'Les méchants te feraient-ils siéger sur leur trône, Eux qui forment des desseins iniques en dépit de la loi?'),
  (19, 94, 21, 'Ils se rassemblent contre la vie du juste, Et ils condamnent le sang innocent.'),
  (19, 94, 22, 'Mais l''Éternel est ma retraite, Mon Dieu est le rocher de mon refuge.'),
  (19, 94, 23, 'Il fera retomber sur eux leur iniquité, Il les anéantira par leur méchanceté; L''Éternel, notre Dieu, les anéantira.'),
  (19, 95, 1, 'Venez, chantons avec allégresse à l''Éternel! Poussons des cris de joie vers le rocher de notre salut.'),
  (19, 95, 2, 'Allons au-devant de lui avec des louanges, Faisons retentir des cantiques en son honneur!'),
  (19, 95, 3, 'Car l''Éternel est un grand Dieu, Il est un grand roi au-dessus de tous les dieux.'),
  (19, 95, 4, 'Il tient dans sa main les profondeurs de la terre, Et les sommets des montagnes sont à lui.'),
  (19, 95, 5, 'La mer est à lui, c''est lui qui l''a faite; La terre aussi, ses mains l''ont formée.'),
  (19, 95, 6, 'Venez, prosternons-nous et humilions-nous, Fléchissons le genou devant l''Éternel, notre créateur!'),
  (19, 95, 7, 'Car il est notre Dieu, Et nous sommes le peuple de son pâturage, Le troupeau que sa main conduit… Oh! si vous pouviez écouter aujourd''hui sa voix!'),
  (19, 95, 8, 'N''endurcissez pas votre cœur, comme à Meriba, Comme à la journée de Massa, dans le désert,'),
  (19, 95, 9, 'Où vos pères me tentèrent, M''éprouvèrent, quoiqu''ils vissent mes œuvres.'),
  (19, 95, 10, 'Pendant quarante ans j''eus cette race en dégoût, Et je dis: C''est un peuple dont le cœur est égaré; Ils ne connaissent pas mes voies.'),
  (19, 95, 11, 'Aussi je jurai dans ma colère: Ils n''entreront pas dans mon repos!'),
  (19, 96, 1, 'Chantez à l''Éternel un cantique nouveau! Chantez à l''Éternel, vous tous, habitants de la terre!'),
  (19, 96, 2, 'Chantez à l''Éternel, bénissez son nom, Annoncez de jour en jour son salut!'),
  (19, 96, 3, 'Racontez parmi les nations sa gloire, Parmi tous les peuples ses merveilles!'),
  (19, 96, 4, 'Car l''Éternel est grand et très digne de louange, Il est redoutable par-dessus tous les dieux;'),
  (19, 96, 5, 'Car tous les dieux des peuples sont des idoles, Et l''Éternel a fait les cieux.'),
  (19, 96, 6, 'La splendeur et la magnificence sont devant sa face, La gloire et la majesté sont dans son sanctuaire.'),
  (19, 96, 7, 'Familles des peuples, rendez à l''Éternel, Rendez à l''Éternel gloire et honneur!'),
  (19, 96, 8, 'Rendez à l''Éternel gloire pour son nom! Apportez des offrandes, et entrez dans ses parvis!'),
  (19, 96, 9, 'Prosternez-vous devant l''Éternel avec des ornements sacrés. Tremblez devant lui, vous tous, habitants de la terre!'),
  (19, 96, 10, 'Dites parmi les nations: L''Éternel règne; Aussi le monde est ferme, il ne chancelle pas; L''Éternel juge les peuples avec droiture.'),
  (19, 96, 11, 'Que les cieux se réjouissent, et que la terre soit dans l''allégresse, Que la mer retentisse avec tout ce qu''elle contient,'),
  (19, 96, 12, 'Que la campagne s''égaie avec tout ce qu''elle renferme, Que tous les arbres des forêts poussent des cris de joie,'),
  (19, 96, 13, 'Devant l''Éternel! Car il vient, Car il vient pour juger la terre; Il jugera le monde avec justice, Et les peuples selon sa fidélité.'),
  (19, 97, 1, 'L''Éternel règne: que la terre soit dans l''allégresse, Que les îles nombreuses se réjouissent!'),
  (19, 97, 2, 'Les nuages et l''obscurité l''environnent, La justice et l''équité sont la base de son trône.'),
  (19, 97, 3, 'Le feu marche devant lui, Et embrase à l''entour ses adversaires.'),
  (19, 97, 4, 'Ses éclairs illuminent le monde, La terre le voit et tremble;'),
  (19, 97, 5, 'Les montagnes se fondent comme la cire devant l''Éternel, Devant le Seigneur de toute la terre.'),
  (19, 97, 6, 'Les cieux publient sa justice, Et tous les peuples voient sa gloire.'),
  (19, 97, 7, 'Ils sont confus, tous ceux qui servent les images, Qui se font gloire des idoles. Tous les dieux se prosternent devant lui.'),
  (19, 97, 8, 'Sion l''entend et se réjouit, Les filles de Juda sont dans l''allégresse, A cause de tes jugements, ô Éternel!'),
  (19, 97, 9, 'Car toi, Éternel! tu es le Très-Haut sur toute la terre, Tu es souverainement élevé au-dessus de tous les dieux.'),
  (19, 97, 10, 'Vous qui aimez l''Éternel, haïssez le mal! Il garde les âmes de ses fidèles, Il les délivre de la main des méchants.'),
  (19, 97, 11, 'La lumière est semée pour le juste, Et la joie pour ceux dont le cœur est droit.'),
  (19, 97, 12, 'Justes, réjouissez-vous en l''Éternel, Et célébrez par vos louanges sa sainteté!'),
  (19, 98, 1, 'Psaume. Chantez à l''Éternel un cantique nouveau! Car il a fait des prodiges. Sa droite et son bras saint lui sont venus en aide.'),
  (19, 98, 2, 'L''Éternel a manifesté son salut, Il a révélé sa justice aux yeux des nations.'),
  (19, 98, 3, 'Il s''est souvenu de sa bonté et de sa fidélité envers la maison d''Israël, Toutes les extrémités de la terre ont vu le salut de notre Dieu.'),
  (19, 98, 4, 'Poussez vers l''Éternel des cris de joie, Vous tous, habitants de la terre! Faites éclater votre allégresse, et chantez!'),
  (19, 98, 5, 'Chantez à l''Éternel avec la harpe; Avec la harpe chantez des cantiques!'),
  (19, 98, 6, 'Avec les trompettes et au son du cor, Poussez des cris de joie devant le roi, l''Éternel!'),
  (19, 98, 7, 'Que la mer retentisse avec tout ce qu''elle contient, Que le monde et ceux qui l''habitent éclatent d''allégresse,'),
  (19, 98, 8, 'Que les fleuves battent des mains, Que toutes les montagnes poussent des cris de joie,'),
  (19, 98, 9, 'Devant l''Éternel! Car il vient pour juger la terre; Il jugera le monde avec justice, Et les peuples avec équité.'),
  (19, 99, 1, 'L''Éternel règne: les peuples tremblent; Il est assis sur les chérubins: la terre chancelle.'),
  (19, 99, 2, 'L''Éternel est grand dans Sion, Il est élevé au-dessus de tous les peuples.'),
  (19, 99, 3, 'Qu''on célèbre ton nom grand et redoutable! Il est saint!'),
  (19, 99, 4, 'Qu''on célèbre la force du roi qui aime la justice! Tu affermis la droiture, Tu exerces en Jacob la justice et l''équité.'),
  (19, 99, 5, 'Exaltez l''Éternel, notre Dieu, Et prosternez-vous devant son marchepied! Il est saint!'),
  (19, 99, 6, 'Moïse et Aaron parmi ses sacrificateurs, Et Samuel parmi ceux qui invoquaient son nom, Invoquèrent l''Éternel, et il les exauça.'),
  (19, 99, 7, 'Il leur parla dans la colonne de nuée; Ils observèrent ses commandements Et la loi qu''il leur donna.'),
  (19, 99, 8, 'Éternel, notre Dieu, tu les exauças, Tu fus pour eux un Dieu qui pardonne, Mais tu les as punis de leurs fautes.'),
  (19, 99, 9, 'Exaltez l''Éternel, notre Dieu, Et prosternez-vous sur sa montagne sainte! Car il est saint, l''Éternel, notre Dieu!'),
  (19, 100, 1, 'Psaume de louange. Poussez vers l''Éternel des cris de joie, Vous tous, habitants de la terre!'),
  (19, 100, 2, 'Servez l''Éternel, avec joie, Venez avec allégresse en sa présence!'),
  (19, 100, 3, 'Sachez que l''Éternel est Dieu! C''est lui qui nous a faits, et nous lui appartenons; Nous sommes son peuple, et le troupeau de son pâturage.'),
  (19, 100, 4, 'Entrez dans ses portes avec des louanges, Dans ses parvis avec des cantiques! Célébrez-le, bénissez son nom!'),
  (19, 100, 5, 'Car l''Éternel est bon; sa bonté dure toujours, Et sa fidélité de génération en génération.'),
  (19, 101, 1, 'De David. Psaume. Je chanterai la bonté et la justice; C''est à toi, Éternel! que je chanterai.'),
  (19, 101, 2, 'Je prendrai garde à la voie droite. Quand viendras-tu à moi? Je marcherai dans l''intégrité de mon cœur, Au milieu de ma maison.'),
  (19, 101, 3, 'Je ne mettrai rien de mauvais devant mes yeux; Je hais la conduite des pécheurs; Elle ne s''attachera point à moi.'),
  (19, 101, 4, 'Le cœur pervers s''éloignera de moi; Je ne veux pas connaître le méchant.'),
  (19, 101, 5, 'Celui qui calomnie en secret son prochain, je l''anéantirai; Celui qui a des regards hautains et un cœur enflé, je ne le supporterai pas.'),
  (19, 101, 6, 'J''aurai les yeux sur les fidèles du pays, Pour qu''ils demeurent auprès de moi; Celui qui marche dans une voie intègre sera mon serviteur.'),
  (19, 101, 7, 'Celui qui se livre à la fraude n''habitera pas dans ma maison; Celui qui dit des mensonges ne subsistera pas en ma présence.'),
  (19, 101, 8, 'Chaque matin j''anéantirai tous les méchants du pays, Afin d''exterminer de la ville de l''Éternel Tous ceux qui commettent l''iniquité.'),
  (19, 102, 1, 'Prière d''un malheureux, lorsqu''il est abattu et qu''il répand sa plainte devant l''Éternel. Éternel, écoute ma prière, Et que mon cri parvienne jusqu''à toi!'),
  (19, 102, 2, 'Ne me cache pas ta face au jour de ma détresse! Incline vers moi ton oreille quand je crie! Hâte-toi de m''exaucer!'),
  (19, 102, 3, 'Car mes jours s''évanouissent en fumée, Et mes os sont enflammés comme un tison.'),
  (19, 102, 4, 'Mon cœur est frappé et se dessèche comme l''herbe; J''oublie même de manger mon pain.'),
  (19, 102, 5, 'Mes gémissements sont tels Que mes os s''attachent à ma chair.'),
  (19, 102, 6, 'Je ressemble au pélican du désert, Je suis comme le chat-huant des ruines;'),
  (19, 102, 7, 'Je n''ai plus de sommeil, et je suis Comme l''oiseau solitaire sur un toit.'),
  (19, 102, 8, 'Chaque jour mes ennemis m''outragent, Et c''est par moi que jurent mes adversaires en fureur.'),
  (19, 102, 9, 'Je mange la poussière au lieu de pain, Et je mêle des larmes à ma boisson,'),
  (19, 102, 10, 'A cause de ta colère et de ta fureur; Car tu m''as soulevé et jeté au loin.'),
  (19, 102, 11, 'Mes jours sont comme l''ombre à son déclin, Et je me dessèche comme l''herbe.'),
  (19, 102, 12, 'Mais toi, Éternel! tu règnes à perpétuité, Et ta mémoire dure de génération en génération.'),
  (19, 102, 13, 'Tu te lèveras, tu auras pitié de Sion; Car le temps d''avoir pitié d''elle, Le temps fixé est à son terme;'),
  (19, 102, 14, 'Car tes serviteurs en aiment les pierres, Ils en chérissent la poussière.'),
  (19, 102, 15, 'Alors les nations craindront le nom de l''Éternel, Et tous les rois de la terre ta gloire.'),
  (19, 102, 16, 'Oui, l''Éternel rebâtira Sion, Il se montrera dans sa gloire.'),
  (19, 102, 17, 'Il est attentif à la prière du misérable, Il ne dédaigne pas sa prière.'),
  (19, 102, 18, 'Que cela soit écrit pour la génération future, Et que le peuple qui sera créé célèbre l''Éternel!'),
  (19, 102, 19, 'Car il regarde du lieu élevé de sa sainteté; Du haut des cieux l''Éternel regarde sur la terre,'),
  (19, 102, 20, 'Pour écouter les gémissements des captifs, Pour délivrer ceux qui vont périr,'),
  (19, 102, 21, 'Afin qu''ils publient dans Sion le nom de l''Éternel, Et ses louanges dans Jérusalem,'),
  (19, 102, 22, 'Quand tous les peuples s''assembleront, Et tous les royaumes, pour servir l''Éternel.'),
  (19, 102, 23, 'Il a brisé ma force dans la route, Il a abrégé mes jours.'),
  (19, 102, 24, 'Je dis: Mon Dieu, ne m''enlève pas au milieu de mes jours, Toi, dont les années durent éternellement!'),
  (19, 102, 25, 'Tu as anciennement fondé la terre, Et les cieux sont l''ouvrage de tes mains.'),
  (19, 102, 26, 'Ils périront, mais tu subsisteras; Ils s''useront tous comme un vêtement; Tu les changeras comme un habit, et ils seront changés.'),
  (19, 102, 27, 'Mais toi, tu restes le même, Et tes années ne finiront point.'),
  (19, 102, 28, 'Les fils de tes serviteurs habiteront leur pays, Et leur postérité s''affermira devant toi.'),
  (19, 103, 1, 'De David. Mon âme, bénis l''Éternel! Que tout ce qui est en moi bénisse son saint nom!'),
  (19, 103, 2, 'Mon âme, bénis l''Éternel, Et n''oublie aucun de ses bienfaits!'),
  (19, 103, 3, 'C''est lui qui pardonne toutes tes iniquités, Qui guérit toutes tes maladies;'),
  (19, 103, 4, 'C''est lui qui délivre ta vie de la fosse, Qui te couronne de bonté et de miséricorde;'),
  (19, 103, 5, 'C''est lui qui rassasie de biens ta vieillesse, Qui te fait rajeunir comme l''aigle.'),
  (19, 103, 6, 'L''Éternel fait justice, Il fait droit à tous les opprimés.'),
  (19, 103, 7, 'Il a manifesté ses voies à Moïse, Ses œuvres aux enfants d''Israël.'),
  (19, 103, 8, 'L''Éternel est miséricordieux et compatissant, Lent à la colère et riche en bonté;'),
  (19, 103, 9, 'Il ne conteste pas sans cesse, Il ne garde pas sa colère à toujours;'),
  (19, 103, 10, 'Il ne nous traite pas selon nos péchés, Il ne nous punit pas selon nos iniquités.'),
  (19, 103, 11, 'Mais autant les cieux sont élevés au-dessus de la terre, Autant sa bonté est grande pour ceux qui le craignent;'),
  (19, 103, 12, 'Autant l''orient est éloigné de l''occident, Autant il éloigne de nous nos transgressions.'),
  (19, 103, 13, 'Comme un père a compassion de ses enfants, L''Éternel a compassion de ceux qui le craignent.'),
  (19, 103, 14, 'Car il sait de quoi nous sommes formés, Il se souvient que nous sommes poussière.'),
  (19, 103, 15, 'L''homme! ses jours sont comme l''herbe, Il fleurit comme la fleur des champs.'),
  (19, 103, 16, 'Lorsqu''un vent passe sur elle, elle n''est plus, Et le lieu qu''elle occupait ne la reconnaît plus.'),
  (19, 103, 17, 'Mais la bonté de l''Éternel dure à jamais pour ceux qui le craignent, Et sa miséricorde pour les enfants de leurs enfants,'),
  (19, 103, 18, 'Pour ceux qui gardent son alliance, Et se souviennent de ses commandements afin de les accomplir.'),
  (19, 103, 19, 'L''Éternel a établi son trône dans les cieux, Et son règne domine sur toutes choses.'),
  (19, 103, 20, 'Bénissez l''Éternel, vous ses anges, Qui êtes puissants en force, et qui exécutez ses ordres, En obéissant à la voix de sa parole!'),
  (19, 103, 21, 'Bénissez l''Éternel, vous toutes ses armées, Qui êtes ses serviteurs, et qui faites sa volonté!'),
  (19, 103, 22, 'Bénissez l''Éternel, vous toutes ses œuvres, Dans tous les lieux de sa domination! Mon âme, bénis l''Éternel!'),
  (19, 104, 1, 'Mon âme, bénis l''Éternel! Éternel, mon Dieu, tu es infiniment grand! Tu es revêtu d''éclat et de magnificence!'),
  (19, 104, 2, 'Il s''enveloppe de lumière comme d''un manteau; Il étend les cieux comme un pavillon.'),
  (19, 104, 3, 'Il forme avec les eaux le faîte de sa demeure; Il prend les nuées pour son char, Il s''avance sur les ailes du vent.'),
  (19, 104, 4, 'Il fait des vents ses messagers, Des flammes de feu ses serviteurs.'),
  (19, 104, 5, 'Il a établi la terre sur ses fondements, Elle ne sera jamais ébranlée.'),
  (19, 104, 6, 'Tu l''avais couverte de l''abîme comme d''un vêtement, Les eaux s''arrêtaient sur les montagnes;'),
  (19, 104, 7, 'Elles ont fui devant ta menace, Elles se sont précipitées à la voix de ton tonnerre.'),
  (19, 104, 8, 'Des montagnes se sont élevées, des vallées se sont abaissées, Au lieu que tu leur avais fixé.'),
  (19, 104, 9, 'Tu as posé une limite que les eaux ne doivent point franchir, Afin qu''elles ne reviennent plus couvrir la terre.'),
  (19, 104, 10, 'Il conduit les sources dans des torrents Qui coulent entre les montagnes.'),
  (19, 104, 11, 'Elles abreuvent tous les animaux des champs; Les ânes sauvages y étanchent leur soif.'),
  (19, 104, 12, 'Les oiseaux du ciel habitent sur leurs bords, Et font résonner leur voix parmi les rameaux.'),
  (19, 104, 13, 'De sa haute demeure, il arrose les montagnes; La terre est rassasiée du fruit de tes œuvres.'),
  (19, 104, 14, 'Il fait germer l''herbe pour le bétail, Et les plantes pour les besoins de l''homme, Afin que la terre produise de la nourriture,'),
  (19, 104, 15, 'Le vin qui réjouit le cœur de l''homme, Et fait plus que l''huile resplendir son visage, Et le pain qui soutient le cœur de l''homme.'),
  (19, 104, 16, 'Les arbres de l''Éternel se rassasient, Les cèdres du Liban, qu''il a plantés.'),
  (19, 104, 17, 'C''est là que les oiseaux font leurs nids; La cigogne a sa demeure dans les cyprès,'),
  (19, 104, 18, 'Les montagnes élevées sont pour les boucs sauvages, Les rochers servent de retraite aux damans.'),
  (19, 104, 19, 'Il a fait la lune pour marquer les temps; Le soleil sait quand il doit se coucher.'),
  (19, 104, 20, 'Tu amènes les ténèbres, et il est nuit: Alors tous les animaux des forêts sont en mouvement;'),
  (19, 104, 21, 'Les lionceaux rugissent après la proie, Et demandent à Dieu leur nourriture.'),
  (19, 104, 22, 'Le soleil se lève: ils se retirent, Et se couchent dans leurs tanières.'),
  (19, 104, 23, 'L''homme sort pour se rendre à son ouvrage, Et à son travail, jusqu''au soir.'),
  (19, 104, 24, 'Que tes œuvres sont en grand nombre, ô Éternel! Tu les as toutes faites avec sagesse. La terre est remplie de tes biens.'),
  (19, 104, 25, 'Voici la grande et vaste mer: Là se meuvent sans nombre Des animaux petits et grands;'),
  (19, 104, 26, 'Là se promènent les navires, Et ce léviathan que tu as formé pour se jouer dans les flots.'),
  (19, 104, 27, 'Tous ces animaux espèrent en toi, Pour que tu leur donnes la nourriture en son temps.'),
  (19, 104, 28, 'Tu la leur donnes, et ils la recueillent; Tu ouvres ta main, et ils se rassasient de biens.'),
  (19, 104, 29, 'Tu caches ta face: ils sont tremblants; Tu leur retires le souffle: ils expirent, Et retournent dans leur poussière.'),
  (19, 104, 30, 'Tu envoies ton souffle: ils sont créés, Et tu renouvelles la face de la terre.'),
  (19, 104, 31, 'Que la gloire de l''Éternel subsiste à jamais! Que l''Éternel se réjouisse de ses œuvres!'),
  (19, 104, 32, 'Il regarde la terre, et elle tremble; Il touche les montagnes, et elles sont fumantes.'),
  (19, 104, 33, 'Je chanterai l''Éternel tant que je vivrai, Je célébrerai mon Dieu tant que j''existerai.'),
  (19, 104, 34, 'Que mes paroles lui soient agréables! Je veux me réjouir en l''Éternel.'),
  (19, 104, 35, 'Que les pécheurs disparaissent de la terre, Et que les méchants ne soient plus! Mon âme, bénis l''Éternel! Louez l''Éternel!'),
  (19, 105, 1, 'Louez l''Éternel, invoquez son nom! Faites connaître parmi les peuples ses hauts faits!'),
  (19, 105, 2, 'Chantez, chantez en son honneur! Parlez de toutes ses merveilles!'),
  (19, 105, 3, 'Glorifiez-vous de son saint nom! Que le cœur de ceux qui cherchent l''Éternel se réjouisse!'),
  (19, 105, 4, 'Ayez recours à l''Éternel et à son appui, Cherchez continuellement sa face!'),
  (19, 105, 5, 'Souvenez-vous des prodiges qu''il a faits, De ses miracles et des jugements de sa bouche,'),
  (19, 105, 6, 'Postérité d''Abraham, son serviteur, Enfants de Jacob, ses élus!'),
  (19, 105, 7, 'L''Éternel est notre Dieu; Ses jugements s''exercent sur toute la terre.'),
  (19, 105, 8, 'Il se rappelle à toujours son alliance, Ses promesses pour mille générations,'),
  (19, 105, 9, 'L''alliance qu''il a traitée avec Abraham, Et le serment qu''il a fait à Isaac;'),
  (19, 105, 10, 'Il l''a érigée pour Jacob en loi, Pour Israël en alliance éternelle,'),
  (19, 105, 11, 'Disant: Je te donnerai le pays de Canaan Comme héritage qui vous est échu.'),
  (19, 105, 12, 'Ils étaient alors peu nombreux, Très peu nombreux, et étrangers dans le pays,'),
  (19, 105, 13, 'Et ils allaient d''une nation à l''autre Et d''un royaume vers un autre peuple;'),
  (19, 105, 14, 'Mais il ne permit à personne de les opprimer, Et il châtia des rois à cause d''eux:'),
  (19, 105, 15, 'Ne touchez pas à mes oints, Et ne faites pas de mal à mes prophètes!'),
  (19, 105, 16, 'Il appela sur le pays la famine, Il coupa tout moyen de subsistance.'),
  (19, 105, 17, 'Il envoya devant eux un homme: Joseph fut vendu comme esclave.'),
  (19, 105, 18, 'On serra ses pieds dans des liens, On le mit aux fers,'),
  (19, 105, 19, 'Jusqu''au temps où arriva ce qu''il avait annoncé, Et où la parole de l''Éternel l''éprouva.'),
  (19, 105, 20, 'Le roi fit ôter ses liens, Le dominateur des peuples le délivra.'),
  (19, 105, 21, 'Il l''établit seigneur sur sa maison, Et gouverneur de tous ses biens,'),
  (19, 105, 22, 'Afin qu''il pût à son gré enchaîner ses princes, Et qu''il enseignât la sagesse à ses anciens.'),
  (19, 105, 23, 'Alors Israël vint en Égypte, Et Jacob séjourna dans le pays de Cham.'),
  (19, 105, 24, 'Il rendit son peuple très fécond, Et plus puissant que ses adversaires.'),
  (19, 105, 25, 'Il changea leur cœur, au point qu''ils haïrent son peuple Et qu''ils traitèrent ses serviteurs avec perfidie.'),
  (19, 105, 26, 'Il envoya Moïse, son serviteur, Et Aaron, qu''il avait choisi.'),
  (19, 105, 27, 'Ils accomplirent par son pouvoir des prodiges au milieu d''eux, Ils firent des miracles dans le pays de Cham.'),
  (19, 105, 28, 'Il envoya des ténèbres et amena l''obscurité, Et ils ne furent pas rebelles à sa parole.'),
  (19, 105, 29, 'Il changea leurs eaux en sang, Et fit périr leurs poissons.'),
  (19, 105, 30, 'Le pays fourmilla de grenouilles, Jusque dans les chambres de leurs rois.'),
  (19, 105, 31, 'Il dit, et parurent les mouches venimeuses, Les poux sur tout leur territoire.'),
  (19, 105, 32, 'Il leur donna pour pluie de la grêle, Des flammes de feu dans leur pays.'),
  (19, 105, 33, 'Il frappa leurs vignes et leurs figuiers, Et brisa les arbres de leur contrée.'),
  (19, 105, 34, 'Il dit, et parurent les sauterelles, Des sauterelles sans nombre,'),
  (19, 105, 35, 'Qui dévorèrent toute l''herbe du pays, Qui dévorèrent les fruits de leurs champs.'),
  (19, 105, 36, 'Il frappa tous les premiers-nés dans leur pays, Toutes les prémices de leur force.'),
  (19, 105, 37, 'Il fit sortir son peuple avec de l''argent et de l''or, Et nul ne chancela parmi ses tribus.'),
  (19, 105, 38, 'Les Égyptiens se réjouirent de leur départ, Car la terreur qu''ils avaient d''eux les saisissait.'),
  (19, 105, 39, 'Il étendit la nuée pour les couvrir, Et le feu pour éclairer la nuit.'),
  (19, 105, 40, 'A leur demande, il fit venir des cailles, Et il les rassasia du pain du ciel.'),
  (19, 105, 41, 'Il ouvrit le rocher, et des eaux coulèrent; Elles se répandirent comme un fleuve dans les lieux arides.'),
  (19, 105, 42, 'Car il se souvint de sa parole sainte, Et d''Abraham, son serviteur.'),
  (19, 105, 43, 'Il fit sortir son peuple dans l''allégresse, Ses élus au milieu des cris de joie.'),
  (19, 105, 44, 'Il leur donna les terres des nations, Et ils possédèrent le fruit du travail des peuples,'),
  (19, 105, 45, 'Afin qu''ils gardassent ses ordonnances, Et qu''ils observassent ses lois. Louez l''Éternel!'),
  (19, 106, 1, 'Louez l''Éternel! Louez l''Éternel, car il est bon, Car sa miséricorde dure à toujours!'),
  (19, 106, 2, 'Qui dira les hauts faits de l''Éternel? Qui publiera toute sa louange?'),
  (19, 106, 3, 'Heureux ceux qui observent la loi, Qui pratiquent la justice en tout temps!'),
  (19, 106, 4, 'Éternel, souviens-toi de moi dans ta bienveillance pour ton peuple! Souviens-toi de moi en lui accordant ton secours,'),
  (19, 106, 5, 'Afin que je voie le bonheur de tes élus, Que je me réjouisse de la joie de ton peuple, Et que je me glorifie avec ton héritage!'),
  (19, 106, 6, 'Nous avons péché comme nos pères, Nous avons commis l''iniquité, nous avons fait le mal.'),
  (19, 106, 7, 'Nos pères en Égypte ne furent pas attentifs à tes miracles, Ils ne se rappelèrent pas la multitude de tes grâces, Ils furent rebelles près de la mer, près de la mer Rouge.'),
  (19, 106, 8, 'Mais il les sauva à cause de son nom, Pour manifester sa puissance.'),
  (19, 106, 9, 'Il menaça la mer Rouge, et elle se dessécha; Et il les fit marcher à travers les abîmes comme dans un désert.'),
  (19, 106, 10, 'Il les sauva de la main de celui qui les haïssait, Il les délivra de la main de l''ennemi.'),
  (19, 106, 11, 'Les eaux couvrirent leurs adversaires: Il n''en resta pas un seul.'),
  (19, 106, 12, 'Et ils crurent à ses paroles, Ils chantèrent ses louanges.'),
  (19, 106, 13, 'Mais ils oublièrent bientôt ses œuvres, Ils n''attendirent pas l''exécution de ses desseins.'),
  (19, 106, 14, 'Ils furent saisis de convoitise dans le désert, Et ils tentèrent Dieu dans la solitude.'),
  (19, 106, 15, 'Il leur accorda ce qu''ils demandaient; Puis il envoya le dépérissement dans leur corps.'),
  (19, 106, 16, 'Ils se montrèrent, dans le camp, jaloux contre Moïse, Contre Aaron, le saint de l''Éternel.'),
  (19, 106, 17, 'La terre s''ouvrit et engloutit Dathan, Et elle se referma sur la troupe d''Abiram;'),
  (19, 106, 18, 'Le feu embrasa leur troupe, La flamme consuma les méchants.'),
  (19, 106, 19, 'Ils firent un veau en Horeb, Ils se prosternèrent devant une image de fonte,'),
  (19, 106, 20, 'Ils échangèrent leur gloire Contre la figure d''un bœuf qui mange l''herbe.'),
  (19, 106, 21, 'Ils oublièrent Dieu, leur sauveur, Qui avait fait de grandes choses en Égypte,'),
  (19, 106, 22, 'Des miracles dans le pays de Cham, Des prodiges sur la mer Rouge.'),
  (19, 106, 23, 'Et il parla de les exterminer; Mais Moïse, son élu, se tint à la brèche devant lui, Pour détourner sa fureur et l''empêcher de les détruire.'),
  (19, 106, 24, 'Ils méprisèrent le pays des délices; Ils ne crurent pas à la parole de l''Éternel,'),
  (19, 106, 25, 'Ils murmurèrent dans leurs tentes, Ils n''obéirent point à sa voix.'),
  (19, 106, 26, 'Et il leva la main pour jurer De les faire tomber dans le désert,'),
  (19, 106, 27, 'De faire tomber leur postérité parmi les nations, Et de les disperser au milieu des pays.'),
  (19, 106, 28, 'Ils s''attachèrent à Baal-Peor, Et mangèrent des victimes sacrifiées aux morts.'),
  (19, 106, 29, 'Ils irritèrent l''Éternel par leurs actions, Et une plaie fit irruption parmi eux.'),
  (19, 106, 30, 'Phinées se leva pour intervenir, Et la plaie s''arrêta;'),
  (19, 106, 31, 'Cela lui fut imputé à justice, De génération en génération pour toujours.'),
  (19, 106, 32, 'Ils irritèrent l''Éternel près des eaux de Meriba; Et Moïse fut puni à cause d''eux,'),
  (19, 106, 33, 'Car ils aigrirent son esprit, Et il s''exprima légèrement des lèvres.'),
  (19, 106, 34, 'Ils ne détruisirent point les peuples Que l''Éternel leur avait ordonné de détruire.'),
  (19, 106, 35, 'Ils se mêlèrent avec les nations, Et ils apprirent leurs œuvres.'),
  (19, 106, 36, 'Ils servirent leurs idoles, Qui furent pour eux un piège;'),
  (19, 106, 37, 'Ils sacrifièrent leurs fils Et leurs filles aux idoles,'),
  (19, 106, 38, 'Ils répandirent le sang innocent, Le sang de leurs fils et de leurs filles, Qu''ils sacrifièrent aux idoles de Canaan, Et le pays fut profané par des meurtres.'),
  (19, 106, 39, 'Ils se souillèrent par leurs œuvres, Ils se prostituèrent par leurs actions.'),
  (19, 106, 40, 'La colère de l''Éternel s''enflamma contre son peuple, Et il prit en horreur son héritage.'),
  (19, 106, 41, 'Il les livra entre les mains des nations; Ceux qui les haïssaient dominèrent sur eux;'),
  (19, 106, 42, 'Leurs ennemis les opprimèrent, Et ils furent humiliés sous leur puissance.'),
  (19, 106, 43, 'Plusieurs fois il les délivra; Mais ils se montrèrent rebelles dans leurs desseins, Et ils devinrent malheureux par leur iniquité.'),
  (19, 106, 44, 'Il vit leur détresse, Lorsqu''il entendit leurs supplications.'),
  (19, 106, 45, 'Il se souvint en leur faveur de son alliance;'),
  (19, 106, 46, 'Il eut pitié selon sa grande bonté, Et il excita pour eux la compassion De tous ceux qui les retenaient captifs.'),
  (19, 106, 47, 'Sauve-nous, Éternel, notre Dieu! Et rassemble-nous du milieu des nations, Afin que nous célébrions ton saint nom, Et que nous mettions notre gloire à te louer!'),
  (19, 106, 48, 'Béni soit l''Éternel, le Dieu d''Israël, d''éternité en éternité! Et que tout le peuple dise: Amen! Louez l''Éternel!'),
  (19, 107, 1, 'Louez l''Éternel, car il est bon, Car sa miséricorde dure à toujours!'),
  (19, 107, 2, 'Qu''ainsi disent les rachetés de l''Éternel, Ceux qu''il a délivrés de la main de l''ennemi,'),
  (19, 107, 3, 'Et qu''il a rassemblés de tous les pays, De l''orient et de l''occident, du nord et de la mer!'),
  (19, 107, 4, 'Ils erraient dans le désert, ils marchaient dans la solitude, Sans trouver une ville où ils pussent habiter.'),
  (19, 107, 5, 'Ils souffraient de la faim et de la soif; Leur âme était languissante.'),
  (19, 107, 6, 'Dans leur détresse, ils crièrent à l''Éternel, Et il les délivra de leurs angoisses;'),
  (19, 107, 7, 'Il les conduisit par le droit chemin, Pour qu''ils arrivassent dans une ville habitable.'),
  (19, 107, 8, 'Qu''ils louent l''Éternel pour sa bonté, Et pour ses merveilles en faveur des fils de l''homme!'),
  (19, 107, 9, 'Car il a satisfait l''âme altérée, Il a comblé de biens l''âme affamée.'),
  (19, 107, 10, 'Ceux qui avaient pour demeure les ténèbres et l''ombre de la mort Vivaient captifs dans la misère et dans les chaînes,'),
  (19, 107, 11, 'Parce qu''ils s''étaient révoltés contre les paroles de Dieu, Parce qu''ils avaient méprisé le conseil du Très-Haut.'),
  (19, 107, 12, 'Il humilia leur cœur par la souffrance; Ils succombèrent, et personne ne les secourut.'),
  (19, 107, 13, 'Dans leur détresse, ils crièrent à l''Éternel, Et il les délivra de leurs angoisses;'),
  (19, 107, 14, 'Il les fit sortir des ténèbres et de l''ombre de la mort, Et il rompit leurs liens.'),
  (19, 107, 15, 'Qu''ils louent l''Éternel pour sa bonté, Et pour ses merveilles en faveur des fils de l''homme!'),
  (19, 107, 16, 'Car il a brisé les portes d''airain, Il a rompu les verrous de fer.'),
  (19, 107, 17, 'Les insensés, par leur conduite coupable Et par leurs iniquités, s''étaient rendus malheureux.'),
  (19, 107, 18, 'Leur âme avait en horreur toute nourriture, Et ils touchaient aux portes de la mort.'),
  (19, 107, 19, 'Dans leur détresse, ils crièrent à l''Éternel, Et il les délivra de leurs angoisses;'),
  (19, 107, 20, 'Il envoya sa parole et les guérit, Il les fit échapper de la fosse.'),
  (19, 107, 21, 'Qu''ils louent l''Éternel pour sa bonté, Et pour ses merveilles en faveur des fils de l''homme!'),
  (19, 107, 22, 'Qu''ils offrent des sacrifices d''actions de grâces, Et qu''ils publient ses œuvres avec des cris de joie!'),
  (19, 107, 23, 'Ceux qui étaient descendus sur la mer dans des navires, Et qui travaillaient sur les grandes eaux,'),
  (19, 107, 24, 'Ceux-là virent les œuvres de l''Éternel Et ses merveilles au milieu de l''abîme.'),
  (19, 107, 25, 'Il dit, et il fit souffler la tempête, Qui souleva les flots de la mer.'),
  (19, 107, 26, 'Ils montaient vers les cieux, ils descendaient dans l''abîme; Leur âme était éperdue en face du danger;'),
  (19, 107, 27, 'Saisis de vertige, ils chancelaient comme un homme ivre, Et toute leur habileté était anéantie.'),
  (19, 107, 28, 'Dans leur détresse, ils crièrent à l''Éternel, Et il les délivra de leurs angoisses;'),
  (19, 107, 29, 'Il arrêta la tempête, ramena le calme, Et les ondes se turent.'),
  (19, 107, 30, 'Ils se réjouirent de ce qu''elles s''étaient apaisées, Et l''Éternel les conduisit au port désiré.'),
  (19, 107, 31, 'Qu''ils louent l''Éternel pour sa bonté, Et pour ses merveilles en faveur des fils de l''homme!'),
  (19, 107, 32, 'Qu''ils l''exaltent dans l''assemblée du peuple, Et qu''ils le célèbrent dans la réunion des anciens!'),
  (19, 107, 33, 'Il change les fleuves en désert, Et les sources d''eaux en terre desséchée,'),
  (19, 107, 34, 'Le pays fertile en pays salé, A cause de la méchanceté de ses habitants.'),
  (19, 107, 35, 'Il change le désert en étang, Et la terre aride en sources d''eaux,'),
  (19, 107, 36, 'Et il y établit ceux qui sont affamés. Ils fondent une ville pour l''habiter;'),
  (19, 107, 37, 'Ils ensemencent des champs, plantent des vignes, Et ils en recueillent les produits.'),
  (19, 107, 38, 'Il les bénit, et ils deviennent très nombreux, Et il ne diminue point leur bétail.'),
  (19, 107, 39, 'Sont-ils amoindris et humiliés Par l''oppression, le malheur et la souffrance;'),
  (19, 107, 40, 'Verse-t-il le mépris sur les grands, Les fait-il errer dans des déserts sans chemin,'),
  (19, 107, 41, 'Il relève l''indigent et le délivre de la misère, Il multiplie les familles comme des troupeaux.'),
  (19, 107, 42, 'Les hommes droits le voient et se réjouissent, Mais toute iniquité ferme la bouche.'),
  (19, 107, 43, 'Que celui qui est sage prenne garde à ces choses, Et qu''il soit attentif aux bontés de l''Éternel.'),
  (19, 108, 1, 'Cantique. Psaume de David. Mon cœur est affermi, ô Dieu! Je chanterai, je ferai retentir mes instruments: c''est ma gloire!'),
  (19, 108, 2, 'Réveillez-vous, mon luth et ma harpe! Je réveillerai l''aurore.'),
  (19, 108, 3, 'Je te louerai parmi les peuples, Éternel! Je te chanterai parmi les nations.'),
  (19, 108, 4, 'Car ta bonté s''élève au-dessus des cieux, Et ta fidélité jusqu''aux nues.'),
  (19, 108, 5, 'Élève-toi sur les cieux, ô Dieu! Et que ta gloire soit sur toute la terre!'),
  (19, 108, 6, 'Afin que tes bien-aimés soient délivrés, Sauve par ta droite, et exauce-nous!'),
  (19, 108, 7, 'Dieu a dit dans sa sainteté: Je triompherai, Je partagerai Sichem, je mesurerai la vallée de Succoth;'),
  (19, 108, 8, 'A moi Galaad, à moi Manassé; Éphraïm est le rempart de ma tête, Et Juda, mon sceptre;'),
  (19, 108, 9, 'Moab est le bassin où je me lave; Je jette mon soulier sur Édom; Je pousse des cris de joie sur le pays des Philistins!'),
  (19, 108, 10, 'Qui me mènera dans la ville forte? Qui me conduit à Édom?'),
  (19, 108, 11, 'N''est-ce pas toi, ô Dieu, qui nous as repoussés, Et qui ne sortais plus, ô Dieu, avec nos armées?'),
  (19, 108, 12, 'Donne-nous du secours contre la détresse! Le secours de l''homme n''est que vanité.'),
  (19, 108, 13, 'Avec Dieu, nous ferons des exploits; Il écrasera nos ennemis.'),
  (19, 109, 1, 'Au chef des chantres. De David. Psaume. Dieu de ma louange, ne te tais point!'),
  (19, 109, 2, 'Car ils ouvrent contre moi une bouche méchante et trompeuse, Ils me parlent avec une langue mensongère,'),
  (19, 109, 3, 'Ils m''environnent de discours haineux Et ils me font la guerre sans cause.'),
  (19, 109, 4, 'Tandis que je les aime, ils sont mes adversaires; Mais moi je recours à la prière.'),
  (19, 109, 5, 'Ils me rendent le mal pour le bien, Et de la haine pour mon amour.'),
  (19, 109, 6, 'Place-le sous l''autorité d''un méchant, Et qu''un accusateur se tienne à sa droite!'),
  (19, 109, 7, 'Quand on le jugera, qu''il soit déclaré coupable, Et que sa prière passe pour un péché!'),
  (19, 109, 8, 'Que ses jours soient peu nombreux, Qu''un autre prenne sa charge!'),
  (19, 109, 9, 'Que ses enfants deviennent orphelins, Et sa femme veuve!'),
  (19, 109, 10, 'Que ses enfants soient vagabonds et qu''ils mendient, Qu''ils cherchent du pain loin de leur demeure en ruines!'),
  (19, 109, 11, 'Que le créancier s''empare de tout ce qui est à lui, Et que les étrangers pillent le fruit de son travail!'),
  (19, 109, 12, 'Que nul ne conserve pour lui de l''affection, Et que personne n''ait pitié de ses orphelins!'),
  (19, 109, 13, 'Que ses descendants soient exterminés, Et que leur nom s''éteigne dans la génération suivante!'),
  (19, 109, 14, 'Que l''iniquité de ses pères reste en souvenir devant l''Éternel, Et que le péché de sa mère ne soit point effacé!'),
  (19, 109, 15, 'Qu''ils soient toujours présents devant l''Éternel, Et qu''il retranche de la terre leur mémoire,'),
  (19, 109, 16, 'Parce qu''il ne s''est pas souvenu d''exercer la miséricorde, Parce qu''il a persécuté le malheureux et l''indigent, Jusqu''à faire mourir l''homme au cœur brisé!'),
  (19, 109, 17, 'Il aimait la malédiction: qu''elle tombe sur lui! Il ne se plaisait pas à la bénédiction: qu''elle s''éloigne de lui!'),
  (19, 109, 18, 'Qu''il revête la malédiction comme son vêtement, Qu''elle pénètre comme de l''eau dans son intérieur, Comme de l''huile dans ses os!'),
  (19, 109, 19, 'Qu''elle lui serve de vêtement pour se couvrir, De ceinture dont il soit toujours ceint!'),
  (19, 109, 20, 'Tel soit, de la part de l''Éternel, le salaire de mes ennemis, Et de ceux qui parlent méchamment de moi!'),
  (19, 109, 21, 'Et toi, Éternel, Seigneur! agis en ma faveur à cause de ton nom, Car ta bonté est grande; délivre-moi!'),
  (19, 109, 22, 'Je suis malheureux et indigent, Et mon cœur est blessé au dedans de moi.'),
  (19, 109, 23, 'Je m''en vais comme l''ombre à son déclin, Je suis chassé comme la sauterelle.'),
  (19, 109, 24, 'Mes genoux sont affaiblis par le jeûne, Et mon corps est épuisé de maigreur.'),
  (19, 109, 25, 'Je suis pour eux un objet d''opprobre; Ils me regardent, et secouent la tête.'),
  (19, 109, 26, 'Secours-moi, Éternel, mon Dieu! Sauve-moi par ta bonté!'),
  (19, 109, 27, 'Et qu''ils sachent que c''est ta main, Que c''est toi, Éternel, qui l''as fait!'),
  (19, 109, 28, 'S''ils maudissent, toi tu béniras; S''ils se lèvent, ils seront confus, Et ton serviteur se réjouira.'),
  (19, 109, 29, 'Que mes adversaires revêtent l''ignominie, Qu''ils se couvrent de leur honte comme d''un manteau!'),
  (19, 109, 30, 'Je louerai de ma bouche hautement l''Éternel, Je le célébrerai au milieu de la multitude;'),
  (19, 109, 31, 'Car il se tient à la droite du pauvre, Pour le délivrer de ceux qui le condamnent.'),
  (19, 110, 1, 'De David. Psaume. Parole de l''Éternel à mon Seigneur: Assieds-toi à ma droite, Jusqu''à ce que je fasse de tes ennemis ton marchepied.'),
  (19, 110, 2, 'L''Éternel étendra de Sion le sceptre de ta puissance: Domine au milieu de tes ennemis!'),
  (19, 110, 3, 'Ton peuple est plein d''ardeur, quand tu rassembles ton armée; Avec des ornements sacrés, du sein de l''aurore Ta jeunesse vient à toi comme une rosée.'),
  (19, 110, 4, 'L''Éternel l''a juré, et il ne s''en repentira point: Tu es sacrificateur pour toujours, A la manière de Melchisédek.'),
  (19, 110, 5, 'Le Seigneur, à ta droite, Brise des rois au jour de sa colère.'),
  (19, 110, 6, 'Il exerce la justice parmi les nations: tout est plein de cadavres; Il brise des têtes sur toute l''étendue du pays.'),
  (19, 110, 7, 'Il boit au torrent pendant la marche: C''est pourquoi il relève la tête.'),
  (19, 111, 1, 'Louez l''Éternel! Je louerai l''Éternel de tout mon cœur, Dans la réunion des hommes droits et dans l''assemblée.'),
  (19, 111, 2, 'Les œuvres de l''Éternel sont grandes, Recherchées par tous ceux qui les aiment.'),
  (19, 111, 3, 'Son œuvre n''est que splendeur et magnificence, Et sa justice subsiste à jamais.'),
  (19, 111, 4, 'Il a laissé la mémoire de ses prodiges, L''Éternel est miséricordieux et compatissant.'),
  (19, 111, 5, 'Il a donné de la nourriture à ceux qui le craignent; Il se souvient toujours de son alliance.'),
  (19, 111, 6, 'Il a manifesté à son peuple la puissance de ses œuvres, En lui livrant l''héritage des nations.'),
  (19, 111, 7, 'Les œuvres de ses mains sont fidélité et justice; Toutes ses ordonnances sont véritables,'),
  (19, 111, 8, 'Affermies pour l''éternité, Faites avec fidélité et droiture.'),
  (19, 111, 9, 'Il a envoyé la délivrance à son peuple, Il a établi pour toujours son alliance; Son nom est saint et redoutable.'),
  (19, 111, 10, 'La crainte de l''Éternel est le commencement de la sagesse; Tous ceux qui l''observent ont une raison saine. Sa gloire subsiste à jamais.'),
  (19, 112, 1, 'Louez l''Éternel! Heureux l''homme qui craint l''Éternel, Qui trouve un grand plaisir à ses commandements.'),
  (19, 112, 2, 'Sa postérité sera puissante sur la terre, La génération des hommes droits sera bénie.'),
  (19, 112, 3, 'Il a dans sa maison bien-être et richesse, Et sa justice subsiste à jamais.'),
  (19, 112, 4, 'La lumière se lève dans les ténèbres pour les hommes droits, Pour celui qui est miséricordieux, compatissant et juste.'),
  (19, 112, 5, 'Heureux l''homme qui exerce la miséricorde et qui prête. Qui règle ses actions d''après la justice.'),
  (19, 112, 6, 'Car il ne chancelle jamais; La mémoire du juste dure toujours.'),
  (19, 112, 7, 'Il ne craint point les mauvaises nouvelles; Son cœur est ferme, confiant en l''Éternel.'),
  (19, 112, 8, 'Son cœur est affermi; il n''a point de crainte, Jusqu''à ce qu''il mette son plaisir à regarder ses adversaires.'),
  (19, 112, 9, 'Il fait des largesses, il donne aux indigents; Sa justice subsiste à jamais; Sa tête s''élève avec gloire,'),
  (19, 112, 10, 'Le méchant le voit et s''irrite, Il grince les dents et se consume; Les désirs des méchants périssent.'),
  (19, 113, 1, 'Louez l''Éternel! Serviteurs de l''Éternel, louez, Louez le nom de l''Éternel!'),
  (19, 113, 2, 'Que le nom de l''Éternel soit béni, Dès maintenant et à jamais!'),
  (19, 113, 3, 'Du lever du soleil jusqu''à son couchant, Que le nom de l''Éternel soit célébré!'),
  (19, 113, 4, 'L''Éternel est élevé au-dessus de toutes les nations, Sa gloire est au-dessus des cieux.'),
  (19, 113, 5, 'Qui est semblable à l''Éternel, notre Dieu? Il a sa demeure en haut;'),
  (19, 113, 6, 'Il abaisse les regards Sur les cieux et sur la terre.'),
  (19, 113, 7, 'De la poussière il retire le pauvre, Du fumier il relève l''indigent,'),
  (19, 113, 8, 'Pour les faire asseoir avec les grands, Avec les grands de son peuple.'),
  (19, 113, 9, 'Il donne une maison à celle qui était stérile, Il en fait une mère joyeuse au milieu de ses enfants. Louez l''Éternel!'),
  (19, 114, 1, 'Quand Israël sortit d''Égypte, Quand la maison de Jacob s''éloigna d''un peuple barbare,'),
  (19, 114, 2, 'Juda devint son sanctuaire, Israël fut son domaine.'),
  (19, 114, 3, 'La mer le vit et s''enfuit, Le Jourdain retourna en arrière;'),
  (19, 114, 4, 'Les montagnes sautèrent comme des béliers, Les collines comme des agneaux.'),
  (19, 114, 5, 'Qu''as-tu, mer, pour t''enfuir, Jourdain, pour retourner en arrière?'),
  (19, 114, 6, 'Qu''avez-vous, montagnes, pour sauter comme des béliers, Et vous, collines, comme des agneaux?'),
  (19, 114, 7, 'Tremble devant le Seigneur, ô terre! Devant le Dieu de Jacob,'),
  (19, 114, 8, 'Qui change le rocher en étang, Le roc en source d''eaux.'),
  (19, 115, 1, 'Non pas à nous, Éternel, non pas à nous, Mais à ton nom donne gloire, A cause de ta bonté, à cause de ta fidélité!'),
  (19, 115, 2, 'Pourquoi les nations diraient-elles: Où donc est leur Dieu?'),
  (19, 115, 3, 'Notre Dieu est au ciel, Il fait tout ce qu''il veut.'),
  (19, 115, 4, 'Leurs idoles sont de l''argent et de l''or, Elles sont l''ouvrage de la main des hommes.'),
  (19, 115, 5, 'Elles ont une bouche et ne parlent point, Elles ont des yeux et ne voient point,'),
  (19, 115, 6, 'Elles ont des oreilles et n''entendent point, Elles ont un nez et ne sentent point,'),
  (19, 115, 7, 'Elles ont des mains et ne touchent point, Des pieds et ne marchent point, Elles ne produisent aucun son dans leur gosier.'),
  (19, 115, 8, 'Ils leur ressemblent, ceux qui les fabriquent, Tous ceux qui se confient en elles.'),
  (19, 115, 9, 'Israël, confie-toi en l''Éternel! Il est leur secours et leur bouclier.'),
  (19, 115, 10, 'Maison d''Aaron, confie-toi en l''Éternel! Il est leur secours et leur bouclier.'),
  (19, 115, 11, 'Vous qui craignez l''Éternel, confiez-vous en l''Éternel! Il est leur secours et leur bouclier.'),
  (19, 115, 12, 'L''Éternel se souvient de nous: il bénira, Il bénira la maison d''Israël, Il bénira la maison d''Aaron,'),
  (19, 115, 13, 'Il bénira ceux qui craignent l''Éternel, les petits et les grands;'),
  (19, 115, 14, 'L''Éternel vous multipliera ses faveurs, A vous et à vos enfants.'),
  (19, 115, 15, 'Soyez bénis par l''Éternel, Qui a fait les cieux et la terre!'),
  (19, 115, 16, 'Les cieux sont les cieux de l''Éternel, Mais il a donné la terre aux fils de l''homme.'),
  (19, 115, 17, 'Ce ne sont pas les morts qui célèbrent l''Éternel, Ce n''est aucun de ceux qui descendent dans le lieu du silence;'),
  (19, 115, 18, 'Mais nous, nous bénirons l''Éternel, Dès maintenant et à jamais. Louez l''Éternel!'),
  (19, 116, 1, 'J''aime l''Éternel, car il entend Ma voix, mes supplications;'),
  (19, 116, 2, 'Car il a penché son oreille vers moi; Et je l''invoquerai toute ma vie.'),
  (19, 116, 3, 'Les liens de la mort m''avaient environné, Et les angoisses du sépulcre m''avaient saisi; J''étais en proie à la détresse et à la douleur.'),
  (19, 116, 4, 'Mais j''invoquai le nom de l''Éternel: O Éternel, sauve mon âme!'),
  (19, 116, 5, 'L''Éternel est miséricordieux et juste, Notre Dieu est plein de compassion;'),
  (19, 116, 6, 'L''Éternel garde les simples; J''étais malheureux, et il m''a sauvé.'),
  (19, 116, 7, 'Mon âme, retourne à ton repos, Car l''Éternel t''a fait du bien.'),
  (19, 116, 8, 'Oui, tu as délivré mon âme de la mort, Mes yeux des larmes, Mes pieds de la chute.'),
  (19, 116, 9, 'Je marcherai devant l''Éternel, Sur la terre des vivants.'),
  (19, 116, 10, 'J''avais confiance, lorsque je disais: Je suis bien malheureux!'),
  (19, 116, 11, 'Je disais dans mon angoisse: Tout homme est trompeur.'),
  (19, 116, 12, 'Comment rendrai-je à l''Éternel Tous ses bienfaits envers moi?'),
  (19, 116, 13, 'J''élèverai la coupe des délivrances, Et j''invoquerai le nom de l''Éternel;'),
  (19, 116, 14, 'J''accomplirai mes vœux envers l''Éternel, En présence de tout son peuple.'),
  (19, 116, 15, 'Elle a du prix aux yeux de l''Éternel, La mort de ceux qui l''aiment.'),
  (19, 116, 16, 'Écoute-moi, ô Éternel! car je suis ton serviteur, Ton serviteur, fils de ta servante. Tu as détaché mes liens.'),
  (19, 116, 17, 'Je t''offrirai un sacrifice d''actions de grâces, Et j''invoquerai le nom de l''Éternel;'),
  (19, 116, 18, 'J''accomplirai mes vœux envers l''Éternel, En présence de tout son peuple,'),
  (19, 116, 19, 'Dans les parvis de la maison de l''Éternel, Au milieu de toi, Jérusalem! Louez l''Éternel!'),
  (19, 117, 1, 'Louez l''Éternel, vous toutes les nations, Célébrez-le, vous tous les peuples!'),
  (19, 117, 2, 'Car sa bonté pour nous est grande, Et sa fidélité dure à toujours. Louez l''Éternel!'),
  (19, 118, 1, 'Louez l''Éternel, car il est bon, Car sa miséricorde dure à toujours!'),
  (19, 118, 2, 'Qu''Israël dise: Car sa miséricorde dure à toujours!'),
  (19, 118, 3, 'Que la maison d''Aaron dise: Car sa miséricorde dure à toujours!'),
  (19, 118, 4, 'Que ceux qui craignent l''Éternel disent: Car sa miséricorde dure à toujours!'),
  (19, 118, 5, 'Du sein de la détresse j''ai invoqué l''Éternel: L''Éternel m''a exaucé, m''a mis au large.'),
  (19, 118, 6, 'L''Éternel est pour moi, je ne crains rien: Que peuvent me faire des hommes?'),
  (19, 118, 7, 'L''Éternel est mon secours, Et je me réjouis à la vue de mes ennemis.'),
  (19, 118, 8, 'Mieux vaut chercher un refuge en l''Éternel Que de se confier à l''homme;'),
  (19, 118, 9, 'Mieux vaut chercher un refuge en l''Éternel Que de se confier aux grands.'),
  (19, 118, 10, 'Toutes les nations m''environnaient: Au nom de l''Éternel, je les taille en pièces.'),
  (19, 118, 11, 'Elles m''environnaient, m''enveloppaient: Au nom de l''Éternel, je les taille en pièces.'),
  (19, 118, 12, 'Elles m''environnaient comme des abeilles; Elles s''éteignent comme un feu d''épines; Au nom de l''Éternel, je les taille en pièces.'),
  (19, 118, 13, 'Tu me poussais pour me faire tomber; Mais l''Éternel m''a secouru.'),
  (19, 118, 14, 'L''Éternel est ma force et le sujet de mes louanges; C''est lui qui m''a sauvé.'),
  (19, 118, 15, 'Des cris de triomphe et de salut s''élèvent dans les tentes des justes: La droite de l''Éternel manifeste sa puissance!'),
  (19, 118, 16, 'La droite de l''Éternel est élevée! La droite de l''Éternel manifeste sa puissance!'),
  (19, 118, 17, 'Je ne mourrai pas, je vivrai, Et je raconterai les œuvres de l''Éternel.'),
  (19, 118, 18, 'L''Éternel m''a châtié, Mais il ne m''a pas livré à la mort.'),
  (19, 118, 19, 'Ouvrez-moi les portes de la justice: J''entrerai, je louerai l''Éternel.'),
  (19, 118, 20, 'Voici la porte de l''Éternel: C''est par elle qu''entrent les justes.'),
  (19, 118, 21, 'Je te loue, parce que tu m''as exaucé, Parce que tu m''as sauvé.'),
  (19, 118, 22, 'La pierre qu''ont rejetée ceux qui bâtissaient Est devenue la principale de l''angle.'),
  (19, 118, 23, 'C''est de l''Éternel que cela est venu: C''est un prodige à nos yeux.'),
  (19, 118, 24, 'C''est ici la journée que l''Éternel a faite: Qu''elle soit pour nous un sujet d''allégresse et de joie!'),
  (19, 118, 25, 'O Éternel, accorde le salut! O Éternel, donne la prospérité!'),
  (19, 118, 26, 'Béni soit celui qui vient au nom de l''Éternel! Nous vous bénissons de la maison de l''Éternel.'),
  (19, 118, 27, 'L''Éternel est Dieu, et il nous éclaire. Attachez la victime avec des liens, Amenez-la jusqu''aux cornes de l''autel!'),
  (19, 118, 28, 'Tu es mon Dieu, et je te louerai; Mon Dieu! je t''exalterai.'),
  (19, 118, 29, 'Louez l''Éternel, car il est bon, Car sa miséricorde dure à toujours!'),
  (19, 119, 1, 'Heureux ceux qui sont intègres dans leur voie, Qui marchent selon la loi de l''Éternel!'),
  (19, 119, 2, 'Heureux ceux qui gardent ses préceptes, Qui le cherchent de tout leur cœur,'),
  (19, 119, 3, 'Qui ne commettent point d''iniquité, Et qui marchent dans ses voies!'),
  (19, 119, 4, 'Tu as prescrit tes ordonnances, Pour qu''on les observe avec soin.'),
  (19, 119, 5, 'Puissent mes actions être bien réglées, Afin que je garde tes statuts!'),
  (19, 119, 6, 'Alors je ne rougirai point, A la vue de tous tes commandements.'),
  (19, 119, 7, 'Je te louerai dans la droiture de mon cœur, En apprenant les lois de ta justice.'),
  (19, 119, 8, 'Je veux garder tes statuts: Ne m''abandonne pas entièrement!'),
  (19, 119, 9, 'Comment le jeune homme rendra-t-il pur son sentier? En se dirigeant d''après ta parole.'),
  (19, 119, 10, 'Je te cherche de tout mon cœur: Ne me laisse pas égarer loin de tes commandements!'),
  (19, 119, 11, 'Je serre ta parole dans mon cœur, Afin de ne pas pécher contre toi.'),
  (19, 119, 12, 'Béni sois-tu, ô Éternel! Enseigne-moi tes statuts!'),
  (19, 119, 13, 'De mes lèvres j''énumère Toutes les sentences de ta bouche.'),
  (19, 119, 14, 'Je me réjouis en suivant tes préceptes, Comme si je possédais tous les trésors.'),
  (19, 119, 15, 'Je médite tes ordonnances, J''ai tes sentiers sous les yeux.'),
  (19, 119, 16, 'Je fais mes délices de tes statuts, Je n''oublie point ta parole.'),
  (19, 119, 17, 'Fais du bien à ton serviteur, pour que je vive Et que j''observe ta parole!'),
  (19, 119, 18, 'Ouvre mes yeux, pour que je contemple Les merveilles de ta loi!'),
  (19, 119, 19, 'Je suis un étranger sur la terre: Ne me cache pas tes commandements!'),
  (19, 119, 20, 'Mon âme est brisée par le désir Qui toujours la porte vers tes lois.'),
  (19, 119, 21, 'Tu menaces les orgueilleux, ces maudits, Qui s''égarent loin de tes commandements.'),
  (19, 119, 22, 'Décharge-moi de l''opprobre et du mépris! Car j''observe tes préceptes.'),
  (19, 119, 23, 'Des princes ont beau s''asseoir et parler contre moi, Ton serviteur médite tes statuts.'),
  (19, 119, 24, 'Tes préceptes font mes délices, Ce sont mes conseillers.'),
  (19, 119, 25, 'Mon âme est attachée à la poussière: Rends-moi la vie selon ta parole!'),
  (19, 119, 26, 'Je raconte mes voies, et tu m''exauces: Enseigne-moi tes statuts!'),
  (19, 119, 27, 'Fais-moi comprendre la voie de tes ordonnances, Et je méditerai sur tes merveilles!'),
  (19, 119, 28, 'Mon âme pleure de chagrin: Relève-moi selon ta parole!'),
  (19, 119, 29, 'Éloigne de moi la voie du mensonge, Et accorde-moi la grâce de suivre ta loi!'),
  (19, 119, 30, 'Je choisis la voie de la vérité, Je place tes lois sous mes yeux.'),
  (19, 119, 31, 'Je m''attache à tes préceptes: Éternel, ne me rends point confus!'),
  (19, 119, 32, 'Je cours dans la voie de tes commandements, Car tu élargis mon cœur.'),
  (19, 119, 33, 'Enseigne-moi, Éternel, la voie de tes statuts, pour que je la retienne jusqu''à la fin!'),
  (19, 119, 34, 'Donne-moi l''intelligence, pour que je garde ta loi Et que je l''observe de tout mon cœur!'),
  (19, 119, 35, 'Conduis-moi dans le sentier de tes commandements! Car je l''aime.'),
  (19, 119, 36, 'Incline mon cœur vers tes préceptes, Et non vers le gain!'),
  (19, 119, 37, 'Détourne mes yeux de la vue des choses vaines, Fais-moi vivre dans ta voie!'),
  (19, 119, 38, 'Accomplis envers ton serviteur ta promesse, Qui est pour ceux qui te craignent!'),
  (19, 119, 39, 'Éloigne de moi l''opprobre que je redoute! Car tes jugements sont pleins de bonté.'),
  (19, 119, 40, 'Voici, je désire pratiquer tes ordonnances: Fais-moi vivre dans ta justice!'),
  (19, 119, 41, 'Éternel, que ta miséricorde vienne sur moi, Ton salut selon ta promesse!'),
  (19, 119, 42, 'Et je pourrai répondre à celui qui m''outrage, Car je me confie en ta parole.'),
  (19, 119, 43, 'N''ôte pas entièrement de ma bouche la parole de la vérité! Car j''espère en tes jugements.'),
  (19, 119, 44, 'Je garderai ta loi constamment, A toujours et à perpétuité.'),
  (19, 119, 45, 'Je marcherai au large, Car je recherche tes ordonnances.'),
  (19, 119, 46, 'Je parlerai de tes préceptes devant les rois, Et je ne rougirai point.'),
  (19, 119, 47, 'Je fais mes délices de tes commandements. Je les aime.'),
  (19, 119, 48, 'Je lève mes mains vers tes commandements que j''aime, Et je veux méditer tes statuts.'),
  (19, 119, 49, 'Souviens-toi de ta promesse à ton serviteur, Puisque tu m''as donné l''espérance!'),
  (19, 119, 50, 'C''est ma consolation dans ma misère, Car ta promesse me rend la vie.'),
  (19, 119, 51, 'Des orgueilleux me chargent de railleries; Je ne m''écarte point de ta loi.'),
  (19, 119, 52, 'Je pense à tes jugements d''autrefois, ô Éternel! Et je me console.'),
  (19, 119, 53, 'Une colère ardente me saisit à la vue des méchants Qui abandonnent ta loi.'),
  (19, 119, 54, 'Tes statuts sont le sujet de mes cantiques, Dans la maison où je suis étranger.'),
  (19, 119, 55, 'La nuit je me rappelle ton nom, ô Éternel! Et je garde ta loi.'),
  (19, 119, 56, 'C''est là ce qui m''est propre, Car j''observe tes ordonnances.'),
  (19, 119, 57, 'Ma part, ô Éternel! je le dis, C''est de garder tes paroles.'),
  (19, 119, 58, 'Je t''implore de tout mon cœur: Aie pitié de moi, selon ta promesse!'),
  (19, 119, 59, 'Je réfléchis à mes voies, Et je dirige mes pieds vers tes préceptes.'),
  (19, 119, 60, 'Je me hâte, je ne diffère point D''observer tes commandements.'),
  (19, 119, 61, 'Les pièges des méchants m''environnent; Je n''oublie point ta loi.'),
  (19, 119, 62, 'Au milieu de la nuit je me lève pour te louer, A cause des jugements de ta justice.'),
  (19, 119, 63, 'Je suis l''ami de tous ceux qui te craignent, Et de ceux qui gardent tes ordonnances.'),
  (19, 119, 64, 'La terre, ô Éternel! est pleine de ta bonté; Enseigne-moi tes statuts!'),
  (19, 119, 65, 'Tu fais du bien à ton serviteur, O Éternel! selon ta promesse.'),
  (19, 119, 66, 'Enseigne-moi le bon sens et l''intelligence! Car je crois à tes commandements.'),
  (19, 119, 67, 'Avant d''avoir été humilié, je m''égarais; Maintenant j''observe ta parole.'),
  (19, 119, 68, 'Tu es bon et bienfaisant; Enseigne-moi tes statuts!'),
  (19, 119, 69, 'Des orgueilleux imaginent contre moi des faussetés; Moi, je garde de tout mon cœur tes ordonnances.'),
  (19, 119, 70, 'Leur cœur est insensible comme la graisse; Moi, je fais mes délices de ta loi.'),
  (19, 119, 71, 'Il m''est bon d''être humilié, Afin que j''apprenne tes statuts.'),
  (19, 119, 72, 'Mieux vaut pour moi la loi de ta bouche Que mille objets d''or et d''argent.'),
  (19, 119, 73, 'Tes mains m''ont créé, elles m''ont formé; Donne-moi l''intelligence, pour que j''apprenne tes commandements!'),
  (19, 119, 74, 'Ceux qui te craignent me voient et se réjouissent, Car j''espère en tes promesses.'),
  (19, 119, 75, 'Je sais, ô Éternel! que tes jugements sont justes; C''est par fidélité que tu m''as humilié.'),
  (19, 119, 76, 'Que ta bonté soit ma consolation, Comme tu l''as promis à ton serviteur!'),
  (19, 119, 77, 'Que tes compassions viennent sur moi, pour que je vive! Car ta loi fait mes délices.'),
  (19, 119, 78, 'Qu''ils soient confondus, les orgueilleux qui m''oppriment sans cause! Moi, je médite sur tes ordonnances.'),
  (19, 119, 79, 'Qu''ils reviennent à moi, ceux qui te craignent, Et ceux qui connaissent tes préceptes!'),
  (19, 119, 80, 'Que mon cœur soit sincère dans tes statuts, Afin que je ne sois pas couvert de honte!'),
  (19, 119, 81, 'Mon âme languit après ton salut; J''espère en ta promesse.'),
  (19, 119, 82, 'Mes yeux languissent après ta promesse; Je dis: Quand me consoleras-tu?'),
  (19, 119, 83, 'Car je suis comme une outre dans la fumée; Je n''oublie point tes statuts.'),
  (19, 119, 84, 'Quel est le nombre des jours de ton serviteur? Quand feras-tu justice de ceux qui me persécutent?'),
  (19, 119, 85, 'Des orgueilleux creusent des fosses devant moi; Ils n''agissent point selon ta loi.'),
  (19, 119, 86, 'Tous tes commandements ne sont que fidélité; Ils me persécutent sans cause: secours-moi!'),
  (19, 119, 87, 'Ils ont failli me terrasser et m''anéantir; Et moi, je n''abandonne point tes ordonnances.'),
  (19, 119, 88, 'Rends-moi la vie selon ta bonté, Afin que j''observe les préceptes de ta bouche!'),
  (19, 119, 89, 'A toujours, ô Éternel! Ta parole subsiste dans les cieux.'),
  (19, 119, 90, 'De génération en génération ta fidélité subsiste; Tu as fondé la terre, et elle demeure ferme.'),
  (19, 119, 91, 'C''est d''après tes lois que tout subsiste aujourd''hui, Car toutes choses te sont assujetties.'),
  (19, 119, 92, 'Si ta loi n''eût fait mes délices, J''eusse alors péri dans ma misère.'),
  (19, 119, 93, 'Je n''oublierai jamais tes ordonnances, Car c''est par elles que tu me rends la vie.'),
  (19, 119, 94, 'Je suis à toi: sauve-moi! Car je recherche tes ordonnances.'),
  (19, 119, 95, 'Des méchants m''attendent pour me faire périr; Je suis attentif à tes préceptes.'),
  (19, 119, 96, 'Je vois des bornes à tout ce qui est parfait: Tes commandements n''ont point de limite.'),
  (19, 119, 97, 'Combien j''aime ta loi! Elle est tout le jour l''objet de ma méditation.'),
  (19, 119, 98, 'Tes commandements me rendent plus sage que mes ennemis, Car je les ai toujours avec moi.'),
  (19, 119, 99, 'Je suis plus instruit que tous mes maîtres, Car tes préceptes sont l''objet de ma méditation.'),
  (19, 119, 100, 'J''ai plus d''intelligence que les vieillards, Car j''observe tes ordonnances.'),
  (19, 119, 101, 'Je retiens mon pied loin de tout mauvais chemin, Afin de garder ta parole.')
insert into public.bible_verses (book_id, chapter, verse, text) values
  (19, 119, 102, 'Je ne m''écarte pas de tes lois, Car c''est toi qui m''enseignes.'),
  (19, 119, 103, 'Que tes paroles sont douces à mon palais, Plus que le miel à ma bouche!'),
  (19, 119, 104, 'Par tes ordonnances je deviens intelligent, Aussi je hais toute voie de mensonge.'),
  (19, 119, 105, 'Ta parole est une lampe à mes pieds, Et une lumière sur mon sentier.'),
  (19, 119, 106, 'Je jure, et je le tiendrai, D''observer les lois de ta justice.'),
  (19, 119, 107, 'Je suis bien humilié: Éternel, rends-moi la vie selon ta parole!'),
  (19, 119, 108, 'Agrée, ô Éternel! les sentiments que ma bouche exprime, Et enseigne-moi tes lois!'),
  (19, 119, 109, 'Ma vie est continuellement exposée, Et je n''oublie point ta loi.'),
  (19, 119, 110, 'Des méchants me tendent des pièges, Et je ne m''égare pas loin de tes ordonnances.'),
  (19, 119, 111, 'Tes préceptes sont pour toujours mon héritage, Car ils sont la joie de mon cœur.'),
  (19, 119, 112, 'J''incline mon cœur à pratiquer tes statuts, Toujours, jusqu''à la fin.'),
  (19, 119, 113, 'Je hais les hommes indécis, Et j''aime ta loi.'),
  (19, 119, 114, 'Tu es mon asile et mon bouclier; J''espère en ta promesse.'),
  (19, 119, 115, 'Éloignez-vous de moi, méchants, Afin que j''observe les commandements de mon Dieu!'),
  (19, 119, 116, 'Soutiens-moi selon ta promesse, afin que je vive, Et ne me rends point confus dans mon espérance!'),
  (19, 119, 117, 'Sois mon appui, pour que je sois sauvé, Et que je m''occupe sans cesse de tes statuts!'),
  (19, 119, 118, 'Tu méprises tous ceux qui s''écartent de tes statuts, Car leur tromperie est sans effet.'),
  (19, 119, 119, 'Tu enlèves comme de l''écume tous les méchants de la terre; C''est pourquoi j''aime tes préceptes.'),
  (19, 119, 120, 'Ma chair frissonne de l''effroi que tu m''inspires, Et je crains tes jugements.'),
  (19, 119, 121, 'J''observe la loi et la justice: Ne m''abandonne pas à mes oppresseurs!'),
  (19, 119, 122, 'Prends sous ta garantie le bien de ton serviteur, Ne me laisse pas opprimer par des orgueilleux!'),
  (19, 119, 123, 'Mes yeux languissent après ton salut, Et après la promesse de ta justice.'),
  (19, 119, 124, 'Agis envers ton serviteur selon ta bonté, Et enseigne-moi tes statuts!'),
  (19, 119, 125, 'Je suis ton serviteur: donne-moi l''intelligence, Pour que je connaisse tes préceptes!'),
  (19, 119, 126, 'Il est temps que l''Éternel agisse: Ils transgressent ta loi.'),
  (19, 119, 127, 'C''est pourquoi j''aime tes commandements, Plus que l''or et que l''or fin;'),
  (19, 119, 128, 'C''est pourquoi je trouve justes toutes tes ordonnances, Je hais toute voie de mensonge.'),
  (19, 119, 129, 'Tes préceptes sont admirables: Aussi mon âme les observe.'),
  (19, 119, 130, 'La révélation de tes paroles éclaire, Elle donne de l''intelligence aux simples.'),
  (19, 119, 131, 'J''ouvre la bouche et je soupire, Car je suis avide de tes commandements.'),
  (19, 119, 132, 'Tourne vers moi ta face, et aie pitié de moi, Selon ta coutume à l''égard de ceux qui aiment ton nom!'),
  (19, 119, 133, 'Affermis mes pas dans ta parole, Et ne laisse aucune iniquité dominer sur moi!'),
  (19, 119, 134, 'Délivre-moi de l''oppression des hommes, Afin que je garde tes ordonnances!'),
  (19, 119, 135, 'Fais luire ta face sur ton serviteur, Et enseigne-moi tes statuts!'),
  (19, 119, 136, 'Mes yeux répandent des torrents d''eaux, Parce qu''on n''observe point ta loi.'),
  (19, 119, 137, 'Tu es juste, ô Éternel! Et tes jugements sont équitables;'),
  (19, 119, 138, 'Tu fondes tes préceptes sur la justice Et sur la plus grande fidélité.'),
  (19, 119, 139, 'Mon zèle me consume, Parce que mes adversaires oublient tes paroles.'),
  (19, 119, 140, 'Ta parole est entièrement éprouvée, Et ton serviteur l''aime.'),
  (19, 119, 141, 'Je suis petit et méprisé; Je n''oublie point tes ordonnances.'),
  (19, 119, 142, 'Ta justice est une justice éternelle, Et ta loi est la vérité.'),
  (19, 119, 143, 'La détresse et l''angoisse m''atteignent: Tes commandements font mes délices.'),
  (19, 119, 144, 'Tes préceptes sont éternellement justes: Donne-moi l''intelligence, pour que je vive!'),
  (19, 119, 145, 'Je t''invoque de tout mon cœur: exauce-moi, Éternel, Afin que je garde tes statuts!'),
  (19, 119, 146, 'Je t''invoque: sauve-moi, Afin que j''observe tes préceptes!'),
  (19, 119, 147, 'Je devance l''aurore et je crie; J''espère en tes promesses.'),
  (19, 119, 148, 'Je devance les veilles et j''ouvre les yeux, Pour méditer ta parole.'),
  (19, 119, 149, 'Écoute ma voix selon ta bonté! Rends-moi la vie selon ton jugement!'),
  (19, 119, 150, 'Ils s''approchent, ceux qui poursuivent le crime, Ils s''éloignent de la loi.'),
  (19, 119, 151, 'Tu es proche, ô Éternel! Et tous tes commandements sont la vérité.'),
  (19, 119, 152, 'Dès longtemps je sais par tes préceptes Que tu les as établis pour toujours.'),
  (19, 119, 153, 'Vois ma misère, et délivre-moi! Car je n''oublie point ta loi.'),
  (19, 119, 154, 'Défends ma cause, et rachète-moi; Rends-moi la vie selon ta promesse!'),
  (19, 119, 155, 'Le salut est loin des méchants, Car ils ne recherchent pas tes statuts.'),
  (19, 119, 156, 'Tes compassions sont grandes, ô Éternel! Rends-moi la vie selon tes jugements!'),
  (19, 119, 157, 'Mes persécuteurs et mes adversaires sont nombreux; Je ne m''écarte point de tes préceptes,'),
  (19, 119, 158, 'Je vois avec dégoût des traîtres Qui n''observent pas ta parole.'),
  (19, 119, 159, 'Considère que j''aime tes ordonnances: Éternel, rends-moi la vie selon ta bonté!'),
  (19, 119, 160, 'Le fondement de ta parole est la vérité, Et toutes les lois de ta justice sont éternelles.'),
  (19, 119, 161, 'Des princes me persécutent sans cause; Mais mon cœur ne tremble qu''à tes paroles.'),
  (19, 119, 162, 'Je me réjouis de ta parole, Comme celui qui trouve un grand butin.'),
  (19, 119, 163, 'Je hais, je déteste le mensonge; J''aime ta loi.'),
  (19, 119, 164, 'Sept fois le jour je te célèbre, A cause des lois de ta justice.'),
  (19, 119, 165, 'Il y a beaucoup de paix pour ceux qui aiment ta loi, Et il ne leur arrive aucun malheur.'),
  (19, 119, 166, 'J''espère en ton salut, ô Éternel! Et je pratique tes commandements.'),
  (19, 119, 167, 'Mon âme observe tes préceptes, Et je les aime beaucoup.'),
  (19, 119, 168, 'Je garde tes ordonnances et tes préceptes, Car toutes mes voies sont devant toi.'),
  (19, 119, 169, 'Que mon cri parvienne jusqu''à toi, ô Éternel! Donne-moi l''intelligence, selon ta promesse!'),
  (19, 119, 170, 'Que ma supplication arrive jusqu''à toi! Délivre-moi, selon ta promesse!'),
  (19, 119, 171, 'Que mes lèvres publient ta louange! Car tu m''enseignes tes statuts.'),
  (19, 119, 172, 'Que ma langue chante ta parole! Car tous tes commandements sont justes.'),
  (19, 119, 173, 'Que ta main me soit en aide! Car j''ai choisi tes ordonnances.'),
  (19, 119, 174, 'Je soupire après ton salut, ô Éternel! Et ta loi fait mes délices.'),
  (19, 119, 175, 'Que mon âme vive et qu''elle te loue! Et que tes jugements me soutiennent!'),
  (19, 119, 176, 'Je suis errant comme une brebis perdue; cherche ton serviteur, Car je n''oublie point tes commandements.'),
  (19, 120, 1, 'Cantique des degrés. Dans ma détresse, c''est à l''Éternel Que je crie, et il m''exauce.'),
  (19, 120, 2, 'Éternel, délivre mon âme de la lèvre mensongère, De la langue trompeuse!'),
  (19, 120, 3, 'Que te donne, que te rapporte Une langue trompeuse?'),
  (19, 120, 4, 'Les traits aigus du guerrier, Avec les charbons ardents du genêt.'),
  (19, 120, 5, 'Malheureux que je suis de séjourner à Méschec, D''habiter parmi les tentes de Kédar!'),
  (19, 120, 6, 'Assez longtemps mon âme a demeuré Auprès de ceux qui haïssent la paix.'),
  (19, 120, 7, 'Je suis pour la paix; mais dès que je parle, Ils sont pour la guerre.'),
  (19, 121, 1, 'Cantique des degrés. Je lève mes yeux vers les montagnes… D''où me viendra le secours?'),
  (19, 121, 2, 'Le secours me vient de l''Éternel, Qui a fait les cieux et la terre.'),
  (19, 121, 3, 'Il ne permettra point que ton pied chancelle; Celui qui te garde ne sommeillera point.'),
  (19, 121, 4, 'Voici, il ne sommeille ni ne dort, Celui qui garde Israël.'),
  (19, 121, 5, 'L''Éternel est celui qui te garde, L''Éternel est ton ombre à ta main droite.'),
  (19, 121, 6, 'Pendant le jour le soleil ne te frappera point, Ni la lune pendant la nuit.'),
  (19, 121, 7, 'L''Éternel te gardera de tout mal, Il gardera ton âme;'),
  (19, 121, 8, 'L''Éternel gardera ton départ et ton arrivée, Dès maintenant et à jamais.'),
  (19, 122, 1, 'Cantique des degrés. De David. Je suis dans la joie quand on me dit: Allons à la maison de l''Éternel!'),
  (19, 122, 2, 'Nos pieds s''arrêtent Dans tes portes, Jérusalem!'),
  (19, 122, 3, 'Jérusalem, tu es bâtie Comme une ville dont les parties sont liées ensemble.'),
  (19, 122, 4, 'C''est là que montent les tribus, les tribus de l''Éternel, Selon la loi d''Israël, Pour louer le nom de l''Éternel.'),
  (19, 122, 5, 'Car là sont les trônes pour la justice, Les trônes de la maison de David.'),
  (19, 122, 6, 'Demandez la paix de Jérusalem. Que ceux qui t''aiment jouissent du repos!'),
  (19, 122, 7, 'Que la paix soit dans tes murs, Et la tranquillité dans tes palais!'),
  (19, 122, 8, 'A cause de mes frères et de mes amis, Je désire la paix dans ton sein;'),
  (19, 122, 9, 'A cause de la maison de l''Éternel, notre Dieu, Je fais des vœux pour ton bonheur.'),
  (19, 123, 1, 'Cantique des degrés, Je lève mes yeux vers toi, Qui sièges dans les cieux.'),
  (19, 123, 2, 'Voici, comme les yeux des serviteurs sont fixés sur la main de leurs maîtres, Et les yeux de la servante sur la main de sa maîtresse, Ainsi nos yeux se tournent vers l''Éternel, notre Dieu, Jusqu''à ce qu''il ait pitié de nous.'),
  (19, 123, 3, 'Aie pitié de nous, Éternel, aie pitié de nous! Car nous sommes assez rassasiés de mépris;'),
  (19, 123, 4, 'Notre âme est assez rassasiée Des moqueries des orgueilleux, du mépris des hautains.'),
  (19, 124, 1, 'Cantique des degrés. De David. Sans l''Éternel qui nous protégea, Qu''Israël le dise!'),
  (19, 124, 2, 'Sans l''Éternel qui nous protégea, Quand les hommes s''élevèrent contre nous,'),
  (19, 124, 3, 'Ils nous auraient engloutis tout vivants, Quand leur colère s''enflamma contre nous;'),
  (19, 124, 4, 'Alors les eaux nous auraient submergés, Les torrents auraient passé sur notre âme;'),
  (19, 124, 5, 'Alors auraient passé sur notre âme Les flots impétueux.'),
  (19, 124, 6, 'Béni soit l''Éternel, Qui ne nous a pas livrés en proie à leurs dents!'),
  (19, 124, 7, 'Notre âme s''est échappée comme l''oiseau du filet des oiseleurs; Le filet s''est rompu, et nous nous sommes échappés.'),
  (19, 124, 8, 'Notre secours est dans le nom de l''Éternel, Qui a fait les cieux et la terre.'),
  (19, 125, 1, 'Cantique des degrés. Ceux qui se confient en l''Éternel Sont comme la montagne de Sion: elle ne chancelle point, Elle est affermie pour toujours.'),
  (19, 125, 2, 'Des montagnes entourent Jérusalem; Ainsi l''Éternel entoure son peuple, Dès maintenant et à jamais.'),
  (19, 125, 3, 'Car le sceptre de la méchanceté ne restera pas sur le lot des justes, Afin que les justes ne tendent pas les mains vers l''iniquité.'),
  (19, 125, 4, 'Éternel, répands tes bienfaits sur les bons Et sur ceux dont le cœur est droit!'),
  (19, 125, 5, 'Mais ceux qui s''engagent dans des voies détournées, Que l''Éternel les détruise avec ceux qui font le mal! Que la paix soit sur Israël!'),
  (19, 126, 1, 'Cantique des degrés. Quand l''Éternel ramena les captifs de Sion, Nous étions comme ceux qui font un rêve.'),
  (19, 126, 2, 'Alors notre bouche était remplie de cris de joie, Et notre langue de chants d''allégresse; Alors on disait parmi les nations: L''Éternel a fait pour eux de grandes choses!'),
  (19, 126, 3, 'L''Éternel a fait pour nous de grandes choses; Nous sommes dans la joie.'),
  (19, 126, 4, 'Éternel, ramène nos captifs, Comme des ruisseaux dans le midi!'),
  (19, 126, 5, 'Ceux qui sèment avec larmes Moissonneront avec chants d''allégresse.'),
  (19, 126, 6, 'Celui qui marche en pleurant, quand il porte la semence, Revient avec allégresse, quand il porte ses gerbes.'),
  (19, 127, 1, 'Cantique des degrés. De Salomon. Si l''Éternel ne bâtit la maison, Ceux qui la bâtissent travaillent en vain; Si l''Éternel ne garde la ville, Celui qui la garde veille en vain.'),
  (19, 127, 2, 'En vain vous levez-vous matin, vous couchez-vous tard, Et mangez-vous le pain de douleur; Il en donne autant à ses bien-aimés pendant leur sommeil.'),
  (19, 127, 3, 'Voici, des fils sont un héritage de l''Éternel, Le fruit des entrailles est une récompense.'),
  (19, 127, 4, 'Comme les flèches dans la main d''un guerrier, Ainsi sont les fils de la jeunesse.'),
  (19, 127, 5, 'Heureux l''homme qui en a rempli son carquois! Ils ne seront pas confus, Quand ils parleront avec des ennemis à la porte.'),
  (19, 128, 1, 'Cantique des degrés. Heureux tout homme qui craint l''Éternel, Qui marche dans ses voies!'),
  (19, 128, 2, 'Tu jouis alors du travail de tes mains, Tu es heureux, tu prospères.'),
  (19, 128, 3, 'Ta femme est comme une vigne féconde Dans l''intérieur de ta maison; Tes fils sont comme des plants d''olivier, Autour de ta table.'),
  (19, 128, 4, 'C''est ainsi qu''est béni L''homme qui craint l''Éternel.'),
  (19, 128, 5, 'L''Éternel te bénira de Sion, Et tu verras le bonheur de Jérusalem Tous les jours de ta vie;'),
  (19, 128, 6, 'Tu verras les fils de tes fils. Que la paix soit sur Israël!'),
  (19, 129, 1, 'Cantique des degrés. Ils m''ont assez opprimé dès ma jeunesse, Qu''Israël le dise!'),
  (19, 129, 2, 'Ils m''ont assez opprimé dès ma jeunesse, Mais ils ne m''ont pas vaincu.'),
  (19, 129, 3, 'Des laboureurs ont labouré mon dos, Ils y ont tracé de longs sillons.'),
  (19, 129, 4, 'L''Éternel est juste: Il a coupé les cordes des méchants.'),
  (19, 129, 5, 'Qu''ils soient confondus et qu''ils reculent, Tous ceux qui haïssent Sion!'),
  (19, 129, 6, 'Qu''ils soient comme l''herbe des toits, Qui sèche avant qu''on l''arrache!'),
  (19, 129, 7, 'Le moissonneur n''en remplit point sa main, Celui qui lie les gerbes n''en charge point son bras,'),
  (19, 129, 8, 'Et les passants ne disent point: Que la bénédiction de l''Éternel soit sur vous! Nous vous bénissons au nom de l''Éternel!'),
  (19, 130, 1, 'Cantique des degrés. Du fond de l''abîme je t''invoque, ô Éternel!'),
  (19, 130, 2, 'Seigneur, écoute ma voix! Que tes oreilles soient attentives A la voix de mes supplications!'),
  (19, 130, 3, 'Si tu gardais le souvenir des iniquités, Éternel, Seigneur, qui pourrait subsister?'),
  (19, 130, 4, 'Mais le pardon se trouve auprès de toi, Afin qu''on te craigne.'),
  (19, 130, 5, 'J''espère en l''Éternel, mon âme espère, Et j''attends sa promesse.'),
  (19, 130, 6, 'Mon âme compte sur le Seigneur, Plus que les gardes ne comptent sur le matin, Que les gardes ne comptent sur le matin.'),
  (19, 130, 7, 'Israël, mets ton espoir en l''Éternel! Car la miséricorde est auprès de l''Éternel, Et la rédemption est auprès de lui en abondance.'),
  (19, 130, 8, 'C''est lui qui rachètera Israël De toutes ses iniquités.'),
  (19, 131, 1, 'Cantique des degrés. De David. Éternel! je n''ai ni un cœur qui s''enfle, ni des regards hautains; Je ne m''occupe pas de choses trop grandes et trop relevées pour moi.'),
  (19, 131, 2, 'Loin de là, j''ai l''âme calme et tranquille, Comme un enfant sevré qui est auprès de sa mère; J''ai l''âme comme un enfant sevré.'),
  (19, 131, 3, 'Israël, mets ton espoir en l''Éternel, Dès maintenant et à jamais!'),
  (19, 132, 1, 'Cantique des degrés. Éternel, souviens-toi de David, De toutes ses peines!'),
  (19, 132, 2, 'Il jura à l''Éternel, Il fit ce vœu au puissant de Jacob:'),
  (19, 132, 3, 'Je n''entrerai pas dans la tente où j''habite, Je ne monterai pas sur le lit où je repose,'),
  (19, 132, 4, 'Je ne donnerai ni sommeil à mes yeux, Ni assoupissement à mes paupières.'),
  (19, 132, 5, 'Jusqu''à ce que j''aie trouvé un lieu pour l''Éternel, Une demeure pour le puissant de Jacob.'),
  (19, 132, 6, 'Voici, nous en entendîmes parler à Éphrata, Nous la trouvâmes dans les champs de Jaar…'),
  (19, 132, 7, 'Allons à sa demeure, Prosternons-nous devant son marchepied!…'),
  (19, 132, 8, 'Lève-toi, Éternel, viens à ton lieu de repos, Toi et l''arche de ta majesté!'),
  (19, 132, 9, 'Que tes sacrificateurs soient revêtus de justice, Et que tes fidèles poussent des cris de joie!'),
  (19, 132, 10, 'A cause de David, ton serviteur, Ne repousse pas ton oint!'),
  (19, 132, 11, 'L''Éternel a juré la vérité à David, Il n''en reviendra pas; Je mettrai sur ton trône un fruit de tes entrailles.'),
  (19, 132, 12, 'Si tes fils observent mon alliance Et mes préceptes que je leur enseigne, Leurs fils aussi pour toujours Seront assis sur ton trône.'),
  (19, 132, 13, 'Oui, l''Éternel a choisi Sion, Il l''a désirée pour sa demeure:'),
  (19, 132, 14, 'C''est mon lieu de repos à toujours; J''y habiterai, car je l''ai désirée.'),
  (19, 132, 15, 'Je bénirai sa nourriture, Je rassasierai de pain ses indigents;'),
  (19, 132, 16, 'Je revêtirai de salut ses sacrificateurs, Et ses fidèles pousseront des cris de joie.'),
  (19, 132, 17, 'Là j''élèverai la puissance de David, Je préparerai une lampe à mon oint,'),
  (19, 132, 18, 'Je revêtirai de honte ses ennemis, Et sur lui brillera sa couronne.'),
  (19, 133, 1, 'Cantique des degrés. De David. Voici, oh! qu''il est agréable, qu''il est doux Pour des frères de demeurer ensemble!'),
  (19, 133, 2, 'C''est comme l''huile précieuse qui, répandue sur la tête, Descend sur la barbe, sur la barbe d''Aaron, Qui descend sur le bord de ses vêtements.'),
  (19, 133, 3, 'C''est comme la rosée de l''Hermon, Qui descend sur les montagnes de Sion; Car c''est là que l''Éternel envoie la bénédiction, La vie, pour l''éternité.'),
  (19, 134, 1, 'Cantique des degrés. Voici, bénissez l''Éternel, vous tous, serviteurs de l''Éternel, Qui vous tenez dans la maison de l''Éternel pendant les nuits!'),
  (19, 134, 2, 'Élevez vos mains vers le sanctuaire, Et bénissez l''Éternel!'),
  (19, 134, 3, 'Que l''Éternel te bénisse de Sion, Lui qui a fait les cieux et la terre!'),
  (19, 135, 1, 'Louez l''Éternel! Louez le nom de l''Éternel, Louez-le, serviteurs de l''Éternel,'),
  (19, 135, 2, 'Qui vous tenez dans la maison de l''Éternel, Dans les parvis de la maison de notre Dieu!'),
  (19, 135, 3, 'Louez l''Éternel! car l''Éternel est bon. Chantez à son nom! car il est favorable.'),
  (19, 135, 4, 'Car l''Éternel s''est choisi Jacob, Israël, pour qu''il lui appartînt.'),
  (19, 135, 5, 'Je sais que l''Éternel est grand, Et que notre Seigneur est au-dessus de tous les dieux.'),
  (19, 135, 6, 'Tout ce que l''Éternel veut, il le fait, Dans les cieux et sur la terre, Dans les mers et dans tous les abîmes.'),
  (19, 135, 7, 'Il fait monter les nuages des extrémités de la terre, Il produit les éclairs et la pluie, Il tire le vent de ses trésors.'),
  (19, 135, 8, 'Il frappa les premiers-nés de l''Égypte, Depuis les hommes jusqu''aux animaux.'),
  (19, 135, 9, 'Il envoya des signes et des miracles au milieu de toi, Égypte! Contre Pharaon et contre tous ses serviteurs.'),
  (19, 135, 10, 'Il frappa des nations nombreuses, Et tua des rois puissants,'),
  (19, 135, 11, 'Sihon, roi des Amoréens, Og, roi de Basan, Et tous les rois de Canaan;'),
  (19, 135, 12, 'Et il donna leur pays en héritage, En héritage à Israël, son peuple.'),
  (19, 135, 13, 'Éternel! ton nom subsiste à toujours, Éternel! ta mémoire dure de génération en génération.'),
  (19, 135, 14, 'Car l''Éternel jugera son peuple, Et il aura pitié de ses serviteurs.'),
  (19, 135, 15, 'Les idoles des nations sont de l''argent et de l''or, Elles sont l''ouvrage de la main des hommes.'),
  (19, 135, 16, 'Elles ont une bouche et ne parlent point, Elles ont des yeux et ne voient point,'),
  (19, 135, 17, 'Elles ont des oreilles et n''entendent point, Elles n''ont point de souffle dans leur bouche.'),
  (19, 135, 18, 'Ils leur ressemblent, ceux qui les fabriquent, Tous ceux qui se confient en elles.'),
  (19, 135, 19, 'Maison d''Israël, bénissez l''Éternel! Maison d''Aaron, bénissez l''Éternel!'),
  (19, 135, 20, 'Maison de Lévi, bénissez l''Éternel! Vous qui craignez l''Éternel, bénissez l''Éternel!'),
  (19, 135, 21, 'Que de Sion l''on bénisse l''Éternel, Qui habite à Jérusalem! Louez l''Éternel!'),
  (19, 136, 1, 'Louez l''Éternel, car il est bon, Car sa miséricorde dure à toujours!'),
  (19, 136, 2, 'Louez le Dieu des dieux, Car sa miséricorde dure à toujours!'),
  (19, 136, 3, 'Louez le Seigneur des seigneurs, Car sa miséricorde dure à toujours!'),
  (19, 136, 4, 'Celui qui seul fait de grands prodiges, Car sa miséricorde dure à toujours!'),
  (19, 136, 5, 'Celui qui a fait les cieux avec intelligence, Car sa miséricorde dure à toujours!'),
  (19, 136, 6, 'Celui qui a étendu la terre sur les eaux, Car sa miséricorde dure à toujours!'),
  (19, 136, 7, 'Celui qui a fait les grands luminaires, Car sa miséricorde dure à toujours!'),
  (19, 136, 8, 'Le soleil pour présider au jour, Car sa miséricorde dure à toujours!'),
  (19, 136, 9, 'La lune et les étoiles pour présider à la nuit, Car sa miséricorde dure à toujours!'),
  (19, 136, 10, 'Celui qui frappa les Égyptiens dans leurs premiers-nés, Car sa miséricorde dure à toujours!'),
  (19, 136, 11, 'Et fit sortir Israël du milieu d''eux, Car sa miséricorde dure à toujours!'),
  (19, 136, 12, 'A main forte et à bras étendu, Car sa miséricorde dure à toujours!'),
  (19, 136, 13, 'Celui qui coupa en deux la mer Rouge, Car sa miséricorde dure à toujours!'),
  (19, 136, 14, 'Qui fit passer Israël au milieu d''elle, Car sa miséricorde dure à toujours!'),
  (19, 136, 15, 'Et précipita Pharaon et son armée dans la mer Rouge, Car sa miséricorde dure à toujours!'),
  (19, 136, 16, 'Celui qui conduisit son peuple dans le désert, Car sa miséricorde dure à toujours!'),
  (19, 136, 17, 'Celui qui frappa de grands rois, Car sa miséricorde dure à toujours!'),
  (19, 136, 18, 'Qui tua des rois puissants, Car sa miséricorde dure à toujours!'),
  (19, 136, 19, 'Sihon, roi des Amoréens, Car sa miséricorde dure à toujours!'),
  (19, 136, 20, 'Et Og, roi de Basan, Car sa miséricorde dure à toujours!'),
  (19, 136, 21, 'Et donna leur pays en héritage, Car sa miséricorde dure à toujours!'),
  (19, 136, 22, 'En héritage à Israël, son serviteur, Car sa miséricorde dure à toujours!'),
  (19, 136, 23, 'Celui qui se souvint de nous quand nous étions humiliés, Car sa miséricorde dure à toujours!'),
  (19, 136, 24, 'Et nous délivra de nos oppresseurs, Car sa miséricorde dure à toujours!'),
  (19, 136, 25, 'Celui qui donne la nourriture à toute chair, Car sa miséricorde dure à toujours!'),
  (19, 136, 26, 'Louez le Dieu des cieux, Car sa miséricorde dure à toujours!'),
  (19, 137, 1, 'Sur les bords des fleuves de Babylone, Nous étions assis et nous pleurions, en nous souvenant de Sion.'),
  (19, 137, 2, 'Aux saules de la contrée Nous avions suspendu nos harpes.'),
  (19, 137, 3, 'Là, nos vainqueurs nous demandaient des chants, Et nos oppresseurs de la joie: Chantez-nous quelques-uns des cantiques de Sion!'),
  (19, 137, 4, 'Comment chanterions-nous les cantiques de l''Éternel Sur une terre étrangère?'),
  (19, 137, 5, 'Si je t''oublie, Jérusalem, Que ma droite m''oublie!'),
  (19, 137, 6, 'Que ma langue s''attache à mon palais, Si je ne me souviens de toi, Si je ne fais de Jérusalem Le principal sujet de ma joie!'),
  (19, 137, 7, 'Éternel, souviens-toi des enfants d''Édom, Qui, dans la journée de Jérusalem, Disaient: Rasez, rasez Jusqu''à ses fondements!'),
  (19, 137, 8, 'Fille de Babylone, la dévastée, Heureux qui te rend la pareille, Le mal que tu nous as fait!'),
  (19, 137, 9, 'Heureux qui saisit tes enfants, Et les écrase sur le roc!'),
  (19, 138, 1, 'De David. Je te célèbre de tout mon cœur, Je chante tes louanges en la présence de Dieu.'),
  (19, 138, 2, 'Je me prosterne dans ton saint temple, Et je célèbre ton nom, à cause de ta bonté et de ta fidélité, Car ta renommée s''est accrue par l''accomplissement de tes promesses.'),
  (19, 138, 3, 'Le jour où je t''ai invoqué, tu m''as exaucé, Tu m''as rassuré, tu as fortifié mon âme.'),
  (19, 138, 4, 'Tous les rois de la terre te loueront, ô Éternel! En entendant les paroles de ta bouche;'),
  (19, 138, 5, 'Ils célébreront les voies de l''Éternel, Car la gloire de l''Éternel est grande.'),
  (19, 138, 6, 'L''Éternel est élevé: il voit les humbles, Et il reconnaît de loin les orgueilleux.'),
  (19, 138, 7, 'Quand je marche au milieu de la détresse, tu me rends la vie, Tu étends ta main sur la colère de mes ennemis, Et ta droite me sauve.'),
  (19, 138, 8, 'L''Éternel agira en ma faveur. Éternel, ta bonté dure toujours, N''abandonne pas les œuvres de tes mains!'),
  (19, 139, 1, 'Au chef des chantres. De David. Psaume. Éternel! tu me sondes et tu me connais,'),
  (19, 139, 2, 'Tu sais quand je m''assieds et quand je me lève, Tu pénètres de loin ma pensée;'),
  (19, 139, 3, 'Tu sais quand je marche et quand je me couche, Et tu pénètres toutes mes voies.'),
  (19, 139, 4, 'Car la parole n''est pas sur ma langue, Que déjà, ô Éternel! tu la connais entièrement.'),
  (19, 139, 5, 'Tu m''entoures par derrière et par devant, Et tu mets ta main sur moi.'),
  (19, 139, 6, 'Une science aussi merveilleuse est au-dessus de ma portée, Elle est trop élevée pour que je puisse la saisir.'),
  (19, 139, 7, 'Où irais-je loin de ton esprit, Et où fuirais-je loin de ta face?'),
  (19, 139, 8, 'Si je monte aux cieux, tu y es; Si je me couche au séjour des morts, t''y voilà.'),
  (19, 139, 9, 'Si je prends les ailes de l''aurore, Et que j''aille habiter à l''extrémité de la mer,'),
  (19, 139, 10, 'Là aussi ta main me conduira, Et ta droite me saisira.'),
  (19, 139, 11, 'Si je dis: Au moins les ténèbres me couvriront, La nuit devient lumière autour de moi;'),
  (19, 139, 12, 'Même les ténèbres ne sont pas obscures pour toi, La nuit brille comme le jour, Et les ténèbres comme la lumière.'),
  (19, 139, 13, 'C''est toi qui as formé mes reins, Qui m''as tissé dans le sein de ma mère.'),
  (19, 139, 14, 'Je te loue de ce que je suis une créature si merveilleuse. Tes œuvres sont admirables, Et mon âme le reconnaît bien.'),
  (19, 139, 15, 'Mon corps n''était point caché devant toi, Lorsque j''ai été fait dans un lieu secret, Tissé dans les profondeurs de la terre.'),
  (19, 139, 16, 'Quand je n''étais qu''une masse informe, tes yeux me voyaient; Et sur ton livre étaient tous inscrits Les jours qui m''étaient destinés, Avant qu''aucun d''eux existât.'),
  (19, 139, 17, 'Que tes pensées, ô Dieu, me semblent impénétrables! Que le nombre en est grand!'),
  (19, 139, 18, 'Si je les compte, elles sont plus nombreuses que les grains de sable. Je m''éveille, et je suis encore avec toi.'),
  (19, 139, 19, 'O Dieu, puisses-tu faire mourir le méchant! Hommes de sang, éloignez-vous de moi!'),
  (19, 139, 20, 'Ils parlent de toi d''une manière criminelle, Ils prennent ton nom pour mentir, eux, tes ennemis!'),
  (19, 139, 21, 'Éternel, n''aurais-je pas de la haine pour ceux qui te haïssent, Du dégoût pour ceux qui s''élèvent contre toi?'),
  (19, 139, 22, 'Je les hais d''une parfaite haine; Ils sont pour moi des ennemis.'),
  (19, 139, 23, 'Sonde-moi, ô Dieu, et connais mon cœur! Éprouve-moi, et connais mes pensées!'),
  (19, 139, 24, 'Regarde si je suis sur une mauvaise voie, Et conduis-moi sur la voie de l''éternité!'),
  (19, 140, 1, 'Au chef des chantres. Psaume de David. Éternel, délivre-moi des hommes méchants! Préserve-moi des hommes violents.'),
  (19, 140, 2, 'Qui méditent de mauvais desseins dans leur cœur, Et sont toujours prêts à faire la guerre!'),
  (19, 140, 3, 'Ils aiguisent leur langue comme un serpent, Ils ont sous leurs lèvres un venin d''aspic. Pause.'),
  (19, 140, 4, 'Éternel, garantis-moi des mains du méchant! Préserve-moi des hommes violents, Qui méditent de me faire tomber!'),
  (19, 140, 5, 'Des orgueilleux me tendent un piège et des filets, Ils placent des rets le long du chemin, Ils me dressent des embûches. Pause.'),
  (19, 140, 6, 'Je dis à l''Éternel: Tu es mon Dieu! Éternel, prête l''oreille à la voix de mes supplications!'),
  (19, 140, 7, 'Éternel, Seigneur, force de mon salut! Tu couvres ma tête au jour du combat.'),
  (19, 140, 8, 'Éternel, n''accomplis pas les désirs du méchant, Ne laisse pas réussir ses projets, de peur qu''il ne s''en glorifie! Pause.'),
  (19, 140, 9, 'Que sur la tête de ceux qui m''environnent Retombe l''iniquité de leurs lèvres!'),
  (19, 140, 10, 'Que des charbons ardents soient jetés sur eux! Qu''il les précipite dans le feu, Dans des abîmes, d''où ils ne se relèvent plus!'),
  (19, 140, 11, 'L''homme dont la langue est fausse ne s''affermit pas sur la terre; Et l''homme violent, le malheur l''entraîne à sa perte.'),
  (19, 140, 12, 'Je sais que l''Éternel fait droit au misérable, Justice aux indigents.'),
  (19, 140, 13, 'Oui, les justes célébreront ton nom, Les hommes droits habiteront devant ta face.'),
  (19, 141, 1, 'Psaume de David. Éternel, je t''invoque: viens en hâte auprès de moi! Prête l''oreille à ma voix, quand je t''invoque!'),
  (19, 141, 2, 'Que ma prière soit devant ta face comme l''encens, Et l''élévation de mes mains comme l''offrande du soir!'),
  (19, 141, 3, 'Éternel, mets une garde à ma bouche, Veille sur la porte de mes lèvres!'),
  (19, 141, 4, 'N''entraîne pas mon cœur à des choses mauvaises, A des actions coupables avec les hommes qui font le mal, Et que je ne prenne aucune part à leurs festins!'),
  (19, 141, 5, 'Que le juste me frappe, c''est une faveur; Qu''il me châtie, c''est de l''huile sur ma tête: Ma tête ne se détournera pas; Mais de nouveau ma prière s''élèvera contre leur méchanceté.'),
  (19, 141, 6, 'Que leurs juges soient précipités le long des rochers, Et l''on écoutera mes paroles, car elles sont agréables.'),
  (19, 141, 7, 'Comme quand on laboure et qu''on fend la terre, Ainsi nos os sont dispersés à l''entrée du séjour des morts.'),
  (19, 141, 8, 'C''est vers toi, Éternel, Seigneur! que se tournent mes yeux, C''est auprès de toi que je cherche un refuge: N''abandonne pas mon âme!'),
  (19, 141, 9, 'Garantis-moi du piège qu''ils me tendent, Et des embûches de ceux qui font le mal!'),
  (19, 141, 10, 'Que les méchants tombent dans leurs filets, Et que j''échappe en même temps!'),
  (19, 142, 1, 'Cantique de David. Lorsqu''il était dans la caverne. Prière. De ma voix je crie à l''Éternel, De ma voix j''implore l''Éternel.'),
  (19, 142, 2, 'Je répands ma plainte devant lui, Je lui raconte ma détresse.'),
  (19, 142, 3, 'Quand mon esprit est abattu au dedans de moi, Toi, tu connais mon sentier. Sur la route où je marche Ils m''ont tendu un piège.'),
  (19, 142, 4, 'Jette les yeux à droite, et regarde! Personne ne me reconnaît, Tout refuge est perdu pour moi, Nul ne prend souci de mon âme.'),
  (19, 142, 5, 'Éternel! c''est à toi que je crie. Je dis: Tu es mon refuge, Mon partage sur la terre des vivants.'),
  (19, 142, 6, 'Sois attentif à mes cris! Car je suis bien malheureux. Délivre-moi de ceux qui me poursuivent! Car ils sont plus forts que moi.'),
  (19, 142, 7, 'Tire mon âme de sa prison, Afin que je célèbre ton nom! Les justes viendront m''entourer, Quand tu m''auras fait du bien.'),
  (19, 143, 1, 'Psaume de David. Éternel, écoute ma prière, prête l''oreille à mes supplications! Exauce-moi dans ta fidélité, dans ta justice!'),
  (19, 143, 2, 'N''entre pas en jugement avec ton serviteur! Car aucun vivant n''est juste devant toi.'),
  (19, 143, 3, 'L''ennemi poursuit mon âme, Il foule à terre ma vie; Il me fait habiter dans les ténèbres, Comme ceux qui sont morts depuis longtemps.'),
  (19, 143, 4, 'Mon esprit est abattu au dedans de moi, Mon cœur est troublé dans mon sein.'),
  (19, 143, 5, 'Je me souviens des jours d''autrefois, Je médite sur toutes tes œuvres, Je réfléchis sur l''ouvrage de tes mains.'),
  (19, 143, 6, 'J''étends mes mains vers toi; Mon âme soupire après toi, comme une terre desséchée. Pause.'),
  (19, 143, 7, 'Hâte-toi de m''exaucer, ô Éternel! Mon esprit se consume. Ne me cache pas ta face! Je serais semblable à ceux qui descendent dans la fosse.'),
  (19, 143, 8, 'Fais-moi dès le matin entendre ta bonté! Car je me confie en toi. Fais-moi connaître le chemin où je dois marcher! Car j''élève à toi mon âme.'),
  (19, 143, 9, 'Délivre-moi de mes ennemis, ô Éternel! Auprès de toi je cherche un refuge.'),
  (19, 143, 10, 'Enseigne-moi à faire ta volonté! Car tu es mon Dieu. Que ton bon esprit me conduise sur la voie droite!'),
  (19, 143, 11, 'A cause de ton nom, Éternel, rends-moi la vie! Dans ta justice, retire mon âme de la détresse!'),
  (19, 143, 12, 'Dans ta bonté, anéantis mes ennemis, Et fais périr tous les oppresseurs de mon âme! Car je suis ton serviteur.'),
  (19, 144, 1, 'De David. Béni soit l''Éternel, mon rocher, Qui exerce mes mains au combat, Mes doigts à la bataille,'),
  (19, 144, 2, 'Mon bienfaiteur et ma forteresse, Ma haute retraite et mon libérateur, Mon bouclier, celui qui est mon refuge, Qui m''assujettit mon peuple!'),
  (19, 144, 3, 'Éternel, qu''est-ce que l''homme, pour que tu le connaisses? Le fils de l''homme, pour que tu prennes garde à lui?'),
  (19, 144, 4, 'L''homme est semblable à un souffle, Ses jours sont comme l''ombre qui passe.'),
  (19, 144, 5, 'Éternel, abaisse tes cieux, et descends! Touche les montagnes, et qu''elles soient fumantes!'),
  (19, 144, 6, 'Fais briller les éclairs, et disperse mes ennemis! Lance tes flèches, et mets-les en déroute!'),
  (19, 144, 7, 'Étends tes mains d''en haut; Délivre-moi et sauve-moi des grandes eaux, De la main des fils de l''étranger,'),
  (19, 144, 8, 'Dont la bouche profère la fausseté, Et dont la droite est une droite mensongère.'),
  (19, 144, 9, 'O Dieu! je te chanterai un cantique nouveau, Je te célébrerai sur le luth à dix cordes.'),
  (19, 144, 10, 'Toi, qui donnes le salut aux rois, Qui sauvas du glaive meurtrier David, ton serviteur,'),
  (19, 144, 11, 'Délivre-moi et sauve-moi de la main des fils de l''étranger, Dont la bouche profère la fausseté, Et dont la droite est une droite mensongère!…'),
  (19, 144, 12, 'Nos fils sont comme des plantes Qui croissent dans leur jeunesse; Nos filles comme les colonnes sculptées Qui font l''ornement des palais.'),
  (19, 144, 13, 'Nos greniers sont pleins, Regorgeant de toute espèce de provisions; Nos troupeaux se multiplient par milliers, par dix milliers, Dans nos campagnes;'),
  (19, 144, 14, 'Nos génisses sont fécondes; Point de désastre, point de captivité, Point de cris dans nos rues!'),
  (19, 144, 15, 'Heureux le peuple pour qui il en est ainsi! Heureux le peuple dont l''Éternel est le Dieu!'),
  (19, 145, 1, 'Louange. De David. Je t''exalterai, ô mon Dieu, mon roi! Et je bénirai ton nom à toujours et à perpétuité.'),
  (19, 145, 2, 'Chaque jour je te bénirai, Et je célébrerai ton nom à toujours et à perpétuité.'),
  (19, 145, 3, 'L''Éternel est grand et très digne de louange, Et sa grandeur est insondable.'),
  (19, 145, 4, 'Que chaque génération célèbre tes œuvres, Et publie tes hauts faits!'),
  (19, 145, 5, 'Je dirai la splendeur glorieuse de ta majesté; Je chanterai tes merveilles.'),
  (19, 145, 6, 'On parlera de ta puissance redoutable, Et je raconterai ta grandeur.'),
  (19, 145, 7, 'Qu''on proclame le souvenir de ton immense bonté, Et qu''on célèbre ta justice!'),
  (19, 145, 8, 'L''Éternel est miséricordieux et compatissant, Lent à la colère et plein de bonté.'),
  (19, 145, 9, 'L''Éternel est bon envers tous, Et ses compassions s''étendent sur toutes ses œuvres.'),
  (19, 145, 10, 'Toutes tes œuvres te loueront, ô Éternel! Et tes fidèles te béniront.'),
  (19, 145, 11, 'Ils diront la gloire de ton règne, Et ils proclameront ta puissance,'),
  (19, 145, 12, 'Pour faire connaître aux fils de l''homme ta puissance Et la splendeur glorieuse de ton règne.'),
  (19, 145, 13, 'Ton règne est un règne de tous les siècles, Et ta domination subsiste dans tous les âges.'),
  (19, 145, 14, 'L''Éternel soutient tous ceux qui tombent, Et il redresse tous ceux qui sont courbés.'),
  (19, 145, 15, 'Les yeux de tous espèrent en toi, Et tu leur donnes la nourriture en son temps.'),
  (19, 145, 16, 'Tu ouvres ta main, Et tu rassasies à souhait tout ce qui a vie.'),
  (19, 145, 17, 'L''Éternel est juste dans toutes ses voies, Et miséricordieux dans toutes ses œuvres.'),
  (19, 145, 18, 'L''Éternel est près de tous ceux qui l''invoquent, De tous ceux qui l''invoquent avec sincérité;'),
  (19, 145, 19, 'Il accomplit les désirs de ceux qui le craignent, Il entend leur cri et il les sauve.'),
  (19, 145, 20, 'L''Éternel garde tous ceux qui l''aiment, Et il détruit tous les méchants.'),
  (19, 145, 21, 'Que ma bouche publie la louange de l''Éternel, Et que toute chair bénisse son saint nom, A toujours et à perpétuité!'),
  (19, 146, 1, 'Louez l''Éternel! Mon âme, loue l''Éternel!'),
  (19, 146, 2, 'Je louerai l''Éternel tant que je vivrai, Je célébrerai mon Dieu tant que j''existerai.'),
  (19, 146, 3, 'Ne vous confiez pas aux grands, Aux fils de l''homme, qui ne peuvent sauver.'),
  (19, 146, 4, 'Leur souffle s''en va, ils rentrent dans la terre, Et ce même jour leurs desseins périssent.'),
  (19, 146, 5, 'Heureux celui qui a pour secours le Dieu de Jacob, Qui met son espoir en l''Éternel, son Dieu!'),
  (19, 146, 6, 'Il a fait les cieux et la terre, La mer et tout ce qui s''y trouve. Il garde la fidélité à toujours.'),
  (19, 146, 7, 'Il fait droit aux opprimés; Il donne du pain aux affamés; L''Éternel délivre les captifs;'),
  (19, 146, 8, 'L''Éternel ouvre les yeux des aveugles; L''Éternel redresse ceux qui sont courbés; L''Éternel aime les justes.'),
  (19, 146, 9, 'L''Éternel protège les étrangers, Il soutient l''orphelin et la veuve, Mais il renverse la voie des méchants.'),
  (19, 146, 10, 'L''Éternel règne éternellement; Ton Dieu, ô Sion! subsiste d''âge en âge! Louez l''Éternel!'),
  (19, 147, 1, 'Louez l''Éternel! Car il est beau de célébrer notre Dieu, Car il est doux, il est bienséant de le louer.'),
  (19, 147, 2, 'L''Éternel rebâtit Jérusalem, Il rassemble les exilés d''Israël;'),
  (19, 147, 3, 'Il guérit ceux qui ont le cœur brisé, Et il panse leurs blessures.'),
  (19, 147, 4, 'Il compte le nombre des étoiles, Il leur donne à toutes des noms.'),
  (19, 147, 5, 'Notre Seigneur est grand, puissant par sa force, Son intelligence n''a point de limite.'),
  (19, 147, 6, 'L''Éternel soutient les malheureux, Il abaisse les méchants jusqu''à terre.'),
  (19, 147, 7, 'Chantez à l''Éternel avec actions de grâces, Célébrez notre Dieu avec la harpe!'),
  (19, 147, 8, 'Il couvre les cieux de nuages, Il prépare la pluie pour la terre; Il fait germer l''herbe sur les montagnes.'),
  (19, 147, 9, 'Il donne la nourriture au bétail, Aux petits du corbeau quand ils crient,'),
  (19, 147, 10, 'Ce n''est pas dans la vigueur du cheval qu''il se complaît, Ce n''est pas dans les jambes de l''homme qu''il met son plaisir;'),
  (19, 147, 11, 'L''Éternel aime ceux qui le craignent, Ceux qui espèrent en sa bonté.'),
  (19, 147, 12, 'Jérusalem, célèbre l''Éternel! Sion, loue ton Dieu!'),
  (19, 147, 13, 'Car il affermit les barres de tes portes, Il bénit tes fils au milieu de toi;'),
  (19, 147, 14, 'Il rend la paix à ton territoire, Il te rassasie du meilleur froment.'),
  (19, 147, 15, 'Il envoie ses ordres sur la terre: Sa parole court avec vitesse'),
  (19, 147, 16, 'Il donne la neige comme de la laine, Il répand la gelée blanche comme de la cendre;'),
  (19, 147, 17, 'Il lance sa glace par morceaux; Qui peut résister devant son froid?'),
  (19, 147, 18, 'Il envoie sa parole, et il les fond; Il fait souffler son vent, et les eaux coulent.'),
  (19, 147, 19, 'Il révèle sa parole à Jacob, Ses lois et ses ordonnances à Israël;'),
  (19, 147, 20, 'Il n''a pas agi de même pour toutes les nations, Et elles ne connaissent point ses ordonnances. Louez l''Éternel!'),
  (19, 148, 1, 'Louez l''Éternel! Louez l''Éternel du haut des cieux! Louez-le dans les lieux élevés!'),
  (19, 148, 2, 'Louez-le, vous tous ses anges! Louez-le, vous toutes ses armées!'),
  (19, 148, 3, 'Louez-le, soleil et lune! Louez-le, vous toutes, étoiles lumineuses!'),
  (19, 148, 4, 'Louez-le, cieux des cieux, Et vous, eaux qui êtes au-dessus des cieux!'),
  (19, 148, 5, 'Qu''ils louent le nom de l''Éternel! Car il a commandé, et ils ont été créés.'),
  (19, 148, 6, 'Il les a affermis pour toujours et à perpétuité; Il a donné des lois, et il ne les violera point.'),
  (19, 148, 7, 'Louez l''Éternel du bas de la terre, Monstres marins, et vous tous, abîmes,'),
  (19, 148, 8, 'Feu et grêle, neige et brouillards, Vents impétueux, qui exécutez ses ordres,'),
  (19, 148, 9, 'Montagnes et toutes les collines, Arbres fruitiers et tous les cèdres,'),
  (19, 148, 10, 'Animaux et tout le bétail, Reptiles et oiseaux ailés,'),
  (19, 148, 11, 'Rois de la terre et tous les peuples, Princes et tous les juges de la terre,'),
  (19, 148, 12, 'Jeunes hommes et jeunes filles, Vieillards et enfants!'),
  (19, 148, 13, 'Qu''ils louent le nom de l''Éternel! Car son nom seul est élevé; Sa majesté est au-dessus de la terre et des cieux.'),
  (19, 148, 14, 'Il a relevé la force de son peuple: Sujet de louange pour tous ses fidèles, Pour les enfants d''Israël, du peuple qui est près de lui. Louez l''Éternel!'),
  (19, 149, 1, 'Louez l''Éternel! Chantez à l''Éternel un cantique nouveau! Chantez ses louanges dans l''assemblée des fidèles!'),
  (19, 149, 2, 'Qu''Israël se réjouisse en celui qui l''a créé! Que les fils de Sion soient dans l''allégresse à cause de leur roi!'),
  (19, 149, 3, 'Qu''ils louent son nom avec des danses, Qu''ils le célèbrent avec le tambourin et la harpe!'),
  (19, 149, 4, 'Car l''Éternel prend plaisir à son peuple, Il glorifie les malheureux en les sauvant.'),
  (19, 149, 5, 'Que les fidèles triomphent dans la gloire, Qu''ils poussent des cris de joie sur leur couche!'),
  (19, 149, 6, 'Que les louanges de Dieu soient dans leur bouche, Et le glaive à deux tranchants dans leur main,'),
  (19, 149, 7, 'Pour exercer la vengeance sur les nations, Pour châtier les peuples,'),
  (19, 149, 8, 'Pour lier leurs rois avec des chaînes Et leurs grands avec des ceps de fer,'),
  (19, 149, 9, 'Pour exécuter contre eux le jugement qui est écrit! C''est une gloire pour tous ses fidèles. Louez l''Éternel!'),
  (19, 150, 1, 'Louez l''Éternel! Louez Dieu dans son sanctuaire! Louez-le dans l''étendue, où éclate sa puissance!'),
  (19, 150, 2, 'Louez-le pour ses hauts faits! Louez-le selon l''immensité de sa grandeur!'),
  (19, 150, 3, 'Louez-le au son de la trompette! Louez-le avec le luth et la harpe!'),
  (19, 150, 4, 'Louez-le avec le tambourin et avec des danses! Louez-le avec les instruments à cordes et le chalumeau!'),
  (19, 150, 5, 'Louez-le avec les cymbales sonores! Louez-le avec les cymbales retentissantes!'),
  (19, 150, 6, 'Que tout ce qui respire loue l''Éternel! Louez l''Éternel!'),
  (20, 1, 1, 'Proverbes de Salomon, fils de David, roi d''Israël,'),
  (20, 1, 2, 'Pour connaître la sagesse et l''instruction, Pour comprendre les paroles de l''intelligence;'),
  (20, 1, 3, 'Pour recevoir des leçons de bon sens, De justice, d''équité et de droiture;'),
  (20, 1, 4, 'Pour donner aux simples du discernement, Au jeune homme de la connaissance et de la réflexion.'),
  (20, 1, 5, 'Que le sage écoute, et il augmentera son savoir, Et celui qui est intelligent acquerra de l''habileté,'),
  (20, 1, 6, 'Pour saisir le sens d''un proverbe ou d''une énigme, Des paroles des sages et de leurs sentences.'),
  (20, 1, 7, 'La crainte de l''Éternel est le commencement de la science; Les insensés méprisent la sagesse et l''instruction.'),
  (20, 1, 8, 'Écoute, mon fils, l''instruction de ton père, Et ne rejette pas l''enseignement de ta mère;'),
  (20, 1, 9, 'Car c''est une couronne de grâce pour ta tête, Et une parure pour ton cou.'),
  (20, 1, 10, 'Mon fils, si des pécheurs veulent te séduire, Ne te laisse pas gagner.'),
  (20, 1, 11, 'S''ils disent: Viens avec nous! dressons des embûches, versons du sang, Tendons des pièges à celui qui se repose en vain sur son innocence,'),
  (20, 1, 12, 'Engloutissons-les tout vifs, comme le séjour des morts, Et tout entiers, comme ceux qui descendent dans la fosse;'),
  (20, 1, 13, 'Nous trouverons toute sorte de biens précieux, Nous remplirons de butin nos maisons;'),
  (20, 1, 14, 'Tu auras ta part avec nous, Il n''y aura qu''une bourse pour nous tous!'),
  (20, 1, 15, 'Mon fils, ne te mets pas en chemin avec eux, Détourne ton pied de leur sentier;'),
  (20, 1, 16, 'Car leurs pieds courent au mal, Et ils ont hâte de répandre le sang.'),
  (20, 1, 17, 'Mais en vain jette-t-on le filet Devant les yeux de tout ce qui a des ailes;'),
  (20, 1, 18, 'Et eux, c''est contre leur propre sang qu''ils dressent des embûches, C''est à leur âme qu''ils tendent des pièges.'),
  (20, 1, 19, 'Ainsi arrive-t-il à tout homme avide de gain; La cupidité cause la perte de ceux qui s''y livrent.'),
  (20, 1, 20, 'La sagesse crie dans les rues, Elle élève sa voix dans les places:'),
  (20, 1, 21, 'Elle crie à l''entrée des lieux bruyants; Aux portes, dans la ville, elle fait entendre ses paroles:'),
  (20, 1, 22, 'Jusqu''à quand, stupides, aimerez-vous la stupidité? Jusqu''à quand les moqueurs se plairont-ils à la moquerie, Et les insensés haïront-ils la science?'),
  (20, 1, 23, 'Tournez-vous pour écouter mes réprimandes! Voici, je répandrai sur vous mon esprit, Je vous ferai connaître mes paroles…'),
  (20, 1, 24, 'Puisque j''appelle et que vous résistez, Puisque j''étends ma main et que personne n''y prend garde,'),
  (20, 1, 25, 'Puisque vous rejetez tous mes conseils, Et que vous n''aimez pas mes réprimandes,'),
  (20, 1, 26, 'Moi aussi, je rirai quand vous serez dans le malheur, Je me moquerai quand la terreur vous saisira,'),
  (20, 1, 27, 'Quand la terreur vous saisira comme une tempête, Et que le malheur vous enveloppera comme un tourbillon, Quand la détresse et l''angoisse fondront sur vous.'),
  (20, 1, 28, 'Alors ils m''appelleront, et je ne répondrai pas; Ils me chercheront, et ils ne me trouveront pas.'),
  (20, 1, 29, 'Parce qu''ils ont haï la science, Et qu''ils n''ont pas choisi la crainte de l''Éternel,'),
  (20, 1, 30, 'Parce qu''ils n''ont point aimé mes conseils, Et qu''ils ont dédaigné toutes mes réprimandes,'),
  (20, 1, 31, 'Ils se nourriront du fruit de leur voie, Et ils se rassasieront de leurs propres conseils,'),
  (20, 1, 32, 'Car la résistance des stupides les tue, Et la sécurité des insensés les perd;'),
  (20, 1, 33, 'Mais celui qui m''écoute reposera avec assurance, Il vivra tranquille et sans craindre aucun mal.'),
  (20, 2, 1, 'Mon fils, si tu reçois mes paroles, Et si tu gardes avec toi mes préceptes,'),
  (20, 2, 2, 'Si tu rends ton oreille attentive à la sagesse, Et si tu inclines ton cœur à l''intelligence;'),
  (20, 2, 3, 'Oui, si tu appelles la sagesse, Et si tu élèves ta voix vers l''intelligence,'),
  (20, 2, 4, 'Si tu la cherches comme l''argent, Si tu la poursuis comme un trésor,'),
  (20, 2, 5, 'Alors tu comprendras la crainte de l''Éternel, Et tu trouveras la connaissance de Dieu.'),
  (20, 2, 6, 'Car l''Éternel donne la sagesse; De sa bouche sortent la connaissance et l''intelligence;'),
  (20, 2, 7, 'Il tient en réserve le salut pour les hommes droits, Un bouclier pour ceux qui marchent dans l''intégrité,'),
  (20, 2, 8, 'En protégeant les sentiers de la justice Et en gardant la voie de ses fidèles.'),
  (20, 2, 9, 'Alors tu comprendras la justice, l''équité, La droiture, toutes les routes qui mènent au bien.'),
  (20, 2, 10, 'Car la sagesse viendra dans ton cœur, Et la connaissance fera les délices de ton âme;'),
  (20, 2, 11, 'La réflexion veillera sur toi, L''intelligence te gardera,'),
  (20, 2, 12, 'Pour te délivrer de la voie du mal, De l''homme qui tient des discours pervers,'),
  (20, 2, 13, 'De ceux qui abandonnent les sentiers de la droiture Afin de marcher dans des chemins ténébreux,'),
  (20, 2, 14, 'Qui trouvent de la jouissance à faire le mal, Qui mettent leur plaisir dans la perversité,'),
  (20, 2, 15, 'Qui suivent des sentiers détournés, Et qui prennent des routes tortueuses;'),
  (20, 2, 16, 'Pour te délivrer de la femme étrangère, De l''étrangère qui emploie des paroles doucereuses,'),
  (20, 2, 17, 'Qui abandonne l''ami de sa jeunesse, Et qui oublie l''alliance de son Dieu;'),
  (20, 2, 18, 'Car sa maison penche vers la mort, Et sa route mène chez les morts:'),
  (20, 2, 19, 'Aucun de ceux qui vont à elle ne revient, Et ne retrouve les sentiers de la vie.'),
  (20, 2, 20, 'Tu marcheras ainsi dans la voie des gens de bien, Tu garderas les sentiers des justes.'),
  (20, 2, 21, 'Car les hommes droits habiteront le pays, Les hommes intègres y resteront;'),
  (20, 2, 22, 'Mais les méchants seront retranchés du pays, Les infidèles en seront arrachés.'),
  (20, 3, 1, 'Mon fils, n''oublie pas mes enseignements, Et que ton cœur garde mes préceptes;'),
  (20, 3, 2, 'Car ils prolongeront les jours et les années de ta vie, Et ils augmenteront ta paix.'),
  (20, 3, 3, 'Que la bonté et la fidélité ne t''abandonnent pas; Lie-les à ton cou, écris-les sur la table de ton cœur.'),
  (20, 3, 4, 'Tu acquerras ainsi de la grâce et une raison saine, Aux yeux de Dieu et des hommes.'),
  (20, 3, 5, 'Confie-toi en l''Éternel de tout ton cœur, Et ne t''appuie pas sur ta sagesse;'),
  (20, 3, 6, 'Reconnais-le dans toutes tes voies, Et il aplanira tes sentiers.'),
  (20, 3, 7, 'Ne sois point sage à tes propres yeux, Crains l''Éternel, et détourne-toi du mal:'),
  (20, 3, 8, 'Ce sera la santé pour tes muscles, Et un rafraîchissement pour tes os.'),
  (20, 3, 9, 'Honore l''Éternel avec tes biens, Et avec les prémices de tout ton revenu:'),
  (20, 3, 10, 'Alors tes greniers seront remplis d''abondance, Et tes cuves regorgeront de moût.'),
  (20, 3, 11, 'Mon fils, ne méprise pas la correction de l''Éternel, Et ne t''effraie point de ses châtiments;'),
  (20, 3, 12, 'Car l''Éternel châtie celui qu''il aime, Comme un père l''enfant qu''il chérit.'),
  (20, 3, 13, 'Heureux l''homme qui a trouvé la sagesse, Et l''homme qui possède l''intelligence!'),
  (20, 3, 14, 'Car le gain qu''elle procure est préférable à celui de l''argent, Et le profit qu''on en tire vaut mieux que l''or;'),
  (20, 3, 15, 'Elle est plus précieuse que les perles, Elle a plus de valeur que tous les objets de prix.'),
  (20, 3, 16, 'Dans sa droite est une longue vie; Dans sa gauche, la richesse et la gloire.'),
  (20, 3, 17, 'Ses voies sont des voies agréables, Et tous ses sentiers sont paisibles.'),
  (20, 3, 18, 'Elle est un arbre de vie pour ceux qui la saisissent, Et ceux qui la possèdent sont heureux.'),
  (20, 3, 19, 'C''est par la sagesse que l''Éternel a fondé la terre, C''est par l''intelligence qu''il a affermi les cieux;'),
  (20, 3, 20, 'C''est par sa science que les abîmes se sont ouverts, Et que les nuages distillent la rosée.'),
  (20, 3, 21, 'Mon fils, que ces enseignements ne s''éloignent pas de tes yeux, Garde la sagesse et la réflexion:'),
  (20, 3, 22, 'Elles seront la vie de ton âme, Et l''ornement de ton cou.'),
  (20, 3, 23, 'Alors tu marcheras avec assurance dans ton chemin, Et ton pied ne heurtera pas.'),
  (20, 3, 24, 'Si tu te couches, tu seras sans crainte; Et quand tu seras couché, ton sommeil sera doux.'),
  (20, 3, 25, 'Ne redoute ni une terreur soudaine, Ni une attaque de la part des méchants;'),
  (20, 3, 26, 'Car l''Éternel sera ton assurance, Et il préservera ton pied de toute embûche.'),
  (20, 3, 27, 'Ne refuse pas un bienfait à celui qui y a droit, Quand tu as le pouvoir de l''accorder.'),
  (20, 3, 28, 'Ne dis pas à ton prochain: Va et reviens, Demain je donnerai! quand tu as de quoi donner.'),
  (20, 3, 29, 'Ne médite pas le mal contre ton prochain, Lorsqu''il demeure tranquillement près de toi.'),
  (20, 3, 30, 'Ne conteste pas sans motif avec quelqu''un, Lorsqu''il ne t''a point fait de mal.'),
  (20, 3, 31, 'Ne porte pas envie à l''homme violent, Et ne choisis aucune de ses voies.'),
  (20, 3, 32, 'Car l''Éternel a en horreur les hommes pervers, Mais il est un ami pour les hommes droits;'),
  (20, 3, 33, 'La malédiction de l''Éternel est dans la maison du méchant, Mais il bénit la demeure des justes;'),
  (20, 3, 34, 'Il se moque des moqueurs, Mais il fait grâce aux humbles;'),
  (20, 3, 35, 'Les sages hériteront la gloire, Mais les insensés ont la honte en partage.'),
  (20, 4, 1, 'Écoutez, mes fils, l''instruction d''un père, Et soyez attentifs, pour connaître la sagesse;'),
  (20, 4, 2, 'Car je vous donne de bons conseils: Ne rejetez pas mon enseignement.'),
  (20, 4, 3, 'J''étais un fils pour mon père, Un fils tendre et unique auprès de ma mère.'),
  (20, 4, 4, 'Il m''instruisait alors, et il me disait: Que ton cœur retienne mes paroles; Observe mes préceptes, et tu vivras.'),
  (20, 4, 5, 'Acquiers la sagesse, acquiers l''intelligence; N''oublie pas les paroles de ma bouche, et ne t''en détourne pas.'),
  (20, 4, 6, 'Ne l''abandonne pas, et elle te gardera; Aime-la, et elle te protégera.'),
  (20, 4, 7, 'Voici le commencement de la sagesse: Acquiers la sagesse, Et avec tout ce que tu possèdes acquiers l''intelligence.'),
  (20, 4, 8, 'Exalte-la, et elle t''élèvera; Elle fera ta gloire, si tu l''embrasses;'),
  (20, 4, 9, 'Elle mettra sur ta tête une couronne de grâce, Elle t''ornera d''un magnifique diadème.'),
  (20, 4, 10, 'Écoute, mon fils, et reçois mes paroles; Et les années de ta vie se multiplieront.'),
  (20, 4, 11, 'Je te montre la voie de la sagesse, Je te conduis dans les sentiers de la droiture.'),
  (20, 4, 12, 'Si tu marches, ton pas ne sera point gêné; Et si tu cours, tu ne chancelleras point.'),
  (20, 4, 13, 'Retiens l''instruction, ne t''en dessaisis pas; Garde-la, car elle est ta vie.'),
  (20, 4, 14, 'N''entre pas dans le sentier des méchants, Et ne marche pas dans la voie des hommes mauvais.'),
  (20, 4, 15, 'Évite-la, n''y passe point; Détourne-t''en, et passe outre.'),
  (20, 4, 16, 'Car ils ne dormiraient pas s''ils n''avaient fait le mal, Le sommeil leur serait ravi s''ils n''avaient fait tomber personne;'),
  (20, 4, 17, 'Car c''est le pain de la méchanceté qu''ils mangent, C''est le vin de la violence qu''ils boivent.'),
  (20, 4, 18, 'Le sentier des justes est comme la lumière resplendissante, Dont l''éclat va croissant jusqu''au milieu du jour.'),
  (20, 4, 19, 'La voie des méchants est comme les ténèbres; Ils n''aperçoivent pas ce qui les fera tomber.'),
  (20, 4, 20, 'Mon fils, sois attentif à mes paroles, Prête l''oreille à mes discours.'),
  (20, 4, 21, 'Qu''ils ne s''éloignent pas de tes yeux; Garde-les dans le fond de ton cœur;'),
  (20, 4, 22, 'Car c''est la vie pour ceux qui les trouvent, C''est la santé pour tout leur corps.'),
  (20, 4, 23, 'Garde ton cœur plus que toute autre chose, Car de lui viennent les sources de la vie.'),
  (20, 4, 24, 'Écarte de ta bouche la fausseté, Éloigne de tes lèvres les détours.'),
  (20, 4, 25, 'Que tes yeux regardent en face, Et que tes paupières se dirigent devant toi.'),
  (20, 4, 26, 'Considère le chemin par où tu passes, Et que toutes tes voies soient bien réglées;'),
  (20, 4, 27, 'N''incline ni à droite ni à gauche, Et détourne ton pied du mal.'),
  (20, 5, 1, 'Mon fils, sois attentif à ma sagesse, Prête l''oreille à mon intelligence,'),
  (20, 5, 2, 'Afin que tu conserves la réflexion, Et que tes lèvres gardent la connaissance.'),
  (20, 5, 3, 'Car les lèvres de l''étrangère distillent le miel, Et son palais est plus doux que l''huile;'),
  (20, 5, 4, 'Mais à la fin elle est amère comme l''absinthe, Aiguë comme un glaive à deux tranchants.'),
  (20, 5, 5, 'Ses pieds descendent vers la mort, Ses pas atteignent le séjour des morts.'),
  (20, 5, 6, 'Afin de ne pas considérer le chemin de la vie, Elle est errante dans ses voies, elle ne sait où elle va.'),
  (20, 5, 7, 'Et maintenant, mes fils, écoutez-moi, Et ne vous écartez pas des paroles de ma bouche.'),
  (20, 5, 8, 'Éloigne-toi du chemin qui conduit chez elle, Et ne t''approche pas de la porte de sa maison,'),
  (20, 5, 9, 'De peur que tu ne livres ta vigueur à d''autres, Et tes années à un homme cruel;'),
  (20, 5, 10, 'De peur que des étrangers ne se rassasient de ton bien, Et du produit de ton travail dans la maison d''autrui;'),
  (20, 5, 11, 'De peur que tu ne gémisses, près de ta fin, Quand ta chair et ton corps se consumeront,'),
  (20, 5, 12, 'Et que tu ne dises: Comment donc ai-je pu haïr la correction, Et comment mon cœur a-t-il dédaigné la réprimande?'),
  (20, 5, 13, 'Comment ai-je pu ne pas écouter la voix de mes maîtres, Ne pas prêter l''oreille à ceux qui m''instruisaient?'),
  (20, 5, 14, 'Peu s''en est fallu que je n''aie éprouvé tous les malheurs Au milieu du peuple et de l''assemblée.'),
  (20, 5, 15, 'Bois les eaux de ta citerne, Les eaux qui sortent de ton puits.'),
  (20, 5, 16, 'Tes sources doivent-elles se répandre au dehors? Tes ruisseaux doivent ils couler sur les places publiques?'),
  (20, 5, 17, 'Qu''ils soient pour toi seul, Et non pour des étrangers avec toi.'),
  (20, 5, 18, 'Que ta source soit bénie, Et fais ta joie de la femme de ta jeunesse,'),
  (20, 5, 19, 'Biche des amours, gazelle pleine de grâce: Sois en tout temps enivré de ses charmes, Sans cesse épris de son amour.'),
  (20, 5, 20, 'Et pourquoi, mon fils, serais-tu épris d''une étrangère, Et embrasserais-tu le sein d''une inconnue?'),
  (20, 5, 21, 'Car les voies de l''homme sont devant les yeux de l''Éternel, Qui observe tous ses sentiers.'),
  (20, 5, 22, 'Le méchant est pris dans ses propres iniquités, Il est saisi par les liens de son péché.'),
  (20, 5, 23, 'Il mourra faute d''instruction, Il chancellera par l''excès de sa folie.'),
  (20, 6, 1, 'Mon fils, si tu as cautionné ton prochain, Si tu t''es engagé pour autrui,'),
  (20, 6, 2, 'Si tu es enlacé par les paroles de ta bouche, Si tu es pris par les paroles de ta bouche,'),
  (20, 6, 3, 'Fais donc ceci, mon fils, dégage-toi, Puisque tu es tombé au pouvoir de ton prochain; Va, prosterne-toi, et fais des instances auprès de lui;'),
  (20, 6, 4, 'Ne donne ni sommeil à tes yeux, Ni assoupissement à tes paupières;'),
  (20, 6, 5, 'Dégage-toi comme la gazelle de la main du chasseur, Comme l''oiseau de la main de l''oiseleur.'),
  (20, 6, 6, 'Va vers la fourmi, paresseux; Considère ses voies, et deviens sage.'),
  (20, 6, 7, 'Elle n''a ni chef, Ni inspecteur, ni maître;'),
  (20, 6, 8, 'Elle prépare en été sa nourriture, Elle amasse pendant la moisson de quoi manger.'),
  (20, 6, 9, 'Paresseux, jusqu''à quand seras-tu couché? Quand te lèveras-tu de ton sommeil?'),
  (20, 6, 10, 'Un peu de sommeil, un peu d''assoupissement, Un peu croiser les mains pour dormir!…'),
  (20, 6, 11, 'Et la pauvreté te surprendra, comme un rôdeur, Et la disette, comme un homme en armes.'),
  (20, 6, 12, 'L''homme pervers, l''homme inique, Marche la fausseté dans la bouche;'),
  (20, 6, 13, 'Il cligne des yeux, parle du pied, Fait des signes avec les doigts;'),
  (20, 6, 14, 'La perversité est dans son cœur, Il médite le mal en tout temps, Il excite des querelles.'),
  (20, 6, 15, 'Aussi sa ruine arrivera-t-elle subitement; Il sera brisé tout d''un coup, et sans remède.'),
  (20, 6, 16, 'Il y a six choses que hait l''Éternel, Et même sept qu''il a en horreur;'),
  (20, 6, 17, 'Les yeux hautains, la langue menteuse, Les mains qui répandent le sang innocent,'),
  (20, 6, 18, 'Le cœur qui médite des projets iniques, Les pieds qui se hâtent de courir au mal,'),
  (20, 6, 19, 'Le faux témoin qui dit des mensonges, Et celui qui excite des querelles entre frères.'),
  (20, 6, 20, 'Mon fils, garde les préceptes de ton père, Et ne rejette pas l''enseignement de ta mère.'),
  (20, 6, 21, 'Lie-les constamment sur ton cœur, Attache-les à ton cou.'),
  (20, 6, 22, 'Ils te dirigeront dans ta marche, Ils te garderont sur ta couche, Ils te parleront à ton réveil.'),
  (20, 6, 23, 'Car le précepte est une lampe, et l''enseignement une lumière, Et les avertissements de la correction sont le chemin de la vie:'),
  (20, 6, 24, 'Ils te préserveront de la femme corrompue, De la langue doucereuse de l''étrangère.'),
  (20, 6, 25, 'Ne la convoite pas dans ton cœur pour sa beauté, Et ne te laisse pas séduire par ses paupières.'),
  (20, 6, 26, 'Car pour la femme prostituée on se réduit à un morceau de pain, Et la femme mariée tend un piège à la vie précieuse.'),
  (20, 6, 27, 'Quelqu''un mettra-t-il du feu dans son sein, Sans que ses vêtements s''enflamment?'),
  (20, 6, 28, 'Quelqu''un marchera-t-il sur des charbons ardents, Sans que ses pieds soient brûlés?'),
  (20, 6, 29, 'Il en est de même pour celui qui va vers la femme de son prochain: Quiconque la touche ne restera pas impuni.'),
  (20, 6, 30, 'On ne tient pas pour innocent le voleur qui dérobe Pour satisfaire son appétit, quand il a faim;'),
  (20, 6, 31, 'Si on le trouve, il fera une restitution au septuple, Il donnera tout ce qu''il a dans sa maison.'),
  (20, 6, 32, 'Mais celui qui commet un adultère avec une femme est dépourvu de sens, Celui qui veut se perdre agit de la sorte;'),
  (20, 6, 33, 'Il n''aura que plaie et ignominie, Et son opprobre ne s''effacera point.'),
  (20, 6, 34, 'Car la jalousie met un homme en fureur, Et il est sans pitié au jour de la vengeance;'),
  (20, 6, 35, 'Il n''a égard à aucune rançon, Et il est inflexible, quand même tu multiplierais les dons.'),
  (20, 7, 1, 'Mon fils, retiens mes paroles, Et garde avec toi mes préceptes.'),
  (20, 7, 2, 'Observe mes préceptes, et tu vivras; Garde mes enseignements comme la prunelle de tes yeux.'),
  (20, 7, 3, 'Lie-les sur tes doigts, Écris-les sur la table de ton cœur.'),
  (20, 7, 4, 'Dis à la sagesse: Tu es ma sœur! Et appelle l''intelligence ton amie,'),
  (20, 7, 5, 'Pour qu''elles te préservent de la femme étrangère, De l''étrangère qui emploie des paroles doucereuses.'),
  (20, 7, 6, 'J''étais à la fenêtre de ma maison, Et je regardais à travers mon treillis.'),
  (20, 7, 7, 'J''aperçus parmi les stupides, Je remarquai parmi les jeunes gens un garçon dépourvu de sens.'),
  (20, 7, 8, 'Il passait dans la rue, près de l''angle où se tenait une de ces étrangères, Et il se dirigeait lentement du côté de sa demeure:'),
  (20, 7, 9, 'C''était au crépuscule, pendant la soirée, Au milieu de la nuit et de l''obscurité.'),
  (20, 7, 10, 'Et voici, il fut abordé par une femme Ayant la mise d''une prostituée et la ruse dans le cœur.'),
  (20, 7, 11, 'Elle était bruyante et rétive; Ses pieds ne restaient point dans sa maison;'),
  (20, 7, 12, 'Tantôt dans la rue, tantôt sur les places, Et près de tous les angles, elle était aux aguets.'),
  (20, 7, 13, 'Elle le saisit et l''embrassa, Et d''un air effronté lui dit:'),
  (20, 7, 14, 'Je devais un sacrifice d''actions de grâces, Aujourd''hui j''ai accompli mes vœux.'),
  (20, 7, 15, 'C''est pourquoi je suis sortie au-devant de toi Pour te chercher, et je t''ai trouvé.'),
  (20, 7, 16, 'J''ai orné mon lit de couvertures, De tapis de fil d''Égypte;'),
  (20, 7, 17, 'J''ai parfumé ma couche De myrrhe, d''aloès et de cinnamome.'),
  (20, 7, 18, 'Viens, enivrons-nous d''amour jusqu''au matin, Livrons-nous joyeusement à la volupté.'),
  (20, 7, 19, 'Car mon mari n''est pas à la maison, Il est parti pour un voyage lointain;'),
  (20, 7, 20, 'Il a pris avec lui le sac de l''argent, Il ne reviendra à la maison qu''à la nouvelle lune.'),
  (20, 7, 21, 'Elle le séduisit à force de paroles, Elle l''entraîna par ses lèvres doucereuses.'),
  (20, 7, 22, 'Il se mit tout à coup à la suivre, Comme le bœuf qui va à la boucherie, Comme un fou qu''on lie pour le châtier,'),
  (20, 7, 23, 'Jusqu''à ce qu''une flèche lui perce le foie, Comme l''oiseau qui se précipite dans le filet, Sans savoir que c''est au prix de sa vie.'),
  (20, 7, 24, 'Et maintenant, mes fils, écoutez-moi, Et soyez attentifs aux paroles de ma bouche.'),
  (20, 7, 25, 'Que ton cœur ne se détourne pas vers les voies d''une telle femme, Ne t''égare pas dans ses sentiers.'),
  (20, 7, 26, 'Car elle a fait tomber beaucoup de victimes, Et ils sont nombreux, tous ceux qu''elle a tués.'),
  (20, 7, 27, 'Sa maison, c''est le chemin du séjour des morts; Il descend vers les demeures de la mort.'),
  (20, 8, 1, 'La sagesse ne crie-t-elle pas? L''intelligence n''élève-t-elle pas sa voix?'),
  (20, 8, 2, 'C''est au sommet des hauteurs près de la route, C''est à la croisée des chemins qu''elle se place;'),
  (20, 8, 3, 'A côté des portes, à l''entrée de la ville, A l''intérieur des portes, elle fait entendre ses cris:'),
  (20, 8, 4, 'Hommes, c''est à vous que je crie, Et ma voix s''adresse aux fils de l''homme.'),
  (20, 8, 5, 'Stupides, apprenez le discernement; Insensés, apprenez l''intelligence.'),
  (20, 8, 6, 'Écoutez, car j''ai de grandes choses à dire, Et mes lèvres s''ouvrent pour enseigner ce qui est droit.'),
  (20, 8, 7, 'Car ma bouche proclame la vérité, Et mes lèvres ont en horreur le mensonge;'),
  (20, 8, 8, 'Toutes les paroles de ma bouche sont justes, Elles n''ont rien de faux ni de détourné;'),
  (20, 8, 9, 'Toutes sont claires pour celui qui est intelligent, Et droites pour ceux qui ont trouvé la science.'),
  (20, 8, 10, 'Préférez mes instructions à l''argent, Et la science à l''or le plus précieux;'),
  (20, 8, 11, 'Car la sagesse vaut mieux que les perles, Elle a plus de valeur que tous les objets de prix.'),
  (20, 8, 12, 'Moi, la sagesse, j''ai pour demeure le discernement, Et je possède la science de la réflexion.'),
  (20, 8, 13, 'La crainte de l''Éternel, c''est la haine du mal; L''arrogance et l''orgueil, la voie du mal, Et la bouche perverse, voilà ce que je hais.'),
  (20, 8, 14, 'Le conseil et le succès m''appartiennent; Je suis l''intelligence, la force est à moi.'),
  (20, 8, 15, 'Par moi les rois règnent, Et les princes ordonnent ce qui est juste;'),
  (20, 8, 16, 'Par moi gouvernent les chefs, Les grands, tous les juges de la terre.'),
  (20, 8, 17, 'J''aime ceux qui m''aiment, Et ceux qui me cherchent me trouvent.'),
  (20, 8, 18, 'Avec moi sont la richesse et la gloire, Les biens durables et la justice.'),
  (20, 8, 19, 'Mon fruit est meilleur que l''or, que l''or pur, Et mon produit est préférable à l''argent.'),
  (20, 8, 20, 'Je marche dans le chemin de la justice, Au milieu des sentiers de la droiture,'),
  (20, 8, 21, 'Pour donner des biens à ceux qui m''aiment, Et pour remplir leurs trésors.'),
  (20, 8, 22, 'L''Éternel m''a créée la première de ses œuvres, Avant ses œuvres les plus anciennes.'),
  (20, 8, 23, 'J''ai été établie depuis l''éternité, Dès le commencement, avant l''origine de la terre.'),
  (20, 8, 24, 'Je fus enfantée quand il n''y avait point d''abîmes, Point de sources chargées d''eaux;'),
  (20, 8, 25, 'Avant que les montagnes soient affermies, Avant que les collines existent, je fus enfantée;'),
  (20, 8, 26, 'Il n''avait encore fait ni la terre, ni les campagnes, Ni le premier atome de la poussière du monde.'),
  (20, 8, 27, 'Lorsqu''il disposa les cieux, j''étais là; Lorsqu''il traça un cercle à la surface de l''abîme,'),
  (20, 8, 28, 'Lorsqu''il fixa les nuages en haut, Et que les sources de l''abîme jaillirent avec force,'),
  (20, 8, 29, 'Lorsqu''il donna une limite à la mer, Pour que les eaux n''en franchissent pas les bords, Lorsqu''il posa les fondements de la terre,'),
  (20, 8, 30, 'J''étais à l''œuvre auprès de lui, Et je faisais tous les jours ses délices, Jouant sans cesse en sa présence,'),
  (20, 8, 31, 'Jouant sur le globe de sa terre, Et trouvant mon bonheur parmi les fils de l''homme.'),
  (20, 8, 32, 'Et maintenant, mes fils, écoutez-moi, Et heureux ceux qui observent mes voies!'),
  (20, 8, 33, 'Écoutez l''instruction, pour devenir sages, Ne la rejetez pas.'),
  (20, 8, 34, 'Heureux l''homme qui m''écoute, Qui veille chaque jour à mes portes, Et qui en garde les poteaux!'),
  (20, 8, 35, 'Car celui qui me trouve a trouvé la vie, Et il obtient la faveur de l''Éternel.'),
  (20, 8, 36, 'Mais celui qui pèche contre moi nuit à son âme; Tous ceux qui me haïssent aiment la mort.'),
  (20, 9, 1, 'La sagesse a bâti sa maison, Elle a taillé ses sept colonnes.'),
  (20, 9, 2, 'Elle a égorgé ses victimes, mêlé son vin, Et dressé sa table.'),
  (20, 9, 3, 'Elle a envoyé ses servantes, elle crie Sur le sommet des hauteurs de la ville:'),
  (20, 9, 4, 'Que celui qui est stupide entre ici! Elle dit à ceux qui sont dépourvus de sens:'),
  (20, 9, 5, 'Venez, mangez de mon pain, Et buvez du vin que j''ai mêlé;'),
  (20, 9, 6, 'Quittez la stupidité, et vous vivrez, Et marchez dans la voie de l''intelligence!'),
  (20, 9, 7, 'Celui qui reprend le moqueur s''attire le dédain, Et celui qui corrige le méchant reçoit un outrage.'),
  (20, 9, 8, 'Ne reprends pas le moqueur, de crainte qu''il ne te haïsse; Reprends le sage, et il t''aimera.'),
  (20, 9, 9, 'Donne au sage, et il deviendra plus sage; Instruis le juste, et il augmentera son savoir.'),
  (20, 9, 10, 'Le commencement de la sagesse, c''est la crainte de l''Éternel; Et la science des saints, c''est l''intelligence.'),
  (20, 9, 11, 'C''est par moi que tes jours se multiplieront, Et que les années de ta vie augmenteront.'),
  (20, 9, 12, 'Si tu es sage, tu es sage pour toi; Si tu es moqueur, tu en porteras seul la peine.'),
  (20, 9, 13, 'La folie est une femme bruyante, Stupide et ne sachant rien.'),
  (20, 9, 14, 'Elle s''assied à l''entrée de sa maison, Sur un siège, dans les hauteurs de la ville,'),
  (20, 9, 15, 'Pour crier aux passants, Qui vont droit leur chemin:'),
  (20, 9, 16, 'Que celui qui est stupide entre ici! Elle dit à celui qui est dépourvu de sens:'),
  (20, 9, 17, 'Les eaux dérobées sont douces, Et le pain du mystère est agréable!'),
  (20, 9, 18, 'Et il ne sait pas que là sont les morts, Et que ses invités sont dans les vallées du séjour des morts.'),
  (20, 10, 1, 'Proverbes de Salomon. Un fils sage fait la joie d''un père, Et un fils insensé le chagrin de sa mère.'),
  (20, 10, 2, 'Les trésors de la méchanceté ne profitent pas, Mais la justice délivre de la mort.'),
  (20, 10, 3, 'L''Éternel ne laisse pas le juste souffrir de la faim, Mais il repousse l''avidité des méchants.'),
  (20, 10, 4, 'Celui qui agit d''une main lâche s''appauvrit, Mais la main des diligents enrichit.'),
  (20, 10, 5, 'Celui qui amasse pendant l''été est un fils prudent, Celui qui dort pendant la moisson est un fils qui fait honte.'),
  (20, 10, 6, 'Il y a des bénédictions sur la tête du juste, Mais la violence couvre la bouche des méchants.'),
  (20, 10, 7, 'La mémoire du juste est en bénédiction, Mais le nom des méchants tombe en pourriture.'),
  (20, 10, 8, 'Celui qui est sage de cœur reçoit les préceptes, Mais celui qui est insensé des lèvres court à sa perte.'),
  (20, 10, 9, 'Celui qui marche dans l''intégrité marche avec assurance, Mais celui qui prend des voies tortueuses sera découvert.'),
  (20, 10, 10, 'Celui qui cligne des yeux est une cause de chagrin, Et celui qui est insensé des lèvres court à sa perte.'),
  (20, 10, 11, 'La bouche du juste est une source de vie, Mais la violence couvre la bouche des méchants.'),
  (20, 10, 12, 'La haine excite des querelles, Mais l''amour couvre toutes les fautes.'),
  (20, 10, 13, 'Sur les lèvres de l''homme intelligent se trouve la sagesse, Mais la verge est pour le dos de celui qui est dépourvu de sens.'),
  (20, 10, 14, 'Les sages tiennent la science en réserve, Mais la bouche de l''insensé est une ruine prochaine.'),
  (20, 10, 15, 'La fortune est pour le riche une ville forte; La ruine des misérables, c''est leur pauvreté.'),
  (20, 10, 16, 'L''œuvre du juste est pour la vie, Le gain du méchant est pour le péché.'),
  (20, 10, 17, 'Celui qui se souvient de la correction prend le chemin de la vie, Mais celui qui oublie la réprimande s''égare.'),
  (20, 10, 18, 'Celui qui dissimule la haine a des lèvres menteuses, Et celui qui répand la calomnie est un insensé.'),
  (20, 10, 19, 'Celui qui parle beaucoup ne manque pas de pécher, Mais celui qui retient ses lèvres est un homme prudent.'),
  (20, 10, 20, 'La langue du juste est un argent de choix; Le cœur des méchants est peu de chose.'),
  (20, 10, 21, 'Les lèvres du juste dirigent beaucoup d''hommes, Et les insensés meurent par défaut de raison.'),
  (20, 10, 22, 'C''est la bénédiction de l''Éternel qui enrichit, Et il ne la fait suivre d''aucun chagrin.'),
  (20, 10, 23, 'Commettre le crime paraît un jeu à l''insensé, Mais la sagesse appartient à l''homme intelligent.'),
  (20, 10, 24, 'Ce que redoute le méchant, c''est ce qui lui arrive; Et ce que désirent les justes leur est accordé.'),
  (20, 10, 25, 'Comme passe le tourbillon, ainsi disparaît le méchant; Mais le juste a des fondements éternels.'),
  (20, 10, 26, 'Ce que le vinaigre est aux dents et la fumée aux yeux, Tel est le paresseux pour celui qui l''envoie.'),
  (20, 10, 27, 'La crainte de l''Éternel augmente les jours, Mais les années des méchants sont abrégées.'),
  (20, 10, 28, 'L''attente des justes n''est que joie, Mais l''espérance des méchants périra.'),
  (20, 10, 29, 'La voie de l''Éternel est un rempart pour l''intégrité, Mais elle est une ruine pour ceux qui font le mal.'),
  (20, 10, 30, 'Le juste ne chancellera jamais, Mais les méchants n''habiteront pas le pays.'),
  (20, 10, 31, 'La bouche du juste produit la sagesse, Mais la langue perverse sera retranchée.'),
  (20, 10, 32, 'Les lèvres du juste connaissent la grâce, Et la bouche des méchants la perversité.'),
  (20, 11, 1, 'La balance fausse est en horreur à l''Éternel, Mais le poids juste lui est agréable.'),
  (20, 11, 2, 'Quand vient l''orgueil, vient aussi l''ignominie; Mais la sagesse est avec les humbles.'),
  (20, 11, 3, 'L''intégrité des hommes droits les dirige, Mais les détours des perfides causent leur ruine.'),
  (20, 11, 4, 'Au jour de la colère, la richesse ne sert à rien; Mais la justice délivre de la mort.'),
  (20, 11, 5, 'La justice de l''homme intègre aplanit sa voie, Mais le méchant tombe par sa méchanceté.'),
  (20, 11, 6, 'La justice des hommes droits les délivre, Mais les méchants sont pris par leur malice.'),
  (20, 11, 7, 'A la mort du méchant, son espoir périt, Et l''attente des hommes iniques est anéantie.'),
  (20, 11, 8, 'Le juste est délivré de la détresse, Et le méchant prend sa place.'),
  (20, 11, 9, 'Par sa bouche l''impie perd son prochain, Mais les justes sont délivrés par la science.'),
  (20, 11, 10, 'Quand les justes sont heureux, la ville est dans la joie; Et quand les méchants périssent, on pousse des cris d''allégresse.'),
  (20, 11, 11, 'La ville s''élève par la bénédiction des hommes droits, Mais elle est renversée par la bouche des méchants.'),
  (20, 11, 12, 'Celui qui méprise son prochain est dépourvu de sens, Mais l''homme qui a de l''intelligence se tait.'),
  (20, 11, 13, 'Celui qui répand la calomnie dévoile les secrets, Mais celui qui a l''esprit fidèle les garde.'),
  (20, 11, 14, 'Quand la prudence fait défaut, le peuple tombe; Et le salut est dans le grand nombre des conseillers.'),
  (20, 11, 15, 'Celui qui cautionne autrui s''en trouve mal, Mais celui qui craint de s''engager est en sécurité.'),
  (20, 11, 16, 'Une femme qui a de la grâce obtient la gloire, Et ceux qui ont de la force obtiennent la richesse.'),
  (20, 11, 17, 'L''homme bon fait du bien à son âme, Mais l''homme cruel trouble sa propre chair.'),
  (20, 11, 18, 'Le méchant fait un gain trompeur, Mais celui qui sème la justice a un salaire véritable.'),
  (20, 11, 19, 'Ainsi la justice conduit à la vie, Mais celui qui poursuit le mal trouve la mort.'),
  (20, 11, 20, 'Ceux qui ont le cœur pervers sont en abomination à l''Éternel, Mais ceux dont la voie est intègre lui sont agréables.'),
  (20, 11, 21, 'Certes, le méchant ne restera pas impuni, Mais la postérité des justes sera sauvée.'),
  (20, 11, 22, 'Un anneau d''or au nez d''un pourceau, C''est une femme belle et dépourvue de sens.'),
  (20, 11, 23, 'Le désir des justes, c''est seulement le bien; L''attente des méchants, c''est la fureur.'),
  (20, 11, 24, 'Tel, qui donne libéralement, devient plus riche; Et tel, qui épargne à l''excès, ne fait que s''appauvrir.'),
  (20, 11, 25, 'L''âme bienfaisante sera rassasiée, Et celui qui arrose sera lui-même arrosé.'),
  (20, 11, 26, 'Celui qui retient le blé est maudit du peuple, Mais la bénédiction est sur la tête de celui qui le vend.'),
  (20, 11, 27, 'Celui qui recherche le bien s''attire de la faveur, Mais celui qui poursuit le mal en est atteint.'),
  (20, 11, 28, 'Celui qui se confie dans ses richesses tombera, Mais les justes verdiront comme le feuillage.'),
  (20, 11, 29, 'Celui qui trouble sa maison héritera du vent, Et l''insensé sera l''esclave de l''homme sage.'),
  (20, 11, 30, 'Le fruit du juste est un arbre de vie, Et le sage s''empare des âmes.'),
  (20, 11, 31, 'Voici, le juste reçoit sur la terre une rétribution; Combien plus le méchant et le pécheur!'),
  (20, 12, 1, 'Celui qui aime la correction aime la science; Celui qui hait la réprimande est stupide.'),
  (20, 12, 2, 'L''homme de bien obtient la faveur de l''Éternel, Mais l''Éternel condamne celui qui est plein de malice.'),
  (20, 12, 3, 'L''homme ne s''affermit pas par la méchanceté, Mais la racine des justes ne sera point ébranlée.'),
  (20, 12, 4, 'Une femme vertueuse est la couronne de son mari, Mais celle qui fait honte est comme la carie dans ses os.'),
  (20, 12, 5, 'Les pensées des justes ne sont qu''équité; Les desseins des méchants ne sont que fraude.'),
  (20, 12, 6, 'Les paroles des méchants sont des embûches pour verser le sang, Mais la bouche des hommes droits est une délivrance.'),
  (20, 12, 7, 'Renversés, les méchants ne sont plus; Et la maison des justes reste debout.'),
  (20, 12, 8, 'Un homme est estimé en raison de son intelligence, Et celui qui a le cœur pervers est l''objet du mépris.'),
  (20, 12, 9, 'Mieux vaut être d''une condition humble et avoir un serviteur Que de faire le glorieux et de manquer de pain.'),
  (20, 12, 10, 'Le juste prend soin de son bétail, Mais les entrailles des méchants sont cruelles.'),
  (20, 12, 11, 'Celui qui cultive son champ est rassasié de pain, Mais celui qui poursuit des choses vaines est dépourvu de sens.'),
  (20, 12, 12, 'Le méchant convoite ce que prennent les méchants, Mais la racine des justes donne du fruit.'),
  (20, 12, 13, 'Il y a dans le péché des lèvres un piège pernicieux, Mais le juste se tire de la détresse.'),
  (20, 12, 14, 'Par le fruit de la bouche on est rassasié de biens, Et chacun reçoit selon l''œuvre de ses mains.'),
  (20, 12, 15, 'La voie de l''insensé est droite à ses yeux, Mais celui qui écoute les conseils est sage.'),
  (20, 12, 16, 'L''insensé laisse voir à l''instant sa colère, Mais celui qui cache un outrage est un homme prudent.'),
  (20, 12, 17, 'Celui qui dit la vérité proclame la justice, Et le faux témoin la tromperie.'),
  (20, 12, 18, 'Tel, qui parle légèrement, blesse comme un glaive; Mais la langue des sages apporte la guérison.'),
  (20, 12, 19, 'La lèvre véridique est affermie pour toujours, Mais la langue fausse ne subsiste qu''un instant.'),
  (20, 12, 20, 'La tromperie est dans le cœur de ceux qui méditent le mal, Mais la joie est pour ceux qui conseillent la paix.'),
  (20, 12, 21, 'Aucun malheur n''arrive au juste, Mais les méchants sont accablés de maux.'),
  (20, 12, 22, 'Les lèvres fausses sont en horreur à l''Éternel, Mais ceux qui agissent avec vérité lui sont agréables.'),
  (20, 12, 23, 'L''homme prudent cache sa science, Mais le cœur des insensés proclame la folie.'),
  (20, 12, 24, 'La main des diligents dominera, Mais la main lâche sera tributaire.'),
  (20, 12, 25, 'L''inquiétude dans le cœur de l''homme l''abat, Mais une bonne parole le réjouit.'),
  (20, 12, 26, 'Le juste montre à son ami la bonne voie, Mais la voie des méchants les égare.'),
  (20, 12, 27, 'Le paresseux ne rôtit pas son gibier; Mais le précieux trésor d''un homme, c''est l''activité.'),
  (20, 12, 28, 'La vie est dans le sentier de la justice, La mort n''est pas dans le chemin qu''elle trace.'),
  (20, 13, 1, 'Un fils sage écoute l''instruction de son père, Mais le moqueur n''écoute pas la réprimande.'),
  (20, 13, 2, 'Par le fruit de la bouche on jouit du bien; Mais ce que désirent les perfides, c''est la violence.'),
  (20, 13, 3, 'Celui qui veille sur sa bouche garde son âme; Celui qui ouvre de grandes lèvres court à sa perte.'),
  (20, 13, 4, 'L''âme du paresseux a des désirs qu''il ne peut satisfaire; Mais l''âme des hommes diligents sera rassasiée.'),
  (20, 13, 5, 'Le juste hait les paroles mensongères; Le méchant se rend odieux et se couvre de honte.'),
  (20, 13, 6, 'La justice garde celui dont la voie est intègre, Mais la méchanceté cause la ruine du pécheur.'),
  (20, 13, 7, 'Tel fait le riche et n''a rien du tout, Tel fait le pauvre et a de grands biens.'),
  (20, 13, 8, 'La richesse d''un homme sert de rançon pour sa vie, Mais le pauvre n''écoute pas la réprimande.'),
  (20, 13, 9, 'La lumière des justes est joyeuse, Mais la lampe des méchants s''éteint.'),
  (20, 13, 10, 'C''est seulement par orgueil qu''on excite des querelles, Mais la sagesse est avec ceux qui écoutent les conseils.'),
  (20, 13, 11, 'La richesse mal acquise diminue, Mais celui qui amasse peu à peu l''augmente.'),
  (20, 13, 12, 'Un espoir différé rend le cœur malade, Mais un désir accompli est un arbre de vie.'),
  (20, 13, 13, 'Celui qui méprise la parole se perd, Mais celui qui craint le précepte est récompensé.'),
  (20, 13, 14, 'L''enseignement du sage est une source de vie, Pour détourner des pièges de la mort.'),
  (20, 13, 15, 'Une raison saine a pour fruit la grâce, Mais la voie des perfides est rude.'),
  (20, 13, 16, 'Tout homme prudent agit avec connaissance, Mais l''insensé fait étalage de folie.'),
  (20, 13, 17, 'Un envoyé méchant tombe dans le malheur, Mais un messager fidèle apporte la guérison.'),
  (20, 13, 18, 'La pauvreté et la honte sont le partage de celui qui rejette la correction, Mais celui qui a égard à la réprimande est honoré.'),
  (20, 13, 19, 'Un désir accompli est doux à l''âme, Mais s''éloigner du mal fait horreur aux insensés.'),
  (20, 13, 20, 'Celui qui fréquente les sages devient sage, Mais celui qui se plaît avec les insensés s''en trouve mal.'),
  (20, 13, 21, 'Le malheur poursuit ceux qui pèchent, Mais le bonheur récompense les justes.'),
  (20, 13, 22, 'L''homme de bien a pour héritiers les enfants de ses enfants, Mais les richesses du pécheur sont réservées pour le juste.'),
  (20, 13, 23, 'Le champ que défriche le pauvre donne une nourriture abondante, Mais tel périt par défaut de justice.'),
  (20, 13, 24, 'Celui qui ménage sa verge hait son fils, Mais celui qui l''aime cherche à le corriger.'),
  (20, 13, 25, 'Le juste mange et satisfait son appétit, Mais le ventre des méchants éprouve la disette.'),
  (20, 14, 1, 'La femme sage bâtit sa maison, Et la femme insensée la renverse de ses propres mains.'),
  (20, 14, 2, 'Celui qui marche dans la droiture craint l''Éternel, Mais celui qui prend des voies tortueuses le méprise.'),
  (20, 14, 3, 'Dans la bouche de l''insensé est une verge pour son orgueil, Mais les lèvres des sages les gardent.'),
  (20, 14, 4, 'S''il n''y a pas de bœufs, la crèche est vide; C''est à la vigueur des bœufs qu''on doit l''abondance des revenus.'),
  (20, 14, 5, 'Un témoin fidèle ne ment pas, Mais un faux témoin dit des mensonges.'),
  (20, 14, 6, 'Le moqueur cherche la sagesse et ne la trouve pas, Mais pour l''homme intelligent la science est chose facile.'),
  (20, 14, 7, 'Éloigne-toi de l''insensé; Ce n''est pas sur ses lèvres que tu aperçois la science.'),
  (20, 14, 8, 'La sagesse de l''homme prudent, c''est l''intelligence de sa voie; La folie des insensés, c''est la tromperie.'),
  (20, 14, 9, 'Les insensés se font un jeu du péché, Mais parmi les hommes droits se trouve la bienveillance.'),
  (20, 14, 10, 'Le cœur connaît ses propres chagrins, Et un étranger ne saurait partager sa joie.'),
  (20, 14, 11, 'La maison des méchants sera détruite, Mais la tente des hommes droits fleurira.'),
  (20, 14, 12, 'Telle voie paraît droite à un homme, Mais son issue, c''est la voie de la mort.'),
  (20, 14, 13, 'Au milieu même du rire le cœur peut être affligé, Et la joie peut finir par la détresse.'),
  (20, 14, 14, 'Celui dont le cœur s''égare se rassasie de ses voies, Et l''homme de bien se rassasie de ce qui est en lui.'),
  (20, 14, 15, 'L''homme simple croit tout ce qu''on dit, Mais l''homme prudent est attentif à ses pas.'),
  (20, 14, 16, 'Le sage a de la retenue et se détourne du mal, Mais l''insensé est arrogant et plein de sécurité.'),
  (20, 14, 17, 'Celui qui est prompt à la colère fait des sottises, Et l''homme plein de malice s''attire la haine.'),
  (20, 14, 18, 'Les simples ont en partage la folie, Et les hommes prudents se font de la science une couronne.'),
  (20, 14, 19, 'Les mauvais s''inclinent devant les bons, Et les méchants aux portes du juste.'),
  (20, 14, 20, 'Le pauvre est odieux même à son ami, Mais les amis du riche sont nombreux.'),
  (20, 14, 21, 'Celui qui méprise son prochain commet un péché, Mais heureux celui qui a pitié des misérables!'),
  (20, 14, 22, 'Ceux qui méditent le mal ne s''égarent-ils pas? Mais ceux qui méditent le bien agissent avec bonté et fidélité.'),
  (20, 14, 23, 'Tout travail procure l''abondance, Mais les paroles en l''air ne mènent qu''à la disette.'),
  (20, 14, 24, 'La richesse est une couronne pour les sages; La folie des insensés est toujours de la folie.'),
  (20, 14, 25, 'Le témoin véridique délivre des âmes, Mais le trompeur dit des mensonges.'),
  (20, 14, 26, 'Celui qui craint l''Éternel possède un appui ferme, Et ses enfants ont un refuge auprès de lui.'),
  (20, 14, 27, 'La crainte de l''Éternel est une source de vie, Pour détourner des pièges de la mort.'),
  (20, 14, 28, 'Quand le peuple est nombreux, c''est la gloire d''un roi; Quand le peuple manque, c''est la ruine du prince.'),
  (20, 14, 29, 'Celui qui est lent à la colère a une grande intelligence, Mais celui qui est prompt à s''emporter proclame sa folie.'),
  (20, 14, 30, 'Un cœur calme est la vie du corps, Mais l''envie est la carie des os.'),
  (20, 14, 31, 'Opprimer le pauvre, c''est outrager celui qui l''a fait; Mais avoir pitié de l''indigent, c''est l''honorer.'),
  (20, 14, 32, 'Le méchant est renversé par sa méchanceté, Mais le juste trouve un refuge même en sa mort.'),
  (20, 14, 33, 'Dans un cœur intelligent repose la sagesse, Mais au milieu des insensés elle se montre à découvert.'),
  (20, 14, 34, 'La justice élève une nation, Mais le péché est la honte des peuples.'),
  (20, 14, 35, 'La faveur du roi est pour le serviteur prudent, Et sa colère pour celui qui fait honte.'),
  (20, 15, 1, 'Une réponse douce calme la fureur, Mais une parole dure excite la colère.'),
  (20, 15, 2, 'La langue des sages rend la science aimable, Et la bouche des insensés répand la folie.'),
  (20, 15, 3, 'Les yeux de l''Éternel sont en tout lieu, Observant les méchants et les bons.'),
  (20, 15, 4, 'La langue douce est un arbre de vie, Mais la langue perverse brise l''âme.'),
  (20, 15, 5, 'L''insensé dédaigne l''instruction de son père, Mais celui qui a égard à la réprimande agit avec prudence.'),
  (20, 15, 6, 'Il y a grande abondance dans la maison du juste, Mais il y a du trouble dans les profits du méchant.'),
  (20, 15, 7, 'Les lèvres des sages répandent la science, Mais le cœur des insensés n''est pas droit.'),
  (20, 15, 8, 'Le sacrifice des méchants est en horreur à l''Éternel, Mais la prière des hommes droits lui est agréable.'),
  (20, 15, 9, 'La voie du méchant est en horreur à l''Éternel, Mais il aime celui qui poursuit la justice.'),
  (20, 15, 10, 'Une correction sévère menace celui qui abandonne le sentier; Celui qui hait la réprimande mourra.'),
  (20, 15, 11, 'Le séjour des morts et l''abîme sont devant l''Éternel; Combien plus les cœurs des fils de l''homme!'),
  (20, 15, 12, 'Le moqueur n''aime pas qu''on le reprenne, Il ne va point vers les sages.'),
  (20, 15, 13, 'Un cœur joyeux rend le visage serein; Mais quand le cœur est triste, l''esprit est abattu.'),
  (20, 15, 14, 'Un cœur intelligent cherche la science, Mais la bouche des insensés se plaît à la folie.'),
  (20, 15, 15, 'Tous les jours du malheureux sont mauvais, Mais le cœur content est un festin perpétuel.'),
  (20, 15, 16, 'Mieux vaut peu, avec la crainte de l''Éternel, Qu''un grand trésor, avec le trouble.'),
  (20, 15, 17, 'Mieux vaut de l''herbe pour nourriture, là où règne l''amour, Qu''un bœuf engraissé, si la haine est là.'),
  (20, 15, 18, 'Un homme violent excite des querelles, Mais celui qui est lent à la colère apaise les disputes.'),
  (20, 15, 19, 'Le chemin du paresseux est comme une haie d''épines, Mais le sentier des hommes droits est aplani.'),
  (20, 15, 20, 'Un fils sage fait la joie de son père, Et un homme insensé méprise sa mère.'),
  (20, 15, 21, 'La folie est une joie pour celui qui est dépourvu de sens, Mais un homme intelligent va le droit chemin.'),
  (20, 15, 22, 'Les projets échouent, faute d''une assemblée qui délibère; Mais ils réussissent quand il y a de nombreux conseillers.'),
  (20, 15, 23, 'On éprouve de la joie à donner une réponse de sa bouche; Et combien est agréable une parole dite à propos!'),
  (20, 15, 24, 'Pour le sage, le sentier de la vie mène en haut, Afin qu''il se détourne du séjour des morts qui est en bas.'),
  (20, 15, 25, 'L''Éternel renverse la maison des orgueilleux, Mais il affermit les bornes de la veuve.'),
  (20, 15, 26, 'Les pensées mauvaises sont en horreur à l''Éternel, Mais les paroles agréables sont pures à ses yeux.'),
  (20, 15, 27, 'Celui qui est avide de gain trouble sa maison, Mais celui qui hait les présents vivra.'),
  (20, 15, 28, 'Le cœur du juste médite pour répondre, Mais la bouche des méchants répand des méchancetés.'),
  (20, 15, 29, 'L''Éternel s''éloigne des méchants, Mais il écoute la prière des justes.'),
  (20, 15, 30, 'Ce qui plaît aux yeux réjouit le cœur; Une bonne nouvelle fortifie les membres.'),
  (20, 15, 31, 'L''oreille attentive aux réprimandes qui mènent à la vie Fait son séjour au milieu des sages.'),
  (20, 15, 32, 'Celui qui rejette la correction méprise son âme, Mais celui qui écoute la réprimande acquiert l''intelligence.'),
  (20, 15, 33, 'La crainte de l''Éternel enseigne la sagesse, Et l''humilité précède la gloire.'),
  (20, 16, 1, 'Les projets que forme le cœur dépendent de l''homme, Mais la réponse que donne la bouche vient de l''Éternel.'),
  (20, 16, 2, 'Toutes les voies de l''homme sont pures à ses yeux; Mais celui qui pèse les esprits, c''est l''Éternel.'),
  (20, 16, 3, 'Recommande à l''Éternel tes œuvres, Et tes projets réussiront.'),
  (20, 16, 4, 'L''Éternel a tout fait pour un but, Même le méchant pour le jour du malheur.'),
  (20, 16, 5, 'Tout cœur hautain est en abomination à l''Éternel; Certes, il ne restera pas impuni.'),
  (20, 16, 6, 'Par la bonté et la fidélité on expie l''iniquité, Et par la crainte de l''Éternel on se détourne du mal.'),
  (20, 16, 7, 'Quand l''Éternel approuve les voies d''un homme, Il dispose favorablement à son égard même ses ennemis.'),
  (20, 16, 8, 'Mieux vaut peu, avec la justice, Que de grands revenus, avec l''injustice.'),
  (20, 16, 9, 'Le cœur de l''homme médite sa voie, Mais c''est l''Éternel qui dirige ses pas.'),
  (20, 16, 10, 'Des oracles sont sur les lèvres du roi: Sa bouche ne doit pas être infidèle quand il juge.'),
  (20, 16, 11, 'Le poids et la balance justes sont à l''Éternel; Tous les poids du sac sont son ouvrage.'),
  (20, 16, 12, 'Les rois ont horreur de faire le mal, Car c''est par la justice que le trône s''affermit.'),
  (20, 16, 13, 'Les lèvres justes gagnent la faveur des rois, Et ils aiment celui qui parle avec droiture.'),
  (20, 16, 14, 'La fureur du roi est un messager de mort, Et un homme sage doit l''apaiser.'),
  (20, 16, 15, 'La sérénité du visage du roi donne la vie, Et sa faveur est comme une pluie du printemps.'),
  (20, 16, 16, 'Combien acquérir la sagesse vaut mieux que l''or! Combien acquérir l''intelligence est préférable à l''argent!'),
  (20, 16, 17, 'Le chemin des hommes droits, c''est d''éviter le mal; Celui qui garde son âme veille sur sa voie.'),
  (20, 16, 18, 'L''arrogance précède la ruine, Et l''orgueil précède la chute.'),
  (20, 16, 19, 'Mieux vaut être humble avec les humbles Que de partager le butin avec les orgueilleux.'),
  (20, 16, 20, 'Celui qui réfléchit sur les choses trouve le bonheur, Et celui qui se confie en l''Éternel est heureux.'),
  (20, 16, 21, 'Celui qui est sage de cœur est appelé intelligent, Et la douceur des lèvres augmente le savoir.'),
  (20, 16, 22, 'La sagesse est une source de vie pour celui qui la possède; Et le châtiment des insensés, c''est leur folie.'),
  (20, 16, 23, 'Celui qui est sage de cœur manifeste la sagesse par sa bouche, Et l''accroissement de son savoir paraît sur ses lèvres.'),
  (20, 16, 24, 'Les paroles agréables sont un rayon de miel, Douces pour l''âme et salutaires pour le corps.'),
  (20, 16, 25, 'Telle voie paraît droite à un homme, Mais son issue, c''est la voie de la mort.'),
  (20, 16, 26, 'Celui qui travaille, travaille pour lui, Car sa bouche l''y excite.'),
  (20, 16, 27, 'L''homme pervers prépare le malheur, Et il y a sur ses lèvres comme un feu ardent.'),
  (20, 16, 28, 'L''homme pervers excite des querelles, Et le rapporteur divise les amis.'),
  (20, 16, 29, 'L''homme violent séduit son prochain, Et le fait marcher dans une voie qui n''est pas bonne.'),
  (20, 16, 30, 'Celui qui ferme les yeux pour se livrer à des pensées perverses, Celui qui se mord les lèvres, a déjà consommé le mal.'),
  (20, 16, 31, 'Les cheveux blancs sont une couronne d''honneur; C''est dans le chemin de la justice qu''on la trouve.'),
  (20, 16, 32, 'Celui qui est lent à la colère vaut mieux qu''un héros, Et celui qui est maître de lui-même, que celui qui prend des villes.'),
  (20, 16, 33, 'On jette le sort dans le pan de la robe, Mais toute décision vient de l''Éternel.'),
  (20, 17, 1, 'Mieux vaut un morceau de pain sec, avec la paix, Qu''une maison pleine de viandes, avec des querelles.'),
  (20, 17, 2, 'Un serviteur prudent domine sur le fils qui fait honte, Et il aura part à l''héritage au milieu des frères.'),
  (20, 17, 3, 'Le creuset est pour l''argent, et le fourneau pour l''or; Mais celui qui éprouve les cœurs, c''est l''Éternel.'),
  (20, 17, 4, 'Le méchant est attentif à la lèvre inique, Le menteur prête l''oreille à la langue pernicieuse.'),
  (20, 17, 5, 'Celui qui se moque du pauvre outrage celui qui l''a fait; Celui qui se réjouit d''un malheur ne restera pas impuni.'),
  (20, 17, 6, 'Les enfants des enfants sont la couronne des vieillards, Et les pères sont la gloire de leurs enfants.'),
  (20, 17, 7, 'Les paroles distinguées ne conviennent pas à un insensé; Combien moins à un noble les paroles mensongères!'),
  (20, 17, 8, 'Les présents sont une pierre précieuse aux yeux de qui en reçoit; De quelque côté qu''ils se tournent, ils ont du succès.'),
  (20, 17, 9, 'Celui qui couvre une faute cherche l''amour, Et celui qui la rappelle dans ses discours divise les amis.'),
  (20, 17, 10, 'Une réprimande fait plus d''impression sur l''homme intelligent Que cent coups sur l''insensé.'),
  (20, 17, 11, 'Le méchant ne cherche que révolte, Mais un messager cruel sera envoyé contre lui.'),
  (20, 17, 12, 'Rencontre une ourse privée de ses petits, Plutôt qu''un insensé pendant sa folie.'),
  (20, 17, 13, 'De celui qui rend le mal pour le bien Le mal ne quittera point la maison.'),
  (20, 17, 14, 'Commencer une querelle, c''est ouvrir une digue; Avant que la dispute s''anime, retire-toi.'),
  (20, 17, 15, 'Celui qui absout le coupable et celui qui condamne le juste Sont tous deux en abomination à l''Éternel.'),
  (20, 17, 16, 'A quoi sert l''argent dans la main de l''insensé? A acheter la sagesse?… Mais il n''a point de sens.'),
  (20, 17, 17, 'L''ami aime en tout temps, Et dans le malheur il se montre un frère.'),
  (20, 17, 18, 'L''homme dépourvu de sens prend des engagements, Il cautionne son prochain.'),
  (20, 17, 19, 'Celui qui aime les querelles aime le péché; Celui qui élève sa porte cherche la ruine.'),
  (20, 17, 20, 'Un cœur faux ne trouve pas le bonheur, Et celui dont la langue est perverse tombe dans le malheur.'),
  (20, 17, 21, 'Celui qui donne naissance à un insensé aura du chagrin; Le père d''un fou ne peut pas se réjouir.'),
  (20, 17, 22, 'Un cœur joyeux est un bon remède, Mais un esprit abattu dessèche les os.'),
  (20, 17, 23, 'Le méchant accepte en secret des présents, Pour pervertir les voies de la justice.'),
  (20, 17, 24, 'La sagesse est en face de l''homme intelligent, Mais les yeux de l''insensé sont à l''extrémité de la terre.'),
  (20, 17, 25, 'Un fils insensé fait le chagrin de son père, Et l''amertume de celle qui l''a enfanté.'),
  (20, 17, 26, 'Il n''est pas bon de condamner le juste à une amende, Ni de frapper les nobles à cause de leur droiture.'),
  (20, 17, 27, 'Celui qui retient ses paroles connaît la science, Et celui qui a l''esprit calme est un homme intelligent.'),
  (20, 17, 28, 'L''insensé même, quand il se tait, passe pour sage; Celui qui ferme ses lèvres est un homme intelligent.'),
  (20, 18, 1, 'Celui qui se tient à l''écart cherche ce qui lui plaît, Il s''irrite contre tout ce qui est sage.'),
  (20, 18, 2, 'Ce n''est pas à l''intelligence que l''insensé prend plaisir, C''est à la manifestation de ses pensées.'),
  (20, 18, 3, 'Quand vient le méchant, vient aussi le mépris; Et avec la honte, vient l''opprobre.'),
  (20, 18, 4, 'Les paroles de la bouche d''un homme sont des eaux profondes; La source de la sagesse est un torrent qui jaillit.'),
  (20, 18, 5, 'Il n''est pas bon d''avoir égard à la personne du méchant, Pour faire tort au juste dans le jugement.'),
  (20, 18, 6, 'Les lèvres de l''insensé se mêlent aux querelles, Et sa bouche provoque les coups.'),
  (20, 18, 7, 'La bouche de l''insensé cause sa ruine, Et ses lèvres sont un piège pour son âme.'),
  (20, 18, 8, 'Les paroles du rapporteur sont comme des friandises, Elles descendent jusqu''au fond des entrailles.'),
  (20, 18, 9, 'Celui qui se relâche dans son travail Est frère de celui qui détruit.'),
  (20, 18, 10, 'Le nom de l''Éternel est une tour forte; Le juste s''y réfugie, et se trouve en sûreté.'),
  (20, 18, 11, 'La fortune est pour le riche une ville forte; Dans son imagination, c''est une haute muraille.'),
  (20, 18, 12, 'Avant la ruine, le cœur de l''homme s''élève; Mais l''humilité précède la gloire.'),
  (20, 18, 13, 'Celui qui répond avant d''avoir écouté Fait un acte de folie et s''attire la confusion.'),
  (20, 18, 14, 'L''esprit de l''homme le soutient dans la maladie; Mais l''esprit abattu, qui le relèvera?'),
  (20, 18, 15, 'Un cœur intelligent acquiert la science, Et l''oreille des sages cherche la science.'),
  (20, 18, 16, 'Les présents d''un homme lui élargissent la voie, Et lui donnent accès auprès des grands.'),
  (20, 18, 17, 'Le premier qui parle dans sa cause paraît juste; Vient sa partie adverse, et on l''examine.'),
  (20, 18, 18, 'Le sort fait cesser les contestations, Et décide entre les puissants.'),
  (20, 18, 19, 'Des frères sont plus intraitables qu''une ville forte, Et leurs querelles sont comme les verrous d''un palais.'),
  (20, 18, 20, 'C''est du fruit de sa bouche que l''homme rassasie son corps, C''est du produit de ses lèvres qu''il se rassasie.'),
  (20, 18, 21, 'La mort et la vie sont au pouvoir de la langue; Quiconque l''aime en mangera les fruits.'),
  (20, 18, 22, 'Celui qui trouve une femme trouve le bonheur; C''est une grâce qu''il obtient de l''Éternel.'),
  (20, 18, 23, 'Le pauvre parle en suppliant, Et le riche répond avec dureté.'),
  (20, 18, 24, 'Celui qui a beaucoup d''amis les a pour son malheur, Mais il est tel ami plus attaché qu''un frère.'),
  (20, 19, 1, 'Mieux vaut le pauvre qui marche dans son intégrité, Que l''homme qui a des lèvres perverses et qui est un insensé.'),
  (20, 19, 2, 'Le manque de science n''est bon pour personne, Et celui qui précipite ses pas tombe dans le péché.'),
  (20, 19, 3, 'La folie de l''homme pervertit sa voie, Et c''est contre l''Éternel que son cœur s''irrite.'),
  (20, 19, 4, 'La richesse procure un grand nombre d''amis, Mais le pauvre est séparé de son ami.'),
  (20, 19, 5, 'Le faux témoin ne restera pas impuni, Et celui qui dit des mensonges n''échappera pas.'),
  (20, 19, 6, 'Beaucoup de gens flattent l''homme généreux, Et tous sont les amis de celui qui fait des présents.'),
  (20, 19, 7, 'Tous les frères du pauvre le haïssent; Combien plus ses amis s''éloignent-ils de lui! Il leur adresse des paroles suppliantes, mais ils disparaissent.'),
  (20, 19, 8, 'Celui qui acquiert du sens aime son âme; Celui qui garde l''intelligence trouve le bonheur.'),
  (20, 19, 9, 'Le faux témoin ne restera pas impuni, Et celui qui dit des mensonges périra.'),
  (20, 19, 10, 'Il ne sied pas à un insensé de vivre dans les délices; Combien moins à un esclave de dominer sur des princes!'),
  (20, 19, 11, 'L''homme qui a de la sagesse est lent à la colère, Et il met sa gloire à oublier les offenses.'),
  (20, 19, 12, 'La colère du roi est comme le rugissement d''un lion, Et sa faveur est comme la rosée sur l''herbe.'),
  (20, 19, 13, 'Un fils insensé est une calamité pour son père, Et les querelles d''une femme sont une gouttière sans fin.'),
  (20, 19, 14, 'On peut hériter de ses pères une maison et des richesses, Mais une femme intelligente est un don de l''Éternel.'),
  (20, 19, 15, 'La paresse fait tomber dans l''assoupissement, Et l''âme nonchalante éprouve la faim.'),
  (20, 19, 16, 'Celui qui garde ce qui est commandé garde son âme; Celui qui ne veille pas sur sa voie mourra.'),
  (20, 19, 17, 'Celui qui a pitié du pauvre prête à l''Éternel, Qui lui rendra selon son œuvre.'),
  (20, 19, 18, 'Châtie ton fils, car il y a encore de l''espérance; Mais ne désire point le faire mourir.'),
  (20, 19, 19, 'Celui que la colère emporte doit en subir la peine; Car si tu le libères, tu devras y revenir.'),
  (20, 19, 20, 'Écoute les conseils, et reçois l''instruction, Afin que tu sois sage dans la suite de ta vie.'),
  (20, 19, 21, 'Il y a dans le cœur de l''homme beaucoup de projets, Mais c''est le dessein de l''Éternel qui s''accomplit.'),
  (20, 19, 22, 'Ce qui fait le charme d''un homme, c''est sa bonté; Et mieux vaut un pauvre qu''un menteur.'),
  (20, 19, 23, 'La crainte de l''Éternel mène à la vie, Et l''on passe la nuit rassasié, sans être visité par le malheur.'),
  (20, 19, 24, 'Le paresseux plonge sa main dans le plat, Et il ne la ramène pas à sa bouche.'),
  (20, 19, 25, 'Frappe le moqueur, et le sot deviendra sage; Reprends l''homme intelligent, et il comprendra la science.'),
  (20, 19, 26, 'Celui qui ruine son père et qui met en fuite sa mère Est un fils qui fait honte et qui fait rougir.'),
  (20, 19, 27, 'Cesse, mon fils, d''écouter l''instruction, Si c''est pour t''éloigner des paroles de la science.'),
  (20, 19, 28, 'Un témoin pervers se moque de la justice, Et la bouche des méchants dévore l''iniquité.'),
  (20, 19, 29, 'Les châtiments sont prêts pour les moqueurs, Et les coups pour le dos des insensés.'),
  (20, 20, 1, 'Le vin est moqueur, les boissons fortes sont tumultueuses; Quiconque en fait excès n''est pas sage.'),
  (20, 20, 2, 'La terreur qu''inspire le roi est comme le rugissement d''un lion; Celui qui l''irrite pèche contre lui-même.'),
  (20, 20, 3, 'C''est une gloire pour l''homme de s''abstenir des querelles, Mais tout insensé se livre à l''emportement.'),
  (20, 20, 4, 'A cause du froid, le paresseux ne laboure pas; A la moisson, il voudrait récolter, mais il n''y a rien.'),
  (20, 20, 5, 'Les desseins dans le cœur de l''homme sont des eaux profondes, Mais l''homme intelligent sait y puiser.'),
  (20, 20, 6, 'Beaucoup de gens proclament leur bonté; Mais un homme fidèle, qui le trouvera?'),
  (20, 20, 7, 'Le juste marche dans son intégrité; Heureux ses enfants après lui!'),
  (20, 20, 8, 'Le roi assis sur le trône de la justice Dissipe tout mal par son regard.'),
  (20, 20, 9, 'Qui dira: J''ai purifié mon cœur, Je suis net de mon péché?'),
  (20, 20, 10, 'Deux sortes de poids, deux sortes d''épha, Sont l''un et l''autre en abomination à l''Éternel.'),
  (20, 20, 11, 'L''enfant laisse déjà voir par ses actions Si sa conduite sera pure et droite.'),
  (20, 20, 12, 'L''oreille qui entend, et l''œil qui voit, C''est l''Éternel qui les a faits l''un et l''autre.'),
  (20, 20, 13, 'N''aime pas le sommeil, de peur que tu ne deviennes pauvre; Ouvre les yeux, tu seras rassasié de pain.'),
  (20, 20, 14, 'Mauvais! mauvais! dit l''acheteur; Et en s''en allant, il se félicite.'),
  (20, 20, 15, 'Il y a de l''or et beaucoup de perles; Mais les lèvres savantes sont un objet précieux.'),
  (20, 20, 16, 'Prends son vêtement, car il a cautionné autrui; Exige de lui des gages, à cause des étrangers.'),
  (20, 20, 17, 'Le pain du mensonge est doux à l''homme, Et plus tard sa bouche est remplie de gravier.'),
  (20, 20, 18, 'Les projets s''affermissent par le conseil; Fais la guerre avec prudence.'),
  (20, 20, 19, 'Celui qui répand la calomnie dévoile les secrets; Ne te mêle pas avec celui qui ouvre ses lèvres.'),
  (20, 20, 20, 'Si quelqu''un maudit son père et sa mère, Sa lampe s''éteindra au milieu des ténèbres.'),
  (20, 20, 21, 'Un héritage promptement acquis dès l''origine Ne sera pas béni quand viendra la fin.'),
  (20, 20, 22, 'Ne dis pas: Je rendrai le mal. Espère en l''Éternel, et il te délivrera.'),
  (20, 20, 23, 'L''Éternel a en horreur deux sortes de poids, Et la balance fausse n''est pas une chose bonne.'),
  (20, 20, 24, 'C''est l''Éternel qui dirige les pas de l''homme, Mais l''homme peut-il comprendre sa voie?'),
  (20, 20, 25, 'C''est un piège pour l''homme que de prendre à la légère un engagement sacré, Et de ne réfléchir qu''après avoir fait un vœu.'),
  (20, 20, 26, 'Un roi sage dissipe les méchants, Et fait passer sur eux la roue.'),
  (20, 20, 27, 'Le souffle de l''homme est une lampe de l''Éternel; Il pénètre jusqu''au fond des entrailles.'),
  (20, 20, 28, 'La bonté et la fidélité gardent le roi, Et il soutient son trône par la bonté.'),
  (20, 20, 29, 'La force est la gloire des jeunes gens, Et les cheveux blancs sont l''ornement des vieillards.'),
  (20, 20, 30, 'Les plaies d''une blessure sont un remède pour le méchant; De même les coups qui pénètrent jusqu''au fond des entrailles.'),
  (20, 21, 1, 'Le cœur du roi est un courant d''eau dans la main de l''Éternel; Il l''incline partout où il veut.'),
  (20, 21, 2, 'Toutes les voies de l''homme sont droites à ses yeux; Mais celui qui pèse les cœurs, c''est l''Éternel.'),
  (20, 21, 3, 'La pratique de la justice et de l''équité, Voilà ce que l''Éternel préfère aux sacrifices.'),
  (20, 21, 4, 'Des regards hautains et un cœur qui s''enfle, Cette lampe des méchants, ce n''est que péché.'),
  (20, 21, 5, 'Les projets de l''homme diligent ne mènent qu''à l''abondance, Mais celui qui agit avec précipitation n''arrive qu''à la disette.'),
  (20, 21, 6, 'Des trésors acquis par une langue mensongère Sont une vanité fugitive et l''avant-coureur de la mort.'),
  (20, 21, 7, 'La violence des méchants les emporte, Parce qu''ils refusent de faire ce qui est juste.'),
  (20, 21, 8, 'Le coupable suit des voies détournées, Mais l''innocent agit avec droiture.'),
  (20, 21, 9, 'Mieux vaut habiter à l''angle d''un toit, Que de partager la demeure d''une femme querelleuse.'),
  (20, 21, 10, 'L''âme du méchant désire le mal; Son ami ne trouve pas grâce à ses yeux.'),
  (20, 21, 11, 'Quand on châtie le moqueur, le sot devient sage; Et quand on instruit le sage, il accueille la science.'),
  (20, 21, 12, 'Le juste considère la maison du méchant; L''Éternel précipite les méchants dans le malheur.'),
  (20, 21, 13, 'Celui qui ferme son oreille au cri du pauvre Criera lui-même et n''aura point de réponse.'),
  (20, 21, 14, 'Un don fait en secret apaise la colère, Et un présent fait en cachette calme une fureur violente.'),
  (20, 21, 15, 'C''est une joie pour le juste de pratiquer la justice, Mais la ruine est pour ceux qui font le mal.')
insert into public.bible_verses (book_id, chapter, verse, text) values
  (20, 21, 16, 'L''homme qui s''écarte du chemin de la sagesse Reposera dans l''assemblée des morts.'),
  (20, 21, 17, 'Celui qui aime la joie reste dans l''indigence; Celui qui aime le vin et l''huile ne s''enrichit pas.'),
  (20, 21, 18, 'Le méchant sert de rançon pour le juste, Et le perfide pour les hommes droits.'),
  (20, 21, 19, 'Mieux vaut habiter dans une terre déserte, Qu''avec une femme querelleuse et irritable.'),
  (20, 21, 20, 'De précieux trésors et de l''huile sont dans la demeure du sage; Mais l''homme insensé les engloutit.'),
  (20, 21, 21, 'Celui qui poursuit la justice et la bonté Trouve la vie, la justice et la gloire.'),
  (20, 21, 22, 'Le sage monte dans la ville des héros, Et il abat la force qui lui donnait de l''assurance.'),
  (20, 21, 23, 'Celui qui veille sur sa bouche et sur sa langue Préserve son âme des angoisses.'),
  (20, 21, 24, 'L''orgueilleux, le hautain, s''appelle un moqueur; Il agit avec la fureur de l''arrogance.'),
  (20, 21, 25, 'Les désirs du paresseux le tuent, Parce que ses mains refusent de travailler;'),
  (20, 21, 26, 'Tout le jour il éprouve des désirs; Mais le juste donne sans parcimonie.'),
  (20, 21, 27, 'Le sacrifice des méchants est quelque chose d''abominable; Combien plus quand ils l''offrent avec des pensées criminelles!'),
  (20, 21, 28, 'Le témoin menteur périra, Mais l''homme qui écoute parlera toujours.'),
  (20, 21, 29, 'Le méchant prend un air effronté, Mais l''homme droit affermit sa voie.'),
  (20, 21, 30, 'Il n''y a ni sagesse, ni intelligence, Ni conseil, en face de l''Éternel.'),
  (20, 21, 31, 'Le cheval est équipé pour le jour de la bataille, Mais la délivrance appartient à l''Éternel.'),
  (20, 22, 1, 'La réputation est préférable à de grandes richesses, Et la grâce vaut mieux que l''argent et que l''or.'),
  (20, 22, 2, 'Le riche et le pauvre se rencontrent; C''est l''Éternel qui les a faits l''un et l''autre.'),
  (20, 22, 3, 'L''homme prudent voit le mal et se cache, Mais les simples avancent et sont punis.'),
  (20, 22, 4, 'Le fruit de l''humilité, de la crainte de l''Éternel, C''est la richesse, la gloire et la vie.'),
  (20, 22, 5, 'Des épines, des pièges sont sur la voie de l''homme pervers; Celui qui garde son âme s''en éloigne.'),
  (20, 22, 6, 'Instruis l''enfant selon la voie qu''il doit suivre; Et quand il sera vieux, il ne s''en détournera pas.'),
  (20, 22, 7, 'Le riche domine sur les pauvres, Et celui qui emprunte est l''esclave de celui qui prête.'),
  (20, 22, 8, 'Celui qui sème l''iniquité moissonne l''iniquité, Et la verge de sa fureur disparaît.'),
  (20, 22, 9, 'L''homme dont le regard est bienveillant sera béni, Parce qu''il donne de son pain au pauvre.'),
  (20, 22, 10, 'Chasse le moqueur, et la querelle prendra fin; Les disputes et les outrages cesseront.'),
  (20, 22, 11, 'Celui qui aime la pureté du cœur, Et qui a la grâce sur les lèvres, a le roi pour ami.'),
  (20, 22, 12, 'Les yeux de l''Éternel gardent la science, Mais il confond les paroles du perfide.'),
  (20, 22, 13, 'Le paresseux dit: Il y a un lion dehors! Je serai tué dans les rues!'),
  (20, 22, 14, 'La bouche des étrangères est une fosse profonde; Celui contre qui l''Éternel est irrité y tombera.'),
  (20, 22, 15, 'La folie est attachée au cœur de l''enfant; La verge de la correction l''éloignera de lui.'),
  (20, 22, 16, 'Opprimer le pauvre pour augmenter son bien, C''est donner au riche pour n''arriver qu''à la disette.'),
  (20, 22, 17, 'Prête l''oreille, et écoute les paroles des sages; Applique ton cœur à ma science.'),
  (20, 22, 18, 'Car il est bon que tu les gardes au dedans de toi, Et qu''elles soient toutes présentes sur tes lèvres.'),
  (20, 22, 19, 'Afin que ta confiance repose sur l''Éternel, Je veux t''instruire aujourd''hui, oui, toi.'),
  (20, 22, 20, 'N''ai-je pas déjà pour toi mis par écrit Des conseils et des réflexions,'),
  (20, 22, 21, 'Pour t''enseigner des choses sûres, des paroles vraies, Afin que tu répondes par des paroles vraies à celui qui t''envoie?'),
  (20, 22, 22, 'Ne dépouille pas le pauvre, parce qu''il est pauvre, Et n''opprime pas le malheureux à la porte;'),
  (20, 22, 23, 'Car l''Éternel défendra leur cause, Et il ôtera la vie à ceux qui les auront dépouillés.'),
  (20, 22, 24, 'Ne fréquente pas l''homme colère, Ne va pas avec l''homme violent,'),
  (20, 22, 25, 'De peur que tu ne t''habitues à ses sentiers, Et qu''ils ne deviennent un piège pour ton âme.'),
  (20, 22, 26, 'Ne sois pas parmi ceux qui prennent des engagements, Parmi ceux qui cautionnent pour des dettes;'),
  (20, 22, 27, 'Si tu n''as pas de quoi payer, Pourquoi voudrais-tu qu''on enlève ton lit de dessous toi?'),
  (20, 22, 28, 'Ne déplace pas la borne ancienne, Que tes pères ont posée.'),
  (20, 22, 29, 'Si tu vois un homme habile dans son ouvrage, Il se tient auprès des rois; Il ne se tient pas auprès des gens obscurs.'),
  (20, 23, 1, 'Si tu es à table avec un grand, Fais attention à ce qui est devant toi;'),
  (20, 23, 2, 'Mets un couteau à ta gorge, Si tu as trop d''avidité.'),
  (20, 23, 3, 'Ne convoite pas ses friandises: C''est un aliment trompeur.'),
  (20, 23, 4, 'Ne te tourmente pas pour t''enrichir, N''y applique pas ton intelligence.'),
  (20, 23, 5, 'Veux-tu poursuivre du regard ce qui va disparaître? Car la richesse se fait des ailes, Et comme l''aigle, elle prend son vol vers les cieux.'),
  (20, 23, 6, 'Ne mange pas le pain de celui dont le regard est malveillant, Et ne convoite pas ses friandises;'),
  (20, 23, 7, 'Car il est comme les pensées de son âme. Mange et bois, te dira-t-il; Mais son cœur n''est point avec toi.'),
  (20, 23, 8, 'Tu vomiras le morceau que tu as mangé, Et tu auras perdu tes propos agréables.'),
  (20, 23, 9, 'Ne parle pas aux oreilles de l''insensé, Car il méprise la sagesse de tes discours.'),
  (20, 23, 10, 'Ne déplace pas la borne ancienne, Et n''entre pas dans le champ des orphelins;'),
  (20, 23, 11, 'Car leur vengeur est puissant: Il défendra leur cause contre toi.'),
  (20, 23, 12, 'Ouvre ton cœur à l''instruction, Et tes oreilles aux paroles de la science.'),
  (20, 23, 13, 'N''épargne pas la correction à l''enfant; Si tu le frappes de la verge, il ne mourra point.'),
  (20, 23, 14, 'En le frappant de la verge, Tu délivres son âme du séjour des morts.'),
  (20, 23, 15, 'Mon fils, si ton cœur est sage, Mon cœur à moi sera dans la joie;'),
  (20, 23, 16, 'Mes entrailles seront émues d''allégresse, Quand tes lèvres diront ce qui est droit.'),
  (20, 23, 17, 'Que ton cœur n''envie point les pécheurs, Mais qu''il ait toujours la crainte de l''Éternel;'),
  (20, 23, 18, 'Car il est un avenir, Et ton espérance ne sera pas anéantie.'),
  (20, 23, 19, 'Écoute, mon fils, et sois sage; Dirige ton cœur dans la voie droite.'),
  (20, 23, 20, 'Ne sois pas parmi les buveurs de vin, Parmi ceux qui font excès des viandes:'),
  (20, 23, 21, 'Car l''ivrogne et celui qui se livre à des excès s''appauvrissent, Et l''assoupissement fait porter des haillons.'),
  (20, 23, 22, 'Écoute ton père, lui qui t''a engendré, Et ne méprise pas ta mère, quand elle est devenue vieille.'),
  (20, 23, 23, 'Acquiers la vérité, et ne la vends pas, La sagesse, l''instruction et l''intelligence.'),
  (20, 23, 24, 'Le père du juste est dans l''allégresse, Celui qui donne naissance à un sage aura de la joie.'),
  (20, 23, 25, 'Que ton père et ta mère se réjouissent, Que celle qui t''a enfanté soit dans l''allégresse!'),
  (20, 23, 26, 'Mon fils, donne-moi ton cœur, Et que tes yeux se plaisent dans mes voies.'),
  (20, 23, 27, 'Car la prostituée est une fosse profonde, Et l''étrangère un puits étroit.'),
  (20, 23, 28, 'Elle dresse des embûches comme un brigand, Et elle augmente parmi les hommes le nombre des perfides.'),
  (20, 23, 29, 'Pour qui les ah? pour qui les hélas? Pour qui les disputes? pour qui les plaintes? Pour qui les blessures sans raison? pour qui les yeux rouges?'),
  (20, 23, 30, 'Pour ceux qui s''attardent auprès du vin, Pour ceux qui vont déguster du vin mêlé.'),
  (20, 23, 31, 'Ne regarde pas le vin qui paraît d''un beau rouge, Qui fait des perles dans la coupe, Et qui coule aisément.'),
  (20, 23, 32, 'Il finit par mordre comme un serpent, Et par piquer comme un basilic.'),
  (20, 23, 33, 'Tes yeux se porteront sur des étrangères, Et ton cœur parlera d''une manière perverse.'),
  (20, 23, 34, 'Tu seras comme un homme couché au milieu de la mer, Comme un homme couché sur le sommet d''un mât:'),
  (20, 23, 35, 'On m''a frappé,… je n''ai point de mal!… On m''a battu,… je ne sens rien!… Quand me réveillerai-je?… J''en veux encore!'),
  (20, 24, 1, 'Ne porte pas envie aux hommes méchants, Et ne désire pas être avec eux;'),
  (20, 24, 2, 'Car leur cœur médite la ruine, Et leurs lèvres parlent d''iniquité.'),
  (20, 24, 3, 'C''est par la sagesse qu''une maison s''élève, Et par l''intelligence qu''elle s''affermit;'),
  (20, 24, 4, 'C''est par la science que les chambres se remplissent De tous les biens précieux et agréables.'),
  (20, 24, 5, 'Un homme sage est plein de force, Et celui qui a de la science affermit sa vigueur;'),
  (20, 24, 6, 'Car tu feras la guerre avec prudence, Et le salut est dans le grand nombre des conseillers.'),
  (20, 24, 7, 'La sagesse est trop élevée pour l''insensé; Il n''ouvrira pas la bouche à la porte.'),
  (20, 24, 8, 'Celui qui médite de faire le mal S''appelle un homme plein de malice.'),
  (20, 24, 9, 'La pensée de la folie n''est que péché, Et le moqueur est en abomination parmi les hommes.'),
  (20, 24, 10, 'Si tu faiblis au jour de la détresse, Ta force n''est que détresse.'),
  (20, 24, 11, 'Délivre ceux qu''on traîne à la mort, Ceux qu''on va égorger, sauve-les!'),
  (20, 24, 12, 'Si tu dis: Ah! nous ne savions pas!… Celui qui pèse les cœurs ne le voit-il pas? Celui qui veille sur ton âme ne le connaît-il pas? Et ne rendra-t-il pas à chacun selon ses œuvres?'),
  (20, 24, 13, 'Mon fils, mange du miel, car il est bon; Un rayon de miel sera doux à ton palais.'),
  (20, 24, 14, 'De même, connais la sagesse pour ton âme; Si tu la trouves, il est un avenir, Et ton espérance ne sera pas anéantie.'),
  (20, 24, 15, 'Ne tends pas méchamment des embûches à la demeure du juste, Et ne dévaste pas le lieu où il repose;'),
  (20, 24, 16, 'Car sept fois le juste tombe, et il se relève, Mais les méchants sont précipités dans le malheur.'),
  (20, 24, 17, 'Ne te réjouis pas de la chute de ton ennemi, Et que ton cœur ne soit pas dans l''allégresse quand il chancelle,'),
  (20, 24, 18, 'De peur que l''Éternel ne le voie, que cela ne lui déplaise, Et qu''il ne détourne de lui sa colère.'),
  (20, 24, 19, 'Ne t''irrite pas à cause de ceux qui font le mal, Ne porte pas envie aux méchants;'),
  (20, 24, 20, 'Car il n''y a point d''avenir pour celui qui fait le mal, La lampe des méchants s''éteint.'),
  (20, 24, 21, 'Mon fils, crains l''Éternel et le roi; Ne te mêle pas avec les hommes remuants;'),
  (20, 24, 22, 'Car soudain leur ruine surgira, Et qui connaît les châtiments des uns et des autres?'),
  (20, 24, 23, 'Voici encore ce qui vient des sages: Il n''est pas bon, dans les jugements, d''avoir égard aux personnes.'),
  (20, 24, 24, 'Celui qui dit au méchant: Tu es juste! Les peuples le maudissent, les nations le maudissent.'),
  (20, 24, 25, 'Mais ceux qui le châtient s''en trouvent bien, Et le bonheur vient sur eux comme une bénédiction.'),
  (20, 24, 26, 'Il baise les lèvres, Celui qui répond des paroles justes.'),
  (20, 24, 27, 'Soigne tes affaires au dehors, Mets ton champ en état, Puis tu bâtiras ta maison.'),
  (20, 24, 28, 'Ne témoigne pas à la légère contre ton prochain; Voudrais-tu tromper par tes lèvres?'),
  (20, 24, 29, 'Ne dis pas: Je lui ferai comme il m''a fait, Je rendrai à chacun selon ses œuvres.'),
  (20, 24, 30, 'J''ai passé près du champ d''un paresseux, Et près de la vigne d''un homme dépourvu de sens.'),
  (20, 24, 31, 'Et voici, les épines y croissaient partout, Les ronces en couvraient la face, Et le mur de pierres était écroulé.'),
  (20, 24, 32, 'J''ai regardé attentivement, Et j''ai tiré instruction de ce que j''ai vu.'),
  (20, 24, 33, 'Un peu de sommeil, un peu d''assoupissement, Un peu croiser les mains pour dormir!…'),
  (20, 24, 34, 'Et la pauvreté te surprendra, comme un rôdeur, Et la disette, comme un homme en armes.'),
  (20, 25, 1, 'Voici encore des Proverbes de Salomon, recueillis par les gens d''Ézéchias, roi de Juda.'),
  (20, 25, 2, 'La gloire de Dieu, c''est de cacher les choses; La gloire des rois, c''est de sonder les choses.'),
  (20, 25, 3, 'Les cieux dans leur hauteur, la terre dans sa profondeur, Et le cœur des rois, sont impénétrables.'),
  (20, 25, 4, 'Ote de l''argent les scories, Et il en sortira un vase pour le fondeur.'),
  (20, 25, 5, 'Ote le méchant de devant le roi, Et son trône s''affermira par la justice.'),
  (20, 25, 6, 'Ne t''élève pas devant le roi, Et ne prends pas la place des grands;'),
  (20, 25, 7, 'Car il vaut mieux qu''on te dise: Monte-ici! Que si l''on t''abaisse devant le prince que tes yeux voient.'),
  (20, 25, 8, 'Ne te hâte pas d''entrer en contestation, De peur qu''à la fin tu ne saches que faire, Lorsque ton prochain t''aura outragé.'),
  (20, 25, 9, 'Défends ta cause contre ton prochain, Mais ne révèle pas le secret d''un autre,'),
  (20, 25, 10, 'De peur qu''en l''apprenant il ne te couvre de honte, Et que ta mauvaise renommée ne s''efface pas.'),
  (20, 25, 11, 'Comme des pommes d''or sur des ciselures d''argent, Ainsi est une parole dite à propos.'),
  (20, 25, 12, 'Comme un anneau d''or et une parure d''or fin, Ainsi pour une oreille docile est le sage qui réprimande.'),
  (20, 25, 13, 'Comme la fraîcheur de la neige au temps de la moisson, Ainsi est un messager fidèle pour celui qui l''envoie; Il restaure l''âme de son maître.'),
  (20, 25, 14, 'Comme des nuages et du vent sans pluie, Ainsi est un homme se glorifiant à tort de ses libéralités.'),
  (20, 25, 15, 'Par la lenteur à la colère on fléchit un prince, Et une langue douce peut briser des os.'),
  (20, 25, 16, 'Si tu trouves du miel, n''en mange que ce qui te suffit, De peur que tu n''en sois rassasié et que tu ne le vomisses.'),
  (20, 25, 17, 'Mets rarement le pied dans la maison de ton prochain, De peur qu''il ne soit rassasié de toi et qu''il ne te haïsse.'),
  (20, 25, 18, 'Comme une massue, une épée et une flèche aiguë, Ainsi est un homme qui porte un faux témoignage contre son prochain.'),
  (20, 25, 19, 'Comme une dent cassée et un pied qui chancelle, Ainsi est la confiance en un perfide au jour de la détresse.'),
  (20, 25, 20, 'Oter son vêtement dans un jour froid, Répandre du vinaigre sur du nitre, C''est dire des chansons à un cœur attristé.'),
  (20, 25, 21, 'Si ton ennemi a faim, donne-lui du pain à manger; S''il a soif, donne-lui de l''eau à boire.'),
  (20, 25, 22, 'Car ce sont des charbons ardents que tu amasses sur sa tête, Et l''Éternel te récompensera.'),
  (20, 25, 23, 'Le vent du nord enfante la pluie, Et la langue mystérieuse un visage irrité.'),
  (20, 25, 24, 'Mieux vaut habiter à l''angle d''un toit, Que de partager la demeure d''une femme querelleuse.'),
  (20, 25, 25, 'Comme de l''eau fraîche pour une personne fatiguée, Ainsi est une bonne nouvelle venant d''une terre lointaine.'),
  (20, 25, 26, 'Comme une fontaine troublée et une source corrompue, Ainsi est le juste qui chancelle devant le méchant.'),
  (20, 25, 27, 'Il n''est pas bon de manger beaucoup de miel, Mais rechercher la gloire des autres est un honneur.'),
  (20, 25, 28, 'Comme une ville forcée et sans murailles, Ainsi est l''homme qui n''est pas maître de lui-même.'),
  (20, 26, 1, 'Comme la neige en été, et la pluie pendant la moisson, Ainsi la gloire ne convient pas à un insensé.'),
  (20, 26, 2, 'Comme l''oiseau s''échappe, comme l''hirondelle s''envole, Ainsi la malédiction sans cause n''a point d''effet.'),
  (20, 26, 3, 'Le fouet est pour le cheval, le mors pour l''âne, Et la verge pour le dos des insensés.'),
  (20, 26, 4, 'Ne réponds pas à l''insensé selon sa folie, De peur que tu ne lui ressembles toi-même.'),
  (20, 26, 5, 'Réponds à l''insensé selon sa folie, Afin qu''il ne se regarde pas comme sage.'),
  (20, 26, 6, 'Il se coupe les pieds, il boit l''injustice, Celui qui donne des messages à un insensé.'),
  (20, 26, 7, 'Comme les jambes du boiteux sont faibles, Ainsi est une sentence dans la bouche des insensés.'),
  (20, 26, 8, 'C''est attacher une pierre à la fronde, Que d''accorder des honneurs à un insensé.'),
  (20, 26, 9, 'Comme une épine qui se dresse dans la main d''un homme ivre, Ainsi est une sentence dans la bouche des insensés.'),
  (20, 26, 10, 'Comme un archer qui blesse tout le monde, Ainsi est celui qui prend à gage les insensés et les premiers venus.'),
  (20, 26, 11, 'Comme un chien qui retourne à ce qu''il a vomi, Ainsi est un insensé qui revient à sa folie.'),
  (20, 26, 12, 'Si tu vois un homme qui se croit sage, Il y a plus à espérer d''un insensé que de lui.'),
  (20, 26, 13, 'Le paresseux dit: Il y a un lion sur le chemin, Il y a un lion dans les rues!'),
  (20, 26, 14, 'La porte tourne sur ses gonds, Et le paresseux sur son lit.'),
  (20, 26, 15, 'Le paresseux plonge sa main dans le plat, Et il trouve pénible de la ramener à sa bouche.'),
  (20, 26, 16, 'Le paresseux se croit plus sage Que sept hommes qui répondent avec bon sens.'),
  (20, 26, 17, 'Comme celui qui saisit un chien par les oreilles, Ainsi est un passant qui s''irrite pour une querelle où il n''a que faire.'),
  (20, 26, 18, 'Comme un furieux qui lance des flammes, Des flèches et la mort,'),
  (20, 26, 19, 'Ainsi est un homme qui trompe son prochain, Et qui dit: N''était-ce pas pour plaisanter?'),
  (20, 26, 20, 'Faute de bois, le feu s''éteint; Et quand il n''y a point de rapporteur, la querelle s''apaise.'),
  (20, 26, 21, 'Le charbon produit un brasier, et le bois du feu; Ainsi un homme querelleur échauffe une dispute.'),
  (20, 26, 22, 'Les paroles du rapporteur sont comme des friandises, Elles descendent jusqu''au fond des entrailles.'),
  (20, 26, 23, 'Comme des scories d''argent appliquées sur un vase de terre, Ainsi sont des lèvres brûlantes et un cœur mauvais.'),
  (20, 26, 24, 'Par ses lèvres celui qui hait se déguise, Et il met au dedans de lui la tromperie.'),
  (20, 26, 25, 'Lorsqu''il prend une voix douce, ne le crois pas, Car il y a sept abominations dans son cœur.'),
  (20, 26, 26, 'S''il cache sa haine sous la dissimulation, Sa méchanceté se révélera dans l''assemblée.'),
  (20, 26, 27, 'Celui qui creuse une fosse y tombe, Et la pierre revient sur celui qui la roule.'),
  (20, 26, 28, 'La langue fausse hait ceux qu''elle écrase, Et la bouche flatteuse prépare la ruine.'),
  (20, 27, 1, 'Ne te vante pas du lendemain, Car tu ne sais pas ce qu''un jour peut enfanter.'),
  (20, 27, 2, 'Qu''un autre te loue, et non ta bouche, Un étranger, et non tes lèvres.'),
  (20, 27, 3, 'La pierre est pesante et le sable est lourd, Mais l''humeur de l''insensé pèse plus que l''un et l''autre.'),
  (20, 27, 4, 'La fureur est cruelle et la colère impétueuse, Mais qui résistera devant la jalousie?'),
  (20, 27, 5, 'Mieux vaut une réprimande ouverte Qu''une amitié cachée.'),
  (20, 27, 6, 'Les blessures d''un ami prouvent sa fidélité, Mais les baisers d''un ennemi sont trompeurs.'),
  (20, 27, 7, 'Celui qui est rassasié foule aux pieds le rayon de miel, Mais celui qui a faim trouve doux tout ce qui est amer.'),
  (20, 27, 8, 'Comme l''oiseau qui erre loin de son nid, Ainsi est l''homme qui erre loin de son lieu.'),
  (20, 27, 9, 'L''huile et les parfums réjouissent le cœur, Et les conseils affectueux d''un ami sont doux.'),
  (20, 27, 10, 'N''abandonne pas ton ami et l''ami de ton père, Et n''entre pas dans la maison de ton frère au jour de ta détresse; Mieux vaut un voisin proche qu''un frère éloigné.'),
  (20, 27, 11, 'Mon fils, sois sage, et réjouis mon cœur, Et je pourrai répondre à celui qui m''outrage.'),
  (20, 27, 12, 'L''homme prudent voit le mal et se cache; Les simples avancent et sont punis.'),
  (20, 27, 13, 'Prends son vêtement, car il a cautionné autrui; Exige de lui des gages, à cause des étrangers.'),
  (20, 27, 14, 'Si l''on bénit son prochain à haute voix et de grand matin, Cela est envisagé comme une malédiction.'),
  (20, 27, 15, 'Une gouttière continue dans un jour de pluie Et une femme querelleuse sont choses semblables.'),
  (20, 27, 16, 'Celui qui la retient retient le vent, Et sa main saisit de l''huile.'),
  (20, 27, 17, 'Comme le fer aiguise le fer, Ainsi un homme excite la colère d''un homme.'),
  (20, 27, 18, 'Celui qui soigne un figuier en mangera le fruit, Et celui qui garde son maître sera honoré.'),
  (20, 27, 19, 'Comme dans l''eau le visage répond au visage, Ainsi le cœur de l''homme répond au cœur de l''homme.'),
  (20, 27, 20, 'Le séjour des morts et l''abîme sont insatiables; De même les yeux de l''homme sont insatiables.'),
  (20, 27, 21, 'Le creuset est pour l''argent, et le fourneau pour l''or; Mais un homme est jugé d''après sa renommée.'),
  (20, 27, 22, 'Quand tu pilerais l''insensé dans un mortier, Au milieu des grains avec le pilon, Sa folie ne se séparerait pas de lui.'),
  (20, 27, 23, 'Connais bien chacune de tes brebis, Donne tes soins à tes troupeaux;'),
  (20, 27, 24, 'Car la richesse ne dure pas toujours, Ni une couronne éternellement.'),
  (20, 27, 25, 'Le foin s''enlève, la verdure paraît, Et les herbes des montagnes sont recueillies.'),
  (20, 27, 26, 'Les agneaux sont pour te vêtir, Et les boucs pour payer le champ;'),
  (20, 27, 27, 'Le lait des chèvres suffit à ta nourriture, à celle de ta maison, Et à l''entretien de tes servantes.'),
  (20, 28, 1, 'Le méchant prend la fuite sans qu''on le poursuive, Le juste a de l''assurance comme un jeune lion.'),
  (20, 28, 2, 'Quand un pays est en révolte, les chefs sont nombreux; Mais avec un homme qui a de l''intelligence et de la science, Le règne se prolonge.'),
  (20, 28, 3, 'Un homme pauvre qui opprime les misérables Est une pluie violente qui fait manquer le pain.'),
  (20, 28, 4, 'Ceux qui abandonnent la loi louent le méchant, Mais ceux qui observent la loi s''irritent contre lui.'),
  (20, 28, 5, 'Les hommes livrés au mal ne comprennent pas ce qui est juste, Mais ceux qui cherchent l''Éternel comprennent tout.'),
  (20, 28, 6, 'Mieux vaut le pauvre qui marche dans son intégrité, Que celui qui a des voies tortueuses et qui est riche.'),
  (20, 28, 7, 'Celui qui observe la loi est un fils intelligent, Mais celui qui fréquente les débauchés fait honte à son père.'),
  (20, 28, 8, 'Celui qui augmente ses biens par l''intérêt et l''usure Les amasse pour celui qui a pitié des pauvres.'),
  (20, 28, 9, 'Si quelqu''un détourne l''oreille pour ne pas écouter la loi, Sa prière même est une abomination.'),
  (20, 28, 10, 'Celui qui égare les hommes droits dans la mauvaise voie Tombe dans la fosse qu''il a creusée; Mais les hommes intègres héritent le bonheur.'),
  (20, 28, 11, 'L''homme riche se croit sage; Mais le pauvre qui est intelligent le sonde.'),
  (20, 28, 12, 'Quand les justes triomphent, c''est une grande gloire; Quand les méchants s''élèvent, chacun se cache.'),
  (20, 28, 13, 'Celui qui cache ses transgressions ne prospère point, Mais celui qui les avoue et les délaisse obtient miséricorde.'),
  (20, 28, 14, 'Heureux l''homme qui est continuellement dans la crainte! Mais celui qui endurcit son cœur tombe dans le malheur.'),
  (20, 28, 15, 'Comme un lion rugissant et un ours affamé, Ainsi est le méchant qui domine sur un peuple pauvre.'),
  (20, 28, 16, 'Un prince sans intelligence multiplie les actes d''oppression, Mais celui qui est ennemi de la cupidité prolonge ses jours.'),
  (20, 28, 17, 'Un homme chargé du sang d''un autre Fuit jusqu''à la fosse: qu''on ne l''arrête pas!'),
  (20, 28, 18, 'Celui qui marche dans l''intégrité trouve le salut, Mais celui qui suit deux voies tortueuses tombe dans l''une d''elles.'),
  (20, 28, 19, 'Celui qui cultive son champ est rassasié de pain, Mais celui qui poursuit des choses vaines est rassasié de pauvreté.'),
  (20, 28, 20, 'Un homme fidèle est comblé de bénédictions, Mais celui qui a hâte de s''enrichir ne reste pas impuni.'),
  (20, 28, 21, 'Il n''est pas bon d''avoir égard aux personnes, Et pour un morceau de pain un homme se livre au péché.'),
  (20, 28, 22, 'Un homme envieux a hâte de s''enrichir, Et il ne sait pas que la disette viendra sur lui.'),
  (20, 28, 23, 'Celui qui reprend les autres trouve ensuite plus de faveur Que celui dont la langue est flatteuse.'),
  (20, 28, 24, 'Celui qui vole son père et sa mère, Et qui dit: Ce n''est pas un péché! Est le compagnon du destructeur.'),
  (20, 28, 25, 'L''orgueilleux excite les querelles, Mais celui qui se confie en l''Éternel est rassasié.'),
  (20, 28, 26, 'Celui qui a confiance dans son propre cœur est un insensé, Mais celui qui marche dans la sagesse sera sauvé.'),
  (20, 28, 27, 'Celui qui donne au pauvre n''éprouve pas la disette, Mais celui qui ferme les yeux est chargé de malédictions.'),
  (20, 28, 28, 'Quand les méchants s''élèvent, chacun se cache; Et quand ils périssent, les justes se multiplient.'),
  (20, 29, 1, 'Un homme qui mérite d''être repris, et qui raidit le cou, Sera brisé subitement et sans remède.'),
  (20, 29, 2, 'Quand les justes se multiplient, le peuple est dans la joie; Quand le méchant domine, le peuple gémit.'),
  (20, 29, 3, 'Un homme qui aime la sagesse réjouit son père, Mais celui qui fréquente des prostituées dissipe son bien.'),
  (20, 29, 4, 'Un roi affermit le pays par la justice, Mais celui qui reçoit des présents le ruine.'),
  (20, 29, 5, 'Un homme qui flatte son prochain Tend un filet sous ses pas.'),
  (20, 29, 6, 'Il y a un piège dans le péché de l''homme méchant, Mais le juste triomphe et se réjouit.'),
  (20, 29, 7, 'Le juste connaît la cause des pauvres, Mais le méchant ne comprend pas la science.'),
  (20, 29, 8, 'Les moqueurs soufflent le feu dans la ville, Mais les sages calment la colère.'),
  (20, 29, 9, 'Si un homme sage conteste avec un insensé, Il aura beau se fâcher ou rire, la paix n''aura pas lieu.'),
  (20, 29, 10, 'Les hommes de sang haïssent l''homme intègre, Mais les hommes droits protègent sa vie.'),
  (20, 29, 11, 'L''insensé met en dehors toute sa passion, Mais le sage la contient.'),
  (20, 29, 12, 'Quand celui qui domine a égard aux paroles mensongères, Tous ses serviteurs sont des méchants.'),
  (20, 29, 13, 'Le pauvre et l''oppresseur se rencontrent; C''est l''Éternel qui éclaire les yeux de l''un et de l''autre.'),
  (20, 29, 14, 'Un roi qui juge fidèlement les pauvres Aura son trône affermi pour toujours.'),
  (20, 29, 15, 'La verge et la correction donnent la sagesse, Mais l''enfant livré à lui-même fait honte à sa mère.'),
  (20, 29, 16, 'Quand les méchants se multiplient, le péché s''accroît; Mais les justes contempleront leur chute.'),
  (20, 29, 17, 'Châtie ton fils, et il te donnera du repos, Et il procurera des délices à ton âme.'),
  (20, 29, 18, 'Quand il n''y a pas de révélation, le peuple est sans frein; Heureux s''il observe la loi!'),
  (20, 29, 19, 'Ce n''est pas par des paroles qu''on châtie un esclave; Même s''il comprend, il n''obéit pas.'),
  (20, 29, 20, 'Si tu vois un homme irréfléchi dans ses paroles, Il y a plus à espérer d''un insensé que de lui.'),
  (20, 29, 21, 'Le serviteur qu''on traite mollement dès l''enfance Finit par se croire un fils.'),
  (20, 29, 22, 'Un homme colère excite des querelles, Et un furieux commet beaucoup de péchés.'),
  (20, 29, 23, 'L''orgueil d''un homme l''abaisse, Mais celui qui est humble d''esprit obtient la gloire.'),
  (20, 29, 24, 'Celui qui partage avec un voleur est ennemi de son âme; Il entend la malédiction, et il ne déclare rien.'),
  (20, 29, 25, 'La crainte des hommes tend un piège, Mais celui qui se confie en l''Éternel est protégé.'),
  (20, 29, 26, 'Beaucoup de gens recherchent la faveur de celui qui domine, Mais c''est l''Éternel qui fait droit à chacun.'),
  (20, 29, 27, 'L''homme inique est en abomination aux justes, Et celui dont la voie est droite est en abomination aux méchants.'),
  (20, 30, 1, 'Paroles d''Agur, fils de Jaké. Sentences prononcées par cet homme pour Ithiel, pour Ithiel et pour Ucal.'),
  (20, 30, 2, 'Certes, je suis plus stupide que personne, Et je n''ai pas l''intelligence d''un homme;'),
  (20, 30, 3, 'Je n''ai pas appris la sagesse, Et je ne connais pas la science des saints.'),
  (20, 30, 4, 'Qui est monté aux cieux, et qui en est descendu? Qui a recueilli le vent dans ses mains? Qui a serré les eaux dans son vêtement? Qui a fait paraître les extrémités de la terre? Quel est son nom, et quel est le nom de son fils? Le sais-tu?'),
  (20, 30, 5, 'Toute parole de Dieu est éprouvée. Il est un bouclier pour ceux qui cherchent en lui un refuge.'),
  (20, 30, 6, 'N''ajoute rien à ses paroles, De peur qu''il ne te reprenne et que tu ne sois trouvé menteur.'),
  (20, 30, 7, 'Je te demande deux choses: Ne me les refuse pas, avant que je meure!'),
  (20, 30, 8, 'Éloigne de moi la fausseté et la parole mensongère; Ne me donne ni pauvreté, ni richesse, Accorde-moi le pain qui m''est nécessaire.'),
  (20, 30, 9, 'De peur que, dans l''abondance, je ne te renie Et ne dise: Qui est l''Éternel? Ou que, dans la pauvreté, je ne dérobe, Et ne m''attaque au nom de mon Dieu.'),
  (20, 30, 10, 'Ne calomnie pas un serviteur auprès de son maître, De peur qu''il ne te maudisse et que tu ne te rendes coupable.'),
  (20, 30, 11, 'Il est une race qui maudit son père, Et qui ne bénit point sa mère.'),
  (20, 30, 12, 'Il est une race qui se croit pure, Et qui n''est pas lavée de sa souillure.'),
  (20, 30, 13, 'Il est une race dont les yeux sont hautains, Et les paupières élevées.'),
  (20, 30, 14, 'Il est une race dont les dents sont des glaives Et les mâchoires des couteaux, Pour dévorer le malheureux sur la terre Et les indigents parmi les hommes.'),
  (20, 30, 15, 'La sangsue a deux filles: Donne! donne! Trois choses sont insatiables, Quatre ne disent jamais: Assez!'),
  (20, 30, 16, 'Le séjour des morts, la femme stérile, La terre, qui n''est pas rassasiée d''eau, Et le feu, qui ne dit jamais: Assez!'),
  (20, 30, 17, 'L''œil qui se moque d''un père Et qui dédaigne l''obéissance envers une mère, Les corbeaux du torrent le perceront, Et les petits de l''aigle le mangeront.'),
  (20, 30, 18, 'Il y a trois choses qui sont au-dessus de ma portée, Même quatre que je ne puis comprendre:'),
  (20, 30, 19, 'La trace de l''aigle dans les cieux, La trace du serpent sur le rocher, La trace du navire au milieu de la mer, Et la trace de l''homme chez la jeune femme.'),
  (20, 30, 20, 'Telle est la voie de la femme adultère: Elle mange, et s''essuie la bouche, Puis elle dit: Je n''ai point fait de mal.'),
  (20, 30, 21, 'Trois choses font trembler la terre, Et il en est quatre qu''elle ne peut supporter:'),
  (20, 30, 22, 'Un esclave qui vient à régner, Un insensé qui est rassasié de pain,'),
  (20, 30, 23, 'Une femme dédaignée qui se marie, Et une servante qui hérite de sa maîtresse.'),
  (20, 30, 24, 'Il y a sur la terre quatre animaux petits, Et cependant des plus sages;'),
  (20, 30, 25, 'Les fourmis, peuple sans force, Préparent en été leur nourriture;'),
  (20, 30, 26, 'Les damans, peuple sans puissance, Placent leur demeure dans les rochers;'),
  (20, 30, 27, 'Les sauterelles n''ont point de roi, Et elles sortent toutes par divisions;'),
  (20, 30, 28, 'Le lézard saisit avec les mains, Et se trouve dans les palais des rois.'),
  (20, 30, 29, 'Il y en a trois qui ont une belle allure, Et quatre qui ont une belle démarche:'),
  (20, 30, 30, 'Le lion, le héros des animaux, Ne reculant devant qui que ce soit;'),
  (20, 30, 31, 'Le cheval tout équipé; ou le bouc; Et le roi à qui personne ne résiste.'),
  (20, 30, 32, 'Si l''orgueil te pousse à des actes de folie, Et si tu as de mauvaises pensées, mets la main sur la bouche:'),
  (20, 30, 33, 'Car la pression du lait produit de la crème, La pression du nez produit du sang, Et la pression de la colère produit des querelles.'),
  (20, 31, 1, 'Paroles du roi Lemuel. Sentences par lesquelles sa mère l''instruisit.'),
  (20, 31, 2, 'Que te dirai-je, mon fils? que te dirai-je, fils de mes entrailles? Que te dirai-je, mon fils, objet de mes vœux?'),
  (20, 31, 3, 'Ne livre pas ta vigueur aux femmes, Et tes voies à celles qui perdent les rois.'),
  (20, 31, 4, 'Ce n''est point aux rois, Lemuel, Ce n''est point aux rois de boire du vin, Ni aux princes de rechercher des liqueurs fortes,'),
  (20, 31, 5, 'De peur qu''en buvant ils n''oublient la loi, Et ne méconnaissent les droits de tous les malheureux.'),
  (20, 31, 6, 'Donnez des liqueurs fortes à celui qui périt, Et du vin à celui qui a l''amertume dans l''âme;'),
  (20, 31, 7, 'Qu''il boive et oublie sa pauvreté, Et qu''il ne se souvienne plus de ses peines.'),
  (20, 31, 8, 'Ouvre ta bouche pour le muet, Pour la cause de tous les délaissés.'),
  (20, 31, 9, 'Ouvre ta bouche, juge avec justice, Et défends le malheureux et l''indigent.'),
  (20, 31, 10, 'Qui peut trouver une femme vertueuse? Elle a bien plus de valeur que les perles.'),
  (20, 31, 11, 'Le cœur de son mari a confiance en elle, Et les produits ne lui feront pas défaut.'),
  (20, 31, 12, 'Elle lui fait du bien, et non du mal, Tous les jours de sa vie.'),
  (20, 31, 13, 'Elle se procure de la laine et du lin, Et travaille d''une main joyeuse.'),
  (20, 31, 14, 'Elle est comme un navire marchand, Elle amène son pain de loin.'),
  (20, 31, 15, 'Elle se lève lorsqu''il est encore nuit, Et elle donne la nourriture à sa maison Et la tâche à ses servantes.'),
  (20, 31, 16, 'Elle pense à un champ, et elle l''acquiert; Du fruit de son travail elle plante une vigne.'),
  (20, 31, 17, 'Elle ceint de force ses reins, Et elle affermit ses bras.'),
  (20, 31, 18, 'Elle sent que ce qu''elle gagne est bon; Sa lampe ne s''éteint point pendant la nuit.'),
  (20, 31, 19, 'Elle met la main à la quenouille, Et ses doigts tiennent le fuseau.'),
  (20, 31, 20, 'Elle tend la main au malheureux, Elle tend la main à l''indigent.'),
  (20, 31, 21, 'Elle ne craint pas la neige pour sa maison, Car toute sa maison est vêtue de cramoisi.'),
  (20, 31, 22, 'Elle se fait des couvertures, Elle a des vêtements de fin lin et de pourpre.'),
  (20, 31, 23, 'Son mari est considéré aux portes, Lorsqu''il siège avec les anciens du pays.'),
  (20, 31, 24, 'Elle fait des chemises, et les vend, Et elle livre des ceintures au marchand.'),
  (20, 31, 25, 'Elle est revêtue de force et de gloire, Et elle se rit de l''avenir.'),
  (20, 31, 26, 'Elle ouvre la bouche avec sagesse, Et des instructions aimables sont sur sa langue.'),
  (20, 31, 27, 'Elle veille sur ce qui se passe dans sa maison, Et elle ne mange pas le pain de paresse.'),
  (20, 31, 28, 'Ses fils se lèvent, et la disent heureuse; Son mari se lève, et lui donne des louanges:'),
  (20, 31, 29, 'Plusieurs filles ont une conduite vertueuse; Mais toi, tu les surpasses toutes.'),
  (20, 31, 30, 'La grâce est trompeuse, et la beauté est vaine; La femme qui craint l''Éternel est celle qui sera louée.'),
  (20, 31, 31, 'Récompensez-la du fruit de son travail, Et qu''aux portes ses œuvres la louent.'),
  (21, 1, 1, 'Paroles de l''Ecclésiaste, fils de David, roi de Jérusalem.'),
  (21, 1, 2, 'Vanité des vanités, dit l''Ecclésiaste, vanité des vanités, tout est vanité.'),
  (21, 1, 3, 'Quel avantage revient-il à l''homme de toute la peine qu''il se donne sous le soleil?'),
  (21, 1, 4, 'Une génération s''en va, une autre vient, et la terre subsiste toujours.'),
  (21, 1, 5, 'Le soleil se lève, le soleil se couche; il soupire après le lieu d''où il se lève de nouveau.'),
  (21, 1, 6, 'Le vent se dirige vers le midi, tourne vers le nord; puis il tourne encore, et reprend les mêmes circuits.'),
  (21, 1, 7, 'Tous les fleuves vont à la mer, et la mer n''est point remplie; ils continuent à aller vers le lieu où ils se dirigent.'),
  (21, 1, 8, 'Toutes choses sont en travail au delà de ce qu''on peut dire; l''œil ne se rassasie pas de voir, et l''oreille ne se lasse pas d''entendre.'),
  (21, 1, 9, 'Ce qui a été, c''est ce qui sera, et ce qui s''est fait, c''est ce qui se fera, il n''y a rien de nouveau sous le soleil.'),
  (21, 1, 10, 'S''il est une chose dont on dise: Vois ceci, c''est nouveau! cette chose existait déjà dans les siècles qui nous ont précédés.'),
  (21, 1, 11, 'On ne se souvient pas de ce qui est ancien; et ce qui arrivera dans la suite ne laissera pas de souvenir chez ceux qui vivront plus tard.'),
  (21, 1, 12, 'Moi, l''Ecclésiaste, j''ai été roi d''Israël à Jérusalem.'),
  (21, 1, 13, 'J''ai appliqué mon cœur à rechercher et à sonder par la sagesse tout ce qui se fait sous les cieux: c''est là une occupation pénible, à laquelle Dieu soumet les fils de l''homme.'),
  (21, 1, 14, 'J''ai vu tout ce qui se fait sous le soleil; et voici, tout est vanité et poursuite du vent.'),
  (21, 1, 15, 'Ce qui est courbé ne peut se redresser, et ce qui manque ne peut être compté.'),
  (21, 1, 16, 'J''ai dit en mon cœur: Voici, j''ai grandi et surpassé en sagesse tous ceux qui ont dominé avant moi sur Jérusalem, et mon cœur a vu beaucoup de sagesse et de science.'),
  (21, 1, 17, 'J''ai appliqué mon cœur à connaître la sagesse, et à connaître la sottise et la folie; j''ai compris que cela aussi c''est la poursuite du vent.'),
  (21, 1, 18, 'Car avec beaucoup de sagesse on a beaucoup de chagrin, et celui qui augmente sa science augmente sa douleur.'),
  (21, 2, 1, 'J''ai dit en mon cœur: Allons! je t''éprouverai par la joie, et tu goûteras le bonheur. Et voici, c''est encore là une vanité.'),
  (21, 2, 2, 'J''ai dit du rire: Insensé! et de la joie: A quoi sert-elle?'),
  (21, 2, 3, 'Je résolus en mon cœur de livrer ma chair au vin, tandis que mon cœur me conduirait avec sagesse, et de m''attacher à la folie jusqu''à ce que je visse ce qu''il est bon pour les fils de l''homme de faire sous les cieux pendant le nombre des jours de leur vie.'),
  (21, 2, 4, 'J''exécutai de grands ouvrages: je me bâtis des maisons; je me plantai des vignes;'),
  (21, 2, 5, 'je me fis des jardins et des vergers, et j''y plantai des arbres à fruit de toute espèce;'),
  (21, 2, 6, 'je me créai des étangs, pour arroser la forêt où croissaient les arbres.'),
  (21, 2, 7, 'J''achetai des serviteurs et des servantes, et j''eus leurs enfants nés dans la maison; je possédai des troupeaux de bœufs et de brebis, plus que tous ceux qui étaient avant moi dans Jérusalem.'),
  (21, 2, 8, 'Je m''amassai de l''argent et de l''or, et les richesses des rois et des provinces. Je me procurai des chanteurs et des chanteuses, et les délices des fils de l''homme, des femmes en grand nombre.'),
  (21, 2, 9, 'Je devins grand, plus grand que tous ceux qui étaient avant moi dans Jérusalem. Et même ma sagesse demeura avec moi.'),
  (21, 2, 10, 'Tout ce que mes yeux avaient désiré, je ne les en ai point privés; je n''ai refusé à mon cœur aucune joie; car mon cœur prenait plaisir à tout mon travail, et c''est la part qui m''en est revenue.'),
  (21, 2, 11, 'Puis, j''ai considéré tous les ouvrages que mes mains avaient faits, et la peine que j''avais prise à les exécuter; et voici, tout est vanité et poursuite du vent, et il n''y a aucun avantage à tirer de ce qu''on fait sous le soleil.'),
  (21, 2, 12, 'Alors j''ai tourné mes regards vers la sagesse, et vers la sottise et la folie. -Car que fera l''homme qui succédera au roi? Ce qu''on a déjà fait.'),
  (21, 2, 13, 'Et j''ai vu que la sagesse a de l''avantage sur la folie, comme la lumière a de l''avantage sur les ténèbres;'),
  (21, 2, 14, 'le sage a ses yeux à la tête, et l''insensé marche dans les ténèbres. Mais j''ai reconnu aussi qu''ils ont l''un et l''autre un même sort.'),
  (21, 2, 15, 'Et j''ai dit en mon cœur: J''aurai le même sort que l''insensé; pourquoi donc ai-je été plus sage? Et j''ai dit en mon cœur que c''est encore là une vanité.'),
  (21, 2, 16, 'Car la mémoire du sage n''est pas plus éternelle que celle de l''insensé, puisque déjà les jours qui suivent, tout est oublié. Eh quoi! le sage meurt aussi bien que l''insensé!'),
  (21, 2, 17, 'Et j''ai haï la vie, car ce qui se fait sous le soleil m''a déplu, car tout est vanité et poursuite du vent.'),
  (21, 2, 18, 'J''ai haï tout le travail que j''ai fait sous le soleil, et dont je dois laisser la jouissance à l''homme qui me succédera.'),
  (21, 2, 19, 'Et qui sait s''il sera sage ou insensé? Cependant il sera maître de tout mon travail, de tout le fruit de ma sagesse sous le soleil. C''est encore là une vanité.'),
  (21, 2, 20, 'Et j''en suis venu à livrer mon cœur au désespoir, à cause de tout le travail que j''ai fait sous le soleil.'),
  (21, 2, 21, 'Car tel homme a travaillé avec sagesse et science et avec succès, et il laisse le produit de son travail à un homme qui ne s''en est point occupé. C''est encore là une vanité et un grand mal.'),
  (21, 2, 22, 'Que revient-il, en effet, à l''homme de tout son travail et de la préoccupation de son cœur, objet de ses fatigues sous le soleil?'),
  (21, 2, 23, 'Tous ses jours ne sont que douleur, et son partage n''est que chagrin; même la nuit son cœur ne repose pas. C''est encore là une vanité.'),
  (21, 2, 24, 'Il n''y a de bonheur pour l''homme qu''à manger et à boire, et à faire jouir son âme du bien-être, au milieu de son travail; mais j''ai vu que cela aussi vient de la main de Dieu.'),
  (21, 2, 25, 'Qui, en effet, peut manger et jouir, si ce n''est moi?'),
  (21, 2, 26, 'Car il donne à l''homme qui lui est agréable la sagesse, la science et la joie; mais il donne au pécheur le soin de recueillir et d''amasser, afin de donner à celui qui est agréable à Dieu. C''est encore là une vanité et la poursuite du vent.'),
  (21, 3, 1, 'Il y a un temps pour tout, un temps pour toute chose sous les cieux:'),
  (21, 3, 2, 'un temps pour naître, et un temps pour mourir; un temps pour planter, et un temps pour arracher ce qui a été planté;'),
  (21, 3, 3, 'un temps pour tuer, et un temps pour guérir; un temps pour abattre, et un temps pour bâtir;'),
  (21, 3, 4, 'un temps pour pleurer, et un temps pour rire; un temps pour se lamenter, et un temps pour danser;'),
  (21, 3, 5, 'un temps pour lancer des pierres, et un temps pour ramasser des pierres; un temps pour embrasser, et un temps pour s''éloigner des embrassements;'),
  (21, 3, 6, 'un temps pour chercher, et un temps pour perdre; un temps pour garder, et un temps pour jeter;'),
  (21, 3, 7, 'un temps pour déchirer, et un temps pour coudre; un temps pour se taire, et un temps pour parler;'),
  (21, 3, 8, 'un temps pour aimer, et un temps pour haïr; un temps pour la guerre, et un temps pour la paix.'),
  (21, 3, 9, 'Quel avantage celui qui travaille retire-t-il de sa peine?'),
  (21, 3, 10, 'J''ai vu à quelle occupation Dieu soumet les fils de l''homme.'),
  (21, 3, 11, 'Il fait toute chose bonne en son temps; même il a mis dans leur cœur la pensée de l''éternité, bien que l''homme ne puisse pas saisir l''œuvre que Dieu fait, du commencement jusqu''à la fin.'),
  (21, 3, 12, 'J''ai reconnu qu''il n''y a de bonheur pour eux qu''à se réjouir et à se donner du bien-être pendant leur vie;'),
  (21, 3, 13, 'mais que, si un homme mange et boit et jouit du bien-être au milieu de tout son travail, c''est là un don de Dieu.'),
  (21, 3, 14, 'J''ai reconnu que tout ce que Dieu fait durera toujours, qu''il n''y a rien à y ajouter et rien à en retrancher, et que Dieu agit ainsi afin qu''on le craigne.'),
  (21, 3, 15, 'Ce qui est a déjà été, et ce qui sera a déjà été, et Dieu ramène ce qui est passé.'),
  (21, 3, 16, 'J''ai encore vu sous le soleil qu''au lieu établi pour juger il y a de la méchanceté, et qu''au lieu établi pour la justice il y a de la méchanceté.'),
  (21, 3, 17, 'J''ai dit en mon cœur: Dieu jugera le juste et le méchant; car il y a là un temps pour toute chose et pour toute œuvre.'),
  (21, 3, 18, 'J''ai dit en mon cœur, au sujet des fils de l''homme, que Dieu les éprouverait, et qu''eux-mêmes verraient qu''ils ne sont que des bêtes.'),
  (21, 3, 19, 'Car le sort des fils de l''homme et celui de la bête sont pour eux un même sort; comme meurt l''un, ainsi meurt l''autre, ils ont tous un même souffle, et la supériorité de l''homme sur la bête est nulle; car tout est vanité.'),
  (21, 3, 20, 'Tout va dans un même lieu; tout a été fait de la poussière, et tout retourne à la poussière.'),
  (21, 3, 21, 'Qui sait si le souffle des fils de l''homme monte en haut, et si le souffle de la bête descend en bas dans la terre?'),
  (21, 3, 22, 'Et j''ai vu qu''il n''y a rien de mieux pour l''homme que de se réjouir de ses œuvres: c''est là sa part. Car qui le fera jouir de ce qui sera après lui?'),
  (21, 4, 1, 'J''ai considéré ensuite toutes les oppressions qui se commettent sous le soleil; et voici, les opprimés sont dans les larmes, et personne qui les console! ils sont en butte à la violence de leurs oppresseurs, et personne qui les console!'),
  (21, 4, 2, 'Et j''ai trouvé les morts qui sont déjà morts plus heureux que les vivants qui sont encore vivants,'),
  (21, 4, 3, 'et plus heureux que les uns et les autres celui qui n''a point encore existé et qui n''a pas vu les mauvaises actions qui se commettent sous le soleil.'),
  (21, 4, 4, 'J''ai vu que tout travail et toute habileté dans le travail n''est que jalousie de l''homme à l''égard de son prochain. C''est encore là une vanité et la poursuite du vent.'),
  (21, 4, 5, 'L''insensé se croise les mains, et mange sa propre chair.'),
  (21, 4, 6, 'Mieux vaut une main pleine avec repos, que les deux mains pleines avec travail et poursuite du vent.'),
  (21, 4, 7, 'J''ai considéré une autre vanité sous le soleil.'),
  (21, 4, 8, 'Tel homme est seul et sans personne qui lui tienne de près, il n''a ni fils ni frère, et pourtant son travail n''a point de fin et ses yeux ne sont jamais rassasiés de richesses. Pour qui donc est-ce que je travaille, et que je prive mon âme de jouissances? C''est encore là une vanité et une chose mauvaise.'),
  (21, 4, 9, 'Deux valent mieux qu''un, parce qu''ils retirent un bon salaire de leur travail.'),
  (21, 4, 10, 'Car, s''ils tombent, l''un relève son compagnon; mais malheur à celui qui est seul et qui tombe, sans avoir un second pour le relever!'),
  (21, 4, 11, 'De même, si deux couchent ensemble, ils auront chaud; mais celui qui est seul, comment aura-t-il chaud?'),
  (21, 4, 12, 'Et si quelqu''un est plus fort qu''un seul, les deux peuvent lui résister; et la corde à trois fils ne se rompt pas facilement.'),
  (21, 4, 13, 'Mieux vaut un enfant pauvre et sage qu''un roi vieux et insensé qui ne sait plus écouter les avis;'),
  (21, 4, 14, 'car il peut sortir de prison pour régner, et même être né pauvre dans son royaume.'),
  (21, 4, 15, 'J''ai vu tous les vivants qui marchent sous le soleil entourer l''enfant qui devait succéder au roi et régner à sa place.'),
  (21, 4, 16, 'Il n''y avait point de fin à tout ce peuple, à tous ceux à la tête desquels il était. Et toutefois, ceux qui viendront après ne se réjouiront pas à son sujet. Car c''est encore là une vanité et la poursuite du vent.'),
  (21, 5, 1, 'Prends garde à ton pied, lorsque tu entres dans la maison de Dieu; approche-toi pour écouter, plutôt que pour offrir le sacrifice des insensés, car ils ne savent pas qu''ils font mal.'),
  (21, 5, 2, 'Ne te presse pas d''ouvrir la bouche, et que ton cœur ne se hâte pas d''exprimer une parole devant Dieu; car Dieu est au ciel, et toi sur la terre: que tes paroles soient donc peu nombreuses.'),
  (21, 5, 3, 'Car, si les songes naissent de la multitude des occupations, la voix de l''insensé se fait entendre dans la multitude des paroles.'),
  (21, 5, 4, 'Lorsque tu as fait un vœu à Dieu, ne tarde pas à l''accomplir, car il n''aime pas les insensés: accomplis le vœu que tu as fait.'),
  (21, 5, 5, 'Mieux vaut pour toi ne point faire de vœu, que d''en faire un et de ne pas l''accomplir.'),
  (21, 5, 6, 'Ne permets pas à ta bouche de faire pécher ta chair, et ne dis pas en présence de l''envoyé que c''est une inadvertance. Pourquoi Dieu s''irriterait-il de tes paroles, et détruirait-il l''ouvrage de tes mains?'),
  (21, 5, 7, 'Car, s''il y a des vanités dans la multitude des songes, il y en a aussi dans beaucoup de paroles; c''est pourquoi, crains Dieu.'),
  (21, 5, 8, 'Si tu vois dans une province le pauvre opprimé et la violation du droit et de la justice, ne t''en étonne point; car un homme élevé est placé sous la surveillance d''un autre plus élevé, et au-dessus d''eux il en est de plus élevés encore.'),
  (21, 5, 9, 'Un avantage pour le pays à tous égards, c''est un roi honoré du pays.'),
  (21, 5, 10, 'Celui qui aime l''argent n''est pas rassasié par l''argent, et celui qui aime les richesses n''en profite pas. C''est encore là une vanité.'),
  (21, 5, 11, 'Quand le bien abonde, ceux qui le mangent abondent; et quel avantage en revient-il à son possesseur, sinon qu''il le voit de ses yeux?'),
  (21, 5, 12, 'Le sommeil du travailleur est doux, qu''il ait peu ou beaucoup à manger; mais le rassasiement du riche ne le laisse pas dormir.'),
  (21, 5, 13, 'Il est un mal grave que j''ai vu sous le soleil: des richesses conservées, pour son malheur, par celui qui les possède.'),
  (21, 5, 14, 'Ces richesses se perdent par quelque événement fâcheux; il a engendré un fils, et il ne reste rien entre ses mains.'),
  (21, 5, 15, 'Comme il est sorti du ventre de sa mère, il s''en retourne nu ainsi qu''il était venu, et pour son travail n''emporte rien qu''il puisse prendre dans sa main.'),
  (21, 5, 16, 'C''est encore là un mal grave. Il s''en va comme il était venu; et quel avantage lui revient-il d''avoir travaillé pour du vent?'),
  (21, 5, 17, 'De plus, toute sa vie il mange dans les ténèbres, et il a beaucoup de chagrin, de maux et d''irritation.'),
  (21, 5, 18, 'Voici ce que j''ai vu: c''est pour l''homme une chose bonne et belle de manger et de boire, et de jouir du bien-être au milieu de tout le travail qu''il fait sous le soleil, pendant le nombre des jours de vie que Dieu lui a donnés; car c''est là sa part.'),
  (21, 5, 19, 'Mais, si Dieu a donné à un homme des richesses et des biens, s''il l''a rendu maître d''en manger, d''en prendre sa part, et de se réjouir au milieu de son travail, c''est là un don de Dieu.'),
  (21, 5, 20, 'Car il ne se souviendra pas beaucoup des jours de sa vie, parce que Dieu répand la joie dans son cœur.'),
  (21, 6, 1, 'Il est un mal que j''ai vu sous le soleil, et qui est fréquent parmi les hommes.'),
  (21, 6, 2, 'Il y a tel homme à qui Dieu a donné des richesses, des biens, et de la gloire, et qui ne manque pour son âme de rien de ce qu''il désire, mais que Dieu ne laisse pas maître d''en jouir, car c''est un étranger qui en jouira. C''est là une vanité et un mal grave.'),
  (21, 6, 3, 'Quand un homme aurait cent fils, vivrait un grand nombre d''années, et que les jours de ses années se multiplieraient, si son âme ne s''est point rassasiée de bonheur, et si de plus il n''a point de sépulture, je dis qu''un avorton est plus heureux que lui.'),
  (21, 6, 4, 'Car il est venu en vain, il s''en va dans les ténèbres, et son nom reste couvert de ténèbres;'),
  (21, 6, 5, 'il n''a point vu, il n''a point connu le soleil; il a plus de repos que cet homme.'),
  (21, 6, 6, 'Et quand celui-ci vivrait deux fois mille ans, sans jouir du bonheur, tout ne va-t-il pas dans un même lieu?'),
  (21, 6, 7, 'Tout le travail de l''homme est pour sa bouche, et cependant ses désirs ne sont jamais satisfaits.'),
  (21, 6, 8, 'Car quel avantage le sage a-t-il sur l''insensé? quel avantage a le malheureux qui sait se conduire en présence des vivants?'),
  (21, 6, 9, 'Ce que les yeux voient est préférable à l''agitation des désirs: c''est encore là une vanité et la poursuite du vent.'),
  (21, 6, 10, 'Ce qui existe a déjà été appelé par son nom; et l''on sait que celui qui est homme ne peut contester avec un plus fort que lui.'),
  (21, 6, 11, 'S''il y a beaucoup de choses, il y a beaucoup de vanités: quel avantage en revient-il à l''homme?'),
  (21, 6, 12, 'Car qui sait ce qui est bon pour l''homme dans la vie, pendant le nombre des jours de sa vie de vanité, qu''il passe comme une ombre? Et qui peut dire à l''homme ce qui sera après lui sous le soleil?'),
  (21, 7, 1, 'Une bonne réputation vaut mieux que le bon parfum, et le jour de la mort que le jour de la naissance.'),
  (21, 7, 2, 'Mieux vaut aller dans une maison de deuil que d''aller dans une maison de festin; car c''est là la fin de tout homme, et celui qui vit prend la chose à cœur.'),
  (21, 7, 3, 'Mieux vaut le chagrin que le rire; car avec un visage triste le cœur peut être content.'),
  (21, 7, 4, 'Le cœur des sages est dans la maison de deuil, et le cœur des insensés dans la maison de joie.'),
  (21, 7, 5, 'Mieux vaut entendre la réprimande du sage que d''entendre le chant des insensés.'),
  (21, 7, 6, 'Car comme le bruit des épines sous la chaudière, ainsi est le rire des insensés. C''est encore là une vanité.'),
  (21, 7, 7, 'L''oppression rend insensé le sage, et les présents corrompent le cœur.'),
  (21, 7, 8, 'Mieux vaut la fin d''une chose que son commencement; mieux vaut un esprit patient qu''un esprit hautain.'),
  (21, 7, 9, 'Ne te hâte pas en ton esprit de t''irriter, car l''irritation repose dans le sein des insensés.'),
  (21, 7, 10, 'Ne dis pas: D''où vient que les jours passés étaient meilleurs que ceux ci? Car ce n''est point par sagesse que tu demandes cela.'),
  (21, 7, 11, 'La sagesse vaut autant qu''un héritage, et même plus pour ceux qui voient le soleil.'),
  (21, 7, 12, 'Car à l''ombre de la sagesse on est abrité comme à l''ombre de l''argent; mais un avantage de la science, c''est que la sagesse fait vivre ceux qui la possèdent.'),
  (21, 7, 13, 'Regarde l''œuvre de Dieu: qui pourra redresser ce qu''il a courbé?'),
  (21, 7, 14, 'Au jour du bonheur, sois heureux, et au jour du malheur, réfléchis: Dieu a fait l''un comme l''autre, afin que l''homme ne découvre en rien ce qui sera après lui.'),
  (21, 7, 15, 'J''ai vu tout cela pendant les jours de ma vanité. Il y a tel juste qui périt dans sa justice, et il y a tel méchant qui prolonge son existence dans sa méchanceté.'),
  (21, 7, 16, 'Ne sois pas juste à l''excès, et ne te montre pas trop sage: pourquoi te détruirais-tu?'),
  (21, 7, 17, 'Ne sois pas méchant à l''excès, et ne sois pas insensé: pourquoi mourrais-tu avant ton temps?'),
  (21, 7, 18, 'Il est bon que tu retiennes ceci, et que tu ne négliges point cela; car celui qui craint Dieu échappe à toutes ces choses.'),
  (21, 7, 19, 'La sagesse rend le sage plus fort que dix chefs qui sont dans une ville.'),
  (21, 7, 20, 'Non, il n''y a sur la terre point d''homme juste qui fasse le bien et qui ne pèche jamais.'),
  (21, 7, 21, 'Ne fais donc pas attention à toutes les paroles qu''on dit, de peur que tu n''entendes ton serviteur te maudire;'),
  (21, 7, 22, 'car ton cœur a senti bien des fois que tu as toi-même maudit les autres.'),
  (21, 7, 23, 'J''ai éprouvé tout cela par la sagesse. J''ai dit: Je serai sage. Et la sagesse est restée loin de moi.'),
  (21, 7, 24, 'Ce qui est loin, ce qui est profond, profond, qui peut l''atteindre?'),
  (21, 7, 25, 'Je me suis appliqué dans mon cœur à connaître, à sonder, et à chercher la sagesse et la raison des choses, et à connaître la folie de la méchanceté et la stupidité de la sottise.'),
  (21, 7, 26, 'Et j''ai trouvé plus amère que la mort la femme dont le cœur est un piège et un filet, et dont les mains sont des liens; celui qui est agréable à Dieu lui échappe, mais le pécheur est pris par elle.'),
  (21, 7, 27, 'Voici ce que j''ai trouvé, dit l''Ecclésiaste, en examinant les choses une à une pour en saisir la raison;'),
  (21, 7, 28, 'voici ce que mon âme cherche encore, et que je n''ai point trouvé. J''ai trouvé un homme entre mille; mais je n''ai pas trouvé une femme entre elles toutes.'),
  (21, 7, 29, 'Seulement, voici ce que j''ai trouvé, c''est que Dieu a fait les hommes droits; mais ils ont cherché beaucoup de détours.'),
  (21, 8, 1, 'Qui est comme le sage, et qui connaît l''explication des choses? La sagesse d''un homme fait briller son visage, et la sévérité de sa face est changée.'),
  (21, 8, 2, 'Je te dis: Observe les ordres du roi, et cela à cause du serment fait à Dieu.'),
  (21, 8, 3, 'Ne te hâte pas de t''éloigner de lui, et ne persiste pas dans une chose mauvaise: car il peut faire tout ce qui lui plaît,'),
  (21, 8, 4, 'parce que la parole du roi est puissante; et qui lui dira: Que fais-tu?'),
  (21, 8, 5, 'Celui qui observe le commandement ne connaît point de chose mauvaise, et le cœur du sage connaît le temps et le jugement.'),
  (21, 8, 6, 'Car il y a pour toute chose un temps et un jugement, quand le malheur accable l''homme.'),
  (21, 8, 7, 'Mais il ne sait point ce qui arrivera, et qui lui dira comment cela arrivera?'),
  (21, 8, 8, 'L''homme n''est pas maître de son souffle pour pouvoir le retenir, et il n''a aucune puissance sur le jour de la mort; il n''y a point de délivrance dans ce combat, et la méchanceté ne saurait sauver les méchants.'),
  (21, 8, 9, 'J''ai vu tout cela, et j''ai appliqué mon cœur à tout ce qui se fait sous le soleil. Il y a un temps où l''homme domine sur l''homme pour le rendre malheureux.'),
  (21, 8, 10, 'Alors j''ai vu des méchants recevoir la sépulture et entrer dans leur repos, et ceux qui avaient agi avec droiture s''en aller loin du lieu saint et être oubliés dans la ville. C''est encore là une vanité.'),
  (21, 8, 11, 'Parce qu''une sentence contre les mauvaises actions ne s''exécute pas promptement, le cœur des fils de l''homme se remplit en eux du désir de faire le mal.'),
  (21, 8, 12, 'Cependant, quoique le pécheur fasse cent fois le mal et qu''il y persévère longtemps, je sais aussi que le bonheur est pour ceux qui craignent Dieu, parce qu''ils ont de la crainte devant lui.'),
  (21, 8, 13, 'Mais le bonheur n''est pas pour le méchant, et il ne prolongera point ses jours, pas plus que l''ombre, parce qu''il n''a pas de la crainte devant Dieu.'),
  (21, 8, 14, 'Il est une vanité qui a lieu sur la terre: c''est qu''il y a des justes auxquels il arrive selon l''œuvre des méchants, et des méchants auxquels il arrive selon l''œuvre des justes. Je dis que c''est encore là une vanité.'),
  (21, 8, 15, 'J''ai donc loué la joie, parce qu''il n''y a de bonheur pour l''homme sous le soleil qu''à manger et à boire et à se réjouir; c''est là ce qui doit l''accompagner au milieu de son travail, pendant les jours de vie que Dieu lui donne sous le soleil.'),
  (21, 8, 16, 'Lorsque j''ai appliqué mon cœur à connaître la sagesse et à considérer les choses qui se passent sur la terre, -car les yeux de l''homme ne goûtent le sommeil ni jour ni nuit,'),
  (21, 8, 17, 'j''ai vu toute l''œuvre de Dieu, j''ai vu que l''homme ne peut pas trouver ce qui se fait sous le soleil; il a beau se fatiguer à chercher, il ne trouve pas; et même si le sage veut connaître, il ne peut pas trouver.'),
  (21, 9, 1, 'Oui, j''ai appliqué mon cœur à tout cela, j''ai fait de tout cela l''objet de mon examen, et j''ai vu que les justes et les sages, et leurs travaux, sont dans la main de Dieu, et l''amour aussi bien que la haine; les hommes ne savent rien: tout est devant eux.'),
  (21, 9, 2, 'Tout arrive également à tous; même sort pour le juste et pour le méchant, pour celui qui est bon et pur et pour celui qui est impur, pour celui qui sacrifie et pour celui qui ne sacrifie pas; il en est du bon comme du pécheur, de celui qui jure comme de celui qui craint de jurer.'),
  (21, 9, 3, 'Ceci est un mal parmi tout ce qui se fait sous le soleil, c''est qu''il y a pour tous un même sort; aussi le cœur des fils de l''homme est-il plein de méchanceté, et la folie est dans leur cœur pendant leur vie; après quoi, ils vont chez les morts. Car, qui est excepté?'),
  (21, 9, 4, 'Pour tous ceux qui vivent il y a de l''espérance; et même un chien vivant vaut mieux qu''un lion mort.'),
  (21, 9, 5, 'Les vivants, en effet, savent qu''ils mourront; mais les morts ne savent rien, et il n''y a pour eux plus de salaire, puisque leur mémoire est oubliée.'),
  (21, 9, 6, 'Et leur amour, et leur haine, et leur envie, ont déjà péri; et ils n''auront plus jamais aucune part à tout ce qui se fait sous le soleil.'),
  (21, 9, 7, 'Va, mange avec joie ton pain, et bois gaiement ton vin; car dès longtemps Dieu prend plaisir à ce que tu fais.'),
  (21, 9, 8, 'Qu''en tout temps tes vêtements soient blancs, et que l''huile ne manque point sur ta tête.'),
  (21, 9, 9, 'Jouis de la vie avec la femme que tu aimes, pendant tous les jours de ta vie de vanité, que Dieu t''a donnés sous le soleil, pendant tous les jours de ta vanité; car c''est ta part dans la vie, au milieu de ton travail que tu fais sous le soleil.'),
  (21, 9, 10, 'Tout ce que ta main trouve à faire avec ta force, fais-le; car il n''y a ni œuvre, ni pensée, ni science, ni sagesse, dans le séjour des morts, où tu vas.'),
  (21, 9, 11, 'J''ai encore vu sous le soleil que la course n''est point aux agiles ni la guerre aux vaillants, ni le pain aux sages, ni la richesse aux intelligents, ni la faveur aux savants; car tout dépend pour eux du temps et des circonstances.'),
  (21, 9, 12, 'L''homme ne connaît pas non plus son heure, pareil aux poissons qui sont pris au filet fatal, et aux oiseaux qui sont pris au piège; comme eux, les fils de l''homme sont enlacés au temps du malheur, lorsqu''il tombe sur eux tout à coup.'),
  (21, 9, 13, 'J''ai aussi vu sous le soleil ce trait d''une sagesse qui m''a paru grande.'),
  (21, 9, 14, 'Il y avait une petite ville, avec peu d''hommes dans son sein; un roi puissant marcha sur elle, l''investit, et éleva contre elle de grands forts.'),
  (21, 9, 15, 'Il s''y trouvait un homme pauvre et sage, qui sauva la ville par sa sagesse. Et personne ne s''est souvenu de cet homme pauvre.'),
  (21, 9, 16, 'Et j''ai dit: La sagesse vaut mieux que la force. Cependant la sagesse du pauvre est méprisée, et ses paroles ne sont pas écoutées.'),
  (21, 9, 17, 'Les paroles des sages tranquillement écoutées valent mieux que les cris de celui qui domine parmi les insensés.'),
  (21, 9, 18, 'La sagesse vaut mieux que les instruments de guerre; mais un seul pécheur détruit beaucoup de bien.'),
  (21, 10, 1, 'Les mouches mortes infectent et font fermenter l''huile du parfumeur; un peu de folie l''emporte sur la sagesse et sur la gloire.'),
  (21, 10, 2, 'Le cœur du sage est à sa droite, et le cœur de l''insensé à sa gauche.'),
  (21, 10, 3, 'Quand l''insensé marche dans un chemin, le sens lui manque, et il dit de chacun: Voilà un fou!'),
  (21, 10, 4, 'Si l''esprit de celui qui domine s''élève contre toi, ne quitte point ta place; car le calme prévient de grands péchés.'),
  (21, 10, 5, 'Il est un mal que j''ai vu sous le soleil, comme une erreur provenant de celui qui gouverne:'),
  (21, 10, 6, 'la folie occupe des postes très élevés, et des riches sont assis dans l''abaissement.'),
  (21, 10, 7, 'J''ai vu des esclaves sur des chevaux, et des princes marchant sur terre comme des esclaves.'),
  (21, 10, 8, 'Celui qui creuse une fosse y tombera, et celui qui renverse une muraille sera mordu par un serpent.'),
  (21, 10, 9, 'Celui qui remue des pierres en sera blessé, et celui qui fend du bois en éprouvera du danger.'),
  (21, 10, 10, 'S''il a émoussé le fer, et s''il n''en a pas aiguisé le tranchant, il devra redoubler de force; mais la sagesse a l''avantage du succès.'),
  (21, 10, 11, 'Si le serpent mord faute d''enchantement, il n''y a point d''avantage pour l''enchanteur.'),
  (21, 10, 12, 'Les paroles de la bouche du sage sont pleines de grâce; mais les lèvres de l''insensé causent sa perte.'),
  (21, 10, 13, 'Le commencement des paroles de sa bouche est folie, et la fin de son discours est une méchante folie.'),
  (21, 10, 14, 'L''insensé multiplie les paroles. L''homme ne sait point ce qui arrivera, et qui lui dira ce qui sera après lui?'),
  (21, 10, 15, 'Le travail de l''insensé le fatigue, parce qu''il ne sait pas aller à la ville.'),
  (21, 10, 16, 'Malheur à toi, pays dont le roi est un enfant, et dont les princes mangent dès le matin!'),
  (21, 10, 17, 'Heureux toi, pays dont le roi est de race illustre, et dont les princes mangent au temps convenable, pour soutenir leurs forces, et non pour se livrer à la boisson!'),
  (21, 10, 18, 'Quand les mains sont paresseuses, la charpente s''affaisse; et quand les mains sont lâches, la maison a des gouttières.'),
  (21, 10, 19, 'On fait des repas pour se divertir, le vin rend la vie joyeuse, et l''argent répond à tout.'),
  (21, 10, 20, 'Ne maudis pas le roi, même dans ta pensée, et ne maudis pas le riche dans la chambre où tu couches; car l''oiseau du ciel emporterait ta voix, l''animal ailé publierait tes paroles.'),
  (21, 11, 1, 'Jette ton pain sur la face des eaux, car avec le temps tu le retrouveras;'),
  (21, 11, 2, 'donnes-en une part à sept et même à huit, car tu ne sais pas quel malheur peut arriver sur la terre.'),
  (21, 11, 3, 'Quand les nuages sont pleins de pluie, ils la répandent sur la terre; et si un arbre tombe, au midi ou au nord, il reste à la place où il est tombé.'),
  (21, 11, 4, 'Celui qui observe le vent ne sèmera point, et celui qui regarde les nuages ne moissonnera point.'),
  (21, 11, 5, 'Comme tu ne sais pas quel est le chemin du vent, ni comment se forment les os dans le ventre de la femme enceinte, tu ne connais pas non plus l''œuvre de Dieu qui fait tout.'),
  (21, 11, 6, 'Dès le matin sème ta semence, et le soir ne laisse pas reposer ta main; car tu ne sais point ce qui réussira, ceci ou cela, ou si l''un et l''autre sont également bons.'),
  (21, 11, 7, 'La lumière est douce, et il est agréable aux yeux de voir le soleil.'),
  (21, 11, 8, 'Si donc un homme vit beaucoup d''années, qu''il se réjouisse pendant toutes ces années, et qu''il pense aux jours de ténèbres qui seront nombreux; tout ce qui arrivera est vanité.'),
  (21, 11, 9, 'Jeune homme, réjouis-toi dans ta jeunesse, livre ton cœur à la joie pendant les jours de ta jeunesse, marche dans les voies de ton cœur et selon les regards de tes yeux; mais sache que pour tout cela Dieu t''appellera en jugement.'),
  (21, 11, 10, 'Bannis de ton cœur le chagrin, et éloigne le mal de ton corps; car la jeunesse et l''aurore sont vanité.'),
  (21, 12, 1, 'Mais souviens-toi de ton créateur pendant les jours de ta jeunesse, avant que les jours mauvais arrivent et que les années s''approchent où tu diras: Je n''y prends point de plaisir;'),
  (21, 12, 2, 'avant que s''obscurcissent le soleil et la lumière, la lune et les étoiles, et que les nuages reviennent après la pluie,'),
  (21, 12, 3, 'temps où les gardiens de la maison tremblent, où les hommes forts se courbent, où celles qui moulent s''arrêtent parce qu''elles sont diminuées, où ceux qui regardent par les fenêtres sont obscurcis,'),
  (21, 12, 4, 'où les deux battants de la porte se ferment sur la rue quand s''abaisse le bruit de la meule, où l''on se lève au chant de l''oiseau, où s''affaiblissent toutes les filles du chant,'),
  (21, 12, 5, 'où l''on redoute ce qui est élevé, où l''on a des terreurs en chemin, où l''amandier fleurit, où la sauterelle devient pesante, et où la câpre n''a plus d''effet, car l''homme s''en va vers sa demeure éternelle, et les pleureurs parcourent les rues;'),
  (21, 12, 6, 'avant que le cordon d''argent se détache, que le vase d''or se brise, que le seau se rompe sur la source, et que la roue se casse sur la citerne;'),
  (21, 12, 7, 'avant que la poussière retourne à la terre, comme elle y était, et que l''esprit retourne à Dieu qui l''a donné.'),
  (21, 12, 8, 'Vanité des vanités, dit l''Ecclésiaste, tout est vanité.'),
  (21, 12, 9, 'Outre que l''Ecclésiaste fut un sage, il a encore enseigné la science au peuple, et il a examiné, sondé, mis en ordre un grand nombre de sentences.'),
  (21, 12, 10, 'L''Ecclésiaste s''est efforcé de trouver des paroles agréables; et ce qui a été écrit avec droiture, ce sont des paroles de vérité.'),
  (21, 12, 11, 'Les paroles des sages sont comme des aiguillons; et, rassemblées en un recueil, elles sont comme des clous plantés, données par un seul maître.'),
  (21, 12, 12, 'Du reste, mon fils, tire instruction de ces choses; on ne finirait pas, si l''on voulait faire un grand nombre de livres, et beaucoup d''étude est une fatigue pour le corps.'),
  (21, 12, 13, 'Écoutons la fin du discours: Crains Dieu et observe ses commandements. C''est là ce que doit faire tout homme.'),
  (21, 12, 14, 'Car Dieu amènera toute œuvre en jugement, au sujet de tout ce qui est caché, soit bien, soit mal.'),
  (22, 1, 1, 'Cantique des cantiques, de Salomon.'),
  (22, 1, 2, 'Qu''il me baise des baisers de sa bouche! Car ton amour vaut mieux que le vin,'),
  (22, 1, 3, 'Tes parfums ont une odeur suave; Ton nom est un parfum qui se répand; C''est pourquoi les jeunes filles t''aiment.'),
  (22, 1, 4, 'Entraîne-moi après toi! Nous courrons! Le roi m''introduit dans ses appartements… Nous nous égaierons, nous nous réjouirons à cause de toi; Nous célébrerons ton amour plus que le vin. C''est avec raison que l''on t''aime.'),
  (22, 1, 5, 'Je suis noire, mais je suis belle, filles de Jérusalem, Comme les tentes de Kédar, comme les pavillons de Salomon.'),
  (22, 1, 6, 'Ne prenez pas garde à mon teint noir: C''est le soleil qui m''a brûlée. Les fils de ma mère se sont irrités contre moi, Ils m''ont faite gardienne des vignes. Ma vigne, à moi, je ne l''ai pas gardée.'),
  (22, 1, 7, 'Dis-moi, ô toi que mon cœur aime, Où tu fais paître tes brebis, Où tu les fais reposer à midi; Car pourquoi serais-je comme une égarée Près des troupeaux de tes compagnons? -'),
  (22, 1, 8, 'Si tu ne le sais pas, ô la plus belle des femmes, Sors sur les traces des brebis, Et fais paître tes chevreaux Près des demeures des bergers. -'),
  (22, 1, 9, 'A ma jument qu''on attelle aux chars de Pharaon Je te compare, ô mon amie.'),
  (22, 1, 10, 'Tes joues sont belles au milieu des colliers, Ton cou est beau au milieu des rangées de perles.'),
  (22, 1, 11, 'Nous te ferons des colliers d''or, Avec des points d''argent. -'),
  (22, 1, 12, 'Tandis que le roi est dans son entourage, Mon nard exhale son parfum.'),
  (22, 1, 13, 'Mon bien-aimé est pour moi un bouquet de myrrhe, Qui repose entre mes seins.'),
  (22, 1, 14, 'Mon bien-aimé est pour moi une grappe de troëne Des vignes d''En-Guédi. -'),
  (22, 1, 15, 'Que tu es belle, mon amie, que tu es belle! Tes yeux sont des colombes. -'),
  (22, 1, 16, 'Que tu es beau, mon bien-aimé, que tu es aimable! Notre lit, c''est la verdure. -'),
  (22, 1, 17, 'Les solives de nos maisons sont des cèdres, Nos lambris sont des cyprès. -'),
  (22, 2, 1, 'Je suis un narcisse de Saron, Un lis des vallées. -'),
  (22, 2, 2, 'Comme un lis au milieu des épines, Telle est mon amie parmi les jeunes filles. -'),
  (22, 2, 3, 'Comme un pommier au milieu des arbres de la forêt, Tel est mon bien-aimé parmi les jeunes hommes. J''ai désiré m''asseoir à son ombre, Et son fruit est doux à mon palais.'),
  (22, 2, 4, 'Il m''a fait entrer dans la maison du vin; Et la bannière qu''il déploie sur moi, c''est l''amour.'),
  (22, 2, 5, 'Soutenez-moi avec des gâteaux de raisins, Fortifiez-moi avec des pommes; Car je suis malade d''amour.'),
  (22, 2, 6, 'Que sa main gauche soit sous ma tête, Et que sa droite m''embrasse! -'),
  (22, 2, 7, 'Je vous en conjure, filles de Jérusalem, Par les gazelles et les biches des champs, Ne réveillez pas, ne réveillez pas l''amour, Avant qu''elle le veuille. -'),
  (22, 2, 8, 'C''est la voix de mon bien-aimé! Le voici, il vient, Sautant sur les montagnes, Bondissant sur les collines.'),
  (22, 2, 9, 'Mon bien-aimé est semblable à la gazelle Ou au faon des biches. Le voici, il est derrière notre mur, Il regarde par la fenêtre, Il regarde par le treillis.'),
  (22, 2, 10, 'Mon bien-aimé parle et me dit: Lève-toi, mon amie, ma belle, et viens!'),
  (22, 2, 11, 'Car voici, l''hiver est passé; La pluie a cessé, elle s''en est allée.'),
  (22, 2, 12, 'Les fleurs paraissent sur la terre, Le temps de chanter est arrivé, Et la voix de la tourterelle se fait entendre dans nos campagnes.'),
  (22, 2, 13, 'Le figuier embaume ses fruits, Et les vignes en fleur exhalent leur parfum. Lève-toi, mon amie, ma belle, et viens!'),
  (22, 2, 14, 'Ma colombe, qui te tiens dans les fentes du rocher, Qui te caches dans les parois escarpées, Fais-moi voir ta figure, Fais-moi entendre ta voix; Car ta voix est douce, et ta figure est agréable.'),
  (22, 2, 15, 'Prenez-nous les renards, Les petits renards qui ravagent les vignes; Car nos vignes sont en fleur.'),
  (22, 2, 16, 'Mon bien-aimé est à moi, et je suis à lui; Il fait paître son troupeau parmi les lis.'),
  (22, 2, 17, 'Avant que le jour se rafraîchisse, Et que les ombres fuient, Reviens!… sois semblable, mon bien-aimé, A la gazelle ou au faon des biches, Sur les montagnes qui nous séparent.'),
  (22, 3, 1, 'Sur ma couche, pendant les nuits, J''ai cherché celui que mon cœur aime; Je l''ai cherché, et je ne l''ai point trouvé…'),
  (22, 3, 2, 'Je me lèverai, et je ferai le tour de la ville, Dans les rues et sur les places; Je chercherai celui que mon cœur aime… Je l''ai cherché, et je ne l''ai point trouvé.'),
  (22, 3, 3, 'Les gardes qui font la ronde dans la ville m''ont rencontrée: Avez-vous vu celui que mon cœur aime?'),
  (22, 3, 4, 'A peine les avais-je passés, Que j''ai trouvé celui que mon cœur aime; Je l''ai saisi, et je ne l''ai point lâché Jusqu''à ce que je l''aie amené dans la maison de ma mère, Dans la chambre de celle qui m''a conçue. -'),
  (22, 3, 5, 'Je vous en conjure, filles de Jérusalem, Par les gazelles et les biches des champs, Ne réveillez pas, ne réveillez pas l''amour, Avant qu''elle le veuille. -'),
  (22, 3, 6, 'Qui est celle qui monte du désert, Comme des colonnes de fumée, Au milieu des vapeurs de myrrhe et d''encens Et de tous les aromates des marchands? -'),
  (22, 3, 7, 'Voici la litière de Salomon, Et autour d''elle soixante vaillants hommes, Des plus vaillants d''Israël.'),
  (22, 3, 8, 'Tous sont armés de l''épée, Sont exercés au combat; Chacun porte l''épée sur sa hanche, En vue des alarmes nocturnes.'),
  (22, 3, 9, 'Le roi Salomon s''est fait une litière De bois du Liban.'),
  (22, 3, 10, 'Il en a fait les colonnes d''argent, Le dossier d''or, Le siège de pourpre; Au milieu est une broderie, œuvre d''amour Des filles de Jérusalem.'),
  (22, 3, 11, 'Sortez, filles de Sion, regardez Le roi Salomon, Avec la couronne dont sa mère l''a couronné Le jour de ses fiançailles, Le jour de la joie de son cœur. -'),
  (22, 4, 1, 'Que tu es belle, mon amie, que tu es belle! Tes yeux sont des colombes, Derrière ton voile. Tes cheveux sont comme un troupeau de chèvres, Suspendues aux flancs de la montagne de Galaad.'),
  (22, 4, 2, 'Tes dents sont comme un troupeau de brebis tondues, Qui remontent de l''abreuvoir; Toutes portent des jumeaux, Aucune d''elles n''est stérile.'),
  (22, 4, 3, 'Tes lèvres sont comme un fil cramoisi, Et ta bouche est charmante; Ta joue est comme une moitié de grenade, Derrière ton voile.'),
  (22, 4, 4, 'Ton cou est comme la tour de David, Bâtie pour être un arsenal; Mille boucliers y sont suspendus, Tous les boucliers des héros.'),
  (22, 4, 5, 'Tes deux seins sont comme deux faons, Comme les jumeaux d''une gazelle, Qui paissent au milieu des lis.'),
  (22, 4, 6, 'Avant que le jour se rafraîchisse, Et que les ombres fuient, J''irai à la montagne de la myrrhe Et à la colline de l''encens.'),
  (22, 4, 7, 'Tu es toute belle, mon amie, Et il n''y a point en toi de défaut.'),
  (22, 4, 8, 'Viens avec moi du Liban, ma fiancée, Viens avec moi du Liban! Regarde du sommet de l''Amana, Du sommet du Senir et de l''Hermon, Des tanières des lions, Des montagnes des léopards.'),
  (22, 4, 9, 'Tu me ravis le cœur, ma sœur, ma fiancée, Tu me ravis le cœur par l''un de tes regards, Par l''un des colliers de ton cou.'),
  (22, 4, 10, 'Que de charmes dans ton amour, ma sœur, ma fiancée! Comme ton amour vaut mieux que le vin, Et combien tes parfums sont plus suaves que tous les aromates!'),
  (22, 4, 11, 'Tes lèvres distillent le miel, ma fiancée; Il y a sous ta langue du miel et du lait, Et l''odeur de tes vêtements est comme l''odeur du Liban.'),
  (22, 4, 12, 'Tu es un jardin fermé, ma sœur, ma fiancée, Une source fermée, une fontaine scellée.'),
  (22, 4, 13, 'Tes jets forment un jardin, où sont des grenadiers, Avec les fruits les plus excellents, Les troënes avec le nard;'),
  (22, 4, 14, 'Le nard et le safran, le roseau aromatique et le cinnamome, Avec tous les arbres qui donnent l''encens; La myrrhe et l''aloès, Avec tous les principaux aromates;'),
  (22, 4, 15, 'Une fontaine des jardins, Une source d''eaux vives, Des ruisseaux du Liban.'),
  (22, 4, 16, 'Lève-toi, aquilon! viens, autan! Soufflez sur mon jardin, et que les parfums s''en exhalent! -Que mon bien-aimé entre dans son jardin, Et qu''il mange de ses fruits excellents! -'),
  (22, 5, 1, 'J''entre dans mon jardin, ma sœur, ma fiancée; Je cueille ma myrrhe avec mes aromates, Je mange mon rayon de miel avec mon miel, Je bois mon vin avec mon lait… -Mangez, amis, buvez, enivrez-vous d''amour! -'),
  (22, 5, 2, 'J''étais endormie, mais mon cœur veillait… C''est la voix de mon bien-aimé, qui frappe: -Ouvre-moi, ma sœur, mon amie, Ma colombe, ma parfaite! Car ma tête est couverte de rosée, Mes boucles sont pleines des gouttes de la nuit. -'),
  (22, 5, 3, 'J''ai ôté ma tunique; comment la remettrais-je? J''ai lavé mes pieds; comment les salirais-je?'),
  (22, 5, 4, 'Mon bien-aimé a passé la main par la fenêtre, Et mes entrailles se sont émues pour lui.'),
  (22, 5, 5, 'Je me suis levée pour ouvrir à mon bien-aimé; Et de mes mains a dégoutté la myrrhe, De mes doigts, la myrrhe répandue Sur la poignée du verrou.'),
  (22, 5, 6, 'J''ai ouvert à mon bien-aimé; Mais mon bien-aimé s''en était allé, il avait disparu. J''étais hors de moi, quand il me parlait. Je l''ai cherché, et je ne l''ai point trouvé; Je l''ai appelé, et il ne m''a point répondu.'),
  (22, 5, 7, 'Les gardes qui font la ronde dans la ville m''ont rencontrée; Ils m''ont frappée, ils m''ont blessée; Ils m''ont enlevé mon voile, les gardes des murs.'),
  (22, 5, 8, 'Je vous en conjure, filles de Jérusalem, Si vous trouvez mon bien-aimé, Que lui direz-vous?… Que je suis malade d''amour. -'),
  (22, 5, 9, 'Qu''a ton bien-aimé de plus qu''un autre, O la plus belle des femmes? Qu''a ton bien-aimé de plus qu''un autre, Pour que tu nous conjures ainsi? -'),
  (22, 5, 10, 'Mon bien-aimé est blanc et vermeil; Il se distingue entre dix mille.'),
  (22, 5, 11, 'Sa tête est de l''or pur; Ses boucles sont flottantes, Noires comme le corbeau.'),
  (22, 5, 12, 'Ses yeux sont comme des colombes au bord des ruisseaux, Se baignant dans le lait, Reposant au sein de l''abondance.'),
  (22, 5, 13, 'Ses joues sont comme un parterre d''aromates, Une couche de plantes odorantes; Ses lèvres sont des lis, D''où découle la myrrhe.'),
  (22, 5, 14, 'Ses mains sont des anneaux d''or, Garnis de chrysolithes; Son corps est de l''ivoire poli, Couvert de saphirs;'),
  (22, 5, 15, 'Ses jambes sont des colonnes de marbre blanc, Posées sur des bases d''or pur. Son aspect est comme le Liban, Distingué comme les cèdres.'),
  (22, 5, 16, 'Son palais n''est que douceur, Et toute sa personne est pleine de charme. Tel est mon bien-aimé, tel est mon ami, Filles de Jérusalem! -'),
  (22, 6, 1, 'Où est allé ton bien-aimé, O la plus belle des femmes? De quel côté ton bien-aimé s''est-il dirigé? Nous le chercherons avec toi.'),
  (22, 6, 2, 'Mon bien-aimé est descendu à son jardin, Au parterre d''aromates, Pour faire paître son troupeau dans les jardins, Et pour cueillir des lis.'),
  (22, 6, 3, 'Je suis à mon bien-aimé, et mon bien-aimé est à moi; Il fait paître son troupeau parmi les lis. -'),
  (22, 6, 4, 'Tu es belle, mon amie, comme Thirtsa, Agréable comme Jérusalem, Mais terrible comme des troupes sous leurs bannières.'),
  (22, 6, 5, 'Détourne de moi tes yeux, car ils me troublent. Tes cheveux sont comme un troupeau de chèvres, Suspendues aux flancs de Galaad.'),
  (22, 6, 6, 'Tes dents sont comme un troupeau de brebis, Qui remontent de l''abreuvoir; Toutes portent des jumeaux, Aucune d''elles n''est stérile.'),
  (22, 6, 7, 'Ta joue est comme une moitié de grenade, Derrière ton voile…'),
  (22, 6, 8, 'Il y a soixante reines, quatre-vingts concubines, Et des jeunes filles sans nombre.'),
  (22, 6, 9, 'Une seule est ma colombe, ma parfaite; Elle est l''unique de sa mère, La préférée de celle qui lui donna le jour. Les jeunes filles la voient, et la disent heureuse; Les reines et les concubines aussi, et elles la louent. -'),
  (22, 6, 10, 'Qui est celle qui apparaît comme l''aurore, Belle comme la lune, pure comme le soleil, Mais terrible comme des troupes sous leurs bannières? -'),
  (22, 6, 11, 'Je suis descendue au jardin des noyers, Pour voir la verdure de la vallée, Pour voir si la vigne pousse, Si les grenadiers fleurissent.'),
  (22, 6, 12, 'Je ne sais, mais mon désir m''a rendue semblable Aux chars de mon noble peuple. -'),
  (22, 6, 13, 'Reviens, reviens, Sulamithe! Reviens, reviens, afin que nous te regardions. -Qu''avez-vous à regarder la Sulamithe Comme une danse de deux chœurs?'),
  (22, 7, 1, 'Que tes pieds sont beaux dans ta chaussure, fille de prince! Les contours de ta hanche sont comme des colliers, Œuvre des mains d''un artiste.'),
  (22, 7, 2, 'Ton sein est une coupe arrondie, Où le vin parfumé ne manque pas; Ton corps est un tas de froment, Entouré de lis.'),
  (22, 7, 3, 'Tes deux seins sont comme deux faons, Comme les jumeaux d''une gazelle.'),
  (22, 7, 4, 'Ton cou est comme une tour d''ivoire; Tes yeux sont comme les étangs de Hesbon, Près de la porte de Bath-Rabbim; Ton nez est comme la tour du Liban, Qui regarde du côté de Damas.'),
  (22, 7, 5, 'Ta tête est élevée comme le Carmel, Et les cheveux de ta tête sont comme la pourpre; Un roi est enchaîné par des boucles!…'),
  (22, 7, 6, 'Que tu es belle, que tu es agréable, O mon amour, au milieu des délices!'),
  (22, 7, 7, 'Ta taille ressemble au palmier, Et tes seins à des grappes.'),
  (22, 7, 8, 'Je me dis: Je monterai sur le palmier, J''en saisirai les rameaux! Que tes seins soient comme les grappes de la vigne, Le parfum de ton souffle comme celui des pommes,'),
  (22, 7, 9, 'Et ta bouche comme un vin excellent,… -Qui coule aisément pour mon bien-aimé, Et glisse sur les lèvres de ceux qui s''endorment!'),
  (22, 7, 10, 'Je suis à mon bien-aimé, Et ses désirs se portent vers moi.'),
  (22, 7, 11, 'Viens, mon bien-aimé, sortons dans les champs, Demeurons dans les villages!'),
  (22, 7, 12, 'Dès le matin nous irons aux vignes, Nous verrons si la vigne pousse, si la fleur s''ouvre, Si les grenadiers fleurissent. Là je te donnerai mon amour.'),
  (22, 7, 13, 'Les mandragores répandent leur parfum, Et nous avons à nos portes tous les meilleurs fruits, Nouveaux et anciens: Mon bien-aimé, je les ai gardés pour toi.'),
  (22, 8, 1, 'Oh! Que n''es-tu mon frère, Allaité des mamelles de ma mère! Je te rencontrerais dehors, je t''embrasserais, Et l''on ne me mépriserait pas.'),
  (22, 8, 2, 'Je veux te conduire, t''amener à la maison de ma mère; Tu me donneras tes instructions, Et je te ferai boire du vin parfumé, Du moût de mes grenades.'),
  (22, 8, 3, 'Que sa main gauche soit sous ma tête, Et que sa droite m''embrasse! -'),
  (22, 8, 4, 'Je vous en conjure, filles de Jérusalem, Ne réveillez pas, ne réveillez pas l''amour, Avant qu''elle le veuille. -'),
  (22, 8, 5, 'Qui est celle qui monte du désert, Appuyée sur son bien-aimé? -Je t''ai réveillée sous le pommier; Là ta mère t''a enfantée, C''est là qu''elle t''a enfantée, qu''elle t''a donné le jour. -'),
  (22, 8, 6, 'Mets-moi comme un sceau sur ton cœur, Comme un sceau sur ton bras; Car l''amour est fort comme la mort, La jalousie est inflexible comme le séjour des morts; Ses ardeurs sont des ardeurs de feu, Une flamme de l''Éternel.'),
  (22, 8, 7, 'Les grandes eaux ne peuvent éteindre l''amour, Et les fleuves ne le submergeraient pas; Quand un homme offrirait tous les biens de sa maison contre l''amour, Il ne s''attirerait que le mépris.'),
  (22, 8, 8, 'Nous avons une petite sœur, Qui n''a point encore de mamelles; Que ferons-nous de notre sœur, Le jour où on la recherchera?'),
  (22, 8, 9, 'Si elle est un mur, Nous bâtirons sur elle des créneaux d''argent; Si elle est une porte, Nous la fermerons avec une planche de cèdre. -'),
  (22, 8, 10, 'Je suis un mur, Et mes seins sont comme des tours; J''ai été à ses yeux comme celle qui trouve la paix.'),
  (22, 8, 11, 'Salomon avait une vigne à Baal-Hamon; Il remit la vigne à des gardiens; Chacun apportait pour son fruit mille sicles d''argent.'),
  (22, 8, 12, 'Ma vigne, qui est à moi, je la garde. A toi, Salomon, les mille sicles, Et deux cents à ceux qui gardent le fruit! -'),
  (22, 8, 13, 'Habitante des jardins! Des amis prêtent l''oreille à ta voix. Daigne me la faire entendre! -'),
  (22, 8, 14, 'Fuis, mon bien-aimé! Sois semblable à la gazelle ou au faon des biches, Sur les montagnes des aromates!'),
  (23, 1, 1, 'Prophétie d''Ésaïe, fils d''Amots, sur Juda et Jérusalem, au temps d''Ozias, de Jotham, d''Achaz, d''Ézéchias, rois de Juda.'),
  (23, 1, 2, 'Cieux, écoutez! terre, prête l''oreille! Car l''Éternel parle. J''ai nourri et élevé des enfants, Mais ils se sont révoltés contre moi.'),
  (23, 1, 3, 'Le bœuf connaît son possesseur, Et l''âne la crèche de son maître: Israël ne connaît rien, Mon peuple n''a point d''intelligence.'),
  (23, 1, 4, 'Malheur à la nation pécheresse, au peuple chargé d''iniquités, A la race des méchants, aux enfants corrompus! Ils ont abandonné l''Éternel, ils ont méprisé le Saint d''Israël. Ils se sont retirés en arrière…'),
  (23, 1, 5, 'Quels châtiments nouveaux vous infliger, Quand vous multipliez vos révoltes? La tête entière est malade, Et tout le cœur est souffrant.'),
  (23, 1, 6, 'De la plante du pied jusqu''à la tête, rien n''est en bon état: Ce ne sont que blessures, contusions et plaies vives, Qui n''ont été ni pansées, ni bandées, Ni adoucies par l''huile.'),
  (23, 1, 7, 'Votre pays est dévasté, Vos villes sont consumées par le feu, Des étrangers dévorent vos campagnes sous vos yeux, Ils ravagent et détruisent, comme des barbares.'),
  (23, 1, 8, 'Et la fille de Sion est restée Comme une cabane dans une vigne, Comme une hutte dans un champ de concombres, Comme une ville épargnée.'),
  (23, 1, 9, 'Si l''Éternel des armées Ne nous eût conservé un faible reste, Nous serions comme Sodome, Nous ressemblerions à Gomorrhe.'),
  (23, 1, 10, 'Écoutez la parole de l''Éternel, chefs de Sodome! Prête l''oreille à la loi de notre Dieu, peuple de Gomorrhe!'),
  (23, 1, 11, 'Qu''ai-je affaire de la multitude de vos sacrifices? dit l''Éternel. Je suis rassasié des holocaustes de béliers et de la graisse des veaux; Je ne prends point plaisir au sang des taureaux, des brebis et des boucs.'),
  (23, 1, 12, 'Quand vous venez vous présenter devant moi, Qui vous demande de souiller mes parvis?'),
  (23, 1, 13, 'Cessez d''apporter de vaines offrandes: J''ai en horreur l''encens, Les nouvelles lunes, les sabbats et les assemblées; Je ne puis voir le crime s''associer aux solennités.'),
  (23, 1, 14, 'Mon âme hait vos nouvelles lunes et vos fêtes; Elles me sont à charge; Je suis las de les supporter.'),
  (23, 1, 15, 'Quand vous étendez vos mains, je détourne de vous mes yeux; Quand vous multipliez les prières, je n''écoute pas: Vos mains sont pleines de sang.'),
  (23, 1, 16, 'Lavez-vous, purifiez-vous, Otez de devant mes yeux la méchanceté de vos actions; Cessez de faire le mal.'),
  (23, 1, 17, 'Apprenez à faire le bien, recherchez la justice, Protégez l''opprimé; Faites droit à l''orphelin, Défendez la veuve.'),
  (23, 1, 18, 'Venez et plaidons! dit l''Éternel. Si vos péchés sont comme le cramoisi, ils deviendront blancs comme la neige; S''ils sont rouges comme la pourpre, ils deviendront comme la laine.'),
  (23, 1, 19, 'Si vous avez de la bonne volonté et si vous êtes dociles, Vous mangerez les meilleures productions du pays;'),
  (23, 1, 20, 'Mais si vous résistez et si vous êtes rebelles, Vous serez dévorés par le glaive, Car la bouche de l''Éternel a parlé.'),
  (23, 1, 21, 'Quoi donc! la cité fidèle est devenue une prostituée! Elle était remplie d''équité, la justice y habitait, Et maintenant il y a des assassins!'),
  (23, 1, 22, 'Ton argent s''est changé en scories, Ton vin a été coupé d''eau.'),
  (23, 1, 23, 'Tes chefs sont rebelles et complices des voleurs, Tous aiment les présents et courent après les récompenses; Ils ne font pas droit à l''orphelin, Et la cause de la veuve ne vient pas jusqu''à eux.'),
  (23, 1, 24, 'C''est pourquoi voici ce que dit le Seigneur, l''Éternel des armées, Le Fort d''Israël: Ah! je tirerai satisfaction de mes adversaires, Et je me vengerai de mes ennemis.'),
  (23, 1, 25, 'Je porterai ma main sur toi, Je fondrai tes scories, comme avec de la potasse, Et j''enlèverai toutes tes parcelles de plomb.'),
  (23, 1, 26, 'Je rétablirai tes juges tels qu''ils étaient autrefois, Et tes conseillers tels qu''ils étaient au commencement. Après cela, on t''appellera ville de la justice, Cité fidèle.'),
  (23, 1, 27, 'Sion sera sauvée par la droiture, Et ceux qui s''y convertiront seront sauvés par la justice.'),
  (23, 1, 28, 'Mais la ruine atteindra tous les rebelles et les pécheurs, Et ceux qui abandonnent l''Éternel périront.'),
  (23, 1, 29, 'On aura honte à cause des térébinthes auxquels vous prenez plaisir, Et vous rougirez à cause des jardins dont vous faites vos délices;'),
  (23, 1, 30, 'Car vous serez comme un térébinthe au feuillage flétri, Comme un jardin qui n''a pas d''eau.'),
  (23, 1, 31, 'L''homme fort sera comme de l''étoupe, Et son œuvre comme une étincelle; Ils brûleront l''un et l''autre ensemble, Et il n''y aura personne pour éteindre.'),
  (23, 2, 1, 'Prophétie d''Ésaïe, fils d''Amots, sur Juda et Jérusalem.'),
  (23, 2, 2, 'Il arrivera, dans la suite des temps, Que la montagne de la maison de l''Éternel Sera fondée sur le sommet des montagnes, Qu''elle s''élèvera par-dessus les collines, Et que toutes les nations y afflueront.'),
  (23, 2, 3, 'Des peuples s''y rendront en foule, et diront: Venez, et montons à la montagne de l''Éternel, A la maison du Dieu de Jacob, Afin qu''il nous enseigne ses voies, Et que nous marchions dans ses sentiers. Car de Sion sortira la loi, Et de Jérusalem la parole de l''Éternel.'),
  (23, 2, 4, 'Il sera le juge des nations, L''arbitre d''un grand nombre de peuples. De leurs glaives ils forgeront des hoyaux, Et de leurs lances des serpes: Une nation ne tirera plus l''épée contre une autre, Et l''on n''apprendra plus la guerre.'),
  (23, 2, 5, 'Maison de Jacob, Venez, et marchons à la lumière de l''Éternel!'),
  (23, 2, 6, 'Car tu as abandonné ton peuple, la maison de Jacob, Parce qu''ils sont pleins de l''Orient, Et adonnés à la magie comme les Philistins, Et parce qu''ils s''allient aux fils des étrangers.'),
  (23, 2, 7, 'Le pays est rempli d''argent et d''or, Et il y a des trésors sans fin; Le pays est rempli de chevaux, Et il y a des chars sans nombre.'),
  (23, 2, 8, 'Le pays est rempli d''idoles; Ils se prosternent devant l''ouvrage de leurs mains, Devant ce que leurs doigts ont fabriqué.'),
  (23, 2, 9, 'Les petits seront abattus, et les grands seront abaissés: Tu ne leur pardonneras point.'),
  (23, 2, 10, 'Entre dans les rochers, Et cache-toi dans la poussière, Pour éviter la terreur de l''Éternel Et l''éclat de sa majesté.'),
  (23, 2, 11, 'L''homme au regard hautain sera abaissé, Et l''orgueilleux sera humilié: L''Éternel seul sera élevé ce jour-là.'),
  (23, 2, 12, 'Car il y a un jour pour l''Éternel des armées Contre tout homme orgueilleux et hautain, Contre quiconque s''élève, afin qu''il soit abaissé;'),
  (23, 2, 13, 'Contre tous les cèdres du Liban, hauts et élevés, Et contre tous les chênes de Basan;'),
  (23, 2, 14, 'Contre toutes les hautes montagnes, Et contre toutes les collines élevées;'),
  (23, 2, 15, 'Contre toutes les hautes tours, Et contre toutes les murailles fortifiées;'),
  (23, 2, 16, 'Contre tous les navires de Tarsis, Et contre tout ce qui plaît à la vue.'),
  (23, 2, 17, 'L''homme orgueilleux sera humilié, Et le hautain sera abaissé: L''Éternel seul sera élevé ce jour-là.'),
  (23, 2, 18, 'Toutes les idoles disparaîtront.'),
  (23, 2, 19, 'On entrera dans les cavernes des rochers Et dans les profondeurs de la poussière, Pour éviter la terreur de l''Éternel et l''éclat de sa majesté, Quand il se lèvera pour effrayer la terre.'),
  (23, 2, 20, 'En ce jour, les hommes jetteront Leurs idoles d''argent et leurs idoles d''or, Qu''ils s''étaient faites pour les adorer, Aux rats et aux chauves-souris;'),
  (23, 2, 21, 'Et ils entreront dans les fentes des rochers Et dans les creux des pierres, Pour éviter la terreur de l''Éternel et l''éclat de sa majesté, Quand il se lèvera pour effrayer la terre.'),
  (23, 2, 22, 'Cessez de vous confier en l''homme, Dans les narines duquel il n''y a qu''un souffle: Car de quelle valeur est-il?'),
  (23, 3, 1, 'Le Seigneur, l''Éternel des armées, Va ôter de Jérusalem et de Juda Tout appui et toute ressource, Toute ressource de pain Et toute ressource d''eau,'),
  (23, 3, 2, 'Le héros et l''homme de guerre, Le juge et le prophète, le devin et l''ancien,'),
  (23, 3, 3, 'Le chef de cinquante et le magistrat, Le conseiller, l''artisan distingué et l''habile enchanteur.'),
  (23, 3, 4, 'Je leur donnerai des jeunes gens pour chefs, Et des enfants domineront sur eux.'),
  (23, 3, 5, 'Il y aura réciprocité d''oppression parmi le peuple; L''un opprimera l''autre, chacun son prochain; Le jeune homme attaquera le vieillard, Et l''homme de rien celui qui est honoré.'),
  (23, 3, 6, 'On ira jusqu''à saisir son frère dans la maison paternelle: Tu as un habit, sois notre chef! Prends ces ruines sous ta main! -'),
  (23, 3, 7, 'Ce jour-là même il répondra: Je ne saurais être un médecin, Et dans ma maison il n''y a ni pain ni vêtement; Ne m''établissez pas chef du peuple!'),
  (23, 3, 8, 'Jérusalem chancelle, Et Juda s''écroule, Parce que leurs paroles et leurs œuvres sont contre l''Éternel, Bravant les regards de sa majesté.'),
  (23, 3, 9, 'L''aspect de leur visage témoigne contre eux, Et, comme Sodome, ils publient leur crime, sans dissimuler. Malheur à leur âme! Car ils se préparent des maux.'),
  (23, 3, 10, 'Dites que le juste prospérera, Car il jouira du fruit de ses œuvres.'),
  (23, 3, 11, 'Malheur au méchant! il sera dans l''infortune, Car il recueillera le produit de ses mains.'),
  (23, 3, 12, 'Mon peuple a pour oppresseurs des enfants, Et des femmes dominent sur lui; Mon peuple, ceux qui te conduisent t''égarent, Et ils corrompent la voie dans laquelle tu marches.'),
  (23, 3, 13, 'L''Éternel se présente pour plaider, Il est debout pour juger les peuples.'),
  (23, 3, 14, 'L''Éternel entre en jugement Avec les anciens de son peuple et avec ses chefs: Vous avez brouté la vigne! La dépouille du pauvre est dans vos maisons!'),
  (23, 3, 15, 'De quel droit foulez-vous mon peuple, Et écrasez-vous la face des pauvres? Dit le Seigneur, l''Éternel des armées.'),
  (23, 3, 16, 'L''Éternel dit: Parce que les filles de Sion sont orgueilleuses, Et qu''elles marchent le cou tendu Et les regards effrontés, Parce qu''elles vont à petits pas, Et qu''elles font résonner les boucles de leurs pieds,'),
  (23, 3, 17, 'Le Seigneur rendra chauve le sommet de la tête des filles de Sion, L''Éternel découvrira leur nudité.'),
  (23, 3, 18, 'En ce jour, le Seigneur ôtera les boucles qui servent d''ornement à leurs pieds, Et les filets et les croissants;'),
  (23, 3, 19, 'Les pendants d''oreilles, les bracelets et les voiles;'),
  (23, 3, 20, 'Les diadèmes, les chaînettes des pieds et les ceintures, Les boîtes de senteur et les amulettes;'),
  (23, 3, 21, 'Les bagues et les anneaux du nez;'),
  (23, 3, 22, 'Les vêtements précieux et les larges tuniques, Les manteaux et les gibecières;'),
  (23, 3, 23, 'Les miroirs et les chemises fines, Les turbans et les surtouts légers.'),
  (23, 3, 24, 'Au lieu de parfum, il y aura de l''infection; Au lieu de ceinture, une corde; Au lieu de cheveux bouclés, une tête chauve; Au lieu d''un large manteau, un sac étroit; Une marque flétrissante, au lieu de beauté.'),
  (23, 3, 25, 'Tes hommes tomberont sous le glaive, Et tes héros dans le combat.'),
  (23, 3, 26, 'Les portes de Sion gémiront et seront dans le deuil; Dépouillée, elle s''assiéra par terre.'),
  (23, 4, 1, 'Et sept femmes saisiront en ce jour un seul homme, et diront: Nous mangerons notre pain, Et nous nous vêtirons de nos habits; Fais-nous seulement porter ton nom! Enlève notre opprobre!'),
  (23, 4, 2, 'En ce temps-là, le germe de l''Éternel Aura de la magnificence et de la gloire, Et le fruit du pays aura de l''éclat et de la beauté Pour les réchappés d''Israël.'),
  (23, 4, 3, 'Et les restes de Sion, les restes de Jérusalem, Seront appelés saints, Quiconque à Jérusalem sera inscrit parmi les vivants,'),
  (23, 4, 4, 'Après que le Seigneur aura lavé les ordures des filles de Sion, Et purifié Jérusalem du sang qui est au milieu d''elle, Par le souffle de la justice et par le souffle de la destruction.'),
  (23, 4, 5, 'L''Éternel établira, sur toute l''étendue de la montagne de Sion Et sur ses lieux d''assemblées, Une nuée fumante pendant le jour, Et un feu de flammes éclatantes pendant la nuit; Car tout ce qui est glorieux sera mis à couvert.'),
  (23, 4, 6, 'Il y aura un abri pour donner de l''ombre contre la chaleur du jour, Pour servir de refuge et d''asile contre l''orage et la pluie.'),
  (23, 5, 1, 'Je chanterai à mon bien-aimé Le cantique de mon bien-aimé sur sa vigne. Mon bien-aimé avait une vigne, Sur un coteau fertile.'),
  (23, 5, 2, 'Il en remua le sol, ôta les pierres, et y mit un plant délicieux; Il bâtit une tour au milieu d''elle, Et il y creusa aussi une cuve. Puis il espéra qu''elle produirait de bons raisins, Mais elle en a produit de mauvais.'),
  (23, 5, 3, 'Maintenant donc, habitants de Jérusalem et hommes de Juda, Soyez juges entre moi et ma vigne!'),
  (23, 5, 4, 'Qu''y avait-il encore à faire à ma vigne, Que je n''aie pas fait pour elle? Pourquoi, quand j''ai espéré qu''elle produirait de bons raisins, En a-t-elle produit de mauvais?'),
  (23, 5, 5, 'Je vous dirai maintenant Ce que je vais faire à ma vigne. J''en arracherai la haie, pour qu''elle soit broutée; J''en abattrai la clôture, pour qu''elle soit foulée aux pieds.'),
  (23, 5, 6, 'Je la réduirai en ruine; elle ne sera plus taillée, ni cultivée; Les ronces et les épines y croîtront; Et je donnerai mes ordres aux nuées, Afin qu''elles ne laissent plus tomber la pluie sur elle.'),
  (23, 5, 7, 'La vigne de l''Éternel des armées, c''est la maison d''Israël, Et les hommes de Juda, c''est le plant qu''il chérissait. Il avait espéré de la droiture, et voici du sang versé! De la justice, et voici des cris de détresse!'),
  (23, 5, 8, 'Malheur à ceux qui ajoutent maison à maison, Et qui joignent champ à champ, Jusqu''à ce qu''il n''y ait plus d''espace, Et qu''ils habitent seuls au milieu du pays!'),
  (23, 5, 9, 'Voici ce que m''a révélé l''Éternel des armées: Certainement, ces maisons nombreuses seront dévastées, Ces grandes et belles maisons n''auront plus d''habitants.'),
  (23, 5, 10, 'Même dix arpents de vigne ne produiront qu''un bath, Et un homer de semence ne produira qu''un épha.'),
  (23, 5, 11, 'Malheur à ceux qui de bon matin Courent après les boissons enivrantes, Et qui bien avant dans la nuit Sont échauffés par le vin!'),
  (23, 5, 12, 'La harpe et le luth, le tambourin, la flûte et le vin, animent leurs festins; Mais ils ne prennent point garde à l''œuvre de l''Éternel, Et ils ne voient point le travail de ses mains.'),
  (23, 5, 13, 'C''est pourquoi mon peuple sera soudain emmené captif; Sa noblesse mourra de faim, Et sa multitude sera desséchée par la soif.'),
  (23, 5, 14, 'C''est pourquoi le séjour des morts ouvre sa bouche, Élargit sa gueule outre mesure; Alors descendent la magnificence et la richesse de Sion, Et sa foule bruyante et joyeuse.'),
  (23, 5, 15, 'Les petits seront abattus, les grands seront humiliés, Et les regards des hautains seront abaissés.'),
  (23, 5, 16, 'L''Éternel des armées sera élevé par le jugement, Et le Dieu saint sera sanctifié par la justice.'),
  (23, 5, 17, 'Des brebis paîtront comme sur leur pâturage, Et des étrangers dévoreront les possessions ruinées des riches.'),
  (23, 5, 18, 'Malheur à ceux qui tirent l''iniquité avec les cordes du vice, Et le péché comme avec les traits d''un char,'),
  (23, 5, 19, 'Et qui disent: Qu''il hâte, qu''il accélère son œuvre, Afin que nous la voyions! Que le décret du Saint d''Israël arrive et s''exécute, Afin que nous le connaissions!'),
  (23, 5, 20, 'Malheur à ceux qui appellent le mal bien, et le bien mal, Qui changent les ténèbres en lumière, et la lumière en ténèbres, Qui changent l''amertume en douceur, et la douceur en amertume!'),
  (23, 5, 21, 'Malheur à ceux qui sont sages à leurs yeux, Et qui se croient intelligents!'),
  (23, 5, 22, 'Malheur à ceux qui ont de la bravoure pour boire du vin, Et de la vaillance pour mêler des liqueurs fortes;'),
  (23, 5, 23, 'Qui justifient le coupable pour un présent, Et enlèvent aux innocents leurs droits!'),
  (23, 5, 24, 'C''est pourquoi, comme une langue de feu dévore le chaume, Et comme la flamme consume l''herbe sèche, Ainsi leur racine sera comme de la pourriture, Et leur fleur se dissipera comme de la poussière; Car ils ont dédaigné la loi de l''Éternel des armées, Et ils ont méprisé la parole du Saint d''Israël.'),
  (23, 5, 25, 'C''est pourquoi la colère de l''Éternel s''enflamme contre son peuple, Il étend sa main sur lui, et il le frappe; Les montagnes s''ébranlent; Et les cadavres sont comme des balayures au milieu des rues. Malgré tout cela, sa colère ne s''apaise point, Et sa main est encore étendue.'),
  (23, 5, 26, 'Il élève une bannière pour les peuples lointains, Et il en siffle un des extrémités de la terre: Et voici, il arrive avec promptitude et légèreté.'),
  (23, 5, 27, 'Nul n''est fatigué, nul ne chancelle de lassitude, Personne ne sommeille, ni ne dort; Aucun n''a la ceinture de ses reins détachée, Ni la courroie de ses souliers rompue.'),
  (23, 5, 28, 'Ses flèches sont aiguës, Et tous ses arcs tendus; Les sabots de ses chevaux ressemblent à des cailloux, Et les roues de ses chars à un tourbillon.'),
  (23, 5, 29, 'Son rugissement est comme celui d''une lionne; Il rugit comme des lionceaux, il gronde, et saisit la proie, Il l''emporte, et personne ne vient au secours.'),
  (23, 5, 30, 'En ce jour, il y aura près de lui un mugissement, Comme celui d''une tempête sur mer; En regardant la terre, on ne verra que ténèbres, Avec des alternatives d''angoisse et d''espérance; Au ciel, l''obscurité régnera.'),
  (23, 6, 1, 'L''année de la mort du roi Ozias, je vis le Seigneur assis sur un trône très élevé, et les pans de sa robe remplissaient le temple.'),
  (23, 6, 2, 'Des séraphins se tenaient au-dessus de lui; ils avaient chacun six ailes; deux dont ils se couvraient la face, deux dont ils se couvraient les pieds, et deux dont ils se servaient pour voler.'),
  (23, 6, 3, 'Ils criaient l''un à l''autre, et disaient: Saint, saint, saint est l''Éternel des armées! toute la terre est pleine de sa gloire!'),
  (23, 6, 4, 'Les portes furent ébranlées dans leurs fondements par la voix qui retentissait, et la maison se remplit de fumée.'),
  (23, 6, 5, 'Alors je dis: Malheur à moi! je suis perdu, car je suis un homme dont les lèvres sont impures, j''habite au milieu d''un peuple dont les lèvres sont impures, et mes yeux ont vu le Roi, l''Éternel des armées.'),
  (23, 6, 6, 'Mais l''un des séraphins vola vers moi, tenant à la main une pierre ardente, qu''il avait prise sur l''autel avec des pincettes.'),
  (23, 6, 7, 'Il en toucha ma bouche, et dit: Ceci a touché tes lèvres; ton iniquité est enlevée, et ton péché est expié.'),
  (23, 6, 8, 'J''entendis la voix du Seigneur, disant: Qui enverrai-je, et qui marchera pour nous? Je répondis: Me voici, envoie-moi.'),
  (23, 6, 9, 'Il dit alors: Va, et dis à ce peuple: Vous entendrez, et vous ne comprendrez point; Vous verrez, et vous ne saisirez point.'),
  (23, 6, 10, 'Rends insensible le cœur de ce peuple, Endurcis ses oreilles, et bouche-lui les yeux, Pour qu''il ne voie point de ses yeux, n''entende point de ses oreilles, Ne comprenne point de son cœur, Ne se convertisse point et ne soit point guéri.'),
  (23, 6, 11, 'Je dis: Jusqu''à quand, Seigneur? Et il répondit: Jusqu''à ce que les villes soient dévastées Et privées d''habitants; Jusqu''à ce qu''il n''y ait personne dans les maisons, Et que le pays soit ravagé par la solitude;'),
  (23, 6, 12, 'Jusqu''à ce que l''Éternel ait éloigné les hommes, Et que le pays devienne un immense désert,'),
  (23, 6, 13, 'Et s''il y reste encore un dixième des habitants, Ils seront à leur tour anéantis. Mais, comme le térébinthe et le chêne Conservent leur tronc quand ils sont abattus, Une sainte postérité renaîtra de ce peuple.'),
  (23, 7, 1, 'Il arriva, du temps d''Achaz, fils de Jotham, fils d''Ozias, roi de Juda, que Retsin, roi de Syrie, monta avec Pékach, fils de Remalia, roi d''Israël, contre Jérusalem, pour l''assiéger; mais il ne put l''assiéger.'),
  (23, 7, 2, 'On vint dire à la maison de David: Les Syriens sont campés en Éphraïm. Et le cœur d''Achaz et le cœur de son peuple furent agités, comme les arbres de la forêt sont agités par le vent.'),
  (23, 7, 3, 'Alors l''Éternel dit à Ésaïe: Va à la rencontre d''Achaz, toi et Schear-Jaschub, ton fils, vers l''extrémité de l''aqueduc de l''étang supérieur, sur la route du champ du foulon.'),
  (23, 7, 4, 'Et dis-lui: Sois tranquille, ne crains rien, Et que ton cœur ne s''alarme pas, Devant ces deux bouts de tisons fumants, Devant la colère de Retsin et de la Syrie, et du fils de Remalia,'),
  (23, 7, 5, 'De ce que la Syrie médite du mal contre toi, De ce qu''Éphraïm et le fils de Remalia disent:'),
  (23, 7, 6, 'Montons contre Juda, assiégeons la ville, Et battons-la en brèche, Et proclamons-y pour roi le fils de Tabeel.'),
  (23, 7, 7, 'Ainsi parle le Seigneur, l''Éternel: Cela n''arrivera pas, cela n''aura pas lieu.'),
  (23, 7, 8, 'Car Damas est la tête de la Syrie, Et Retsin est la tête de Damas. Encore soixante-cinq ans, Éphraïm ne sera plus un peuple.'),
  (23, 7, 9, 'La Samarie est la tête d''Éphraïm, Et le fils de Remalia est la tête de la Samarie. Si vous ne croyez pas, Vous ne subsisterez pas.'),
  (23, 7, 10, 'L''Éternel parla de nouveau à Achaz, et lui dit:'),
  (23, 7, 11, 'Demande en ta faveur un signe à l''Éternel, ton Dieu; demande-le, soit dans les lieux bas, soit dans les lieux élevés.'),
  (23, 7, 12, 'Achaz répondit: Je ne demanderai rien, je ne tenterai pas l''Éternel.'),
  (23, 7, 13, 'Ésaïe dit alors: Écoutez donc, maison de David! Est-ce trop peu pour vous de lasser la patience des hommes, Que vous lassiez encore celle de mon Dieu?'),
  (23, 7, 14, 'C''est pourquoi le Seigneur lui-même vous donnera un signe, Voici, la jeune fille deviendra enceinte, elle enfantera un fils, Et elle lui donnera le nom d''Emmanuel.'),
  (23, 7, 15, 'Il mangera de la crème et du miel, Jusqu''à ce qu''il sache rejeter le mal et choisir le bien.'),
  (23, 7, 16, 'Mais avant que l''enfant sache rejeter le mal et choisir le bien, Le pays dont tu crains les deux rois sera abandonné.'),
  (23, 7, 17, 'L''Éternel fera venir sur toi, Sur ton peuple et sur la maison de ton père, Des jours tels qu''il n''y en a point eu Depuis le jour où Éphraïm s''est séparé de Juda (Le roi d''Assyrie).'),
  (23, 7, 18, 'En ce jour-là, l''Éternel sifflera les mouches Qui sont à l''extrémité des canaux de l''Égypte, Et les abeilles qui sont au pays d''Assyrie;'),
  (23, 7, 19, 'Elles viendront, et se poseront toutes dans les vallons désolés, Et dans les fentes des rochers, Sur tous les buissons, Et sur tous les pâturages.'),
  (23, 7, 20, 'En ce jour-là, le Seigneur rasera, avec un rasoir pris à louage Au delà du fleuve, Avec le roi d''Assyrie, La tête et le poil des pieds; Il enlèvera aussi la barbe.'),
  (23, 7, 21, 'En ce jour-là, Chacun entretiendra une jeune vache et deux brebis;'),
  (23, 7, 22, 'Et il y aura une telle abondance de lait Qu''on mangera de la crème, Car c''est de crème et de miel que se nourriront Tous ceux qui seront restés dans le pays.'),
  (23, 7, 23, 'En ce jour-là, Tout lieu qui contiendra mille ceps de vigne, Valant mille sicles d''argent, Sera livré aux ronces et aux épines:'),
  (23, 7, 24, 'On y entrera avec les flèches et avec l''arc, Car tout le pays ne sera que ronces et épines.'),
  (23, 7, 25, 'Et toutes les montagnes que l''on cultivait avec la bêche Ne seront plus fréquentées, par crainte des ronces et des épines: On y lâchera le bœuf, et la brebis en foulera le sol.'),
  (23, 8, 1, 'L''Éternel me dit: Prends une grande table, et écris dessus, d''une manière intelligible: Qu''on se hâte de piller, qu''on se précipite sur le butin.'),
  (23, 8, 2, 'Je pris avec moi des témoins dignes de foi, le sacrificateur Urie, et Zacharie, fils de Bérékia.'),
  (23, 8, 3, 'Je m''étais approché de la prophétesse; elle conçut, et elle enfanta un fils. L''Éternel me dit: Donne-lui pour nom Maher-Schalal-Chasch-Baz.'),
  (23, 8, 4, 'Car, avant que l''enfant sache dire: Mon père! ma mère! on emportera devant le roi d''Assyrie les richesses de Damas et le butin de Samarie.'),
  (23, 8, 5, 'L''Éternel me parla encore, et me dit:'),
  (23, 8, 6, 'Parce que ce peuple a méprisé les eaux de Siloé qui coulent doucement Et qu''il s''est réjoui au sujet de Retsin et du fils de Remalia,'),
  (23, 8, 7, 'Voici, le Seigneur va faire monter contre eux Les puissantes et grandes eaux du fleuve (Le roi d''Assyrie et toute sa gloire); Il s''élèvera partout au-dessus de son lit, Et il se répandra sur toutes ses rives;'),
  (23, 8, 8, 'Il pénétrera dans Juda, il débordera et inondera, Il atteindra jusqu''au cou. Le déploiement de ses ailes Remplira l''étendue de ton pays, ô Emmanuel!'),
  (23, 8, 9, 'Poussez des cris de guerre, peuples! et vous serez brisés; Prêtez l''oreille, vous tous qui habitez au loin! Préparez-vous au combat, et vous serez brisés; Préparez-vous au combat, et vous serez brisés.'),
  (23, 8, 10, 'Formez des projets, et ils seront anéantis; Donnez des ordres, et ils seront sans effet: Car Dieu est avec nous.'),
  (23, 8, 11, 'Ainsi m''a parlé l''Éternel, quand sa main me saisit, Et qu''il m''avertit de ne pas marcher dans la voie de ce peuple:'),
  (23, 8, 12, 'N''appelez pas conjuration tout ce que ce peuple appelle conjuration; Ne craignez pas ce qu''il craint, et ne soyez pas effrayés.'),
  (23, 8, 13, 'C''est l''Éternel des armées que vous devez sanctifier, C''est lui que vous devez craindre et redouter.'),
  (23, 8, 14, 'Et il sera un sanctuaire, Mais aussi une pierre d''achoppement, Un rocher de scandale pour les deux maisons d''Israël, Un filet et un piège Pour les habitants de Jérusalem.'),
  (23, 8, 15, 'Plusieurs trébucheront; Ils tomberont et se briseront, Ils seront enlacés et pris.'),
  (23, 8, 16, 'Enveloppe cet oracle, Scelle cette révélation, parmi mes disciples. -'),
  (23, 8, 17, 'J''espère en l''Éternel, Qui cache sa face à la maison de Jacob; Je place en lui ma confiance.'),
  (23, 8, 18, 'Voici, moi et les enfants que l''Éternel m''a donnés, Nous sommes des signes et des présages en Israël, De la part de l''Éternel des armées, Qui habite sur la montagne de Sion.'),
  (23, 8, 19, 'Si l''on vous dit: Consultez ceux qui évoquent les morts et ceux qui prédisent l''avenir, Qui poussent des sifflements et des soupirs, Répondez: Un peuple ne consultera-t-il pas son Dieu? S''adressera-t-il aux morts en faveur des vivants?'),
  (23, 8, 20, 'A la loi et au témoignage! Si l''on ne parle pas ainsi, Il n''y aura point d''aurore pour le peuple.'),
  (23, 8, 21, 'Il sera errant dans le pays, accablé et affamé; Et, quand il aura faim, il s''irritera, Maudira son roi et son Dieu, Et tournera les yeux en haut;'),
  (23, 8, 22, 'Puis il regardera vers la terre, Et voici, il n''y aura que détresse, obscurité et de sombres angoisses: Il sera repoussé dans d''épaisses ténèbres.'),
  (23, 9, 1, 'Mais les ténèbres ne régneront pas toujours Sur la terre où il y a maintenant des angoisses: Si les temps passés ont couvert d''opprobre Le pays de Zabulon et le pays de Nephthali, Les temps à venir couvriront de gloire La contrée voisine de la mer, au delà du Jourdain, Le territoire des Gentils.'),
  (23, 9, 2, 'Le peuple qui marchait dans les ténèbres Voit une grande lumière; Sur ceux qui habitaient le pays de l''ombre de la mort Une lumière resplendit.'),
  (23, 9, 3, 'Tu rends le peuple nombreux, Tu lui accordes de grandes joies; Il se réjouit devant toi, comme on se réjouit à la moisson, Comme on pousse des cris d''allégresse au partage du butin.'),
  (23, 9, 4, 'Car le joug qui pesait sur lui, Le bâton qui frappait son dos, La verge de celui qui l''opprimait, Tu les brises, comme à la journée de Madian.'),
  (23, 9, 5, 'Car toute chaussure qu''on porte dans la mêlée, Et tout vêtement guerrier roulé dans le sang, Seront livrés aux flammes, Pour être dévorés par le feu.'),
  (23, 9, 6, 'Car un enfant nous est né, un fils nous est donné, Et la domination reposera sur son épaule; On l''appellera Admirable, Conseiller, Dieu puissant, Père éternel, Prince de la paix.'),
  (23, 9, 7, 'Donner à l''empire de l''accroissement, Et une paix sans fin au trône de David et à son royaume, L''affermir et le soutenir par le droit et par la justice, Dès maintenant et à toujours: Voilà ce que fera le zèle de l''Éternel des armées.'),
  (23, 9, 8, 'Le Seigneur envoie une parole à Jacob: Elle tombe sur Israël.'),
  (23, 9, 9, 'Tout le peuple en aura connaissance, Éphraïm et les habitants de Samarie, Qui disent avec orgueil et fierté:'),
  (23, 9, 10, 'Des briques sont tombées, Nous bâtirons en pierres de taille; Des sycomores ont été coupés, Nous les remplacerons par des cèdres.'),
  (23, 9, 11, 'L''Éternel élèvera contre eux les ennemis de Retsin, Et il armera leurs ennemis,'),
  (23, 9, 12, 'Les Syriens à l''orient, les Philistins à l''occident; Et ils dévoreront Israël à pleine bouche. Malgré tout cela, sa colère ne s''apaise point, Et sa main est encore étendue.'),
  (23, 9, 13, 'Le peuple ne revient pas à celui qui le frappe, Et il ne cherche pas l''Éternel des armées.'),
  (23, 9, 14, 'Aussi l''Éternel arrachera d''Israël la tête et la queue, La branche de palmier et le roseau, En un seul jour.'),
  (23, 9, 15, '(L''ancien et le magistrat, c''est la tête, Et le prophète qui enseigne le mensonge, c''est la queue).'),
  (23, 9, 16, 'Ceux qui conduisent ce peuple l''égarent, Et ceux qui se laissent conduire se perdent.'),
  (23, 9, 17, 'C''est pourquoi le Seigneur ne saurait se réjouir de leurs jeunes hommes, Ni avoir pitié de leurs orphelins et de leurs veuves; Car tous sont des impies et des méchants, Et toutes les bouches profèrent des infamies. Malgré tout cela, sa colère ne s''apaise point, Et sa main est encore étendue.'),
  (23, 9, 18, 'Car la méchanceté consume comme un feu, Qui dévore ronces et épines; Il embrase l''épaisseur de la forêt, D''où s''élèvent des colonnes de fumée.'),
  (23, 9, 19, 'Par la colère de l''Éternel des armées le pays est embrasé, Et le peuple est comme la proie du feu; Nul n''épargne son frère.'),
  (23, 9, 20, 'On pille à droite, et l''on a faim; On dévore à gauche, et l''on n''est pas rassasié; Chacun dévore la chair de son bras.'),
  (23, 9, 21, 'Manassé dévore Éphraïm, Éphraïm Manassé, Et ensemble ils fondent sur Juda. Malgré tout cela, sa colère ne s''apaise point, Et sa main est encore étendue.'),
  (23, 10, 1, 'Malheur à ceux qui prononcent des ordonnances iniques, Et à ceux qui transcrivent des arrêts injustes,'),
  (23, 10, 2, 'Pour refuser justice aux pauvres, Et ravir leur droit aux malheureux de mon peuple, Pour faire des veuves leur proie, Et des orphelins leur butin!'),
  (23, 10, 3, 'Que ferez-vous au jour du châtiment, Et de la ruine qui du lointain fondra sur vous? Vers qui fuirez-vous, pour avoir du secours, Et où laisserez-vous votre gloire?'),
  (23, 10, 4, 'Les uns seront courbés parmi les captifs, Les autres tomberont parmi les morts. Malgré tout cela, sa colère ne s''apaise point, Et sa main est encore étendue.'),
  (23, 10, 5, 'Malheur à l''Assyrien, verge de ma colère! La verge dans sa main, c''est l''instrument de ma fureur.'),
  (23, 10, 6, 'Je l''ai lâché contre une nation impie, Je l''ai fait marcher contre le peuple de mon courroux, Pour qu''il se livre au pillage et fasse du butin, Pour qu''il le foule aux pieds comme la boue des rues.'),
  (23, 10, 7, 'Mais il n''en juge pas ainsi, Et ce n''est pas là la pensée de son cœur; Il ne songe qu''à détruire, Qu''à exterminer les nations en foule.'),
  (23, 10, 8, 'Car il dit: Mes princes ne sont-ils pas autant de rois?'),
  (23, 10, 9, 'N''en a-t-il pas été de Calno comme de Carkemisch? N''en a-t-il pas été de Hamath comme d''Arpad? N''en a-t-il pas été de Samarie comme de Damas?'),
  (23, 10, 10, 'De même que ma main a atteint les royaumes des idoles, Où il y avait plus d''images qu''à Jérusalem et à Samarie,'),
  (23, 10, 11, 'Ce que j''ai fait à Samarie et à ses idoles, Ne le ferai-je pas à Jérusalem et à ses images?'),
  (23, 10, 12, 'Mais, quand le Seigneur aura accompli toute son œuvre Sur la montagne de Sion et à Jérusalem, Je punirai le roi d''Assyrie pour le fruit de son cœur orgueilleux, Et pour l''arrogance de ses regards hautains.'),
  (23, 10, 13, 'Car il dit: C''est par la force de ma main que j''ai agi, C''est par ma sagesse, car je suis intelligent; J''ai reculé les limites des peuples, et pillé leurs trésors, Et, comme un héros, j''ai renversé ceux qui siégeaient sur des trônes;'),
  (23, 10, 14, 'J''ai mis la main sur les richesses des peuples, comme sur un nid, Et, comme on ramasse des œufs abandonnés, J''ai ramassé toute la terre: Nul n''a remué l''aile, Ni ouvert le bec, ni poussé un cri. -'),
  (23, 10, 15, 'La hache se glorifie-t-elle envers celui qui s''en sert? Ou la scie est-elle arrogante envers celui qui la manie? Comme si la verge faisait mouvoir celui qui la lève, Comme si le bâton soulevait celui qui n''est pas du bois!'),
  (23, 10, 16, 'C''est pourquoi le Seigneur, le Seigneur des armées, enverra Le dépérissement parmi ses robustes guerriers; Et, sous sa magnificence, éclatera un embrasement, Comme l''embrasement d''un feu.'),
  (23, 10, 17, 'La lumière d''Israël deviendra un feu, Et son Saint une flamme, Qui consumera et dévorera ses épines et ses ronces, En un seul jour;'),
  (23, 10, 18, 'Qui consumera, corps et âme, La magnificence de sa forêt et de ses campagnes. Il en sera comme d''un malade, qui tombe en défaillance.'),
  (23, 10, 19, 'Le reste des arbres de sa forêt pourra être compté, Et un enfant en écrirait le nombre.'),
  (23, 10, 20, 'En ce jour-là, Le reste d''Israël et les réchappés de la maison de Jacob, Cesseront de s''appuyer sur celui qui les frappait; Ils s''appuieront avec confiance sur l''Éternel, le Saint d''Israël.'),
  (23, 10, 21, 'Le reste reviendra, le reste de Jacob, Au Dieu puissant.'),
  (23, 10, 22, 'Quand ton peuple, ô Israël, serait comme le sable de la mer, Un reste seulement reviendra; La destruction est résolue, elle fera déborder la justice.'),
  (23, 10, 23, 'Et cette destruction qui a été résolue, Le Seigneur, l''Éternel des armées, l''accomplira dans tout le pays.'),
  (23, 10, 24, 'Cependant, ainsi parle le Seigneur, l''Éternel des armées: O mon peuple, qui habites en Sion, ne crains pas l''Assyrien! Il te frappe de la verge, Et il lève son bâton sur toi, comme faisaient les Égyptiens.'),
  (23, 10, 25, 'Mais, encore un peu de temps, Et le châtiment cessera, Puis ma colère se tournera contre lui pour l''anéantir.'),
  (23, 10, 26, 'L''Éternel des armées agitera le fouet contre lui, Comme il frappa Madian au rocher d''Oreb; Et, de même qu''il leva son bâton sur la mer, Il le lèvera encore, comme en Égypte.'),
  (23, 10, 27, 'En ce jour, son fardeau sera ôté de dessus ton épaule, Et son joug de dessus ton cou; Et la graisse fera éclater le joug.'),
  (23, 10, 28, 'Il marche sur Ajjath, traverse Migron, Laisse ses bagages à Micmasch.'),
  (23, 10, 29, 'Ils passent le défilé, Ils couchent à Guéba; Rama tremble, Guibea de Saül prend la fuite.'),
  (23, 10, 30, 'Fais éclater ta voix, fille de Gallim! Prends garde, Laïs! malheur à toi, Anathoth!'),
  (23, 10, 31, 'Madména se disperse, Les habitants de Guébim sont en fuite.'),
  (23, 10, 32, 'Encore un jour de halte à Nob, Et il menace de sa main la montagne de la fille de Sion, La colline de Jérusalem.'),
  (23, 10, 33, 'Voici, le Seigneur, l''Éternel des armées, Brise les rameaux avec violence: Les plus grands sont coupés, Les plus élevés sont abattus.'),
  (23, 10, 34, 'Il renverse avec le fer les taillis de la forêt, Et le Liban tombe sous le Puissant.'),
  (23, 11, 1, 'Puis un rameau sortira du tronc d''Isaï, Et un rejeton naîtra de ses racines.'),
  (23, 11, 2, 'L''Esprit de l''Éternel reposera sur lui: Esprit de sagesse et d''intelligence, Esprit de conseil et de force, Esprit de connaissance et de crainte de l''Éternel.'),
  (23, 11, 3, 'Il respirera la crainte de l''Éternel; Il ne jugera point sur l''apparence, Il ne prononcera point sur un ouï-dire.'),
  (23, 11, 4, 'Mais il jugera les pauvres avec équité, Et il prononcera avec droiture sur les malheureux de la terre; Il frappera la terre de sa parole comme d''une verge, Et du souffle de ses lèvres il fera mourir le méchant.'),
  (23, 11, 5, 'La justice sera la ceinture de ses flancs, Et la fidélité la ceinture de ses reins.'),
  (23, 11, 6, 'Le loup habitera avec l''agneau, Et la panthère se couchera avec le chevreau; Le veau, le lionceau, et le bétail qu''on engraisse, seront ensemble, Et un petit enfant les conduira.'),
  (23, 11, 7, 'La vache et l''ourse auront un même pâturage, Leurs petits un même gîte; Et le lion, comme le bœuf, mangera de la paille.'),
  (23, 11, 8, 'Le nourrisson s''ébattra sur l''antre de la vipère, Et l''enfant sevré mettra sa main dans la caverne du basilic.'),
  (23, 11, 9, 'Il ne se fera ni tort ni dommage Sur toute ma montagne sainte; Car la terre sera remplie de la connaissance de l''Éternel, Comme le fond de la mer par les eaux qui le couvrent.'),
  (23, 11, 10, 'En ce jour, le rejeton d''Isaï Sera là comme une bannière pour les peuples; Les nations se tourneront vers lui, Et la gloire sera sa demeure.'),
  (23, 11, 11, 'Dans ce même temps, le Seigneur étendra une seconde fois sa main, Pour racheter le reste de son peuple, Dispersé en Assyrie et en Égypte, A Pathros et en Éthiopie, A Élam, à Schinear et à Hamath, Et dans les îles de la mer.'),
  (23, 11, 12, 'Il élèvera une bannière pour les nations, Il rassemblera les exilés d''Israël, Et il recueillera les dispersés de Juda, Des quatre extrémités de la terre.'),
  (23, 11, 13, 'La jalousie d''Éphraïm disparaîtra, Et ses ennemis en Juda seront anéantis; Éphraïm ne sera plus jaloux de Juda, Et Juda ne sera plus hostile à Éphraïm.'),
  (23, 11, 14, 'Ils voleront sur l''épaule des Philistins à l''occident, Ils pilleront ensemble les fils de l''Orient; Édom et Moab seront la proie de leurs mains, Et les fils d''Ammon leur seront assujettis.'),
  (23, 11, 15, 'L''Éternel desséchera la langue de la mer d''Égypte, Et il lèvera sa main sur le fleuve, en soufflant avec violence: Il le partagera en sept canaux, Et on le traversera avec des souliers.'),
  (23, 11, 16, 'Et il y aura une route pour le reste de son peuple, Qui sera échappé de l''Assyrie, Comme il y en eut une pour Israël, Le jour où il sortit du pays d''Égypte.'),
  (23, 12, 1, 'Tu diras en ce jour-là: Je te loue, ô Éternel! Car tu as été irrité contre moi, Ta colère s''est apaisée, et tu m''as consolé.'),
  (23, 12, 2, 'Voici, Dieu est ma délivrance, Je serai plein de confiance, et je ne craindrai rien; Car l''Éternel, l''Éternel est ma force et le sujet de mes louanges; C''est lui qui m''a sauvé.'),
  (23, 12, 3, 'Vous puiserez de l''eau avec joie Aux sources du salut,'),
  (23, 12, 4, 'Et vous direz en ce jour-là: Louez l''Éternel, invoquez son nom, Publiez ses œuvres parmi les peuples, Rappelez la grandeur de son nom!'),
  (23, 12, 5, 'Célébrez l''Éternel, car il a fait des choses magnifiques: Qu''elles soient connues par toute la terre!'),
  (23, 12, 6, 'Pousse des cris de joie et d''allégresse, habitant de Sion! Car il est grand au milieu de toi, le Saint d''Israël.'),
  (23, 13, 1, 'Oracle sur Babylone, révélé à Ésaïe, fils d''Amots.'),
  (23, 13, 2, 'Sur une montagne nue dressez une bannière, Élevez la voix vers eux, Faites des signes avec la main, Et qu''ils franchissent les portes des tyrans!'),
  (23, 13, 3, 'J''ai donné des ordres à ma sainte milice, J''ai appelé les héros de ma colère, Ceux qui se réjouissent de ma grandeur.'),
  (23, 13, 4, 'On entend une rumeur sur les montagnes, Comme celle d''un peuple nombreux; On entend un tumulte de royaumes, de nations rassemblées: L''Éternel des armées passe en revue l''armée qui va combattre.'),
  (23, 13, 5, 'Ils viennent d''un pays lointain, De l''extrémité des cieux: L''Éternel et les instruments de sa colère Vont détruire toute la contrée.'),
  (23, 13, 6, 'Gémissez, car le jour de l''Éternel est proche: Il vient comme un ravage du Tout-Puissant.'),
  (23, 13, 7, 'C''est pourquoi toutes les mains s''affaiblissent, Et tout cœur d''homme est abattu.'),
  (23, 13, 8, 'Ils sont frappés d''épouvante; Les spasmes et les douleurs les saisissent; Ils se tordent comme une femme en travail; Ils se regardent les uns les autres avec stupeur; Leurs visages sont enflammés.'),
  (23, 13, 9, 'Voici, le jour de l''Éternel arrive, Jour cruel, jour de colère et d''ardente fureur, Qui réduira la terre en solitude, Et en exterminera les pécheurs.'),
  (23, 13, 10, 'Car les étoiles des cieux et leurs astres Ne feront plus briller leur lumière, Le soleil s''obscurcira dès son lever, Et la lune ne fera plus luire sa clarté.'),
  (23, 13, 11, 'Je punirai le monde pour sa malice, Et les méchants pour leurs iniquités; Je ferai cesser l''orgueil des hautains, Et j''abattrai l''arrogance des tyrans.'),
  (23, 13, 12, 'Je rendrai les hommes plus rares que l''or fin, Je les rendrai plus rares que l''or d''Ophir.'),
  (23, 13, 13, 'C''est pourquoi j''ébranlerai les cieux, Et la terre sera secouée sur sa base, Par la colère de l''Éternel des armées, Au jour de son ardente fureur.'),
  (23, 13, 14, 'Alors, comme une gazelle effarouchée, Comme un troupeau sans berger, Chacun se tournera vers son peuple, Chacun fuira vers son pays;'),
  (23, 13, 15, 'Tous ceux qu''on trouvera seront percés, Et tous ceux qu''on saisira tomberont par l''épée.'),
  (23, 13, 16, 'Leurs enfants seront écrasés sous leurs yeux, Leurs maisons seront pillées, et leurs femmes violées.'),
  (23, 13, 17, 'Voici, j''excite contre eux les Mèdes, Qui ne font point cas de l''argent, Et qui ne convoitent point l''or.'),
  (23, 13, 18, 'De leurs arcs ils abattront les jeunes gens, Et ils seront sans pitié pour le fruit des entrailles: Leur œil n''épargnera point les enfants.'),
  (23, 13, 19, 'Et Babylone, l''ornement des royaumes, La fière parure des Chaldéens, Sera comme Sodome et Gomorrhe, que Dieu détruisit.'),
  (23, 13, 20, 'Elle ne sera plus jamais habitée, Elle ne sera plus jamais peuplée; L''Arabe n''y dressera point sa tente, Et les bergers n''y parqueront point leurs troupeaux.'),
  (23, 13, 21, 'Les animaux du désert y prendront leur gîte, Les hiboux rempliront ses maisons, Les autruches en feront leur demeure Et les boucs y sauteront.'),
  (23, 13, 22, 'Les chacals hurleront dans ses palais, Et les chiens sauvages dans ses maisons de plaisance. Son temps est près d''arriver, Et ses jours ne se prolongeront pas.'),
  (23, 14, 1, 'Car l''Éternel aura pitié de Jacob, Il choisira encore Israël, Et il les rétablira dans leur pays; Les étrangers se joindront à eux, Et ils s''uniront à la maison de Jacob.'),
  (23, 14, 2, 'Les peuples les prendront, et les ramèneront à leur demeure, Et la maison d''Israël les possédera dans le pays de l''Éternel, Comme serviteurs et comme servantes; Ils retiendront captifs ceux qui les avaient faits captifs, Et ils domineront sur leurs oppresseurs.'),
  (23, 14, 3, 'Et quand l''Éternel t''aura donné du repos, Après tes fatigues et tes agitations, Et après la dure servitude qui te fut imposée,'),
  (23, 14, 4, 'Alors tu prononceras ce chant sur le roi de Babylone, Et tu diras: Eh quoi! le tyran n''est plus! L''oppression a cessé!'),
  (23, 14, 5, 'L''Éternel a brisé le bâton des méchants, La verge des dominateurs.'),
  (23, 14, 6, 'Celui qui dans sa fureur frappait les peuples, Par des coups sans relâche, Celui qui dans sa colère subjuguait les nations, Est poursuivi sans ménagement.'),
  (23, 14, 7, 'Toute la terre jouit du repos et de la paix; On éclate en chants d''allégresse,'),
  (23, 14, 8, 'Les cyprès même, les cèdres du Liban, se réjouissent de ta chute: Depuis que tu es tombé, personne ne monte pour nous abattre.'),
  (23, 14, 9, 'Le séjour des morts s''émeut jusque dans ses profondeurs, Pour t''accueillir à ton arrivée; Il réveille devant toi les ombres, tous les grands de la terre, Il fait lever de leurs trônes tous les rois des nations.'),
  (23, 14, 10, 'Tous prennent la parole pour te dire: Toi aussi, tu es sans force comme nous, Tu es devenu semblable à nous!'),
  (23, 14, 11, 'Ta magnificence est descendue dans le séjour des morts, Avec le son de tes luths; Sous toi est une couche de vers, Et les vers sont ta couverture.'),
  (23, 14, 12, 'Te voilà tombé du ciel, Astre brillant, fils de l''aurore! Tu es abattu à terre, Toi, le vainqueur des nations!'),
  (23, 14, 13, 'Tu disais en ton cœur: Je monterai au ciel, J''élèverai mon trône au-dessus des étoiles de Dieu; Je m''assiérai sur la montagne de l''assemblée, A l''extrémité du septentrion;'),
  (23, 14, 14, 'Je monterai sur le sommet des nues, Je serai semblable au Très-Haut.'),
  (23, 14, 15, 'Mais tu as été précipité dans le séjour des morts, Dans les profondeurs de la fosse.'),
  (23, 14, 16, 'Ceux qui te voient fixent sur toi leurs regards, Ils te considèrent attentivement: Est-ce là cet homme qui faisait trembler la terre, Qui ébranlait les royaumes,'),
  (23, 14, 17, 'Qui réduisait le monde en désert, Qui ravageait les villes, Et ne relâchait point ses prisonniers?'),
  (23, 14, 18, 'Tous les rois des nations, oui, tous, Reposent avec honneur, chacun dans son tombeau.'),
  (23, 14, 19, 'Mais toi, tu as été jeté loin de ton sépulcre, Comme un rameau qu''on dédaigne, Comme une dépouille de gens tués à coups d''épée, Et précipités sur les pierres d''une fosse, Comme un cadavre foulé aux pieds.'),
  (23, 14, 20, 'Tu n''es pas réuni à eux dans le sépulcre, Car tu as détruit ton pays, tu as fait périr ton peuple: On ne parlera plus jamais de la race des méchants.'),
  (23, 14, 21, 'Préparez le massacre des fils, A cause de l''iniquité de leurs pères! Qu''ils ne se relèvent pas pour conquérir la terre, Et remplir le monde d''ennemis! -'),
  (23, 14, 22, 'Je me lèverai contre eux, Dit l''Éternel des armées; J''anéantirai le nom et la trace de Babylone, Ses descendants et sa postérité, dit l''Éternel.'),
  (23, 14, 23, 'J''en ferai le gîte du hérisson et un marécage, Et je la balaierai avec le balai de la destruction, Dit l''Éternel des armées.'),
  (23, 14, 24, 'L''Éternel des armées l''a juré, en disant: Oui, ce que j''ai décidé arrivera, Ce que j''ai résolu s''accomplira.'),
  (23, 14, 25, 'Je briserai l''Assyrien dans mon pays, Je le foulerai aux pieds sur mes montagnes; Et son joug leur sera ôté, Et son fardeau sera ôté de leurs épaules.'),
  (23, 14, 26, 'Voilà la résolution prise contre toute la terre, Voilà la main étendue sur toutes les nations.'),
  (23, 14, 27, 'L''Éternel des armées a pris cette résolution: qui s''y opposera? Sa main est étendue: qui la détournera?'),
  (23, 14, 28, 'L''année de la mort du roi Achaz, cet oracle fut prononcé:'),
  (23, 14, 29, 'Ne te réjouis pas, pays des Philistins, De ce que la verge qui te frappait est brisée! Car de la racine du serpent sortira un basilic, Et son fruit sera un dragon volant.'),
  (23, 14, 30, 'Alors les plus pauvres pourront paître, Et les malheureux reposer en sécurité; Mais je ferai mourir ta racine par la faim, Et ce qui restera de toi sera tué.'),
  (23, 14, 31, 'Porte, gémis! ville, lamente-toi! Tremble, pays tout entier des Philistins! Car du nord vient une fumée, Et les rangs de l''ennemi sont serrés. -'),
  (23, 14, 32, 'Et que répondra-t-on aux envoyés du peuple? -Que l''Éternel a fondé Sion, Et que les malheureux de son peuple y trouvent un refuge.'),
  (23, 15, 1, 'Oracle sur Moab. La nuit même où elle est ravagée, Ar-Moab est détruite! La nuit même où elle est ravagée, Kir-Moab est détruite!…'),
  (23, 15, 2, 'On monte au temple et à Dibon, Sur les hauts lieux, pour pleurer; Moab est en lamentations, sur Nebo et sur Médeba: Toutes les têtes sont rasées, Toutes les barbes sont coupées.'),
  (23, 15, 3, 'Dans les rues, ils sont couverts de sacs; Sur les toits et dans les places, Tout gémit et fond en larmes.'),
  (23, 15, 4, 'Hesbon et Élealé poussent des cris, On entend leur voix jusqu''à Jahats; Même les guerriers de Moab se lamentent, Ils ont l''effroi dans l''âme.'),
  (23, 15, 5, 'Mon cœur gémit sur Moab, Dont les fugitifs se sauvent jusqu''à Tsoar, Jusqu''à Églath-Schelischija; Car ils font, en pleurant, la montée de Luchith, Et ils jettent des cris de détresse sur le chemin de Choronaïm;'),
  (23, 15, 6, 'Car les eaux de Nimrim sont ravagées, L''herbe est desséchée, le gazon est détruit, La verdure a disparu.'),
  (23, 15, 7, 'C''est pourquoi ils ramassent ce qui leur reste, Et ils transportent leurs biens au delà du torrent des saules.'),
  (23, 15, 8, 'Car les cris environnent les frontières de Moab; Ses lamentations retentissent jusqu''à Églaïm, Ses lamentations retentissent jusqu''à Beer-Élim.'),
  (23, 15, 9, 'Les eaux de Dimon sont pleines de sang, Et j''enverrai sur Dimon de nouveaux malheurs, Un lion contre les réchappés de Moab, Contre le reste du pays.'),
  (23, 16, 1, 'Envoyez les agneaux au souverain du pays, Envoyez-les de Séla, par le désert, A la montagne de la fille de Sion.'),
  (23, 16, 2, 'Tel un oiseau fugitif, telle une nichée effarouchée, Telles seront les filles de Moab, au passage de l''Arnon. -'),
  (23, 16, 3, 'Donne conseil, fais justice, Couvre-nous en plein midi de ton ombre comme de la nuit, Cache ceux que l''on poursuit, Ne trahis pas le fugitif!'),
  (23, 16, 4, 'Laisse séjourner chez toi les exilés de Moab, Sois pour eux un refuge contre le dévastateur! Car l''oppression cessera, la dévastation finira, Celui qui foule le pays disparaîtra.'),
  (23, 16, 5, 'Et le trône s''affermira par la clémence; Et l''on y verra siéger fidèlement, dans la maison de David, Un juge ami du droit et zélé pour la justice. -'),
  (23, 16, 6, 'Nous entendons l''orgueil du superbe Moab, Sa fierté et sa hauteur, son arrogance et ses vains discours.'),
  (23, 16, 7, 'C''est pourquoi Moab gémit sur Moab, tout gémit; Vous soupirez sur les ruines de Kir-Haréseth, Profondément abattus.'),
  (23, 16, 8, 'Car les campagnes de Hesbon languissent; Les maîtres des nations ont brisé les ceps de la vigne de Sibma, Qui s''étendaient jusqu''à Jaezer, qui erraient dans le désert: Les rameaux se prolongeaient, et allaient au delà de la mer.'),
  (23, 16, 9, 'Aussi je pleure sur la vigne de Sibma, comme sur Jaezer; Je vous arrose de mes larmes, Hesbon, Élealé! Car sur votre récolte et sur votre moisson Est venu fondre un cri de guerre.'),
  (23, 16, 10, 'La joie et l''allégresse ont disparu des campagnes; Dans les vignes, plus de chants, plus de réjouissances! Le vendangeur ne foule plus le vin dans les cuves; J''ai fait cesser les cris de joie.'),
  (23, 16, 11, 'Aussi mes entrailles frémissent sur Moab, comme une harpe, Et mon cœur sur Kir-Harès.'),
  (23, 16, 12, 'On voit Moab, qui se fatigue sur les hauts lieux; Il entre dans son sanctuaire pour prier, et il ne peut rien obtenir.'),
  (23, 16, 13, 'Telle est la parole que l''Éternel a prononcée dès longtemps sur Moab.'),
  (23, 16, 14, 'Et maintenant l''Éternel parle, et dit: Dans trois ans, comme les années d''un mercenaire, La gloire de Moab sera l''objet du mépris, Avec toute cette grande multitude; Et ce qui restera sera peu de chose, presque rien.'),
  (23, 17, 1, 'Oracle sur Damas. Voici, Damas ne sera plus une ville, Elle ne sera qu''un monceau de ruines.'),
  (23, 17, 2, 'Les villes d''Aroër sont abandonnées, Elles sont livrées aux troupeaux; Ils s''y couchent, et personne ne les effraie.'),
  (23, 17, 3, 'C''en est fait de la forteresse d''Éphraïm, Et du royaume de Damas, et du reste de la Syrie: Il en sera comme de la gloire des enfants d''Israël, Dit l''Éternel des armées.'),
  (23, 17, 4, 'En ce jour, la gloire de Jacob sera affaiblie, Et la graisse de sa chair s''évanouira.'),
  (23, 17, 5, 'Il en sera comme quand le moissonneur récolte les blés, Et que son bras coupe les épis; Comme quand on ramasse les épis, Dans la vallée de Rephaïm.'),
  (23, 17, 6, 'Il en restera un grappillage, comme quand on secoue l''olivier, Deux, trois olives, au haut de la cime, Quatre, cinq, dans ses branches à fruits, Dit l''Éternel, le Dieu d''Israël.'),
  (23, 17, 7, 'En ce jour, l''homme regardera vers son créateur, Et ses yeux se tourneront vers le Saint d''Israël;'),
  (23, 17, 8, 'Il ne regardera plus vers les autels, Ouvrage de ses mains, Et il ne contemplera plus ce que ses doigts ont fabriqué, Les idoles d''Astarté et les statues du soleil.'),
  (23, 17, 9, 'En ce jour, ses villes fortes seront Comme des débris dans la forêt et sur la cime des montagnes, Abandonnés devant les enfants d''Israël: Et ce sera un désert.'),
  (23, 17, 10, 'Car tu as oublié le Dieu de ton salut, Tu ne t''es pas souvenu du rocher de ton refuge. Aussi tu as fait des plantations d''agrément, Tu as planté des ceps étrangers;'),
  (23, 17, 11, 'Lorsque tu les plantas, tu les entouras d''une haie, Et bientôt tu les fis venir en fleurs. Mais la récolte a fui, au moment de la jouissance: Et la douleur est sans remède.'),
  (23, 17, 12, 'Oh! quelle rumeur de peuples nombreux! Ils mugissent comme mugit la mer. Quel tumulte de nations! Elles grondent comme grondent les eaux puissantes.'),
  (23, 17, 13, 'Les nations grondent comme grondent les grandes eaux… Il les menace, et elles fuient au loin, Chassées comme la balle des montagnes au souffle du vent, Comme la poussière par un tourbillon.'),
  (23, 17, 14, 'Quand vient le soir, voici, c''est une ruine soudaine; Avant le matin, ils ne sont plus! Voilà le partage de ceux qui nous dépouillent, Le sort de ceux qui nous pillent.'),
  (23, 18, 1, 'Terre, où retentit le cliquetis des armes, Au delà des fleuves de l''Éthiopie!'),
  (23, 18, 2, 'Toi qui envoies sur mer des messagers, Dans des navires de jonc voguant à la surface des eaux! Allez, messagers rapides, vers la nation forte et vigoureuse, Vers ce peuple redoutable depuis qu''il existe, Nation puissante et qui écrase tout, Et dont le pays est coupé par des fleuves.')
insert into public.bible_verses (book_id, chapter, verse, text) values
  (23, 18, 3, 'Vous tous, habitants du monde, habitants de la terre, Voyez la bannière qui se dresse sur les montagnes, Écoutez la trompette qui sonne!'),
  (23, 18, 4, 'Car ainsi m''a parlé l''Éternel: Je regarde tranquillement de ma demeure, Par la chaleur brillante de la lumière, Et par la vapeur de la rosée, au temps de la chaude moisson.'),
  (23, 18, 5, 'Mais avant la moisson, quand la pousse est achevée, Quand la fleur devient un raisin qui mûrit, Il coupe les sarments avec des serpes, Il enlève, il tranche les ceps…'),
  (23, 18, 6, 'Ils seront tous abandonnés aux oiseaux de proie des montagnes Et aux bêtes de la terre; Les oiseaux de proie passeront l''été sur leurs cadavres, Et les bêtes de la terre y passeront l''hiver.'),
  (23, 18, 7, 'En ce temps-là, des offrandes seront apportées à l''Éternel des armées, Par le peuple fort et vigoureux, Par le peuple redoutable depuis qu''il existe, Nation puissante et qui écrase tout, Et dont le pays est coupé par des fleuves; Elles seront apportées là où réside le nom de l''Éternel des armées, Sur la montagne de Sion.'),
  (23, 19, 1, 'Oracle sur l''Égypte. Voici, l''Éternel est monté sur une nuée rapide, il vient en Égypte; Et les idoles de l''Égypte tremblent devant lui, Et le cœur des Égyptiens tombe en défaillance.'),
  (23, 19, 2, 'J''armerai l''Égyptien contre l''Égyptien, Et l''on se battra frère contre frère, ami contre ami, Ville contre ville, royaume contre royaume.'),
  (23, 19, 3, 'L''esprit de l''Égypte disparaîtra du milieu d''elle, Et j''anéantirai son conseil; On consultera les idoles et les enchanteurs, Ceux qui évoquent les morts et ceux qui prédisent l''avenir.'),
  (23, 19, 4, 'Et je livrerai l''Égypte entre les mains d''un maître sévère; Un roi cruel dominera sur eux, Dit le Seigneur, l''Éternel des armées.'),
  (23, 19, 5, 'Les eaux de la mer tariront, Le fleuve deviendra sec et aride;'),
  (23, 19, 6, 'Les rivières seront infectes, Les canaux de l''Égypte seront bas et desséchés, Les joncs et les roseaux se flétriront.'),
  (23, 19, 7, 'Ce ne sera que nudité le long du fleuve, à l''embouchure du fleuve; Tout ce qui aura été semé près du fleuve se desséchera, Se réduira en poussière et périra.'),
  (23, 19, 8, 'Les pêcheurs gémiront, Tous ceux qui jettent l''hameçon dans le fleuve se lamenteront, Et ceux qui étendent des filets sur les eaux seront désolés.'),
  (23, 19, 9, 'Ceux qui travaillent le lin peigné Et qui tissent des étoffes blanches seront confus.'),
  (23, 19, 10, 'Les soutiens du pays seront dans l''abattement, Tous les mercenaires auront l''âme attristée.'),
  (23, 19, 11, 'Les princes de Tsoan ne sont que des insensés, Les sages conseillers de Pharaon forment un conseil stupide. Comment osez-vous dire à Pharaon: Je suis fils des sages, fils des anciens rois?'),
  (23, 19, 12, 'Où sont-ils donc tes sages? Qu''ils te fassent des révélations, Et qu''on apprenne ce que l''Éternel des armées a résolu contre l''Égypte.'),
  (23, 19, 13, 'Les princes de Tsoan sont fous, Les princes de Noph sont dans l''illusion, Les chefs des tribus égarent l''Égypte;'),
  (23, 19, 14, 'L''Éternel a répandu au milieu d''elle un esprit de vertige, Pour qu''ils fassent chanceler les Égyptiens dans tous leurs actes, Comme un homme ivre chancelle en vomissant.'),
  (23, 19, 15, 'Et l''Égypte sera hors d''état de faire Ce que font la tête et la queue, La branche de palmier et le roseau.'),
  (23, 19, 16, 'En ce jour, l''Égypte sera comme des femmes: Elle tremblera et aura peur, En voyant s''agiter la main de l''Éternel des armées, Quand il la lèvera contre elle.'),
  (23, 19, 17, 'Et le pays de Juda sera pour l''Égypte un objet d''effroi: Dès qu''on lui en parlera, elle sera dans l''épouvante, A cause de la résolution prise contre elle par l''Éternel des armées.'),
  (23, 19, 18, 'En ce temps-là, il y aura cinq villes au pays d''Égypte, Qui parleront la langue de Canaan, Et qui jureront par l''Éternel des armées: L''une d''elles sera appelée ville de la destruction.'),
  (23, 19, 19, 'En ce même temps, il y aura un autel à l''Éternel Au milieu du pays d''Égypte, Et sur la frontière un monument à l''Éternel.'),
  (23, 19, 20, 'Ce sera pour l''Éternel des armées un signe et un témoignage Dans le pays d''Égypte; Ils crieront à l''Éternel à cause des oppresseurs, Et il leur enverra un sauveur et un défenseur pour les délivrer.'),
  (23, 19, 21, 'Et l''Éternel sera connu des Égyptiens, Et les Égyptiens connaîtront l''Éternel en ce jour-là; Ils feront des sacrifices et des offrandes, Ils feront des vœux à l''Éternel et les accompliront.'),
  (23, 19, 22, 'Ainsi l''Éternel frappera les Égyptiens, Il les frappera, mais il les guérira; Et ils se convertiront à l''Éternel, Qui les exaucera et les guérira.'),
  (23, 19, 23, 'En ce même temps, il y aura une route d''Égypte en Assyrie: Les Assyriens iront en Égypte, et les Égyptiens en Assyrie, Et les Égyptiens avec les Assyriens serviront l''Éternel.'),
  (23, 19, 24, 'En ce même temps, Israël sera, lui troisième, Uni à l''Égypte et à l''Assyrie, Et ces pays seront l''objet d''une bénédiction.'),
  (23, 19, 25, 'L''Éternel des armées les bénira, en disant: Bénis soient l''Égypte, mon peuple, Et l''Assyrie, œuvre de mes mains, Et Israël, mon héritage!'),
  (23, 20, 1, 'L''année où Tharthan, envoyé par Sargon, roi d''Assyrie, vint assiéger Asdod et s''en empara,'),
  (23, 20, 2, 'en ce temps-là l''Éternel adressa la parole à Ésaïe, fils d''Amots, et lui dit: Va, détache le sac de tes reins et ôte tes souliers de tes pieds. Il fit ainsi, marcha nu et déchaussé.'),
  (23, 20, 3, 'Et l''Éternel dit: De même que mon serviteur Ésaïe marche nu et déchaussé, ce qui sera dans trois ans un signe et un présage pour l''Égypte et pour l''Éthiopie,'),
  (23, 20, 4, 'de même le roi d''Assyrie emmènera de l''Égypte et de l''Éthiopie captifs et exilés les jeunes hommes et les vieillards, nus et déchaussés, et le dos découvert, à la honte de l''Égypte.'),
  (23, 20, 5, 'Alors on sera dans l''effroi et dans la confusion, à cause de l''Éthiopie en qui l''on avait mis sa confiance, et de l''Égypte dont on se glorifiait.'),
  (23, 20, 6, 'Et les habitants de cette côte diront en ce jour: Voilà ce qu''est devenu l''objet de notre attente, sur lequel nous avions compté pour être secourus, pour être délivrés du roi d''Assyrie! Comment échapperons-nous?'),
  (23, 21, 1, 'Oracle sur le désert de la mer. Comme s''avance l''ouragan du midi, Il vient du désert, du pays redoutable.'),
  (23, 21, 2, 'Une vision terrible m''a été révélée. L''oppresseur opprime, le dévastateur dévaste. -Monte, Élam! Assiège, Médie! Je fais cesser tous les soupirs. -'),
  (23, 21, 3, 'C''est pourquoi mes reins sont remplis d''angoisses; Des douleurs me saisissent, Comme les douleurs d''une femme en travail; Les spasmes m''empêchent d''entendre, Le tremblement m''empêche de voir.'),
  (23, 21, 4, 'Mon cœur est troublé, La terreur s''empare de moi; La nuit de mes plaisirs devient une nuit d''épouvante.'),
  (23, 21, 5, 'On dresse la table, la garde veille, on mange, on boit… Debout, princes! oignez le bouclier!'),
  (23, 21, 6, 'Car ainsi m''a parlé le Seigneur: Va, place la sentinelle; Qu''elle annonce ce qu''elle verra. -'),
  (23, 21, 7, 'Elle vit de la cavalerie, des cavaliers deux à deux, Des cavaliers sur des ânes, des cavaliers sur des chameaux; Et elle était attentive, très attentive.'),
  (23, 21, 8, 'Puis elle s''écria, comme un lion: Seigneur, je me tiens sur la tour toute la journée, Et je suis à mon poste toutes les nuits;'),
  (23, 21, 9, 'Et voici, il vient de la cavalerie, des cavaliers deux à deux! Elle prit encore la parole, et dit: Elle est tombée, elle est tombée, Babylone, Et toutes les images de ses dieux sont brisées par terre! -'),
  (23, 21, 10, 'O mon peuple, qui as été battu comme du grain dans mon aire! Ce que j''ai appris de l''Éternel des armées, Dieu d''Israël, Je vous l''ai annoncé.'),
  (23, 21, 11, 'Oracle sur Duma. On me crie de Séir: Sentinelle, que dis-tu de la nuit? Sentinelle, que dis-tu de la nuit?'),
  (23, 21, 12, 'La sentinelle répond: Le matin vient, et la nuit aussi. Si vous voulez interroger, interrogez; Convertissez-vous, et revenez.'),
  (23, 21, 13, 'Oracle sur l''Arabie. Vous passerez la nuit dans les broussailles de l''Arabie, Caravanes de Dedan!'),
  (23, 21, 14, 'Portez de l''eau à ceux qui ont soif; Les habitants du pays de Théma Portent du pain aux fugitifs.'),
  (23, 21, 15, 'Car ils fuient devant les épées, Devant l''épée nue, devant l''arc tendu, Devant un combat acharné.'),
  (23, 21, 16, 'Car ainsi m''a parlé le Seigneur: Encore une année, comme les années d''un mercenaire, Et c''en est fait de toute la gloire de Kédar.'),
  (23, 21, 17, 'Il ne restera qu''un petit nombre des vaillants archers, fils de Kédar, Car l''Éternel, le Dieu d''Israël, l''a déclaré.'),
  (23, 22, 1, 'Oracle sur la vallée des visions. Qu''as-tu donc, que tout ton peuple monte sur les toits?'),
  (23, 22, 2, 'Ville bruyante, pleine de tumulte, Cité joyeuse! Tes morts ne périront pas par l''épée, Ils ne mourront pas en combattant.'),
  (23, 22, 3, 'Tous tes chefs fuient ensemble, Ils sont faits prisonniers par les archers; Tous tes habitants deviennent à la fois captifs, Tandis qu''ils prennent au loin la fuite.'),
  (23, 22, 4, 'C''est pourquoi je dis: Détournez de moi les regards, Laissez-moi pleurer amèrement; N''insistez pas pour me consoler Du désastre de la fille de mon peuple.'),
  (23, 22, 5, 'Car c''est un jour de trouble, d''écrasement et de confusion, Envoyé par le Seigneur, l''Éternel des armées, Dans la vallée des visions. On démolit les murailles, Et les cris de détresse retentissent vers la montagne.'),
  (23, 22, 6, 'Élam porte le carquois; Des chars de combattants, des cavaliers, s''avancent; Kir met à nu le bouclier.'),
  (23, 22, 7, 'Tes plus belles vallées sont remplies de chars, Et les cavaliers se rangent en bataille à tes portes.'),
  (23, 22, 8, 'Les derniers retranchements de Juda sont forcés, Et en ce jour tu visites les armures de la maison de la forêt.'),
  (23, 22, 9, 'Vous regardez les brèches nombreuses faites à la ville de David, Et vous retenez les eaux de l''étang inférieur.'),
  (23, 22, 10, 'Vous comptez les maisons de Jérusalem, Et vous les abattez, pour fortifier la muraille.'),
  (23, 22, 11, 'Vous faites un réservoir entre les deux murs, Pour les eaux de l''ancien étang. Mais vous ne regardez pas vers celui qui a voulu ces choses, Vous ne voyez pas celui qui les a préparées de loin.'),
  (23, 22, 12, 'Le Seigneur, l''Éternel des armées, vous appelle en ce jour A pleurer et à vous frapper la poitrine, A vous raser la tête et à ceindre le sac.'),
  (23, 22, 13, 'Et voici de la gaîté et de la joie! On égorge des bœufs et l''on tue des brebis, On mange de la viande et l''on boit du vin: Mangeons et buvons, car demain nous mourrons! -'),
  (23, 22, 14, 'L''Éternel des armées me l''a révélé: Non, ce crime ne vous sera point pardonné que vous ne soyez morts, Dit le Seigneur, l''Éternel des armées.'),
  (23, 22, 15, 'Ainsi parle le Seigneur, l''Éternel des armées: Va vers ce courtisan, Vers Schebna, gouverneur du palais:'),
  (23, 22, 16, 'Qu''y a-t-il à toi ici, et qui as-tu ici, Que tu creuses ici un sépulcre? Il se creuse un sépulcre sur la hauteur, Il se taille une demeure dans le roc!'),
  (23, 22, 17, 'Voici, l''Éternel te lancera d''un jet vigoureux; Il t''enveloppera comme une pelote,'),
  (23, 22, 18, 'Il te fera rouler, rouler comme une balle, Sur une terre spacieuse; Là tu mourras, là seront tes chars magnifiques, O toi, l''opprobre de la maison de ton maître!'),
  (23, 22, 19, 'Je te chasserai de ton poste, L''Éternel t''arrachera de ta place.'),
  (23, 22, 20, 'En ce jour-là, J''appellerai mon serviteur Éliakim, fils de Hilkija;'),
  (23, 22, 21, 'Je le revêtirai de ta tunique, je le ceindrai de ta ceinture, Et je remettrai ton pouvoir entre ses mains; Il sera un père pour les habitants de Jérusalem Et pour la maison de Juda.'),
  (23, 22, 22, 'Je mettrai sur son épaule la clé de la maison de David: Quand il ouvrira, nul ne fermera; Quand il fermera, nul n''ouvrira.'),
  (23, 22, 23, 'Je l''enfoncerai comme un clou dans un lieu sûr, Et il sera un siège de gloire pour la maison de son père.'),
  (23, 22, 24, 'Il sera le soutien de toute la gloire de la maison de son père, Des rejetons nobles et ignobles, De tous les petits ustensiles, Des bassins comme des vases.'),
  (23, 22, 25, 'En ce jour, dit l''Éternel des armées, Le clou enfoncé dans un lieu sûr sera enlevé, Il sera abattu et tombera, Et le fardeau qui était sur lui sera détruit, Car l''Éternel a parlé.'),
  (23, 23, 1, 'Oracle sur Tyr. Lamentez-vous, navires de Tarsis! Car elle est détruite: plus de maisons! plus d''entrée! C''est du pays de Kittim que la nouvelle leur en est venue.'),
  (23, 23, 2, 'Soyez muets d''effroi, habitants de la côte, Que remplissaient les marchands de Sidon, parcourant la mer!'),
  (23, 23, 3, 'A travers les vastes eaux, le blé du Nil, La moisson du fleuve, était pour elle un revenu; Elle était le marché des nations.'),
  (23, 23, 4, 'Sois confuse, Sidon! Car ainsi parle la mer, la forteresse de la mer: Je n''ai point eu de douleurs, je n''ai point enfanté, Je n''ai point nourri de jeunes gens, ni élevé de jeunes filles.'),
  (23, 23, 5, 'Quand les Égyptiens sauront la nouvelle, Ils trembleront en apprenant la chute de Tyr.'),
  (23, 23, 6, 'Passez à Tarsis, Lamentez-vous, habitants de la côte!'),
  (23, 23, 7, 'Est-ce là votre ville joyeuse? Elle avait une origine antique, Et ses pieds la mènent séjourner au loin.'),
  (23, 23, 8, 'Qui a pris cette résolution contre Tyr, la dispensatrice des couronnes, Elle dont les marchands étaient des princes, Dont les commerçants étaient les plus riches de la terre?'),
  (23, 23, 9, 'C''est l''Éternel des armées qui a pris cette résolution, Pour blesser l''orgueil de tout ce qui brille, Pour humilier tous les grands de la terre.'),
  (23, 23, 10, 'Parcours librement ton pays, pareille au Nil, Fille de Tarsis! Plus de joug!'),
  (23, 23, 11, 'L''Éternel a étendu sa main sur la mer; Il a fait trembler les royaumes; Il a ordonné la destruction des forteresses de Canaan.'),
  (23, 23, 12, 'Il a dit: Tu ne te livreras plus à la joie, Vierge déshonorée, fille de Sidon! Lève-toi, passe au pays de Kittim! Même là, il n''y aura pas de repos pour toi.'),
  (23, 23, 13, 'Vois les Chaldéens, qui n''étaient pas un peuple, Ces habitants du désert, pour qui l''Assyrien a fondé un pays; Ils élèvent des tours, ils renversent les palais de Tyr, Ils les mettent en ruines.'),
  (23, 23, 14, 'Lamentez-vous, navires de Tarsis! Car votre forteresse est détruite!'),
  (23, 23, 15, 'En ce temps-là, Tyr tombera dans l''oubli soixante-dix ans, Ce que dure la vie d''un roi. Au bout de soixante-dix ans, il en sera de Tyr Comme de la prostituée dont parle la chanson: -'),
  (23, 23, 16, 'Prends la harpe, parcours la ville, Prostituée qu''on oublie! Joue bien, répète tes chants, Pour qu''on se souvienne de toi! -'),
  (23, 23, 17, 'Au bout de soixante-dix ans, l''Éternel visitera Tyr, Et elle retournera à son salaire impur; Elle se prostituera à tous les royaumes de la terre, Sur la face du monde.'),
  (23, 23, 18, 'Mais son gain et son salaire impur seront consacrés à l''Éternel, Ils ne seront ni entassés ni conservés; Car son gain fournira pour ceux qui habitent devant l''Éternel Une nourriture abondante et des vêtements magnifiques.'),
  (23, 24, 1, 'Voici, l''Éternel dévaste le pays et le rend désert, Il en bouleverse la face et en disperse les habitants.'),
  (23, 24, 2, 'Et il en est du sacrificateur comme du peuple, Du maître comme du serviteur, De la maîtresse comme de la servante, Du vendeur comme de l''acheteur, Du prêteur comme de l''emprunteur, Du créancier comme du débiteur.'),
  (23, 24, 3, 'Le pays est dévasté, livré au pillage; Car l''Éternel l''a décrété.'),
  (23, 24, 4, 'Le pays est triste, épuisé; Les habitants sont abattus, languissants; Les chefs du peuple sont sans force.'),
  (23, 24, 5, 'Le pays était profané par ses habitants; Car ils transgressaient les lois, violaient les ordonnances, Ils rompaient l''alliance éternelle.'),
  (23, 24, 6, 'C''est pourquoi la malédiction dévore le pays, Et ses habitants portent la peine de leurs crimes; C''est pourquoi les habitants du pays sont consumés, Et il n''en reste qu''un petit nombre.'),
  (23, 24, 7, 'Le moût est triste, la vigne est flétrie; Tous ceux qui avaient le cœur joyeux soupirent.'),
  (23, 24, 8, 'La joie des tambourins a cessé, la gaîté bruyante a pris fin, La joie de la harpe a cessé.'),
  (23, 24, 9, 'On ne boit plus de vin en chantant; Les liqueurs fortes sont amères au buveur.'),
  (23, 24, 10, 'La ville déserte est en ruines; Toutes les maisons sont fermées, on n''y entre plus.'),
  (23, 24, 11, 'On crie dans les rues, parce que le vin manque; Toute réjouissance a disparu, L''allégresse est bannie du pays.'),
  (23, 24, 12, 'La dévastation est restée dans la ville, Et les portes abattues sont en ruines.'),
  (23, 24, 13, 'Car il en est dans le pays, au milieu des peuples, Comme quand on secoue l''olivier, Comme quand on grappille après la vendange.'),
  (23, 24, 14, 'Ils élèvent leur voix, ils poussent des cris d''allégresse; Des bords de la mer, ils célèbrent la majesté de l''Éternel.'),
  (23, 24, 15, 'Glorifiez donc l''Éternel dans les lieux où brille la lumière, Le nom de l''Éternel, Dieu d''Israël, dans les îles de la mer! -'),
  (23, 24, 16, 'De l''extrémité de la terre nous entendons chanter: Gloire au juste! Mais moi je dis: Je suis perdu! je suis perdu! malheur à moi! Les pillards pillent, et les pillards s''acharnent au pillage.'),
  (23, 24, 17, 'La terreur, la fosse, et le filet, Sont sur toi, habitant du pays!'),
  (23, 24, 18, 'Celui qui fuit devant les cris de terreur tombe dans la fosse, Et celui qui remonte de la fosse se prend au filet; Car les écluses d''en haut s''ouvrent, Et les fondements de la terre sont ébranlés.'),
  (23, 24, 19, 'La terre est déchirée, La terre se brise, La terre chancelle.'),
  (23, 24, 20, 'La terre chancelle comme un homme ivre, Elle vacille comme une cabane; Son péché pèse sur elle, Elle tombe, et ne se relève plus.'),
  (23, 24, 21, 'En ce temps-là, l''Éternel châtiera dans le ciel l''armée d''en haut, Et sur la terre les rois de la terre.'),
  (23, 24, 22, 'Ils seront assemblés captifs dans une prison, Ils seront enfermés dans des cachots, Et, après un grand nombre de jours, ils seront châtiés.'),
  (23, 24, 23, 'La lune sera couverte de honte, Et le soleil de confusion; Car l''Éternel des armées régnera Sur la montagne de Sion et à Jérusalem, Resplendissant de gloire en présence de ses anciens.'),
  (23, 25, 1, 'O Éternel! tu es mon Dieu; Je t''exalterai, je célébrerai ton nom, Car tu as fait des choses merveilleuses; Tes desseins conçus à l''avance se sont fidèlement accomplis.'),
  (23, 25, 2, 'Car tu as réduit la ville en un monceau de pierres, La cité forte en un tas de ruines; La forteresse des barbares est détruite, Jamais elle ne sera rebâtie.'),
  (23, 25, 3, 'C''est pourquoi les peuples puissants te glorifient, Les villes des nations puissantes te craignent.'),
  (23, 25, 4, 'Tu as été un refuge pour le faible, Un refuge pour le malheureux dans la détresse, Un abri contre la tempête, Un ombrage contre la chaleur; Car le souffle des tyrans Est comme l''ouragan qui frappe une muraille.'),
  (23, 25, 5, 'Comme tu domptes la chaleur dans une terre brûlante, Tu as dompté le tumulte des barbares; Comme la chaleur est étouffée par l''ombre d''un nuage, Ainsi ont été étouffés les chants de triomphe des tyrans.'),
  (23, 25, 6, 'L''Éternel des armées prépare à tous les peuples, sur cette montagne, Un festin de mets succulents, Un festin de vins vieux, De mets succulents, pleins de moelle, De vins vieux, clarifiés.'),
  (23, 25, 7, 'Et, sur cette montagne, il anéantit le voile qui voile tous les peuples, La couverture qui couvre toutes les nations;'),
  (23, 25, 8, 'Il anéantit la mort pour toujours; Le Seigneur, l''Éternel, essuie les larmes de tous les visages, Il fait disparaître de toute la terre l''opprobre de son peuple; Car l''Éternel a parlé.'),
  (23, 25, 9, 'En ce jour l''on dira: Voici, c''est notre Dieu, en qui nous avons confiance, Et c''est lui qui nous sauve; C''est l''Éternel, en qui nous avons confiance; Soyons dans l''allégresse, et réjouissons-nous de son salut!'),
  (23, 25, 10, 'Car la main de l''Éternel repose sur cette montagne; Et Moab est foulé sur place, Comme la paille est foulée dans une mare à fumier.'),
  (23, 25, 11, 'Au milieu de cette mare, il étend ses mains, Comme le nageur les étend pour nager; Mais l''Éternel abat son orgueil, Et déjoue l''artifice de ses mains.'),
  (23, 25, 12, 'Il renverse, il précipite les fortifications élevées de tes murs, Il les fait crouler à terre, jusque dans la poussière.'),
  (23, 26, 1, 'En ce jour, on chantera ce cantique dans le pays de Juda: Nous avons une ville forte; Il nous donne le salut pour murailles et pour rempart.'),
  (23, 26, 2, 'Ouvrez les portes, Laissez entrer la nation juste et fidèle.'),
  (23, 26, 3, 'A celui qui est ferme dans ses sentiments Tu assures la paix, la paix, Parce qu''il se confie en toi.'),
  (23, 26, 4, 'Confiez-vous en l''Éternel à perpétuité, Car l''Éternel, l''Éternel est le rocher des siècles.'),
  (23, 26, 5, 'Il a renversé ceux qui habitaient les hauteurs, Il a abaissé la ville superbe; Il l''a abaissée jusqu''à terre, Il lui a fait toucher la poussière.'),
  (23, 26, 6, 'Elle est foulée aux pieds, Aux pieds des pauvres, sous les pas des misérables.'),
  (23, 26, 7, 'Le chemin du juste est la droiture; Toi qui es juste, tu aplanis le sentier du juste.'),
  (23, 26, 8, 'Aussi nous t''attendons, ô Éternel! sur la voie de tes jugements; Notre âme soupire après ton nom et après ton souvenir.'),
  (23, 26, 9, 'Mon âme te désire pendant la nuit, Et mon esprit te cherche au dedans de moi; Car, lorsque tes jugements s''exercent sur la terre, Les habitants du monde apprennent la justice.'),
  (23, 26, 10, 'Si l''on fait grâce au méchant, il n''apprend pas la justice, Il se livre au mal dans le pays de la droiture, Et il n''a point égard à la majesté de Dieu.'),
  (23, 26, 11, 'Éternel, ta main est puissante: Ils ne l''aperçoivent pas. Ils verront ton zèle pour le peuple, et ils en seront confus; Le feu consumera tes ennemis.'),
  (23, 26, 12, 'Éternel, tu nous donnes la paix; Car tout ce que nous faisons, C''est toi qui l''accomplis pour nous.'),
  (23, 26, 13, 'Éternel, notre Dieu, d''autres maîtres que toi ont dominé sur nous; Mais c''est grâce à toi seul que nous invoquons ton nom.'),
  (23, 26, 14, 'Ceux qui sont morts ne revivront pas, Des ombres ne se relèveront pas; Car tu les as châtiés, tu les as anéantis, Et tu en as détruit tout souvenir.'),
  (23, 26, 15, 'Multiplie le peuple, ô Éternel! Multiplie le peuple, manifeste ta gloire; Recule toutes les limites du pays.'),
  (23, 26, 16, 'Éternel, ils t''ont cherché, quand ils étaient dans la détresse; Ils se sont répandus en prières, quand tu les as châtiés.'),
  (23, 26, 17, 'Comme une femme enceinte, sur le point d''accoucher, Se tord et crie au milieu de ses douleurs, Ainsi avons-nous été, loin de ta face, ô Éternel!'),
  (23, 26, 18, 'Nous avons conçu, nous avons éprouvé des douleurs, Et, quand nous enfantons, ce n''est que du vent: Le pays n''est pas sauvé, Et ses habitants ne sont pas nés.'),
  (23, 26, 19, 'Que tes morts revivent! Que mes cadavres se relèvent! -Réveillez-vous et tressaillez de joie, habitants de la poussière! Car ta rosée est une rosée vivifiante, Et la terre redonnera le jour aux ombres.'),
  (23, 26, 20, 'Va, mon peuple, entre dans ta chambre, Et ferme la porte derrière toi; Cache-toi pour quelques instants, Jusqu''à ce que la colère soit passée.'),
  (23, 26, 21, 'Car voici, l''Éternel sort de sa demeure, Pour punir les crimes des habitants de la terre; Et la terre mettra le sang à nu, Elle ne couvrira plus les meurtres.'),
  (23, 27, 1, 'En ce jour, l''Éternel frappera de sa dure, grande et forte épée Le léviathan, serpent fuyard, Le léviathan, serpent tortueux; Et il tuera le monstre qui est dans la mer.'),
  (23, 27, 2, 'En ce jour-là, Chantez un cantique sur la vigne.'),
  (23, 27, 3, 'Moi l''Éternel, j''en suis le gardien, Je l''arrose à chaque instant; De peur qu''on ne l''attaque, Nuit et jour je la garde.'),
  (23, 27, 4, 'Il n''y a point en moi de colère; Mais si je trouve à combattre des ronces et des épines, Je marcherai contre elles, je les consumerai toutes ensemble,'),
  (23, 27, 5, 'A moins qu''on ne me prenne pour refuge, Qu''on ne fasse la paix avec moi, qu''on ne fasse la paix avec moi.'),
  (23, 27, 6, 'Dans les temps à venir, Jacob prendra racine, Israël poussera des fleurs et des rejetons, Et il remplira le monde de ses fruits.'),
  (23, 27, 7, 'L''Éternel l''a-t-il frappé comme il a frappé ceux qui le frappaient? L''a-t-il tué comme il a tué ceux qui le tuaient?'),
  (23, 27, 8, 'C''est avec mesure que tu l''as châtié par l''exil, En l''emportant par le souffle impétueux du vent d''orient.'),
  (23, 27, 9, 'Ainsi le crime de Jacob a été expié, Et voici le fruit du pardon de son péché: L''Éternel a rendu toutes les pierres des autels Pareilles à des pierres de chaux réduites en poussière; Les idoles d''Astarté et les statues du soleil ne se relèveront plus.'),
  (23, 27, 10, 'Car la ville forte est solitaire, C''est une demeure délaissée et abandonnée comme le désert; Là pâture le veau, il s''y couche, et broute les branches.'),
  (23, 27, 11, 'Quand les rameaux sèchent, on les brise; Des femmes viennent, pour les brûler. C''était un peuple sans intelligence: Aussi celui qui l''a fait n''a point eu pitié de lui, Celui qui l''a formé ne lui a point fait grâce.'),
  (23, 27, 12, 'En ce temps-là, L''Éternel secouera des fruits, Depuis le cours du fleuve jusqu''au torrent d''Égypte; Et vous serez ramassés un à un, enfants d''Israël!'),
  (23, 27, 13, 'En ce jour, on sonnera de la grande trompette, Et alors reviendront ceux qui étaient exilés au pays d''Assyrie Ou fugitifs au pays d''Égypte; Et ils se prosterneront devant l''Éternel, Sur la montagne sainte, à Jérusalem.'),
  (23, 28, 1, 'Malheur à la couronne superbe des ivrognes d''Éphraïm, A la fleur fanée, qui fait l''éclat de sa parure, Sur la cime de la fertile vallée de ceux qui s''enivrent!'),
  (23, 28, 2, 'Voici venir, de la part du Seigneur, un homme fort et puissant, Comme un orage de grêle, un ouragan destructeur, Comme une tempête qui précipite des torrents d''eaux: Il la fait tomber en terre avec violence.'),
  (23, 28, 3, 'Elle sera foulée aux pieds, La couronne superbe des ivrognes d''Éphraïm;'),
  (23, 28, 4, 'Et la fleur fanée, qui fait l''éclat de sa parure, Sur la cime de la fertile vallée, Sera comme une figue hâtive qu''on aperçoit avant la récolte, Et qui, à peine dans la main, est aussitôt avalée.'),
  (23, 28, 5, 'En ce jour, l''Éternel des armées sera Une couronne éclatante et une parure magnifique Pour le reste de son peuple,'),
  (23, 28, 6, 'Un esprit de justice pour celui qui est assis au siège de la justice, Et une force pour ceux qui repoussent l''ennemi jusqu''à ses portes.'),
  (23, 28, 7, 'Mais eux aussi, ils chancellent dans le vin, Et les boissons fortes leur donnent des vertiges; Sacrificateurs et prophètes chancellent dans les boissons fortes, Ils sont absorbés par le vin, Ils ont des vertiges à cause des boissons fortes; Ils chancellent en prophétisant, Ils vacillent en rendant la justice.'),
  (23, 28, 8, 'Toutes les tables sont pleines de vomissements, d''ordures; Il n''y a plus de place. -'),
  (23, 28, 9, 'A qui veut-on enseigner la sagesse? A qui veut-on donner des leçons? Est-ce à des enfants qui viennent d''être sevrés, Qui viennent de quitter la mamelle?'),
  (23, 28, 10, 'Car c''est précepte sur précepte, précepte sur précepte, Règle sur règle, règle sur règle, Un peu ici, un peu là. -'),
  (23, 28, 11, 'Hé bien! c''est par des hommes aux lèvres balbutiantes Et au langage barbare Que l''Éternel parlera à ce peuple.'),
  (23, 28, 12, 'Il lui disait: Voici le repos, Laissez reposer celui qui est fatigué; Voici le lieu du repos! Mais ils n''ont point voulu écouter.'),
  (23, 28, 13, 'Et pour eux la parole de l''Éternel sera Précepte sur précepte, précepte sur précepte, Règle sur règle, règle sur règle, Un peu ici, un peu là, Afin qu''en marchant ils tombent à la renverse et se brisent, Afin qu''ils soient enlacés et pris.'),
  (23, 28, 14, 'Écoutez donc la parole de l''Éternel, moqueurs, Vous qui dominez sur ce peuple de Jérusalem!'),
  (23, 28, 15, 'Vous dites: Nous avons fait une alliance avec la mort, Nous avons fait un pacte avec le séjour des morts; Quand le fléau débordé passera, il ne nous atteindra pas, Car nous avons la fausseté pour refuge et le mensonge pour abri.'),
  (23, 28, 16, 'C''est pourquoi ainsi parle le Seigneur, l''Éternel: Voici, j''ai mis pour fondement en Sion une pierre, Une pierre éprouvée, une pierre angulaire de prix, solidement posée; Celui qui la prendra pour appui n''aura point hâte de fuir.'),
  (23, 28, 17, 'Je ferai de la droiture une règle, Et de la justice un niveau; Et la grêle emportera le refuge de la fausseté, Et les eaux inonderont l''abri du mensonge.'),
  (23, 28, 18, 'Votre alliance avec la mort sera détruite, Votre pacte avec le séjour des morts ne subsistera pas; Quand le fléau débordé passera, Vous serez par lui foulés aux pieds.'),
  (23, 28, 19, 'Chaque fois qu''il passera, il vous saisira; Car il passera tous les matins, le jour et la nuit, Et son bruit seul donnera l''épouvante.'),
  (23, 28, 20, 'Le lit sera trop court pour s''y étendre, Et la couverture trop étroite pour s''en envelopper.'),
  (23, 28, 21, 'Car l''Éternel se lèvera comme à la montagne de Peratsim, Il s''irritera comme dans la vallée de Gabaon, Pour faire son œuvre, son œuvre étrange, Pour exécuter son travail, son travail inouï.'),
  (23, 28, 22, 'Maintenant, ne vous livrez point à la moquerie, De peur que vos liens ne soient resserrés; Car la destruction de tout le pays est résolue; Je l''ai appris du Seigneur, de l''Éternel des armées.'),
  (23, 28, 23, 'Prêtez l''oreille, et écoutez ma voix! Soyez attentifs, et écoutez ma parole!'),
  (23, 28, 24, 'Celui qui laboure pour semer laboure-t-il toujours? Ouvre-t-il et brise-t-il toujours son terrain?'),
  (23, 28, 25, 'N''est-ce pas après en avoir aplani la surface Qu''il répand de la nielle et sème du cumin; Qu''il met le froment par rangées, L''orge à une place marquée, Et l''épeautre sur les bords?'),
  (23, 28, 26, 'Son Dieu lui a enseigné la marche à suivre, Il lui a donné ses instructions.'),
  (23, 28, 27, 'On ne foule pas la nielle avec le traîneau, Et la roue du chariot ne passe pas sur le cumin; Mais on bat la nielle avec le bâton, Et le cumin avec la verge.'),
  (23, 28, 28, 'On bat le blé, Mais on ne le bat pas toujours; On y pousse la roue du chariot et les chevaux, Mais on ne l''écrase pas.'),
  (23, 28, 29, 'Cela aussi vient de l''Éternel des armées; Admirable est son conseil, et grande est sa sagesse.'),
  (23, 29, 1, 'Malheur à Ariel, à Ariel, Cité dont David fit sa demeure! Ajoutez année à année, Laissez les fêtes accomplir leur cycle.'),
  (23, 29, 2, 'Puis j''assiégerai Ariel; Il y aura des plaintes et des gémissements; Et la ville sera pour moi comme un Ariel.'),
  (23, 29, 3, 'Je t''investirai de toutes parts, Je te cernerai par des postes armés, J''élèverai contre toi des retranchements.'),
  (23, 29, 4, 'Tu seras abaissée, ta parole viendra de terre, Et les sons en seront étouffés par la poussière; Ta voix sortira de terre comme celle d''un spectre, Et c''est de la poussière que tu murmureras tes discours.'),
  (23, 29, 5, 'La multitude de tes ennemis sera comme une fine poussière, Cette multitude de guerriers sera comme la balle qui vole, Et cela tout à coup, en un instant.'),
  (23, 29, 6, 'C''est de l''Éternel des armées que viendra le châtiment, Avec des tonnerres, des tremblements de terre et un bruit formidable, Avec l''ouragan et la tempête, Et avec la flamme d''un feu dévorant.'),
  (23, 29, 7, 'Et, comme il en est d''un songe, d''une vision nocturne, Ainsi en sera-t-il de la multitude des nations qui combattront Ariel, De tous ceux qui l''attaqueront, elle et sa forteresse, Et qui la serreront de près.'),
  (23, 29, 8, 'Comme celui qui a faim rêve qu''il mange, Puis s''éveille, l''estomac vide, Et comme celui qui a soif rêve qu''il boit, Puis s''éveille, épuisé et languissant; Ainsi en sera-t-il de la multitude des nations Qui viendront attaquer la montagne de Sion.'),
  (23, 29, 9, 'Soyez stupéfaits et étonnés! Fermez les yeux et devenez aveugles! Ils sont ivres, mais ce n''est pas de vin; Ils chancellent, mais ce n''est pas l''effet des liqueurs fortes.'),
  (23, 29, 10, 'Car l''Éternel a répandu sur vous un esprit d''assoupissement; Il a fermé vos yeux (les prophètes), Il a voilé vos têtes (les voyants).'),
  (23, 29, 11, 'Toute la révélation est pour vous comme les mots d''un livre cacheté Que l''on donne à un homme qui sait lire, en disant: Lis donc cela! Et qui répond: Je ne le puis, Car il est cacheté;'),
  (23, 29, 12, 'Ou comme un livre que l''on donne A un homme qui ne sait pas lire, en disant: Lis donc cela! Et qui répond: Je ne sais pas lire.'),
  (23, 29, 13, 'Le Seigneur dit: Quand ce peuple s''approche de moi, Il m''honore de la bouche et des lèvres; Mais son cœur est éloigné de moi, Et la crainte qu''il a de moi N''est qu''un précepte de tradition humaine.'),
  (23, 29, 14, 'C''est pourquoi je frapperai encore ce peuple Par des prodiges et des miracles; Et la sagesse de ses sages périra, Et l''intelligence de ses hommes intelligents disparaîtra.'),
  (23, 29, 15, 'Malheur à ceux qui cachent leurs desseins Pour les dérober à l''Éternel, Qui font leurs œuvres dans les ténèbres, Et qui disent: Qui nous voit et qui nous connaît?'),
  (23, 29, 16, 'Quelle perversité est la vôtre! Le potier doit-il être considéré comme de l''argile, Pour que l''ouvrage dise de l''ouvrier: Il ne m''a point fait? Pour que le vase dise du potier: Il n''a point d''intelligence?'),
  (23, 29, 17, 'Encore un peu de temps, Et le Liban se changera en verger, Et le verger sera considéré comme une forêt.'),
  (23, 29, 18, 'En ce jour-là, les sourds entendront les paroles du livre; Et, délivrés de l''obscurité et des ténèbres, Les yeux des aveugles verront.'),
  (23, 29, 19, 'Les malheureux se réjouiront de plus en plus en l''Éternel, Et les pauvres feront du Saint d''Israël le sujet de leur allégresse.'),
  (23, 29, 20, 'Car le violent ne sera plus, le moqueur aura fini, Et tous ceux qui veillaient pour l''iniquité seront exterminés,'),
  (23, 29, 21, 'Ceux qui condamnaient les autres en justice, Tendaient des pièges à qui défendait sa cause à la porte, Et violaient par la fraude les droits de l''innocent.'),
  (23, 29, 22, 'C''est pourquoi ainsi parle l''Éternel à la maison de Jacob, Lui qui a racheté Abraham: Maintenant Jacob ne rougira plus, Maintenant son visage ne pâlira plus.'),
  (23, 29, 23, 'Car, lorsque ses enfants verront au milieu d''eux l''œuvre de mes mains, Ils sanctifieront mon nom; Ils sanctifieront le Saint de Jacob, Et ils craindront le Dieu d''Israël;'),
  (23, 29, 24, 'Ceux dont l''esprit s''égarait acquerront de l''intelligence, Et ceux qui murmuraient recevront instruction.'),
  (23, 30, 1, 'Malheur, dit l''Éternel, aux enfants rebelles, Qui prennent des résolutions sans moi, Et qui font des alliances sans ma volonté, Pour accumuler péché sur péché!'),
  (23, 30, 2, 'Qui descendent en Égypte sans me consulter, Pour se réfugier sous la protection de Pharaon, Et chercher un abri sous l''ombre de l''Égypte!'),
  (23, 30, 3, 'La protection de Pharaon sera pour vous une honte, Et l''abri sous l''ombre de l''Égypte une ignominie.'),
  (23, 30, 4, 'Déjà ses princes sont à Tsoan, Et ses envoyés ont atteint Hanès.'),
  (23, 30, 5, 'Tous seront confus au sujet d''un peuple qui ne leur sera point utile, Ni pour les secourir, ni pour les aider, Mais qui fera leur honte et leur opprobre.'),
  (23, 30, 6, 'Sentence des bêtes du midi: A travers une contrée de détresse et d''angoisse, D''où viennent la lionne et le lion, La vipère et le dragon volant, Ils portent à dos d''ânes leurs richesses, Et sur la bosse des chameaux leurs trésors, A un peuple qui ne leur sera point utile.'),
  (23, 30, 7, 'Car le secours de l''Égypte n''est que vanité et néant; C''est pourquoi j''appelle cela du bruit qui n''aboutit à rien.'),
  (23, 30, 8, 'Va maintenant, écris ces choses devant eux sur une table, Et grave-les dans un livre, Afin qu''elles subsistent dans les temps à venir, Éternellement et à perpétuité.'),
  (23, 30, 9, 'Car c''est un peuple rebelle, Ce sont des enfants menteurs, Des enfants qui ne veulent point écouter la loi de l''Éternel,'),
  (23, 30, 10, 'Qui disent aux voyants: Ne voyez pas! Et aux prophètes: Ne nous prophétisez pas des vérités, Dites-nous des choses flatteuses, Prophétisez des chimères!'),
  (23, 30, 11, 'Détournez-vous du chemin, Écartez-vous du sentier, Éloignez de notre présence le Saint d''Israël!'),
  (23, 30, 12, 'C''est pourquoi ainsi parle le Saint d''Israël: Puisque vous rejetez cette parole, Que vous vous confiez dans la violence et dans les détours Et que vous les prenez pour appuis,'),
  (23, 30, 13, 'Ce crime sera pour vous Comme une partie crevassée qui menace ruine Et fait saillie dans un mur élevé, Dont l''écroulement arrive tout à coup, en un instant:'),
  (23, 30, 14, 'Il se brise comme se brise un vase de terre, Que l''on casse sans ménagement, Et dont les débris ne laissent pas un morceau Pour prendre du feu au foyer, Ou pour puiser de l''eau à la citerne.'),
  (23, 30, 15, 'Car ainsi a parlé le Seigneur, l''Éternel, le Saint d''Israël: C''est dans la tranquillité et le repos que sera votre salut, C''est dans le calme et la confiance que sera votre force. Mais vous ne l''avez pas voulu!'),
  (23, 30, 16, 'Vous avez dit: Non! nous prendrons la course à cheval! -C''est pourquoi vous fuirez à la course. -Nous monterons des coursiers légers! -C''est pourquoi ceux qui vous poursuivront seront légers.'),
  (23, 30, 17, 'Mille fuiront à la menace d''un seul, Et, à la menace de cinq, vous fuirez, Jusqu''à ce que vous restiez Comme un signal au sommet de la montagne, Comme un étendard sur la colline.'),
  (23, 30, 18, 'Cependant l''Éternel désire vous faire grâce, Et il se lèvera pour vous faire miséricorde; Car l''Éternel est un Dieu juste: Heureux tous ceux qui espèrent en lui!'),
  (23, 30, 19, 'Oui, peuple de Sion, habitant de Jérusalem, Tu ne pleureras plus! Il te fera grâce, quand tu crieras; Dès qu''il aura entendu, il t''exaucera.'),
  (23, 30, 20, 'Le Seigneur vous donnera du pain dans l''angoisse, Et de l''eau dans la détresse; Ceux qui t''instruisent ne se cacheront plus, Mais tes yeux verront ceux qui t''instruisent.'),
  (23, 30, 21, 'Tes oreilles entendront derrière toi la voix qui dira: Voici le chemin, marchez-y! Car vous iriez à droite, ou vous iriez à gauche.'),
  (23, 30, 22, 'Vous tiendrez pour souillés l''argent qui recouvre vos idoles, Et l''or dont elles sont revêtues; Tu en disperseras les débris comme une impureté: Hors d''ici! leur diras-tu.'),
  (23, 30, 23, 'Alors il répandra la pluie sur la semence que tu auras mise en terre, Et le pain que produira la terre sera savoureux et nourrissant; En ce même temps, tes troupeaux paîtront dans de vastes pâturages.'),
  (23, 30, 24, 'Les bœufs et les ânes, qui labourent la terre, Mangeront un fourrage salé, Qu''on aura vanné avec la pelle et le van.'),
  (23, 30, 25, 'Sur toute haute montagne et sur toute colline élevée, Il y aura des ruisseaux, des courants d''eau, Au jour du grand carnage, A la chute des tours.'),
  (23, 30, 26, 'La lumière de la lune sera comme la lumière du soleil, Et la lumière du soleil sera sept fois plus grande (Comme la lumière de sept jours), Lorsque l''Éternel bandera la blessure de son peuple, Et qu''il guérira la plaie de ses coups.'),
  (23, 30, 27, 'Voici, le nom de l''Éternel vient de loin; Sa colère est ardente, c''est un violent incendie; Ses lèvres sont pleines de fureur, Et sa langue est comme un feu dévorant;'),
  (23, 30, 28, 'Son souffle est comme un torrent débordé qui atteint jusqu''au cou, Pour cribler les nations avec le crible de la destruction, Et comme un mors trompeur Entre les mâchoires des peuples.'),
  (23, 30, 29, 'Vous chanterez comme la nuit où l''on célèbre la fête, Vous aurez le cœur joyeux comme celui qui marche au son de la flûte, Pour aller à la montagne de l''Éternel, vers le rocher d''Israël.'),
  (23, 30, 30, 'Et l''Éternel fera retentir sa voix majestueuse, Il montrera son bras prêt à frapper, Dans l''ardeur de sa colère, Au milieu de la flamme d''un feu dévorant, De l''inondation, de la tempête et des pierres de grêle.'),
  (23, 30, 31, 'A la voix de l''Éternel, l''Assyrien tremblera; L''Éternel le frappera de sa verge.'),
  (23, 30, 32, 'A chaque coup de la verge qui lui est destinée, Et que l''Éternel fera tomber sur lui, On entendra les tambourins et les harpes; L''Éternel combattra contre lui à main levée.'),
  (23, 30, 33, 'Depuis longtemps un bûcher est préparé, Il est préparé pour le roi, Il est profond, il est vaste; Son bûcher, c''est du feu et du bois en abondance; Le souffle de l''Éternel l''enflamme, comme un torrent de soufre.'),
  (23, 31, 1, 'Malheur à ceux qui descendent en Égypte pour avoir du secours, Qui s''appuient sur des chevaux, Et se fient à la multitude des chars et à la force des cavaliers, Mais qui ne regardent pas vers le Saint d''Israël, Et ne recherchent pas l''Éternel!'),
  (23, 31, 2, 'Lui aussi, cependant, il est sage, il fait venir le malheur, Et ne retire point ses paroles; Il s''élève contre la maison des méchants, Et contre le secours de ceux qui commettent l''iniquité.'),
  (23, 31, 3, 'L''Égyptien est homme et non dieu; Ses chevaux sont chair et non esprit. Quand l''Éternel étendra sa main, Le protecteur chancellera, le protégé tombera, Et tous ensemble ils périront.'),
  (23, 31, 4, 'Car ainsi m''a parlé l''Éternel: Comme le lion, comme le lionceau rugit sur sa proie, Et, malgré tous les bergers rassemblés contre lui, Ne se laisse ni effrayer par leur voix, Ni intimider par leur nombre; De même l''Éternel des armées descendra Pour combattre sur la montagne de Sion et sur sa colline.'),
  (23, 31, 5, 'Comme des oiseaux déploient les ailes sur leur couvée, Ainsi l''Éternel des armées étendra sa protection sur Jérusalem; Il protégera et délivrera, Il épargnera et sauvera.'),
  (23, 31, 6, 'Revenez à celui dont on s''est profondément détourné, Enfants d''Israël!'),
  (23, 31, 7, 'En ce jour, chacun rejettera ses idoles d''argent et ses idoles d''or, Que vous vous êtes fabriquées de vos mains criminelles.'),
  (23, 31, 8, 'Et l''Assyrien tombera sous un glaive qui n''est pas celui d''un homme, Et un glaive qui n''est pas celui d''un homme le dévorera; Il s''enfuira devant le glaive, Et ses jeunes guerriers seront asservis.'),
  (23, 31, 9, 'Son rocher s''enfuira d''épouvante, Et ses chefs trembleront devant la bannière, Dit l''Éternel, qui a son feu dans Sion Et sa fournaise dans Jérusalem.'),
  (23, 32, 1, 'Alors le roi régnera selon la justice, Et les princes gouverneront avec droiture.'),
  (23, 32, 2, 'Chacun sera comme un abri contre le vent, Et un refuge contre la tempête, Comme des courants d''eau dans un lieu desséché, Comme l''ombre d''un grand rocher dans une terre altérée.'),
  (23, 32, 3, 'Les yeux de ceux qui voient ne seront plus bouchés, Et les oreilles de ceux qui entendent seront attentives.'),
  (23, 32, 4, 'Le cœur des hommes légers sera intelligent pour comprendre, Et la langue de ceux qui balbutient parlera vite et nettement.'),
  (23, 32, 5, 'On ne donnera plus à l''insensé le nom de noble, Ni au fourbe celui de magnanime.'),
  (23, 32, 6, 'Car l''insensé profère des folies, Et son cœur s''adonne au mal, Pour commettre l''impiété, Et dire des faussetés contre l''Éternel, Pour laisser à vide l''âme de celui qui a faim, Et enlever le breuvage de celui qui a soif.'),
  (23, 32, 7, 'Les armes du fourbe sont pernicieuses; Il forme de coupables desseins, Pour perdre les malheureux par des paroles mensongères, Même quand la cause du pauvre est juste.'),
  (23, 32, 8, 'Mais celui qui est noble forme de nobles desseins, Et il persévère dans ses nobles desseins.'),
  (23, 32, 9, 'Femmes insouciantes, Levez-vous, écoutez ma voix! Filles indolentes, Prêtez l''oreille à ma parole!'),
  (23, 32, 10, 'Dans un an et quelques jours, Vous tremblerez, indolentes; Car c''en est fait de la vendange, La récolte n''arrivera pas.'),
  (23, 32, 11, 'Soyez dans l''effroi, insouciantes! Tremblez, indolentes! Déshabillez-vous, mettez-vous à nu Et ceignez vos reins!'),
  (23, 32, 12, 'On se frappe le sein, Au souvenir de la beauté des champs Et de la fécondité des vignes.'),
  (23, 32, 13, 'Sur la terre de mon peuple Croissent les épines et les ronces, Même dans toutes les maisons de plaisance De la cité joyeuse.'),
  (23, 32, 14, 'Le palais est abandonné, La ville bruyante est délaissée; La colline et la tour serviront à jamais de cavernes; Les ânes sauvages y joueront, les troupeaux y paîtront,'),
  (23, 32, 15, 'Jusqu''à ce que l''esprit soit répandu d''en haut sur nous, Et que le désert se change en verger, Et que le verger soit considéré comme une forêt.'),
  (23, 32, 16, 'Alors la droiture habitera dans le désert, Et la justice aura sa demeure dans le verger.'),
  (23, 32, 17, 'L''œuvre de la justice sera la paix, Et le fruit de la justice le repos et la sécurité pour toujours.'),
  (23, 32, 18, 'Mon peuple demeurera dans le séjour de la paix, Dans des habitations sûres, Dans des asiles tranquilles.'),
  (23, 32, 19, 'Mais la forêt sera précipitée sous la grêle, Et la ville profondément abaissée.'),
  (23, 32, 20, 'Heureux vous qui partout semez le long des eaux, Et qui laissez sans entraves le pied du bœuf et de l''âne!'),
  (23, 33, 1, 'Malheur à toi qui ravages, et qui n''as pas été ravagé! Qui pilles, et qu''on n''a pas encore pillé! Quand tu auras fini de ravager, tu seras ravagé; Quand tu auras achevé de piller, on te pillera.'),
  (23, 33, 2, 'Éternel, aie pitié de nous! Nous espérons en toi. Sois notre aide chaque matin, Et notre délivrance au temps de la détresse!'),
  (23, 33, 3, 'Quand ta voix retentit, Les peuples fuient; Quand tu te lèves, Les nations se dispersent.'),
  (23, 33, 4, 'On moissonne votre butin, Comme moissonne la sauterelle; On se précipite dessus, Comme se précipitent les sauterelles.'),
  (23, 33, 5, 'L''Éternel est élevé, Car il habite en haut; Il remplit Sion De droiture et de justice.'),
  (23, 33, 6, 'Tes jours seront en sûreté; La sagesse et l''intelligence sont une source de salut; La crainte de l''Éternel, C''est là le trésor de Sion.'),
  (23, 33, 7, 'Voici, les héros Poussent des cris au dehors; Les messagers de paix Pleurent amèrement.'),
  (23, 33, 8, 'Les routes sont désertes; On ne passe plus dans les chemins. Il a rompu l''alliance, il méprise les villes, Il n''a de respect pour personne.'),
  (23, 33, 9, 'Le pays est dans le deuil, dans la tristesse; Le Liban est confus, languissant; Le Saron est comme un désert; Le Basan et le Carmel secouent leur feuillage.'),
  (23, 33, 10, 'Maintenant je me lèverai, Dit l''Éternel, Maintenant je serai exalté, Maintenant je serai élevé.'),
  (23, 33, 11, 'Vous avez conçu du foin, Vous enfanterez de la paille; Votre souffle, C''est un feu qui vous consumera.'),
  (23, 33, 12, 'Les peuples seront Des fournaises de chaux, Des épines coupées Qui brûlent dans le feu.'),
  (23, 33, 13, 'Vous qui êtes loin, écoutez ce que j''ai fait! Et vous qui êtes près, sachez quelle est ma puissance!'),
  (23, 33, 14, 'Les pécheurs sont effrayés dans Sion, Un tremblement saisit les impies: Qui de nous pourra rester auprès d''un feu dévorant? Qui de nous pourra rester auprès de flammes éternelles? -'),
  (23, 33, 15, 'Celui qui marche dans la justice, Et qui parle selon la droiture, Qui méprise un gain acquis par extorsion, Qui secoue les mains pour ne pas accepter un présent, Qui ferme l''oreille pour ne pas entendre des propos sanguinaires, Et qui se bande les yeux pour ne pas voir le mal,'),
  (23, 33, 16, 'Celui-là habitera dans des lieux élevés; Des rochers fortifiés seront sa retraite; Du pain lui sera donné, De l''eau lui sera assurée.'),
  (23, 33, 17, 'Tes yeux verront le roi dans sa magnificence, Ils contempleront le pays dans toute son étendue.'),
  (23, 33, 18, 'Ton cœur se souviendra de la terreur: Où est le secrétaire, où est le trésorier? Où est celui qui inspectait les tours?'),
  (23, 33, 19, 'Tu ne verras plus le peuple audacieux, Le peuple au langage obscur qu''on n''entend pas, A la langue barbare qu''on ne comprend pas.'),
  (23, 33, 20, 'Regarde Sion, la cité de nos fêtes! Tes yeux verront Jérusalem, séjour tranquille, Tente qui ne sera plus transportée, Dont les pieux ne seront jamais enlevés, Et dont les cordages ne seront point détachés.'),
  (23, 33, 21, 'C''est là vraiment que l''Éternel est magnifique pour nous: Il nous tient lieu de fleuves, de vastes rivières, Où ne pénètrent point de navires à rames, Et que ne traverse aucun grand vaisseau.'),
  (23, 33, 22, 'Car l''Éternel est notre juge, L''Éternel est notre législateur, L''Éternel est notre roi: C''est lui qui nous sauve.'),
  (23, 33, 23, 'Tes cordages sont relâchés; Ils ne serrent plus le pied du mât et ne tendent plus les voiles. Alors on partage la dépouille d''un immense butin; Les boiteux même prennent part au pillage:'),
  (23, 33, 24, 'Aucun habitant ne dit: Je suis malade! Le peuple de Jérusalem reçoit le pardon de ses iniquités.'),
  (23, 34, 1, 'Approchez, nations, pour entendre! Peuples, soyez attentifs! Que la terre écoute, elle et ce qui la remplit, Le monde et tout ce qu''il produit!'),
  (23, 34, 2, 'Car la colère de l''Éternel va fondre sur toutes les nations, Et sa fureur sur toute leur armée: Il les voue à l''extermination, Il les livre au carnage.'),
  (23, 34, 3, 'Leurs morts sont jetés, Leurs cadavres exhalent la puanteur, Et les montagnes se fondent dans leur sang.'),
  (23, 34, 4, 'Toute l''armée des cieux se dissout; Les cieux sont roulés comme un livre, Et toute leur armée tombe, Comme tombe la feuille de la vigne, Comme tombe celle du figuier.'),
  (23, 34, 5, 'Mon épée s''est enivrée dans les cieux; Voici, elle va descendre sur Édom, Sur le peuple que j''ai voué à l''extermination, pour le châtier.'),
  (23, 34, 6, 'L''épée de l''Éternel est pleine de sang, couverte de graisse, Du sang des agneaux et des boucs, De la graisse des reins des béliers; Car il y a des victimes de l''Éternel à Botsra, Et un grand carnage dans le pays d''Édom,'),
  (23, 34, 7, 'Les buffles tombent avec eux, Et les bœufs avec les taureaux; La terre s''abreuve de sang, Et le sol est imprégné de graisse.'),
  (23, 34, 8, 'Car c''est un jour de vengeance pour l''Éternel, Une année de représailles pour la cause de Sion.'),
  (23, 34, 9, 'Les torrents d''Édom seront changés en poix, Et sa poussière en soufre; Et sa terre sera comme de la poix qui brûle.'),
  (23, 34, 10, 'Elle ne s''éteindra ni jour ni nuit, La fumée s''en élèvera éternellement; D''âge en âge elle sera désolée, A tout jamais personne n''y passera.'),
  (23, 34, 11, 'Le pélican et le hérisson la posséderont, La chouette et le corbeau l''habiteront. On y étendra le cordeau de la désolation, Et le niveau de la destruction.'),
  (23, 34, 12, 'Il n''y aura plus de grands pour proclamer un roi, Tous ses princes seront anéantis.'),
  (23, 34, 13, 'Les épines croîtront dans ses palais, Les ronces et les chardons dans ses forteresses. Ce sera la demeure des chacals, Le repaire des autruches;'),
  (23, 34, 14, 'Les animaux du désert y rencontreront les chiens sauvages, Et les boucs s''y appelleront les uns les autres; Là le spectre de la nuit aura sa demeure, Et trouvera son lieu de repos;'),
  (23, 34, 15, 'Là le serpent fera son nid, déposera ses œufs, Les couvera, et recueillera ses petits à son ombre; Là se rassembleront tous les vautours.'),
  (23, 34, 16, 'Consultez le livre de l''Éternel, et lisez! Aucun d''eux ne fera défaut, Ni l''un ni l''autre ne manqueront; Car sa bouche l''a ordonné. C''est son esprit qui les rassemblera.'),
  (23, 34, 17, 'Il a jeté pour eux le sort, Et sa main leur a partagé cette terre au cordeau, Ils la posséderont toujours, Ils l''habiteront d''âge en âge.'),
  (23, 35, 1, 'Le désert et le pays aride se réjouiront; La solitude s''égaiera, et fleurira comme un narcisse;'),
  (23, 35, 2, 'Elle se couvrira de fleurs, et tressaillira de joie, Avec chants d''allégresse et cris de triomphe; La gloire du Liban lui sera donnée, La magnificence du Carmel et de Saron. Ils verront la gloire de l''Éternel, la magnificence de notre Dieu.'),
  (23, 35, 3, 'Fortifiez les mains languissantes, Et affermissez les genoux qui chancellent;'),
  (23, 35, 4, 'Dites à ceux qui ont le cœur troublé: Prenez courage, ne craignez point; Voici votre Dieu, la vengeance viendra, La rétribution de Dieu; Il viendra lui-même, et vous sauvera.'),
  (23, 35, 5, 'Alors s''ouvriront les yeux des aveugles, S''ouvriront les oreilles des sourds;'),
  (23, 35, 6, 'Alors le boiteux sautera comme un cerf, Et la langue du muet éclatera de joie. Car des eaux jailliront dans le désert, Et des ruisseaux dans la solitude;'),
  (23, 35, 7, 'Le mirage se changera en étang Et la terre desséchée en sources d''eaux; Dans le repaire qui servait de gîte aux chacals, Croîtront des roseaux et des joncs.'),
  (23, 35, 8, 'Il y aura là un chemin frayé, une route, Qu''on appellera la voie sainte; Nul impur n''y passera; elle sera pour eux seuls; Ceux qui la suivront, même les insensés, ne pourront s''égarer.'),
  (23, 35, 9, 'Sur cette route, point de lion; Nulle bête féroce ne la prendra, Nulle ne s''y rencontrera; Les délivrés y marcheront.'),
  (23, 35, 10, 'Les rachetés de l''Éternel retourneront, Ils iront à Sion avec chants de triomphe, Et une joie éternelle couronnera leur tête; L''allégresse et la joie s''approcheront, La douleur et les gémissements s''enfuiront.'),
  (23, 36, 1, 'La quatorzième année du roi Ézéchias, Sanchérib, roi d''Assyrie, monta contre toutes les villes fortes de Juda et s''en empara.'),
  (23, 36, 2, 'Et le roi d''Assyrie envoya de Lakis à Jérusalem, vers le roi Ézéchias, Rabschaké avec une puissante armée. Rabschaké s''arrêta à l''aqueduc de l''étang supérieur, sur le chemin du champ du foulon.'),
  (23, 36, 3, 'Alors Éliakim, fils de Hilkija, chef de la maison du roi, se rendit auprès de lui, avec Schebna, le secrétaire, et Joach, fils d''Asaph, l''archiviste.'),
  (23, 36, 4, 'Rabschaké leur dit: Dites à Ézéchias: Ainsi parle le grand roi, le roi d''Assyrie: Quelle est cette confiance, sur laquelle tu t''appuies?'),
  (23, 36, 5, 'Je te le dis, ce ne sont que des paroles en l''air: il faut pour la guerre de la prudence et de la force. En qui donc as-tu placé ta confiance, pour t''être révolté contre moi?'),
  (23, 36, 6, 'Voici, tu l''as placée dans l''Égypte, tu as pris pour soutien ce roseau cassé, qui pénètre et perce la main de quiconque s''appuie dessus: tel est Pharaon, roi d''Égypte, pour tous ceux qui se confient en lui.'),
  (23, 36, 7, 'Peut-être me diras-tu: C''est en l''Éternel, notre Dieu, que nous nous confions. Mais n''est-ce pas lui dont Ézéchias a fait disparaître les hauts lieux et les autels, en disant à Juda et à Jérusalem: Vous vous prosternerez devant cet autel?'),
  (23, 36, 8, 'Maintenant, fais une convention avec mon maître, le roi d''Assyrie, et je te donnerai deux mille chevaux, si tu peux fournir des cavaliers pour les monter.'),
  (23, 36, 9, 'Comment repousserais-tu un seul chef d''entre les moindres serviteurs de mon maître? Tu mets ta confiance dans l''Égypte pour les chars et pour les cavaliers.'),
  (23, 36, 10, 'D''ailleurs, est-ce sans la volonté de l''Éternel que je suis monté contre ce pays pour le détruire? L''Éternel m''a dit: Monte contre ce pays, et détruis-le.'),
  (23, 36, 11, 'Éliakim, Schebna et Joach dirent à Rabschaké: Parle à tes serviteurs en araméen, car nous le comprenons; et ne nous parle pas en langue judaïque aux oreilles du peuple qui est sur la muraille.'),
  (23, 36, 12, 'Rabschaké répondit: Est-ce à ton maître et à toi que mon maître m''a envoyé dire ces paroles? N''est-ce pas à ces hommes assis sur la muraille pour manger leurs excréments et pour boire leur urine avec vous?'),
  (23, 36, 13, 'Puis Rabschaké s''avança et cria de toute sa force en langue judaïque: Écoutez les paroles du grand roi, du roi d''Assyrie!'),
  (23, 36, 14, 'Ainsi parle le roi: Qu''Ézéchias ne vous abuse point, car il ne pourra vous délivrer.'),
  (23, 36, 15, 'Qu''Ézéchias ne vous amène point à vous confier en l''Éternel, en disant: L''Éternel nous délivrera, cette ville ne sera pas livrée entre les mains du roi d''Assyrie.'),
  (23, 36, 16, 'N''écoutez point Ézéchias; car ainsi parle le roi d''Assyrie: Faites la paix avec moi, rendez-vous à moi, et chacun de vous mangera de sa vigne et de son figuier, et chacun boira de l''eau de sa citerne,'),
  (23, 36, 17, 'jusqu''à ce que je vienne, et que je vous emmène dans un pays comme le vôtre, dans un pays de blé et de vin, un pays de pain et de vignes.'),
  (23, 36, 18, 'Qu''Ézéchias ne vous séduise point, en disant: L''Éternel nous délivrera. Les dieux des nations ont-ils délivré chacun son pays de la main du roi d''Assyrie?'),
  (23, 36, 19, 'Où sont les dieux de Hamath et d''Arpad? Où sont les dieux de Sepharvaïm? Ont-ils délivré Samarie de ma main?'),
  (23, 36, 20, 'Parmi tous les dieux de ces pays, quels sont ceux qui ont délivré leur pays de ma main, pour que l''Éternel délivre Jérusalem de ma main?'),
  (23, 36, 21, 'Mais ils se turent, et ne lui répondirent pas un mot; car le roi avait donné cet ordre: Vous ne lui répondrez pas.'),
  (23, 36, 22, 'Et Éliakim, fils de Hilkija, chef de la maison du roi, Schebna, le secrétaire, et Joach, fils d''Asaph, l''archiviste, vinrent auprès d''Ézéchias, les vêtements déchirés, et lui rapportèrent les paroles de Rabschaké.'),
  (23, 37, 1, 'Lorsque le roi Ézéchias eut entendu cela, il déchira ses vêtements, se couvrit d''un sac, et alla dans la maison de l''Éternel.'),
  (23, 37, 2, 'Il envoya Éliakim, chef de la maison du roi, Schebna, le secrétaire, et les plus anciens des sacrificateurs, couverts de sacs, vers Ésaïe, le prophète, fils d''Amots.'),
  (23, 37, 3, 'Et ils lui dirent: Ainsi parle Ézéchias: Ce jour est un jour d''angoisse, de châtiment et d''opprobre; car les enfants sont près de sortir du sein maternel, et il n''y a point de force pour l''enfantement.'),
  (23, 37, 4, 'Peut-être l''Éternel, ton Dieu, a-t-il entendu les paroles de Rabschaké, que le roi d''Assyrie, son maître, a envoyé pour insulter le Dieu vivant, et peut-être l''Éternel, ton Dieu, exercera-t-il ses châtiments à cause des paroles qu''il a entendues. Fais donc monter une prière pour le reste qui subsiste encore.'),
  (23, 37, 5, 'Les serviteurs du roi Ézéchias allèrent donc auprès d''Ésaïe.'),
  (23, 37, 6, 'Et Ésaïe leur dit: Voici ce que vous direz à votre maître: Ainsi parle l''Éternel: Ne t''effraie point des paroles que tu as entendues et par lesquelles m''ont outragé les serviteurs du roi d''Assyrie.'),
  (23, 37, 7, 'Je vais mettre en lui un esprit tel que, sur une nouvelle qu''il recevra, il retournera dans son pays; et je le ferai tomber par l''épée dans son pays.'),
  (23, 37, 8, 'Rabschaké, s''étant retiré, trouva le roi d''Assyrie qui attaquait Libna, car il avait appris son départ de Lakis.'),
  (23, 37, 9, 'Alors le roi d''Assyrie reçut une nouvelle au sujet de Tirhaka, roi d''Éthiopie; on lui dit: Il s''est mis en marche pour te faire la guerre. Dès qu''il eut entendu cela, il envoya des messagers à Ézéchias, en disant:'),
  (23, 37, 10, 'Vous parlerez ainsi à Ézéchias, roi de Juda: Que ton Dieu, auquel tu te confies, ne t''abuse point en disant: Jérusalem ne sera pas livrée entre les mains du roi d''Assyrie.'),
  (23, 37, 11, 'Voici, tu as appris ce qu''ont fait les rois d''Assyrie à tous les pays, et comment ils les ont détruits; et toi, tu serais délivré!'),
  (23, 37, 12, 'Les dieux des nations que mes pères ont détruites les ont-ils délivrées, Gozan, Charan, Retseph, et les fils d''Éden qui sont à Telassar?'),
  (23, 37, 13, 'Où sont le roi de Hamath, le roi d''Arpad, et le roi de la ville de Sepharvaïm, d''Héna et d''Ivva?'),
  (23, 37, 14, 'Ézéchias prit la lettre de la main des messagers, et la lut. Puis il monta à la maison de l''Éternel, et la déploya devant l''Éternel,'),
  (23, 37, 15, 'à qui il adressa cette prière:'),
  (23, 37, 16, 'Éternel des armées, Dieu d''Israël, assis sur les chérubins! C''est toi qui es le seul Dieu de tous les royaumes de la terre, c''est toi qui as fait les cieux et la terre.'),
  (23, 37, 17, 'Éternel, incline ton oreille, et écoute! Éternel, ouvre tes yeux, et regarde! Entends toutes les paroles que Sanchérib a envoyées pour insulter au Dieu vivant!'),
  (23, 37, 18, 'Il est vrai, ô Éternel! que les rois d''Assyrie ont ravagé tous les pays et leur propre pays,'),
  (23, 37, 19, 'et qu''ils ont jeté leurs dieux dans le feu; mais ce n''étaient point des dieux, c''étaient des ouvrages de mains d''homme, du bois et de la pierre; et ils les ont anéantis.'),
  (23, 37, 20, 'Maintenant, Éternel, notre Dieu, délivre-nous de la main de Sanchérib, et que tous les royaumes de la terre sachent que toi seul es l''Éternel!'),
  (23, 37, 21, 'Alors Ésaïe, fils d''Amots, envoya dire à Ézéchias: Ainsi parle l''Éternel, le Dieu d''Israël: J''ai entendu la prière que tu m''as adressée au sujet de Sanchérib, roi d''Assyrie.'),
  (23, 37, 22, 'Voici la parole que l''Éternel a prononcée contre lui: Elle te méprise, elle se moque de toi, La vierge, fille de Sion; Elle hoche la tête après toi, La fille de Jérusalem.'),
  (23, 37, 23, 'Qui as-tu insulté et outragé? Contre qui as-tu élevé la voix? Tu as porté tes yeux en haut Sur le Saint d''Israël.'),
  (23, 37, 24, 'Par tes serviteurs tu as insulté le Seigneur, Et tu as dit: Avec la multitude de mes chars, J''ai gravi le sommet des montagnes, Les extrémités du Liban; Je couperai les plus élevés de ses cèdres, Les plus beaux de ses cyprès, Et j''atteindrai sa dernière cime, Sa forêt semblable à un verger;'),
  (23, 37, 25, 'J''ai ouvert des sources, et j''en ai bu les eaux, Et je tarirai avec la plante de mes pieds Tous les fleuves de l''Égypte.'),
  (23, 37, 26, 'N''as-tu pas appris que j''ai préparé ces choses de loin, Et que je les ai résolues dès les temps anciens? Maintenant j''ai permis qu''elles s''accomplissent, Et que tu réduisisses des villes fortes en monceaux de ruines.'),
  (23, 37, 27, 'Leurs habitants sont impuissants, Épouvantés et confus; Ils sont comme l''herbe des champs et la tendre verdure, Comme le gazon des toits Et le blé qui sèche avant la formation de sa tige.'),
  (23, 37, 28, 'Mais je sais quand tu t''assieds, quand tu sors et quand tu entres, Et quand tu es furieux contre moi.'),
  (23, 37, 29, 'Parce que tu es furieux contre moi, Et que ton arrogance est montée à mes oreilles, Je mettrai ma boucle à tes narines et mon mors entre tes lèvres, Et je te ferai retourner par le chemin par lequel tu es venu.'),
  (23, 37, 30, 'Que ceci soit un signe pour toi: On a mangé une année le produit du grain tombé, et une seconde année ce qui croît de soi-même; mais la troisième année, vous sèmerez, vous moissonnerez, vous planterez des vignes, et vous en mangerez le fruit.'),
  (23, 37, 31, 'Ce qui aura été sauvé de la maison de Juda, ce qui sera resté poussera encore des racines par-dessous, et portera du fruit par-dessus.'),
  (23, 37, 32, 'Car de Jérusalem il sortira un reste, et de la montagne de Sion des réchappés. Voilà ce que fera le zèle de l''Éternel des armées.'),
  (23, 37, 33, 'C''est pourquoi ainsi parle l''Éternel sur le roi d''Assyrie: Il n''entrera point dans cette ville, Il n''y lancera point de traits, Il ne lui présentera point de boucliers, Et il n''élèvera point de retranchements contre elle.'),
  (23, 37, 34, 'Il s''en retournera par le chemin par lequel il est venu, Et il n''entrera point dans cette ville, dit l''Éternel.'),
  (23, 37, 35, 'Je protégerai cette ville pour la sauver, A cause de moi, et à cause de David, mon serviteur.'),
  (23, 37, 36, 'L''ange de l''Éternel sortit, et frappa dans le camp des Assyriens cent quatre-vingt-cinq mille hommes. Et quand on se leva le matin, voici, c''étaient tous des corps morts.'),
  (23, 37, 37, 'Alors Sanchérib, roi d''Assyrie, leva son camp, partit et s''en retourna; et il resta à Ninive.'),
  (23, 37, 38, 'Or, comme il était prosterné dans la maison de Nisroc, son dieu, Adrammélec et Scharetser, ses fils, le frappèrent par l''épée, et s''enfuirent au pays d''Ararat. Et Esar-Haddon, son fils, régna à sa place.'),
  (23, 38, 1, 'En ce temps-là, Ézéchias fut malade à la mort. Le prophète Ésaïe, fils d''Amots, vint auprès de lui, et lui dit: Ainsi parle l''Éternel: Donne tes ordres à ta maison, car tu vas mourir, et tu ne vivras plus.'),
  (23, 38, 2, 'Ézéchias tourna son visage contre le mur, et fit cette prière à l''Éternel:'),
  (23, 38, 3, 'O Éternel! souviens-toi que j''ai marché devant ta face avec fidélité et intégrité de cœur, et que j''ai fait ce qui est bien à tes yeux! Et Ézéchias répandit d''abondantes larmes.'),
  (23, 38, 4, 'Puis la parole de l''Éternel fut adressée à Ésaïe, en ces mots:'),
  (23, 38, 5, 'Va, et dis à Ézéchias: Ainsi parle l''Éternel, le Dieu de David, ton père: J''ai entendu ta prière, j''ai vu tes larmes. Voici, j''ajouterai à tes jours quinze années.'),
  (23, 38, 6, 'Je te délivrerai, toi et cette ville, de la main du roi d''Assyrie; je protégerai cette ville.'),
  (23, 38, 7, 'Et voici, de la part de l''Éternel, le signe auquel tu connaîtras que l''Éternel accomplira la parole qu''il a prononcée.'),
  (23, 38, 8, 'Je ferai reculer de dix degrés en arrière avec le soleil l''ombre des degrés qui est descendue sur les degrés d''Achaz. Et le soleil recula de dix degrés sur les degrés où il était descendu.'),
  (23, 38, 9, 'Cantique d''Ézéchias, roi de Juda, sur sa maladie et sur son rétablissement.'),
  (23, 38, 10, 'Je disais: Quand mes jours sont en repos, je dois m''en aller Aux portes du séjour des morts. Je suis privé du reste de mes années!'),
  (23, 38, 11, 'Je disais: Je ne verrai plus l''Éternel, L''Éternel, sur la terre des vivants; Je ne verrai plus aucun homme Parmi les habitants du monde!'),
  (23, 38, 12, 'Ma demeure est enlevée et transportée loin de moi, Comme une tente de berger; Je sens le fil de ma vie coupé comme par un tisserand Qui me retrancherait de sa trame. Du jour à la nuit tu m''auras achevé!'),
  (23, 38, 13, 'Je me suis contenu jusqu''au matin; Comme un lion, il brisait tous mes os, Du jour à la nuit tu m''auras achevé!'),
  (23, 38, 14, 'Je poussais des cris comme une hirondelle en voltigeant, Je gémissais comme la colombe; Mes yeux s''élevaient languissants vers le ciel: O Éternel! je suis dans l''angoisse, secours-moi!'),
  (23, 38, 15, 'Que dirai-je? Il m''a répondu, et il m''a exaucé. Je marcherai humblement jusqu''au terme de mes années, Après avoir été ainsi affligé.'),
  (23, 38, 16, 'Seigneur, c''est par tes bontés qu''on jouit de la vie, C''est par elles que je respire encore; Tu me rétablis, tu me rends à la vie.'),
  (23, 38, 17, 'Voici, mes souffrances mêmes sont devenues mon salut; Tu as pris plaisir à retirer mon âme de la fosse du néant, Car tu as jeté derrière toi tous mes péchés.'),
  (23, 38, 18, 'Ce n''est pas le séjour des morts qui te loue, Ce n''est pas la mort qui te célèbre; Ceux qui sont descendus dans la fosse n''espèrent plus en ta fidélité.'),
  (23, 38, 19, 'Le vivant, le vivant, c''est celui-là qui te loue, Comme moi aujourd''hui; Le père fait connaître à ses enfants ta fidélité.'),
  (23, 38, 20, 'L''Éternel m''a sauvé! Nous ferons résonner les cordes de nos instruments, Tous les jours de notre vie, Dans la maison de l''Éternel.'),
  (23, 38, 21, 'Ésaïe avait dit: Qu''on apporte une masse de figues, et qu''on les étende sur l''ulcère; et Ézéchias vivra.'),
  (23, 38, 22, 'Et Ézéchias avait dit: A quel signe connaîtrai-je que je monterai à la maison de l''Éternel?'),
  (23, 39, 1, 'En ce même temps, Merodac-Baladan, fils de Baladan, roi de Babylone, envoya une lettre et un présent à Ézéchias, parce qu''il avait appris sa maladie et son rétablissement.'),
  (23, 39, 2, 'Ézéchias en eut de la joie, et il montra aux envoyés le lieu où étaient ses choses de prix, l''argent et l''or, les aromates et l''huile précieuse, tout son arsenal, et tout ce qui se trouvait dans ses trésors: il n''y eut rien qu''Ézéchias ne leur fît voir dans sa maison et dans tous ses domaines.'),
  (23, 39, 3, 'Ésaïe, le prophète, vint ensuite auprès du roi Ézéchias, et lui dit: Qu''ont dit ces gens-là, et d''où sont-ils venus vers toi? Ézéchias répondit: Ils sont venus vers moi d''un pays éloigné, de Babylone.'),
  (23, 39, 4, 'Ésaïe dit encore: Qu''ont-ils vu dans ta maison? Ézéchias répondit: Ils ont vu tout ce qui est dans ma maison: il n''y a rien dans mes trésors que je ne leur aie fait voir.'),
  (23, 39, 5, 'Alors Ésaïe dit à Ézéchias: Écoute la parole de l''Éternel des armées!'),
  (23, 39, 6, 'Voici, les temps viendront où l''on emportera à Babylone tout ce qui est dans ta maison et ce que tes pères ont amassé jusqu''à ce jour; il n''en restera rien, dit l''Éternel.'),
  (23, 39, 7, 'Et l''on prendra de tes fils, qui seront sortis de toi, que tu auras engendrés, pour en faire des eunuques dans le palais du roi de Babylone.'),
  (23, 39, 8, 'Ézéchias répondit à Ésaïe: La parole de l''Éternel, que tu as prononcée, est bonne; car, ajouta-t-il, il y aura paix et sécurité pendant ma vie.'),
  (23, 40, 1, 'Consolez, consolez mon peuple, Dit votre Dieu.'),
  (23, 40, 2, 'Parlez au cœur de Jérusalem, et criez lui Que sa servitude est finie, Que son iniquité est expiée, Qu''elle a reçu de la main de l''Éternel Au double de tous ses péchés.'),
  (23, 40, 3, 'Une voix crie: Préparez au désert le chemin de l''Éternel, Aplanissez dans les lieux arides Une route pour notre Dieu.'),
  (23, 40, 4, 'Que toute vallée soit exhaussée, Que toute montagne et toute colline soient abaissées! Que les coteaux se changent en plaines, Et les défilés étroits en vallons!'),
  (23, 40, 5, 'Alors la gloire de l''Éternel sera révélée, Et au même instant toute chair la verra; Car la bouche de l''Éternel a parlé.'),
  (23, 40, 6, 'Une voix dit: Crie! -Et il répond: Que crierai-je? Toute chair est comme l''herbe, Et tout son éclat comme la fleur des champs.'),
  (23, 40, 7, 'L''herbe sèche, la fleur tombe, Quand le vent de l''Éternel souffle dessus. -Certainement le peuple est comme l''herbe:'),
  (23, 40, 8, 'L''herbe sèche, la fleur tombe; Mais la parole de notre Dieu subsiste éternellement.'),
  (23, 40, 9, 'Monte sur une haute montagne, Sion, pour publier la bonne nouvelle; Élève avec force ta voix, Jérusalem, pour publier la bonne nouvelle; Élève ta voix, ne crains point, Dis aux villes de Juda: Voici votre Dieu!'),
  (23, 40, 10, 'Voici, le Seigneur, l''Éternel vient avec puissance, Et de son bras il commande; Voici, le salaire est avec lui, Et les rétributions le précèdent.'),
  (23, 40, 11, 'Comme un berger, il paîtra son troupeau, Il prendra les agneaux dans ses bras, Et les portera dans son sein; Il conduira les brebis qui allaitent.'),
  (23, 40, 12, 'Qui a mesuré les eaux dans le creux de sa main, Pris les dimensions des cieux avec la paume, Et ramassé la poussière de la terre dans un tiers de mesure? Qui a pesé les montagnes au crochet, Et les collines à la balance?'),
  (23, 40, 13, 'Qui a sondé l''esprit de l''Éternel, Et qui l''a éclairé de ses conseils?'),
  (23, 40, 14, 'Avec qui a-t-il délibéré pour en recevoir de l''instruction? Qui lui a appris le sentier de la justice? Qui lui a enseigné la sagesse, Et fait connaître le chemin de l''intelligence?'),
  (23, 40, 15, 'Voici, les nations sont comme une goutte d''un seau, Elles sont comme de la poussière sur une balance; Voici, les îles sont comme une fine poussière qui s''envole.'),
  (23, 40, 16, 'Le Liban ne suffit pas pour le feu, Et ses animaux ne suffisent pas pour l''holocauste.'),
  (23, 40, 17, 'Toutes les nations sont devant lui comme un rien, Elles ne sont pour lui que néant et vanité.'),
  (23, 40, 18, 'A qui voulez-vous comparer Dieu? Et quelle image ferez-vous son égale?'),
  (23, 40, 19, 'C''est un ouvrier qui fond l''idole, Et c''est un orfèvre qui la couvre d''or, Et y soude des chaînettes d''argent.'),
  (23, 40, 20, 'Celui que la pauvreté oblige à donner peu Choisit un bois qui résiste à la vermoulure; Il se procure un ouvrier capable, Pour faire une idole qui ne branle pas.'),
  (23, 40, 21, 'Ne le savez-vous pas? ne l''avez-vous pas appris? Ne vous l''a-t-on pas fait connaître dès le commencement? N''avez-vous jamais réfléchi à la fondation de la terre?'),
  (23, 40, 22, 'C''est lui qui est assis au-dessus du cercle de la terre, Et ceux qui l''habitent sont comme des sauterelles; Il étend les cieux comme une étoffe légère, Il les déploie comme une tente, pour en faire sa demeure.'),
  (23, 40, 23, 'C''est lui qui réduit les princes au néant, Et qui fait des juges de la terre une vanité;'),
  (23, 40, 24, 'Ils ne sont pas même plantés, pas même semés, Leur tronc n''a pas même de racine en terre: Il souffle sur eux, et ils se dessèchent, Et un tourbillon les emporte comme le chaume.'),
  (23, 40, 25, 'A qui me comparerez-vous, pour que je lui ressemble? Dit le Saint.'),
  (23, 40, 26, 'Levez vos yeux en haut, et regardez! Qui a créé ces choses? Qui fait marcher en ordre leur armée? Il les appelle toutes par leur nom; Par son grand pouvoir et par sa force puissante, Il n''en est pas une qui fasse défaut.'),
  (23, 40, 27, 'Pourquoi dis-tu, Jacob, Pourquoi dis-tu, Israël: Ma destinée est cachée devant l''Éternel, Mon droit passe inaperçu devant mon Dieu?'),
  (23, 40, 28, 'Ne le sais-tu pas? ne l''as-tu pas appris? C''est le Dieu d''éternité, l''Éternel, Qui a créé les extrémités de la terre; Il ne se fatigue point, il ne se lasse point; On ne peut sonder son intelligence.'),
  (23, 40, 29, 'Il donne de la force à celui qui est fatigué, Et il augmente la vigueur de celui qui tombe en défaillance.'),
  (23, 40, 30, 'Les adolescents se fatiguent et se lassent, Et les jeunes hommes chancellent;'),
  (23, 40, 31, 'Mais ceux qui se confient en l''Éternel renouvellent leur force. Ils prennent le vol comme les aigles; Ils courent, et ne se lassent point, Ils marchent, et ne se fatiguent point.'),
  (23, 41, 1, 'Iles, faites silence pour m''écouter! Que les peuples raniment leur force, Qu''ils avancent, et qu''ils parlent! Approchons pour plaider ensemble.'),
  (23, 41, 2, 'Qui a suscité de l''orient Celui que le salut appelle à sa suite? Qui lui a livré les nations et assujetti des rois? Qui a réduit leur glaive en poussière, Et leur arc en un chaume qui s''envole?'),
  (23, 41, 3, 'Il s''est mis à leur poursuite, il a parcouru avec bonheur Un chemin que son pied n''avait jamais foulé.'),
  (23, 41, 4, 'Qui a fait et exécuté ces choses? C''est celui qui a appelé les générations dès le commencement, Moi, l''Éternel, le premier Et le même jusqu''aux derniers âges.'),
  (23, 41, 5, 'Les îles le voient, et sont dans la crainte, Les extrémités de la terre tremblent: Ils s''approchent, ils viennent.'),
  (23, 41, 6, 'Ils s''aident l''un l''autre, Et chacun dit à son frère: Courage!'),
  (23, 41, 7, 'Le sculpteur encourage le fondeur; Celui qui polit au marteau encourage celui qui frappe sur l''enclume; Il dit de la soudure: Elle est bonne! Et il fixe l''idole avec des clous, pour qu''elle ne branle pas.'),
  (23, 41, 8, 'Mais toi, Israël, mon serviteur, Jacob, que j''ai choisi, Race d''Abraham que j''ai aimé!'),
  (23, 41, 9, 'Toi, que j''ai pris aux extrémités de la terre, Et que j''ai appelé d''une contrée lointaine, A qui j''ai dit: Tu es mon serviteur, Je te choisis, et ne te rejette point!'),
  (23, 41, 10, 'Ne crains rien, car je suis avec toi; Ne promène pas des regards inquiets, car je suis ton Dieu; Je te fortifie, je viens à ton secours, Je te soutiens de ma droite triomphante.'),
  (23, 41, 11, 'Voici, ils seront confondus, ils seront couverts de honte, Tous ceux qui sont irrités contre toi; Ils seront réduits à rien, ils périront, Ceux qui disputent contre toi.'),
  (23, 41, 12, 'Tu les chercheras, et ne les trouveras plus, Ceux qui te suscitaient querelle; Ils seront réduits à rien, réduits au néant, Ceux qui te faisaient la guerre.'),
  (23, 41, 13, 'Car je suis l''Éternel, ton Dieu, Qui fortifie ta droite, Qui te dis: Ne crains rien, Je viens à ton secours.'),
  (23, 41, 14, 'Ne crains rien, vermisseau de Jacob, Faible reste d''Israël; Je viens à ton secours, dit l''Éternel, Et le Saint d''Israël est ton sauveur.'),
  (23, 41, 15, 'Voici, je fais de toi un traîneau aigu, tout neuf, Garni de pointes; Tu écraseras, tu broieras les montagnes, Et tu rendras les collines semblables à de la balle.'),
  (23, 41, 16, 'Tu les vanneras, et le vent les emportera, Et un tourbillon les dispersera. Mais toi, tu te réjouiras en l''Éternel, Tu mettras ta gloire dans le Saint d''Israël.'),
  (23, 41, 17, 'Les malheureux et les indigents cherchent de l''eau, et il n''y en a point; Leur langue est desséchée par la soif. Moi, l''Éternel, je les exaucerai; Moi, le Dieu d''Israël, je ne les abandonnerai pas.'),
  (23, 41, 18, 'Je ferai jaillir des fleuves sur les collines, Et des sources au milieu des vallées; Je changerai le désert en étang, Et la terre aride en courants d''eau;'),
  (23, 41, 19, 'Je mettrai dans le désert le cèdre, l''acacia, Le myrte et l''olivier; Je mettrai dans les lieux stériles Le cyprès, l''orme et le buis, tous ensemble;'),
  (23, 41, 20, 'Afin qu''ils voient, qu''ils sachent, Qu''ils observent et considèrent Que la main de l''Éternel a fait ces choses, Que le Saint d''Israël en est l''auteur.'),
  (23, 41, 21, 'Plaidez votre cause, Dit l''Éternel; Produisez vos moyens de défense, Dit le roi de Jacob.'),
  (23, 41, 22, 'Qu''ils les produisent, et qu''ils nous déclarent Ce qui doit arriver. Quelles sont les prédictions que jadis vous avez faites? Dites-le, pour que nous y prenions garde, Et que nous en reconnaissions l''accomplissement; Ou bien, annoncez-nous l''avenir.'),
  (23, 41, 23, 'Dites ce qui arrivera plus tard, Pour que nous sachions si vous êtes des dieux; Faites seulement quelque chose de bien ou de mal, Pour que nous le voyions et le regardions ensemble.'),
  (23, 41, 24, 'Voici, vous n''êtes rien, Et votre œuvre est le néant; C''est une abomination que de se complaire en vous.'),
  (23, 41, 25, 'Je l''ai suscité du septentrion, et il est venu; De l''orient, il invoque mon nom; Il foule les puissants comme de la boue, Comme de l''argile que foule un potier.'),
  (23, 41, 26, 'Qui l''a annoncé dès le commencement, pour que nous le sachions, Et longtemps d''avance, pour que nous disions: C''est vrai? Nul ne l''a annoncé, nul ne l''a prédit, Et personne n''a entendu vos paroles.'),
  (23, 41, 27, 'C''est moi le premier qui ai dit à Sion: Les voici, les voici! Et à Jérusalem: J''envoie un messager de bonnes nouvelles!'),
  (23, 41, 28, 'Je regarde, et il n''y a personne, Personne parmi eux qui prophétise, Et qui puisse répondre, si je l''interroge.'),
  (23, 41, 29, 'Voici, ils ne sont tous que vanité, Leurs œuvres ne sont que néant, Leurs idoles ne sont qu''un vain souffle.'),
  (23, 42, 1, 'Voici mon serviteur, que je soutiendrai, Mon élu, en qui mon âme prend plaisir. J''ai mis mon esprit sur lui; Il annoncera la justice aux nations.'),
  (23, 42, 2, 'Il ne criera point, il n''élèvera point la voix, Et ne la fera point entendre dans les rues.'),
  (23, 42, 3, 'Il ne brisera point le roseau cassé, Et il n''éteindra point la mèche qui brûle encore; Il annoncera la justice selon la vérité.'),
  (23, 42, 4, 'Il ne se découragera point et ne se relâchera point, Jusqu''à ce qu''il ait établi la justice sur la terre, Et que les îles espèrent en sa loi.'),
  (23, 42, 5, 'Ainsi parle Dieu, l''Éternel, Qui a créé les cieux et qui les a déployés, Qui a étendu la terre et ses productions, Qui a donné la respiration à ceux qui la peuplent, Et le souffle à ceux qui y marchent.'),
  (23, 42, 6, 'Moi, l''Éternel, je t''ai appelé pour le salut, Et je te prendrai par la main, Je te garderai, et je t''établirai pour traiter alliance avec le peuple, Pour être la lumière des nations,'),
  (23, 42, 7, 'Pour ouvrir les yeux des aveugles, Pour faire sortir de prison le captif, Et de leur cachot ceux qui habitent dans les ténèbres.'),
  (23, 42, 8, 'Je suis l''Éternel, c''est là mon nom; Et je ne donnerai pas ma gloire à un autre, Ni mon honneur aux idoles.'),
  (23, 42, 9, 'Voici, les premières choses se sont accomplies, Et je vous en annonce de nouvelles; Avant qu''elles arrivent, je vous les prédis.'),
  (23, 42, 10, 'Chantez à l''Éternel un cantique nouveau, Chantez ses louanges aux extrémités de la terre, Vous qui voguez sur la mer et vous qui la peuplez, Iles et habitants des îles!'),
  (23, 42, 11, 'Que le désert et ses villes élèvent la voix! Que les villages occupés par Kédar élèvent la voix! Que les habitants des rochers tressaillent d''allégresse! Que du sommet des montagnes retentissent des cris de joie!'),
  (23, 42, 12, 'Qu''on rende gloire à l''Éternel, Et que dans les îles on publie ses louanges!'),
  (23, 42, 13, 'L''Éternel s''avance comme un héros, Il excite son ardeur comme un homme de guerre; Il élève la voix, il jette des cris, Il manifeste sa force contre ses ennemis.'),
  (23, 42, 14, 'J''ai longtemps gardé le silence, je me suis tu, je me suis contenu; Je crierai comme une femme en travail, Je serai haletant et je soufflerai tout à la fois.'),
  (23, 42, 15, 'Je ravagerai montagnes et collines, Et j''en dessécherai toute la verdure; Je changerai les fleuves en terre ferme, Et je mettrai les étangs à sec.'),
  (23, 42, 16, 'Je ferai marcher les aveugles sur un chemin qu''ils ne connaissent pas, Je les conduirai par des sentiers qu''ils ignorent; Je changerai devant eux les ténèbres en lumière, Et les endroits tortueux en plaine: Voilà ce que je ferai, et je ne les abandonnerai point.'),
  (23, 42, 17, 'Ils reculeront, ils seront confus, Ceux qui se confient aux idoles taillées, Ceux qui disent aux idoles de fonte: Vous êtes nos dieux!'),
  (23, 42, 18, 'Sourds, écoutez! Aveugles, regardez et voyez!'),
  (23, 42, 19, 'Qui est aveugle, sinon mon serviteur, Et sourd comme mon messager que j''envoie? Qui est aveugle, comme l''ami de Dieu, Aveugle comme le serviteur de l''Éternel?'),
  (23, 42, 20, 'Tu as vu beaucoup de choses, mais tu n''y as point pris garde; On a ouvert les oreilles, mais on n''a point entendu.'),
  (23, 42, 21, 'L''Éternel a voulu, pour le bonheur d''Israël, Publier une loi grande et magnifique.'),
  (23, 42, 22, 'Et c''est un peuple pillé et dépouillé! On les a tous enchaînés dans des cavernes, Plongés dans des cachots; Ils ont été mis au pillage, et personne qui les délivre! Dépouillés, et personne qui dise: Restitue!'),
  (23, 42, 23, 'Qui parmi vous prêtera l''oreille à ces choses? Qui voudra s''y rendre attentif et écouter à l''avenir?'),
  (23, 42, 24, 'Qui a livré Jacob au pillage, Et Israël aux pillards? N''est-ce pas l''Éternel? Nous avons péché contre lui. Ils n''ont point voulu marcher dans ses voies, Et ils n''ont point écouté sa loi.'),
  (23, 42, 25, 'Aussi a-t-il versé sur Israël l''ardeur de sa colère Et la violence de la guerre; La guerre l''a embrasé de toutes parts, et il n''a point compris; Elle l''a consumé, et il n''y a point pris garde.'),
  (23, 43, 1, 'Ainsi parle maintenant l''Éternel, qui t''a créé, ô Jacob! Celui qui t''a formé, ô Israël! Ne crains rien, car je te rachète, Je t''appelle par ton nom: tu es à moi!'),
  (23, 43, 2, 'Si tu traverses les eaux, je serai avec toi; Et les fleuves, ils ne te submergeront point; Si tu marches dans le feu, tu ne te brûleras pas, Et la flamme ne t''embrasera pas.'),
  (23, 43, 3, 'Car je suis l''Éternel, ton Dieu, Le Saint d''Israël, ton sauveur; Je donne l''Égypte pour ta rançon, L''Éthiopie et Saba à ta place.'),
  (23, 43, 4, 'Parce que tu as du prix à mes yeux, Parce que tu es honoré et que je t''aime, Je donne des hommes à ta place, Et des peuples pour ta vie.'),
  (23, 43, 5, 'Ne crains rien, car je suis avec toi; Je ramènerai de l''orient ta race, Et je te rassemblerai de l''occident.'),
  (23, 43, 6, 'Je dirai au septentrion: Donne! Et au midi: Ne retiens point! Fais venir mes fils des pays lointains, Et mes filles de l''extrémité de la terre,'),
  (23, 43, 7, 'Tous ceux qui s''appellent de mon nom, Et que j''ai créés pour ma gloire, Que j''ai formés et que j''ai faits.'),
  (23, 43, 8, 'Qu''on fasse sortir le peuple aveugle, qui a des yeux, Et les sourds, qui ont des oreilles.'),
  (23, 43, 9, 'Que toutes les nations se rassemblent, Et que les peuples se réunissent. Qui d''entre eux a annoncé ces choses? Lesquels nous ont fait entendre les premières prédictions? Qu''ils produisent leurs témoins et établissent leur droit; Qu''on écoute et qu''on dise: C''est vrai!'),
  (23, 43, 10, 'Vous êtes mes témoins, dit l''Éternel, Vous, et mon serviteur que j''ai choisi, Afin que vous le sachiez, Que vous me croyiez et compreniez que c''est moi: Avant moi il n''a point été formé de Dieu, Et après moi il n''y en aura point.'),
  (23, 43, 11, 'C''est moi, moi qui suis l''Éternel, Et hors moi il n''y a point de sauveur.'),
  (23, 43, 12, 'C''est moi qui ai annoncé, sauvé, prédit, Ce n''est point parmi vous un dieu étranger; Vous êtes mes témoins, dit l''Éternel, C''est moi qui suis Dieu.'),
  (23, 43, 13, 'Je le suis dès le commencement, Et nul ne délivre de ma main; J''agirai: qui s''y opposera?'),
  (23, 43, 14, 'Ainsi parle l''Éternel, Votre rédempteur, le Saint d''Israël: A cause de vous, j''envoie l''ennemi contre Babylone, Et je fais descendre tous les fuyards, Même les Chaldéens, sur les navires dont ils tiraient gloire.'),
  (23, 43, 15, 'Je suis l''Éternel, votre Saint, Le créateur d''Israël, votre roi.'),
  (23, 43, 16, 'Ainsi parle l''Éternel, Qui fraya dans la mer un chemin, Et dans les eaux puissantes un sentier,'),
  (23, 43, 17, 'Qui mit en campagne des chars et des chevaux, Une armée et de vaillants guerriers, Soudain couchés ensemble, pour ne plus se relever, Anéantis, éteints comme une mèche:'),
  (23, 43, 18, 'Ne pensez plus aux événements passés, Et ne considérez plus ce qui est ancien.'),
  (23, 43, 19, 'Voici, je vais faire une chose nouvelle, sur le point d''arriver: Ne la connaîtrez-vous pas? Je mettrai un chemin dans le désert, Et des fleuves dans la solitude.'),
  (23, 43, 20, 'Les bêtes des champs me glorifieront, Les chacals et les autruches, Parce que j''aurai mis des eaux dans le désert, Des fleuves dans la solitude, Pour abreuver mon peuple, mon élu.'),
  (23, 43, 21, 'Le peuple que je me suis formé Publiera mes louanges.'),
  (23, 43, 22, 'Et tu ne m''as pas invoqué, ô Jacob! Car tu t''es lassé de moi, ô Israël!'),
  (23, 43, 23, 'Tu ne m''as pas offert tes brebis en holocauste, Et tu ne m''as pas honoré par tes sacrifices; Je ne t''ai point tourmenté pour des offrandes, Et je ne t''ai point fatigué pour de l''encens.'),
  (23, 43, 24, 'Tu n''as pas à prix d''argent acheté pour moi des aromates, Et tu ne m''as pas rassasié de la graisse de tes sacrifices; Mais tu m''as tourmenté par tes péchés, Tu m''as fatigué par tes iniquités.'),
  (23, 43, 25, 'C''est moi, moi qui efface tes transgressions pour l''amour de moi, Et je ne me souviendrai plus de tes péchés.'),
  (23, 43, 26, 'Réveille ma mémoire, plaidons ensemble, Parle toi-même, pour te justifier.'),
  (23, 43, 27, 'Ton premier père a péché, Et tes interprètes se sont rebellés contre moi.'),
  (23, 43, 28, 'C''est pourquoi j''ai traité en profanes les chefs du sanctuaire, J''ai livré Jacob à la destruction, Et Israël aux outrages.'),
  (23, 44, 1, 'Écoute maintenant, ô Jacob, mon serviteur! O Israël, que j''ai choisi!'),
  (23, 44, 2, 'Ainsi parle l''Éternel, qui t''a fait, Et qui t''a formé dès ta naissance, Celui qui est ton soutien: Ne crains rien, mon serviteur Jacob, Mon Israël, que j''ai choisi.'),
  (23, 44, 3, 'Car je répandrai des eaux sur le sol altéré, Et des ruisseaux sur la terre desséchée; Je répandrai mon esprit sur ta race, Et ma bénédiction sur tes rejetons.'),
  (23, 44, 4, 'Ils pousseront comme au milieu de l''herbe, Comme les saules près des courants d''eau.'),
  (23, 44, 5, 'Celui-ci dira: Je suis à l''Éternel; Celui-là se réclamera du nom de Jacob; Cet autre écrira de sa main: à l''Éternel! Et prononcera avec amour le nom d''Israël.'),
  (23, 44, 6, 'Ainsi parle l''Éternel, roi d''Israël et son rédempteur, L''Éternel des armées: Je suis le premier et je suis le dernier, Et hors moi il n''y a point de Dieu.'),
  (23, 44, 7, 'Qui a, comme moi, fait des prédictions (Qu''il le déclare et me le prouve!), Depuis que j''ai fondé le peuple ancien? Qu''ils annoncent l''avenir et ce qui doit arriver!'),
  (23, 44, 8, 'N''ayez pas peur, et ne tremblez pas; Ne te l''ai-je pas dès longtemps annoncé et déclaré? Vous êtes mes témoins: Y a-t-il un autre Dieu que moi? Il n''y a pas d''autre rocher, je n''en connais point.'),
  (23, 44, 9, 'Ceux qui fabriquent des idoles ne sont tous que vanité, Et leurs plus belles œuvres ne servent à rien; Elles le témoignent elles-mêmes: Elles n''ont ni la vue, ni l''intelligence, Afin qu''ils soient dans la confusion.'),
  (23, 44, 10, 'Qui est-ce qui fabrique un dieu, ou fond une idole, Pour n''en retirer aucune utilité?'),
  (23, 44, 11, 'Voici, tous ceux qui y travaillent seront confondus, Et les ouvriers ne sont que des hommes; Qu''ils se réunissent tous, qu''ils se présentent, Et tous ensemble ils seront tremblants et couverts de honte.'),
  (23, 44, 12, 'Le forgeron fait une hache, Il travaille avec le charbon, Et il la façonne à coups de marteau; Il la forge d''un bras vigoureux; Mais a-t-il faim, le voilà sans force; Ne boit-il pas d''eau, le voilà épuisé.'),
  (23, 44, 13, 'Le charpentier étend le cordeau, Fait un tracé au crayon, Façonne le bois avec un couteau, Et marque ses dimensions avec le compas; Et il produit une figure d''homme, Une belle forme humaine, Pour qu''elle habite dans une maison.'),
  (23, 44, 14, 'Il se coupe des cèdres, Il prend des rouvres et des chênes, Et fait un choix parmi les arbres de la forêt; Il plante des pins, Et la pluie les fait croître.'),
  (23, 44, 15, 'Ces arbres servent à l''homme pour brûler, Il en prend et il se chauffe. Il y met aussi le feu pour cuire du pain; Et il en fait également un dieu, qu''il adore, Il en fait une idole, devant laquelle il se prosterne.'),
  (23, 44, 16, 'Il brûle au feu la moitié de son bois, Avec cette moitié il cuit de la viande, Il apprête un rôti, et se rassasie; Il se chauffe aussi, et dit: Ha! Ha! Je me chauffe, je vois la flamme!'),
  (23, 44, 17, 'Et avec le reste il fait un dieu, son idole, Il se prosterne devant elle, il l''adore, il l''invoque, Et s''écrie: Sauve-moi! Car tu es mon dieu!'),
  (23, 44, 18, 'Ils n''ont ni intelligence, ni entendement, Car on leur a fermé les yeux pour qu''ils ne voient point, Et le cœur pour qu''ils ne comprennent point.'),
  (23, 44, 19, 'Il ne rentre pas en lui-même, Et il n''a ni l''intelligence, ni le bon sens de dire: J''en ai brûlé une moitié au feu, J''ai cuit du pain sur les charbons, J''ai rôti de la viande et je l''ai mangée; Et avec le reste je ferais une abomination! Je me prosternerais devant un morceau de bois!'),
  (23, 44, 20, 'Il se repaît de cendres, Son cœur abusé l''égare, Et il ne sauvera point son âme, et ne dira point: N''est-ce pas du mensonge que j''ai dans ma main?'),
  (23, 44, 21, 'Souviens-toi de ces choses, ô Jacob! O Israël! car tu es mon serviteur; Je t''ai formé, tu es mon serviteur; Israël, je ne t''oublierai pas.'),
  (23, 44, 22, 'J''efface tes transgressions comme un nuage, Et tes péchés comme une nuée; Reviens à moi, Car je t''ai racheté.'),
  (23, 44, 23, 'Cieux, réjouissez-vous! car l''Éternel a agi; Profondeurs de la terre, retentissez d''allégresse! Montagnes, éclatez en cris de joie! Vous aussi, forêts, avec tous vos arbres! Car l''Éternel a racheté Jacob, Il a manifesté sa gloire en Israël.'),
  (23, 44, 24, 'Ainsi parle l''Éternel, ton rédempteur, Celui qui t''a formé dès ta naissance: Moi, l''Éternel, j''ai fait toutes choses, Seul j''ai déployé les cieux, Seul j''ai étendu la terre.'),
  (23, 44, 25, 'J''anéantis les signes des prophètes de mensonge, Et je proclame insensés les devins; Je fais reculer les sages, Et je tourne leur science en folie.'),
  (23, 44, 26, 'Je confirme la parole de mon serviteur, Et j''accomplis ce que prédisent mes envoyés; Je dis de Jérusalem: Elle sera habitée, Et des villes de Juda: Elles seront rebâties; Et je relèverai leurs ruines.'),
  (23, 44, 27, 'Je dis à l''abîme: Dessèche-toi, Je tarirai tes fleuves.'),
  (23, 44, 28, 'Je dis de Cyrus: Il est mon berger, Et il accomplira toute ma volonté; Il dira de Jérusalem: Qu''elle soit rebâtie! Et du temple: Qu''il soit fondé!'),
  (23, 45, 1, 'Ainsi parle l''Éternel à son oint, à Cyrus, Qu''il tient par la main, Pour terrasser les nations devant lui, Et pour relâcher la ceinture des rois, Pour lui ouvrir les portes, Afin qu''elles ne soient plus fermées;'),
  (23, 45, 2, 'Je marcherai devant toi, J''aplanirai les chemins montueux, Je romprai les portes d''airain, Et je briserai les verrous de fer.'),
  (23, 45, 3, 'Je te donnerai des trésors cachés, Des richesses enfouies, Afin que tu saches Que je suis l''Éternel qui t''appelle par ton nom, Le Dieu d''Israël.'),
  (23, 45, 4, 'Pour l''amour de mon serviteur Jacob, Et d''Israël, mon élu, Je t''ai appelé par ton nom, Je t''ai parlé avec bienveillance, avant que tu me connusses.'),
  (23, 45, 5, 'Je suis l''Éternel, et il n''y en a point d''autre, Hors moi il n''y a point de Dieu; Je t''ai ceint, avant que tu me connusses.'),
  (23, 45, 6, 'C''est afin que l''on sache, du soleil levant au soleil couchant, Que hors moi il n''y a point de Dieu: Je suis l''Éternel, et il n''y en a point d''autre.'),
  (23, 45, 7, 'Je forme la lumière, et je crée les ténèbres, Je donne la prospérité, et je crée l''adversité; Moi, l''Éternel, je fais toutes ces choses.'),
  (23, 45, 8, 'Que les cieux répandent d''en haut Et que les nuées laissent couler la justice! Que la terre s''ouvre, que le salut y fructifie, Et qu''il en sorte à la fois la délivrance! Moi, l''Éternel, je crée ces choses.'),
  (23, 45, 9, 'Malheur à qui conteste avec son créateur! -Vase parmi des vases de terre! -L''argile dit-elle à celui qui la façonne: Que fais-tu? Et ton œuvre: Il n''a point de mains?'),
  (23, 45, 10, 'Malheur à qui dit à son père: Pourquoi m''as-tu engendré? Et à sa mère: Pourquoi m''as-tu enfanté?'),
  (23, 45, 11, 'Ainsi parle l''Éternel, le Saint d''Israël, et son créateur: Veut-on me questionner sur l''avenir, Me donner des ordres sur mes enfants et sur l''œuvre de mes mains?'),
  (23, 45, 12, 'C''est moi qui ai fait la terre, Et qui sur elle ai créé l''homme; C''est moi, ce sont mes mains qui ont déployé les cieux, Et c''est moi qui ai disposé toute leur armée.'),
  (23, 45, 13, 'C''est moi qui ai suscité Cyrus dans ma justice, Et j''aplanirai toutes ses voies; Il rebâtira ma ville, et libérera mes captifs, Sans rançon ni présents, Dit l''Éternel des armées.'),
  (23, 45, 14, 'Ainsi parle l''Éternel: Les gains de l''Égypte et les profits de l''Éthiopie, Et ceux des Sabéens à la taille élevée, Passeront chez toi et seront à toi; Ces peuples marcheront à ta suite, Ils passeront enchaînés, Ils se prosterneront devant toi, et te diront en suppliant: C''est auprès de toi seulement que se trouve Dieu, Et il n''y a point d''autre Dieu que lui.'),
  (23, 45, 15, 'Mais tu es un Dieu qui te caches, Dieu d''Israël, sauveur!'),
  (23, 45, 16, 'Ils sont tous honteux et confus, Ils s''en vont tous avec ignominie, Les fabricateurs d''idoles.'),
  (23, 45, 17, 'C''est par l''Éternel qu''Israël obtient le salut, Un salut éternel; Vous ne serez ni honteux ni confus, Jusque dans l''éternité.'),
  (23, 45, 18, 'Car ainsi parle l''Éternel, Le créateur des cieux, le seul Dieu, Qui a formé la terre, qui l''a faite et qui l''a affermie, Qui l''a créée pour qu''elle ne fût pas déserte, Qui l''a formée pour qu''elle fût habitée: Je suis l''Éternel, et il n''y en a point d''autre.'),
  (23, 45, 19, 'Je n''ai point parlé en cachette, Dans un lieu ténébreux de la terre; Je n''ai point dit à la postérité de Jacob: Cherchez-moi vainement! Moi, l''Éternel, je dis ce qui est vrai, Je proclame ce qui est droit.'),
  (23, 45, 20, 'Assemblez-vous et venez, approchez ensemble, Réchappés des nations! Ils n''ont point d''intelligence, ceux qui portent leur idole de bois, Et qui invoquent un dieu incapable de sauver.'),
  (23, 45, 21, 'Déclarez-le, et faites-les venir! Qu''ils prennent conseil les uns des autres! Qui a prédit ces choses dès le commencement, Et depuis longtemps les a annoncées? N''est-ce pas moi, l''Éternel? Il n''y a point d''autre Dieu que moi, Je suis le seul Dieu juste et qui sauve.'),
  (23, 45, 22, 'Tournez-vous vers moi, et vous serez sauvés, Vous tous qui êtes aux extrémités de la terre! Car je suis Dieu, et il n''y en a point d''autre.'),
  (23, 45, 23, 'Je le jure par moi-même, La vérité sort de ma bouche et ma parole ne sera point révoquée: Tout genou fléchira devant moi, Toute langue jurera par moi.'),
  (23, 45, 24, 'En l''Éternel seul, me dira-t-on, résident la justice et la force; A lui viendront, pour être confondus, Tous ceux qui étaient irrités contre lui.'),
  (23, 45, 25, 'Par l''Éternel seront justifiés et glorifiés Tous les descendants d''Israël.'),
  (23, 46, 1, 'Bel s''écroule, Nebo tombe; On met leurs idoles sur des animaux, sur des bêtes; Vous les portiez, et les voilà chargées, Devenues un fardeau pour l''animal fatigué!'),
  (23, 46, 2, 'Ils sont tombés, ils se sont écroulés ensemble, Ils ne peuvent sauver le fardeau, Et ils s''en vont eux-mêmes en captivité.'),
  (23, 46, 3, 'Écoutez-moi, maison de Jacob, Et vous tous, restes de la maison d''Israël, Vous que j''ai pris à ma charge dès votre origine, Que j''ai portés dès votre naissance!'),
  (23, 46, 4, 'Jusqu''à votre vieillesse je serai le même, Jusqu''à votre vieillesse je vous soutiendrai; Je l''ai fait, et je veux encore vous porter, Vous soutenir et vous sauver.'),
  (23, 46, 5, 'A qui me comparerez-vous, pour le faire mon égal? A qui me ferez-vous ressembler, pour que nous soyons semblables?'),
  (23, 46, 6, 'Ils versent l''or de leur bourse, Et pèsent l''argent à la balance; Ils paient un orfèvre, pour qu''il en fasse un dieu, Et ils adorent et se prosternent.'),
  (23, 46, 7, 'Ils le portent, ils le chargent sur l''épaule, Ils le mettent en place, et il y reste; Il ne bouge pas de sa place; Puis on crie vers lui, mais il ne répond pas, Il ne sauve pas de la détresse.'),
  (23, 46, 8, 'Souvenez-vous de ces choses, et soyez des hommes! Pécheurs, rentrez en vous-mêmes!'),
  (23, 46, 9, 'Souvenez-vous de ce qui s''est passé dès les temps anciens; Car je suis Dieu, et il n''y en a point d''autre, Je suis Dieu, et nul n''est semblable à moi.'),
  (23, 46, 10, 'J''annonce dès le commencement ce qui doit arriver, Et longtemps d''avance ce qui n''est pas encore accompli; Je dis: Mes arrêts subsisteront, Et j''exécuterai toute ma volonté.'),
  (23, 46, 11, 'C''est moi qui appelle de l''orient un oiseau de proie, D''une terre lointaine un homme pour accomplir mes desseins, Je l''ai dit, et je le réaliserai; Je l''ai conçu, et je l''exécuterai.'),
  (23, 46, 12, 'Écoutez-moi, gens endurcis de cœur, Ennemis de la droiture!'),
  (23, 46, 13, 'Je fais approcher ma justice: elle n''est pas loin; Et mon salut: il ne tardera pas. Je mettrai le salut en Sion, Et ma gloire sur Israël.'),
  (23, 47, 1, 'Descends, et assieds-toi dans la poussière, Vierge, fille de Babylone! Assieds-toi à terre, sans trône, Fille des Chaldéens! On ne t''appellera plus délicate et voluptueuse.'),
  (23, 47, 2, 'Prends les meules, et mouds de la farine; Ote ton voile, relève les pans de ta robe, Découvre tes jambes, traverse les fleuves!'),
  (23, 47, 3, 'Ta nudité sera découverte, Et ta honte sera vue. J''exercerai ma vengeance, Je n''épargnerai personne. -'),
  (23, 47, 4, 'Notre rédempteur, c''est celui qui s''appelle l''Éternel des armées, C''est le Saint d''Israël. -'),
  (23, 47, 5, 'Assieds-toi en silence, et va dans les ténèbres, Fille des Chaldéens! On ne t''appellera plus la souveraine des royaumes.'),
  (23, 47, 6, 'J''étais irrité contre mon peuple, J''avais profané mon héritage, Et je les avais livrés entre tes mains: Tu n''as pas eu pour eux de la compassion, Tu as durement appesanti ton joug sur le vieillard.'),
  (23, 47, 7, 'Tu disais: A toujours je serai souveraine! Tu n''as point mis dans ton esprit, Tu n''as point songé que cela prendrait fin.'),
  (23, 47, 8, 'Écoute maintenant ceci, voluptueuse, Qui t''assieds avec assurance, Et qui dis en ton cœur: Moi, et rien que moi! Je ne serai jamais veuve, Et je ne serai jamais privée d''enfants!'),
  (23, 47, 9, 'Ces deux choses t''arriveront subitement, au même jour, La privation d''enfants et le veuvage; Elles fondront en plein sur toi, Malgré la multitude de tes sortilèges, Malgré le grand nombre de tes enchantements.'),
  (23, 47, 10, 'Tu avais confiance dans ta méchanceté, Tu disais: Personne ne me voit! Ta sagesse et ta science t''ont séduite. Et tu disais en ton cœur: Moi, et rien que moi!'),
  (23, 47, 11, 'Le malheur viendra sur toi, Sans que tu en voies l''aurore; La calamité tombera sur toi, Sans que tu puisses la conjurer; Et la ruine fondra sur toi tout à coup, A l''improviste.'),
  (23, 47, 12, 'Reste donc au milieu de tes enchantements Et de la multitude de tes sortilèges, Auxquels tu as consacré ton travail dès ta jeunesse; Peut-être pourras-tu en tirer profit, Peut-être deviendras-tu redoutable.'),
  (23, 47, 13, 'Tu t''es fatiguée à force de consulter: Qu''ils se lèvent donc et qu''ils te sauvent, Ceux qui connaissent le ciel, Qui observent les astres, Qui annoncent, d''après les nouvelles lunes, Ce qui doit t''arriver!'),
  (23, 47, 14, 'Voici, ils sont comme de la paille, le feu les consume, Ils ne sauveront pas leur vie des flammes: Ce ne sera pas du charbon dont on se chauffe, Ni un feu auprès duquel on s''assied.'),
  (23, 47, 15, 'Tel sera le sort de ceux que tu te fatiguais à consulter. Et ceux avec qui tu as trafiqué dès ta jeunesse Se disperseront chacun de son côté: Il n''y aura personne qui vienne à ton secours.'),
  (23, 48, 1, 'Écoutez ceci, maison de Jacob, Vous qui portez le nom d''Israël, Et qui êtes sortis des eaux de Juda; Vous qui jurez par le nom de l''Éternel, Et qui invoquez le Dieu d''Israël, Mais sans vérité ni droiture!'),
  (23, 48, 2, 'Car ils prennent leur nom de la ville sainte, Et ils s''appuient sur le Dieu d''Israël, Dont le nom est l''Éternel des armées.'),
  (23, 48, 3, 'Dès longtemps j''ai fait les premières prédictions, Elles sont sorties de ma bouche, et je les ai publiées: Soudain j''ai agi, et elles se sont accomplies.'),
  (23, 48, 4, 'Sachant que tu es endurci, Que ton cou est une barre de fer, Et que tu as un front d''airain,'),
  (23, 48, 5, 'Je t''ai annoncé dès longtemps ces choses, je te les ai déclarées avant qu''elles arrivassent, Afin que tu ne dises pas: C''est mon idole qui les a faites, C''est mon image taillée ou mon image en fonte qui les a ordonnées.'),
  (23, 48, 6, 'Tu entends! Considère tout cela! Et vous, ne l''avouerez-vous pas?… Maintenant, je t''annonce des choses nouvelles, Cachées, inconnues de toi.'),
  (23, 48, 7, 'Elles se produisent à présent, et n''appartiennent point au passé; Jusqu''à leur avènement tu n''en avais aucune connaissance, Afin que tu ne dises pas: Voici, je le savais.'),
  (23, 48, 8, 'Tu n''en as rien appris, tu n''en as rien su, Et jadis ton oreille n''en a point été frappée: Car je savais que tu serais infidèle, Et que dès ta naissance tu fus appelé rebelle.'),
  (23, 48, 9, 'A cause de mon nom, je suspends ma colère; A cause de ma gloire, je me contiens envers toi, Pour ne pas t''exterminer.'),
  (23, 48, 10, 'Je t''ai mis au creuset, mais non pour retirer de l''argent; Je t''ai éprouvé dans la fournaise de l''adversité.'),
  (23, 48, 11, 'C''est pour l''amour de moi, pour l''amour de moi, que je veux agir; Car comment mon nom serait-il profané? Je ne donnerai pas ma gloire à un autre.'),
  (23, 48, 12, 'Écoute-moi, Jacob! Et toi, Israël, que j''ai appelé! C''est moi, moi qui suis le premier, C''est aussi moi qui suis le dernier.'),
  (23, 48, 13, 'Ma main a fondé la terre, Et ma droite a étendu les cieux: Je les appelle, et aussitôt ils se présentent.'),
  (23, 48, 14, 'Vous tous, assemblez-vous, et écoutez! Qui d''entre eux a annoncé ces choses? Celui que l''Éternel aime exécutera sa volonté contre Babylone, Et son bras s''appesantira sur les Chaldéens.'),
  (23, 48, 15, 'Moi, moi, j''ai parlé, et je l''ai appelé; Je l''ai fait venir, et son œuvre réussira.'),
  (23, 48, 16, 'Approchez-vous de moi, et écoutez! Dès le commencement, je n''ai point parlé en cachette, Dès l''origine de ces choses, j''ai été là. Et maintenant, le Seigneur, l''Éternel, m''a envoyé avec son esprit.'),
  (23, 48, 17, 'Ainsi parle l''Éternel, ton rédempteur, le Saint d''Israël: Moi, l''Éternel, ton Dieu, je t''instruis pour ton bien, Je te conduis dans la voie que tu dois suivre.'),
  (23, 48, 18, 'Oh! si tu étais attentif à mes commandements! Ton bien-être serait comme un fleuve, Et ton bonheur comme les flots de la mer;'),
  (23, 48, 19, 'Ta postérité serait comme le sable, Et les fruits de tes entrailles comme les grains de sable; Ton nom ne serait point effacé, anéanti devant moi.'),
  (23, 48, 20, 'Sortez de Babylone, fuyez du milieu des Chaldéens! Avec une voix d''allégresse annoncez-le, publiez-le, Faites-le savoir jusqu''à l''extrémité de la terre, Dites: L''Éternel a racheté son serviteur Jacob!'),
  (23, 48, 21, 'Et ils n''auront pas soif dans les déserts où il les conduira: Il fera jaillir pour eux l''eau du rocher, Il fendra le rocher, Et l''eau coulera.'),
  (23, 48, 22, 'Il n''y a point de paix pour les méchants, dit l''Éternel.'),
  (23, 49, 1, 'Iles, écoutez-moi! Peuples lointains, soyez attentifs! L''Éternel m''a appelé dès ma naissance, Il m''a nommé dès ma sortie des entrailles maternelles.'),
  (23, 49, 2, 'Il a rendu ma bouche semblable à un glaive tranchant, Il m''a couvert de l''ombre de sa main; Il a fait de moi une flèche aiguë, Il m''a caché dans son carquois.'),
  (23, 49, 3, 'Et il m''a dit: Tu es mon serviteur, Israël en qui je me glorifierai.'),
  (23, 49, 4, 'Et moi j''ai dit: C''est en vain que j''ai travaillé, C''est pour le vide et le néant que j''ai consumé ma force; Mais mon droit est auprès de l''Éternel, Et ma récompense auprès de mon Dieu.'),
  (23, 49, 5, 'Maintenant, l''Éternel parle, Lui qui m''a formé dès ma naissance Pour être son serviteur, Pour ramener à lui Jacob, Et Israël encore dispersé; Car je suis honoré aux yeux de l''Éternel, Et mon Dieu est ma force.'),
  (23, 49, 6, 'Il dit: C''est peu que tu sois mon serviteur Pour relever les tribus de Jacob Et pour ramener les restes d''Israël: Je t''établis pour être la lumière des nations, Pour porter mon salut jusqu''aux extrémités de la terre.'),
  (23, 49, 7, 'Ainsi parle l''Éternel, le rédempteur, le Saint d''Israël, A celui qu''on méprise, qui est en horreur au peuple, A l''esclave des puissants: Des rois le verront, et ils se lèveront, Des princes, et ils se prosterneront, A cause de l''Éternel, qui est fidèle, Du Saint d''Israël, qui t''a choisi.'),
  (23, 49, 8, 'Ainsi parle l''Éternel: Au temps de la grâce je t''exaucerai, Et au jour du salut je te secourrai; Je te garderai, et je t''établirai pour traiter alliance avec le peuple, Pour relever le pays, Et pour distribuer les héritages désolés;'),
  (23, 49, 9, 'Pour dire aux captifs: Sortez! Et à ceux qui sont dans les ténèbres: Paraissez! Ils paîtront sur les chemins, Et ils trouveront des pâturages sur tous les coteaux.'),
  (23, 49, 10, 'Ils n''auront pas faim et ils n''auront pas soif; Le mirage et le soleil ne les feront point souffrir; Car celui qui a pitié d''eux sera leur guide, Et il les conduira vers des sources d''eaux.'),
  (23, 49, 11, 'Je changerai toutes mes montagnes en chemins, Et mes routes seront frayées.'),
  (23, 49, 12, 'Les voici, ils viennent de loin, Les uns du septentrion et de l''occident, Les autres du pays de Sinim.'),
  (23, 49, 13, 'Cieux, réjouissez-vous! Terre, sois dans l''allégresse! Montagnes, éclatez en cris de joie! Car l''Éternel console son peuple, Il a pitié de ses malheureux.'),
  (23, 49, 14, 'Sion disait: L''Éternel m''abandonne, Le Seigneur m''oublie! -'),
  (23, 49, 15, 'Une femme oublie-t-elle l''enfant qu''elle allaite? N''a-t-elle pas pitié du fruit de ses entrailles? Quand elle l''oublierait, Moi je ne t''oublierai point.'),
  (23, 49, 16, 'Voici, je t''ai gravée sur mes mains; Tes murs sont toujours devant mes yeux.'),
  (23, 49, 17, 'Tes fils accourent; Ceux qui t''avaient détruite et ravagée Sortiront du milieu de toi.'),
  (23, 49, 18, 'Porte tes yeux alentour, et regarde: Tous ils s''assemblent, ils viennent vers toi. Je suis vivant! dit l''Éternel, Tu les revêtiras tous comme une parure, Tu t''en ceindras comme une fiancée.'),
  (23, 49, 19, 'Dans tes places ravagées et désertes, Dans ton pays ruiné, Tes habitants seront désormais à l''étroit; Et ceux qui te dévoraient s''éloigneront.'),
  (23, 49, 20, 'Ils répéteront à tes oreilles, Ces fils dont tu fus privée: L''espace est trop étroit pour moi; Fais-moi de la place, pour que je puisse m''établir.'),
  (23, 49, 21, 'Et tu diras en ton cœur: Qui me les a engendrés? Car j''étais sans enfants, j''étais stérile. J''étais exilée, répudiée: qui les a élevés? J''étais restée seule: ceux-ci, où étaient-ils?'),
  (23, 49, 22, 'Ainsi a parlé le Seigneur, l''Éternel: Voici: Je lèverai ma main vers les nations, Je dresserai ma bannière vers les peuples; Et ils ramèneront tes fils entre leurs bras, Ils porteront tes filles sur les épaules.'),
  (23, 49, 23, 'Des rois seront tes nourriciers, et leurs princesses tes nourrices; Ils se prosterneront devant toi la face contre terre, Et ils lécheront la poussière de tes pieds, Et tu sauras que je suis l''Éternel, Et que ceux qui espèrent en moi ne seront point confus.'),
  (23, 49, 24, 'Le butin du puissant lui sera-t-il enlevé? Et la capture faite sur le juste échappera-t-elle? -'),
  (23, 49, 25, 'Oui, dit l''Éternel, la capture du puissant lui sera enlevée, Et le butin du tyran lui échappera; Je combattrai tes ennemis, Et je sauverai tes fils.'),
  (23, 49, 26, 'Je ferai manger à tes oppresseurs leur propre chair; Ils s''enivreront de leur sang comme du moût; Et toute chair saura que je suis l''Éternel, ton sauveur, Ton rédempteur, le puissant de Jacob.'),
  (23, 50, 1, 'Ainsi parle l''Éternel: Où est la lettre de divorce par laquelle j''ai répudié votre mère? Ou bien, auquel de mes créanciers vous ai-je vendus? Voici, c''est à cause de vos iniquités que vous avez été vendus, Et c''est à cause de vos péchés que votre mère a été répudiée.'),
  (23, 50, 2, 'Je suis venu: pourquoi n''y avait-il personne? J''ai appelé: pourquoi personne n''a-t-il répondu? Ma main est-elle trop courte pour racheter? N''ai-je pas assez de force pour délivrer? Par ma menace, je dessèche la mer, Je réduis les fleuves en désert; Leurs poissons se corrompent, faute d''eau, Et ils périssent de soif.'),
  (23, 50, 3, 'Je revêts les cieux d''obscurité, Et je fais d''un sac leur couverture.'),
  (23, 50, 4, 'Le Seigneur, l''Éternel, m''a donné une langue exercée, Pour que je sache soutenir par la parole celui qui est abattu; Il éveille, chaque matin, il éveille mon oreille, Pour que j''écoute comme écoutent des disciples.'),
  (23, 50, 5, 'Le Seigneur, l''Éternel, m''a ouvert l''oreille, Et je n''ai point résisté, Je ne me suis point retiré en arrière.'),
  (23, 50, 6, 'J''ai livré mon dos à ceux qui me frappaient, Et mes joues à ceux qui m''arrachaient la barbe; Je n''ai pas dérobé mon visage Aux ignominies et aux crachats.'),
  (23, 50, 7, 'Mais le Seigneur, l''Éternel, m''a secouru; C''est pourquoi je n''ai point été déshonoré, C''est pourquoi j''ai rendu mon visage semblable à un caillou, Sachant que je ne serais point confondu.'),
  (23, 50, 8, 'Celui qui me justifie est proche: Qui disputera contre moi? Comparaissons ensemble! Qui est mon adversaire? Qu''il s''avance vers moi!'),
  (23, 50, 9, 'Voici, le Seigneur, l''Éternel, me secourra: Qui me condamnera? Voici, ils tomberont tous en lambeaux comme un vêtement, La teigne les dévorera.'),
  (23, 50, 10, 'Quiconque parmi vous craint l''Éternel, Qu''il écoute la voix de son serviteur! Quiconque marche dans l''obscurité et manque de lumière, Qu''il se confie dans le nom de l''Éternel, Et qu''il s''appuie sur son Dieu!'),
  (23, 50, 11, 'Voici, vous tous qui allumez un feu, Et qui êtes armés de torches, Allez au milieu de votre feu et de vos torches enflammées! C''est par ma main que ces choses vous arriveront; Vous vous coucherez dans la douleur.'),
  (23, 51, 1, 'Écoutez-moi, vous qui poursuivez la justice, Qui cherchez l''Éternel! Portez les regards sur le rocher d''où vous avez été taillés, Sur le creux de la fosse d''où vous avez été tirés.'),
  (23, 51, 2, 'Portez les regards sur Abraham votre père, Et sur Sara qui vous a enfantés; Car lui seul je l''ai appelé, Je l''ai béni et multiplié.'),
  (23, 51, 3, 'Ainsi l''Éternel a pitié de Sion, Il a pitié de toutes ses ruines; Il rendra son désert semblable à un Éden, Et sa terre aride à un jardin de l''Éternel. La joie et l''allégresse se trouveront au milieu d''elle, Les actions de grâces et le chant des cantiques.'),
  (23, 51, 4, 'Mon peuple, sois attentif! Ma nation, prête-moi l''oreille! Car la loi sortira de moi, Et j''établirai ma loi pour être la lumière des peuples.'),
  (23, 51, 5, 'Ma justice est proche, mon salut va paraître, Et mes bras jugeront les peuples; Les îles espéreront en moi, Elles se confieront en mon bras.'),
  (23, 51, 6, 'Levez les yeux vers le ciel, et regardez en bas sur la terre! Car les cieux s''évanouiront comme une fumée, La terre tombera en lambeaux comme un vêtement, Et ses habitants périront comme des mouches; Mais mon salut durera éternellement, Et ma justice n''aura point de fin.'),
  (23, 51, 7, 'Écoutez-moi, vous qui connaissez la justice, Peuple, qui as ma loi dans ton cœur! Ne craignez pas l''opprobre des hommes, Et ne tremblez pas devant leurs outrages.'),
  (23, 51, 8, 'Car la teigne les dévorera comme un vêtement, Et la gerce les rongera comme de la laine; Mais ma justice durera éternellement, Et mon salut s''étendra d''âge en âge.'),
  (23, 51, 9, 'Réveille-toi, réveille-toi! revêts-toi de force, bras de l''Éternel! Réveille-toi, comme aux jours d''autrefois, Dans les anciens âges! N''est-ce pas toi qui abattis l''Égypte, Qui transperças le monstre?'),
  (23, 51, 10, 'N''est-ce pas toi qui mis à sec la mer, Les eaux du grand abîme, Qui frayas dans les profondeurs de la mer Un chemin pour le passage des rachetés?'),
  (23, 51, 11, 'Ainsi les rachetés de l''Éternel retourneront, Ils iront à Sion avec chants de triomphe, Et une joie éternelle couronnera leur tête; L''allégresse et la joie s''approcheront, La douleur et les gémissements s''enfuiront.'),
  (23, 51, 12, 'C''est moi, c''est moi qui vous console. Qui es-tu, pour avoir peur de l''homme mortel, Et du fils de l''homme, pareil à l''herbe?'),
  (23, 51, 13, 'Et tu oublierais l''Éternel, qui t''a fait, Qui a étendu les cieux et fondé la terre! Et tu tremblerais incessamment tout le jour Devant la colère de l''oppresseur, Parce qu''il cherche à détruire! Où donc est la colère de l''oppresseur?'),
  (23, 51, 14, 'Bientôt celui qui est courbé sous les fers sera délivré; Il ne mourra pas dans la fosse, Et son pain ne lui manquera pas.'),
  (23, 51, 15, 'Je suis l''Éternel, ton Dieu, Qui soulève la mer et fais mugir ses flots. L''Éternel des armées est son nom.'),
  (23, 51, 16, 'Je mets mes paroles dans ta bouche, Et je te couvre de l''ombre de ma main, Pour étendre de nouveaux cieux et fonder une nouvelle terre, Et pour dire à Sion: Tu es mon peuple!'),
  (23, 51, 17, 'Réveille-toi, réveille-toi! lève-toi, Jérusalem, Qui as bu de la main de l''Éternel la coupe de sa colère, Qui as bu, sucé jusqu''à la lie la coupe d''étourdissement!'),
  (23, 51, 18, 'Il n''y en a aucun pour la conduire De tous les fils qu''elle a enfantés, Il n''y en a aucun pour la prendre par la main De tous les fils qu''elle a élevés.'),
  (23, 51, 19, 'Ces deux choses te sont arrivées: -Qui te plaindra? -Le ravage et la ruine, la famine et l''épée. -Qui suis-je pour te consoler? -'),
  (23, 51, 20, 'Tes fils en défaillance gisaient à tous les coins de rues, Comme le cerf dans un filet, Chargés de la colère de l''Éternel, Des menaces de ton Dieu.'),
  (23, 51, 21, 'C''est pourquoi, écoute ceci, malheureuse, Ivre, mais non de vin!'),
  (23, 51, 22, 'Ainsi parle ton Seigneur, l''Éternel, Ton Dieu, qui défend son peuple: Voici, je prends de ta main la coupe d''étourdissement, La coupe de ma colère; Tu ne la boiras plus!'),
  (23, 51, 23, 'Je la mettrai dans la main de tes oppresseurs, Qui te disaient: Courbe-toi, et nous passerons! Tu faisais alors de ton dos comme une terre, Comme une rue pour les passants.'),
  (23, 52, 1, 'Réveille-toi! réveille-toi! revêts ta parure, Sion! Revêts tes habits de fête, Jérusalem, ville sainte! Car il n''entrera plus chez toi ni incirconcis ni impur.'),
  (23, 52, 2, 'Secoue ta poussière, lève-toi, Mets-toi sur ton séant, Jérusalem! Détache les liens de ton cou, Captive, fille de Sion!'),
  (23, 52, 3, 'Car ainsi parle l''Éternel: C''est gratuitement que vous avez été vendus, Et ce n''est pas à prix d''argent que vous serez rachetés.'),
  (23, 52, 4, 'Car ainsi parle le Seigneur, l''Éternel: Jadis mon peuple descendit en Égypte, pour y séjourner; Puis l''Assyrien l''opprima sans cause.'),
  (23, 52, 5, 'Et maintenant, qu''ai-je à faire, dit l''Éternel, Quand mon peuple a été gratuitement enlevé? Ses tyrans poussent des cris, dit l''Éternel, Et toute la durée du jour mon nom est outragé.'),
  (23, 52, 6, 'C''est pourquoi mon peuple connaîtra mon nom; C''est pourquoi il saura, en ce jour, Que c''est moi qui parle: me voici!'),
  (23, 52, 7, 'Qu''ils sont beaux sur les montagnes, Les pieds de celui qui apporte de bonnes nouvelles, Qui publie la paix! De celui qui apporte de bonnes nouvelles, Qui publie le salut! De celui qui dit à Sion: ton Dieu règne!'),
  (23, 52, 8, 'La voix de tes sentinelles retentit; Elles élèvent la voix, Elles poussent ensemble des cris d''allégresse; Car de leurs propres yeux elles voient Que l''Éternel ramène Sion.'),
  (23, 52, 9, 'Éclatez ensemble en cris de joie, Ruines de Jérusalem! Car l''Éternel console son peuple, Il rachète Jérusalem.'),
  (23, 52, 10, 'L''Éternel découvre le bras de sa sainteté, Aux yeux de toutes les nations; Et toutes les extrémités de la terre verront Le salut de notre Dieu.'),
  (23, 52, 11, 'Partez, partez, sortez de là! Ne touchez rien d''impur! Sortez du milieu d''elle! Purifiez-vous, vous qui portez les vases de l''Éternel!'),
  (23, 52, 12, 'Ne sortez pas avec précipitation, Ne partez pas en fuyant; Car l''Éternel ira devant vous, Et le Dieu d''Israël fermera votre marche.'),
  (23, 52, 13, 'Voici, mon serviteur prospérera; Il montera, il s''élèvera, il s''élèvera bien haut.'),
  (23, 52, 14, 'De même qu''il a été pour plusieurs un sujet d''effroi, -Tant son visage était défiguré, Tant son aspect différait de celui des fils de l''homme, -'),
  (23, 52, 15, 'De même il sera pour beaucoup de peuples un sujet de joie; Devant lui des rois fermeront la bouche; Car ils verront ce qui ne leur avait point été raconté, Ils apprendront ce qu''ils n''avaient point entendu.'),
  (23, 53, 1, 'Qui a cru à ce qui nous était annoncé? Qui a reconnu le bras de l''Éternel?'),
  (23, 53, 2, 'Il s''est élevé devant lui comme une faible plante, Comme un rejeton qui sort d''une terre desséchée; Il n''avait ni beauté, ni éclat pour attirer nos regards, Et son aspect n''avait rien pour nous plaire.'),
  (23, 53, 3, 'Méprisé et abandonné des hommes, Homme de douleur et habitué à la souffrance, Semblable à celui dont on détourne le visage, Nous l''avons dédaigné, nous n''avons fait de lui aucun cas.'),
  (23, 53, 4, 'Cependant, ce sont nos souffrances qu''il a portées, C''est de nos douleurs qu''il s''est chargé; Et nous l''avons considéré comme puni, Frappé de Dieu, et humilié.'),
  (23, 53, 5, 'Mais il était blessé pour nos péchés, Brisé pour nos iniquités; Le châtiment qui nous donne la paix est tombé sur lui, Et c''est par ses meurtrissures que nous sommes guéris.'),
  (23, 53, 6, 'Nous étions tous errants comme des brebis, Chacun suivait sa propre voie; Et l''Éternel a fait retomber sur lui l''iniquité de nous tous.'),
  (23, 53, 7, 'Il a été maltraité et opprimé, Et il n''a point ouvert la bouche, Semblable à un agneau qu''on mène à la boucherie, A une brebis muette devant ceux qui la tondent; Il n''a point ouvert la bouche.'),
  (23, 53, 8, 'Il a été enlevé par l''angoisse et le châtiment; Et parmi ceux de sa génération, qui a cru Qu''il était retranché de la terre des vivants Et frappé pour les péchés de mon peuple?'),
  (23, 53, 9, 'On a mis son sépulcre parmi les méchants, Son tombeau avec le riche, Quoiqu''il n''eût point commis de violence Et qu''il n''y eût point de fraude dans sa bouche.'),
  (23, 53, 10, 'Il a plu à l''Éternel de le briser par la souffrance… Après avoir livré sa vie en sacrifice pour le péché, Il verra une postérité et prolongera ses jours; Et l''œuvre de l''Éternel prospérera entre ses mains.'),
  (23, 53, 11, 'A cause du travail de son âme, il rassasiera ses regards; Par sa connaissance mon serviteur juste justifiera beaucoup d''hommes, Et il se chargera de leurs iniquités.'),
  (23, 53, 12, 'C''est pourquoi je lui donnerai sa part avec les grands; Il partagera le butin avec les puissants, Parce qu''il s''est livré lui-même à la mort, Et qu''il a été mis au nombre des malfaiteurs, Parce qu''il a porté les péchés de beaucoup d''hommes, Et qu''il a intercédé pour les coupables.'),
  (23, 54, 1, 'Réjouis-toi, stérile, toi qui n''enfantes plus! Fais éclater ton allégresse et ta joie, toi qui n''as plus de douleurs! Car les fils de la délaissée seront plus nombreux Que les fils de celle qui est mariée, dit l''Éternel.'),
  (23, 54, 2, 'Élargis l''espace de ta tente; Qu''on déploie les couvertures de ta demeure: Ne retiens pas! Allonge tes cordages, Et affermis tes pieux!'),
  (23, 54, 3, 'Car tu te répandras à droite et à gauche; Ta postérité envahira des nations, Et peuplera des villes désertes.'),
  (23, 54, 4, 'Ne crains pas, car tu ne seras point confondue; Ne rougis pas, car tu ne seras pas déshonorée; Mais tu oublieras la honte de ta jeunesse, Et tu ne te souviendras plus de l''opprobre de ton veuvage.'),
  (23, 54, 5, 'Car ton créateur est ton époux: L''Éternel des armées est son nom; Et ton rédempteur est le Saint d''Israël: Il se nomme Dieu de toute la terre;'),
  (23, 54, 6, 'Car l''Éternel te rappelle comme une femme délaissée et au cœur attristé, Comme une épouse de la jeunesse qui a été répudiée, dit ton Dieu.'),
  (23, 54, 7, 'Quelques instants je t''avais abandonnée, Mais avec une grande affection je t''accueillerai;'),
  (23, 54, 8, 'Dans un instant de colère, je t''avais un moment dérobé ma face, Mais avec un amour éternel j''aurai compassion de toi, Dit ton rédempteur, l''Éternel.'),
  (23, 54, 9, 'Il en sera pour moi comme des eaux de Noé: J''avais juré que les eaux de Noé ne se répandraient plus sur la terre; Je jure de même de ne plus m''irriter contre toi Et de ne plus te menacer.'),
  (23, 54, 10, 'Quand les montagnes s''éloigneraient, Quand les collines chancelleraient, Mon amour ne s''éloignera point de toi, Et mon alliance de paix ne chancellera point, Dit l''Éternel, qui a compassion de toi.'),
  (23, 54, 11, 'Malheureuse, battue de la tempête, et que nul ne console! Voici, je garnirai tes pierres d''antimoine, Et je te donnerai des fondements de saphir;'),
  (23, 54, 12, 'Je ferai tes créneaux de rubis, Tes portes d''escarboucles, Et toute ton enceinte de pierres précieuses.'),
  (23, 54, 13, 'Tous tes fils seront disciples de l''Éternel, Et grande sera la prospérité de tes fils.'),
  (23, 54, 14, 'Tu seras affermie par la justice; Bannis l''inquiétude, car tu n''as rien à craindre, Et la frayeur, car elle n''approchera pas de toi.'),
  (23, 54, 15, 'Si l''on forme des complots, cela ne viendra pas de moi; Quiconque se liguera contre toi tombera sous ton pouvoir.'),
  (23, 54, 16, 'Voici, j''ai créé l''ouvrier qui souffle le charbon au feu, Et qui fabrique une arme par son travail; Mais j''ai créé aussi le destructeur pour la briser.'),
  (23, 54, 17, 'Toute arme forgée contre toi sera sans effet; Et toute langue qui s''élèvera en justice contre toi, Tu la condamneras. Tel est l''héritage des serviteurs de l''Éternel, Tel est le salut qui leur viendra de moi, Dit l''Éternel.'),
  (23, 55, 1, 'Vous tous qui avez soif, venez aux eaux, Même celui qui n''a pas d''argent! Venez, achetez et mangez, Venez, achetez du vin et du lait, sans argent, sans rien payer!'),
  (23, 55, 2, 'Pourquoi pesez-vous de l''argent pour ce qui ne nourrit pas? Pourquoi travaillez-vous pour ce qui ne rassasie pas? Écoutez-moi donc, et vous mangerez ce qui est bon, Et votre âme se délectera de mets succulents.'),
  (23, 55, 3, 'Prêtez l''oreille, et venez à moi, Écoutez, et votre âme vivra: Je traiterai avec vous une alliance éternelle, Pour rendre durables mes faveurs envers David.'),
  (23, 55, 4, 'Voici, je l''ai établi comme témoin auprès des peuples, Comme chef et dominateur des peuples.'),
  (23, 55, 5, 'Voici, tu appelleras des nations que tu ne connais pas, Et les nations qui ne te connaissent pas accourront vers toi, A cause de l''Éternel, ton Dieu, Du Saint d''Israël, qui te glorifie.'),
  (23, 55, 6, 'Cherchez l''Éternel pendant qu''il se trouve; Invoquez-le, tandis qu''il est près.'),
  (23, 55, 7, 'Que le méchant abandonne sa voie, Et l''homme d''iniquité ses pensées; Qu''il retourne à l''Éternel, qui aura pitié de lui, A notre Dieu, qui ne se lasse pas de pardonner.'),
  (23, 55, 8, 'Car mes pensées ne sont pas vos pensées, Et vos voies ne sont pas mes voies, Dit l''Éternel.'),
  (23, 55, 9, 'Autant les cieux sont élevés au-dessus de la terre, Autant mes voies sont élevées au-dessus de vos voies, Et mes pensées au-dessus de vos pensées.'),
  (23, 55, 10, 'Comme la pluie et la neige descendent des cieux, Et n''y retournent pas Sans avoir arrosé, fécondé la terre, et fait germer les plantes, Sans avoir donné de la semence au semeur Et du pain à celui qui mange,'),
  (23, 55, 11, 'Ainsi en est-il de ma parole, qui sort de ma bouche: Elle ne retourne point à moi sans effet, Sans avoir exécuté ma volonté Et accompli mes desseins.'),
  (23, 55, 12, 'Oui, vous sortirez avec joie, Et vous serez conduits en paix; Les montagnes et les collines éclateront d''allégresse devant vous, Et tous les arbres de la campagne battront des mains.'),
  (23, 55, 13, 'Au lieu de l''épine s''élèvera le cyprès, Au lieu de la ronce croîtra le myrte; Et ce sera pour l''Éternel une gloire, Un monument perpétuel, impérissable.'),
  (23, 56, 1, 'Ainsi parle l''Éternel: Observez ce qui est droit, et pratiquez ce qui est juste; Car mon salut ne tardera pas à venir, Et ma justice à se manifester.'),
  (23, 56, 2, 'Heureux l''homme qui fait cela, Et le fils de l''homme qui y demeure ferme, Gardant le sabbat, pour ne point le profaner, Et veillant sur sa main, pour ne commettre aucun mal!'),
  (23, 56, 3, 'Que l''étranger qui s''attache à l''Éternel ne dise pas: L''Éternel me séparera de son peuple! Et que l''eunuque ne dise pas: Voici, je suis un arbre sec!'),
  (23, 56, 4, 'Car ainsi parle l''Éternel: Aux eunuques qui garderont mes sabbats, Qui choisiront ce qui m''est agréable, Et qui persévéreront dans mon alliance,'),
  (23, 56, 5, 'Je donnerai dans ma maison et dans mes murs une place et un nom Préférables à des fils et à des filles; Je leur donnerai un nom éternel, Qui ne périra pas.'),
  (23, 56, 6, 'Et les étrangers qui s''attacheront à l''Éternel pour le servir, Pour aimer le nom de l''Éternel, Pour être ses serviteurs, Tous ceux qui garderont le sabbat, pour ne point le profaner, Et qui persévéreront dans mon alliance,'),
  (23, 56, 7, 'Je les amènerai sur ma montagne sainte, Et je les réjouirai dans ma maison de prière; Leurs holocaustes et leurs sacrifices seront agréés sur mon autel; Car ma maison sera appelée une maison de prière pour tous les peuples.'),
  (23, 56, 8, 'Le Seigneur, l''Éternel, parle, Lui qui rassemble les exilés d''Israël: Je réunirai d''autres peuples à lui, aux siens déjà rassemblés.'),
  (23, 56, 9, 'Vous toutes, bêtes des champs, Venez pour manger, vous toutes, bêtes de la forêt!'),
  (23, 56, 10, 'Ses gardiens sont tous aveugles, sans intelligence; Ils sont tous des chiens muets, incapables d''aboyer; Ils ont des rêveries, se tiennent couchés, Aiment à sommeiller.'),
  (23, 56, 11, 'Et ce sont des chiens voraces, insatiables; Ce sont des bergers qui ne savent rien comprendre; Tous suivent leur propre voie, Chacun selon son intérêt, jusqu''au dernier: -'),
  (23, 56, 12, 'Venez, je vais chercher du vin, Et nous boirons des liqueurs fortes! Nous en ferons autant demain, Et beaucoup plus encore! -'),
  (23, 57, 1, 'Le juste périt, et nul n''y prend garde; Les gens de bien sont enlevés, et nul ne fait attention Que c''est par suite de la malice que le juste est enlevé.'),
  (23, 57, 2, 'Il entrera dans la paix, Il reposera sur sa couche, Celui qui aura suivi le droit chemin.'),
  (23, 57, 3, 'Mais vous, approchez ici, fils de l''enchanteresse, Race de l''adultère et de la prostituée!'),
  (23, 57, 4, 'De qui vous moquez-vous? Contre qui ouvrez-vous une large bouche Et tirez-vous la langue? N''êtes-vous pas des enfants de péché, Une race de mensonge,'),
  (23, 57, 5, 'S''échauffant près des térébinthes, sous tout arbre vert, Égorgeant les enfants dans les vallées, Sous des fentes de rochers?'),
  (23, 57, 6, 'C''est dans les pierres polies des torrents qu''est ton partage, Voilà, voilà ton lot; C''est à elles que tu verses des libations, Que tu fais des offrandes: Puis-je être insensible à cela?'),
  (23, 57, 7, 'C''est sur une montagne haute et élevée que tu dresses ta couche; C''est aussi là que tu montes pour offrir des sacrifices.'),
  (23, 57, 8, 'Tu mets ton souvenir derrière la porte et les poteaux; Car, loin de moi, tu lèves la couverture et tu montes, Tu élargis ta couche, et tu traites alliance avec eux, Tu aimes leur commerce, tu choisis une place.'),
  (23, 57, 9, 'Tu vas auprès du roi avec de l''huile, Tu multiplies tes aromates, Tu envoies au loin tes messagers, Tu t''abaisses jusqu''au séjour des morts.'),
  (23, 57, 10, 'A force de marcher tu te fatigues, Et tu ne dis pas: J''y renonce! Tu trouves encore de la vigueur dans ta main: Aussi n''es-tu pas dans l''abattement.'),
  (23, 57, 11, 'Et qui redoutais-tu, qui craignais-tu, pour être infidèle, Pour ne pas te souvenir, te soucier de moi? Est-ce que je ne garde pas le silence, et depuis longtemps? C''est pourquoi tu ne me crains pas.'),
  (23, 57, 12, 'Je vais publier ta droiture, Et tes œuvres ne te profiteront pas.'),
  (23, 57, 13, 'Quand tu crieras, la foule de tes idoles te délivrera-t-elle? Le vent les emportera toutes, un souffle les enlèvera. Mais celui qui se confie en moi héritera le pays, Et possédera ma montagne sainte.'),
  (23, 57, 14, 'On dira: Frayez, frayez, préparez le chemin, Enlevez tout obstacle du chemin de mon peuple!'),
  (23, 57, 15, 'Car ainsi parle le Très-Haut, Dont la demeure est éternelle et dont le nom est saint: J''habite dans les lieux élevés et dans la sainteté; Mais je suis avec l''homme contrit et humilié, Afin de ranimer les esprits humiliés, Afin de ranimer les cœurs contrits.'),
  (23, 57, 16, 'Je ne veux pas contester à toujours, Ni garder une éternelle colère, Quand devant moi tombent en défaillance les esprits, Les âmes que j''ai faites.'),
  (23, 57, 17, 'A cause de son avidité coupable, je me suis irrité et je l''ai frappé, Je me suis caché dans mon indignation; Et le rebelle a suivi le chemin de son cœur.'),
  (23, 57, 18, 'J''ai vu ses voies, Et je le guérirai; Je lui servirai de guide, Et je le consolerai, lui et ceux qui pleurent avec lui.'),
  (23, 57, 19, 'Je mettrai la louange sur les lèvres. Paix, paix à celui qui est loin et à celui qui est près! dit l''Éternel. Je les guérirai.'),
  (23, 57, 20, 'Mais les méchants sont comme la mer agitée, Qui ne peut se calmer, Et dont les eaux soulèvent la vase et le limon.'),
  (23, 57, 21, 'Il n''y a point de paix pour les méchants, dit mon Dieu.'),
  (23, 58, 1, 'Crie à plein gosier, ne te retiens pas, Élève ta voix comme une trompette, Et annonce à mon peuple ses iniquités, A la maison de Jacob ses péchés!'),
  (23, 58, 2, 'Tous les jours ils me cherchent, Ils veulent connaître mes voies; Comme une nation qui aurait pratiqué la justice Et n''aurait pas abandonné la loi de son Dieu, Ils me demandent des arrêts de justice, Ils désirent l''approche de Dieu. -'),
  (23, 58, 3, 'Que nous sert de jeûner, si tu ne le vois pas? De mortifier notre âme, si tu n''y as point égard? -Voici, le jour de votre jeûne, vous vous livrez à vos penchants, Et vous traitez durement tous vos mercenaires.'),
  (23, 58, 4, 'Voici, vous jeûnez pour disputer et vous quereller, Pour frapper méchamment du poing; Vous ne jeûnez pas comme le veut ce jour, Pour que votre voix soit entendue en haut.'),
  (23, 58, 5, 'Est-ce là le jeûne auquel je prends plaisir, Un jour où l''homme humilie son âme? Courber la tête comme un jonc, Et se coucher sur le sac et la cendre, Est-ce là ce que tu appelleras un jeûne, Un jour agréable à l''Éternel?'),
  (23, 58, 6, 'Voici le jeûne auquel je prends plaisir: Détache les chaînes de la méchanceté, Dénoue les liens de la servitude, Renvoie libres les opprimés, Et que l''on rompe toute espèce de joug;'),
  (23, 58, 7, 'Partage ton pain avec celui qui a faim, Et fais entrer dans ta maison les malheureux sans asile; Si tu vois un homme nu, couvre-le, Et ne te détourne pas de ton semblable.'),
  (23, 58, 8, 'Alors ta lumière poindra comme l''aurore, Et ta guérison germera promptement; Ta justice marchera devant toi, Et la gloire de l''Éternel t''accompagnera.'),
  (23, 58, 9, 'Alors tu appelleras, et l''Éternel répondra; Tu crieras, et il dira: Me voici! Si tu éloignes du milieu de toi le joug, Les gestes menaçants et les discours injurieux,'),
  (23, 58, 10, 'Si tu donnes ta propre subsistance à celui qui a faim, Si tu rassasies l''âme indigente, Ta lumière se lèvera sur l''obscurité, Et tes ténèbres seront comme le midi.'),
  (23, 58, 11, 'L''Éternel sera toujours ton guide, Il rassasiera ton âme dans les lieux arides, Et il redonnera de la vigueur à tes membres; Tu seras comme un jardin arrosé, Comme une source dont les eaux ne tarissent pas.'),
  (23, 58, 12, 'Les tiens rebâtiront sur d''anciennes ruines, Tu relèveras des fondements antiques; On t''appellera réparateur des brèches, Celui qui restaure les chemins, qui rend le pays habitable.'),
  (23, 58, 13, 'Si tu retiens ton pied pendant le sabbat, Pour ne pas faire ta volonté en mon saint jour, Si tu fais du sabbat tes délices, Pour sanctifier l''Éternel en le glorifiant, Et si tu l''honores en ne suivant point tes voies, En ne te livrant pas à tes penchants et à de vains discours,'),
  (23, 58, 14, 'Alors tu mettras ton plaisir en l''Éternel, Et je te ferai monter sur les hauteurs du pays, Je te ferai jouir de l''héritage de Jacob, ton père; Car la bouche de l''Éternel a parlé.'),
  (23, 59, 1, 'Non, la main de l''Éternel n''est pas trop courte pour sauver, Ni son oreille trop dure pour entendre.'),
  (23, 59, 2, 'Mais ce sont vos crimes qui mettent une séparation Entre vous et votre Dieu; Ce sont vos péchés qui vous cachent sa face Et l''empêchent de vous écouter.'),
  (23, 59, 3, 'Car vos mains sont souillées de sang, Et vos doigts de crimes; Vos lèvres profèrent le mensonge, Votre langue fait entendre l''iniquité.'),
  (23, 59, 4, 'Nul ne se plaint avec justice, Nul ne plaide avec droiture; Ils s''appuient sur des choses vaines et disent des faussetés, Ils conçoivent le mal et enfantent le crime.'),
  (23, 59, 5, 'Ils couvent des œufs de basilic, Et ils tissent des toiles d''araignée. Celui qui mange de leurs œufs meurt; Et, si l''on en brise un, il sort une vipère.'),
  (23, 59, 6, 'Leurs toiles ne servent point à faire un vêtement, Et ils ne peuvent se couvrir de leur ouvrage; Leurs œuvres sont des œuvres d''iniquité, Et les actes de violence sont dans leurs mains.'),
  (23, 59, 7, 'Leurs pieds courent au mal, Et ils ont hâte de répandre le sang innocent; Leurs pensées sont des pensées d''iniquité, Le ravage et la ruine sont sur leur route.'),
  (23, 59, 8, 'Ils ne connaissent pas le chemin de la paix, Et il n''y a point de justice dans leurs voies; Ils prennent des sentiers détournés: Quiconque y marche ne connaît point la paix. -'),
  (23, 59, 9, 'C''est pourquoi l''arrêt de délivrance est loin de nous, Et le salut ne nous atteint pas; Nous attendons la lumière, et voici les ténèbres, La clarté, et nous marchons dans l''obscurité.'),
  (23, 59, 10, 'Nous tâtonnons comme des aveugles le long d''un mur, Nous tâtonnons comme ceux qui n''ont point d''yeux; Nous chancelons à midi comme de nuit, Au milieu de l''abondance nous ressemblons à des morts.'),
  (23, 59, 11, 'Nous grondons tous comme des ours, Nous gémissons comme des colombes; Nous attendons la délivrance, et elle n''est pas là, Le salut, et il est loin de nous.'),
  (23, 59, 12, 'Car nos transgressions sont nombreuses devant toi, Et nos péchés témoignent contre nous; Nos transgressions sont avec nous, Et nous connaissons nos crimes.'),
  (23, 59, 13, 'Nous avons été coupables et infidèles envers l''Éternel, Nous avons abandonné notre Dieu; Nous avons proféré la violence et la révolte, Conçu et médité dans le cœur des paroles de mensonge;'),
  (23, 59, 14, 'Et la délivrance s''est retirée, Et le salut se tient éloigné; Car la vérité trébuche sur la place publique, Et la droiture ne peut approcher.'),
  (23, 59, 15, 'La vérité a disparu, Et celui qui s''éloigne du mal est dépouillé. -L''Éternel voit, d''un regard indigné, Qu''il n''y a plus de droiture.'),
  (23, 59, 16, 'Il voit qu''il n''y a pas un homme, Il s''étonne de ce que personne n''intercède; Alors son bras lui vient en aide, Et sa justice lui sert d''appui.'),
  (23, 59, 17, 'Il se revêt de la justice comme d''une cuirasse, Et il met sur sa tête le casque du salut; Il prend la vengeance pour vêtement, Et il se couvre de la jalousie comme d''un manteau.'),
  (23, 59, 18, 'Il rendra à chacun selon ses œuvres, La fureur à ses adversaires, La pareille à ses ennemis; Il rendra la pareille aux îles.'),
  (23, 59, 19, 'On craindra le nom de l''Éternel depuis l''occident, Et sa gloire depuis le soleil levant; Quand l''ennemi viendra comme un fleuve, L''esprit de l''Éternel le mettra en fuite.'),
  (23, 59, 20, 'Un rédempteur viendra pour Sion, Pour ceux de Jacob qui se convertiront de leurs péchés, Dit l''Éternel.'),
  (23, 59, 21, 'Voici mon alliance avec eux, dit l''Éternel: Mon esprit, qui repose sur toi, Et mes paroles, que j''ai mises dans ta bouche, Ne se retireront point de ta bouche, ni de la bouche de tes enfants, Ni de la bouche des enfants de tes enfants, Dit l''Éternel, dès maintenant et à jamais.'),
  (23, 60, 1, 'Lève-toi, sois éclairée, car ta lumière arrive, Et la gloire de l''Éternel se lève sur toi.'),
  (23, 60, 2, 'Voici, les ténèbres couvrent la terre, Et l''obscurité les peuples; Mais sur toi l''Éternel se lève, Sur toi sa gloire apparaît.'),
  (23, 60, 3, 'Des nations marchent à ta lumière, Et des rois à la clarté de tes rayons.'),
  (23, 60, 4, 'Porte tes yeux alentour, et regarde: Tous ils s''assemblent, ils viennent vers toi; Tes fils arrivent de loin, Et tes filles sont portées sur les bras.'),
  (23, 60, 5, 'Tu tressailliras alors et tu te réjouiras, Et ton cœur bondira et se dilatera, Quand les richesses de la mer se tourneront vers toi, Quand les trésors des nations viendront à toi.'),
  (23, 60, 6, 'Tu seras couverte d''une foule de chameaux, De dromadaires de Madian et d''Épha; Ils viendront tous de Séba; Ils porteront de l''or et de l''encens, Et publieront les louanges de l''Éternel.'),
  (23, 60, 7, 'Les troupeaux de Kédar se réuniront tous chez toi; Les béliers de Nebajoth seront à ton service; Ils monteront sur mon autel et me seront agréables, Et je glorifierai la maison de ma gloire.'),
  (23, 60, 8, 'Qui sont ceux-là qui volent comme des nuées, Comme des colombes vers leur colombier?'),
  (23, 60, 9, 'Car les îles espèrent en moi, Et les navires de Tarsis sont en tête, Pour ramener de loin tes enfants, Avec leur argent et leur or, A cause du nom de l''Éternel, ton Dieu, Du Saint d''Israël qui te glorifie.'),
  (23, 60, 10, 'Les fils de l''étranger rebâtiront tes murs, Et leurs rois seront tes serviteurs; Car je t''ai frappée dans ma colère, Mais dans ma miséricorde j''ai pitié de toi.'),
  (23, 60, 11, 'Tes portes seront toujours ouvertes, Elles ne seront fermées ni jour ni nuit, Afin de laisser entrer chez toi les trésors des nations, Et leurs rois avec leur suite.'),
  (23, 60, 12, 'Car la nation et le royaume qui ne te serviront pas périront, Ces nations-là seront exterminées.'),
  (23, 60, 13, 'La gloire du Liban viendra chez toi, Le cyprès, l''orme et le buis, tous ensemble, Pour orner le lieu de mon sanctuaire, Et je glorifierai la place où reposent mes pieds.'),
  (23, 60, 14, 'Les fils de tes oppresseurs viendront s''humilier devant toi, Et tous ceux qui te méprisaient se prosterneront à tes pieds; Ils t''appelleront ville de l''Éternel, Sion du Saint d''Israël.'),
  (23, 60, 15, 'Au lieu que tu étais délaissée et haïe, Et que personne ne te parcourait, Je ferai de toi un ornement pour toujours, Un sujet de joie de génération en génération.'),
  (23, 60, 16, 'Tu suceras le lait des nations, Tu suceras la mamelle des rois; Et tu sauras que je suis l''Éternel, ton sauveur, Ton rédempteur, le puissant de Jacob.'),
  (23, 60, 17, 'Au lieu de l''airain je ferai venir de l''or, Au lieu du fer je ferai venir de l''argent, Au lieu du bois, de l''airain, Et au lieu des pierres, du fer; Je ferai régner sur toi la paix, Et dominer la justice.'),
  (23, 60, 18, 'On n''entendra plus parler de violence dans ton pays, Ni de ravage et de ruine dans ton territoire; Tu donneras à tes murs le nom de salut, Et à tes portes celui de gloire.'),
  (23, 60, 19, 'Ce ne sera plus le soleil qui te servira de lumière pendant le jour, Ni la lune qui t''éclairera de sa lueur; Mais l''Éternel sera ta lumière à toujours, Ton Dieu sera ta gloire.'),
  (23, 60, 20, 'Ton soleil ne se couchera plus, Et ta lune ne s''obscurcira plus; Car l''Éternel sera ta lumière à toujours, Et les jours de ton deuil seront passés.'),
  (23, 60, 21, 'Il n''y aura plus que des justes parmi ton peuple, Ils posséderont à toujours le pays; C''est le rejeton que j''ai planté, l''œuvre de mes mains, Pour servir à ma gloire.'),
  (23, 60, 22, 'Le plus petit deviendra un millier, Et le moindre une nation puissante. Moi, l''Éternel, je hâterai ces choses en leur temps.'),
  (23, 61, 1, 'L''esprit du Seigneur, l''Éternel, est sur moi, Car l''Éternel m''a oint pour porter de bonnes nouvelles aux malheureux; Il m''a envoyé pour guérir ceux qui ont le cœur brisé, Pour proclamer aux captifs la liberté, Et aux prisonniers la délivrance;'),
  (23, 61, 2, 'Pour publier une année de grâce de l''Éternel, Et un jour de vengeance de notre Dieu; Pour consoler tous les affligés;'),
  (23, 61, 3, 'Pour accorder aux affligés de Sion, Pour leur donner un diadème au lieu de la cendre, Une huile de joie au lieu du deuil, Un vêtement de louange au lieu d''un esprit abattu, Afin qu''on les appelle des térébinthes de la justice, Une plantation de l''Éternel, pour servir à sa gloire.'),
  (23, 61, 4, 'Ils rebâtiront sur d''anciennes ruines, Ils relèveront d''antiques décombres, Ils renouvelleront des villes ravagées, Dévastées depuis longtemps.'),
  (23, 61, 5, 'Des étrangers seront là et feront paître vos troupeaux, Des fils de l''étranger seront vos laboureurs et vos vignerons.'),
  (23, 61, 6, 'Mais vous, on vous appellera sacrificateurs de l''Éternel, On vous nommera serviteurs de notre Dieu; Vous mangerez les richesses des nations, Et vous vous glorifierez de leur gloire.'),
  (23, 61, 7, 'Au lieu de votre opprobre, vous aurez une portion double; Au lieu de l''ignominie, ils seront joyeux de leur part; Ils posséderont ainsi le double dans leur pays, Et leur joie sera éternelle.'),
  (23, 61, 8, 'Car moi, l''Éternel, j''aime la justice, Je hais la rapine avec l''iniquité; Je leur donnerai fidèlement leur récompense, Et je traiterai avec eux une alliance éternelle.'),
  (23, 61, 9, 'Leur race sera connue parmi les nations, Et leur postérité parmi les peuples; Tous ceux qui les verront reconnaîtront Qu''ils sont une race bénie de l''Éternel.'),
  (23, 61, 10, 'Je me réjouirai en l''Éternel, Mon âme sera ravie d''allégresse en mon Dieu; Car il m''a revêtu des vêtements du salut, Il m''a couvert du manteau de la délivrance, Comme le fiancé s''orne d''un diadème, Comme la fiancée se pare de ses joyaux.'),
  (23, 61, 11, 'Car, comme la terre fait éclore son germe, Et comme un jardin fait pousser ses semences, Ainsi le Seigneur, l''Éternel, fera germer le salut et la louange, En présence de toutes les nations.'),
  (23, 62, 1, 'Pour l''amour de Sion je ne me tairai point, Pour l''amour de Jérusalem je ne prendrai point de repos, Jusqu''à ce que son salut paraisse, comme l''aurore, Et sa délivrance, comme un flambeau qui s''allume.'),
  (23, 62, 2, 'Alors les nations verront ton salut, Et tous les rois ta gloire; Et l''on t''appellera d''un nom nouveau, Que la bouche de l''Éternel déterminera.'),
  (23, 62, 3, 'Tu seras une couronne éclatante dans la main de l''Éternel, Un turban royal dans la main de ton Dieu.'),
  (23, 62, 4, 'On ne te nommera plus délaissée, On ne nommera plus ta terre désolation; Mais on t''appellera mon plaisir en elle, Et l''on appellera ta terre épouse; Car l''Éternel met son plaisir en toi, Et ta terre aura un époux.'),
  (23, 62, 5, 'Comme un jeune homme s''unit à une vierge, Ainsi tes fils s''uniront à toi; Et comme la fiancée fait la joie de son fiancé, Ainsi tu feras la joie de ton Dieu.'),
  (23, 62, 6, 'Sur tes murs, Jérusalem, j''ai placé des gardes; Ils ne se tairont ni jour ni nuit. Vous qui la rappelez au souvenir de l''Éternel, Point de repos pour vous!'),
  (23, 62, 7, 'Et ne lui laissez aucun relâche, Jusqu''à ce qu''il rétablisse Jérusalem Et la rende glorieuse sur la terre.'),
  (23, 62, 8, 'L''Éternel l''a juré par sa droite et par son bras puissant: Je ne donnerai plus ton blé pour nourriture à tes ennemis, Et les fils de l''étranger ne boiront plus ton vin, Produit de tes labeurs;'),
  (23, 62, 9, 'Mais ceux qui auront amassé le blé le mangeront Et loueront l''Éternel, Et ceux qui auront récolté le vin le boiront, Dans les parvis de mon sanctuaire.'),
  (23, 62, 10, 'Franchissez, franchissez les portes! Préparez un chemin pour le peuple! Frayez, frayez la route, ôtez les pierres! Élevez une bannière vers les peuples!'),
  (23, 62, 11, 'Voici ce que l''Éternel proclame aux extrémités de la terre: Dites à la fille de Sion: Voici, ton sauveur arrive; Voici, le salaire est avec lui, Et les rétributions le précèdent.'),
  (23, 62, 12, 'On les appellera peuple saint, rachetés de l''Éternel; Et toi, on t''appellera recherchée, ville non délaissée.'),
  (23, 63, 1, 'Qui est celui-ci qui vient d''Édom, De Botsra, en vêtements rouges, En habits éclatants, Et se redressant avec fierté dans la plénitude de sa force? -C''est moi qui ai promis le salut, Qui ai le pouvoir de délivrer. -'),
  (23, 63, 2, 'Pourquoi tes habits sont-ils rouges, Et tes vêtements comme les vêtements de celui qui foule dans la cuve? -'),
  (23, 63, 3, 'J''ai été seul à fouler au pressoir, Et nul homme d''entre les peuples n''était avec moi; Je les ai foulés dans ma colère, Je les ai écrasés dans ma fureur; Leur sang a jailli sur mes vêtements, Et j''ai souillé tous mes habits.'),
  (23, 63, 4, 'Car un jour de vengeance était dans mon cœur, Et l''année de mes rachetés est venue.'),
  (23, 63, 5, 'Je regardais, et personne pour m''aider; J''étais étonné, et personne pour me soutenir; Alors mon bras m''a été en aide, Et ma fureur m''a servi d''appui.'),
  (23, 63, 6, 'J''ai foulé des peuples dans ma colère, Je les ai rendus ivres dans ma fureur, Et j''ai répandu leur sang sur la terre.'),
  (23, 63, 7, 'Je publierai les grâces de l''Éternel, les louanges de l''Éternel, D''après tout ce que l''Éternel a fait pour nous; Je dirai sa grande bonté envers la maison d''Israël, Qu''il a traitée selon ses compassions et la richesse de son amour.'),
  (23, 63, 8, 'Il avait dit: Certainement ils sont mon peuple, Des enfants qui ne seront pas infidèles! Et il a été pour eux un sauveur.'),
  (23, 63, 9, 'Dans toutes leurs détresses ils n''ont pas été sans secours, Et l''ange qui est devant sa face les a sauvés; Il les a lui-même rachetés, dans son amour et sa miséricorde, Et constamment il les a soutenus et portés, aux anciens jours.'),
  (23, 63, 10, 'Mais ils ont été rebelles, ils ont attristé son esprit saint; Et il est devenu leur ennemi, il a combattu contre eux.'),
  (23, 63, 11, 'Alors son peuple se souvint des anciens jours de Moïse: Où est celui qui les fit monter de la mer, Avec le berger de son troupeau? Où est celui qui mettait au milieu d''eux son esprit saint;'),
  (23, 63, 12, 'Qui dirigea la droite de Moïse, Par son bras glorieux; Qui fendit les eaux devant eux, Pour se faire un nom éternel;'),
  (23, 63, 13, 'Qui les dirigea au travers des flots, Comme un coursier dans le désert, Sans qu''ils bronchassent?'),
  (23, 63, 14, 'Comme la bête qui descend dans la vallée, L''esprit de l''Éternel les a menés au repos. C''est ainsi que tu as conduit ton peuple, Pour te faire un nom glorieux.'),
  (23, 63, 15, 'Regarde du ciel, et vois, De ta demeure sainte et glorieuse: Où sont ton zèle et ta puissance? Le frémissement de tes entrailles et tes compassions Ne se font plus sentir envers moi.'),
  (23, 63, 16, 'Tu es cependant notre père, Car Abraham ne nous connaît pas, Et Israël ignore qui nous sommes; C''est toi, Éternel, qui es notre père, Qui, dès l''éternité, t''appelles notre sauveur.'),
  (23, 63, 17, 'Pourquoi, ô Éternel, nous fais-tu errer loin de tes voies, Et endurcis-tu notre cœur contre ta crainte? Reviens, pour l''amour de tes serviteurs, Des tribus de ton héritage!'),
  (23, 63, 18, 'Ton peuple saint n''a possédé le pays que peu de temps; Nos ennemis ont foulé ton sanctuaire.'),
  (23, 63, 19, 'Nous sommes depuis longtemps comme un peuple que tu ne gouvernes pas, Et qui n''est point appelé de ton nom…'),
  (23, 64, 1, 'Oh! si tu déchirais les cieux, et si tu descendais, Les montagnes s''ébranleraient devant toi,'),
  (23, 64, 2, 'Comme s''allume un feu de bois sec, Comme s''évapore l''eau qui bouillonne; Tes ennemis connaîtraient ton nom, Et les nations trembleraient devant toi.'),
  (23, 64, 3, 'Lorsque tu fis des prodiges que nous n''attendions pas, Tu descendis, et les montagnes s''ébranlèrent devant toi.'),
  (23, 64, 4, 'Jamais on n''a appris ni entendu dire, Et jamais l''œil n''a vu qu''un autre dieu que toi Fît de telles choses pour ceux qui se confient en lui.'),
  (23, 64, 5, 'Tu vas au-devant de celui qui pratique avec joie la justice, De ceux qui marchent dans tes voies et se souviennent de toi. Mais tu as été irrité, parce que nous avons péché; Et nous en souffrons longtemps jusqu''à ce que nous soyons sauvés.'),
  (23, 64, 6, 'Nous sommes tous comme des impurs, Et toute notre justice est comme un vêtement souillé; Nous sommes tous flétris comme une feuille, Et nos crimes nous emportent comme le vent.'),
  (23, 64, 7, 'Il n''y a personne qui invoque ton nom, Qui se réveille pour s''attacher à toi: Aussi nous as-tu caché ta face, Et nous laisses-tu périr par l''effet de nos crimes.'),
  (23, 64, 8, 'Cependant, ô Éternel, tu es notre père; Nous sommes l''argile, et c''est toi qui nous as formés, Nous sommes tous l''ouvrage de tes mains.'),
  (23, 64, 9, 'Ne t''irrite pas à l''extrême, ô Éternel, Et ne te souviens pas à toujours du crime; Regarde donc, nous sommes tous ton peuple.'),
  (23, 64, 10, 'Tes villes saintes sont un désert; Sion est un désert, Jérusalem une solitude.'),
  (23, 64, 11, 'Notre maison sainte et glorieuse, Où nos pères célébraient tes louanges, Est devenue la proie des flammes; Tout ce que nous avions de précieux a été dévasté.'),
  (23, 64, 12, 'Après cela, ô Éternel, te contiendras-tu? Est-ce que tu te tairas, et nous affligeras à l''excès?'),
  (23, 65, 1, 'J''ai exaucé ceux qui ne demandaient rien, Je me suis laissé trouver par ceux qui ne me cherchaient pas; J''ai dit: Me voici, me voici! A une nation qui ne s''appelait pas de mon nom.'),
  (23, 65, 2, 'J''ai tendu mes mains tous les jours vers un peuple rebelle, Qui marche dans une voie mauvaise, Au gré de ses pensées;'),
  (23, 65, 3, 'Vers un peuple qui ne cesse de m''irriter en face, Sacrifiant dans les jardins, Et brûlant de l''encens sur les briques:'),
  (23, 65, 4, 'Qui fait des sépulcres sa demeure, Et passe la nuit dans les cavernes, Mangeant de la chair de porc, Et ayant dans ses vases des mets impurs;'),
  (23, 65, 5, 'Qui dit: Retire-toi, Ne m''approche pas, car je suis saint!… De pareilles choses, c''est une fumée dans mes narines, C''est un feu qui brûle toujours.'),
  (23, 65, 6, 'Voici ce que j''ai résolu par devers moi: Loin de me taire, je leur ferai porter la peine, Oui, je leur ferai porter la peine'),
  (23, 65, 7, 'De vos crimes, dit l''Éternel, et des crimes de vos pères, Qui ont brûlé de l''encens sur les montagnes, Et qui m''ont outragé sur les collines; Je leur mesurerai le salaire de leurs actions passées.'),
  (23, 65, 8, 'Ainsi parle l''Éternel: Quand il se trouve du jus dans une grappe, On dit: Ne la détruis pas, Car il y a là une bénédiction! J''agirai de même, pour l''amour de mes serviteurs, Afin de ne pas tout détruire.'),
  (23, 65, 9, 'Je ferai sortir de Jacob une postérité, Et de Juda un héritier de mes montagnes; Mes élus posséderont le pays, Et mes serviteurs y habiteront.'),
  (23, 65, 10, 'Le Saron servira de pâturage au menu bétail, Et la vallée d''Acor servira de gîte au gros bétail, Pour mon peuple qui m''aura cherché.'),
  (23, 65, 11, 'Mais vous, qui abandonnez l''Éternel, Qui oubliez ma montagne sainte, Qui dressez une table pour Gad, Et remplissez une coupe pour Meni,'),
  (23, 65, 12, 'Je vous destine au glaive, Et vous fléchirez tous le genou pour être égorgés; Car j''ai appelé, et vous n''avez point répondu, J''ai parlé, et vous n''avez point écouté; Mais vous avez fait ce qui est mal à mes yeux, Et vous avez choisi ce qui me déplaît.'),
  (23, 65, 13, 'C''est pourquoi ainsi parle le Seigneur, l''Éternel: Voici, mes serviteurs mangeront, et vous aurez faim; Voici, mes serviteurs boiront, et vous aurez soif; Voici, mes serviteurs se réjouiront, et vous serez confondus;'),
  (23, 65, 14, 'Voici, mes serviteurs chanteront dans la joie de leur cœur; Mais vous, vous crierez dans la douleur de votre âme, Et vous vous lamenterez dans l''abattement de votre esprit.'),
  (23, 65, 15, 'Vous laisserez votre nom en imprécation à mes élus; Le Seigneur, l''Éternel, vous fera mourir, Et il donnera à ses serviteurs un autre nom.'),
  (23, 65, 16, 'Celui qui voudra être béni dans le pays Voudra l''être par le Dieu de vérité, Et celui qui jurera dans le pays Jurera par le Dieu de vérité; Car les anciennes souffrances seront oubliées, Elles seront cachées à mes yeux.'),
  (23, 65, 17, 'Car je vais créer de nouveaux cieux Et une nouvelle terre; On ne se rappellera plus les choses passées, Elles ne reviendront plus à l''esprit.'),
  (23, 65, 18, 'Réjouissez-vous plutôt et soyez à toujours dans l''allégresse, A cause de ce que je vais créer; Car je vais créer Jérusalem pour l''allégresse, Et son peuple pour la joie.'),
  (23, 65, 19, 'Je ferai de Jérusalem mon allégresse, Et de mon peuple ma joie; On n''y entendra plus Le bruit des pleurs et le bruit des cris.'),
  (23, 65, 20, 'Il n''y aura plus ni enfants ni vieillards Qui n''accomplissent leurs jours; Car celui qui mourra à cent ans sera jeune, Et le pécheur âgé de cent ans sera maudit.'),
  (23, 65, 21, 'Ils bâtiront des maisons et les habiteront; Ils planteront des vignes et en mangeront le fruit.'),
  (23, 65, 22, 'Ils ne bâtiront pas des maisons pour qu''un autre les habite, Ils ne planteront pas des vignes pour qu''un autre en mange le fruit; Car les jours de mon peuple seront comme les jours des arbres, Et mes élus jouiront de l''œuvre de leurs mains.'),
  (23, 65, 23, 'Ils ne travailleront pas en vain, Et ils n''auront pas des enfants pour les voir périr; Car ils formeront une race bénie de l''Éternel, Et leurs enfants seront avec eux.'),
  (23, 65, 24, 'Avant qu''ils m''invoquent, je répondrai; Avant qu''ils aient cessé de parler, j''exaucerai.'),
  (23, 65, 25, 'Le loup et l''agneau paîtront ensemble, Le lion, comme le bœuf, mangera de la paille, Et le serpent aura la poussière pour nourriture. Il ne se fera ni tort ni dommage Sur toute ma montagne sainte, Dit l''Éternel.'),
  (23, 66, 1, 'Ainsi parle l''Éternel: Le ciel est mon trône, Et la terre mon marchepied. Quelle maison pourriez-vous me bâtir, Et quel lieu me donneriez-vous pour demeure?'),
  (23, 66, 2, 'Toutes ces choses, ma main les a faites, Et toutes ont reçu l''existence, dit l''Éternel. Voici sur qui je porterai mes regards: Sur celui qui souffre et qui a l''esprit abattu, Sur celui qui craint ma parole.'),
  (23, 66, 3, 'Celui qui immole un bœuf est comme celui qui tuerait un homme, Celui qui sacrifie un agneau est comme celui qui romprait la nuque à un chien, Celui qui présente une offrande est comme celui qui répandrait du sang de porc, Celui qui brûle de l''encens est comme celui qui adorerait des idoles; Tous ceux-là se complaisent dans leurs voies, Et leur âme trouve du plaisir dans leurs abominations.'),
  (23, 66, 4, 'Moi aussi, je me complairai dans leur infortune, Et je ferai venir sur eux ce qui cause leur effroi, Parce que j''ai appelé, et qu''ils n''ont point répondu, Parce que j''ai parlé, et qu''ils n''ont point écouté; Mais ils ont fait ce qui est mal à mes yeux, Et ils ont choisi ce qui me déplaît.'),
  (23, 66, 5, 'Écoutez la parole de l''Éternel, Vous qui craignez sa parole. Voici ce que disent vos frères, Qui vous haïssent et vous repoussent A cause de mon nom: Que l''Éternel montre sa gloire, Et que nous voyions votre joie! -Mais ils seront confondus.'),
  (23, 66, 6, 'Une voix éclatante sort de la ville, Une voix sort du temple. C''est la voix de l''Éternel, Qui paie à ses ennemis leur salaire.'),
  (23, 66, 7, 'Avant d''éprouver les douleurs, Elle a enfanté; Avant que les souffrances lui vinssent, Elle a donné naissance à un fils.'),
  (23, 66, 8, 'Qui a jamais entendu pareille chose? Qui a jamais vu rien de semblable? Un pays peut-il naître en un jour? Une nation est-elle enfantée d''un seul coup? A peine en travail, Sion a enfanté ses fils!'),
  (23, 66, 9, 'Ouvrirais-je le sein maternel, Pour ne pas laisser enfanter? dit l''Éternel; Moi, qui fais naître, Empêcherais-je d''enfanter? dit ton Dieu.'),
  (23, 66, 10, 'Réjouissez-vous avec Jérusalem, Faites d''elle le sujet de votre allégresse, Vous tous qui l''aimez; Tressaillez avec elle de joie, Vous tous qui menez deuil sur elle;'),
  (23, 66, 11, 'Afin que vous soyez nourris et rassasiés Du lait de ses consolations, Afin que vous savouriez avec bonheur La plénitude de sa gloire.'),
  (23, 66, 12, 'Car ainsi parle l''Éternel: Voici, je dirigerai vers elle la paix comme un fleuve, Et la gloire des nations comme un torrent débordé, Et vous serez allaités; Vous serez portés sur les bras, Et caressés sur les genoux.'),
  (23, 66, 13, 'Comme un homme que sa mère console, Ainsi je vous consolerai; Vous serez consolés dans Jérusalem.'),
  (23, 66, 14, 'Vous le verrez, et votre cœur sera dans la joie, Et vos os reprendront de la vigueur comme l''herbe; L''Éternel manifestera sa puissance envers ses serviteurs, Mais il fera sentir sa colère à ses ennemis.'),
  (23, 66, 15, 'Car voici, l''Éternel arrive dans un feu, Et ses chars sont comme un tourbillon; Il convertit sa colère en un brasier, Et ses menaces en flammes de feu.'),
  (23, 66, 16, 'C''est par le feu que l''Éternel exerce ses jugements, C''est par son glaive qu''il châtie toute chair; Et ceux que tuera l''Éternel seront en grand nombre.'),
  (23, 66, 17, 'Ceux qui se sanctifient et se purifient dans les jardins, Au milieu desquels ils vont un à un, Qui mangent de la chair de porc, Des choses abominables et des souris, Tous ceux-là périront, dit l''Éternel.'),
  (23, 66, 18, 'Je connais leurs œuvres et leurs pensées. Le temps est venu de rassembler toutes les nations Et toutes les langues; Elles viendront et verront ma gloire.'),
  (23, 66, 19, 'Je mettrai un signe parmi elles, Et j''enverrai leurs réchappés vers les nations, A Tarsis, à Pul et à Lud, qui tirent de l''arc, A Tubal et à Javan, Aux îles lointaines, Qui jamais n''ont entendu parler de moi, Et qui n''ont pas vu ma gloire; Et ils publieront ma gloire parmi les nations.'),
  (23, 66, 20, 'Ils amèneront tous vos frères du milieu de toutes les nations, En offrande à l''Éternel, Sur des chevaux, des chars et des litières, Sur des mulets et des dromadaires, A ma montagne sainte, A Jérusalem, dit l''Éternel, Comme les enfants d''Israël apportent leur offrande, Dans un vase pur, A la maison de l''Éternel.'),
  (23, 66, 21, 'Et je prendrai aussi parmi eux Des sacrificateurs, des Lévites, dit l''Éternel.'),
  (23, 66, 22, 'Car, comme les nouveaux cieux Et la nouvelle terre que je vais créer Subsisteront devant moi, dit l''Éternel, Ainsi subsisteront votre postérité et votre nom.'),
  (23, 66, 23, 'A chaque nouvelle lune et à chaque sabbat, Toute chair viendra se prosterner devant moi, dit l''Éternel.'),
  (23, 66, 24, 'Et quand on sortira, on verra Les cadavres des hommes qui se sont rebellés contre moi; Car leur ver ne mourra point, et leur feu ne s''éteindra point; Et ils seront pour toute chair un objet d''horreur.'),
  (24, 1, 1, 'Paroles de Jérémie, fils de Hilkija, l''un des sacrificateurs d''Anathoth, dans le pays de Benjamin.'),
  (24, 1, 2, 'La parole de l''Éternel lui fut adressée au temps de Josias, fils d''Amon, roi de Juda, la treizième année de son règne,'),
  (24, 1, 3, 'et au temps de Jojakim, fils de Josias, roi de Juda, jusqu''à la fin de la onzième année de Sédécias, fils de Josias, roi de Juda, jusqu''à l''époque où Jérusalem fut emmenée en captivité, au cinquième mois.'),
  (24, 1, 4, 'La parole de l''Éternel me fut adressée, en ces mots:'),
  (24, 1, 5, 'Avant que je t''eusse formé dans le ventre de ta mère, je te connaissais, et avant que tu fusses sorti de son sein, je t''avais consacré, je t''avais établi prophète des nations.'),
  (24, 1, 6, 'Je répondis: Ah! Seigneur Éternel! voici, je ne sais point parler, car je suis un enfant.'),
  (24, 1, 7, 'Et l''Éternel me dit: Ne dis pas: Je suis un enfant. Car tu iras vers tous ceux auprès de qui je t''enverrai, et tu diras tout ce que je t''ordonnerai.'),
  (24, 1, 8, 'Ne les crains point, car je suis avec toi pour te délivrer, dit l''Éternel.'),
  (24, 1, 9, 'Puis l''Éternel étendit sa main, et toucha ma bouche; et l''Éternel me dit: Voici, je mets mes paroles dans ta bouche.'),
  (24, 1, 10, 'Regarde, je t''établis aujourd''hui sur les nations et sur les royaumes, pour que tu arraches et que tu abattes, pour que tu ruines et que tu détruises, pour que tu bâtisses et que tu plantes.'),
  (24, 1, 11, 'La parole de l''Éternel me fut adressée, en ces mots: Que vois-tu, Jérémie? Je répondis: Je vois une branche d''amandier.'),
  (24, 1, 12, 'Et l''Éternel me dit: Tu as bien vu; car je veille sur ma parole, pour l''exécuter.'),
  (24, 1, 13, 'La parole de l''Éternel me fut adressée une seconde fois, en ces mots: Que vois-tu? Je répondis: Je vois une chaudière bouillante, du côté du septentrion.'),
  (24, 1, 14, 'Et l''Éternel me dit: C''est du septentrion que la calamité se répandra sur tous les habitants du pays.'),
  (24, 1, 15, 'Car voici, je vais appeler tous les peuples des royaumes du septentrion, dit l''Éternel; ils viendront, et placeront chacun leur siège à l''entrée des portes de Jérusalem, contre ses murailles tout alentour, et contre toutes les villes de Juda.'),
  (24, 1, 16, 'Je prononcerai mes jugements contre eux, à cause de toute leur méchanceté, parce qu''ils m''ont abandonné et ont offert de l''encens à d''autres dieux, et parce qu''ils se sont prosternés devant l''ouvrage de leurs mains.'),
  (24, 1, 17, 'Et toi, ceins tes reins, lève-toi, et dis-leur tout ce que je t''ordonnerai. Ne tremble pas en leur présence, de peur que je ne te fasse trembler devant eux.'),
  (24, 1, 18, 'Voici, je t''établis en ce jour sur tout le pays comme une ville forte, une colonne de fer et un mur d''airain, contre les rois de Juda, contre ses chefs, contre ses sacrificateurs, et contre le peuple du pays.'),
  (24, 1, 19, 'Ils te feront la guerre, mais ils ne te vaincront pas; car je suis avec toi pour te délivrer, dit l''Éternel.'),
  (24, 2, 1, 'La parole de l''Éternel me fut adressée, en ces mots:'),
  (24, 2, 2, 'Va, et crie aux oreilles de Jérusalem: Ainsi parle l''Éternel: Je me souviens de ton amour lorsque tu étais jeune, De ton affection lorsque tu étais fiancée, Quand tu me suivais au désert, Dans une terre inculte.'),
  (24, 2, 3, 'Israël était consacré à l''Éternel, Il était les prémices de son revenu; Tous ceux qui en mangeaient se rendaient coupables, Et le malheur fondait sur eux, dit l''Éternel.'),
  (24, 2, 4, 'Écoutez la parole de l''Éternel, maison de Jacob, Et vous toutes, familles de la maison d''Israël!'),
  (24, 2, 5, 'Ainsi parle l''Éternel: Quelle iniquité vos pères ont-ils trouvée en moi, Pour s''éloigner de moi, Et pour aller après des choses de néant et n''être eux-mêmes que néant?'),
  (24, 2, 6, 'Ils n''ont pas dit: Où est l''Éternel, Qui nous a fait monter du pays d''Égypte, Qui nous a conduits dans le désert, Dans une terre aride et pleine de fosses, Dans une terre où règnent la sécheresse et l''ombre de la mort, Dans une terre par où personne ne passe, Et où n''habite aucun homme?'),
  (24, 2, 7, 'Je vous ai fait venir dans un pays semblable à un verger, Pour que vous en mangiez les fruits et les meilleures productions; Mais vous êtes venus, et vous avez souillé mon pays, Et vous avez fait de mon héritage une abomination.'),
  (24, 2, 8, 'Les sacrificateurs n''ont pas dit: Où est l''Éternel? Les dépositaires de la loi ne m''ont pas connu, Les pasteurs m''ont été infidèles, Les prophètes ont prophétisé par Baal, Et sont allés après ceux qui ne sont d''aucun secours.'),
  (24, 2, 9, 'C''est pourquoi je veux encore contester avec vous, dit l''Éternel, Je veux contester avec les enfants de vos enfants.'),
  (24, 2, 10, 'Passez aux îles de Kittim, et regardez! Envoyez quelqu''un à Kédar, observez bien, Et regardez s''il y a rien de semblable!'),
  (24, 2, 11, 'Y a-t-il une nation qui change ses dieux, Quoiqu''ils ne soient pas des Dieux? Et mon peuple a changé sa gloire contre ce qui n''est d''aucun secours!'),
  (24, 2, 12, 'Cieux, soyez étonnés de cela; Frémissez d''épouvante et d''horreur! dit l''Éternel.'),
  (24, 2, 13, 'Car mon peuple a commis un double péché: Ils m''ont abandonné, moi qui suis une source d''eau vive, Pour se creuser des citernes, des citernes crevassées, Qui ne retiennent pas l''eau.'),
  (24, 2, 14, 'Israël est-il un esclave acheté, ou né dans la maison? Pourquoi donc devient-il une proie?'),
  (24, 2, 15, 'Contre lui les lionceaux rugissent, poussent leurs cris, Et ils ravagent son pays; Ses villes sont brûlées, il n''y a plus d''habitants.'),
  (24, 2, 16, 'Même les enfants de Noph et de Tachpanès Te briseront le sommet de la tête.'),
  (24, 2, 17, 'Cela ne t''arrive-t-il pas Parce que tu as abandonné l''Éternel, ton Dieu, Lorsqu''il te dirigeait dans la bonne voie?'),
  (24, 2, 18, 'Et maintenant, qu''as-tu à faire d''aller en Égypte, Pour boire l''eau du Nil? Qu''as-tu à faire d''aller en Assyrie, Pour boire l''eau du fleuve?'),
  (24, 2, 19, 'Ta méchanceté te châtiera, et ton infidélité te punira, Tu sauras et tu verras que c''est une chose mauvaise et amère D''abandonner l''Éternel, ton Dieu, Et de n''avoir de moi aucune crainte, Dit le Seigneur, l''Éternel des armées.'),
  (24, 2, 20, 'Tu as dès longtemps brisé ton joug, Rompu tes liens, Et tu as dit: Je ne veux plus être dans la servitude! Mais sur toute colline élevée Et sous tout arbre vert Tu t''es courbée comme une prostituée.'),
  (24, 2, 21, 'Je t''avais plantée comme une vigne excellente Et du meilleur plant; Comment as-tu changé, Dégénéré en une vigne étrangère?'),
  (24, 2, 22, 'Quand tu te laverais avec du nitre, Quand tu emploierais beaucoup de potasse, Ton iniquité resterait marquée devant moi, Dit le Seigneur, l''Éternel.'),
  (24, 2, 23, 'Comment dirais-tu: Je ne me suis point souillée, Je ne suis point allée après les Baals? Regarde tes pas dans la vallée, Reconnais ce que tu as fait, Dromadaire à la course légère et vagabonde!'),
  (24, 2, 24, 'Anesse sauvage, habituée au désert, Haletante dans l''ardeur de sa passion, Qui l''empêchera de satisfaire son désir? Tous ceux qui la cherchent n''ont pas à se fatiguer; Ils la trouvent pendant son mois.'),
  (24, 2, 25, 'Ne t''expose pas à avoir les pieds nus, Ne dessèche pas ton gosier! Mais tu dis: C''est en vain, non! Car j''aime les dieux étrangers, je veux aller après eux.'),
  (24, 2, 26, 'Comme un voleur est confus lorsqu''il est surpris, Ainsi seront confus ceux de la maison d''Israël, Eux, leurs rois, leurs chefs, Leurs sacrificateurs et leurs prophètes.'),
  (24, 2, 27, 'Ils disent au bois: Tu es mon père! Et à la pierre: Tu m''as donné la vie! Car ils me tournent le dos, ils ne me regardent pas. Et quand ils sont dans le malheur, ils disent: Lève-toi, sauve-nous!'),
  (24, 2, 28, 'Où donc sont tes dieux que tu t''es faits? Qu''ils se lèvent, s''ils peuvent te sauver au temps du malheur! Car tu as autant de dieux que de villes, ô Juda!'),
  (24, 2, 29, 'Pourquoi contesteriez-vous avec moi? Vous m''avez tous été infidèles, dit l''Éternel.'),
  (24, 2, 30, 'En vain ai-je frappé vos enfants; Ils n''ont point eu égard à la correction; Votre glaive a dévoré vos prophètes, Comme un lion destructeur.'),
  (24, 2, 31, 'Hommes de cette génération, considérez la parole de l''Éternel! Ai-je été pour Israël un désert, Ou un pays d''épaisses ténèbres? Pourquoi mon peuple dit-il: Nous sommes libres, Nous ne voulons pas retourner à toi?'),
  (24, 2, 32, 'La jeune fille oublie-t-elle ses ornements, La fiancée sa ceinture? Et mon peuple m''a oublié Depuis des jours sans nombre.'),
  (24, 2, 33, 'Comme tu es habile dans tes voies pour chercher ce que tu aimes! C''est même au crime que tu les exerces.'),
  (24, 2, 34, 'Jusque sur les pans de ton habit se trouve Le sang de pauvres innocents, Que tu n''as pas surpris faisant effraction.')
insert into public.bible_verses (book_id, chapter, verse, text) values
  (24, 2, 35, 'Malgré cela, tu dis: Oui, je suis innocente! Certainement sa colère s''est détournée de moi! Voici, je vais contester avec toi, Parce que tu dis: Je n''ai point péché.'),
  (24, 2, 36, 'Pourquoi tant d''empressement à changer ton chemin? C''est de l''Égypte que viendra ta honte, Comme elle est venue de l''Assyrie.'),
  (24, 2, 37, 'De là aussi tu sortiras, les mains sur la tête; Car l''Éternel rejette ceux en qui tu te confies, Et tu ne réussiras pas auprès d''eux.'),
  (24, 3, 1, 'Il dit: Lorsqu''un homme répudie sa femme, Qu''elle le quitte et devient la femme d''un autre, Cet homme retourne-t-il encore vers elle? Le pays même ne serait-il pas souillé? Et toi, tu t''es prostituée à de nombreux amants, Et tu reviendrais à moi! dit l''Éternel.'),
  (24, 3, 2, 'Lève tes yeux vers les hauteurs, et regarde! Où ne t''es-tu pas prostituée! Tu te tenais sur les chemins, comme l''Arabe dans le désert, Et tu as souillé le pays par tes prostitutions et par ta méchanceté.'),
  (24, 3, 3, 'Aussi les pluies ont-elles été retenues, Et la pluie du printemps a-t-elle manqué; Mais tu as eu le front d''une femme prostituée, Tu n''as pas voulu avoir honte.'),
  (24, 3, 4, 'Maintenant, n''est-ce pas? tu cries vers moi: Mon père! Tu as été l''ami de ma jeunesse!'),
  (24, 3, 5, 'Gardera-t-il à toujours sa colère? La conservera-t-il à jamais? Et voici, tu as dit, tu as fait des choses criminelles, tu les as consommées.'),
  (24, 3, 6, 'L''Éternel me dit, au temps du roi Josias: As-tu vu ce qu''a fait l''infidèle Israël? Elle est allée sur toute montagne élevée et sous tout arbre vert, et là elle s''est prostituée.'),
  (24, 3, 7, 'Je disais: Après avoir fait toutes ces choses, elle reviendra à moi. Mais elle n''est pas revenue. Et sa sœur, la perfide Juda, en a été témoin.'),
  (24, 3, 8, 'Quoique j''eusse répudié l''infidèle Israël à cause de tous ses adultères, et que je lui eusse donné sa lettre de divorce, j''ai vu que la perfide Juda, sa sœur, n''a point eu de crainte, et qu''elle est allée se prostituer pareillement.'),
  (24, 3, 9, 'Par sa criante impudicité Israël a souillé le pays, elle a commis un adultère avec la pierre et le bois.'),
  (24, 3, 10, 'Malgré tout cela, la perfide Juda, sa sœur, n''est pas revenue à moi de tout son cœur; c''est avec fausseté qu''elle l''a fait, dit l''Éternel.'),
  (24, 3, 11, 'L''Éternel me dit: L''infidèle Israël paraît innocente En comparaison de la perfide Juda.'),
  (24, 3, 12, 'Va, crie ces paroles vers le septentrion, et dis: Reviens, infidèle Israël! dit l''Éternel. Je ne jetterai pas sur vous un regard sévère; Car je suis miséricordieux, dit l''Éternel, Je ne garde pas ma colère à toujours.'),
  (24, 3, 13, 'Reconnais seulement ton iniquité, Reconnais que tu as été infidèle à l''Éternel, ton Dieu, Que tu as dirigé çà et là tes pas vers les dieux étrangers, Sous tout arbre vert, Et que tu n''as pas écouté ma voix, dit l''Éternel.'),
  (24, 3, 14, 'Revenez, enfants rebelles, dit l''Éternel; Car je suis votre maître. Je vous prendrai, un d''une ville, deux d''une famille, Et je vous ramènerai dans Sion.'),
  (24, 3, 15, 'Je vous donnerai des bergers selon mon cœur, Et ils vous paîtront avec intelligence et avec sagesse.'),
  (24, 3, 16, 'Lorsque vous aurez multiplié et fructifié dans le pays, En ces jours-là, dit l''Éternel, On ne parlera plus de l''arche de l''alliance de l''Éternel; Elle ne viendra plus à la pensée; On ne se la rappellera plus, on ne s''apercevra plus de son absence, Et l''on n''en fera point une autre.'),
  (24, 3, 17, 'En ce temps-là, on appellera Jérusalem le trône de l''Éternel; Toutes les nations s''assembleront à Jérusalem, au nom de l''Éternel, Et elles ne suivront plus les penchants de leur mauvais cœur.'),
  (24, 3, 18, 'En ces jours, La maison de Juda marchera avec la maison d''Israël; Elles viendront ensemble du pays du septentrion Au pays dont j''ai donné la possession à vos pères.'),
  (24, 3, 19, 'Je disais: Comment te mettrai-je parmi mes enfants, Et te donnerai-je un pays de délices, Un héritage, le plus bel ornement des nations? Je disais: Tu m''appelleras: Mon père! Et tu ne te détourneras pas de moi.'),
  (24, 3, 20, 'Mais, comme une femme est infidèle à son amant, Ainsi vous m''avez été infidèles, maison d''Israël, Dit l''Éternel.'),
  (24, 3, 21, 'Une voix se fait entendre sur les lieux élevés; Ce sont les pleurs, les supplications des enfants d''Israël; Car ils ont perverti leur voie, Ils ont oublié l''Éternel, leur Dieu.'),
  (24, 3, 22, 'Revenez, enfants rebelles, Je pardonnerai vos infidélités. -Nous voici, nous allons à toi, Car tu es l''Éternel, notre Dieu.'),
  (24, 3, 23, 'Oui, le bruit qui vient des collines et des montagnes n''est que mensonge; Oui, c''est en l''Éternel, notre Dieu, qu''est le salut d''Israël.'),
  (24, 3, 24, 'Les idoles ont dévoré le produit du travail de nos pères, Dès notre jeunesse, Leurs brebis et leurs bœufs, leurs fils et leurs filles.'),
  (24, 3, 25, 'Nous avons notre honte pour couche, Et notre ignominie pour couverture; Car nous avons péché contre l''Éternel, notre Dieu, Nous et nos pères, dès notre jeunesse jusqu''à ce jour, Et nous n''avons pas écouté la voix de l''Éternel, notre Dieu. -'),
  (24, 4, 1, 'Israël, si tu reviens, si tu reviens à moi, dit l''Éternel, Si tu ôtes tes abominations de devant moi, Tu ne seras plus errant.'),
  (24, 4, 2, 'Si tu jures: L''Éternel est vivant! Avec vérité, avec droiture et avec justice, Alors les nations seront bénies en lui, Et se glorifieront en lui.'),
  (24, 4, 3, 'Car ainsi parle l''Éternel aux hommes de Juda et de Jérusalem: Défrichez-vous un champ nouveau, Et ne semez pas parmi les épines.'),
  (24, 4, 4, 'Circoncisez-vous pour l''Éternel, circoncisez vos cœurs, Hommes de Juda et habitants de Jérusalem, De peur que ma colère n''éclate comme un feu, Et ne s''enflamme, sans qu''on puisse l''éteindre, A cause de la méchanceté de vos actions.'),
  (24, 4, 5, 'Annoncez en Juda, publiez à Jérusalem, Et dites: Sonnez de la trompette dans le pays! Criez à pleine voix, et dites: Rassemblez-vous, et allons dans les villes fortes!'),
  (24, 4, 6, 'Élevez une bannière vers Sion, Fuyez, ne vous arrêtez pas! Car je fais venir du septentrion le malheur Et un grand désastre.'),
  (24, 4, 7, 'Le lion s''élance de son taillis, Le destructeur des nations est en marche, il a quitté son lieu, Pour ravager ton pays; Tes villes seront ruinées, il n''y aura plus d''habitants.'),
  (24, 4, 8, 'C''est pourquoi couvrez-vous de sacs, pleurez et gémissez; Car la colère ardente de l''Éternel ne se détourne pas de nous.'),
  (24, 4, 9, 'En ce jour-là, dit l''Éternel, Le roi et les chefs perdront courage, Les sacrificateurs seront étonnés, Et les prophètes stupéfaits.'),
  (24, 4, 10, 'Je dis: Ah! Seigneur Éternel! Tu as donc trompé ce peuple et Jérusalem, en disant: Vous aurez la paix! Et cependant l''épée menace leur vie.'),
  (24, 4, 11, 'En ce temps-là, il sera dit à ce peuple et à Jérusalem: Un vent brûlant souffle des lieux élevés du désert Sur le chemin de la fille de mon peuple, Non pour vanner ni pour nettoyer le grain.'),
  (24, 4, 12, 'C''est un vent impétueux qui vient de là jusqu''à moi. Maintenant, je prononcerai leur sentence.'),
  (24, 4, 13, 'Voici, le destructeur s''avance comme les nuées; Ses chars sont comme un tourbillon, Ses chevaux sont plus légers que les aigles. -Malheur à nous, car nous sommes détruits! -'),
  (24, 4, 14, 'Purifie ton cœur du mal, Jérusalem, Afin que tu sois sauvée! Jusques à quand garderas-tu dans ton cœur tes pensées iniques?'),
  (24, 4, 15, 'Car une voix qui part de Dan annonce la calamité, Elle la publie depuis la montagne d''Éphraïm.'),
  (24, 4, 16, 'Dites-le aux nations, faites-le connaître à Jérusalem: Des assiégeants viennent d''une terre lointaine; Ils poussent des cris contre les villes de Juda.'),
  (24, 4, 17, 'Comme ceux qui gardent un champ, ils entourent Jérusalem, Car elle s''est révoltée contre moi, dit l''Éternel.'),
  (24, 4, 18, 'C''est là le produit de tes voies et de tes actions, C''est là le produit de ta méchanceté; Certes cela est amer, cela pénètre jusqu''à ton cœur.'),
  (24, 4, 19, 'Mes entrailles! mes entrailles: je souffre au dedans de mon cœur, Le cœur me bat, je ne puis me taire; Car tu entends, mon âme, le son de la trompette, Le cri de guerre.'),
  (24, 4, 20, 'On annonce ruine sur ruine, Car tout le pays est ravagé; Mes tentes sont ravagées tout à coup, Mes pavillons en un instant.'),
  (24, 4, 21, 'Jusques à quand verrai-je la bannière, Et entendrai-je le son de la trompette? -'),
  (24, 4, 22, 'Certainement mon peuple est fou, il ne me connaît pas; Ce sont des enfants insensés, dépourvus d''intelligence; Ils sont habiles pour faire le mal, Mais ils ne savent pas faire le bien. -'),
  (24, 4, 23, 'Je regarde la terre, et voici, elle est informe et vide; Les cieux, et leur lumière a disparu.'),
  (24, 4, 24, 'Je regarde les montagnes, et voici, elles sont ébranlées; Et toutes les collines chancellent.'),
  (24, 4, 25, 'Je regarde, et voici, il n''y a point d''homme; Et tous les oiseaux des cieux ont pris la fuite.'),
  (24, 4, 26, 'Je regarde, et voici, le Carmel est un désert; Et toutes ses villes sont détruites, devant l''Éternel, Devant son ardente colère.'),
  (24, 4, 27, 'Car ainsi parle l''Éternel: Tout le pays sera dévasté; Mais je ne ferai pas une entière destruction.'),
  (24, 4, 28, 'A cause de cela, le pays est en deuil, Et les cieux en haut sont obscurcis; Car je l''ai dit, je l''ai résolu, Et je ne m''en repens pas, je ne me rétracterai pas.'),
  (24, 4, 29, 'Au bruit des cavaliers et des archers, toutes les villes sont en fuite; On entre dans les bois, on monte sur les rochers; Toutes les villes sont abandonnées, il n''y a plus d''habitants.'),
  (24, 4, 30, 'Et toi, dévastée, que vas-tu faire? Tu te revêtiras de cramoisi, tu te pareras d''ornements d''or, Tu mettras du fard à tes yeux; Mais c''est en vain que tu t''embelliras; Tes amants te méprisent, Ils en veulent à ta vie.'),
  (24, 4, 31, 'Car j''entends des cris comme ceux d''une femme en travail, Des cris d''angoisse comme dans un premier enfantement. C''est la voix de la fille de Sion; elle soupire, elle étend les mains: Malheureuse que je suis! je succombe sous les meurtriers!'),
  (24, 5, 1, 'Parcourez les rues de Jérusalem, Regardez, informez-vous, cherchez dans les places, S''il s''y trouve un homme, s''il y en a un Qui pratique la justice, qui s''attache à la vérité, Et je pardonne à Jérusalem.'),
  (24, 5, 2, 'Même quand ils disent: L''Éternel est vivant! C''est faussement qu''ils jurent.'),
  (24, 5, 3, 'Éternel, tes yeux n''aperçoivent-ils pas la vérité? Tu les frappes, et ils ne sentent rien; Tu les consumes, et ils ne veulent pas recevoir instruction; Ils prennent un visage plus dur que le roc, Ils refusent de se convertir.'),
  (24, 5, 4, 'Je disais: Ce ne sont que les petits; Ils agissent en insensés, parce qu''ils ne connaissent pas la voie de l''Éternel, La loi de leur Dieu.'),
  (24, 5, 5, 'J''irai vers les grands, et je leur parlerai; Car eux, ils connaissent la voie de l''Éternel, La loi de leur Dieu; Mais ils ont tous aussi brisé le joug, Rompu les liens.'),
  (24, 5, 6, 'C''est pourquoi le lion de la forêt les tue, Le loup du désert les détruit, La panthère est aux aguets devant leurs villes; Tous ceux qui en sortiront seront déchirés; Car leurs transgressions sont nombreuses, Leurs infidélités se sont multipliées.'),
  (24, 5, 7, 'Pourquoi te pardonnerais-je? Tes enfants m''ont abandonné, Et ils jurent par des dieux qui n''existent pas. J''ai reçu leurs serments, et ils se livrent à l''adultère, Ils sont en foule dans la maison de la prostituée.'),
  (24, 5, 8, 'Semblables à des chevaux bien nourris, qui courent çà et là, Ils hennissent chacun après la femme de son prochain.'),
  (24, 5, 9, 'Ne châtierais-je pas ces choses-là, dit l''Éternel, Ne me vengerais-je pas d''une pareille nation?'),
  (24, 5, 10, 'Montez sur ses murailles, et abattez, Mais ne détruisez pas entièrement! Enlevez ses ceps Qui n''appartiennent point à l''Éternel!'),
  (24, 5, 11, 'Car la maison d''Israël et la maison de Juda m''ont été infidèles, Dit l''Éternel.'),
  (24, 5, 12, 'Ils renient l''Éternel, ils disent: Il n''existe pas! Et le malheur ne viendra pas sur nous, Nous ne verrons ni l''épée ni la famine.'),
  (24, 5, 13, 'Les prophètes ne sont que du vent, Et personne ne parle en eux. Qu''il leur soit fait ainsi!'),
  (24, 5, 14, 'C''est pourquoi ainsi parle l''Éternel, le Dieu des armées: Parce que vous avez dit cela, Voici, je veux que ma parole dans ta bouche soit du feu, Et ce peuple du bois, et que ce feu les consume.'),
  (24, 5, 15, 'Voici, je fais venir de loin une nation contre vous, maison d''Israël, Dit l''Éternel; C''est une nation forte, c''est une nation ancienne, Une nation dont tu ne connais pas la langue, Et dont tu ne comprendras point les paroles.'),
  (24, 5, 16, 'Son carquois est comme un sépulcre ouvert; Ils sont tous des héros.'),
  (24, 5, 17, 'Elle dévorera ta moisson et ton pain, Elle dévorera tes fils et tes filles, Elle dévorera tes brebis et tes bœufs, Elle dévorera ta vigne et ton figuier; Elle détruira par l''épée tes villes fortes dans lesquelles tu te confies.'),
  (24, 5, 18, 'Mais en ces jours, dit l''Éternel, Je ne vous détruirai pas entièrement.'),
  (24, 5, 19, 'Si vous dites alors: Pourquoi l''Éternel, notre Dieu, nous fait-il tout cela? Tu leur répondras: Comme vous m''avez abandonné, Et que vous avez servi des dieux étrangers dans votre pays, Ainsi vous servirez des étrangers dans un pays qui n''est pas le vôtre.'),
  (24, 5, 20, 'Annoncez ceci à la maison de Jacob, Publiez-le en Juda, et dites:'),
  (24, 5, 21, 'Écoutez ceci, peuple insensé, et qui n''as point de cœur! Ils ont des yeux et ne voient point, Ils ont des oreilles et n''entendent point.'),
  (24, 5, 22, 'Ne me craindrez-vous pas, dit l''Éternel, Ne tremblerez-vous pas devant moi? C''est moi qui ai donné à la mer le sable pour limite, Limite éternelle qu''elle ne doit pas franchir; Ses flots s''agitent, mais ils sont impuissants; Ils mugissent, mais ils ne la franchissent pas.'),
  (24, 5, 23, 'Ce peuple a un cœur indocile et rebelle; Ils se révoltent, et s''en vont.'),
  (24, 5, 24, 'Ils ne disent pas dans leur cœur: Craignons l''Éternel, notre Dieu, Qui donne la pluie en son temps, La pluie de la première et de l''arrière saison, Et qui nous réserve les semaines destinées à la moisson.'),
  (24, 5, 25, 'C''est à cause de vos iniquités que ces dispensations n''ont pas lieu, Ce sont vos péchés qui vous privent de ces biens.'),
  (24, 5, 26, 'Car il se trouve parmi mon peuple des méchants; Ils épient comme l''oiseleur qui dresse des pièges, Ils tendent des filets, et prennent des hommes.'),
  (24, 5, 27, 'Comme une cage est remplie d''oiseaux, Leurs maisons sont remplies de fraude; C''est ainsi qu''ils deviennent puissants et riches.'),
  (24, 5, 28, 'Ils s''engraissent, ils sont brillants d''embonpoint; Ils dépassent toute mesure dans le mal, Ils ne défendent pas la cause, la cause de l''orphelin, et ils prospèrent; Ils ne font pas droit aux indigents.'),
  (24, 5, 29, 'Ne châtierais-je pas ces choses-là, dit l''Éternel, Ne me vengerais-je pas d''une pareille nation?'),
  (24, 5, 30, 'Des choses horribles, abominables, Se font dans le pays.'),
  (24, 5, 31, 'Les prophètes prophétisent avec fausseté, Les sacrificateurs dominent sous leur conduite, Et mon peuple prend plaisir à cela. Que ferez-vous à la fin?'),
  (24, 6, 1, 'Fuyez, enfants de Benjamin, du milieu de Jérusalem, Sonnez de la trompette à Tekoa, Élevez un signal à Beth-Hakkérem! Car on voit venir du septentrion le malheur Et un grand désastre.'),
  (24, 6, 2, 'La belle et la délicate, Je la détruis, la fille de Sion!'),
  (24, 6, 3, 'Vers elle marchent des bergers avec leurs troupeaux; Ils dressent des tentes autour d''elle, Ils broutent chacun sa part. -'),
  (24, 6, 4, 'Préparez-vous à l''attaquer! Allons! montons en plein midi!… Malheureusement pour nous, le jour baisse, Les ombres du soir s''allongent.'),
  (24, 6, 5, 'Allons! montons de nuit! Détruisons ses palais! -'),
  (24, 6, 6, 'Car ainsi parle l''Éternel des armées: Abattez les arbres, Élevez des terrasses contre Jérusalem! C''est la ville qui doit être châtiée; Il n''y a qu''oppression au milieu d''elle.'),
  (24, 6, 7, 'Comme un puits fait jaillir ses eaux, Ainsi elle fait jaillir sa méchanceté; Il n''est bruit en son sein que de violence et de ruine; Sans cesse à mes regards s''offrent la douleur et les plaies.'),
  (24, 6, 8, 'Reçois instruction, Jérusalem, De peur que je ne m''éloigne de toi, Que je ne fasse de toi un désert, Un pays inhabité!'),
  (24, 6, 9, 'Ainsi parle l''Éternel des armées: On grappillera comme une vigne les restes d''Israël. Portes-y de nouveau la main, Comme le vendangeur sur les ceps.'),
  (24, 6, 10, 'A qui m''adresser, et qui prendre à témoin pour qu''on écoute? Voici, leur oreille est incirconcise, Et ils sont incapables d''être attentifs; Voici, la parole de l''Éternel est pour eux un opprobre, Ils n''y trouvent aucun plaisir.'),
  (24, 6, 11, 'Je suis plein de la fureur de l''Éternel, je ne puis la contenir. Répands-la sur l''enfant dans la rue, Et sur les assemblées des jeunes gens. Car l''homme et la femme seront pris, Le vieillard et celui qui est chargé de jours.'),
  (24, 6, 12, 'Leurs maisons passeront à d''autres, Les champs et les femmes aussi, Quand j''étendrai ma main sur les habitants du pays, Dit l''Éternel.'),
  (24, 6, 13, 'Car depuis le plus petit jusqu''au plus grand, Tous sont avides de gain; Depuis le prophète jusqu''au sacrificateur, Tous usent de tromperie.'),
  (24, 6, 14, 'Ils pansent à la légère la plaie de la fille de mon peuple: Paix! paix! disent-ils; Et il n''y a point de paix;'),
  (24, 6, 15, 'Ils seront confus, car ils commettent des abominations; Ils ne rougissent pas, ils ne connaissent pas la honte; C''est pourquoi ils tomberont avec ceux qui tombent, Ils seront renversés quand je les châtierai, Dit l''Éternel.'),
  (24, 6, 16, 'Ainsi parle l''Éternel: Placez-vous sur les chemins, regardez, Et demandez quels sont les anciens sentiers, Quelle est la bonne voie; marchez-y, Et vous trouverez le repos de vos âmes! Mais ils répondent: Nous n''y marcherons pas.'),
  (24, 6, 17, 'J''ai mis près de vous des sentinelles: Soyez attentifs au son de la trompette! Mais ils répondent: Nous n''y serons pas attentifs.'),
  (24, 6, 18, 'C''est pourquoi écoutez, nations! Sachez ce qui leur arrivera, assemblée des peuples!'),
  (24, 6, 19, 'Écoute, terre! Voici, je fais venir sur ce peuple le malheur, Fruit de ses pensées; Car ils n''ont point été attentifs à mes paroles, Ils ont méprisé ma loi.'),
  (24, 6, 20, 'Qu''ai-je besoin de l''encens qui vient de Séba, Du roseau aromatique d''un pays lointain? Vos holocaustes ne me plaisent point, Et vos sacrifices ne me sont point agréables.'),
  (24, 6, 21, 'C''est pourquoi ainsi parle l''Éternel: Voici, je mettrai devant ce peuple des pierres d''achoppement, Contre lesquelles se heurteront ensemble pères et fils, Voisins et amis, et ils périront.'),
  (24, 6, 22, 'Ainsi parle l''Éternel: Voici, un peuple vient du pays du septentrion, Une grande nation se lève des extrémités de la terre.'),
  (24, 6, 23, 'Ils portent l''arc et le javelot; Ils sont cruels, sans miséricorde; Leur voix mugit comme la mer; Ils sont montés sur des chevaux, Prêts à combattre comme un seul homme, Contre toi, fille de Sion!'),
  (24, 6, 24, 'Au bruit de leur approche, Nos mains s''affaiblissent, L''angoisse nous saisit, Comme la douleur d''une femme qui accouche.'),
  (24, 6, 25, 'Ne sortez pas dans les champs, N''allez pas sur les chemins; Car là est le glaive de l''ennemi, Et l''épouvante règne à l''entour!'),
  (24, 6, 26, 'Fille de mon peuple, couvre-toi d''un sac et roule-toi dans la cendre, Prends le deuil comme pour un fils unique, Verse des larmes, des larmes amères! Car le dévastateur vient sur nous à l''improviste.'),
  (24, 6, 27, 'Je t''avais établi en observation parmi mon peuple, Comme une forteresse, Pour que tu connusses et sondasses leur voie.'),
  (24, 6, 28, 'Ils sont tous des rebelles, des calomniateurs, De l''airain et du fer; Ils sont tous corrompus.'),
  (24, 6, 29, 'Le soufflet est brûlant, Le plomb est consumé par le feu; C''est en vain qu''on épure, Les scories ne se détachent pas.'),
  (24, 6, 30, 'On les appelle de l''argent méprisable, Car l''Éternel les a rejetés.'),
  (24, 7, 1, 'La parole qui fut adressée à Jérémie de la part de l''Éternel, en ces mots:'),
  (24, 7, 2, 'Place-toi à la porte de la maison de l''Éternel, Et là publie cette parole, Et dis: Écoutez la parole de l''Éternel, Vous tous, hommes de Juda, qui entrez par ces portes, Pour vous prosterner devant l''Éternel!'),
  (24, 7, 3, 'Ainsi parle l''Éternel des armées, le Dieu d''Israël: Réformez vos voies et vos œuvres, Et je vous laisserai demeurer dans ce lieu.'),
  (24, 7, 4, 'Ne vous livrez pas à des espérances trompeuses, en disant: C''est ici le temple de l''Éternel, le temple de l''Éternel, Le temple de l''Éternel!'),
  (24, 7, 5, 'Si vous réformez vos voies et vos œuvres, Si vous pratiquez la justice envers les uns et les autres,'),
  (24, 7, 6, 'Si vous n''opprimez pas l''étranger, l''orphelin et la veuve, Si vous ne répandez pas en ce lieu le sang innocent, Et si vous n''allez pas après d''autres dieux, pour votre malheur,'),
  (24, 7, 7, 'Alors je vous laisserai demeurer dans ce lieu, Dans le pays que j''ai donné à vos pères, D''éternité en éternité.'),
  (24, 7, 8, 'Mais voici, vous vous livrez à des espérances trompeuses, Qui ne servent à rien.'),
  (24, 7, 9, 'Quoi! dérober, tuer, commettre des adultères, Jurer faussement, offrir de l''encens à Baal, Aller après d''autres dieux que vous ne connaissez pas!…'),
  (24, 7, 10, 'Puis vous venez vous présenter devant moi, Dans cette maison sur laquelle mon nom est invoqué, Et vous dites: Nous sommes délivrés!… Et c''est afin de commettre toutes ces abominations!'),
  (24, 7, 11, 'Est-elle à vos yeux une caverne de voleurs, Cette maison sur laquelle mon nom est invoqué? Je le vois moi-même, dit l''Éternel.'),
  (24, 7, 12, 'Allez donc au lieu qui m''était consacré à Silo, Où j''avais fait autrefois résider mon nom. Et voyez comment je l''ai traité, A cause de la méchanceté de mon peuple d''Israël.'),
  (24, 7, 13, 'Et maintenant, puisque vous avez commis toutes ces actions, Dit l''Éternel, Puisque je vous ai parlé dès le matin et que vous n''avez pas écouté, Puisque je vous ai appelés et que vous n''avez pas répondu,'),
  (24, 7, 14, 'Je traiterai la maison sur laquelle mon nom est invoqué, Sur laquelle vous faites reposer votre confiance, Et le lieu que j''ai donné à vous et à vos pères, De la même manière que j''ai traité Silo;'),
  (24, 7, 15, 'Et je vous rejetterai loin de ma face, Comme j''ai rejeté tous vos frères, Toute la postérité d''Éphraïm.'),
  (24, 7, 16, 'Et toi, n''intercède pas en faveur de ce peuple, N''élève pour eux ni supplications ni prières, Ne fais pas des instances auprès de moi; Car je ne t''écouterai pas.'),
  (24, 7, 17, 'Ne vois-tu pas ce qu''ils font dans les villes de Juda Et dans les rues de Jérusalem?'),
  (24, 7, 18, 'Les enfants ramassent du bois, Les pères allument le feu, Et les femmes pétrissent la pâte, Pour préparer des gâteaux à la reine du ciel, Et pour faire des libations à d''autres dieux, Afin de m''irriter.'),
  (24, 7, 19, 'Est-ce moi qu''ils irritent? dit l''Éternel; N''est-ce pas eux-mêmes, A leur propre confusion?'),
  (24, 7, 20, 'C''est pourquoi ainsi parle le Seigneur, l''Éternel: Voici, ma colère et ma fureur se répandent sur ce lieu, Sur les hommes et sur les bêtes, Sur les arbres des champs et sur les fruits de la terre; Elle brûlera, et ne s''éteindra point.'),
  (24, 7, 21, 'Ainsi parle l''Éternel des armées, le Dieu d''Israël: Ajoutez vos holocaustes à vos sacrifices, Et mangez-en la chair!'),
  (24, 7, 22, 'Car je n''ai point parlé avec vos pères et je ne leur ai donné aucun ordre, Le jour où je les ai fait sortir du pays d''Égypte, Au sujet des holocaustes et des sacrifices.'),
  (24, 7, 23, 'Mais voici l''ordre que je leur ai donné: Écoutez ma voix, Et je serai votre Dieu, Et vous serez mon peuple; Marchez dans toutes les voies que je vous prescris, Afin que vous soyez heureux.'),
  (24, 7, 24, 'Et ils n''ont point écouté, ils n''ont point prêté l''oreille; Ils ont suivi les conseils, les penchants de leur mauvais cœur, Ils ont été en arrière et non en avant.'),
  (24, 7, 25, 'Depuis le jour où vos pères sont sortis du pays d''Égypte, Jusqu''à ce jour, Je vous ai envoyé tous mes serviteurs, les prophètes, Je les ai envoyés chaque jour, dès le matin.'),
  (24, 7, 26, 'Mais ils ne m''ont point écouté, ils n''ont point prêté l''oreille; Ils ont raidi leur cou, Ils ont fait le mal plus que leurs pères.'),
  (24, 7, 27, 'Si tu leur dis toutes ces choses, ils ne t''écouteront pas; Si tu cries vers eux, ils ne te répondront pas.'),
  (24, 7, 28, 'Alors dis-leur: C''est ici la nation qui n''écoute pas la voix de l''Éternel, son Dieu, Et qui ne veut pas recevoir instruction; La vérité a disparu, elle s''est retirée de leur bouche.'),
  (24, 7, 29, 'Coupe ta chevelure, et jette-la au loin; Monte sur les hauteurs, et prononce une complainte! Car l''Éternel rejette Et repousse la génération qui a provoqué sa fureur.'),
  (24, 7, 30, 'Car les enfants de Juda ont fait ce qui est mal à mes yeux, Dit l''Éternel; Ils ont placé leurs abominations Dans la maison sur laquelle mon nom est invoqué, Afin de la souiller.'),
  (24, 7, 31, 'Ils ont bâti des hauts lieux à Topheth dans la vallée de Ben-Hinnom, Pour brûler au feu leurs fils et leurs filles: Ce que je n''avais point ordonné, Ce qui ne m''était point venu à la pensée.'),
  (24, 7, 32, 'C''est pourquoi voici, les jours viennent, dit l''Éternel, Où l''on ne dira plus Topheth et la vallée de Ben-Hinnom, Mais où l''on dira la vallée du carnage; Et l''on enterrera les morts à Topheth par défaut de place.'),
  (24, 7, 33, 'Les cadavres de ce peuple seront la pâture Des oiseaux du ciel et des bêtes de la terre; Et il n''y aura personne pour les troubler.'),
  (24, 7, 34, 'Je ferai cesser dans les villes de Juda et dans les rues de Jérusalem Les cris de réjouissance et les cris d''allégresse, Les chants du fiancé et les chants de la fiancée; Car le pays sera un désert.'),
  (24, 8, 1, 'En ce temps-là, dit l''Éternel, on tirera de leurs sépulcres les os des rois de Juda, les os de ses chefs, les os des sacrificateurs, les os des prophètes, et les os des habitants de Jérusalem.'),
  (24, 8, 2, 'On les étendra devant le soleil, devant la lune, et devant toute l''armée des cieux, qu''ils ont aimés, qu''ils ont servis, qu''ils ont suivis, qu''ils ont recherchés, et devant lesquels ils se sont prosternés; on ne les recueillera point, on ne les enterrera point, et ils seront comme du fumier sur la terre.'),
  (24, 8, 3, 'La mort sera préférable à la vie pour tous ceux qui resteront de cette race méchante, dans tous les lieux où je les aurai chassés, dit l''Éternel des armées.'),
  (24, 8, 4, 'Dis-leur: Ainsi parle l''Éternel: Est-ce que l''on tombe sans se relever? Ou se détourne-t-on sans revenir?'),
  (24, 8, 5, 'Pourquoi donc ce peuple de Jérusalem s''abandonne-t-il A de perpétuels égarements? Ils persistent dans la tromperie, Ils refusent de se convertir.'),
  (24, 8, 6, 'Je suis attentif, et j''écoute: Ils ne parlent pas comme ils devraient; Aucun ne se repent de sa méchanceté, Et ne dit: Qu''ai-je fait? Tous reprennent leur course, Comme un cheval qui s''élance au combat.'),
  (24, 8, 7, 'Même la cigogne connaît dans les cieux sa saison; La tourterelle, l''hirondelle et la grue Observent le temps de leur arrivée; Mais mon peuple ne connaît pas la loi de l''Éternel.'),
  (24, 8, 8, 'Comment pouvez-vous dire: Nous sommes sages, La loi de l''Éternel est avec nous? C''est bien en vain que s''est mise à l''œuvre La plume mensongère des scribes.'),
  (24, 8, 9, 'Les sages sont confondus, Ils sont consternés, ils sont pris; Voici, ils ont méprisé la parole de l''Éternel, Et quelle sagesse ont-ils?'),
  (24, 8, 10, 'C''est pourquoi je donnerai leurs femmes à d''autres, Et leurs champs à ceux qui les déposséderont. Car depuis le plus petit jusqu''au plus grand, Tous sont avides de gain; Depuis le prophète jusqu''au sacrificateur, Tous usent de tromperie.'),
  (24, 8, 11, 'Ils pansent à la légère la plaie de la fille de mon peuple: Paix! paix! disent-ils. Et il n''y a point de paix.'),
  (24, 8, 12, 'Ils seront confus, car ils commettent des abominations; Ils ne rougissent pas, ils ne connaissent pas la honte; C''est pourquoi ils tomberont avec ceux qui tombent, Ils seront renversés quand je les châtierai, Dit l''Éternel.'),
  (24, 8, 13, 'Je veux en finir avec eux, dit l''Éternel; Il n''y aura plus de raisins à la vigne, Plus de figues au figuier, Et les feuilles se flétriront; Ce que je leur avais donné leur échappera. -'),
  (24, 8, 14, 'Pourquoi restons-nous assis? Rassemblez-vous, et allons dans les villes fortes, Pour y périr! Car l''Éternel, notre Dieu, nous destine à la mort, Il nous fait boire des eaux empoisonnées, Parce que nous avons péché contre l''Éternel.'),
  (24, 8, 15, 'Nous espérions la paix, et il n''arrive rien d''heureux; Un temps de guérison, et voici la terreur! -'),
  (24, 8, 16, 'Le hennissement de ses chevaux se fait entendre du côté de Dan, Et au bruit de leur hennissement toute la terre tremble; Ils viennent, ils dévorent le pays et ce qu''il renferme, La ville et ceux qui l''habitent.'),
  (24, 8, 17, 'Car j''envoie parmi vous des serpents, des basilics, Contre lesquels il n''y a point d''enchantement; Ils vous mordront, dit l''Éternel.'),
  (24, 8, 18, 'Je voudrais soulager ma douleur; Mon cœur souffre au dedans de moi.'),
  (24, 8, 19, 'Voici les cris de la fille de mon peuple Retentissent sur la terre lointaine: L''Éternel n''est-il plus à Sion? N''a-t-elle plus son roi au milieu d''elle? -Pourquoi m''ont-ils irrité par leurs images taillées, Par des idoles étrangères? -'),
  (24, 8, 20, 'La moisson est passée, l''été est fini, Et nous ne sommes pas sauvés!'),
  (24, 8, 21, 'Je suis brisé par la douleur de la fille de mon peuple, Je suis dans la tristesse, l''épouvante me saisit.'),
  (24, 8, 22, 'N''y a-t-il point de baume en Galaad? N''y a-t-il point de médecin? Pourquoi donc la guérison de la fille de mon peuple ne s''opère-t-elle pas?'),
  (24, 9, 1, 'Oh! si ma tête était remplie d''eau, Si mes yeux étaient une source de larmes, Je pleurerais jour et nuit Les morts de la fille de mon peuple!'),
  (24, 9, 2, 'Oh! si j''avais au désert une cabane de voyageurs, J''abandonnerais mon peuple, je m''en éloignerais! Car ce sont tous des adultères, C''est une troupe de perfides.'),
  (24, 9, 3, 'Ils ont la langue tendue comme un arc et lancent le mensonge; Ce n''est pas par la vérité qu''ils sont puissants dans le pays; Car ils vont de méchanceté en méchanceté, Et ils ne me connaissent pas, dit l''Éternel.'),
  (24, 9, 4, 'Que chacun se tienne en garde contre son ami, Et qu''on ne se fie à aucun de ses frères; Car tout frère cherche à tromper, Et tout ami répand des calomnies.'),
  (24, 9, 5, 'Ils se jouent les uns des autres, Et ne disent point la vérité; Ils exercent leur langue à mentir, Ils s''étudient à faire le mal.'),
  (24, 9, 6, 'Ta demeure est au sein de la fausseté; C''est par fausseté qu''ils refusent de me connaître, Dit l''Éternel.'),
  (24, 9, 7, 'C''est pourquoi ainsi parle l''Éternel des armées: Voici je les sonderai, je les éprouverai. Car comment agir à l''égard de la fille de mon peuple?'),
  (24, 9, 8, 'Leur langue est un trait meurtrier, Ils ne disent que des mensonges; De la bouche ils parlent de paix à leur prochain, Et au fond du cœur ils lui dressent des pièges.'),
  (24, 9, 9, 'Ne les châtierais-je pas pour ces choses-là, dit l''Éternel, Ne me vengerais-je pas d''une pareille nation?'),
  (24, 9, 10, 'Sur les montagnes je veux pleurer et gémir, Sur les plaines du désert je prononce une complainte; Car elles sont brûlées, personne n''y passe, On n''y entend plus la voix des troupeaux; Les oiseaux du ciel et les bêtes ont pris la fuite, ont disparu. -'),
  (24, 9, 11, 'Je ferai de Jérusalem un monceau de ruines, un repaire de chacals, Et je réduirai les villes de Juda en un désert sans habitants. -'),
  (24, 9, 12, 'Où est l''homme sage qui comprenne ces choses? Qu''il le dise, celui à qui la bouche de l''Éternel a parlé! Pourquoi le pays est-il détruit, Brûlé comme un désert où personne ne passe?'),
  (24, 9, 13, 'L''Éternel dit: C''est parce qu''ils ont abandonné ma loi, Que j''avais mise devant eux; Parce qu''ils n''ont point écouté ma voix, Et qu''ils ne l''ont point suivie;'),
  (24, 9, 14, 'Parce qu''ils ont suivi les penchants de leur cœur, Et qu''ils sont allés après les Baals, Comme leurs pères le leur ont appris.'),
  (24, 9, 15, 'C''est pourquoi ainsi parle l''Éternel des armées, le Dieu d''Israël: Voici, je vais nourrir ce peuple d''absinthe, Et je lui ferai boire des eaux empoisonnées.'),
  (24, 9, 16, 'Je les disperserai parmi des nations Que n''ont connues ni eux ni leurs pères, Et j''enverrai derrière eux l''épée, Jusqu''à ce que je les aie exterminés.'),
  (24, 9, 17, 'Ainsi parle l''Éternel des armées: Cherchez, appelez les pleureuses, et qu''elles viennent! Envoyez vers les femmes habiles, et qu''elles viennent!'),
  (24, 9, 18, 'Qu''elles se hâtent de dire sur nous une complainte! Et que les larmes tombent de nos yeux, Que l''eau coule de nos paupières!'),
  (24, 9, 19, 'Car des cris lamentables se font entendre de Sion: Eh quoi! nous sommes détruits! Nous sommes couverts de honte! Il nous faut abandonner le pays! On a renversé nos demeures! -'),
  (24, 9, 20, 'Femmes, écoutez la parole de l''Éternel, Et que votre oreille saisisse ce que dit sa bouche! Apprenez à vos filles des chants lugubres, Enseignez-vous des complaintes les unes aux autres!'),
  (24, 9, 21, 'Car la mort est montée par nos fenêtres, Elle a pénétré dans nos palais; Elle extermine les enfants dans la rue, Les jeunes gens sur les places.'),
  (24, 9, 22, 'Dis: Ainsi parle l''Éternel: Les cadavres des hommes tomberont Comme du fumier sur les champs, Comme tombe derrière le moissonneur une gerbe Que personne ne ramasse.'),
  (24, 9, 23, 'Ainsi parle l''Éternel: Que le sage ne se glorifie pas de sa sagesse, Que le fort ne se glorifie pas de sa force, Que le riche ne se glorifie pas de sa richesse.'),
  (24, 9, 24, 'Mais que celui qui veut se glorifier se glorifie D''avoir de l''intelligence et de me connaître, De savoir que je suis l''Éternel, Qui exerce la bonté, le droit et la justice sur la terre; Car c''est à cela que je prends plaisir, dit l''Éternel.'),
  (24, 9, 25, 'Voici, les jours viennent, dit l''Éternel, Où je châtierai tous les circoncis qui ne le sont pas de cœur,'),
  (24, 9, 26, 'L''Égypte, Juda, Édom, les enfants d''Ammon, Moab, Tous ceux qui se rasent les coins de la barbe, Ceux qui habitent dans le désert; Car toutes les nations sont incirconcises, Et toute la maison d''Israël a le cœur incirconcis.'),
  (24, 10, 1, 'Écoutez la parole que l''Éternel vous adresse, Maison d''Israël!'),
  (24, 10, 2, 'Ainsi parle l''Éternel: N''imitez pas la voie des nations, Et ne craignez pas les signes du ciel, Parce que les nations les craignent.'),
  (24, 10, 3, 'Car les coutumes des peuples ne sont que vanité. On coupe le bois dans la forêt; La main de l''ouvrier le travaille avec la hache;'),
  (24, 10, 4, 'On l''embellit avec de l''argent et de l''or, On le fixe avec des clous et des marteaux, Pour qu''il ne branle pas.'),
  (24, 10, 5, 'Ces dieux sont comme une colonne massive, et ils ne parlent point; On les porte, parce qu''ils ne peuvent marcher. Ne les craignez pas, car ils ne sauraient faire aucun mal, Et ils sont incapables de faire du bien.'),
  (24, 10, 6, 'Nul n''est semblable à toi, ô Éternel! Tu es grand, et ton nom est grand par ta puissance.'),
  (24, 10, 7, 'Qui ne te craindrait, roi des nations? C''est à toi que la crainte est due; Car, parmi tous les sages des nations et dans tous leurs royaumes, Nul n''est semblable à toi.'),
  (24, 10, 8, 'Tous ensemble, ils sont stupides et insensés; Leur science n''est que vanité, c''est du bois!'),
  (24, 10, 9, 'On apporte de Tarsis des lames d''argent, et d''Uphaz de l''or, L''ouvrier et la main de l''orfèvre les mettent en œuvre; Les vêtements de ces dieux sont d''étoffes teintes en bleu et en pourpre, Tous sont l''ouvrage d''habiles artisans.'),
  (24, 10, 10, 'Mais l''Éternel est Dieu en vérité, Il est un Dieu vivant et un roi éternel; La terre tremble devant sa colère, Et les nations ne supportent pas sa fureur.'),
  (24, 10, 11, 'Vous leur parlerez ainsi: Les dieux qui n''ont point fait les cieux et la terre Disparaîtront de la terre et de dessous les cieux.'),
  (24, 10, 12, 'Il a créé la terre par sa puissance, Il a fondé le monde par sa sagesse, Il a étendu les cieux par son intelligence.'),
  (24, 10, 13, 'A sa voix, les eaux mugissent dans les cieux; Il fait monter les nuages des extrémités de la terre, Il produit les éclairs et la pluie, Il tire le vent de ses trésors.'),
  (24, 10, 14, 'Tout homme devient stupide par sa science, Tout orfèvre est honteux de son image taillée; Car ses idoles ne sont que mensonge, Il n''y a point en elles de souffle,'),
  (24, 10, 15, 'Elles sont une chose de néant, une œuvre de tromperie; Elles périront, quand viendra le châtiment.'),
  (24, 10, 16, 'Celui qui est la part de Jacob n''est pas comme elles; Car c''est lui qui a tout formé, Et Israël est la tribu de son héritage. L''Éternel des armées est son nom.'),
  (24, 10, 17, 'Emporte du pays ce qui t''appartient, Toi qui es assise dans la détresse!'),
  (24, 10, 18, 'Car ainsi parle l''Éternel: Voici, cette fois je vais lancer au loin les habitants du pays; Je vais les serrer de près, afin qu''on les atteigne. -'),
  (24, 10, 19, 'Malheur à moi! je suis brisée! Ma plaie est douloureuse! Mais je dis: C''est une calamité qui m''arrive, Je la supporterai!'),
  (24, 10, 20, 'Ma tente est détruite, Tous mes cordages sont rompus; Mes fils m''ont quittée, ils ne sont plus; Je n''ai personne qui dresse de nouveau ma tente, Qui relève mes pavillons. -'),
  (24, 10, 21, 'Les bergers ont été stupides, Ils n''ont pas cherché l''Éternel; C''est pour cela qu''ils n''ont point prospéré, Et que tous leurs troupeaux se dispersent.'),
  (24, 10, 22, 'Voici, une rumeur se fait entendre; C''est un grand tumulte qui vient du septentrion, Pour réduire les villes de Juda en un désert, En un repaire de chacals. -'),
  (24, 10, 23, 'Je le sais, ô Éternel! La voie de l''homme n''est pas en son pouvoir; Ce n''est pas à l''homme, quand il marche, A diriger ses pas.'),
  (24, 10, 24, 'Châtie-moi, ô Éternel! mais avec équité, Et non dans ta colère, de peur que tu ne m''anéantisses.'),
  (24, 10, 25, 'Répands ta fureur sur les nations qui ne te connaissent pas, Et sur les peuples qui n''invoquent pas ton nom! Car ils dévorent Jacob, ils le dévorent, ils le consument, Ils ravagent sa demeure.'),
  (24, 11, 1, 'La parole qui fut adressée à Jérémie de la part de l''Éternel, en ces mots:'),
  (24, 11, 2, 'Écoutez les paroles de cette alliance, Et parlez aux hommes de Juda et aux habitants de Jérusalem!'),
  (24, 11, 3, 'Dis-leur: Ainsi parle l''Éternel, le Dieu d''Israël: Maudit soit l''homme qui n''écoute point les paroles de cette alliance,'),
  (24, 11, 4, 'Que j''ai prescrite à vos pères, Le jour où je les ai fait sortir du pays d''Égypte, De la fournaise de fer, en disant: Écoutez ma voix, et faites tout ce que je vous ordonnerai; Alors vous serez mon peuple, Je serai votre Dieu,'),
  (24, 11, 5, 'Et j''accomplirai le serment que j''ai fait à vos pères, De leur donner un pays où coulent le lait et le miel, Comme vous le voyez aujourd''hui. -Et je répondis: Amen, Éternel!'),
  (24, 11, 6, 'L''Éternel me dit: Publie toutes ces paroles dans les villes de Juda Et dans les rues de Jérusalem, en disant: Écoutez les paroles de cette alliance, Et mettez-les en pratique!'),
  (24, 11, 7, 'Car j''ai averti vos pères, Depuis le jour où je les ai fait monter du pays d''Égypte Jusqu''à ce jour, Je les ai avertis tous les matins, en disant: Écoutez ma voix!'),
  (24, 11, 8, 'Mais ils n''ont pas écouté, ils n''ont pas prêté l''oreille, Ils ont suivi chacun les penchants de leur mauvais cœur; Alors j''ai accompli sur eux toutes les paroles de cette alliance, Que je leur avais ordonné d''observer et qu''ils n''ont point observée.'),
  (24, 11, 9, 'L''Éternel me dit: Il y a une conjuration entre les hommes de Juda Et les habitants de Jérusalem.'),
  (24, 11, 10, 'Ils sont retournés aux iniquités de leurs premiers pères, Qui ont refusé d''écouter mes paroles, Et ils sont allés après d''autres dieux, pour les servir. La maison d''Israël et la maison de Juda ont violé mon alliance, Que j''avais faite avec leurs pères.'),
  (24, 11, 11, 'C''est pourquoi ainsi parle l''Éternel: Voici, je vais faire venir sur eux des malheurs Dont ils ne pourront se délivrer. Ils crieront vers moi, Et je ne les écouterai pas.'),
  (24, 11, 12, 'Les villes de Juda et les habitants de Jérusalem Iront invoquer les dieux auxquels ils offrent de l''encens, Mais ils ne les sauveront pas au temps de leur malheur.'),
  (24, 11, 13, 'Car tu as autant de dieux que de villes, ô Juda! Et autant Jérusalem a de rues, Autant vous avez dressé d''autels aux idoles, D''autels pour offrir de l''encens à Baal…'),
  (24, 11, 14, 'Et toi, n''intercède pas en faveur de ce peuple, N''élève pour eux ni supplications ni prières; Car je ne les écouterai pas, Quand ils m''invoqueront à cause de leur malheur.'),
  (24, 11, 15, 'Que ferait mon bien-aimé dans ma maison? Il s''y commet une foule de crimes. La chair sacrée disparaîtra devant toi. Quand tu fais le mal, c''est alors que tu triomphes!'),
  (24, 11, 16, 'Olivier verdoyant, remarquable par la beauté de son fruit, Tel est le nom que t''avait donné l''Éternel; Au bruit d''un grand fracas, il l''embrase par le feu, Et ses rameaux sont brisés.'),
  (24, 11, 17, 'L''Éternel des armées, qui t''a planté, Appelle sur toi le malheur, A cause de la méchanceté de la maison d''Israël et de la maison de Juda, Qui ont agi pour m''irriter, en offrant de l''encens à Baal.'),
  (24, 11, 18, 'L''Éternel m''en a informé, et je l''ai su; Alors tu m''as fait voir leurs œuvres.'),
  (24, 11, 19, 'J''étais comme un agneau familier qu''on mène à la boucherie, Et j''ignorais les mauvais desseins qu''ils méditaient contre moi: Détruisons l''arbre avec son fruit! Retranchons-le de la terre des vivants, Et qu''on ne se souvienne plus de son nom! -'),
  (24, 11, 20, 'Mais l''Éternel des armées est un juste juge, Qui sonde les reins et les cœurs. Je verrai ta vengeance s''exercer contre eux, Car c''est à toi que je confie ma cause.'),
  (24, 11, 21, 'C''est pourquoi ainsi parle l''Éternel contre les gens d''Anathoth, Qui en veulent à ta vie, et qui disent: Ne prophétise pas au nom de l''Éternel, Ou tu mourras de notre main!'),
  (24, 11, 22, 'C''est pourquoi ainsi parle l''Éternel des armées: Voici, je vais les châtier; Les jeunes hommes mourront par l''épée, Leurs fils et leurs filles mourront par la famine.'),
  (24, 11, 23, 'Aucun d''eux n''échappera; Car je ferai venir le malheur sur les gens d''Anathoth, L''année où je les châtierai.'),
  (24, 12, 1, 'Tu es trop juste, Éternel, pour que je conteste avec toi; Je veux néanmoins t''adresser la parole sur tes jugements: Pourquoi la voie des méchants est-elle prospère? Pourquoi tous les perfides vivent-ils en paix?'),
  (24, 12, 2, 'Tu les as plantés, ils ont pris racine, Ils croissent, ils portent du fruit; Tu es près de leur bouche, Mais loin de leur cœur.'),
  (24, 12, 3, 'Et toi, Éternel, tu me connais, Tu me vois, tu sondes mon cœur qui est avec toi. Enlève-les comme des brebis qu''on doit égorger, Et prépare-les pour le jour du carnage!'),
  (24, 12, 4, 'Jusques à quand le pays sera-t-il dans le deuil, Et l''herbe de tous les champs sera-t-elle desséchée? A cause de la méchanceté des habitants, Les bêtes et les oiseaux périssent. Car ils disent: Il ne verra pas notre fin. -'),
  (24, 12, 5, 'Si tu cours avec des piétons et qu''ils te fatiguent, Comment pourras-tu lutter avec des chevaux? Et si tu ne te crois en sûreté que dans une contrée paisible, Que feras-tu sur les rives orgueilleuses du Jourdain?'),
  (24, 12, 6, 'Car tes frères eux-mêmes et la maison de ton père te trahissent, Ils crient eux-mêmes à pleine voix derrière toi. Ne les crois pas, quand ils te diront des paroles amicales.'),
  (24, 12, 7, 'J''ai abandonné ma maison, J''ai délaissé mon héritage, J''ai livré l''objet de mon amour aux mains de ses ennemis.'),
  (24, 12, 8, 'Mon héritage a été pour moi comme un lion dans la forêt, Il a poussé contre moi ses rugissements; C''est pourquoi je l''ai pris en haine.'),
  (24, 12, 9, 'Mon héritage a été pour moi un oiseau de proie, une hyène; Aussi les oiseaux de proie viendront de tous côtés contre lui. Allez, rassemblez tous les animaux des champs, Faites-les venir pour qu''ils le dévorent!'),
  (24, 12, 10, 'Des bergers nombreux ravagent ma vigne, Ils foulent mon champ; Ils réduisent le champ de mes délices En un désert, en une solitude.'),
  (24, 12, 11, 'Ils le réduisent en un désert; Il est en deuil, il est désolé devant moi. Tout le pays est ravagé, Car nul n''y prend garde.'),
  (24, 12, 12, 'Sur tous les lieux élevés du désert arrivent les dévastateurs, Car le glaive de l''Éternel dévore le pays d''un bout à l''autre; Il n''y a de paix pour aucun homme.'),
  (24, 12, 13, 'Ils ont semé du froment, et ils moissonnent des épines, Ils se sont fatigués sans profit. Ayez honte de ce que vous récoltez, Par suite de la colère ardente de l''Éternel.'),
  (24, 12, 14, 'Ainsi parle l''Éternel sur tous mes méchants voisins, Qui attaquent l''héritage que j''ai donné à mon peuple d''Israël: Voici, je les arracherai de leur pays, Et j''arracherai la maison de Juda du milieu d''eux.'),
  (24, 12, 15, 'Mais après que je les aurai arrachés, J''aurai de nouveau compassion d''eux, Et je les ramènerai chacun dans son héritage, Chacun dans son pays.'),
  (24, 12, 16, 'Et s''ils apprennent les voies de mon peuple, S''ils jurent par mon nom, en disant: L''Éternel est vivant! Comme ils ont enseigné à mon peuple à jurer par Baal, Alors ils jouiront du bonheur au milieu de mon peuple.'),
  (24, 12, 17, 'Mais s''ils n''écoutent rien, Je détruirai une telle nation, Je la détruirai, je la ferai périr, dit l''Éternel.'),
  (24, 13, 1, 'Ainsi m''a parlé l''Éternel: Va, achète-toi une ceinture de lin, et mets-la sur tes reins; mais ne la trempe pas dans l''eau.'),
  (24, 13, 2, 'J''achetai la ceinture, selon la parole de l''Éternel, et je la mis sur mes reins.'),
  (24, 13, 3, 'La parole de l''Éternel me fut adressée une seconde fois, en ces mots:'),
  (24, 13, 4, 'Prends la ceinture que tu as achetée, et qui est sur tes reins; lève-toi, va vers l''Euphrate, et là, cache-la dans la fente d''un rocher.'),
  (24, 13, 5, 'J''allai, et je la cachai près de l''Euphrate, comme l''Éternel me l''avait ordonné.'),
  (24, 13, 6, 'Plusieurs jours après, l''Éternel me dit: Lève-toi, va vers l''Euphrate, et là, prends la ceinture que je t''avais ordonné d''y cacher.'),
  (24, 13, 7, 'J''allai vers l''Euphrate, je fouillai, et je pris la ceinture dans le lieu où je l''avais cachée; mais voici, la ceinture était gâtée, elle n''était plus bonne à rien.'),
  (24, 13, 8, 'La parole de l''Éternel me fut adressée, en ces mots:'),
  (24, 13, 9, 'Ainsi parle l''Éternel: C''est ainsi que je détruirai l''orgueil de Juda Et l''orgueil immense de Jérusalem.'),
  (24, 13, 10, 'Ce méchant peuple, qui refuse d''écouter mes paroles, Qui suit les penchants de son cœur, Et qui va après d''autres dieux, Pour les servir et se prosterner devant eux, Qu''il devienne comme cette ceinture, Qui n''est plus bonne à rien!'),
  (24, 13, 11, 'Car comme on attache la ceinture aux reins d''un homme, Ainsi je m''étais attaché toute la maison d''Israël Et toute la maison de Juda, dit l''Éternel, Afin qu''elles fussent mon peuple, Mon nom, ma louange, et ma gloire. Mais ils ne m''ont point écouté.'),
  (24, 13, 12, 'Tu leur diras cette parole: Ainsi parle l''Éternel, le Dieu d''Israël: Tous les vases seront remplis de vin. Et ils te diront: Ne savons-nous pas Que tous les vases seront remplis de vin?'),
  (24, 13, 13, 'Alors dis-leur: Ainsi parle l''Éternel: Voici, je remplirai tous les habitants de ce pays, Les rois qui sont assis sur le trône de David, Les sacrificateurs, les prophètes, et tous les habitants de Jérusalem, Je les remplirai d''ivresse.'),
  (24, 13, 14, 'Je les briserai les uns contre les autres, Les pères et les fils ensemble, dit l''Éternel; Je n''épargnerai pas, je n''aurai point de pitié, point de miséricorde, Rien ne m''empêchera de les détruire.'),
  (24, 13, 15, 'Écoutez et prêtez l''oreille! Ne soyez point orgueilleux! Car l''Éternel parle.'),
  (24, 13, 16, 'Rendez gloire à l''Éternel, votre Dieu, Avant qu''il fasse venir les ténèbres, Avant que vos pieds heurtent contre les montagnes de la nuit; Vous attendrez la lumière, Et il la changera en ombre de la mort, Il la réduira en obscurité profonde.'),
  (24, 13, 17, 'Si vous n''écoutez pas, Je pleurerai en secret, à cause de votre orgueil; Mes yeux fondront en larmes, Parce que le troupeau de l''Éternel sera emmené captif.'),
  (24, 13, 18, 'Dis au roi et à la reine: Asseyez-vous à terre! Car il est tombé de vos têtes, Le diadème qui vous servait d''ornement.'),
  (24, 13, 19, 'Les villes du midi sont fermées, Il n''y a personne pour ouvrir; Tout Juda est emmené captif, Il est emmené tout entier captif.'),
  (24, 13, 20, 'Lève tes yeux et regarde Ceux qui viennent du septentrion. Où est le troupeau qui t''avait été donné, Le troupeau qui faisait ta gloire?'),
  (24, 13, 21, 'Que diras-tu de ce qu''il te châtie? C''est toi-même qui leur as appris à te traiter en maîtres. Les douleurs ne te saisiront-elles pas, Comme elles saisissent une femme en travail?'),
  (24, 13, 22, 'Si tu dis en ton cœur: Pourquoi cela m''arrive-t-il? C''est à cause de la multitude de tes iniquités Que les pans de tes habits sont relevés, Et que tes talons sont violemment mis à nu.'),
  (24, 13, 23, 'Un Éthiopien peut-il changer sa peau, Et un léopard ses taches? De même, pourriez-vous faire le bien, Vous qui êtes accoutumés à faire le mal?'),
  (24, 13, 24, 'Je les disperserai, comme la paille emportée Par le vent du désert.'),
  (24, 13, 25, 'Voilà ton sort, la part que je te mesure, Dit l''Éternel, Parce que tu m''as oublié, Et que tu as mis ta confiance dans le mensonge.'),
  (24, 13, 26, 'Je relèverai tes pans jusque sur ton visage, Afin qu''on voie ta honte.'),
  (24, 13, 27, 'J''ai vu tes adultères et tes hennissements, Tes criminelles prostitutions sur les collines et dans les champs, J''ai vu tes abominations. Malheur à toi, Jérusalem! Jusques à quand tarderas-tu à te purifier?'),
  (24, 14, 1, 'La parole qui fut adressée à Jérémie par l''Éternel, à l''occasion de la sécheresse.'),
  (24, 14, 2, 'Juda est dans le deuil, Ses villes sont désolées, tristes, abattues, Et les cris de Jérusalem s''élèvent.'),
  (24, 14, 3, 'Les grands envoient les petits chercher de l''eau, Et les petits vont aux citernes, ne trouvent point d''eau, Et retournent avec leurs vases vides; Confus et honteux, ils se couvrent la tête.'),
  (24, 14, 4, 'La terre est saisie d''épouvante, Parce qu''il ne tombe point de pluie dans le pays, Et les laboureurs confus se couvrent la tête.'),
  (24, 14, 5, 'Même la biche dans la campagne Met bas et abandonne sa portée, Parce qu''il n''y a point de verdure.'),
  (24, 14, 6, 'Les ânes sauvages se tiennent sur les lieux élevés, Aspirant l''air comme des serpents; Leurs yeux languissent, parce qu''il n''y a point d''herbe.'),
  (24, 14, 7, 'Si nos iniquités témoignent contre nous, Agis à cause de ton nom, ô Éternel! Car nos infidélités sont nombreuses, Nous avons péché contre toi.'),
  (24, 14, 8, 'Toi qui es l''espérance d''Israël, Son sauveur au temps de la détresse, Pourquoi serais-tu comme un étranger dans le pays, Comme un voyageur qui y entre pour passer la nuit?'),
  (24, 14, 9, 'Pourquoi serais-tu comme un homme stupéfait, Comme un héros incapable de nous secourir? Tu es pourtant au milieu de nous, ô Éternel, Et ton nom est invoqué sur nous: Ne nous abandonne pas!'),
  (24, 14, 10, 'Voici ce que l''Éternel dit de ce peuple: Ils aiment à courir çà et là, Ils ne savent retenir leurs pieds; L''Éternel n''a point d''attachement pour eux, Il se souvient maintenant de leurs crimes, Et il châtie leurs péchés.'),
  (24, 14, 11, 'Et l''Éternel me dit: N''intercède pas en faveur de ce peuple.'),
  (24, 14, 12, 'S''ils jeûnent, je n''écouterai pas leurs supplications; S''ils offrent des holocaustes et des offrandes, je ne les agréerai pas; Car je veux les détruire par l''épée, par la famine et par la peste.'),
  (24, 14, 13, 'Je répondis: Ah! Seigneur Éternel! Voici, les prophètes leur disent: Vous ne verrez point d''épée, Vous n''aurez point de famine; Mais je vous donnerai dans ce lieu une paix assurée.'),
  (24, 14, 14, 'Et l''Éternel me dit: C''est le mensonge que prophétisent en mon nom les prophètes; Je ne les ai point envoyés, je ne leur ai point donné d''ordre, Je ne leur ai point parlé; Ce sont des visions mensongères, de vaines prédictions, Des tromperies de leur cœur, qu''ils vous prophétisent.'),
  (24, 14, 15, 'C''est pourquoi ainsi parle l''Éternel Sur les prophètes qui prophétisent en mon nom, Sans que je les aie envoyés, Et qui disent: Il n''y aura dans ce pays ni épée ni famine: Ces prophètes périront par l''épée et par la famine.'),
  (24, 14, 16, 'Et ceux à qui ils prophétisent Seront étendus dans les rues de Jérusalem, Par la famine et par l''épée; Il n''y aura personne pour leur donner la sépulture, Ni à eux, ni à leurs femmes, ni à leurs fils, ni à leurs filles; Je répandrai sur eux leur méchanceté.'),
  (24, 14, 17, 'Dis-leur cette parole: Les larmes coulent de mes yeux nuit et jour, Et elles ne s''arrêtent pas; Car la vierge, fille de mon peuple, a été frappée d''un grand coup, D''une plaie très douloureuse.'),
  (24, 14, 18, 'Si je vais dans les champs, voici des hommes que le glaive a percés; Si j''entre dans la ville, voici des êtres que consume la faim; Le prophète même et le sacrificateur parcourent le pays, Sans savoir où ils vont.'),
  (24, 14, 19, 'As-tu donc rejeté Juda, Et ton âme a-t-elle pris Sion en horreur? Pourquoi nous frappes-tu Sans qu''il y ait pour nous de guérison? Nous espérions la paix, et il n''arrive rien d''heureux, Un temps de guérison, et voici la terreur!'),
  (24, 14, 20, 'Éternel, nous reconnaissons notre méchanceté, l''iniquité de nos pères; Car nous avons péché contre toi.'),
  (24, 14, 21, 'A cause de ton nom, ne méprise pas, Ne déshonore pas le trône de ta gloire! N''oublie pas, ne romps pas ton alliance avec nous!'),
  (24, 14, 22, 'Parmi les idoles des nations, en est-il qui fassent pleuvoir? Ou est-ce le ciel qui donne la pluie? N''est-ce pas toi, Éternel, notre Dieu? Nous espérons en toi, Car c''est toi qui as fait toutes ces choses.'),
  (24, 15, 1, 'L''Éternel me dit: Quand Moïse et Samuel se présenteraient devant moi, Je ne serais pas favorable à ce peuple. Chasse-le loin de ma face, qu''il s''en aille!'),
  (24, 15, 2, 'Et s''ils te disent: Où irons-nous? Tu leur répondras: Ainsi parle l''Éternel: A la mort ceux qui sont pour la mort, A l''épée ceux qui sont pour l''épée, A la famine ceux qui sont pour la famine, A la captivité ceux qui sont pour la captivité!'),
  (24, 15, 3, 'J''enverrai contre eux quatre espèces de fléaux, dit l''Éternel, L''épée pour les tuer, Les chiens pour les traîner, Les oiseaux du ciel et les bêtes de la terre Pour les dévorer et les détruire.'),
  (24, 15, 4, 'Je les rendrai un objet d''effroi pour tous les royaumes de la terre, A cause de Manassé, fils d''Ézéchias, roi de Juda, Et de tout ce qu''il a fait dans Jérusalem.'),
  (24, 15, 5, 'Qui aura pitié de toi, Jérusalem, Qui te plaindra? Qui ira s''informer de ton état?'),
  (24, 15, 6, 'Tu m''as abandonné, dit l''Éternel, tu es allée en arrière; Mais j''étends ma main sur toi, et je te détruis, Je suis las d''avoir compassion.'),
  (24, 15, 7, 'Je les vanne avec le vent aux portes du pays; Je prive d''enfants, je fais périr mon peuple, Qui ne s''est pas détourné de ses voies.'),
  (24, 15, 8, 'Ses veuves sont plus nombreuses que les grains de sable de la mer; J''amène sur eux, sur la mère du jeune homme, Le dévastateur en plein midi; Je fais soudain tomber sur elle l''angoisse et la terreur.'),
  (24, 15, 9, 'Celle qui avait enfanté sept fils est désolée, Elle rend l''âme; Son soleil se couche quand il est encore jour; Elle est confuse, couverte de honte. Ceux qui restent, je les livre à l''épée devant leurs ennemis, Dit l''Éternel.'),
  (24, 15, 10, 'Malheur à moi, ma mère, de ce que tu m''as fait naître Homme de dispute et de querelle pour tout le pays! Je n''emprunte ni ne prête, Et cependant tous me maudissent.'),
  (24, 15, 11, 'L''Éternel dit: Certes, tu auras un avenir heureux; Certes, je forcerai l''ennemi à t''adresser ses supplications, Au temps du malheur et au temps de la détresse.'),
  (24, 15, 12, 'Le fer brisera-t-il le fer du septentrion et l''airain?'),
  (24, 15, 13, 'Je livre gratuitement au pillage tes biens et tes trésors, A cause de tous tes péchés, sur tout ton territoire.'),
  (24, 15, 14, 'Je te fais passer avec ton ennemi dans un pays que tu ne connais pas, Car le feu de ma colère s''est allumé, Il brûle sur vous.'),
  (24, 15, 15, 'Tu sais tout, ô Éternel, souviens-toi de moi, ne m''oublie pas, Venge-moi de mes persécuteurs! Ne m''enlève pas, tandis que tu te montres lent à la colère! Sache que je supporte l''opprobre à cause de toi.'),
  (24, 15, 16, 'J''ai recueilli tes paroles, et je les ai dévorées; Tes paroles ont fait la joie et l''allégresse de mon cœur; Car ton nom est invoqué sur moi, Éternel, Dieu des armées!'),
  (24, 15, 17, 'Je ne me suis point assis dans l''assemblée des moqueurs, afin de m''y réjouir; Mais à cause de ta puissance, je me suis assis solitaire, Car tu me remplissais de fureur.'),
  (24, 15, 18, 'Pourquoi ma souffrance est-elle continuelle? Pourquoi ma plaie est-elle douloureuse, et ne veut-elle pas se guérir? Serais-tu pour moi comme une source trompeuse, Comme une eau dont on n''est pas sûr?'),
  (24, 15, 19, 'C''est pourquoi ainsi parle l''Éternel: Si tu te rattaches à moi, je te répondrai, et tu te tiendras devant moi; Si tu sépares ce qui est précieux de ce qui est vil, tu seras comme ma bouche. C''est à eux de revenir à toi, Mais ce n''est pas à toi de retourner vers eux.'),
  (24, 15, 20, 'Je te rendrai pour ce peuple comme une forte muraille d''airain; Ils te feront la guerre, mais ils ne te vaincront pas; Car je serai avec toi pour te sauver et te délivrer, Dit l''Éternel.'),
  (24, 15, 21, 'Je te délivrerai de la main des méchants, Je te sauverai de la main des violents.'),
  (24, 16, 1, 'La parole de l''Éternel me fut adressée, en ces mots:'),
  (24, 16, 2, 'Tu ne prendras point de femme, Et tu n''auras dans ce lieu ni fils ni filles.'),
  (24, 16, 3, 'Car ainsi parle l''Éternel sur les fils et les filles Qui naîtront en ce lieu, Sur leurs mères qui les auront enfantés, Et sur leurs pères qui les auront engendrés dans ce pays:'),
  (24, 16, 4, 'Ils mourront consumés par la maladie; On ne leur donnera ni larmes ni sépulture; Ils seront comme du fumier sur la terre; Ils périront par l''épée et par la famine; Et leurs cadavres serviront de pâture Aux oiseaux du ciel et aux bêtes de la terre.'),
  (24, 16, 5, 'Car ainsi parle l''Éternel: N''entre pas dans une maison de deuil, N''y va pas pleurer, te lamenter avec eux; Car j''ai retiré à ce peuple ma paix, dit l''Éternel, Ma bonté et ma miséricorde.'),
  (24, 16, 6, 'Grands et petits mourront dans ce pays; On ne leur donnera point de sépulture; On ne les pleurera point, On ne se fera point d''incision, Et l''on ne se rasera pas pour eux.'),
  (24, 16, 7, 'On ne rompra pas le pain dans le deuil Pour consoler quelqu''un au sujet d''un mort, Et l''on n''offrira pas la coupe de consolation Pour un père ou pour une mère.'),
  (24, 16, 8, 'N''entre pas non plus dans une maison de festin, Pour t''asseoir avec eux, Pour manger et pour boire.'),
  (24, 16, 9, 'Car ainsi parle l''Éternel des armées, le Dieu d''Israël: Voici, je ferai cesser dans ce lieu, sous vos yeux et de vos jours, Les cris de réjouissance et les cris d''allégresse, Les chants du fiancé et les chants de la fiancée.'),
  (24, 16, 10, 'Lorsque tu annonceras à ce peuple toutes ces choses, Ils te diront: Pourquoi l''Éternel nous menace-t-il de tous ces grands malheurs? Quelle est notre iniquité? Quel péché avons-nous commis contre l''Éternel, notre Dieu?'),
  (24, 16, 11, 'Alors tu leur répondras: Vos pères m''ont abandonné, dit l''Éternel, Ils sont allés après d''autres dieux, Ils les ont servis et se sont prosternés devant eux; Ils m''ont abandonné, et n''ont point observé ma loi.'),
  (24, 16, 12, 'Et vous, vous avez fait le mal plus encore que vos pères; Et voici, vous suivez chacun les penchants de votre mauvais cœur, Pour ne point m''écouter.'),
  (24, 16, 13, 'Je vous transporterai de ce pays Dans un pays que vous n''avez point connu, Ni vous, ni vos pères; Et là, vous servirez les autres dieux jour et nuit, Car je ne vous accorderai point de grâce.'),
  (24, 16, 14, 'C''est pourquoi voici, les jours viennent, dit l''Éternel, Où l''on ne dira plus: L''Éternel est vivant, Lui qui a fait monter du pays d''Égypte les enfants d''Israël!'),
  (24, 16, 15, 'Mais on dira: L''Éternel est vivant, Lui qui a fait monter les enfants d''Israël du pays du septentrion Et de tous les pays où il les avait chassés! Je les ramènerai dans leur pays, Que j''avais donné à leurs pères.'),
  (24, 16, 16, 'Voici, j''envoie une multitude de pêcheurs, dit l''Éternel, et ils les pêcheront; Et après cela j''enverrai une multitude de chasseurs, et ils les chasseront De toutes les montagnes et de toutes les collines, Et des fentes des rochers.'),
  (24, 16, 17, 'Car mes yeux sont attentifs à toutes leurs voies, Elles ne sont point cachées devant ma face, Et leur iniquité ne se dérobe point à mes regards.'),
  (24, 16, 18, 'Je leur donnerai d''abord le double salaire de leur iniquité et de leur péché, Parce qu''ils ont profané mon pays, Parce qu''ils ont rempli mon héritage Des cadavres de leurs idoles et de leurs abominations.'),
  (24, 16, 19, 'Éternel, ma force et mon appui, mon refuge au jour de la détresse! Les nations viendront à toi des extrémités de la terre, Et elles diront: Nos pères n''ont hérité que le mensonge, De vaines idoles, qui ne servent à rien.'),
  (24, 16, 20, 'L''homme peut-il se faire des dieux, Qui ne sont pas des dieux? -'),
  (24, 16, 21, 'C''est pourquoi voici, je leur fais connaître, cette fois, Je leur fais connaître ma puissance et ma force; Et ils sauront que mon nom est l''Éternel.'),
  (24, 17, 1, 'Le péché de Juda est écrit avec un burin de fer, Avec une pointe de diamant; Il est gravé sur la table de leur cœur, Et sur les cornes de vos autels.'),
  (24, 17, 2, 'Comme ils pensent à leurs enfants, ainsi pensent-ils à leurs autels Et à leurs idoles d''Astarté près des arbres verts, Sur les collines élevées.'),
  (24, 17, 3, 'Je livre au pillage ma montagne et ses champs, tes biens, tous tes trésors, Et tes hauts lieux, à cause de tes péchés, sur tout ton territoire.'),
  (24, 17, 4, 'Tu perdras par ta faute l''héritage que je t''avais donné; Je t''asservirai à ton ennemi dans un pays que tu ne connais pas; Car vous avez allumé le feu de ma colère, Et il brûlera toujours.'),
  (24, 17, 5, 'Ainsi parle l''Éternel: Maudit soit l''homme qui se confie dans l''homme, Qui prend la chair pour son appui, Et qui détourne son cœur de l''Éternel!'),
  (24, 17, 6, 'Il est comme un misérable dans le désert, Et il ne voit point arriver le bonheur; Il habite les lieux brûlés du désert, Une terre salée et sans habitants.'),
  (24, 17, 7, 'Béni soit l''homme qui se confie dans l''Éternel, Et dont l''Éternel est l''espérance!'),
  (24, 17, 8, 'Il est comme un arbre planté près des eaux, Et qui étend ses racines vers le courant; Il n''aperçoit point la chaleur quand elle vient, Et son feuillage reste vert; Dans l''année de la sécheresse, il n''a point de crainte, Et il ne cesse de porter du fruit.'),
  (24, 17, 9, 'Le cœur est tortueux par-dessus tout, et il est méchant: Qui peut le connaître?'),
  (24, 17, 10, 'Moi, l''Éternel, j''éprouve le cœur, je sonde les reins, Pour rendre à chacun selon ses voies, Selon le fruit de ses œuvres.'),
  (24, 17, 11, 'Comme une perdrix qui couve des œufs qu''elle n''a point pondus, Tel est celui qui acquiert des richesses injustement; Au milieu de ses jours il doit les quitter, Et à la fin il n''est qu''un insensé.'),
  (24, 17, 12, 'Il est un trône de gloire, élevé dès le commencement, C''est le lieu de notre sanctuaire.'),
  (24, 17, 13, 'Toi qui es l''espérance d''Israël, ô Éternel! Tous ceux qui t''abandonnent seront confondus. -Ceux qui se détournent de moi seront inscrits sur la terre, Car ils abandonnent la source d''eau vive, l''Éternel.'),
  (24, 17, 14, 'Guéris-moi, Éternel, et je serai guéri; Sauve-moi, et je serai sauvé; Car tu es ma gloire.'),
  (24, 17, 15, 'Voici, ils me disent: Où est la parole de l''Éternel? Qu''elle s''accomplisse donc!'),
  (24, 17, 16, 'Et moi, pour t''obéir, je n''ai pas refusé d''être pasteur; Je n''ai pas non plus désiré le jour du malheur, tu le sais; Ce qui est sorti de mes lèvres a été découvert devant toi.'),
  (24, 17, 17, 'Ne sois pas pour moi un sujet d''effroi, Toi, mon refuge au jour du malheur!'),
  (24, 17, 18, 'Que mes persécuteurs soient confus, et que je ne sois pas confus; Qu''ils tremblent, et que je ne tremble pas, moi! Fais venir sur eux le jour du malheur, Frappe-les d''une double plaie!'),
  (24, 17, 19, 'Ainsi m''a parlé l''Éternel: Va, et tiens-toi à la porte des enfants du peuple, par laquelle entrent et sortent les rois de Juda, et à toutes les portes de Jérusalem.'),
  (24, 17, 20, 'Tu leur diras: Écoutez la parole de l''Éternel, rois de Juda, et tout Juda, et vous tous, habitants de Jérusalem, qui entrez par ces portes!'),
  (24, 17, 21, 'Ainsi parle l''Éternel: Prenez garde à vos âmes; Ne portez point de fardeau le jour du sabbat, Et n''en introduisez point par les portes de Jérusalem.'),
  (24, 17, 22, 'Ne sortez de vos maisons aucun fardeau le jour du sabbat, Et ne faites aucun ouvrage; Mais sanctifiez le jour du sabbat, Comme je l''ai ordonné à vos pères.'),
  (24, 17, 23, 'Ils n''ont pas écouté, ils n''ont pas prêté l''oreille; Ils ont raidi leur cou, Pour ne point écouter et ne point recevoir instruction.'),
  (24, 17, 24, 'Si vous m''écoutez, dit l''Éternel, Si vous n''introduisez point de fardeau Par les portes de cette ville le jour du sabbat, Si vous sanctifiez le jour du sabbat, Et ne faites aucun ouvrage ce jour-là,'),
  (24, 17, 25, 'Alors entreront par les portes de cette ville Les rois et les princes assis sur le trône de David, Montés sur des chars et sur des chevaux, Eux et leurs princes, les hommes de Juda et les habitants de Jérusalem, Et cette ville sera habitée à toujours.'),
  (24, 17, 26, 'On viendra des villes de Juda et des environs de Jérusalem, Du pays de Benjamin, de la vallée, De la montagne et du midi, Pour amener des holocaustes et des victimes, Pour apporter des offrandes et de l''encens, Et pour offrir des sacrifices d''actions de grâces dans la maison de l''Éternel.'),
  (24, 17, 27, 'Mais si vous n''écoutez pas quand je vous ordonne De sanctifier le jour du sabbat, De ne porter aucun fardeau, De ne point en introduire par les portes de Jérusalem le jour du sabbat, Alors j''allumerai un feu aux portes de la ville, Et il dévorera les palais de Jérusalem et ne s''éteindra point.'),
  (24, 18, 1, 'La parole qui fut adressée à Jérémie de la part de l''Éternel, en ces mots:'),
  (24, 18, 2, 'Lève-toi, et descends dans la maison du potier; Là, je te ferai entendre mes paroles.'),
  (24, 18, 3, 'Je descendis dans la maison du potier, Et voici, il travaillait sur un tour.'),
  (24, 18, 4, 'Le vase qu''il faisait ne réussit pas, Comme il arrive à l''argile dans la main du potier; Il en refit un autre vase, Tel qu''il trouva bon de le faire.'),
  (24, 18, 5, 'Et la parole de l''Éternel me fut adressée, en ces mots:'),
  (24, 18, 6, 'Ne puis-je pas agir envers vous comme ce potier, maison d''Israël? Dit l''Éternel. Voici, comme l''argile est dans la main du potier, Ainsi vous êtes dans ma main, maison d''Israël!'),
  (24, 18, 7, 'Soudain je parle, sur une nation, sur un royaume, D''arracher, d''abattre et de détruire;'),
  (24, 18, 8, 'Mais si cette nation, sur laquelle j''ai parlé, revient de sa méchanceté, Je me repens du mal que j''avais pensé lui faire.'),
  (24, 18, 9, 'Et soudain je parle, sur une nation, sur un royaume, De bâtir et de planter;'),
  (24, 18, 10, 'Mais si cette nation fait ce qui est mal à mes yeux, Et n''écoute pas ma voix, Je me repens du bien que j''avais eu l''intention de lui faire.'),
  (24, 18, 11, 'Parle maintenant aux hommes de Juda et aux habitants de Jérusalem, et dis: Ainsi parle l''Éternel: Voici, je prépare contre vous un malheur, Je médite un projet contre vous. Revenez chacun de votre mauvaise voie, Réformez vos voies et vos œuvres!'),
  (24, 18, 12, 'Mais ils disent: C''est en vain! Car nous suivrons nos pensées, Nous agirons chacun selon les penchants de notre mauvais cœur.'),
  (24, 18, 13, 'C''est pourquoi ainsi parle l''Éternel: Interrogez les nations! Qui a jamais entendu pareilles choses? La vierge d''Israël a commis d''horribles excès.'),
  (24, 18, 14, 'La neige du Liban abandonne-t-elle le rocher des champs? Ou voit-on tarir les eaux qui viennent de loin, fraîches et courantes?'),
  (24, 18, 15, 'Cependant mon peuple m''a oublié, il offre de l''encens à des idoles; Il a été conduit à chanceler dans ses voies, à quitter les anciens sentiers, Pour suivre des sentiers, des chemins non frayés.'),
  (24, 18, 16, 'Ils ont fait de leur pays, un objet de désolation, d''éternelle moquerie; Tous ceux qui y passent sont stupéfaits et secouent la tête.'),
  (24, 18, 17, 'Pareil au vent d''orient, je les disperserai devant l''ennemi; Je leur tournerai le dos, je ne les regarderai pas au jour de leur détresse.'),
  (24, 18, 18, 'Et ils ont dit: Venez, complotons contre Jérémie! Car la loi ne périra pas faute de sacrificateurs, Ni le conseil faute de sages, ni la parole faute de prophètes. Venez, tuons-le avec la langue; Ne prenons pas garde à tous ses discours!'),
  (24, 18, 19, 'Écoute-moi, Éternel! Et entends la voix de mes adversaires!'),
  (24, 18, 20, 'Le mal sera-t-il rendu pour le bien? Car ils ont creusé une fosse pour m''ôter la vie. Souviens-t''en, je me suis tenu devant toi, Afin de parler en leur faveur, Et de détourner d''eux ta colère.'),
  (24, 18, 21, 'C''est pourquoi livre leurs enfants à la famine, Précipite-les par le glaive; Que leurs femmes soient privées d''enfants et deviennent veuves, Et que leurs maris soient enlevés par la peste; Que leurs jeunes gens soient frappés par l''épée dans le combat!'),
  (24, 18, 22, 'Qu''on entende des cris sortir de leurs maisons, Quand soudain tu feras fondre sur eux des bandes armées! Car ils ont creusé une fosse pour me prendre, Ils ont tendu des filets sous mes pieds.'),
  (24, 18, 23, 'Et toi, Éternel, tu connais tous leurs complots pour me faire mourir; Ne pardonne pas leur iniquité, N''efface pas leur péché de devant toi! Qu''ils soient renversés en ta présence! Agis contre eux au temps de ta colère!'),
  (24, 19, 1, 'Ainsi a parlé l''Éternel: Va, achète d''un potier un vase de terre, et prends avec toi des anciens du peuple et des anciens des sacrificateurs.'),
  (24, 19, 2, 'Rends-toi dans la vallée de Ben-Hinnom, qui est à l''entrée de la porte de la poterie; et là, tu publieras les paroles que je te dirai.'),
  (24, 19, 3, 'Tu diras: Écoutez la parole de l''Éternel, rois de Juda, et vous, habitants de Jérusalem! Ainsi parle l''Éternel des armées, le Dieu d''Israël: Voici, je vais faire venir sur ce lieu un malheur Qui étourdira les oreilles de quiconque en entendra parler.'),
  (24, 19, 4, 'Ils m''ont abandonné, ils ont profané ce lieu, Ils y ont offert de l''encens à d''autres dieux, Que ne connaissaient ni eux, ni leurs pères, ni les rois de Juda, Et ils ont rempli ce lieu de sang innocent;'),
  (24, 19, 5, 'Ils ont bâti des hauts lieux à Baal, Pour brûler leurs enfants au feu en holocaustes à Baal: Ce que je n''avais ni ordonné ni prescrit, Ce qui ne m''était point venu à la pensée.'),
  (24, 19, 6, 'C''est pourquoi voici, les jours viennent, dit l''Éternel, Où ce lieu ne sera plus appelé Topheth et vallée de Ben-Hinnom, Mais où on l''appellera vallée du carnage.'),
  (24, 19, 7, 'J''anéantirai dans ce lieu le conseil de Juda et de Jérusalem; Je les ferai tomber par l''épée devant leurs ennemis Et par la main de ceux qui en veulent à leur vie; Je donnerai leurs cadavres en pâture Aux oiseaux du ciel et aux bêtes de la terre.'),
  (24, 19, 8, 'Je ferai de cette ville un objet de désolation et de moquerie; Tous ceux qui passeront près d''elle Seront dans l''étonnement et siffleront sur toutes ses plaies.'),
  (24, 19, 9, 'Je leur ferai manger la chair de leurs fils et la chair de leurs filles, Et les uns mangeront la chair des autres, Au milieu de l''angoisse et de la détresse Où les réduiront leurs ennemis Et ceux qui en veulent à leur vie.'),
  (24, 19, 10, 'Tu briseras ensuite le vase, sous les yeux des hommes qui seront allés avec toi.'),
  (24, 19, 11, 'Et tu leur diras: Ainsi parle l''Éternel des armées: C''est ainsi que je briserai ce peuple et cette ville, Comme on brise un vase de potier, Sans qu''il puisse être rétabli. Et l''on enterrera les morts à Topheth par défaut de place pour enterrer.'),
  (24, 19, 12, 'C''est ainsi que je ferai à ce lieu, dit l''Éternel, et à ses habitants, Et je rendrai cette ville semblable à Topheth.'),
  (24, 19, 13, 'Les maisons de Jérusalem et les maisons des rois de Juda Seront impures comme le lieu de Topheth, Toutes les maisons sur les toits desquelles on offrait de l''encens A toute l''armée des cieux, Et on faisait des libations à d''autres dieux.'),
  (24, 19, 14, 'Jérémie revint de Topheth, où l''Éternel l''avait envoyé prophétiser. Puis il se tint dans le parvis de la maison de l''Éternel, et il dit à tout le peuple:'),
  (24, 19, 15, 'Ainsi parle l''Éternel des armées, le Dieu d''Israël: Voici, je vais faire venir sur cette ville et sur toutes les villes qui dépendent d''elle tous les malheurs que je lui ai prédits, parce qu''ils ont raidi leur cou, pour ne point écouter mes paroles.'),
  (24, 20, 1, 'Paschhur, fils d''Immer, sacrificateur et inspecteur en chef dans la maison de l''Éternel, entendit Jérémie qui prophétisait ces choses.'),
  (24, 20, 2, 'Et Paschhur frappa Jérémie, le prophète, et le mit dans la prison qui était à la porte supérieure de Benjamin, dans la maison de l''Éternel.'),
  (24, 20, 3, 'Mais le lendemain, Paschhur fit sortir Jérémie de prison. Et Jérémie lui dit: Ce n''est pas le nom de Paschhur que l''Éternel te donne, c''est celui de Magor-Missabib.'),
  (24, 20, 4, 'Car ainsi parle l''Éternel: Voici, je te livrerai à la terreur, toi et tous tes amis; ils tomberont par l''épée de leurs ennemis, et tes yeux le verront. Je livrerai aussi tout Juda entre les mains du roi de Babylone, qui les emmènera captifs à Babylone et les frappera de l''épée.'),
  (24, 20, 5, 'Je livrerai toutes les richesses de cette ville, tout le produit de son travail, tout ce qu''elle a de précieux, je livrerai tous les trésors des rois de Juda entre les mains de leurs ennemis, qui les pilleront, les enlèveront et les transporteront à Babylone.'),
  (24, 20, 6, 'Et toi, Paschhur, et tous ceux qui demeurent dans ta maison, vous irez en captivité; tu iras à Babylone, et là tu mourras, et là tu seras enterré, toi et tous tes amis auxquels tu as prophétisé le mensonge.'),
  (24, 20, 7, 'Tu m''as persuadé, Éternel, et je me suis laissé persuader; Tu m''as saisi, tu m''as vaincu. Et je suis chaque jour un objet de raillerie, Tout le monde se moque de moi.'),
  (24, 20, 8, 'Car toutes les fois que je parle, il faut que je crie, Que je crie à la violence et à l''oppression! Et la parole de l''Éternel est pour moi Un sujet d''opprobre et de risée chaque jour.'),
  (24, 20, 9, 'Si je dis: Je ne ferai plus mention de lui, Je ne parlerai plus en son nom, Il y a dans mon cœur comme un feu dévorant Qui est renfermé dans mes os. Je m''efforce de le contenir, et je ne le puis.'),
  (24, 20, 10, 'Car j''apprends les mauvais propos de plusieurs, L''épouvante qui règne à l''entour: Accusez-le, et nous l''accuserons! Tous ceux qui étaient en paix avec moi Observent si je chancelle: Peut-être se laissera-t-il surprendre, Et nous serons maîtres de lui, Nous tirerons vengeance de lui!'),
  (24, 20, 11, 'Mais l''Éternel est avec moi comme un héros puissant; C''est pourquoi mes persécuteurs chancellent et n''auront pas le dessus; Ils seront remplis de confusion pour n''avoir pas réussi: Ce sera une honte éternelle qui ne s''oubliera pas.'),
  (24, 20, 12, 'L''Éternel des armées éprouve le juste, Il pénètre les reins et les cœurs. Je verrai ta vengeance s''exercer contre eux, Car c''est à toi que je confie ma cause.'),
  (24, 20, 13, 'Chantez à l''Éternel, louez l''Éternel! Car il délivre l''âme du malheureux de la main des méchants.'),
  (24, 20, 14, 'Maudit soit le jour où je suis né! Que le jour où ma mère m''a enfanté Ne soit pas béni!'),
  (24, 20, 15, 'Maudit soit l''homme qui porta cette nouvelle à mon père: Il t''est né un enfant mâle, Et qui le combla de joie!'),
  (24, 20, 16, 'Que cet homme soit comme les villes Que l''Éternel a détruites sans miséricorde! Qu''il entende des gémissements le matin, Et des cris de guerre à midi!'),
  (24, 20, 17, 'Que ne m''a-t-on fait mourir dans le sein de ma mère! Que ne m''a-t-elle servi de tombeau! Que n''est-elle restée éternellement enceinte!'),
  (24, 20, 18, 'Pourquoi suis-je sorti du sein maternel Pour voir la souffrance et la douleur, Et pour consumer mes jours dans la honte?'),
  (24, 21, 1, 'La parole qui fut adressée à Jérémie de la part de l''Éternel, lorsque le roi Sédécias lui envoya Paschhur, fils de Malkija, et Sophonie, fils de Maaséja, le sacrificateur, pour lui dire:'),
  (24, 21, 2, 'Consulte pour nous l''Éternel; car Nebucadnetsar, roi de Babylone, nous fait la guerre; peut-être l''Éternel fera-t-il en notre faveur quelqu''un de ses miracles, afin qu''il s''éloigne de nous.'),
  (24, 21, 3, 'Jérémie leur répondit: Vous direz à Sédécias:'),
  (24, 21, 4, 'Ainsi parle l''Éternel, le Dieu d''Israël: Voici, je vais détourner les armes de guerre qui sont dans vos mains, et avec lesquelles vous combattez en dehors des murailles le roi de Babylone et les Chaldéens qui vous assiègent, et je les rassemblerai au milieu de cette ville.'),
  (24, 21, 5, 'Puis je combattrai contre vous, la main étendue et le bras fort, avec colère, avec fureur, avec une grande irritation.'),
  (24, 21, 6, 'Je frapperai les habitants de cette ville, les hommes et les bêtes; ils mourront d''une peste affreuse.'),
  (24, 21, 7, 'Après cela, dit l''Éternel, je livrerai Sédécias, roi de Juda, ses serviteurs, le peuple, et ceux qui dans cette ville échapperont à la peste, à l''épée et à la famine, je les livrerai entre les mains de Nebucadnetsar, roi de Babylone, entre les mains de leurs ennemis, entre les mains de ceux qui en veulent à leur vie; et Nebucadnetsar les frappera du tranchant de l''épée, il ne les épargnera pas, il n''aura point de pitié, point de compassion.'),
  (24, 21, 8, 'Tu diras à ce peuple: Ainsi parle l''Éternel: Voici, je mets devant vous le chemin de la vie et le chemin de la mort.'),
  (24, 21, 9, 'Celui qui restera dans cette ville mourra par l''épée, par la famine ou par la peste; mais celui qui sortira pour se rendre aux Chaldéens qui vous assiègent aura la vie sauve, et sa vie sera son butin.'),
  (24, 21, 10, 'Car je dirige mes regards contre cette ville pour faire du mal et non du bien, dit l''Éternel; elle sera livrée entre les mains du roi de Babylone, qui la brûlera par le feu.'),
  (24, 21, 11, 'Et tu diras à la maison du roi de Juda: Écoutez la parole de l''Éternel!'),
  (24, 21, 12, 'Maison de David! Ainsi parle l''Éternel: Rendez la justice dès le matin, Et délivrez l''opprimé des mains de l''oppresseur, De peur que ma colère n''éclate comme un feu, Et ne s''enflamme, sans qu''on puisse l''éteindre, A cause de la méchanceté de vos actions.'),
  (24, 21, 13, 'Voici, j''en veux à toi, Ville assise dans la vallée, sur le rocher de la plaine, Dit l''Éternel, A vous qui dites: Qui descendra contre nous? Qui entrera dans nos demeures?'),
  (24, 21, 14, 'Je vous châtierai selon le fruit de vos œuvres, dit l''Éternel; Je mettrai le feu à votre forêt, Et il en dévorera tous les alentours.'),
  (24, 22, 1, 'Ainsi parle l''Éternel: Descends dans la maison du roi de Juda, et là prononce cette parole.'),
  (24, 22, 2, 'Tu diras: Écoute la parole de l''Éternel, roi de Juda, qui es assis sur le trône de David, toi, tes serviteurs, et ton peuple, qui entrez par ces portes!'),
  (24, 22, 3, 'Ainsi parle l''Éternel: Pratiquez la justice et l''équité; délivrez l''opprimé des mains de l''oppresseur; ne maltraitez pas l''étranger, l''orphelin et la veuve; n''usez pas de violence, et ne répandez point de sang innocent dans ce lieu.'),
  (24, 22, 4, 'Car si vous agissez selon cette parole, les rois assis sur le trône de David entreront par les portes de cette maison, montés sur des chars et sur des chevaux, eux, leurs serviteurs et leur peuple.'),
  (24, 22, 5, 'Mais si vous n''écoutez pas ces paroles, je le jure par moi-même, dit l''Éternel, cette maison deviendra une ruine.'),
  (24, 22, 6, 'Car ainsi parle l''Éternel sur la maison du roi de Juda: Tu es pour moi comme Galaad, comme le sommet du Liban; Mais certes, je ferai de toi un désert, Une ville sans habitants.'),
  (24, 22, 7, 'Je prépare contre toi des destructeurs, Chacun avec ses armes; Ils abattront tes plus beaux cèdres, Et les jetteront au feu.'),
  (24, 22, 8, 'Des nations nombreuses passeront près de cette ville, Et elles se diront l''une à l''autre: Pourquoi l''Éternel a-t-il ainsi traité cette grande ville?'),
  (24, 22, 9, 'Et l''on répondra: Parce qu''ils ont abandonné L''alliance de l''Éternel, leur Dieu, Parce qu''ils se sont prosternés devant d''autres dieux et les ont servis.'),
  (24, 22, 10, 'Ne pleurez point celui qui est mort, Et ne vous lamentez pas sur lui; Pleurez, pleurez celui qui s''en va, Car il ne reviendra plus, Il ne reverra plus le pays de sa naissance.'),
  (24, 22, 11, 'Car ainsi parle l''Éternel sur Schallum, fils de Josias, roi de Juda, Qui régnait à la place de Josias, son père, Et qui est sorti de ce lieu: Il n''y reviendra plus;'),
  (24, 22, 12, 'Mais il mourra dans le lieu où on l''emmène captif, Et il ne verra plus ce pays.'),
  (24, 22, 13, 'Malheur à celui qui bâtit sa maison par l''injustice, Et ses chambres par l''iniquité; Qui fait travailler son prochain sans le payer, Sans lui donner son salaire;'),
  (24, 22, 14, 'Qui dit: Je me bâtirai une maison vaste, Et des chambres spacieuses; Et qui s''y fait percer des fenêtres, La lambrisse de cèdre, Et la peint en couleur rouge!'),
  (24, 22, 15, 'Est-ce que tu règnes, parce que tu as de la passion pour le cèdre? Ton père ne mangeait-il pas, ne buvait-il pas? Mais il pratiquait la justice et l''équité, Et il fut heureux;'),
  (24, 22, 16, 'Il jugeait la cause du pauvre et de l''indigent, Et il fut heureux. N''est-ce pas là me connaître? dit l''Éternel.'),
  (24, 22, 17, 'Mais tu n''as des yeux et un cœur Que pour te livrer à la cupidité, Pour répandre le sang innocent, Et pour exercer l''oppression et la violence.'),
  (24, 22, 18, 'C''est pourquoi ainsi parle l''Éternel sur Jojakim, fils de Josias, roi de Juda: On ne le pleurera pas, en disant: Hélas, mon frère! hélas, ma sœur! On ne le pleurera pas, en disant: Hélas, seigneur! hélas, sa majesté!'),
  (24, 22, 19, 'Il aura la sépulture d''un âne, Il sera traîné et jeté hors des portes de Jérusalem.'),
  (24, 22, 20, 'Monte sur le Liban, et crie! Élève ta voix sur le Basan! Crie du haut d''Abarim! Car tous ceux qui t''aimaient sont brisés.'),
  (24, 22, 21, 'Je t''ai parlé dans le temps de ta prospérité; Tu disais: Je n''écouterai pas. C''est ainsi que tu as agi dès ta jeunesse; Tu n''as pas écouté ma voix.'),
  (24, 22, 22, 'Tous tes pasteurs seront la pâture du vent, Et ceux qui t''aiment iront en captivité; C''est alors que tu seras dans la honte, dans la confusion, A cause de toute ta méchanceté.'),
  (24, 22, 23, 'Toi qui habites sur le Liban, Qui as ton nid dans les cèdres, Combien tu gémiras quand les douleurs t''atteindront, Douleurs semblables à celles d''une femme en travail!'),
  (24, 22, 24, 'Je suis vivant! dit l''Éternel, Quand Jeconia, fils de Jojakim, roi de Juda, serait Un anneau à ma main droite, Je t''arracherais de là.'),
  (24, 22, 25, 'Je te livrerai entre les mains de ceux qui en veulent à ta vie, Entre les mains de ceux devant qui tu trembles, Entre les mains de Nebucadnetsar, roi de Babylone, Entre les mains des Chaldéens.'),
  (24, 22, 26, 'Je te jetterai, toi et ta mère qui t''a enfanté, Dans un autre pays où vous n''êtes pas nés, Et là vous mourrez;'),
  (24, 22, 27, 'Mais dans le pays où ils auront le désir de retourner, Ils ne retourneront pas.'),
  (24, 22, 28, 'Est-il donc un vase méprisé, brisé, ce Jeconia? Est-il un objet auquel on n''attache aucun prix? Pourquoi sont-ils jetés, lui et sa postérité, Lancés dans un pays qu''ils ne connaissent pas? -'),
  (24, 22, 29, 'Terre, terre, terre, Écoute la parole de l''Éternel!'),
  (24, 22, 30, 'Ainsi parle l''Éternel: Inscrivez cet homme comme privé d''enfants, Comme un homme dont les jours ne seront pas prospères; Car nul de ses descendants ne réussira A s''asseoir sur le trône de David Et à régner sur Juda.'),
  (24, 23, 1, 'Malheur aux pasteurs qui détruisent et dispersent Le troupeau de mon pâturage! dit l''Éternel.'),
  (24, 23, 2, 'C''est pourquoi ainsi parle l''Éternel, le Dieu d''Israël, Sur les pasteurs qui paissent mon peuple: Vous avez dispersé mes brebis, vous les avez chassées, Vous n''en avez pas pris soin; Voici, je vous châtierai à cause de la méchanceté de vos actions, Dit l''Éternel.'),
  (24, 23, 3, 'Et je rassemblerai le reste de mes brebis De tous les pays où je les ai chassées; Je les ramènerai dans leur pâturage; Elles seront fécondes et multiplieront.'),
  (24, 23, 4, 'J''établirai sur elles des pasteurs qui les paîtront; Elles n''auront plus de crainte, plus de terreur, Et il n''en manquera aucune, dit l''Éternel.'),
  (24, 23, 5, 'Voici, les jours viennent, dit l''Éternel, Où je susciterai à David un germe juste; Il régnera en roi et prospérera, Il pratiquera la justice et l''équité dans le pays.'),
  (24, 23, 6, 'En son temps, Juda sera sauvé, Israël aura la sécurité dans sa demeure; Et voici le nom dont on l''appellera: L''Éternel notre justice.'),
  (24, 23, 7, 'C''est pourquoi voici, les jours viennent, dit l''Éternel, Où l''on ne dira plus: L''Éternel est vivant, Lui qui a fait monter du pays d''Égypte les enfants d''Israël!'),
  (24, 23, 8, 'Mais on dira: L''Éternel est vivant, Lui qui a fait monter et qui a ramené La postérité de la maison d''Israël du pays du septentrion Et de tous les pays où je les avais chassés! Et ils habiteront dans leur pays.'),
  (24, 23, 9, 'Sur les prophètes. Mon cœur est brisé au dedans de moi, Tous mes os tremblent; Je suis comme un homme ivre, Comme un homme pris de vin, A cause de l''Éternel et à cause de ses paroles saintes.'),
  (24, 23, 10, 'Car le pays est rempli d''adultères; Le pays est en deuil à cause de la malédiction; Les plaines du désert sont desséchées. Ils courent au mal, Ils n''ont de la force que pour l''iniquité.'),
  (24, 23, 11, 'Prophètes et sacrificateurs sont corrompus; Même dans ma maison j''ai trouvé leur méchanceté, Dit l''Éternel.'),
  (24, 23, 12, 'C''est pourquoi leur chemin sera glissant et ténébreux, Ils seront poussés et ils tomberont; Car je ferai venir sur eux le malheur, L''année où je les châtierai, dit l''Éternel.'),
  (24, 23, 13, 'Dans les prophètes de Samarie j''ai vu de l''extravagance; Ils ont prophétisé par Baal, Ils ont égaré mon peuple d''Israël.'),
  (24, 23, 14, 'Mais dans les prophètes de Jérusalem j''ai vu des choses horribles; Ils sont adultères, ils marchent dans le mensonge; Ils fortifient les mains des méchants, Afin qu''aucun ne revienne de sa méchanceté; Ils sont tous à mes yeux comme Sodome, Et les habitants de Jérusalem comme Gomorrhe.'),
  (24, 23, 15, 'C''est pourquoi ainsi parle l''Éternel des armées sur les prophètes: Voici, je vais les nourrir d''absinthe, Et je leur ferai boire des eaux empoisonnées; Car c''est par les prophètes de Jérusalem Que l''impiété s''est répandue dans tout le pays.'),
  (24, 23, 16, 'Ainsi parle l''Éternel des armées: N''écoutez pas les paroles des prophètes qui vous prophétisent! Ils vous entraînent à des choses de néant; Ils disent les visions de leur cœur, Et non ce qui vient de la bouche de l''Éternel.'),
  (24, 23, 17, 'Ils disent à ceux qui me méprisent: L''Éternel a dit: Vous aurez la paix; Et ils disent à tous ceux qui suivent les penchants de leur cœur: Il ne vous arrivera aucun mal.'),
  (24, 23, 18, 'Qui donc a assisté au conseil de l''Éternel Pour voir, pour écouter sa parole? Qui a prêté l''oreille à sa parole, qui l''a entendue?'),
  (24, 23, 19, 'Voici, la tempête de l''Éternel, la fureur éclate, L''orage se précipite, Il fond sur la tête des méchants.'),
  (24, 23, 20, 'La colère de l''Éternel ne se calmera pas, Jusqu''à ce qu''il ait accompli, exécuté les desseins de son cœur. Vous le comprendrez dans la suite des temps.'),
  (24, 23, 21, 'Je n''ai point envoyé ces prophètes, et ils ont couru; Je ne leur ai point parlé, et ils ont prophétisé.'),
  (24, 23, 22, 'S''ils avaient assisté à mon conseil, Ils auraient dû faire entendre mes paroles à mon peuple, Et les faire revenir de leur mauvaise voie, De la méchanceté de leurs actions.'),
  (24, 23, 23, 'Ne suis-je un Dieu que de près, dit l''Éternel, Et ne suis-je pas aussi un Dieu de loin?'),
  (24, 23, 24, 'Quelqu''un se tiendra-t-il dans un lieu caché, Sans que je le voie? dit l''Éternel. Ne remplis-je pas, moi, les cieux et la terre? dit l''Éternel.'),
  (24, 23, 25, 'J''ai entendu ce que disent les prophètes Qui prophétisent en mon nom le mensonge, disant: J''ai eu un songe! j''ai eu un songe!'),
  (24, 23, 26, 'Jusques à quand ces prophètes veulent-ils prophétiser le mensonge, Prophétiser la tromperie de leur cœur?'),
  (24, 23, 27, 'Ils pensent faire oublier mon nom à mon peuple Par les songes que chacun d''eux raconte à son prochain, Comme leurs pères ont oublié mon nom pour Baal.'),
  (24, 23, 28, 'Que le prophète qui a eu un songe raconte ce songe, Et que celui qui a entendu ma parole rapporte fidèlement ma parole. Pourquoi mêler la paille au froment? dit l''Éternel.'),
  (24, 23, 29, 'Ma parole n''est-elle pas comme un feu, dit l''Éternel, Et comme un marteau qui brise le roc?'),
  (24, 23, 30, 'C''est pourquoi voici, dit l''Éternel, j''en veux aux prophètes Qui se dérobent mes paroles l''un à l''autre.'),
  (24, 23, 31, 'Voici, dit l''Éternel, j''en veux aux prophètes Qui prennent leur propre parole et la donnent pour ma parole.'),
  (24, 23, 32, 'Voici, dit l''Éternel, j''en veux à ceux qui prophétisent des songes faux, Qui les racontent, et qui égarent mon peuple Par leurs mensonges et par leur témérité; Je ne les ai point envoyés, je ne leur ai point donné d''ordre, Et ils ne sont d''aucune utilité à ce peuple, dit l''Éternel.'),
  (24, 23, 33, 'Si ce peuple, ou un prophète, ou un sacrificateur te demande: Quelle est la menace de l''Éternel? Tu leur diras quelle est cette menace: Je vous rejetterai, dit l''Éternel.'),
  (24, 23, 34, 'Et le prophète, le sacrificateur, ou celui du peuple Qui dira: Menace de l''Éternel, Je le châtierai, lui et sa maison.'),
  (24, 23, 35, 'Vous direz, chacun à son prochain, chacun à son frère: Qu''a répondu l''Éternel? Qu''a dit l''Éternel?'),
  (24, 23, 36, 'Mais vous ne direz plus: Menace de l''Éternel! Car la parole de chacun sera pour lui une menace; Vous tordez les paroles du Dieu vivant, De l''Éternel des armées, notre Dieu.'),
  (24, 23, 37, 'Tu diras au prophète: Que t''a répondu l''Éternel? Qu''a dit l''Éternel?'),
  (24, 23, 38, 'Et si vous dites encore: Menace de l''Éternel! Alors ainsi parle l''Éternel: Parce que vous dites ce mot: Menace de l''Éternel! Quoique j''aie envoyé vers vous pour dire: Vous ne direz pas: Menace de l''Éternel!'),
  (24, 23, 39, 'A cause de cela voici, je vous oublierai, Et je vous rejetterai, vous et la ville Que j''avais donnée à vous et à vos pères, Je vous rejetterai loin de ma face;'),
  (24, 23, 40, 'Je mettrai sur vous un opprobre éternel Et une honte éternelle, Qui ne s''oublieront pas.'),
  (24, 24, 1, 'L''Éternel me fit voir deux paniers de figues posés devant le temple de l''Éternel, après que Nebucadnetsar, roi de Babylone, eut emmené de Jérusalem et conduit à Babylone Jeconia, fils de Jojakim, roi de Juda, les chefs de Juda, les charpentiers et les serruriers.'),
  (24, 24, 2, 'L''un des paniers contenait de très bonnes figues, comme les figues de la première récolte, et l''autre panier de très mauvaises figues, qu''on ne pouvait manger à cause de leur mauvaise qualité.'),
  (24, 24, 3, 'L''Éternel me dit: Que vois-tu, Jérémie? Je répondis: Des figues, Les bonnes figues sont très bonnes, et les mauvaises sont très mauvaises et ne peuvent être mangées à cause de leur mauvaise qualité.'),
  (24, 24, 4, 'La parole de l''Éternel me fut adressée, en ces mots:'),
  (24, 24, 5, 'Ainsi parle l''Éternel, le Dieu d''Israël: Comme tu distingues ces bonnes figues, ainsi je distinguerai, pour leur être favorable, les captifs de Juda, que j''ai envoyés de ce lieu dans le pays des Chaldéens.'),
  (24, 24, 6, 'Je les regarderai d''un œil favorable, et je les ramènerai dans ce pays; je les établirai et ne les détruirai plus, je les planterai et ne les arracherai plus.'),
  (24, 24, 7, 'Je leur donnerai un cœur pour qu''ils connaissent que je suis l''Éternel; ils seront mon peuple, et je serai leur Dieu, s''ils reviennent à moi de tout leur cœur.'),
  (24, 24, 8, 'Et comme les mauvaises figues qui ne peuvent être mangées à cause de leur mauvaise qualité, dit l''Éternel, ainsi ferai-je devenir Sédécias, roi de Juda, ses chefs, et le reste de Jérusalem, ceux qui sont restés dans ce pays et ceux qui habitent dans le pays d''Égypte.'),
  (24, 24, 9, 'Je les rendrai un objet d''effroi, de malheur, pour tous les royaumes de la terre, un sujet d''opprobre, de sarcasme, de raillerie, et de malédiction, dans tous les lieux où je les chasserai.'),
  (24, 24, 10, 'J''enverrai parmi eux l''épée, la famine et la peste, jusqu''à ce qu''ils aient disparu du pays que j''avais donné à eux et à leurs pères.'),
  (24, 25, 1, 'La parole fut adressée à Jérémie sur tout le peuple de Juda, la quatrième année de Jojakim, fils de Josias, roi de Juda, -c''était la première année de Nebucadnetsar, roi de Babylone, -'),
  (24, 25, 2, 'parole que Jérémie prononça devant tout le peuple de Juda et devant tous les habitants de Jérusalem, en disant:'),
  (24, 25, 3, 'Depuis la treizième année de Josias, fils d''Amon, roi de Juda, il y a vingt-trois ans que la parole de l''Éternel m''a été adressée; je vous ai parlé, je vous ai parlé dès le matin, et vous n''avez pas écouté.'),
  (24, 25, 4, 'L''Éternel vous a envoyé tous ses serviteurs, les prophètes, il les a envoyés dès le matin; et vous n''avez pas écouté, vous n''avez pas prêté l''oreille pour écouter.'),
  (24, 25, 5, 'Ils ont dit: Revenez chacun de votre mauvaise voie et de la méchanceté de vos actions, et vous resterez dans le pays que j''ai donné à vous et à vos pères, d''éternité en éternité;'),
  (24, 25, 6, 'n''allez pas après d''autres dieux, pour les servir et pour vous prosterner devant eux, ne m''irritez pas par l''ouvrage de vos mains, et je ne vous ferai aucun mal.'),
  (24, 25, 7, 'Mais vous ne m''avez pas écouté, dit l''Éternel, afin de m''irriter par l''ouvrage de vos mains, pour votre malheur.'),
  (24, 25, 8, 'C''est pourquoi ainsi parle l''Éternel des armées: Parce que vous n''avez point écouté mes paroles,'),
  (24, 25, 9, 'j''enverrai chercher tous les peuples du septentrion, dit l''Éternel, et j''enverrai auprès de Nebucadnetsar, roi de Babylone, mon serviteur; je le ferai venir contre ce pays et contre ses habitants, et contre toutes ces nations à l''entour, afin de les dévouer par interdit, et d''en faire un objet de désolation et de moquerie, des ruines éternelles.'),
  (24, 25, 10, 'Je ferai cesser parmi eux les cris de réjouissance et les cris d''allégresse, les chants du fiancé et les chants de la fiancée, le bruit de la meule et la lumière de la lampe.'),
  (24, 25, 11, 'Tout ce pays deviendra une ruine, un désert, et ces nations seront asservies au roi de Babylone pendant soixante-dix ans.'),
  (24, 25, 12, 'Mais lorsque ces soixante-dix ans seront accomplis, je châtierai le roi de Babylone et cette nation, dit l''Éternel, à cause de leurs iniquités; je punirai le pays des Chaldéens, et j''en ferai des ruines éternelles.'),
  (24, 25, 13, 'Je ferai venir sur ce pays toutes les choses que j''ai annoncées sur lui, tout ce qui est écrit dans ce livre, ce que Jérémie a prophétisé sur toutes les nations.'),
  (24, 25, 14, 'Car des nations puissantes et de grands rois les asserviront, eux aussi, et je leur rendrai selon leurs œuvres et selon l''ouvrage de leurs mains.'),
  (24, 25, 15, 'Car ainsi m''a parlé l''Éternel, le Dieu d''Israël: Prends de ma main cette coupe remplie du vin de ma colère, Et fais-la boire à toutes les nations Vers lesquelles je t''enverrai.'),
  (24, 25, 16, 'Ils boiront, et ils chancelleront et seront comme fous, A la vue du glaive que j''enverrai au milieu d''eux.'),
  (24, 25, 17, 'Et je pris la coupe de la main de l''Éternel, Et je la fis boire à toutes les nations Vers lesquelles l''Éternel m''envoyait:'),
  (24, 25, 18, 'A Jérusalem et aux villes de Juda, A ses rois et à ses chefs, Pour en faire une ruine, Un objet de désolation, de moquerie et de malédiction, Comme cela se voit aujourd''hui;'),
  (24, 25, 19, 'A Pharaon, roi d''Égypte, A ses serviteurs, à ses chefs, et à tout son peuple;'),
  (24, 25, 20, 'A toute l''Arabie, à tous les rois du pays d''Uts, A tous les rois du pays des Philistins, A Askalon, à Gaza, à Ékron, et à ce qui reste d''Asdod;'),
  (24, 25, 21, 'A Édom, A Moab, et aux enfants d''Ammon;'),
  (24, 25, 22, 'A tous les rois de Tyr, à tous les rois de Sidon, Et aux rois des îles qui sont au delà de la mer;'),
  (24, 25, 23, 'A Dedan, à Théma, à Buz, Et à tous ceux qui se rasent les coins de la barbe;'),
  (24, 25, 24, 'A tous les rois d''Arabie, Et à tous les rois des Arabes qui habitent dans le désert;'),
  (24, 25, 25, 'A tous les rois de Zimri, A tous les rois d''Élam, Et à tous les rois de Médie;'),
  (24, 25, 26, 'A tous les rois du septentrion, Proches ou éloignés, Aux uns et aux autres, Et à tous les royaumes du monde Qui sont sur la face de la terre. Et le roi de Schéschac boira après eux.'),
  (24, 25, 27, 'Tu leur diras: Ainsi parle l''Éternel des armées, le Dieu d''Israël: Buvez, enivrez-vous, et vomissez, Et tombez sans vous relever, A la vue du glaive que j''enverrai au milieu de vous!'),
  (24, 25, 28, 'Et s''ils refusent de prendre de ta main la coupe pour boire, Dis-leur: Ainsi parle l''Éternel des armées: Vous boirez!'),
  (24, 25, 29, 'Car voici, dans la ville sur laquelle mon nom est invoqué Je commence à faire du mal; Et vous, vous resteriez impunis! Vous ne resterez pas impunis; Car j''appellerai le glaive sur tous les habitants de la terre, Dit l''Éternel des armées.'),
  (24, 25, 30, 'Et toi, tu leur prophétiseras toutes ces choses, Et tu leur diras: L''Éternel rugira d''en haut; De sa demeure sainte il fera retentir sa voix; Il rugira contre le lieu de sa résidence; Il poussera des cris, comme ceux qui foulent au pressoir, Contre tous les habitants de la terre.'),
  (24, 25, 31, 'Le bruit parvient jusqu''à l''extrémité de la terre; Car l''Éternel est en dispute avec les nations, Il entre en jugement contre toute chair; Il livre les méchants au glaive, dit l''Éternel.'),
  (24, 25, 32, 'Ainsi parle l''Éternel des armées: Voici, la calamité va de nation en nation, Et une grande tempête s''élève des extrémités de la terre.'),
  (24, 25, 33, 'Ceux que tuera l''Éternel en ce jour seront étendus D''un bout à l''autre de la terre; Ils ne seront ni pleurés, ni recueillis, ni enterrés, Ils seront comme du fumier sur la terre.'),
  (24, 25, 34, 'Gémissez, pasteurs, et criez! Roulez-vous dans la cendre, conducteurs de troupeaux! Car les jours sont venus où vous allez être égorgés. Je vous briserai, et vous tomberez comme un vase de prix.'),
  (24, 25, 35, 'Plus de refuge pour les pasteurs! Plus de salut pour les conducteurs de troupeaux!'),
  (24, 25, 36, 'On entend les cris des pasteurs, Les gémissements des conducteurs de troupeaux; Car l''Éternel ravage leur pâturage.'),
  (24, 25, 37, 'Les habitations paisibles sont détruites Par la colère ardente de l''Éternel.'),
  (24, 25, 38, 'Il a abandonné sa demeure comme un lionceau sa tanière; Car leur pays est réduit en désert Par la fureur du destructeur Et par son ardente colère.'),
  (24, 26, 1, 'Au commencement du règne de Jojakim, fils de Josias, roi de Juda, cette parole fut prononcée de la part de l''Éternel, en ces mots:'),
  (24, 26, 2, 'Ainsi parle l''Éternel: Tiens-toi dans le parvis de la maison de l''Éternel, et dis à ceux qui de toutes les villes de Juda viennent se prosterner dans la maison de l''Éternel toutes les paroles que je t''ordonne de leur dire; n''en retranche pas un mot.'),
  (24, 26, 3, 'Peut-être écouteront-ils, et reviendront-ils chacun de leur mauvaise voie; alors je me repentirai du mal que j''avais pensé leur faire à cause de la méchanceté de leurs actions.'),
  (24, 26, 4, 'Tu leur diras: Ainsi parle l''Éternel: Si vous ne m''écoutez pas quand je vous ordonne de suivre ma loi que j''ai mise devant vous,'),
  (24, 26, 5, 'd''écouter les paroles de mes serviteurs, les prophètes, que je vous envoie, que je vous ai envoyés dès le matin, et que vous n''avez pas écoutés,'),
  (24, 26, 6, 'alors je traiterai cette maison comme Silo, et je ferai de cette ville un objet de malédiction pour toutes les nations de la terre.'),
  (24, 26, 7, 'Les sacrificateurs, les prophètes, et tout le peuple, entendirent Jérémie prononcer ces paroles dans la maison de l''Éternel.'),
  (24, 26, 8, 'Et comme Jérémie achevait de dire tout ce que l''Éternel lui avait ordonné de dire à tout le peuple, les sacrificateurs, les prophètes, et tout le peuple, se saisirent de lui, en disant: Tu mourras!'),
  (24, 26, 9, 'Pourquoi prophétises-tu au nom de l''Éternel, en disant: Cette maison sera comme Silo, et cette ville sera dévastée, privée d''habitants? Tout le peuple s''attroupa autour de Jérémie dans la maison de l''Éternel.'),
  (24, 26, 10, 'Lorsque les chefs de Juda eurent appris ces choses, ils montèrent de la maison du roi à la maison de l''Éternel, et s''assirent à l''entrée de la porte neuve de la maison de l''Éternel.'),
  (24, 26, 11, 'Alors les sacrificateurs et les prophètes parlèrent ainsi aux chefs et à tout le peuple: Cet homme mérite la mort; car il a prophétisé contre cette ville, comme vous l''avez entendu de vos oreilles.'),
  (24, 26, 12, 'Jérémie dit à tous les chefs et à tout le peuple: L''Éternel m''a envoyé pour prophétiser contre cette maison et contre cette ville, toutes les choses que vous avez entendues.'),
  (24, 26, 13, 'Maintenant réformez vos voies et vos œuvres, écoutez la voix de l''Éternel, votre Dieu, et l''Éternel se repentira du mal qu''il a prononcé contre vous.'),
  (24, 26, 14, 'Pour moi, me voici entre vos mains; traitez-moi comme il vous semblera bon et juste.'),
  (24, 26, 15, 'Seulement sachez que, si vous me faites mourir, vous vous chargez du sang innocent, vous, cette ville et ses habitants; car l''Éternel m''a véritablement envoyé vers vous pour prononcer à vos oreilles toutes ces paroles.'),
  (24, 26, 16, 'Les chefs et tout le peuple dirent aux sacrificateurs et aux prophètes: Cet homme ne mérite point la mort; car c''est au nom de l''Éternel, notre Dieu, qu''il nous a parlé.'),
  (24, 26, 17, 'Et quelques-uns des anciens du pays se levèrent, et dirent à toute l''assemblée du peuple:'),
  (24, 26, 18, 'Michée, de Moréscheth, prophétisait du temps d''Ézéchias, roi de Juda, et il disait à tout le peuple de Juda: Ainsi parle l''Éternel des armées: Sion sera labourée comme un champ, Jérusalem deviendra un monceau de pierres, Et la montagne de la maison une haute forêt.'),
  (24, 26, 19, 'Ézéchias, roi de Juda, et tout Juda l''ont-ils fait mourir? Ézéchias ne craignit-il pas l''Éternel? N''implora-t-il pas l''Éternel? Alors l''Éternel se repentit du mal qu''il avait prononcé contre eux. Et nous, nous chargerions notre âme d''un si grand crime!'),
  (24, 26, 20, 'Il y eut aussi un homme qui prophétisait au nom de l''Éternel, Urie, fils de Schemaeja, de Kirjath-Jearim. Il prophétisa contre cette ville et contre ce pays entièrement les mêmes choses que Jérémie.'),
  (24, 26, 21, 'Le roi Jojakim, tous ses vaillants hommes, et tous ses chefs, entendirent ses paroles, et le roi chercha à le faire mourir. Urie, qui en fut informé, eut peur, prit la fuite, et alla en Égypte.'),
  (24, 26, 22, 'Le roi Jojakim envoya des gens en Égypte, Elnathan, fils d''Acbor, et des gens avec lui en Égypte.'),
  (24, 26, 23, 'Ils firent sortir d''Égypte Urie et l''amenèrent au roi Jojakim, qui le fit mourir par l''épée et jeta son cadavre sur les sépulcres des enfants du peuple.'),
  (24, 26, 24, 'Cependant la main d''Achikam, fils de Schaphan, fut avec Jérémie, et empêcha qu''il ne fût livré au peuple pour être mis à mort.'),
  (24, 27, 1, 'Au commencement du règne de Jojakim, fils de Josias, roi de Juda, cette parole fut adressée à Jérémie de la part de l''Éternel, en ces mots:'),
  (24, 27, 2, 'Ainsi m''a parlé l''Éternel: Fais-toi des liens et des jougs, et mets-les sur ton cou.'),
  (24, 27, 3, 'Envoie-les au roi d''Édom, au roi de Moab, au roi des enfants d''Ammon, au roi de Tyr et au roi de Sidon, par les envoyés qui sont venus à Jérusalem auprès de Sédécias, roi de Juda,'),
  (24, 27, 4, 'et à qui tu donneras mes ordres pour leurs maîtres, en disant: Ainsi parle l''Éternel des armées, le Dieu d''Israël: Voici ce que vous direz à vos maîtres:'),
  (24, 27, 5, 'C''est moi qui ai fait la terre, les hommes et les animaux qui sont sur la terre, par ma grande puissance et par mon bras étendu, et je donne la terre à qui cela me plaît.'),
  (24, 27, 6, 'Maintenant je livre tous ces pays entre les mains de Nebucadnetsar, roi de Babylone, mon serviteur; je lui donne aussi les animaux des champs, pour qu''ils lui soient assujettis.'),
  (24, 27, 7, 'Toutes les nations lui seront soumises, à lui, à son fils, et au fils de son fils, jusqu''à ce que le temps de son pays arrive, et que des nations puissantes et de grands rois l''asservissent.'),
  (24, 27, 8, 'Si une nation, si un royaume ne se soumet pas à lui, à Nebucadnetsar, roi de Babylone, et ne livre pas son cou au joug du roi de Babylone, je châtierai cette nation par l''épée, par la famine et par la peste, dit l''Éternel, jusqu''à ce que je l''aie anéantie par sa main.'),
  (24, 27, 9, 'Et vous, n''écoutez pas vos prophètes, vos devins, vos songeurs, vos astrologues, vos magiciens, qui vous disent: Vous ne serez point asservis au roi de Babylone!'),
  (24, 27, 10, 'Car c''est le mensonge qu''ils vous prophétisent, afin que vous soyez éloignés de votre pays, afin que je vous chasse et que vous périssiez.'),
  (24, 27, 11, 'Mais la nation qui pliera son cou sous le joug du roi de Babylone, et qui lui sera soumise, je la laisserai dans son pays, dit l''Éternel, pour qu''elle le cultive et qu''elle y demeure.'),
  (24, 27, 12, 'J''ai dit entièrement les mêmes choses à Sédécias, roi de Juda: Pliez votre cou sous le joug du roi de Babylone, soumettez-vous à lui et à son peuple, et vous vivrez.'),
  (24, 27, 13, 'Pourquoi mourriez-vous, toi et ton peuple, par l''épée, par la famine et par la peste, comme l''Éternel l''a prononcé sur la nation qui ne se soumettra pas au roi de Babylone?'),
  (24, 27, 14, 'N''écoutez pas les paroles des prophètes qui vous disent: Vous ne serez point asservis au roi de Babylone! Car c''est le mensonge qu''ils vous prophétisent.'),
  (24, 27, 15, 'Je ne les ai point envoyés, dit l''Éternel, et ils prophétisent le mensonge en mon nom, afin que je vous chasse et que vous périssiez, vous et les prophètes qui vous prophétisent.'),
  (24, 27, 16, 'J''ai dit aux sacrificateurs et à tout ce peuple: Ainsi parle l''Éternel: N''écoutez pas les paroles de vos prophètes qui vous prophétisent, disant: Voici, les ustensiles de la maison de l''Éternel seront bientôt rapportés de Babylone! Car c''est le mensonge qu''ils vous prophétisent.'),
  (24, 27, 17, 'Ne les écoutez pas, soumettez-vous au roi de Babylone, et vous vivrez. Pourquoi cette ville deviendrait-elle une ruine?'),
  (24, 27, 18, 'S''ils sont prophètes et si la parole de l''Éternel est avec eux, qu''ils intercèdent auprès de l''Éternel des armées pour que les ustensiles qui restent dans la maison de l''Éternel, dans la maison du roi de Juda, et dans Jérusalem, ne s''en aillent point à Babylone.'),
  (24, 27, 19, 'Car ainsi parle l''Éternel des armées au sujet des colonnes, de la mer, des bases, et des autres ustensiles qui sont restés dans cette ville,'),
  (24, 27, 20, 'qui n''ont pas été enlevés par Nebucadnetsar, roi de Babylone, lorsqu''il emmena captifs de Jérusalem à Babylone Jeconia, fils de Jojakim, roi de Juda, et tous les grands de Juda et de Jérusalem,'),
  (24, 27, 21, 'ainsi parle l''Éternel des armées, le Dieu d''Israël, au sujet des ustensiles qui restent dans la maison de l''Éternel, dans la maison du roi de Juda, et dans Jérusalem:'),
  (24, 27, 22, 'Ils seront emportés à Babylone, et ils y resteront jusqu''au jour où je les chercherai, dit l''Éternel, où je les ferai remonter et revenir dans ce lieu.'),
  (24, 28, 1, 'Dans la même année, au commencement du règne de Sédécias, roi de Juda, le cinquième mois de la quatrième année, Hanania, fils d''Azzur, prophète, de Gabaon, me dit dans la maison de l''Éternel, en présence des sacrificateurs et de tout le peuple:'),
  (24, 28, 2, 'Ainsi parle l''Éternel des armées, le Dieu d''Israël: Je brise le joug du roi de Babylone!'),
  (24, 28, 3, 'Encore deux années, et je fais revenir dans ce lieu tous les ustensiles de la maison de l''Éternel, que Nebucadnetsar, roi de Babylone, a enlevés de ce lieu, et qu''il a emportés à Babylone.'),
  (24, 28, 4, 'Et je ferai revenir dans ce lieu, dit l''Éternel, Jeconia, fils de Jojakim, roi de Juda, et tous les captifs de Juda, qui sont allés à Babylone; car je briserai le joug du roi de Babylone.'),
  (24, 28, 5, 'Jérémie, le prophète, répondit à Hanania, le prophète, en présence des sacrificateurs et de tout le peuple qui se tenaient dans la maison de l''Éternel.'),
  (24, 28, 6, 'Jérémie, le prophète, dit: Amen! que l''Éternel fasse ainsi! que l''Éternel accomplisse les paroles que tu as prophétisées, et qu''il fasse revenir de Babylone en ce lieu les ustensiles de la maison de l''Éternel et tous les captifs!'),
  (24, 28, 7, 'Seulement écoute cette parole que je prononce à tes oreilles et aux oreilles de tout le peuple:'),
  (24, 28, 8, 'Les prophètes qui ont paru avant moi et avant toi, dès les temps anciens, ont prophétisé contre des pays puissants et de grands royaumes la guerre, le malheur et la peste;'),
  (24, 28, 9, 'mais si un prophète prophétise la paix, c''est par l''accomplissement de ce qu''il prophétise qu''il sera reconnu comme véritablement envoyé par l''Éternel.'),
  (24, 28, 10, 'Alors Hanania, le prophète, enleva le joug de dessus le cou de Jérémie, le prophète, et il le brisa.'),
  (24, 28, 11, 'Et Hanania dit en présence de tout le peuple: Ainsi parle l''Éternel: C''est ainsi que, dans deux années, je briserai de dessus le cou de toutes les nations le joug de Nebucadnetsar, roi de Babylone. Et Jérémie, le prophète, s''en alla.'),
  (24, 28, 12, 'Après que Hanania, le prophète, eut brisé le joug de dessus le cou de Jérémie, le prophète, la parole de l''Éternel fut adressée à Jérémie, en ces mots:'),
  (24, 28, 13, 'Va, et dis à Hanania: Ainsi parle l''Éternel: Tu as brisé un joug de bois, et tu auras à sa place un joug de fer.'),
  (24, 28, 14, 'Car ainsi parle l''Éternel des armées, le Dieu d''Israël: Je mets un joug de fer sur le cou de toutes ces nations, pour qu''elles soient asservies à Nebucadnetsar, roi de Babylone, et elles lui seront asservies; je lui donne aussi les animaux des champs.'),
  (24, 28, 15, 'Et Jérémie, le prophète, dit à Hanania, le prophète: Écoute, Hanania! L''Éternel ne t''a point envoyé, et tu inspires à ce peuple une fausse confiance.'),
  (24, 28, 16, 'C''est pourquoi ainsi parle l''Éternel: Voici, je te chasse de la terre; tu mourras cette année; car tes paroles sont une révolte contre l''Éternel.'),
  (24, 28, 17, 'Et Hanania, le prophète, mourut cette année-là, dans le septième mois.'),
  (24, 29, 1, 'Voici le contenu de la lettre que Jérémie, le prophète, envoya de Jérusalem au reste des anciens en captivité, aux sacrificateurs, aux prophètes, et à tout le peuple, que Nebucadnetsar avait emmenés captifs de Jérusalem à Babylone,'),
  (24, 29, 2, 'après que le roi Jeconia, la reine, les eunuques, les chefs de Juda et de Jérusalem, les charpentiers et les serruriers, furent sortis de Jérusalem.'),
  (24, 29, 3, 'Il la remit à Éleasa, fils de Schaphan, et à Guemaria, fils de Hilkija, envoyés à Babylone par Sédécias, roi de Juda, auprès de Nebucadnetsar, roi de Babylone. Elle était ainsi conçue:'),
  (24, 29, 4, 'Ainsi parle l''Éternel des armées, le Dieu d''Israël, à tous les captifs que j''ai emmenés de Jérusalem à Babylone:'),
  (24, 29, 5, 'Bâtissez des maisons, et habitez-les; plantez des jardins, et mangez-en les fruits.'),
  (24, 29, 6, 'Prenez des femmes, et engendrez des fils et des filles; prenez des femmes pour vos fils, et donnez des maris à vos filles, afin qu''elles enfantent des fils et des filles; multipliez là où vous êtes, et ne diminuez pas.'),
  (24, 29, 7, 'Recherchez le bien de la ville où je vous ai menés en captivité, et priez l''Éternel en sa faveur, parce que votre bonheur dépend du sien.'),
  (24, 29, 8, 'Car ainsi parle l''Éternel des armées, le Dieu d''Israël: Ne vous laissez pas tromper par vos prophètes qui sont au milieu de vous, et par vos devins, n''écoutez pas vos songeurs dont vous provoquez les songes!'),
  (24, 29, 9, 'Car c''est le mensonge qu''ils vous prophétisent en mon nom. Je ne les ai point envoyés, dit l''Éternel.'),
  (24, 29, 10, 'Mais voici ce que dit l''Éternel: Dès que soixante-dix ans seront écoulés pour Babylone, je me souviendrai de vous, et j''accomplirai à votre égard ma bonne parole, en vous ramenant dans ce lieu.'),
  (24, 29, 11, 'Car je connais les projets que j''ai formés sur vous, dit l''Éternel, projets de paix et non de malheur, afin de vous donner un avenir et de l''espérance.'),
  (24, 29, 12, 'Vous m''invoquerez, et vous partirez; vous me prierez, et je vous exaucerai.'),
  (24, 29, 13, 'Vous me chercherez, et vous me trouverez, si vous me cherchez de tout votre cœur.'),
  (24, 29, 14, 'Je me laisserai trouver par vous, dit l''Éternel, et je ramènerai vos captifs; je vous rassemblerai de toutes les nations et de tous les lieux où je vous ai chassés, dit l''Éternel, et je vous ramènerai dans le lieu d''où je vous ai fait aller en captivité.'),
  (24, 29, 15, 'Cependant vous dites: Dieu nous a suscité des prophètes à Babylone!'),
  (24, 29, 16, 'Ainsi parle l''Éternel sur le roi qui occupe le trône de David, sur tout le peuple qui habite cette ville, sur vos frères qui ne sont point allés avec vous en captivité;'),
  (24, 29, 17, 'ainsi parle l''Éternel des armées: Voici, j''enverrai parmi eux l''épée, la famine et la peste, et je les rendrai semblables à des figues affreuses qui ne peuvent être mangées à cause de leur mauvaise qualité.'),
  (24, 29, 18, 'Je les poursuivrai par l''épée, par la famine et par la peste, je les rendrai un objet d''effroi pour tous les royaumes de la terre, un sujet de malédiction, de désolation, de moquerie et d''opprobre, parmi toutes les nations où je les chasserai,'),
  (24, 29, 19, 'parce qu''ils n''ont pas écouté mes paroles, dit l''Éternel, eux à qui j''ai envoyé mes serviteurs, les prophètes, à qui je les ai envoyés dès le matin; et ils n''ont pas écouté, dit l''Éternel.'),
  (24, 29, 20, 'Mais vous, écoutez la parole de l''Éternel, vous tous, captifs, que j''ai envoyés de Jérusalem à Babylone!'),
  (24, 29, 21, 'Ainsi parle l''Éternel des armées, le Dieu d''Israël, sur Achab, fils de Kolaja, et sur Sédécias, fils de Maaséja, qui vous prophétisent le mensonge en mon nom: Voici, je les livre entre les mains de Nebucadnetsar, roi de Babylone; et il les fera mourir sous vos yeux.'),
  (24, 29, 22, 'On se servira d''eux comme d''un sujet de malédiction, parmi tous les captifs de Juda qui sont à Babylone; on dira: Que l''Éternel te traite comme Sédécias et comme Achab, que le roi de Babylone a fait rôtir au feu!'),
  (24, 29, 23, 'Et cela arrivera parce qu''ils ont commis une infamie en Israël, se livrant à l''adultère avec les femmes de leur prochain, et parce qu''ils ont dit des mensonges en mon nom, quand je ne leur avais point donné d''ordre. Je le sais, et j''en suis témoin, dit l''Éternel.'),
  (24, 29, 24, 'Tu diras à Schemaeja, Néchélamite:'),
  (24, 29, 25, 'Ainsi parle l''Éternel des armées, le Dieu d''Israël: Tu as envoyé en ton nom à tout le peuple de Jérusalem, à Sophonie, fils de Maaséja, le sacrificateur, et à tous les sacrificateurs, une lettre ainsi conçue:'),
  (24, 29, 26, 'L''Éternel t''a établi sacrificateur à la place de Jehojada, le sacrificateur, afin qu''il y ait dans la maison de l''Éternel des inspecteurs pour surveiller tout homme qui est fou et se donne pour prophète, et afin que tu le mettes en prison et dans les fers.'),
  (24, 29, 27, 'Maintenant, pourquoi ne réprimes-tu pas Jérémie d''Anathoth, qui prophétise parmi vous,'),
  (24, 29, 28, 'qui nous a même envoyé dire à Babylone: Elle sera longue, la captivité; bâtissez des maisons, et habitez-les; plantez des jardins, et mangez-en les fruits! -'),
  (24, 29, 29, 'Sophonie, le sacrificateur, lut cette lettre en présence de Jérémie, le prophète. -'),
  (24, 29, 30, 'Et la parole de l''Éternel fut adressée à Jérémie, en ces mots:'),
  (24, 29, 31, 'Fais dire à tous les captifs: Ainsi parle l''Éternel sur Schemaeja, Néchélamite: Parce que Schemaeja vous prophétise, sans que je l''aie envoyé, et qu''il vous inspire une fausse confiance,'),
  (24, 29, 32, 'voici ce que dit l''Éternel: Je châtierai Schemaeja, Néchélamite, et sa postérité; nul des siens n''habitera au milieu de ce peuple, et il ne verra pas le bien que je ferai à mon peuple, dit l''Éternel; car ses paroles sont une révolte contre l''Éternel.'),
  (24, 30, 1, 'La parole qui fut adressée à Jérémie de la part de l''Éternel, en ces mots:'),
  (24, 30, 2, 'Ainsi parle l''Éternel, le Dieu d''Israël: Écris dans un livre toutes les paroles que je t''ai dites.'),
  (24, 30, 3, 'Voici, les jours viennent, dit l''Éternel, où je ramènerai les captifs de mon peuple d''Israël et de Juda, dit l''Éternel; je les ramènerai dans le pays que j''ai donné à leurs pères, et ils le posséderont.'),
  (24, 30, 4, 'Ce sont ici les paroles que l''Éternel a prononcées sur Israël et sur Juda.'),
  (24, 30, 5, 'Ainsi parle l''Éternel: Nous entendons des cris d''effroi; C''est l''épouvante, ce n''est pas la paix.'),
  (24, 30, 6, 'Informez-vous, et regardez si un mâle enfante! Pourquoi vois-je tous les hommes les mains sur leurs reins, Comme une femme en travail? Pourquoi tous les visages sont-ils devenus pâles?'),
  (24, 30, 7, 'Malheur! car ce jour est grand; Il n''y en a point eu de semblable. C''est un temps d''angoisse pour Jacob; Mais il en sera délivré.'),
  (24, 30, 8, 'En ce jour-là, dit l''Éternel des armées, Je briserai son joug de dessus ton cou, Je romprai tes liens, Et des étrangers ne t''assujettiront plus.'),
  (24, 30, 9, 'Ils serviront l''Éternel, leur Dieu, Et David, leur roi, que je leur susciterai.'),
  (24, 30, 10, 'Et toi, mon serviteur Jacob, ne crains pas, dit l''Éternel; Ne t''effraie pas, Israël! Car je te délivrerai de la terre lointaine, Je délivrerai ta postérité du pays où elle est captive; Jacob reviendra, il jouira du repos et de la tranquillité, Et il n''y aura personne pour le troubler.'),
  (24, 30, 11, 'Car je suis avec toi, dit l''Éternel, pour te délivrer; J''anéantirai toutes les nations parmi lesquelles je t''ai dispersé, Mais toi, je ne t''anéantirai pas; Je te châtierai avec équité, Je ne puis pas te laisser impuni.'),
  (24, 30, 12, 'Ainsi parle l''Éternel: Ta blessure est grave, Ta plaie est douloureuse.'),
  (24, 30, 13, 'Nul ne défend ta cause, pour bander ta plaie; Tu n''as ni remède, ni moyen de guérison.'),
  (24, 30, 14, 'Tous ceux qui t''aimaient t''oublient, Aucun ne prend souci de toi; Car je t''ai frappée comme frappe un ennemi, Je t''ai châtiée avec violence, A cause de la multitude de tes iniquités, Du grand nombre de tes péchés.'),
  (24, 30, 15, 'Pourquoi te plaindre de ta blessure, De la douleur que cause ton mal? C''est à cause de la multitude de tes iniquités, Du grand nombre de tes péchés, Que je t''ai fait souffrir ces choses.'),
  (24, 30, 16, 'Cependant, tous ceux qui te dévorent seront dévorés, Et tous tes ennemis, tous, iront en captivité; Ceux qui te dépouillent seront dépouillés, Et j''abandonnerai au pillage tous ceux qui te pillent.'),
  (24, 30, 17, 'Mais je te guérirai, je panserai tes plaies, Dit l''Éternel. Car ils t''appellent la repoussée, Cette Sion dont nul ne prend souci.'),
  (24, 30, 18, 'Ainsi parle l''Éternel: Voici, je ramène les captifs des tentes de Jacob, J''ai compassion de ses demeures; La ville sera rebâtie sur ses ruines, Le palais sera rétabli comme il était.'),
  (24, 30, 19, 'Du milieu d''eux s''élèveront des actions de grâces Et des cris de réjouissance; Je les multiplierai, et ils ne diminueront pas; Je les honorerai, et ils ne seront pas méprisés.'),
  (24, 30, 20, 'Ses fils seront comme autrefois, Son assemblée subsistera devant moi, Et je châtierai tous ses oppresseurs.'),
  (24, 30, 21, 'Son chef sera tiré de son sein, Son dominateur sortira du milieu de lui; Je le ferai approcher, et il viendra vers moi; Car qui oserait de lui-même s''approcher de moi? Dit l''Éternel.'),
  (24, 30, 22, 'Vous serez mon peuple, Et je serai votre Dieu.'),
  (24, 30, 23, 'Voici, la tempête de l''Éternel, la fureur éclate, L''orage se précipite, Il fond sur la tête des méchants.'),
  (24, 30, 24, 'La colère ardente de l''Éternel ne se calmera pas, Jusqu''à ce qu''il ait accompli, exécuté les desseins de son cœur. Vous le comprendrez dans la suite des temps.'),
  (24, 31, 1, 'En ce temps-là, dit l''Éternel, Je serai le Dieu de toutes les familles d''Israël, Et ils seront mon peuple.'),
  (24, 31, 2, 'Ainsi parle l''Éternel: Il a trouvé grâce dans le désert, Le peuple de ceux qui ont échappé au glaive; Israël marche vers son lieu de repos.'),
  (24, 31, 3, 'De loin l''Éternel se montre à moi: Je t''aime d''un amour éternel; C''est pourquoi je te conserve ma bonté.'),
  (24, 31, 4, 'Je te rétablirai encore, et tu seras rétablie, Vierge d''Israël! Tu auras encore tes tambourins pour parure, Et tu sortiras au milieu des danses joyeuses.'),
  (24, 31, 5, 'Tu planteras encore des vignes sur les montagnes de Samarie; Les planteurs planteront, et cueilleront les fruits.'),
  (24, 31, 6, 'Car le jour vient où les gardes crieront sur la montagne d''Éphraïm: Levez-vous, montons à Sion, vers l''Éternel, notre Dieu!'),
  (24, 31, 7, 'Car ainsi parle l''Éternel: Poussez des cris de joie sur Jacob, Éclatez d''allégresse à la tête des nations! Élevez vos voix, chantez des louanges, et dites: Éternel, délivre ton peuple, le reste d''Israël!'),
  (24, 31, 8, 'Voici, je les ramène du pays du septentrion, Je les rassemble des extrémités de la terre; Parmi eux sont l''aveugle et le boiteux, La femme enceinte et celle en travail; C''est une grande multitude, qui revient ici.'),
  (24, 31, 9, 'Ils viennent en pleurant, et je les conduis au milieu de leurs supplications; Je les mène vers des torrents d''eau, Par un chemin uni où ils ne chancellent pas; Car je suis un père pour Israël, Et Éphraïm est mon premier-né.'),
  (24, 31, 10, 'Nations, écoutez la parole de l''Éternel, Et publiez-la dans les îles lointaines! Dites: Celui qui a dispersé Israël le rassemblera, Et il le gardera comme le berger garde son troupeau.'),
  (24, 31, 11, 'Car l''Éternel rachète Jacob, Il le délivre de la main d''un plus fort que lui.'),
  (24, 31, 12, 'Ils viendront, et pousseront des cris de joie sur les hauteurs de Sion; Ils accourront vers les biens de l''Éternel, Le blé, le moût, l''huile, Les brebis et les bœufs; Leur âme sera comme un jardin arrosé, Et ils ne seront plus dans la souffrance.'),
  (24, 31, 13, 'Alors les jeunes filles se réjouiront à la danse, Les jeunes hommes et les vieillards se réjouiront aussi; Je changerai leur deuil en allégresse, et je les consolerai; Je leur donnerai de la joie après leurs chagrins.'),
  (24, 31, 14, 'Je rassasierai de graisse l''âme des sacrificateurs, Et mon peuple se rassasiera de mes biens, dit l''Éternel.'),
  (24, 31, 15, 'Ainsi parle l''Éternel: On entend des cris à Rama, Des lamentations, des larmes amères; Rachel pleure ses enfants; Elle refuse d''être consolée sur ses enfants, Car ils ne sont plus.'),
  (24, 31, 16, 'Ainsi parle l''Éternel: Retiens tes pleurs, Retiens les larmes de tes yeux; Car il y aura un salaire pour tes œuvres, dit l''Éternel; Ils reviendront du pays de l''ennemi.'),
  (24, 31, 17, 'Il y a de l''espérance pour ton avenir, dit l''Éternel; Tes enfants reviendront dans leur territoire.'),
  (24, 31, 18, 'J''entends Éphraïm qui se lamente: Tu m''as châtié, et j''ai été châtié Comme un veau qui n''est pas dompté; Fais-moi revenir, et je reviendrai, Car tu es l''Éternel, mon Dieu.'),
  (24, 31, 19, 'Après m''être détourné, j''éprouve du repentir; Et après avoir reconnu mes fautes, je frappe sur ma cuisse; Je suis honteux et confus, Car je porte l''opprobre de ma jeunesse. -'),
  (24, 31, 20, 'Éphraïm est-il donc pour moi un fils chéri, Un enfant qui fait mes délices? Car plus je parle de lui, plus encore son souvenir est en moi; Aussi mes entrailles sont émues en sa faveur: J''aurai pitié de lui, dit l''Éternel. -'),
  (24, 31, 21, 'Dresse des signes, place des poteaux, Prends garde à la route, au chemin que tu as suivi… Reviens, vierge d''Israël, Reviens dans ces villes qui sont à toi!'),
  (24, 31, 22, 'Jusques à quand seras-tu errante, Fille égarée? Car l''Éternel crée une chose nouvelle sur la terre: La femme recherchera l''homme.'),
  (24, 31, 23, 'Ainsi parle l''Éternel des armées, le Dieu d''Israël: Voici encore ce que l''on dira dans le pays de Juda et dans ses villes, Quand j''aurai ramené leurs captifs: Que l''Éternel te bénisse, demeure de la justice, Montagne sainte!'),
  (24, 31, 24, 'Là s''établiront Juda et toutes ses villes, Les laboureurs et ceux qui conduisent les troupeaux.'),
  (24, 31, 25, 'Car je rafraîchirai l''âme altérée, Et je rassasierai toute âme languissante.'),
  (24, 31, 26, 'Là-dessus je me suis réveillé, et j''ai regardé; Mon sommeil m''avait été agréable.'),
  (24, 31, 27, 'Voici, les jours viennent, dit l''Éternel, Où j''ensemencerai la maison d''Israël et la maison de Juda D''une semence d''hommes et d''une semence de bêtes.'),
  (24, 31, 28, 'Et comme j''ai veillé sur eux Pour arracher, abattre, détruire, ruiner et faire du mal, Ainsi je veillerai sur eux pour bâtir et pour planter, Dit l''Éternel.'),
  (24, 31, 29, 'En ces jours-là, on ne dira plus: Les pères ont mangé des raisins verts, Et les dents des enfants en ont été agacées.'),
  (24, 31, 30, 'Mais chacun mourra pour sa propre iniquité; Tout homme qui mangera des raisins verts, Ses dents en seront agacées.'),
  (24, 31, 31, 'Voici, les jours viennent, dit l''Éternel, Où je ferai avec la maison d''Israël et la maison de Juda Une alliance nouvelle,'),
  (24, 31, 32, 'Non comme l''alliance que je traitai avec leurs pères, Le jour où je les saisis par la main Pour les faire sortir du pays d''Égypte, Alliance qu''ils ont violée, Quoique je fusse leur maître, dit l''Éternel.'),
  (24, 31, 33, 'Mais voici l''alliance que je ferai avec la maison d''Israël, Après ces jours-là, dit l''Éternel: Je mettrai ma loi au dedans d''eux, Je l''écrirai dans leur cœur; Et je serai leur Dieu, Et ils seront mon peuple.'),
  (24, 31, 34, 'Celui-ci n''enseignera plus son prochain, Ni celui-là son frère, en disant: Connaissez l''Éternel! Car tous me connaîtront, Depuis le plus petit jusqu''au plus grand, dit l''Éternel; Car je pardonnerai leur iniquité, Et je ne me souviendrai plus de leur péché.'),
  (24, 31, 35, 'Ainsi parle l''Éternel, qui a fait le soleil pour éclairer le jour, Qui a destiné la lune et les étoiles à éclairer la nuit, Qui soulève la mer et fait mugir ses flots, Lui dont le nom est l''Éternel des armées:'),
  (24, 31, 36, 'Si ces lois viennent à cesser devant moi, dit l''Éternel, La race d''Israël aussi cessera pour toujours d''être une nation devant moi.'),
  (24, 31, 37, 'Ainsi parle l''Éternel: Si les cieux en haut peuvent être mesurés, Si les fondements de la terre en bas peuvent être sondés, Alors je rejetterai toute la race d''Israël, A cause de tout ce qu''ils ont fait, dit l''Éternel.'),
  (24, 31, 38, 'Voici, les jours viennent, dit l''Éternel, Où la ville sera rebâtie à l''honneur de l''Éternel, Depuis la tour de Hananeel jusqu''à la porte de l''angle.'),
  (24, 31, 39, 'Le cordeau s''étendra encore vis-à-vis, Jusqu''à la colline de Gareb, Et fera un circuit du côté de Goath.'),
  (24, 31, 40, 'Toute la vallée des cadavres et de la cendre, Et tous les champs jusqu''au torrent de Cédron, Jusqu''à l''angle de la porte des chevaux à l''orient, Seront consacrés à l''Éternel, Et ne seront plus à jamais ni renversés ni détruits.'),
  (24, 32, 1, 'La parole qui fut adressée à Jérémie de la part de l''Éternel, la dixième année de Sédécias, roi de Juda. -C''était la dix-huitième année de Nebucadnetsar.'),
  (24, 32, 2, 'L''armée du roi de Babylone assiégeait alors Jérusalem; et Jérémie, le prophète, était enfermé dans la cour de la prison qui était dans la maison du roi de Juda.'),
  (24, 32, 3, 'Sédécias, roi de Juda, l''avait fait enfermer, et lui avait dit: Pourquoi prophétises-tu, en disant: Ainsi parle l''Éternel: Voici, je livre cette ville entre les mains du roi de Babylone, et il la prendra;'),
  (24, 32, 4, 'Sédécias, roi de Juda, n''échappera pas aux Chaldéens, mais il sera livré entre les mains du roi de Babylone, il lui parlera bouche à bouche, et ses yeux verront ses yeux;'),
  (24, 32, 5, 'le roi de Babylone emmènera Sédécias à Babylone, où il restera jusqu''à ce que je me souvienne de lui, dit l''Éternel; si vous vous battez contre les Chaldéens, vous n''aurez point de succès.'),
  (24, 32, 6, 'Jérémie dit: La parole de l''Éternel m''a été adressée, en ces mots:'),
  (24, 32, 7, 'Voici, Hanameel, fils de ton oncle Schallum, va venir auprès de toi pour te dire: Achète mon champ qui est à Anathoth, car tu as le droit de rachat pour l''acquérir.'),
  (24, 32, 8, 'Et Hanameel, fils de mon oncle, vint auprès de moi, selon la parole de l''Éternel, dans la cour de la prison, et il me dit: Achète mon champ, qui est à Anathoth, dans le pays de Benjamin, car tu as le droit d''héritage et de rachat, achète-le! Je reconnus que c''était la parole de l''Éternel.'),
  (24, 32, 9, 'J''achetai de Hanameel, fils de mon oncle, le champ qui est à Anathoth, et je lui pesai l''argent, dix-sept sicles d''argent.'),
  (24, 32, 10, 'J''écrivis un contrat, que je cachetai, je pris des témoins, et je pesai l''argent dans une balance.'),
  (24, 32, 11, 'Je pris ensuite le contrat d''acquisition, celui qui était cacheté, conformément à la loi et aux usages, et celui qui était ouvert;'),
  (24, 32, 12, 'et je remis le contrat d''acquisition à Baruc, fils de Nérija, fils de Machséja, en présence de Hanameel, fils de mon oncle, en présence des témoins qui avaient signé le contrat d''acquisition, et en présence de tous les juifs qui se trouvaient dans la cour de la prison.'),
  (24, 32, 13, 'Et je donnai devant eux cet ordre à Baruc:'),
  (24, 32, 14, 'Ainsi parle l''Éternel des armées, le Dieu d''Israël: Prends ces écrits, ce contrat d''acquisition, celui qui est cacheté et celui qui est ouvert, et mets-les dans un vase de terre, afin qu''ils se conservent longtemps.'),
  (24, 32, 15, 'Car ainsi parle l''Éternel des armées, le Dieu d''Israël: On achètera encore des maisons, des champs et des vignes, dans ce pays.'),
  (24, 32, 16, 'Après que j''eus remis le contrat d''acquisition à Baruc, fils de Nérija, j''adressai cette prière à l''Éternel:'),
  (24, 32, 17, 'Ah! Seigneur Éternel, Voici, tu as fait les cieux et la terre Par ta grande puissance et par ton bras étendu: Rien n''est étonnant de ta part.'),
  (24, 32, 18, 'Tu fais miséricorde jusqu''à la millième génération, Et tu punis l''iniquité des pères dans le sein de leurs enfants après eux. Tu es le Dieu grand, le puissant, Dont le nom est l''Éternel des armées.'),
  (24, 32, 19, 'Tu es grand en conseil et puissant en action; Tu as les yeux ouverts sur toutes les voies des enfants des hommes, Pour rendre à chacun selon ses voies, Selon le fruit de ses œuvres.'),
  (24, 32, 20, 'Tu as fait des miracles et des prodiges dans le pays d''Égypte jusqu''à ce jour, Et en Israël et parmi les hommes, Et tu t''es fait un nom comme il l''est aujourd''hui.'),
  (24, 32, 21, 'Tu as fait sortir du pays d''Égypte ton peuple d''Israël, Avec des miracles et des prodiges, à main forte et à bras étendu, Et avec une grande terreur.'),
  (24, 32, 22, 'Tu leur as donné ce pays, Que tu avais juré à leurs pères de leur donner, Pays où coulent le lait et le miel.'),
  (24, 32, 23, 'Ils sont venus, et ils en ont pris possession. Mais ils n''ont point obéi à ta voix, Ils n''ont point observé ta loi, Ils n''ont pas fait tout ce que tu leur avais ordonné de faire. Et c''est alors que tu as fait fondre sur eux tous ces malheurs!'),
  (24, 32, 24, 'Voici, les terrasses s''élèvent contre la ville et la menacent; La ville sera livrée entre les mains des Chaldéens qui l''attaquent, Vaincue par l''épée, par la famine et par la peste. Ce que tu as dit est arrivé, et tu le vois.'),
  (24, 32, 25, 'Néanmoins, Seigneur Éternel, tu m''as dit: Achète un champ pour de l''argent, prends des témoins… Et la ville est livrée entre les mains des Chaldéens!'),
  (24, 32, 26, 'La parole de l''Éternel fut adressée à Jérémie, en ces mots:'),
  (24, 32, 27, 'Voici, je suis l''Éternel, le Dieu de toute chair. Y a-t-il rien qui soit étonnant de ma part?'),
  (24, 32, 28, 'C''est pourquoi ainsi parle l''Éternel: Voici, je livre cette ville entre les mains des Chaldéens, Et entre les mains de Nebucadnetsar, roi de Babylone, Et il la prendra.'),
  (24, 32, 29, 'Les Chaldéens qui attaquent cette ville vont entrer, Ils y mettront le feu, et ils la brûleront, Avec les maisons sur les toits desquelles on a offert de l''encens à Baal Et fait des libations à d''autres dieux, Afin de m''irriter.'),
  (24, 32, 30, 'Car les enfants d''Israël et les enfants de Juda N''ont fait, dès leur jeunesse, que ce qui est mal à mes yeux; Les enfants d''Israël n''ont fait que m''irriter Par l''œuvre de leurs mains, dit l''Éternel.'),
  (24, 32, 31, 'Car cette ville excite ma colère et ma fureur, Depuis le jour où on l''a bâtie jusqu''à ce jour; Aussi je veux l''ôter de devant ma face,'),
  (24, 32, 32, 'A cause de tout le mal que les enfants d''Israël et les enfants de Juda Ont fait pour m''irriter, Eux, leurs rois, leurs chefs, leurs sacrificateurs et leurs prophètes, Les hommes de Juda et les habitants de Jérusalem.'),
  (24, 32, 33, 'Ils m''ont tourné le dos, ils ne m''ont pas regardé; On les a enseignés, on les a enseignés dès le matin; Mais ils n''ont pas écouté pour recevoir instruction.'),
  (24, 32, 34, 'Ils ont placé leurs abominations Dans la maison sur laquelle mon nom est invoqué, Afin de la souiller.'),
  (24, 32, 35, 'Ils ont bâti des hauts lieux à Baal dans la vallée de Ben-Hinnom, Pour faire passer à Moloc leurs fils et leurs filles: Ce que je ne leur avais point ordonné; Et il ne m''était point venu à la pensée Qu''ils commettraient de telles horreurs Pour faire pécher Juda.'),
  (24, 32, 36, 'Et maintenant, ainsi parle l''Éternel, le Dieu d''Israël, Sur cette ville dont vous dites: Elle sera livrée entre les mains du roi de Babylone, Vaincue par l''épée, par la famine et par la peste:'),
  (24, 32, 37, 'Voici, je les rassemblerai de tous les pays où je les ai chassés, Dans ma colère, dans ma fureur, et dans ma grande irritation; Je les ramènerai dans ce lieu, Et je les y ferai habiter en sûreté.'),
  (24, 32, 38, 'Ils seront mon peuple, Et je serai leur Dieu.'),
  (24, 32, 39, 'Je leur donnerai un même cœur et une même voie, Afin qu''ils me craignent toujours, Pour leur bonheur et celui de leurs enfants après eux.'),
  (24, 32, 40, 'Je traiterai avec eux une alliance éternelle, Je ne me détournerai plus d''eux, Je leur ferai du bien, Et je mettrai ma crainte dans leur cœur, Afin qu''ils ne s''éloignent pas de moi.'),
  (24, 32, 41, 'Je prendrai plaisir à leur faire du bien, Et je les planterai véritablement dans ce pays, De tout mon cœur et de toute mon âme.'),
  (24, 32, 42, 'Car ainsi parle l''Éternel: De même que j''ai fait venir sur ce peuple tous ces grands malheurs, De même je ferai venir sur eux tout le bien que je leur promets.'),
  (24, 32, 43, 'On achètera des champs dans ce pays Dont vous dites: C''est un désert, sans hommes ni bêtes, Il est livré entre les mains des Chaldéens.'),
  (24, 32, 44, 'On achètera des champs pour de l''argent, On écrira des contrats, on les cachètera, on prendra des témoins, Dans le pays de Benjamin et aux environs de Jérusalem, Dans les villes de Juda, dans les villes de la montagne, Dans les villes de la plaine et dans les villes du midi; Car je ramènerai leurs captifs, dit l''Éternel.'),
  (24, 33, 1, 'La parole de l''Éternel fut adressée à Jérémie une seconde fois, en ces mots, pendant qu''il était encore enfermé dans la cour de la prison:'),
  (24, 33, 2, 'Ainsi parle l''Éternel, qui fait ces choses, L''Éternel, qui les conçoit et les exécute, Lui, dont le nom est l''Éternel:'),
  (24, 33, 3, 'Invoque-moi, et je te répondrai; Je t''annoncerai de grandes choses, des choses cachées, Que tu ne connais pas.'),
  (24, 33, 4, 'Car ainsi parle l''Éternel, le Dieu d''Israël, Sur les maisons de cette ville Et sur les maisons des rois de Juda, Qui seront abattues par les terrasses et par l''épée,'),
  (24, 33, 5, 'Quand on s''avancera pour combattre les Chaldéens, Et qu''elles seront remplies des cadavres des hommes Que je frapperai dans ma colère et dans ma fureur, Et à cause de la méchanceté desquels je cacherai ma face à cette ville;'),
  (24, 33, 6, 'Voici, je lui donnerai la guérison et la santé, je les guérirai, Et je leur ouvrirai une source abondante de paix et de fidélité.'),
  (24, 33, 7, 'Je ramènerai les captifs de Juda et les captifs d''Israël, Et je les rétablirai comme autrefois.'),
  (24, 33, 8, 'Je les purifierai de toutes les iniquités qu''ils ont commises contre moi, Je leur pardonnerai toutes les iniquités par lesquelles ils m''ont offensé, Par lesquelles ils se sont révoltés contre moi.'),
  (24, 33, 9, 'Cette ville sera pour moi un sujet de joie, de louange et de gloire, Parmi toutes les nations de la terre, Qui apprendront tout le bien que je leur ferai; Elles seront étonnées et émues de tout le bonheur Et de toute la prospérité que je leur accorderai.'),
  (24, 33, 10, 'Ainsi parle l''Éternel: On entendra encore dans ce lieu Dont vous dites: Il est désert, il n''y a plus d''hommes, plus de bêtes; On entendra dans les villes de Juda et dans les rues de Jérusalem, Dévastées, privées d''hommes, d''habitants, de bêtes,'),
  (24, 33, 11, 'Les cris de réjouissance et les cris d''allégresse, Les chants du fiancé et les chants de la fiancée, La voix de ceux qui disent: Louez l''Éternel des armées, Car l''Éternel est bon, car sa miséricorde dure à toujours! La voix de ceux qui offrent des sacrifices d''actions de grâces Dans la maison de l''Éternel. Car je ramènerai les captifs du pays, je les rétablirai comme autrefois, Dit l''Éternel.'),
  (24, 33, 12, 'Ainsi parle l''Éternel des armées: Il y aura encore dans ce lieu Qui est désert, sans hommes ni bêtes, Et dans toutes ses villes, Il y aura des demeures pour les bergers Faisant reposer leurs troupeaux.'),
  (24, 33, 13, 'Dans les villes de la montagne, dans les villes de la plaine, Dans les villes du midi, Dans le pays de Benjamin et aux environs de Jérusalem, Et dans les villes de Juda, Les brebis passeront encore sous la main de celui qui les compte, Dit l''Éternel.'),
  (24, 33, 14, 'Voici, les jours viennent, dit l''Éternel, Où j''accomplirai la bonne parole Que j''ai dite sur la maison d''Israël et sur la maison de Juda.'),
  (24, 33, 15, 'En ces jours et en ce temps-là, Je ferai éclore à David un germe de justice; Il pratiquera la justice et l''équité dans le pays.'),
  (24, 33, 16, 'En ces jours-là, Juda sera sauvé, Jérusalem aura la sécurité dans sa demeure; Et voici comment on l''appellera: L''Éternel notre justice.'),
  (24, 33, 17, 'Car ainsi parle l''Éternel: David ne manquera jamais d''un successeur Assis sur le trône de la maison d''Israël;'),
  (24, 33, 18, 'Les sacrificateurs, les Lévites, ne manqueront jamais devant moi de successeurs Pour offrir des holocaustes, brûler de l''encens avec les offrandes, Et faire des sacrifices tous les jours.'),
  (24, 33, 19, 'La parole de l''Éternel fut adressée à Jérémie, en ces mots:'),
  (24, 33, 20, 'Ainsi parle l''Éternel: Si vous pouvez rompre mon alliance avec le jour Et mon alliance avec la nuit, En sorte que le jour et la nuit ne soient plus en leur temps,'),
  (24, 33, 21, 'Alors aussi mon alliance sera rompue avec David, mon serviteur, En sorte qu''il n''aura point de fils régnant sur son trône, Et mon alliance avec les Lévites, les sacrificateurs, qui font mon service.'),
  (24, 33, 22, 'De même qu''on ne peut compter l''armée des cieux, Ni mesurer le sable de la mer, De même je multiplierai la postérité de David, mon serviteur, Et les Lévites qui font mon service.'),
  (24, 33, 23, 'La parole de l''Éternel fut adressée à Jérémie, en ces mots:'),
  (24, 33, 24, 'N''as-tu pas remarqué ce que disent ces gens: Les deux familles que l''Éternel avait choisies, il les a rejetées? Ainsi ils méprisent mon peuple, Au point de ne plus le regarder comme une nation.'),
  (24, 33, 25, 'Ainsi parle l''Éternel: Si je n''ai pas fait mon alliance avec le jour et avec la nuit, Si je n''ai pas établi les lois des cieux et de la terre,'),
  (24, 33, 26, 'Alors aussi je rejetterai la postérité de Jacob et de David, mon serviteur, Et je ne prendrai plus dans sa postérité ceux qui domineront Sur les descendants d''Abraham, d''Isaac et de Jacob. Car je ramènerai leurs captifs, et j''aurai pitié d''eux.'),
  (24, 34, 1, 'La parole qui fut adressée à Jérémie de la part de l''Éternel, en ces mots, lorsque Nebucadnetsar, roi de Babylone, avec toute son armée, et tous les royaumes des pays sous sa domination, et tous les peuples, faisaient la guerre à Jérusalem et à toutes les villes qui en dépendaient:'),
  (24, 34, 2, 'Ainsi parle l''Éternel, le Dieu d''Israël: Va, et dis à Sédécias, roi de Juda, dis-lui: Ainsi parle l''Éternel: Voici, je livre cette ville entre les mains du roi de Babylone, et il la brûlera par le feu.'),
  (24, 34, 3, 'Et toi, tu n''échapperas pas à ses mains, mais tu seras pris et livré entre ses mains, tes yeux verront les yeux du roi de Babylone, et il te parlera bouche à bouche, et tu iras à Babylone.'),
  (24, 34, 4, 'Seulement écoute la parole de l''Éternel, Sédécias, roi de Juda! Ainsi parle l''Éternel sur toi: Tu ne mourras point par l''épée.'),
  (24, 34, 5, 'Tu mourras en paix; et comme on a brûlé des parfums pour tes pères, les anciens rois qui t''ont précédé, ainsi on en brûlera pour toi, et l''on te pleurera, en disant: Hélas, seigneur! Car j''ai prononcé cette parole, dit l''Éternel.'),
  (24, 34, 6, 'Jérémie, le prophète, dit toutes ces paroles à Sédécias, roi de Juda, à Jérusalem.'),
  (24, 34, 7, 'Et l''armée du roi de Babylone combattait contre Jérusalem et contre toutes les autres villes de Juda, contre Lakis et Azéka, car c''étaient des villes fortes qui restaient parmi les villes de Juda.'),
  (24, 34, 8, 'La parole fut adressée à Jérémie de la part de l''Éternel, après que le roi Sédécias eut fait un pacte avec tout le peuple de Jérusalem, pour publier la liberté,'),
  (24, 34, 9, 'afin que chacun renvoyât libres son esclave et sa servante, l''Hébreu et la femme de l''Hébreu, et que personne ne tînt plus dans la servitude le Juif, son frère.'),
  (24, 34, 10, 'Tous les chefs et tout le peuple, qui étaient entrés dans le pacte, s''engagèrent à renvoyer libres chacun son esclave et sa servante, afin de ne plus les tenir dans la servitude; ils obéirent, et les renvoyèrent.'),
  (24, 34, 11, 'Mais ensuite ils changèrent d''avis; ils reprirent les esclaves et les servantes qu''ils avaient affranchis, et les forcèrent à redevenir esclaves et servantes.'),
  (24, 34, 12, 'Alors la parole de l''Éternel fut adressée à Jérémie de la part de l''Éternel, en ces mots:'),
  (24, 34, 13, 'Ainsi parle l''Éternel, le Dieu d''Israël: J''ai fait une alliance avec vos pères, le jour où je les ai fait sortir du pays d''Égypte, de la maison de servitude; et je leur ai dit:'),
  (24, 34, 14, 'Au bout de sept ans, chacun de vous renverra libre son frère hébreu qui se vend à lui; il te servira six années, puis tu le renverras libre de chez toi. Mais vos pères ne m''ont point écouté, ils n''ont point prêté l''oreille.'),
  (24, 34, 15, 'Vous, vous aviez fait aujourd''hui un retour sur vous-mêmes, vous aviez fait ce qui est droit à mes yeux, en publiant la liberté chacun pour son prochain, vous aviez fait un pacte devant moi, dans la maison sur laquelle mon nom est invoqué.'),
  (24, 34, 16, 'Mais vous êtes revenus en arrière, et vous avez profané mon nom; vous avez repris chacun les esclaves et les servantes que vous aviez affranchis, rendus à eux-mêmes, et vous les avez forcés à redevenir vos esclaves et vos servantes.'),
  (24, 34, 17, 'C''est pourquoi ainsi parle l''Éternel: Vous ne m''avez point obéi, en publiant la liberté chacun pour son frère, chacun pour son prochain. Voici, je publie contre vous, dit l''Éternel, la liberté de l''épée, de la peste et de la famine, et je vous rendrai un objet d''effroi pour tous les royaumes de la terre.'),
  (24, 34, 18, 'Je livrerai les hommes qui ont violé mon alliance, qui n''ont pas observé les conditions du pacte qu''ils avaient fait devant moi, en coupant un veau en deux et en passant entre ses morceaux;'),
  (24, 34, 19, 'je livrerai les chefs de Juda et les chefs de Jérusalem, les eunuques, les sacrificateurs, et tout le peuple du pays, qui ont passé entre les morceaux du veau;'),
  (24, 34, 20, 'je les livrerai entre les mains de leurs ennemis, entre les mains de ceux qui en veulent à leur vie, et leurs cadavres serviront de pâture aux oiseaux du ciel et aux bêtes de la terre.'),
  (24, 34, 21, 'Je livrerai Sédécias, roi de Juda, et ses chefs, entre les mains de leurs ennemis, entre les mains de ceux qui en veulent à leur vie, entre les mains de l''armée du roi de Babylone, qui s''est éloignée de vous.'),
  (24, 34, 22, 'Voici, je donnerai mes ordres, dit l''Éternel, et je les ramènerai contre cette ville; ils l''attaqueront, ils la prendront, et la brûleront par le feu. Et je ferai des villes de Juda un désert sans habitants.'),
  (24, 35, 1, 'La parole fut adressée à Jérémie de la part de l''Éternel, au temps de Jojakim, fils de Josias, roi de Juda, en ces mots:'),
  (24, 35, 2, 'Va à la maison des Récabites, et parle-leur; tu les conduiras à la maison de l''Éternel, dans une des chambres, et tu leur offriras du vin à boire.'),
  (24, 35, 3, 'Je pris Jaazania, fils de Jérémie, fils de Habazinia, ses frères, tous ses fils, et toute la maison des Récabites,'),
  (24, 35, 4, 'et je les conduisis à la maison de l''Éternel, dans la chambre des fils de Hanan, fils de Jigdalia, homme de Dieu, près de la chambre des chefs, au-dessus de la chambre de Maaséja, fils de Schallum, garde du seuil.'),
  (24, 35, 5, 'Je mis devant les fils de la maison des Récabites des coupes pleines de vin, et des calices, et je leur dis: Buvez du vin!'),
  (24, 35, 6, 'Mais ils répondirent: Nous ne buvons pas de vin; car Jonadab, fils de Récab, notre père, nous a donné cet ordre: Vous ne boirez jamais de vin, ni vous, ni vos fils;'),
  (24, 35, 7, 'et vous ne bâtirez point de maisons, vous ne sèmerez aucune semence, vous ne planterez point de vignes et vous n''en posséderez point; mais vous habiterez sous des tentes toute votre vie, afin que vous viviez longtemps dans le pays où vous êtes étrangers.'),
  (24, 35, 8, 'Nous obéissons à tout ce que nous a prescrit Jonadab, fils de Récab, notre père: nous ne buvons pas de vin pendant toute notre vie, nous, nos femmes, nos fils et nos filles;'),
  (24, 35, 9, 'nous ne bâtissons point de maisons pour nos demeures, et nous ne possédons ni vignes, ni champs, ni terres ensemencées;'),
  (24, 35, 10, 'nous habitons sous des tentes, et nous suivons et pratiquons tout ce que nous a prescrit Jonadab, notre père.'),
  (24, 35, 11, 'Lorsque Nebucadnetsar, roi de Babylone, est monté contre ce pays, nous avons dit: Allons, retirons-nous à Jérusalem, loin de l''armée des Chaldéens et de l''armée de Syrie. C''est ainsi que nous habitons à Jérusalem.'),
  (24, 35, 12, 'Alors la parole de l''Éternel fut adressée à Jérémie, en ces mots:'),
  (24, 35, 13, 'Ainsi parle l''Éternel des armées, le Dieu d''Israël: Va, et dis aux hommes de Juda et aux habitants de Jérusalem: Ne recevrez-vous pas instruction, pour obéir à mes paroles? dit l''Éternel.'),
  (24, 35, 14, 'On a observé les paroles de Jonadab, fils de Récab, qui a ordonné à ses fils de ne pas boire du vin, et ils n''en ont point bu jusqu''à ce jour, parce qu''ils ont obéi à l''ordre de leur père. Et moi, je vous ai parlé, je vous ai parlé dès le matin, et vous ne m''avez pas écouté.'),
  (24, 35, 15, 'Je vous ai envoyé tous mes serviteurs, les prophètes, je les ai envoyés dès le matin, pour vous dire: Revenez chacun de votre mauvaise voie, amendez vos actions, n''allez pas après d''autres dieux pour les servir, et vous resterez dans le pays que j''ai donné à vous et à vos pères. Mais vous n''avez pas prêté l''oreille, vous ne m''avez pas écouté.'),
  (24, 35, 16, 'Oui, les fils de Jonadab, fils de Récab, observent l''ordre que leur a donné leur père, et ce peuple ne m''écoute pas!'),
  (24, 35, 17, 'C''est pourquoi ainsi parle l''Éternel, le Dieu des armées, le Dieu d''Israël: Voici, je vais faire venir sur Juda et sur tous les habitants de Jérusalem tous les malheurs que j''ai annoncés sur eux, parce que je leur ai parlé et qu''ils n''ont pas écouté, parce que je les ai appelés et qu''ils n''ont pas répondu.'),
  (24, 35, 18, 'Et Jérémie dit à la maison des Récabites: Ainsi parle l''Éternel des armées, le Dieu d''Israël: Parce que vous avez obéi aux ordres de Jonadab, votre père, parce que vous avez observé tous ses commandements et fait tout ce qu''il vous a prescrit;'),
  (24, 35, 19, 'à cause de cela, ainsi parle l''Éternel des armées, le Dieu d''Israël: Jonadab, fils de Récab, ne manquera jamais de descendants qui se tiennent en ma présence.'),
  (24, 36, 1, 'La quatrième année de Jojakim, fils de Josias, roi de Juda, cette parole fut adressée à Jérémie de la part de l''Éternel, en ces mots:'),
  (24, 36, 2, 'Prends un livre, et tu y écriras toutes les paroles que je t''ai dites sur Israël et sur Juda, et sur toutes les nations, depuis le jour où je t''ai parlé, au temps de Josias, jusqu''à ce jour.'),
  (24, 36, 3, 'Quand la maison de Juda entendra tout le mal que je pense lui faire, peut-être reviendront-ils chacun de leur mauvaise voie; alors je pardonnerai leur iniquité et leur péché.'),
  (24, 36, 4, 'Jérémie appela Baruc, fils de Nérija; et Baruc écrivit dans un livre, sous la dictée de Jérémie, toutes les paroles que l''Éternel avait dites à Jérémie.'),
  (24, 36, 5, 'Puis Jérémie donna cet ordre à Baruc: Je suis retenu, et je ne peux pas aller à la maison de l''Éternel.'),
  (24, 36, 6, 'Tu iras toi-même, et tu liras dans le livre que tu as écrit sous ma dictée les paroles de l''Éternel, aux oreilles du peuple, dans la maison de l''Éternel, le jour du jeûne; tu les liras aussi aux oreilles de tous ceux de Juda qui seront venus de leurs villes.'),
  (24, 36, 7, 'Peut-être l''Éternel écoutera-t-il leurs supplications, et reviendront ils chacun de leur mauvaise voie; car grande est la colère, la fureur dont l''Éternel a menacé ce peuple.'),
  (24, 36, 8, 'Baruc, fils de Nérija, fit tout ce que lui avait ordonné Jérémie, le prophète, et lut dans le livre les paroles de l''Éternel, dans la maison de l''Éternel.'),
  (24, 36, 9, 'La cinquième année de Jojakim, fils de Josias, roi de Juda, le neuvième mois, on publia un jeûne devant l''Éternel pour tout le peuple de Jérusalem et pour tout le peuple venu des villes de Juda à Jérusalem.'),
  (24, 36, 10, 'Et Baruc lut dans le livre les paroles de Jérémie, aux oreilles de tout le peuple, dans la maison de l''Éternel, dans la chambre de Guemaria, fils de Schaphan, le secrétaire, dans le parvis supérieur, à l''entrée de la porte neuve de la maison de l''Éternel.'),
  (24, 36, 11, 'Michée, fils de Guemaria, fils de Schaphan, ayant entendu toutes les paroles de l''Éternel contenues dans le livre,'),
  (24, 36, 12, 'descendit à la maison du roi, dans la chambre du secrétaire, où étaient assis tous les chefs, Élischama, le secrétaire, Delaja, fils de Schemaeja, Elnathan, fils d''Acbor, Guemaria, fils de Schaphan, Sédécias, fils de Hanania, et tous les autres chefs.'),
  (24, 36, 13, 'Et Michée leur rapporta toutes les paroles qu''il avait entendues, lorsque Baruc lisait dans le livre, aux oreilles du peuple.'),
  (24, 36, 14, 'Alors tous les chefs envoyèrent vers Baruc Jehudi, fils de Nethania, fils de Schélémia, fils de Cuschi, pour lui dire: Prends en main le livre dans lequel tu as lu, aux oreilles du peuple, et viens! Baruc, fils de Nérija, prit en main le livre, et se rendit auprès d''eux.'),
  (24, 36, 15, 'Ils lui dirent: Assieds-toi, et lis-le à nos oreilles. Et Baruc lut à leurs oreilles.'),
  (24, 36, 16, 'Lorsqu''ils eurent entendu toutes les paroles, ils se regardèrent avec effroi les uns les autres, et ils dirent à Baruc: Nous rapporterons au roi toutes ces paroles.'),
  (24, 36, 17, 'Ils posèrent encore à Baruc cette question: Dis-nous comment tu as écrit toutes ces paroles sous sa dictée.'),
  (24, 36, 18, 'Baruc leur répondit: Il m''a dicté de sa bouche toutes ces paroles, et je les ai écrites dans ce livre avec de l''encre.'),
  (24, 36, 19, 'Les chefs dirent à Baruc: Va, cache-toi, ainsi que Jérémie, et que personne ne sache où vous êtes.'),
  (24, 36, 20, 'Ils allèrent ensuite vers le roi dans la cour, laissant le livre dans la chambre d''Élischama, le secrétaire, et ils en rapportèrent toutes les paroles aux oreilles du roi.'),
  (24, 36, 21, 'Le roi envoya Jehudi pour prendre le livre, Jehudi le prit dans la chambre d''Élischama, le secrétaire, et il le lut aux oreilles du roi et aux oreilles de tous les chefs qui étaient auprès du roi.'),
  (24, 36, 22, 'Le roi était assis dans la maison d''hiver, -c''était au neuvième mois, -et un brasier était allumé devant lui.'),
  (24, 36, 23, 'Lorsque Jehudi eut lu trois ou quatre feuilles, le roi coupa le livre avec le canif du secrétaire, et le jeta dans le feu du brasier, où il fut entièrement consumé.'),
  (24, 36, 24, 'Le roi et tous ses serviteurs, qui entendirent toutes ces paroles, ne furent point effrayés et ne déchirèrent point leurs vêtements.'),
  (24, 36, 25, 'Elnathan, Delaja et Guemaria, avaient fait des instances auprès du roi pour qu''il ne brûlât pas le livre; mais il ne les écouta pas.'),
  (24, 36, 26, 'Le roi ordonna à Jerachmeel, fils du roi, à Seraja, fils d''Azriel, et à Schélémia, fils d''Abdeel, de saisir Baruc, le secrétaire, et Jérémie, le prophète. Mais l''Éternel les cacha.'),
  (24, 36, 27, 'La parole de l''Éternel fut adressée à Jérémie, en ces mots, après que le roi eut brûlé le livre contenant les paroles que Baruc avait écrites sous la dictée de Jérémie:'),
  (24, 36, 28, 'Prends de nouveau un autre livre, et tu y écriras toutes les paroles qui étaient dans le premier livre qu''a brûlé Jojakim, roi de Juda.'),
  (24, 36, 29, 'Et sur Jojakim, roi de Juda, tu diras: Ainsi parle l''Éternel: Tu as brûlé ce livre, en disant: Pourquoi y as-tu écrit ces paroles: Le roi de Babylone viendra, il détruira ce pays, et il en fera disparaître les hommes et les bêtes?'),
  (24, 36, 30, 'C''est pourquoi ainsi parle l''Éternel sur Jojakim, roi de Juda: Aucun des siens ne sera assis sur le trône de David, et son cadavre sera exposé à la chaleur pendant le jour et au froid pendant la nuit.'),
  (24, 36, 31, 'Je le châtierai, lui, sa postérité, et ses serviteurs, à cause de leur iniquité, et je ferai venir sur eux, sur les habitants de Jérusalem et sur les hommes de Juda tous les malheurs dont je les ai menacés, sans qu''ils aient voulu m''écouter.'),
  (24, 36, 32, 'Jérémie prit un autre livre, et le donna à Baruc, fils de Nérija, le secrétaire. Baruc y écrivit, sous la dictée de Jérémie, toutes les paroles du livre qu''avait brûlé au feu Jojakim, roi de Juda. Beaucoup d''autres paroles semblables y furent encore ajoutées.'),
  (24, 37, 1, 'Sédécias, fils de Josias, régna à la place de Jeconia, fils de Jojakim, et fut établi roi dans le pays de Juda par Nebucadnetsar, roi de Babylone.'),
  (24, 37, 2, 'Ni lui, ni ses serviteurs, ni le peuple du pays, n''écoutèrent les paroles que l''Éternel prononça par Jérémie, le prophète.'),
  (24, 37, 3, 'Le roi Sédécias envoya Jucal, fils de Schélémia, et Sophonie, fils de Maaséja, le sacrificateur, vers Jérémie, le prophète, pour lui dire: Intercède en notre faveur auprès de l''Éternel, notre Dieu.'),
  (24, 37, 4, 'Or Jérémie allait et venait parmi le peuple; on ne l''avait pas encore mis en prison.'),
  (24, 37, 5, 'L''armée de Pharaon était sortie d''Égypte; et les Chaldéens, qui assiégeaient Jérusalem, ayant appris cette nouvelle, s''étaient retirés de Jérusalem.'),
  (24, 37, 6, 'Alors la parole de l''Éternel fut adressée à Jérémie, le prophète, en ces mots:'),
  (24, 37, 7, 'Ainsi parle l''Éternel, le Dieu d''Israël: Vous direz au roi de Juda, qui vous a envoyés vers moi pour me consulter: Voici, l''armée de Pharaon, qui était en marche pour vous secourir, retourne dans son pays, en Égypte;'),
  (24, 37, 8, 'et les Chaldéens reviendront, ils attaqueront cette ville, ils la prendront, et la brûleront par le feu.'),
  (24, 37, 9, 'Ainsi parle l''Éternel: Ne vous faites pas d''illusion, en disant: Les Chaldéens s''en iront loin de nous! Car ils ne s''en iront pas.'),
  (24, 37, 10, 'Et même quand vous battriez toute l''armée des Chaldéens qui vous font la guerre, quand il ne resterait d''eux que des hommes blessés, ils se relèveraient chacun dans sa tente, et brûleraient cette ville par le feu.'),
  (24, 37, 11, 'Pendant que l''armée des Chaldéens s''était éloignée de Jérusalem, à cause de l''armée de Pharaon,'),
  (24, 37, 12, 'Jérémie voulut sortir de Jérusalem, pour aller dans le pays de Benjamin et s''échapper du milieu du peuple.'),
  (24, 37, 13, 'Lorsqu''il fut à la porte de Benjamin, le commandant de la garde, nommé Jireija, fils de Schélémia, fils de Hanania, se trouvait là, et il saisit Jérémie, le prophète, en disant: Tu passes aux Chaldéens!'),
  (24, 37, 14, 'Jérémie répondit: C''est faux! je ne passe pas aux Chaldéens. Mais Jireija ne l''écouta point; il arrêta Jérémie, et le conduisit devant les chefs.'),
  (24, 37, 15, 'Les chefs, irrités contre Jérémie, le frappèrent, et le mirent en prison dans la maison de Jonathan, le secrétaire; car ils en avaient fait une prison.'),
  (24, 37, 16, 'Ce fut ainsi que Jérémie entra dans la prison et dans les cachots, où il resta longtemps.'),
  (24, 37, 17, 'Le roi Sédécias l''envoya chercher, et l''interrogea secrètement dans sa maison. Il dit: Y a-t-il une parole de la part de l''Éternel? Jérémie répondit: Oui. Et il ajouta: Tu seras livré entre les mains du roi de Babylone.'),
  (24, 37, 18, 'Jérémie dit encore au roi Sédécias: En quoi ai-je péché contre toi, contre tes serviteurs, et contre ce peuple, pour que vous m''ayez mis en prison?'),
  (24, 37, 19, 'Et où sont vos prophètes qui vous prophétisaient, en disant: Le roi de Babylone ne viendra pas contre vous, ni contre ce pays?'),
  (24, 37, 20, 'Maintenant, écoute, je te prie, ô roi, mon seigneur, et que mes supplications soient favorablement reçues devant toi! Ne me renvoie pas dans la maison de Jonathan, le secrétaire, de peur que je n''y meure!'),
  (24, 37, 21, 'Le roi Sédécias ordonna qu''on gardât Jérémie dans la cour de la prison, et qu''on lui donnât chaque jour un pain de la rue des boulangers, jusqu''à ce que tout le pain de la ville fût consommé. Ainsi Jérémie demeura dans la cour de la prison.'),
  (24, 38, 1, 'Schephathia, fils de Matthan, Guedalia, fils de Paschhur, Jucal, fils de Schélémia, et Paschhur, fils de Malkija, entendirent les paroles que Jérémie adressait à tout le peuple, en disant:'),
  (24, 38, 2, 'Ainsi parle l''Éternel: Celui qui restera dans cette ville mourra par l''épée, par la famine ou par la peste; mais celui qui sortira pour se rendre aux Chaldéens, aura la vie sauve, sa vie sera son butin, et il vivra.'),
  (24, 38, 3, 'Ainsi parle l''Éternel: Cette ville sera livrée à l''armée du roi de Babylone, qui la prendra.'),
  (24, 38, 4, 'Et les chefs dirent au roi: Que cet homme soit mis à mort! car il décourage les hommes de guerre qui restent dans cette ville, et tout le peuple, en leur tenant de pareils discours; cet homme ne cherche pas le bien de ce peuple, il ne veut que son malheur.'),
  (24, 38, 5, 'Le roi Sédécias répondit: Voici, il est entre vos mains; car le roi ne peut rien contre vous.'),
  (24, 38, 6, 'Alors ils prirent Jérémie, et le jetèrent dans la citerne de Malkija, fils du roi, laquelle se trouvait dans la cour de la prison; ils descendirent Jérémie avec des cordes. Il n''y avait point d''eau dans la citerne, mais il y avait de la boue; et Jérémie enfonça dans la boue.'),
  (24, 38, 7, 'Ébed-Mélec, l''Éthiopien, eunuque qui était dans la maison du roi, apprit qu''on avait mis Jérémie dans la citerne. Le roi était assis à la porte de Benjamin.'),
  (24, 38, 8, 'Ébed-Mélec sortit de la maison du roi, et parla ainsi au roi:'),
  (24, 38, 9, 'O roi, mon seigneur, ces hommes ont mal agi en traitant de la sorte Jérémie, le prophète, en le jetant dans la citerne; il mourra de faim là où il est, car il n''y a plus de pain dans la ville.'),
  (24, 38, 10, 'Le roi donna cet ordre à Ébed-Mélec, l''Éthiopien: Prends ici trente hommes avec toi, et tu retireras de la citerne Jérémie, le prophète, avant qu''il ne meure.'),
  (24, 38, 11, 'Ébed-Mélec prit avec lui les hommes, et se rendit à la maison du roi, dans un lieu au-dessous du trésor; il en sortit des lambeaux usés et de vieux haillons, et les descendit à Jérémie dans la citerne, avec des cordes.'),
  (24, 38, 12, 'Ébed-Mélec, l''Éthiopien, dit à Jérémie: Mets ces lambeaux usés et ces haillons sous tes aisselles, sous les cordes. Et Jérémie fit ainsi.'),
  (24, 38, 13, 'Ils tirèrent Jérémie avec les cordes, et le firent monter hors de la citerne. Jérémie resta dans la cour de la prison.'),
  (24, 38, 14, 'Le roi Sédécias envoya chercher Jérémie, le prophète, et le fit venir auprès de lui dans la troisième entrée de la maison de l''Éternel. Et le roi dit à Jérémie: J''ai une chose à te demander; ne me cache rien.'),
  (24, 38, 15, 'Jérémie répondit à Sédécias: Si je te la dis, ne me feras-tu pas mourir? Et si je te donne un conseil, tu ne m''écouteras pas.'),
  (24, 38, 16, 'Le roi Sédécias jura secrètement à Jérémie, en disant: L''Éternel est vivant, lui qui nous a donné la vie! je ne te ferai pas mourir, et je ne te livrerai pas entre les mains de ces hommes qui en veulent à ta vie.'),
  (24, 38, 17, 'Jérémie dit alors à Sédécias: Ainsi parle l''Éternel, le Dieu des armées, le Dieu d''Israël: Si tu vas te rendre aux chefs du roi de Babylone, tu auras la vie sauve, et cette ville ne sera pas brûlée par le feu; tu vivras, toi et ta maison.'),
  (24, 38, 18, 'Mais si tu ne te rends pas aux chefs du roi de Babylone, cette ville sera livrée entre les mains des Chaldéens, qui la brûleront par le feu; et toi, tu n''échapperas pas à leurs mains.'),
  (24, 38, 19, 'Le roi Sédécias dit à Jérémie: Je crains les Juifs qui ont passé aux Chaldéens; je crains qu''on ne me livre entre leurs mains, et qu''ils ne m''outragent.'),
  (24, 38, 20, 'Jérémie répondit: On ne te livrera pas. Écoute la voix de l''Éternel dans ce que je te dis; tu t''en trouveras bien, et tu auras la vie sauve.'),
  (24, 38, 21, 'Mais si tu refuses de sortir, voici ce que l''Éternel m''a révélé:'),
  (24, 38, 22, 'Toutes les femmes qui restent dans la maison du roi de Juda seront menées aux chefs du roi de Babylone, et elles diront: Tu as été trompé, dominé, par ceux qui t''annonçaient la paix; et quand tes pieds sont enfoncés dans la boue, ils se retirent.'),
  (24, 38, 23, 'Toutes tes femmes et tes enfants seront menés aux Chaldéens; et toi, tu n''échapperas pas à leurs mains, tu seras saisi par la main du roi de Babylone, et cette ville sera brûlée par le feu.'),
  (24, 38, 24, 'Sédécias dit à Jérémie: Que personne ne sache rien de ces discours, et tu ne mourras pas.'),
  (24, 38, 25, 'Si les chefs apprennent que je t''ai parlé, et s''ils viennent te dire: Rapporte-nous ce que tu as dit au roi, et ce que le roi t''a dit, ne nous cache rien, et nous ne te ferons pas mourir, -'),
  (24, 38, 26, 'tu leur répondras: J''ai supplié le roi de ne pas me renvoyer dans la maison de Jonathan, de peur que je n''y meure.'),
  (24, 38, 27, 'Tous les chefs vinrent auprès de Jérémie et le questionnèrent. Il leur répondit entièrement comme le roi l''avait ordonné. Ils gardèrent alors le silence et se retirèrent, car la chose ne s''était pas répandue.'),
  (24, 38, 28, 'Jérémie resta dans la cour de la prison jusqu''au jour de la prise de Jérusalem.'),
  (24, 39, 1, 'Lorsque Jérusalem fut prise, -la neuvième année de Sédécias, roi de Juda, le dixième mois, Nebucadnetsar, roi de Babylone, vint avec toute son armée devant Jérusalem, et en fit le siège;'),
  (24, 39, 2, 'la onzième année de Sédécias, le neuvième jour du quatrième mois, la brèche fut faite à la ville, -'),
  (24, 39, 3, 'tous les chefs du roi de Babylone s''avancèrent, et occupèrent la porte du milieu: Nergal-Scharetser, Samgar-Nebu, Sarsekim, chef des eunuques, Nergal-Scharetser, chef des mages, et tous les autres chefs du roi de Babylone.'),
  (24, 39, 4, 'Dès que Sédécias, roi de Juda, et tous les gens de guerre les eurent vus, ils s''enfuirent, et sortirent de la ville pendant la nuit par le chemin du jardin du roi, par la porte entre les deux murs, et ils prirent le chemin de la plaine.'),
  (24, 39, 5, 'Mais l''armée des Chaldéens les poursuivit, et atteignit Sédécias dans les plaines de Jéricho. Ils le prirent, et le firent monter vers Nebucadnetsar, roi de Babylone, à Ribla, dans le pays de Hamath; et il prononça contre lui une sentence.'),
  (24, 39, 6, 'Le roi de Babylone fit égorger à Ribla les fils de Sédécias en sa présence; le roi de Babylone fit aussi égorger tous les grands de Juda.'),
  (24, 39, 7, 'Puis il fit crever les yeux à Sédécias, et le fit lier avec des chaînes d''airain, pour l''emmener à Babylone.'),
  (24, 39, 8, 'Les Chaldéens brûlèrent par le feu la maison du roi et les maisons du peuple, et ils démolirent les murailles de Jérusalem.'),
  (24, 39, 9, 'Nebuzaradan, chef des gardes, emmena captifs à Babylone ceux du peuple qui étaient demeurés dans la ville, ceux qui s''étaient rendus à lui, et le reste du peuple.'),
  (24, 39, 10, 'Mais Nebuzaradan, chef des gardes, laissa dans le pays de Juda quelques-uns des plus pauvres du peuple, ceux qui n''avaient rien; et il leur donna alors des vignes et des champs.'),
  (24, 39, 11, 'Nebucadnetsar, roi de Babylone, avait donné cet ordre au sujet de Jérémie par Nebuzaradan, chef des gardes:'),
  (24, 39, 12, 'Prends-le, et veille sur lui; ne lui fais aucun mal, mais agis à son égard comme il te dira.'),
  (24, 39, 13, 'Nebuzaradan, chef des gardes, Nebuschazban, chef des eunuques, Nergal-Scharetser, chef des mages, et tous les chefs du roi de Babylone,'),
  (24, 39, 14, 'envoyèrent chercher Jérémie dans la cour de la prison, et ils le remirent à Guedalia, fils d''Achikam, fils de Schaphan, pour qu''il fût conduit dans sa maison. Et il resta au milieu du peuple.'),
  (24, 39, 15, 'La parole de l''Éternel fut adressée à Jérémie en ces mots, pendant qu''il était enfermé dans la cour de la prison:'),
  (24, 39, 16, 'Va, parle à Ébed-Mélec, l''Éthiopien, et dis-lui: Ainsi parle l''Éternel des armées, le Dieu d''Israël: Voici, je vais faire venir sur cette ville les choses que j''ai annoncées pour le mal et non pour le bien; elles arriveront en ce jour devant toi.'),
  (24, 39, 17, 'Mais en ce jour je te délivrerai, dit l''Éternel, et tu ne seras pas livré entre les mains des hommes que tu crains.'),
  (24, 39, 18, 'Je te sauverai, et tu ne tomberas pas sous l''épée; ta vie sera ton butin, parce que tu as eu confiance en moi, dit l''Éternel.'),
  (24, 40, 1, 'La parole qui fut adressée à Jérémie de la part de l''Éternel, après que Nebuzaradan, chef des gardes, l''eut renvoyé de Rama. Quand il le fit chercher, Jérémie était lié de chaînes parmi tous les captifs de Jérusalem et de Juda qu''on emmenait à Babylone.'),
  (24, 40, 2, 'Le chef des gardes envoya chercher Jérémie, et lui dit: L''Éternel, ton Dieu, a annoncé ces malheurs contre ce lieu;'),
  (24, 40, 3, 'l''Éternel a fait venir et a exécuté ce qu''il avait dit, et ces choses vous sont arrivées parce que vous avez péché contre l''Éternel et que vous n''avez pas écouté sa voix.'),
  (24, 40, 4, 'Maintenant voici, je te délivre aujourd''hui des chaînes que tu as aux mains; si tu veux venir avec moi à Babylone, viens, j''aurai soin de toi; si cela te déplaît de venir avec moi à Babylone, ne viens pas; regarde, tout le pays est devant toi, va où il te semblera bon et convenable d''aller.'),
  (24, 40, 5, 'Et comme il tardait à répondre: Retourne, ajouta-t-il, vers Guedalia, fils d''Achikam, fils de Schaphan, que le roi de Babylone a établi sur les villes de Juda, et reste avec lui parmi le peuple; ou bien, va partout où il te conviendra d''aller. Le chef des gardes lui donna des vivres et des présents, et le congédia.'),
  (24, 40, 6, 'Jérémie alla vers Guedalia, fils d''Achikam, à Mitspa, et il resta avec lui parmi le peuple qui était demeuré dans le pays.'),
  (24, 40, 7, 'Lorsque tous les chefs des troupes qui étaient dans les campagnes eurent appris, eux et leurs hommes, que le roi de Babylone avait établi gouverneur du pays Guedalia, fils d''Achikam, et qu''il lui avait confié les hommes, les femmes, les enfants, et ceux des pauvres du pays qu''on n''avait pas emmenés captifs à Babylone,'),
  (24, 40, 8, 'ils se rendirent auprès de Guedalia à Mitspa, savoir Ismaël, fils de Nethania, Jochanan et Jonathan, fils de Karéach, Seraja, fils de Thanhumeth, les fils d''Éphaï de Nethopha, et Jezania, fils du Maacatite, eux et leurs hommes.'),
  (24, 40, 9, 'Guedalia, fils d''Achikam, fils de Schaphan, leur jura, à eux et à leurs hommes, en disant: Ne craignez pas de servir les Chaldéens; demeurez dans le pays, servez le roi de Babylone, et vous vous en trouverez bien.'),
  (24, 40, 10, 'Voici, je reste à Mitspa, pour être présent devant les Chaldéens qui viendront vers nous; et vous, faites la récolte du vin, des fruits d''été et de l''huile, mettez-les dans vos vases, et demeurez dans vos villes que vous occupez.'),
  (24, 40, 11, 'Tous les Juifs qui étaient au pays de Moab, chez les Ammonites, au pays d''Édom, et dans tous les pays, apprirent que le roi de Babylone avait laissé un reste dans Juda, et qu''il leur avait donné pour gouverneur Guedalia, fils d''Achikam, fils de Schaphan.'),
  (24, 40, 12, 'Et tous les Juifs revinrent de tous les lieux où ils étaient dispersés, ils se rendirent dans le pays de Juda vers Guedalia à Mitspa, et ils firent une abondante récolte de vin et de fruits d''été.'),
  (24, 40, 13, 'Jochanan, fils de Karéach, et tous les chefs des troupes qui étaient dans les campagnes, vinrent auprès de Guedalia à Mitspa,'),
  (24, 40, 14, 'et lui dirent: Sais-tu que Baalis, roi des Ammonites, a chargé Ismaël, fils de Nethania, de t''ôter la vie? Mais Guedalia, fils d''Achikam, ne les crut point.'),
  (24, 40, 15, 'Et Jochanan, fils de Karéach, dit secrètement à Guedalia à Mitspa: Permets que j''aille tuer Ismaël, fils de Nethania. Personne ne le saura. Pourquoi t''ôterait-il la vie? pourquoi tous ceux de Juda rassemblés auprès de toi se disperseraient-ils, et le reste de Juda périrait-il?'),
  (24, 40, 16, 'Guedalia, fils d''Achikam, répondit à Jochanan, fils de Karéach: Ne fais pas cela; car ce que tu dis sur Ismaël est faux.'),
  (24, 41, 1, 'Au septième mois, Ismaël, fils de Nethania, fils d''Élischama, de la race royale, vint avec des grands du roi et dix hommes auprès de Guedalia, fils d''Achikam, à Mitspa. Là, ils mangèrent ensemble à Mitspa.'),
  (24, 41, 2, 'Alors Ismaël, fils de Nethania, se leva avec les dix hommes dont il était accompagné, et ils frappèrent avec l''épée Guedalia, fils d''Achikam, fils de Schaphan; il fit ainsi mourir celui que le roi de Babylone avait établi gouverneur du pays.'),
  (24, 41, 3, 'Ismaël tua encore tous les juifs qui étaient auprès de Guedalia à Mitspa, et les Chaldéens qui se trouvaient là, les gens de guerre.'),
  (24, 41, 4, 'Le second jour après l''assassinat de Guedalia, tandis que personne n''en savait rien,'),
  (24, 41, 5, 'il arriva de Sichem, de Silo et de Samarie, quatre-vingts hommes, qui avaient la barbe rasée et les vêtements déchirés, et qui s''étaient fait des incisions; ils portaient des offrandes et de l''encens, pour les présenter à la maison de l''Éternel.'),
  (24, 41, 6, 'Ismaël, fils de Nethania, sortit de Mitspa au-devant d''eux; il marchait en pleurant. Lorsqu''il les rencontra, il leur dit: Venez vers Guedalia, fils d''Achikam.'),
  (24, 41, 7, 'Et quand ils furent au milieu de la ville, Ismaël, fils de Nethania, les égorgea et les jeta dans la citerne, avec l''aide des gens qui l''accompagnaient.'),
  (24, 41, 8, 'Mais il se trouva parmi eux dix hommes, qui dirent à Ismaël: Ne nous fais pas mourir, car nous avons des provisions cachées dans les champs, du froment, de l''orge, de l''huile et du miel. Alors il les épargna, et ne les fit pas mourir avec leurs frères.'),
  (24, 41, 9, 'La citerne dans laquelle Ismaël jeta tous les cadavres des hommes qu''il tua près de Guedalia est celle qu''avait construite le roi Asa, lorsqu''il craignait Baescha, roi d''Israël; c''est cette citerne qu''Ismaël, fils de Nethania, remplit de cadavres.'),
  (24, 41, 10, 'Ismaël fit prisonniers tous ceux qui restaient à Mitspa, les filles du roi et tous ceux du peuple qui y demeuraient, et que Nebuzaradan, chef des gardes, avait confiés à Guedalia, fils d''Achikam; Ismaël, fils de Nethania, les emmena captifs, et partit pour passer chez les Ammonites.'),
  (24, 41, 11, 'Jochanan, fils de Karéach, et tous les chefs des troupes qui étaient avec lui, furent informés de tout le mal qu''avait fait Ismaël, fils de Nethania.'),
  (24, 41, 12, 'Ils prirent tous les hommes, et se mirent en marche pour attaquer Ismaël, fils de Nethania. Ils le trouvèrent près des grandes eaux de Gabaon.'),
  (24, 41, 13, 'Quand tout le peuple qui était avec Ismaël vit Jochanan, fils de Karéach, et tous les chefs des troupes avec lui, il en eut de la joie;'),
  (24, 41, 14, 'et tout le peuple qu''Ismaël avait emmené de Mitspa se retourna, et vint se joindre à Jochanan, fils de Karéach.'),
  (24, 41, 15, 'Mais Ismaël, fils de Nethania, se sauva avec huit hommes devant Jochanan, et alla chez les Ammonites.'),
  (24, 41, 16, 'Jochanan, fils de Karéach, et tous les chefs des troupes qui étaient avec lui, prirent tout le reste du peuple, et le délivrèrent des mains d''Ismaël, fils de Nethania, lorsqu''il l''emmenait de Mitspa, après avoir tué Guedalia, fils d''Achikam. Hommes de guerre, femmes, enfants, eunuques, Jochanan les ramena depuis Gabaon.'),
  (24, 41, 17, 'Ils se mirent en marche, et s''arrêtèrent à l''hôtellerie de Kimham près de Bethléhem, pour se retirer ensuite en Égypte,'),
  (24, 41, 18, 'loin des Chaldéens dont ils avaient peur, parce qu''Ismaël, fils de Nethania, avait tué Guedalia, fils d''Achikam, que le roi de Babylone avait établi gouverneur du pays.'),
  (24, 42, 1, 'Tous les chefs des troupes, Jochanan, fils de Karéach, Jezania, fils d''Hosée, et tout le peuple, depuis le plus petit jusqu''au plus grand, s''avancèrent,'),
  (24, 42, 2, 'et dirent à Jérémie, le prophète: Que nos supplications soient favorablement reçues devant toi! Intercède en notre faveur auprès de l''Éternel, ton Dieu, en faveur de tous ceux qui restent, car nous étions beaucoup, et nous restons en petit nombre, comme tes yeux le voient;'),
  (24, 42, 3, 'et que l''Éternel, ton Dieu, nous montre le chemin que nous devons suivre, et ce que nous avons à faire!'),
  (24, 42, 4, 'Jérémie, le prophète, leur dit: J''entends; voici je vais prier l''Éternel, votre Dieu, selon votre demande; et je vous ferai connaître, sans rien vous cacher, tout ce que l''Éternel vous répondra.'),
  (24, 42, 5, 'Et ils dirent à Jérémie: Que l''Éternel soit contre nous un témoin véritable et fidèle, si nous ne faisons pas tout ce que l''Éternel, ton Dieu, te chargera de nous dire!'),
  (24, 42, 6, 'Que ce soit du bien ou du mal, nous obéirons à la voix de l''Éternel, notre Dieu, vers qui nous t''envoyons, afin que nous soyons heureux, si nous obéissons à la voix de l''Éternel, notre Dieu.'),
  (24, 42, 7, 'Dix jours après, la parole de l''Éternel fut adressée à Jérémie.'),
  (24, 42, 8, 'Et Jérémie appela Jochanan, fils de Karéach, tous les chefs des troupes qui étaient avec lui, et tout le peuple, depuis le plus petit jusqu''au plus grand.'),
  (24, 42, 9, 'Il leur dit: Ainsi parle l''Éternel, le Dieu d''Israël, vers qui vous m''avez envoyé, pour que je lui présente vos supplications:'),
  (24, 42, 10, 'Si vous restez dans ce pays, je vous y établirai et je ne vous détruirai pas, je vous planterai et je ne vous arracherai pas; car je me repens du mal que je vous ai fait.'),
  (24, 42, 11, 'Ne craignez pas le roi de Babylone, dont vous avez peur; ne le craignez pas, dit l''Éternel, car je suis avec vous pour vous sauver et vous délivrer de sa main;'),
  (24, 42, 12, 'je lui inspirerai de la compassion pour vous, et il aura pitié de vous, et il vous laissera demeurer dans votre pays.'),
  (24, 42, 13, 'Mais si vous n''obéissez pas à la voix de l''Éternel, votre Dieu, et si vous dites: Nous ne resterons pas dans ce pays,'),
  (24, 42, 14, 'non, nous irons au pays d''Égypte, où nous ne verrons point de guerre, où nous n''entendrons pas le son de la trompette, où nous ne manquerons pas de pain, et c''est là que nous habiterons, -'),
  (24, 42, 15, 'alors écoutez la parole de l''Éternel, restes de Juda! Ainsi parle l''Éternel des armées, le Dieu d''Israël: Si vous tournez le visage pour aller en Égypte, si vous y allez demeurer,'),
  (24, 42, 16, 'l''épée que vous redoutez vous atteindra là au pays d''Égypte, la famine que vous craignez s''attachera à vous là en Égypte, et vous y mourrez.'),
  (24, 42, 17, 'Tous ceux qui tourneront le visage pour aller en Égypte, afin d''y demeurer, mourront par l''épée, par la famine ou par la peste, et nul n''échappera, ne fuira, devant les malheurs que je ferai venir sur eux.'),
  (24, 42, 18, 'Car ainsi parle l''Éternel des armées, le Dieu d''Israël: De même que ma colère et ma fureur se sont répandues sur les habitants de Jérusalem, de même ma fureur se répandra sur vous, si vous allez en Égypte; vous serez un sujet d''exécration, d''épouvante, de malédiction et d''opprobre, et vous ne verrez plus ce lieu.'),
  (24, 42, 19, 'Restes de Juda, l''Éternel vous dit: N''allez pas en Égypte! sachez que je vous le défends aujourd''hui.'),
  (24, 42, 20, 'Vous vous trompez vous-mêmes, car vous m''avez envoyé vers l''Éternel, votre Dieu, en disant: Intercède en notre faveur auprès de l''Éternel, notre Dieu, fais-nous connaître tout ce que l''Éternel, notre Dieu, dira, et nous le ferons.'),
  (24, 42, 21, 'Je vous l''ai déclaré aujourd''hui; mais vous n''écoutez pas la voix de l''Éternel, votre Dieu, ni tout ce qu''il m''a chargé de vous dire.'),
  (24, 42, 22, 'Sachez maintenant que vous mourrez par l''épée, par la famine ou par la peste, dans le lieu où vous voulez aller pour y demeurer.'),
  (24, 43, 1, 'Lorsque Jérémie eut achevé de dire à tout le peuple toutes les paroles de l''Éternel, leur Dieu, toutes ces paroles que l''Éternel, leur Dieu, l''avait chargé de leur dire,'),
  (24, 43, 2, 'Azaria, fils d''Hosée, Jochanan, fils de Karéach, et tous ces hommes orgueilleux, dirent à Jérémie: Tu dis un mensonge: l''Éternel, notre Dieu, ne t''a point chargé de nous dire: N''allez pas en Égypte pour y demeurer.')
